    function onTaskTypeChange() {
      // RCU type selector removed
    }

    // ── Comment type selector ──
    function tmSelectType(btn, type) {
      document.querySelectorAll('.tm-type-btn').forEach(b => {
        b.style.background = 'transparent';
        b.style.color = 'var(--text2)';
        b.style.borderColor = 'var(--border2)';
      });
      btn.style.background = 'var(--accent)';
      btn.style.color = '#fff';
      btn.style.borderColor = 'var(--accent)';
      btn.classList.add('active');

      const pendingSection = document.getElementById('tm-pending-docs-section');
      const subNoteRow = document.getElementById('tm-subnote-row');
      const commentHint = document.getElementById('tm-comment-hint');
      const commentLabel = document.getElementById('tm-comment-label');
      const commentBox = document.getElementById('tm-comment');

      if (type === 'pending') {
        pendingSection.style.display = 'block';
        subNoteRow.style.display = 'none';
        commentHint.textContent = '— describe why docs are needed or what is missing';
        commentBox.placeholder = 'e.g. Salary slips are outdated. Please provide last 3 months slips reflecting current CTC.';
      } else if (type === 'query') {
        pendingSection.style.display = 'none';
        subNoteRow.style.display = 'block';
        commentHint.textContent = '— clearly state the issue or question';
        commentBox.placeholder = 'e.g. CIBIL score mismatch noticed. Please clarify the settlement entry dated 12-Jan-2025.';
      } else if (type === 'task') {
        pendingSection.style.display = 'none';
        subNoteRow.style.display = 'block';
        commentHint.textContent = '— describe action taken or next step';
        commentBox.placeholder = 'e.g. Login completed. File forwarded to underwriting team for review.';
      } else {
        pendingSection.style.display = 'none';
        subNoteRow.style.display = 'block';
        commentHint.textContent = '';
        commentBox.placeholder = 'Describe the update, issue or action clearly...';
      }
      document.getElementById('tm-comment').dataset.commentType = type;
    }

    function tmAddCustomDoc(event) {
      if (event.key !== 'Enter') return;
      const inp = document.getElementById('tm-doc-custom');
      const val = (inp.value || '').trim();
      if (!val) return;
      const list = document.getElementById('tm-doc-checklist');
      const lbl = document.createElement('label');
      lbl.className = 'tm-doc-item';
      lbl.innerHTML = `<input type="checkbox" value="${val}" checked> ${val}`;
      list.appendChild(lbl);
      inp.value = '';
    }

    // Build professional formatted comment from type + inputs
    function _buildFormattedComment() {
      const type = document.getElementById('tm-comment').dataset.commentType || 'general';
      const rawComment = (document.getElementById('tm-comment').value || '').trim();

      if (type === 'pending') {
        // Collect checked docs
        const checked = Array.from(document.querySelectorAll('#tm-doc-checklist input[type=checkbox]:checked'))
          .map(c => c.value);
        const docLines = checked.map(d => `• ${d}`).join('\n');
        const note = rawComment ? `\nNote: ${rawComment}` : '';
        if (!checked.length && !rawComment) return { comment: '', type };
        const body = checked.length
          ? `📋 PENDING DOCUMENTS REQUIRED\n${'─'.repeat(32)}\n${docLines}${note}`
          : rawComment;
        return { comment: body, type };
      }

      if (type === 'query') {
        if (!rawComment) return { comment: '', type };
        return { comment: `❓ QUERY / ISSUE\n${'─'.repeat(32)}\n${rawComment}`, type };
      }

      if (type === 'task') {
        if (!rawComment) return { comment: '', type };
        return { comment: `✅ TASK UPDATE\n${'─'.repeat(32)}\n${rawComment}`, type };
      }

      // general
      return { comment: rawComment, type };
    }

    function selectFI(field, val, el) {
      const container = el.parentElement;
      container.querySelectorAll('.fi-option').forEach(o => o.classList.remove('selected'));
      el.classList.add('selected');
      document.getElementById('tm-' + field + '-add').value = val;
    }

    // No-op placeholder (FI modal now uses native <select>; kept to preserve onchange hook).
    function onFIFieldChange() {}

    function submitTracking() {
      const app = APPLICATIONS.find(a => a.id === trackingContext.appId);
      if (!app) return;
      const rd = ROLES[currentUser.role];
      const mode = trackingContext.mode;

      const stage = document.getElementById('tm-stage').value;
      const status = document.getElementById('tm-status').value;
      const { comment: formattedComment, type: commentType } = _buildFormattedComment();
      const comment = formattedComment;
      const subnote = document.getElementById('tm-subnote').value;

      // Validate
      if (mode === 'fi') {
        const resi = document.getElementById('tm-resi-add').value;
        const office = document.getElementById('tm-office-add').value;
        if (!resi || !office) { showToast('Select Residential & Office address result', 'error'); return; }
        const subNote = `Final Resi Address - ${resi}\n Final Office Address - ${office}`;
        addTrackingEntry(app, 'EFIN- FI report', stage, comment, subNote);
        app.final_report = true;
        // Persist FI selections on the app so button visibility can key off them
        app.fi_resi = resi;
        app.fi_office = office;
        // Auto-post a short system note in a natural, human-reviewer tone.
        // Picks phrasing based on which address(es) triggered the follow-up.
        const negResi = resi === 'Negative', negOffice = office === 'Negative';
        const pendResi = resi === 'Pending', pendOffice = office === 'Pending';
        let sysComment = '';
        let sysTask = 'EFIN- FI report';

        if (negResi && negOffice) {
          sysTask = 'EFIN- Report review';
          sysComment = 'Both addresses came back negative. Sending for physical re-verification before we move ahead.';
        } else if (negResi) {
          sysTask = 'EFIN- Report review';
          sysComment = 'Residence verification failed. Raising for physical review — office FI is '
            + (office === 'Waived' ? 'waived' : office.toLowerCase()) + '.';
        } else if (negOffice) {
          sysTask = 'EFIN- Report review';
          sysComment = 'Office verification failed. Need a physical check at the office — residence is '
            + (resi === 'Waived' ? 'waived' : resi.toLowerCase()) + '.';
        } else if (pendResi && pendOffice) {
          sysComment = 'Both FIs are still pending. Will follow up with the agency and update once reports are in.';
        } else if (pendResi) {
          sysComment = 'Residence FI is still pending. Office is '
            + (office === 'Waived' ? 'waived' : office.toLowerCase())
            + ' — will chase the agency for the resi report.';
        } else if (pendOffice) {
          sysComment = 'Office FI is still pending. Resi is '
            + (resi === 'Waived' ? 'waived' : resi.toLowerCase())
            + ' — waiting on the office verification to close this out.';
        } else {
          // Positive / Waived combinations — no follow-up needed.
          sysComment = (resi === 'Waived' && office === 'Waived')
            ? 'Both FIs waived as per policy. Closing this step.'
            : 'Both addresses cleared. No further FI action required.';
        }
        addTrackingEntry(app, sysTask, 'System Comments', sysComment, ' ');
      } else if (mode === 'task') {
        const tt = document.getElementById('tm-task-type').value;
        if (!tt) { showToast('Select a task type', 'error'); return; }
        if (!comment && !subnote) { showToast('Enter a comment or sub note', 'error'); return; }
        addTrackingEntry(app, tt, stage, comment, subnote);
        // Status changes
        const statusMap = { 'approved_deviation': 'approved_deviation', 'EFIN-Customer Confirmation': 'acceptance', 'EFIN-Final Offer Check': 'offer', 'deviation': 'decision', 'EFIN-Approved': 'approved' };
        if (statusMap[tt]) { app.status = statusMap[tt]; showToast(`Status → ${STATUSES[statusMap[tt]] || statusMap[tt]}`, 'info'); }
        if (tt === 'EFIN-Nach') app.nach_done = true;
        if (tt === 'EFIN-Customer Agreement') app.customer_agreement_done = true;
      } else {
        // direct / manual / incom / bank / ecs
        const name = document.getElementById('tm-name')?.value;
        if (!name) { showToast('Enter task name', 'error'); return; }
        if (!comment && !subnote) { showToast('Enter a comment or sub note', 'error'); return; }
        addTrackingEntry(app, name, stage, comment, subnote);
        if (mode === 'direct_doc')   app.document_checked = true;
        if (mode === 'direct_incom') app.incom_check = true;
        if (mode === 'direct_bank')  app.bank_check = true;
        if (mode === 'direct_ecs')   app.ecs_return = true;
      }

      closeModal('modal-tracking');
      // Animate new tracking row appearance
      setTimeout(() => {
        // Use refreshDetailTimeline — it calls buildDetailActionBar (authoritative)
        // so action buttons, Re-open, More Actions all update correctly
        if (typeof refreshDetailTimeline === 'function') {
          refreshDetailTimeline(trackingContext.appId);
        } else {
          renderTrackingSection(app);
        }
        // Re-render the disburse checklist so pre-condition badges update live
        if (typeof _renderDisburseChecklist === 'function') _renderDisburseChecklist(app);
        showToast('Timeline entry posted ✓', 'success');
      }, 100);
    }

    function addTrackingEntry(app, name, stage, comment, subnote) {
      if (!app.tracking) app.tracking = [];
      const now = new Date();
      const dateStr = now.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
      app.tracking.push({ id: app.tracking.length + 1, name, current_stage: stage, current_user: currentUser.name, status: 'Complete', comment: comment || '', sub_note: subnote || '', date: dateStr });
    }

    // ── Lightweight timeline refresh (no full openDetail re-render) ──
    // Mirrors Income Check's pattern: re-render only what changed.
    function refreshDetailTimeline(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      const rd = ROLES[currentUser.role];

      // ── Action bar: always use the authoritative renderer so Re-open,
      //    More Actions, and all role/status guards are applied correctly ──
      const actEl = document.getElementById('detail-actions');
      if (actEl) {
        actEl.innerHTML = (typeof buildDetailActionBar === 'function')
          ? buildDetailActionBar(app, rd)
          : (() => {
              let h = `<span class="badge badge-${app.status}" style="font-size:13px;padding:6px 14px">${STATUSES[app.status] || app.status}</span>`;
              h += buildWorkflowActionButtons(app, rd);
              if (rd.canHoldApp && !['disbursed','rejected','ni','cancelled'].includes(app.status))
                h += `<button class="btn btn-warn btn-sm" onclick="holdApp('${app.id}')">Hold</button>`;
              if (rd.canRejectApp && !['disbursed','rejected'].includes(app.status))
                h += `<button class="btn btn-danger btn-sm" onclick="rejectApp('${app.id}')">Reject</button>`;
              return h;
            })();
      }

      // ── Re-render tracking section ──
      renderTrackingSection(app);

      // ── Keep aggregate views in sync ──
      if (typeof renderTable         === 'function') renderTable();
      if (typeof updateDashboardStats=== 'function') updateDashboardStats();
      if (typeof renderPipeline      === 'function') renderPipeline();
      if (typeof persistSave         === 'function') persistSave();

      // ── Switch to Timeline tab so new entry is immediately visible ──
      const tabEl = document.querySelector('#page-app-detail .tabs .tab[onclick*="tracking-tab"]');
      if (tabEl) switchTab('tracking-tab', tabEl);

      // ── Flash newest row ──
      setTimeout(() => {
        const firstRow = document.querySelector('#tracking-section .tracking-table tbody tr:first-child');
        if (firstRow) {
          firstRow.classList.add('row-new');
          setTimeout(() => firstRow.classList.remove('row-new'), 600);
        }
      }, 40);
    }

    function skipDeviation(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      addTrackingEntry(app, 'EFIN- SKIP Deviation', ROLES[currentUser.role].dept, 'SKIP', ' ');
      app.status = 'approved_deviation';
      showToast('Deviation skipped', 'success');
      openDetail(appId);
    }

