        "Application ID": "🔖", "Status": "🟣", "Loan Type": "💰", "Loan Amount": "💵", "Bank/NBFC": "🏦",
        "Sales Person": "👤", "Created": "📅", "CIBIL Score": "📊", "Loan Rate": "📈", "Tenure": "⏱️",
