    /* Done checkmark — bold, satisfying tick */
    const CHECK_ICON = `<svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="20 6 9 17 4 12"/></svg>`;

    // ── Product-aware wizard step helpers ────────────────────────
    // Returns the active step config for the currently selected product.
    // Falls back to all-9-steps if no product selected yet.
    function getActiveWizardSteps() {
      const prodKey = (typeof _selectedLoanProduct !== 'undefined' && _selectedLoanProduct)
        ? _selectedLoanProduct
        : (document.getElementById('w-loantype')?.value || 'personal_loan');
      const cfg = (typeof LOAN_PRODUCT_CONFIG !== 'undefined' && LOAN_PRODUCT_CONFIG[prodKey]) || {};
      const steps  = cfg.wizardSteps  || [1,2,3,4,5,6,7,8,9];
      const labels = cfg.wizardLabels || ['Contact','KYC Verify','Personal Details','Address','Employment','Initial Offer','References','Documents','Loan Analytics'];
      return { steps, labels, total: steps.length };
    }

    // Map wizard position (1-based) → physical step div id (wstep-N)
    function wizPosToStepId(pos) {
      const { steps } = getActiveWizardSteps();
      return steps[pos - 1] || pos;
    }

    // Map physical step div id → wizard position (1-based), or -1 if not in this product's flow
    function stepIdToWizPos(stepId) {
      const { steps } = getActiveWizardSteps();
      const idx = steps.indexOf(stepId);
      return idx >= 0 ? idx + 1 : -1;
    }

    // ══════════════════════════════════════════════════════════
    //  TEAM WORKFLOW — WIZARD STEP 1 HELPERS
    //  mirrors create_new_loan.py + loan_application_inherit.py
    // ══════════════════════════════════════════════════════════

    // Populate Location dropdown from twLocations master
    function wPopulateLocations() {
      const sel = document.getElementById('w-location');
      if (!sel) return;
      const cur = sel.value;
      sel.innerHTML = '<option value="">— Select Location —</option>' +
        (typeof twLocations !== 'undefined' ? twLocations : [])
          .map(l => `<option value="${l.name}" ${l.name===cur?'selected':''}>${l.name}</option>`).join('');
    }

    // Channel → show DSA / Partner / Lead-Source conditional fields
    // ── Live Channel Preview ─────────────────────────────────────────
    // Renders a real-time summary card below the channel fields showing
    // exactly what will appear in the Overview tab after submission.
    function wUpdateChannelPreview() {
      // Overview Preview removed — keep function as no-op for call-site compatibility
    }
    window.wUpdateChannelPreview = wUpdateChannelPreview;

    // ══════════════════════════════════════════════════════════
    //  WSDD — Wizard Searchable Dropdown Engine
    //  Replaces plain <select> with a styled searchable widget.
    //  Each instance is self-contained; all existing code that
    //  reads hidden backing fields continues to work unchanged.
    // ══════════════════════════════════════════════════════════
    (function() {

      // Registry of all active WSDD instances keyed by wrapperId
      var _instances = {};

      /**
       * wsddCreate(wrapperId, options)
       *
       * options = {
       *   items      : [{ value, label, meta?, badge?, badgeColor? }]
       *   placeholder: string          (default "— Select —")
       *   searchPlaceholder: string    (default "Search…")
       *   hiddenId   : string          (id of hidden <input> to sync value into)
       *   allowEmpty : bool            (show "clear" option, default true)
       *   emptyLabel : string          (label for empty option)
       *   onChange   : function(value, label, item)
       * }
       */
      window.wsddCreate = function(wrapperId, options) {
        var wrap = document.getElementById(wrapperId);
        if (!wrap) return;
        options = options || {};

        var items          = options.items         || [];
        var placeholder    = options.placeholder   || '— Select —';
        var searchPh       = options.searchPlaceholder || 'Type to search…';
        var hiddenId       = options.hiddenId      || null;
        var allowEmpty     = options.allowEmpty !== false;
        var emptyLabel     = options.emptyLabel    || '— ' + placeholder.replace(/^—\s*/,'') + ' —';
        var onChange       = options.onChange      || null;
        // Opt-in only — every other existing wsddCreate() call site (DSA,
        // Partner, Permanent State, etc.) omits this and is unaffected.
        var allowManualEntry = options.allowManualEntry === true;
        var onManualEntry     = options.onManualEntry || null;

        // Current state
        var selValue = '';
        var selLabel = '';
        var isOpen   = false;

        // ── Build DOM ──
        wrap.innerHTML =
          '<div class="wsdd-display" tabindex="0" role="combobox" aria-haspopup="listbox" aria-expanded="false">' +
            '<span class="wsdd-val placeholder">' + placeholder + '</span>' +
            '<span class="wsdd-arrow">▾</span>' +
          '</div>' +
          '<div class="wsdd-panel" style="display:none" role="listbox">' +
            '<div style="position:relative">' +
              '<span style="position:absolute;left:10px;top:50%;transform:translateY(-50%);font-size:12px;opacity:.45;pointer-events:none">🔍</span>' +
              '<input class="wsdd-search" placeholder="' + searchPh + '" style="padding-left:30px" type="text" autocomplete="off">' +
            '</div>' +
            '<div class="wsdd-list"></div>' +
          '</div>';

        var displayEl = wrap.querySelector('.wsdd-display');
        var panelEl   = wrap.querySelector('.wsdd-panel');
        var searchEl  = wrap.querySelector('.wsdd-search');
        var listEl    = wrap.querySelector('.wsdd-list');

        // ── Render list items ──
        function renderList(q) {
          var filtered = items.filter(function(it) {
            if (!q) return true;
            var lq = q.toLowerCase();
            return (it.label || '').toLowerCase().includes(lq) ||
                   (it.meta  || '').toLowerCase().includes(lq);
          });

          var html = '';
          if (allowEmpty) {
            html += '<div class="wsdd-item' + (!selValue ? ' wsdd-selected' : '') + '" data-val="" data-lbl="">' +
              '<span style="color:var(--text3);font-style:italic">' + emptyLabel + '</span></div>';
          }
          if (!filtered.length) {
            html += '<div class="wsdd-empty">No results for "<strong>' + (q || '') + '</strong>"</div>';
            if (allowManualEntry) {
              html += '<div class="wsdd-item wsdd-manual-entry" data-manual-entry="1">' +
                '<span style="width:26px;height:26px;border-radius:6px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:13px;flex-shrink:0">✏️</span>' +
                '<div style="flex:1;min-width:0">' +
                  '<div style="font-size:13px;font-weight:700;color:var(--accent)">Enter' + (q ? ' "' + q + '"' : '') + ' manually</div>' +
                  '<div style="font-size:11px;color:var(--text3);margin-top:1px">Company not in the list? Add it yourself</div>' +
                '</div>' +
              '</div>';
            }
          } else {
            filtered.forEach(function(it) {
              var isSel = it.value === selValue;
              html += '<div class="wsdd-item' + (isSel ? ' wsdd-selected' : '') + '" data-val="' + it.value + '" data-lbl="' + (it.label || '') + '">' +
                // optional left avatar initial
                (it.label ? '<span style="width:26px;height:26px;border-radius:6px;background:' + (isSel ? 'var(--accent)' : 'var(--accent-subtle)') + ';display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:800;color:' + (isSel ? '#fff' : 'var(--accent)') + ';flex-shrink:0">' + it.label.charAt(0).toUpperCase() + '</span>' : '') +
                '<div style="flex:1;min-width:0">' +
                  '<div style="font-size:13px;font-weight:' + (isSel ? '700' : '500') + '">' + _highlight(it.label || '', q) + '</div>' +
                  (it.meta ? '<div style="font-size:11px;color:var(--text3);margin-top:1px">' + _highlight(it.meta, q) + '</div>' : '') +
                '</div>' +
                (it.badge ? '<span style="font-size:10px;font-weight:800;padding:2px 8px;border-radius:99px;background:' + (it.badgeColor || 'rgba(26,79,163,.1)') + ';color:' + (it.badgeColor ? '#fff' : 'var(--accent)') + ';white-space:nowrap">' + it.badge + '</span>' : '') +
              '</div>';
            });
          }
          listEl.innerHTML = html;

          // Bind click handlers
          listEl.querySelectorAll('.wsdd-item[data-val]').forEach(function(row) {
            row.addEventListener('mousedown', function(e) {
              e.preventDefault();
              e.stopPropagation();
              selectItem(this.dataset.val, this.dataset.lbl);
            });
          });
          var manualRow = listEl.querySelector('[data-manual-entry]');
          if (manualRow) {
            manualRow.addEventListener('mousedown', function(e) {
              e.preventDefault();
              e.stopPropagation();
              var typedQuery = searchEl.value.trim();
              closePanel();
              if (onManualEntry) onManualEntry(typedQuery);
            });
          }
        }

        // Highlight matching text
        function _highlight(text, q) {
          if (!q || !text) return text;
          var escaped = q.replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
          return text.replace(new RegExp('(' + escaped + ')', 'gi'), '<mark style="background:rgba(26,79,163,.15);color:inherit;border-radius:2px;padding:0 1px">$1</mark>');
        }

        // ── Open / close ──
        function openPanel() {
          if (isOpen) return;
          isOpen = true;
          // Close any other open WSDD
          Object.keys(_instances).forEach(function(k) {
            if (k !== wrapperId && _instances[k]) _instances[k].close();
          });
          panelEl.classList.remove('wsdd-up');
          panelEl.style.display = '';
          // Field itself becomes the search input — hide the display box so no
          // separate/duplicate search control appears (single combobox control).
          displayEl.style.display = 'none';
          panelEl.classList.add('wsdd-as-field');
          displayEl.classList.add('wsdd-open');
          displayEl.setAttribute('aria-expanded','true');
          renderList('');
          searchEl.value = '';
          // Show the current selection as the search placeholder so the field still
          // communicates what's selected when it turns into the search input.
          searchEl.placeholder = selLabel ? selLabel : searchPh;
          // ── Smart positioning: flip up if not enough room below ──
          _wsddPositionPanel(displayEl, panelEl, listEl);
          setTimeout(function() { searchEl.focus(); }, 30);
        }

        function closePanel() {
          if (!isOpen) return;
          isOpen = false;
          panelEl.style.display = 'none';
          panelEl.classList.remove('wsdd-as-field');
          // Restore the display box showing the (possibly newly) selected value.
          displayEl.style.display = '';
          displayEl.classList.remove('wsdd-open');
          displayEl.setAttribute('aria-expanded','false');
        }

        // ── Select an item ──
        function selectItem(value, label) {
          selValue = value;
          selLabel = label;

          var valEl = displayEl.querySelector('.wsdd-val');
          if (value) {
            valEl.textContent = label;
            valEl.classList.remove('placeholder');
          } else {
            valEl.textContent = placeholder;
            valEl.classList.add('placeholder');
          }

          // Sync to hidden backing field
          if (hiddenId) {
            var hid = document.getElementById(hiddenId);
            if (hid) hid.value = value;
          }

          closePanel();

          // Fire onChange callback
          var item = items.find(function(it) { return it.value === value; });
          if (onChange) onChange(value, label, item || null);
        }

        // ── Events ──
        displayEl.addEventListener('click', function() { isOpen ? closePanel() : openPanel(); });
        displayEl.addEventListener('keydown', function(e) {
          if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); isOpen ? closePanel() : openPanel(); }
          if (e.key === 'Escape') closePanel();
          if (e.key === 'ArrowDown') { openPanel(); setTimeout(function(){ searchEl.focus(); },30); }
        });
        searchEl.addEventListener('input', function() { renderList(this.value.trim()); });
        searchEl.addEventListener('keydown', function(e) { if (e.key === 'Escape') closePanel(); });

        // Close on outside click
        document.addEventListener('click', function(e) {
          if (isOpen && !wrap.contains(e.target)) closePanel();
        });

        // ── Public API ──
        var api = {
          setItems: function(newItems) {
            items = newItems || [];
            if (isOpen) renderList(searchEl.value.trim());
          },
          setValue: function(value) {
            var it = items.find(function(x) { return x.value === value; });
            selectItem(value, it ? it.label : '');
          },
          getValue: function() { return selValue; },
          getLabel: function() { return selLabel; },
          clear:    function() { selectItem('', ''); },
          open:     openPanel,
          close:    closePanel,
        };

        _instances[wrapperId] = api;
        return api;
      };

      // Convenience read helpers (replaces .value on old <select>)
      window.wsddGetValue = function(wrapperId) {
        return _instances[wrapperId] ? _instances[wrapperId].getValue() : '';
      };
      window.wsddGetLabel = function(wrapperId) {
        return _instances[wrapperId] ? _instances[wrapperId].getLabel() : '';
      };
      window.wsddSetValue = function(wrapperId, value) {
        if (_instances[wrapperId]) _instances[wrapperId].setValue(value);
      };
      window.wsddSetItems = function(wrapperId, items) {
        if (_instances[wrapperId]) _instances[wrapperId].setItems(items);
      };
      window.wsddClear = function(wrapperId) {
        if (_instances[wrapperId]) _instances[wrapperId].clear();
      };

    })();

    // ══════════════════════════════════════════════════════════
    //  INITIALISE the three wizard WSDD instances
    //  (called on DOMContentLoaded and whenever wizard opens)
    // ══════════════════════════════════════════════════════════
    function _initWizardWsdds() {

      // ── 1. DSA Name ──
      wsddCreate('wsdd-dsa-name', {
        placeholder: '— Select DSA —',
        searchPlaceholder: 'Search DSA by name or code…',
        hiddenId: 'w-dsa-name-val',
        allowEmpty: true,
        emptyLabel: '— Select DSA —',
        items: _buildDsaItems(),
        onChange: function(value, label) {
          // When DSA changes, filter the Linked Partner list to this DSA's linked partners
          var dsa = (window.twDSAList || []).find(function(d) { return d.id === value; });
          var partnerItems = _buildPartnerItemsForDsa(value);
          wsddSetItems('wsdd-dsa-partner', partnerItems);
          wsddClear('wsdd-dsa-partner');
          if (document.getElementById('w-dsa-partner-linked-val'))
            document.getElementById('w-dsa-partner-linked-val').value = '';
          wUpdateChannelPreview();
        }
      });

      // ── 2. Linked Partner ──
      wsddCreate('wsdd-dsa-partner', {
        placeholder: '— None (optional) —',
        searchPlaceholder: 'Search partner by name…',
        hiddenId: 'w-dsa-partner-linked-val',
        allowEmpty: true,
        emptyLabel: '— None (optional) —',
        items: [],   // populated when a DSA is selected
        onChange: function() { wUpdateChannelPreview(); }
      });

      // ── 2b. Partner / Agent Name (for channel=agent) ──
      wsddCreate('wsdd-partner-name', {
        placeholder: '— Select Partner —',
        searchPlaceholder: 'Search partner by name or code…',
        hiddenId: 'w-partner-name-val',
        allowEmpty: true,
        emptyLabel: '— Select Partner —',
        items: _buildPartnerItemsForDsa(''),
        onChange: function(value, label) {
          // Sync legacy select for submission compatibility
          var legacySel = document.getElementById('w-partner-name');
          if (legacySel) {
            // Ensure the option exists
            var found = Array.from(legacySel.options).find(o => o.value === value);
            if (!found && value) {
              var opt = document.createElement('option');
              opt.value = value; opt.text = label;
              legacySel.appendChild(opt);
            }
            legacySel.value = value;
          }
          // Also set the mapped DSA hidden field
          var partner = (window.twPartnerList||[]).find(function(p){ return p.id === value; });
          var hidDsa = document.getElementById('w-partner-mapped-dsa-id');
          if (hidDsa && partner) hidDsa.value = partner.mappedDsaId || '';
          if (typeof wUpdateChannelPreview === 'function') wUpdateChannelPreview();
        }
      });

      // ── 3. Company / Employer Name ──
      wsddCreate('wsdd-company-name', {
        placeholder: '— Select from master list —',
        searchPlaceholder: 'Search company by name or type…',
        hiddenId: 'w-company-name-id',
        allowEmpty: true,
        emptyLabel: '— Select from master list —',
        items: _buildCompanyItems(),
        allowManualEntry: true,
        onManualEntry: function(typedQuery) {
          // Reuses the existing manual-company mechanism exactly as if the
          // user had ticked "Enter manually" themselves — same checkbox,
          // same hidden field, same downstream eligibility/submit/draft
          // handling. Only difference: whatever they'd already typed while
          // searching is carried over instead of being lost.
          var cb = document.getElementById('w-is-custom-company');
          if (cb) cb.checked = true;
          if (typeof toggleCustomCompany === 'function') toggleCustomCompany();
          var txt = document.getElementById('w-compname');
          if (txt) {
            if (typedQuery) txt.value = typedQuery;
            txt.focus();
          }
        },
        onChange: function(value) {
          // Mirror the hidden field and trigger eligibility
          var hid = document.getElementById('w-company-name-id');
          if (hid) hid.value = value;
          if (typeof laAutoDetectFromWizard === 'function') laAutoDetectFromWizard();
        }
      });

      // ── 4. Permanent Address State ──
      var _INDIA_STATES = ['Andhra Pradesh','Arunachal Pradesh','Assam','Bihar','Chhattisgarh','Goa','Gujarat','Haryana','Himachal Pradesh','Jharkhand','Karnataka','Kerala','Madhya Pradesh','Maharashtra','Manipur','Meghalaya','Mizoram','Nagaland','Odisha','Punjab','Rajasthan','Sikkim','Tamil Nadu','Telangana','Tripura','Uttar Pradesh','Uttarakhand','West Bengal','Delhi','Jammu and Kashmir','Ladakh'];
      wsddCreate('wsdd-pstate', {
        placeholder: 'Select State',
        searchPlaceholder: 'Search state…',
        allowEmpty: true,
        emptyLabel: 'Select State',
        items: _INDIA_STATES.map(function(s){ return { value: s, label: s }; }),
        onChange: function(value) {
          var sel = document.getElementById('w-pstate');
          if (sel) sel.value = value;
        }
      });
    }

    // ── Item builders ──
    function _buildDsaItems() {
      return (window.twDSAList || []).map(function(d) {
        return {
          value: d.id,
          label: d.name + (d.code ? ' (' + d.code + ')' : ''),
          // meta and badge intentionally omitted — show name+code only
        };
      });
    }

    function _buildPartnerItemsForDsa(dsaId) {
      var all = window.twPartnerList || [];
      // If a DSA is selected, show its linked partners first, then all active ones
      var linked    = dsaId ? all.filter(function(p) { return p.mappedDsaId === dsaId; }) : [];
      var unlinked  = dsaId ? all.filter(function(p) { return p.status === 'active' && p.mappedDsaId !== dsaId; }) : all.filter(function(p){ return p.status==='active'; });
      var pool = linked.concat(unlinked);
      return pool.map(function(p) {
        var isDsaLinked = dsaId && p.mappedDsaId === dsaId;
        return {
          value: p.id,
          label: p.name + (p.code ? ' (' + p.code + ')' : ''),
          meta:  (p.type || '') + (isDsaLinked ? (p.type ? ' · Linked to this DSA' : 'Linked to this DSA') : ''),
          badge: isDsaLinked ? 'Linked' : (p.status === 'active' ? 'Active' : 'Inactive'),
          badgeColor: isDsaLinked ? 'rgba(26,79,163,.75)' : (p.status === 'active' ? 'rgba(26,115,64,.55)' : 'rgba(120,130,155,.55)'),
        };
      });
    }

    function _buildCompanyItems() {
      // Merge LA_DB master list with any companies from existing applications
      var masterList = (window.LA_DB && window.LA_DB.companies) ? window.LA_DB.companies : [];
      var appCompanies = [];
      if (typeof APPLICATIONS !== 'undefined') {
        var seen = new Set(masterList.map(function(c){ return c.name.toLowerCase(); }));
        APPLICATIONS.forEach(function(a) {
          if (a.compName && !seen.has(a.compName.toLowerCase())) {
            appCompanies.push({ id: 'custom_' + a.compName, name: a.compName, compType: '' });
            seen.add(a.compName.toLowerCase());
          }
        });
      }
      return masterList.concat(appCompanies).map(function(c) {
        var typeLabel = { plcc:'Listed Company',plc:'Public Ltd',llp:'LLP',govt:'Govt/PSU',psu:'PSU',other:'Other',proprietorship:'Proprietorship' }[c.compType] || c.compType || '';
        return {
          value: String(c.id),
          label: c.name,
          meta:  typeLabel + (c.empTypes ? ' · ' + c.empTypes.join(', ') : ''),
          badge: typeLabel || null,
          badgeColor: 'rgba(26,79,163,.55)',
        };
      });
    }

    // ── Re-init WSDDs whenever wizard is opened ──
    (function _hookWizardOpen() {
      var _origOpenWiz = window.openWizard || window.openNewLoanWizard || null;
      // Try DOMContentLoaded hook first (runs once)
      document.addEventListener('DOMContentLoaded', function() {
        _initWizardWsdds();
        // Also hook the wizard open button/function if present
        var wizBtn = document.getElementById('btn-new-loan') || document.getElementById('open-wizard-btn');
        if (wizBtn) {
          var origClick = wizBtn.onclick;
          wizBtn.onclick = function(e) {
            if (origClick) origClick.call(this, e);
            setTimeout(_initWizardWsdds, 80);
          };
        }
      });
    })();

    function wChannelChange(sel) {
      const val = sel.value;
      const dsaGrp         = document.getElementById('w-dsa-group');
      const dsaPartGrp     = document.getElementById('w-dsa-partner-group');
      const partnerGrp     = document.getElementById('w-partner-group');
      const leadsrcGrp     = document.getElementById('w-leadsrc-group');
      const directSalesGrp = document.getElementById('w-direct-sales-group');

      // Hide all conditional groups first
      if (dsaGrp)         dsaGrp.style.display         = 'none';
      if (dsaPartGrp)     dsaPartGrp.style.display      = 'none';
      if (partnerGrp)     partnerGrp.style.display      = 'none';
      if (leadsrcGrp)     leadsrcGrp.style.display      = 'none';
      if (directSalesGrp) directSalesGrp.style.display  = 'none';

      if (val === 'dsa') {
        // Refresh WSDD items from latest master list
        if (typeof wsddSetItems === 'function') {
          wsddSetItems('wsdd-dsa-name',    _buildDsaItems());
          wsddSetItems('wsdd-dsa-partner', _buildPartnerItemsForDsa(''));
        }
        if (dsaGrp)     dsaGrp.style.display    = '';
        if (dsaPartGrp) dsaPartGrp.style.display = '';
      } else if (val === 'agent') {
        // Refresh the WSDD partner list
        if (typeof wsddSetItems === 'function') {
          wsddSetItems('wsdd-partner-name', _buildPartnerItemsForDsa(''));
        }
        // Also keep legacy select in sync for submission compatibility
        const pSel = document.getElementById('w-partner-name');
        if (pSel) {
          pSel.innerHTML = '<option value="">— Select Partner —</option>' +
            (window.twPartnerList || []).map(p => `<option value="${p.id}">${p.name}${p.code?' ('+p.code+')':''}</option>`).join('');
        }
        if (partnerGrp) partnerGrp.style.display = '';

        // ── AUTO-POPULATE: if current user is a partner role,
        //    pre-select them and show their mapped DSA chip ──
        if (currentUser && currentUser.role === 'partner') {
          const matchedPartner = (window.twPartnerList||[]).find(p =>
            p.email === currentUser.email ||
            p.name  === currentUser.name
          );
          if (matchedPartner) {
            // Pre-select in WSDD
            if (typeof wsddSetValue === 'function') {
              wsddSetValue('wsdd-partner-name', matchedPartner.id, matchedPartner.name + (matchedPartner.code ? ' ('+matchedPartner.code+')' : ''));
            }
            if (pSel) pSel.value = matchedPartner.id;
            wShowMappedDsaChip(matchedPartner);
          }
        }
      } else if (val === 'online') {
        if (leadsrcGrp) leadsrcGrp.style.display = '';
      } else if (val === 'direct') {
        const salesSel  = document.getElementById('w-sales');
        const salesName = salesSel?.options[salesSel.selectedIndex]?.value || '';
        const nameEl    = document.getElementById('w-direct-sales-name');
        const aviEl     = document.getElementById('w-direct-sales-avi');
        if (nameEl) nameEl.textContent = salesName || '— Select Sales Person above —';
        if (aviEl)  aviEl.textContent  = salesName ? salesName.charAt(0).toUpperCase() : '?';
        if (directSalesGrp) directSalesGrp.style.display = '';
      }

      // Remove any stale DSA chip when channel changes away from agent
      if (val !== 'agent') _wRemoveMappedDsaChip();

      // Clear values when hidden
      if (val !== 'dsa') {
        if (typeof wsddClear === 'function') {
          wsddClear('wsdd-dsa-name');
          wsddClear('wsdd-dsa-partner');
        }
        // Clear hidden backing fields
        const hidDsa = document.getElementById('w-dsa-name-val');     if (hidDsa) hidDsa.value = '';
        const hidLp  = document.getElementById('w-dsa-partner-linked-val'); if (hidLp) hidLp.value = '';
      }
      if (val !== 'agent') {
        const pSel = document.getElementById('w-partner-name'); if (pSel) pSel.value = '';
      }
      if (val !== 'online') {
        const ls = document.getElementById('w-leadsrc'); if (ls) ls.value = '';
      }

      // Update live overview preview
      wUpdateChannelPreview();
    }

    // ── Show mapped-DSA info chip below the partner selector ──
    function wShowMappedDsaChip(partnerObj) {
      _wRemoveMappedDsaChip();
      if (!partnerObj || !partnerObj.mappedDsaId) return;
      const dsa = (window.twDSAList||[]).find(d=>d.id===partnerObj.mappedDsaId);
      if (!dsa) return;
      const partnerGrp = document.getElementById('w-partner-group');
      if (!partnerGrp) return;
      const chip = document.createElement('div');
      chip.id = 'w-mapped-dsa-chip';
      chip.style.cssText = 'display:flex;align-items:center;gap:10px;padding:10px 14px;background:linear-gradient(135deg,var(--accent-subtle),rgba(26,79,163,.04));border:1.5px solid rgba(26,79,163,.2);border-radius:10px;margin-top:10px;animation:fadeIn .3s ease';
      chip.innerHTML = `
        <div style="width:32px;height:32px;border-radius:8px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:var(--accent);flex-shrink:0">${dsa.name.charAt(0)}</div>
        <div style="flex:1;min-width:0">
          <div style="font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);margin-bottom:2px">Mapped DSA (auto-filled)</div>
          <div style="font-size:13px;font-weight:700;color:var(--text)">${dsa.name}</div>
          <div style="font-size:11px;color:var(--text3);margin-top:1px">${dsa.code}${dsa.mobile?' · '+dsa.mobile:''}</div>
        </div>
        <span style="font-size:10.5px;padding:3px 9px;border-radius:20px;font-weight:700;background:${dsa.status==='active'?'rgba(26,115,64,.12)':'rgba(138,150,180,.12)'};color:${dsa.status==='active'?'var(--success)':'var(--text3)'}">${dsa.status==='active'?'Active':'Inactive'}</span>`;
      partnerGrp.appendChild(chip);
      // Also store dsaId in a hidden field for submitWizard to pick up
      let hidden = document.getElementById('w-partner-mapped-dsa-id');
      if (!hidden) { hidden = document.createElement('input'); hidden.type='hidden'; hidden.id='w-partner-mapped-dsa-id'; partnerGrp.appendChild(hidden); }
      hidden.value = dsa.id;

      // Refresh channel preview to show the mapped DSA
      if (typeof wUpdateChannelPreview === 'function') wUpdateChannelPreview();
    }

    function _wRemoveMappedDsaChip() {
      const c = document.getElementById('w-mapped-dsa-chip'); if(c) c.remove();
      const h = document.getElementById('w-partner-mapped-dsa-id'); if(h) h.value='';
    }

    // ── When partner selector changes, update the DSA chip ──
    (function _hookPartnerSelect() {
      function doHook() {
        const pSel = document.getElementById('w-partner-name');
        if (!pSel) { setTimeout(doHook, 400); return; }
        pSel.addEventListener('change', function() {
          const pid = this.value;
          const partner = (window.twPartnerList||[]).find(p=>p.id===pid);
          if (partner && partner.mappedDsaId) {
            wShowMappedDsaChip(partner);
          } else {
            _wRemoveMappedDsaChip();
          }
        });
      }
      if (document.readyState==='loading') document.addEventListener('DOMContentLoaded', doHook);
      else doHook();
    })();

    // When Location changes → re-populate Sales Person dropdown filtered to that location
    // mirrors create_new_loan.py get_assigned_user_domain (Sales Executive group, no team yet)
    function wLocationChange() {
      const loc = document.getElementById('w-location')?.value || '';
      const salesSel = document.getElementById('w-sales');
      if (!salesSel) return;

      // Sales executives for this location (from twUsers filtered by Sales Person / Sales Executive role)
      const salesUsers = (typeof twUsers !== 'undefined' ? twUsers : [])
        .filter(u => u.loc === loc && (u.role === 'Sales Person' || u.role === 'Team Leader'));

      salesSel.innerHTML = '<option value="">— Select Sales Person —</option>' +
        salesUsers.map(u => `<option value="${u.name}">${u.name} (${u.role})</option>`).join('');

      // Clear previous auto-assign
      const hint = document.getElementById('w-sales-hint');
      const loginGroup = null; // w-login-user-group removed
      if (hint) hint.textContent = '';
      if (loginGroup) loginGroup.style.display = 'none';
    }

    // When Sales Person changes → auto-assign Sales Team + Login User (least workload)
    // mirrors loan_application_inherit.py _assign_sales_team
    function wSalesPersonChange() {
      const loc       = document.getElementById('w-location')?.value || '';
      const salesName = document.getElementById('w-sales')?.value || '';
      const hint      = document.getElementById('w-sales-hint');
      const loginGroup= document.getElementById('w-login-user-group');
      const loginDisp = document.getElementById('w-login-user-display');

      if (!salesName || !loc) return;

      // 1. Find Sales Team — team at this location that has this person as member/leader
      const salesTeam = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : [])
        .find(t => t.location === loc && (t.leader === salesName || (t.members || []).includes(salesName)));
      if (hint) hint.textContent = salesTeam ? `Sales Team: ${salesTeam.name}` : '';

      // 2. Find Login User — least-workload operation team member at this location + loanType (Fix 2)
      // Read loanType from wizard if already selected (Step 6 field or product selector)
      const _wizLoanType = (document.getElementById('w-loantype')?.value || window._wizardLoanProduct || '').trim();

      const opTeams = (typeof twLoginTeams !== 'undefined' ? twLoginTeams : [])
        .filter(t => {
          if (t.location !== loc) return false;
          // If team has loanTypes restriction AND loanType is known, filter by it
          if (_wizLoanType && Array.isArray(t.loanTypes) && t.loanTypes.length > 0) {
            return t.loanTypes.includes(_wizLoanType);
          }
          return true; // no loanType restriction on team — include it
        });
      const loginMembers = opTeams.flatMap(t => t.members || []);

      if (!loginMembers.length) {
        if (loginGroup) loginGroup.style.display = 'none';
        return;
      }

      const activeApps = (typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : [])
        .filter(a => !['rejected','hold','cancelled','cancel','ni','disbursed'].includes(a.status)
          && a.location === loc);

      // Count active apps per login user (also filter by loanType when available — Fix 2)
      let bestUser = null, bestCount = Infinity;
      for (const member of loginMembers) {
        const cnt = activeApps.filter(a =>
          a.loginUser === member &&
          (!_wizLoanType || !a.loanType || a.loanType === _wizLoanType)
        ).length;
        if (cnt < bestCount) { bestCount = cnt; bestUser = member; }
      }

      // If nobody has any app, just pick first member
      if (!bestUser) bestUser = loginMembers[0];

      if (loginDisp) loginDisp.value = bestUser || '—';
      if (loginGroup) loginGroup.style.display = bestUser ? '' : 'none';

      // Live-update the Direct channel sales person chip if Direct is selected
      const channelVal = document.getElementById('w-channel')?.value || '';
      if (channelVal === 'direct') {
        const nameEl = document.getElementById('w-direct-sales-name');
        const aviEl  = document.getElementById('w-direct-sales-avi');
        if (nameEl) nameEl.textContent = salesName || '— Select Sales Person above —';
        if (aviEl)  aviEl.textContent  = salesName ? salesName.charAt(0).toUpperCase() : '?';
      }

      // Refresh channel preview card
      if (typeof wUpdateChannelPreview === 'function') wUpdateChannelPreview();
    }

    // Live PAN duplicate check — mirrors create_new_loan.py action_continue search
    function wPanCheck() {
      const pan = (document.getElementById('w-pan')?.value || '').trim().toUpperCase();
      const alertEl = document.getElementById('w-pan-dup-alert');
      const msgEl   = document.getElementById('w-pan-dup-msg');
      if (!pan || pan.length !== 10 || !alertEl) return;

      const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 60);
      const dup = (typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []).find(a => {
        if (a.is_draft) return false;
        if ((a.pan || '').toUpperCase() !== pan) return false;
        const d = parseAppDate(a.date);
        return d && d >= cutoff;
      });

      if (dup) {
        const stateMap = { wip:'WIP', login:'Assign Lender', underwriting:'Underwriting', approved:'Approved',
          disbursed:'Disbursed', cancelled:'Cancelled', rejected:'Rejected', hold:'Hold', ni:'NI' };
        alertEl.style.display = '';
        if (msgEl) msgEl.innerHTML = `⚠ Customer has a recent <strong>${stateMap[dup.status]||dup.status}</strong> application (${dup.id} — ${dup.name || ''}). Created within 60 days.`;
      } else {
        alertEl.style.display = 'none';
      }
    }

    // ══════════════════════════════════════════════════════════
    //  OTHER INFO SECTION — mirrors loan_application_view.xml
    //  custom_collapsible_section with assigned_user, salles_id,
    //  location_id, login_user_id, login_id
    // ══════════════════════════════════════════════════════════
    let _otherInfoOpen = true;

    function toggleOtherInfoSection() {
      _otherInfoOpen = !_otherInfoOpen;
      const content = document.getElementById('other-info-section-content');
      const icon    = document.getElementById('other-info-toggle-icon');
      if (content) content.style.display = _otherInfoOpen ? '' : 'none';
      if (icon)    icon.textContent = _otherInfoOpen ? '▾' : '▸';
    }

    function renderDetailOtherInfo(app) {
      const section  = document.getElementById('detail-other-info-section');
      const grid     = document.getElementById('detail-other-info-grid');
      if (!section || !grid) return;

      // Only show if we have any of these fields
      const hasMeta = app.sales || app.salesTeam || app.location || app.loginUser;
      section.style.display = '';  // Always show for apps with location/team info
      if (!hasMeta && !app.location) { section.style.display = 'none'; return; }

      // ── ACCESS CONTROL: Can user edit Team & Assignment fields? ──
      const canEditFields = canEditTeamAssignment(app);

      // ── SALES PERSON CELL ──
      // FIX: Admin should be able to change sales person via dropdown
      const salesPersons = (typeof twUsers !== 'undefined' ? twUsers : [])
        .filter(u => {
          const r = (u.role || '').toLowerCase();
          const isSalesPerson = r.includes('sales') || r === 'partner';
          const locMatch = !app.location || (u.locs || []).includes(app.location);
          return isSalesPerson && locMatch;
        });
      const salesPersonCell = canEditFields
        ? `<select onchange="updateSalesPerson('${app.id}',this.value)"
            style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:4px 8px;font-size:12px;color:var(--text);font-family:var(--font-body)">
            <option value="">— Select Sales Person —</option>
            ${salesPersons.map(u => `<option value="${u.name}" ${u.name===app.sales?'selected':''}>${u.name} (${u.role})</option>`).join('')}
           </select>`
        : (app.sales || '—');

      // ── SALES TEAM CELL ──
      const salesTeams = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : [])
        .filter(t => !app.location || t.location === app.location)
        .map(t => t.name);
      const salesTeamCell = canEditFields
        ? `<select onchange="updateSalesTeam('${app.id}',this.value)"
            style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:4px 8px;font-size:12px;color:var(--text);font-family:var(--font-body)">
            <option value="">— Select Sales Team —</option>
            ${salesTeams.map(t => `<option value="${t}" ${t===app.salesTeam?'selected':''}>${t}</option>`).join('')}
           </select>`
        : (app.salesTeam || '—');

      // ── LOCATION CELL ──
      const locations = (typeof twLocations !== 'undefined' ? twLocations : [])
        .map(l => l.name);
      const locationCell = canEditFields
        ? `<select onchange="updateLocation('${app.id}',this.value)"
            style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:4px 8px;font-size:12px;color:var(--text);font-family:var(--font-body)">
            <option value="">— Select Location —</option>
            ${locations.map(l => `<option value="${l}" ${l===app.location?'selected':''}>${l}</option>`).join('')}
           </select>`
        : (app.location || '—');

      // ── LOGIN USER CELL ──
      // FIX: Show all login-team/ops users; if location not set yet, show all eligible users
      const loginTeam = (typeof twLoginTeams !== 'undefined' ? twLoginTeams : [])
        .find(t => t.location === app.location && (t.members||[]).includes(app.loginUser));
      const canEditLoginUser = canChangeLoginUser(app);
      const loginUserOptions = (typeof twUsers !== 'undefined' ? twUsers : [])
        .filter(u => {
          const r = (u.role || '').toLowerCase();
          const isLoginEligible = r.includes('login') || r.includes('operation') || r === 'admin';
          const locMatch = !app.location || (u.locs || []).length === 0 || (u.locs || []).includes(app.location);
          return isLoginEligible && locMatch;
        });
      const loginUserCell = canEditLoginUser
        ? `<div style="display:flex;align-items:center;gap:8px">
            <select onchange="updateLoginUser('${app.id}',this.value)"
              style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:4px 8px;font-size:12px;color:var(--text);font-family:var(--font-body)">
              <option value="">— Select Login User —</option>
              ${loginUserOptions.map(u => `<option value="${u.name}" ${u.name===app.loginUser?'selected':''}>${u.name} (${u.role})</option>`).join('')}
            </select>
            <span style="font-size:10.5px;color:var(--text3)">is_change_login_user</span>
           </div>`
        : (app.loginUser || '—');

      // ── OPERATIONS MANAGER CELL ──
      // FIX: Show dropdown even when opsManagerId is empty so admin can assign one
      const opsManagers = (typeof twLoginTeams !== 'undefined' ? twLoginTeams : [])
        .filter(t => !app.location || t.location === app.location)
        .map(t => t.leader)
        .filter((v, i, a) => v && a.indexOf(v) === i);
      const opsManagerCell = canEditFields
        ? `<select onchange="updateOpsManager('${app.id}',this.value)"
            style="background:var(--surface2);border:1px solid var(--border);border-radius:6px;padding:4px 8px;font-size:12px;color:var(--text);font-family:var(--font-body)">
            <option value="">— Select Operations Manager —</option>
            ${opsManagers.map(m => `<option value="${m}" ${m===app.opsManagerId?'selected':''}>${m}</option>`).join('')}
           </select>`
        : (app.opsManagerId || '—');

      grid.innerHTML = fieldGrid([
        ['Sales Person',        salesPersonCell],
        ['Sales Team',          salesTeamCell],
        ['Location',            locationCell],
        ['Login User',          loginUserCell],
        ['Operations Manager',  opsManagerCell],
        ['Login Team',          loginTeam ? loginTeam.name : '—'],
      ]);
    }

    // ══════════════════════════════════════════════════════════
    //  APPROVAL DETAILS SECTION
    //  Visible to ALL roles (once app has sanction data).
    //  Editable ONLY by: partner, sales_executive
    //  All other roles see a read-only view with a lock notice.
    // ══════════════════════════════════════════════════════════
    let _approvalSectionOpen = true;

    function toggleApprovalSection() {
      _approvalSectionOpen = !_approvalSectionOpen;
      const content = document.getElementById('approval-section-content');
      const icon    = document.getElementById('approval-toggle-icon');
      if (content) content.style.display = _approvalSectionOpen ? '' : 'none';
      if (icon)    icon.textContent = _approvalSectionOpen ? '▾' : '▸';
    }

    function renderDetailApproval(app) {
      const section  = document.getElementById('detail-approval-section');
      const grid     = document.getElementById('detail-approval-grid');
      const lockLbl  = document.getElementById('approval-section-lock-label');
      if (!section || !grid) return;

      // Only show when sanction data exists
      const hasSanction = app.sanctionLoanAmt || app.sanctionEMI || app.sanctionROI;
      if (!hasSanction) { section.style.display = 'none'; return; }
      section.style.display = '';

      // Editable by whoever has access to THIS application — reuses the
      // existing app-level access/assignment check (same one used to
      // lock/unlock the rest of the detail page) instead of a fixed role list.
      const role    = currentUser.role;
      const isAdmin = role === 'admin';
      // Once the application reaches Disbursed, Rejected, Cancelled, or Hold,
      // these details are final — only admin may still edit them; every other
      // role becomes read-only regardless of assignment/task ownership.
      const isFinalStage = (typeof isAppFinalLocked === 'function') && isAppFinalLocked(app);
      const canEdit = isAdmin
        ? true
        : (!isFinalStage && !(typeof efinIsAppLocked === 'function' && efinIsAppLocked(app)));

      // Lock label
      if (lockLbl) {
        lockLbl.innerHTML = canEdit
          ? `<span style="color:var(--success);font-weight:600">✏️ You can update these details</span>`
          : isFinalStage
            ? `<span style="color:var(--text3)">🔒 View-only — application is ${STATUSES[app.status] || app.status}; only admin can edit now</span>`
            : `<span style="color:var(--text3)">🔒 View-only — you don't have access to this application</span>`;
      }

      const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
      const pct = v => v ? v + '%' : '—';
      const emiDateLabel = d => {
        if (!d) return '—';
        const n = parseInt(d);
        return n === 1 ? '1st of every Month' : n === 2 ? '2nd of every Month' : n === 3 ? '3rd of every Month' : n + 'th of every Month';
      };

      if (canEdit) {
        // ── Editable form (partner / sales_executive) ──
        grid.innerHTML = `
          <div class="form-group full" style="margin-bottom:8px">
            <div style="display:flex;align-items:center;gap:8px;padding:10px 14px;background:rgba(26,79,163,.06);border:1px solid rgba(26,79,163,.15);border-radius:10px;font-size:12px;color:var(--accent)">
              ✏️ <strong>Editable by your role.</strong>&nbsp; Changes are saved immediately to the application record.
            </div>
          </div>
          <div class="form-group">
            <label>Loan Amount (₹)</label>
            <input class="field-val" id="dv-loanamt-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionLoanAmt||''}" oninput="approvalFieldSave('${app.id}','sanctionLoanAmt',this.value,'number');dvAutoRecalc('${app.id}')">
          </div>
          <div class="form-group">
            <label>Tenure (Months)</label>
            <input class="field-val" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionTenureMo||''}" oninput="approvalFieldSave('${app.id}','sanctionTenureMo',this.value,'number')">
          </div>
          <div class="form-group">
            <label>Rate of Interest — Annual (%)</label>
            <input class="field-val" id="dv-roi-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" step="0.01" value="${app.sanctionROI||''}" oninput="approvalFieldSave('${app.id}','sanctionROI',this.value,'number');dvAutoFlatRate('${app.id}')">
          </div>
          <div class="form-group">
            <label>Flat Reducing Rate (%)</label>
            <input class="field-val" id="dv-flat-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" step="0.01" value="${app.sanctionFlatRate||''}"
              oninput="this.dataset.manual='true';approvalFieldSave('${app.id}','sanctionFlatRate',this.value,'number')"
              data-manual="${app.sanctionFlatRate ? 'true' : 'false'}">
            <div id="dv-flat-hint-${app.id}" style="font-size:10px;color:var(--text3);margin-top:3px;font-style:italic">
              ${app.sanctionFlatRate ? 'Saved value — edit to override' : 'Auto from ROI'}
            </div>
          </div>
          <div class="form-group">
            <label>Processing Fee (%)</label>
            <input class="field-val" id="dv-pfpct-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" step="0.01" value="${app.sanctionPFPct||''}" oninput="approvalFieldSave('${app.id}','sanctionPFPct',this.value,'number');dvAutoRecalc('${app.id}')">
          </div>
          <div class="form-group">
            <label>EMI (Calculated — Rounded) ₹</label>
            <input class="field-val" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionEMI||''}" oninput="approvalFieldSave('${app.id}','sanctionEMI',this.value,'number')">
          </div>
          <div class="form-group">
            <label>EMI Date</label>
            <select style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2);color:var(--text)"
              onchange="approvalFieldSave('${app.id}','sanctionEMIDate',this.value,'text')">
              ${[1,2,3,4,5,7,10,15,20,25].map(d=>`<option value="${d}" ${String(app.sanctionEMIDate||3)===String(d)?'selected':''}>${d===1?'1st':d===2?'2nd':d===3?'3rd':d+'th'} of every Month</option>`).join('')}
            </select>
          </div>
          <div class="form-group">
            <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:6px;margin-bottom:5px">
              <label style="margin-bottom:0">Insurance Amount (₹)</label>
              <button type="button" id="dv-ins-toggle-${app.id}"
                class="${app.sanctionInsInBundled ? 'ins-on' : 'ins-off'}"
                style="display:inline-flex;align-items:center;gap:5px;padding:3px 9px 3px 7px;border-radius:20px;font-size:10.5px;font-weight:700;font-family:var(--font-body);cursor:pointer;border:1.5px solid;transition:background .2s,color .2s,border-color .2s;white-space:nowrap;background:${app.sanctionInsInBundled ? 'rgba(26,79,163,.11)' : 'rgba(122,138,170,.10)'};border-color:${app.sanctionInsInBundled ? 'rgba(26,79,163,.35)' : 'rgba(122,138,170,.3)'};color:${app.sanctionInsInBundled ? 'var(--accent)' : 'var(--text3)'}"
                onclick="dvToggleIns('${app.id}')">
                <span style="width:7px;height:7px;border-radius:50%;flex-shrink:0;background:${app.sanctionInsInBundled ? 'var(--accent)' : 'var(--text3)'}"></span>
                <span id="dv-ins-txt-${app.id}">${app.sanctionInsInBundled ? '+ Insurance: ON' : '+ Insurance: OFF'}</span>
              </button>
            </div>
            <input class="field-val" id="dv-insurance-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionInsurance||''}" oninput="approvalFieldSave('${app.id}','sanctionInsurance',this.value,'number');dvAutoRecalc('${app.id}')">
          </div>
          <div class="form-group">
            <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:6px;margin-bottom:5px">
              <label style="margin-bottom:0">Bundled Loan Amount (₹)</label>
              <button type="button" id="dv-pf-toggle-${app.id}"
                class="${app.sanctionPFInBundled ? 'pf-on' : 'pf-off'}"
                style="display:inline-flex;align-items:center;gap:5px;padding:3px 9px 3px 7px;border-radius:20px;font-size:10.5px;font-weight:700;font-family:var(--font-body);cursor:pointer;border:1.5px solid;transition:background .2s,color .2s,border-color .2s;white-space:nowrap;background:${app.sanctionPFInBundled ? 'rgba(26,79,163,.11)' : 'rgba(122,138,170,.10)'};border-color:${app.sanctionPFInBundled ? 'rgba(26,79,163,.35)' : 'rgba(122,138,170,.3)'};color:${app.sanctionPFInBundled ? 'var(--accent)' : 'var(--text3)'}"
                onclick="dvTogglePF('${app.id}')">
                <span style="width:7px;height:7px;border-radius:50%;flex-shrink:0;background:${app.sanctionPFInBundled ? 'var(--accent)' : 'var(--text3)'}"></span>
                <span id="dv-pf-txt-${app.id}">${app.sanctionPFInBundled ? '+ Proc. Fee: ON' : '+ Proc. Fee: OFF'}</span>
              </button>
            </div>
            <input class="field-val" id="dv-bundled-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionBundled||''}" oninput="approvalFieldSave('${app.id}','sanctionBundled',this.value,'number')">
          </div>
          <div class="form-group">
            <label>BT (Balance Transfer)</label>
            <select style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2);color:var(--text)"
              onchange="approvalFieldSave('${app.id}','sanctionBT',this.value,'text')">
              <option value="NO" ${(app.sanctionBT||'NO')==='NO'?'selected':''}>NO</option>
              <option value="YES" ${app.sanctionBT==='YES'?'selected':''}>YES</option>
            </select>
          </div>
          <div class="form-group">
            <label>GST Applicable (%)</label>
            <input class="field-val" id="dv-gst-${app.id}" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="number" value="${app.sanctionGST||18}" oninput="approvalFieldSave('${app.id}','sanctionGST',this.value,'number');dvAutoRecalc('${app.id}')">
          </div>
          <div class="form-group">
            <label>Stamp Duty</label>
            <input class="field-val" style="border:1px solid var(--border);border-radius:8px;padding:7px 10px;width:100%;font-size:13px;background:var(--surface2)"
              type="text" value="${app.sanctionStamp||'As per government applicable'}" oninput="approvalFieldSave('${app.id}','sanctionStamp',this.value,'text')">
          </div>
        `;
      } else {
        // ── Read-only view for users without access to this application ──
        grid.innerHTML = fieldGrid([
          ['Your Loan Amount',      fmt(app.sanctionLoanAmt)],
          ['Tenure (Years)',        app.sanctionTenureYr  ? app.sanctionTenureYr + ' yrs'   : '—'],
          ['Tenure (Months)',       app.sanctionTenureMo  ? app.sanctionTenureMo + ' months' : '—'],
          ['Rate of Interest (Annual)', pct(app.sanctionROI)],
          ['Flat Reducing Rate',    pct(app.sanctionFlatRate)],
          ['Processing Fee',        pct(app.sanctionPFPct)],
          ['EMI (Calculated)',      fmt(app.sanctionEMI)],
          ['EMI Date',              emiDateLabel(app.sanctionEMIDate)],
          ['Insurance',             fmt(app.sanctionInsurance)],
          ['Bundled Loan Amount',   fmt(app.sanctionBundled)],
          ['Proc. Fee in Bundled',  app.sanctionPFInBundled  ? '✅ Included' : '—  Excluded'],
          ['Insurance in Bundled',   app.sanctionInsInBundled ? '✅ Included' : '—  Excluded'],
          ['BT (Balance Transfer)', app.sanctionBT || '—'],
          ['GST Applicable',        pct(app.sanctionGST)],
          ['Stamp Duty',            app.sanctionStamp || '—'],
        ]);
      }
    }

    // Save individual approval field — triggered by partner / sales_executive inline edits
    function approvalFieldSave(appId, field, rawVal, type) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      const val = type === 'number' ? (parseFloat(rawVal) || 0) : rawVal;
      app[field] = val;
      // Debounced toast so it doesn't fire on every keystroke
      clearTimeout(approvalFieldSave._t);
      approvalFieldSave._t = setTimeout(() => showToast('Approval detail updated', 'success'), 900);
    }

    // Auto-calc flat rate from ROI in detail view (partner/sales editable section)
    function dvAutoFlatRate(appId) {
      const flatEl  = document.getElementById('dv-flat-' + appId);
      const hintEl  = document.getElementById('dv-flat-hint-' + appId);
      const roiEl   = document.getElementById('dv-roi-' + appId);
      if (!flatEl || !roiEl) return;
      if (flatEl.dataset.manual === 'true') return; // user has overridden
      const roi = parseFloat(roiEl.value) || 0;
      if (!roi) { if (hintEl) hintEl.textContent = 'Auto from ROI'; return; }
      // Exact reducing-balance → flat rate conversion (tenure-aware).
      // Formula: FlatRate = TotalInterest / (P * n/12), P cancels → depends only on ROI & tenure.
      var app_dv  = APPLICATIONS.find(function(a){ return a.id === appId; });
      var n_dv    = parseFloat((document.getElementById('dv-tenuremo-' + appId) || {}).value)
                 || (app_dv && app_dv.sanctionTenureMo) || (app_dv && parseFloat(app_dv.tenure)) || 36;
      var r_dv      = roi / 12 / 100;
      var factor_dv = Math.pow(1 + r_dv, n_dv);
      var emiPR_dv  = r_dv > 0 ? (r_dv * factor_dv / (factor_dv - 1)) : (1 / n_dv);
      var autoFlat  = +((emiPR_dv * n_dv - 1) / (n_dv / 12) * 100).toFixed(2);
      flatEl.value = autoFlat;
      approvalFieldSave(appId, 'sanctionFlatRate', autoFlat, 'number');
      if (hintEl) {
        hintEl.style.color = 'var(--accent)'; hintEl.style.fontStyle = 'normal'; hintEl.style.fontWeight = '600';
        hintEl.textContent = 'Auto-calculated from ROI ' + roi + '%';
        clearTimeout(hintEl._t);
        hintEl._t = setTimeout(() => {
          hintEl.style.color = ''; hintEl.style.fontStyle = ''; hintEl.style.fontWeight = '';
          hintEl.textContent = 'Edit to override';
        }, 2600);
      }
      dvAutoRecalc(appId);
    }

    // Recalculate bundled loan amount in detail view when any source field changes
    function dvAutoRecalc(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      const bundledEl  = document.getElementById('dv-bundled-'  + appId);
      const toggleEl   = document.getElementById('dv-pf-toggle-' + appId);
      if (!bundledEl) return;
      const amt       = parseFloat(document.getElementById('dv-loanamt-'   + appId)?.value) || app.sanctionLoanAmt   || 0;
      const pfPct     = parseFloat(document.getElementById('dv-pfpct-'     + appId)?.value) || app.sanctionPFPct     || 0;
      const insurance = parseFloat(document.getElementById('dv-insurance-' + appId)?.value) || app.sanctionInsurance || 0;
      const gst       = parseFloat(document.getElementById('dv-gst-'       + appId)?.value) || app.sanctionGST       || 18;
      const pfOn      = toggleEl ? toggleEl.classList.contains('pf-on') : !!app.sanctionPFInBundled;
      const insToggleDV = document.getElementById('dv-ins-toggle-' + appId);
      const insOn     = insToggleDV ? insToggleDV.classList.contains('ins-on') : !!app.sanctionInsInBundled;
      const pf        = amt * pfPct / 100;
      const pfWithGst = pf * (1 + gst / 100);
      const bundled   = Math.round(amt + (pfOn ? pfWithGst : 0) + (insOn ? insurance : 0));
      if (bundled > 0) {
        bundledEl.value = bundled;
        approvalFieldSave(appId, 'sanctionBundled', bundled, 'number');
      }
    }

    // Toggle Insurance inclusion in Bundled — detail view inline
    function dvToggleIns(appId) {
      const app     = APPLICATIONS.find(a => a.id === appId);
      const btn     = document.getElementById('dv-ins-toggle-' + appId);
      const txt     = document.getElementById('dv-ins-txt-'    + appId);
      if (!btn || !app) return;
      const isOn  = btn.classList.contains('ins-on');
      const nowOn = !isOn;
      btn.classList.toggle('ins-on',   nowOn);
      btn.classList.toggle('ins-off', !nowOn);
      btn.style.background    = nowOn ? 'rgba(26,79,163,.11)' : 'rgba(122,138,170,.10)';
      btn.style.borderColor   = nowOn ? 'rgba(26,79,163,.35)' : 'rgba(122,138,170,.3)';
      btn.style.color         = nowOn ? 'var(--accent)'       : 'var(--text3)';
      const dot = btn.querySelector('span');
      if (dot) dot.style.background = nowOn ? 'var(--accent)' : 'var(--text3)';
      if (txt) txt.textContent = nowOn ? '+ Insurance: ON' : '+ Insurance: OFF';
      app.sanctionInsInBundled = nowOn;
      approvalFieldSave(appId, 'sanctionInsInBundled', nowOn, 'text');
      dvAutoRecalc(appId);
    }

    // Toggle PF inclusion in Bundled — detail view inline
    function dvTogglePF(appId) {
      const app     = APPLICATIONS.find(a => a.id === appId);
      const btn     = document.getElementById('dv-pf-toggle-' + appId);
      const txt     = document.getElementById('dv-pf-txt-'    + appId);
      if (!btn || !app) return;
      const isOn = btn.classList.contains('pf-on');
      const nowOn = !isOn;
      btn.classList.toggle('pf-on',   nowOn);
      btn.classList.toggle('pf-off', !nowOn);
      btn.style.background    = nowOn ? 'rgba(26,79,163,.11)' : 'rgba(122,138,170,.10)';
      btn.style.borderColor   = nowOn ? 'rgba(26,79,163,.35)' : 'rgba(122,138,170,.3)';
      btn.style.color         = nowOn ? 'var(--accent)'       : 'var(--text3)';
      const dot = btn.querySelector('span');
      if (dot) dot.style.background = nowOn ? 'var(--accent)' : 'var(--text3)';
      if (txt) txt.textContent = nowOn ? '+ Proc. Fee: ON' : '+ Proc. Fee: OFF';
      app.sanctionPFInBundled = nowOn;
      approvalFieldSave(appId, 'sanctionPFInBundled', nowOn, 'text');
      dvAutoRecalc(appId);
    }

    // Update login user on app and re-render Other Info section
    function updateLoginUser(appId, userName) {
      const app = APPLICATIONS.find(a => a.id === appId); if (!app) return;
      app.loginUser = userName;
      // Re-compute login team from twLoginTeams
      const opTeam = (typeof twLoginTeams !== 'undefined' ? twLoginTeams : [])
        .find(t => t.location === app.location && (t.members||[]).includes(userName));
      // Log to tracking
      addTrackingEntry(app, 'Login User Changed', 'System Comments',
        `Login User updated to: ${userName}${opTeam ? ' (Team: '+opTeam.name+')' : ''}`, '');
      showToast(`Login User updated to ${userName}`, 'success');
    }

