    // ── Employment Type change — show/hide relevant field groups ──
    // ─────────────────────────────────────────────────────────────────────
    //  EMPLOYMENT TYPE OPTION FILTER
    //  Rules (exclusively per product):
    //    personal_loan  → hide "Self Employed"  (SELFEMP option removed)
    //    business_loan  → hide "Salaried"        (SALARIED option removed)
    //    all others     → all three options visible
    //
    //  If the currently-selected value becomes invalid after filtering,
    //  the first available option is auto-selected and wOnEmpTypeChange()
    //  is re-triggered so downstream field visibility stays consistent.
    // ─────────────────────────────────────────────────────────────────────
    function wFilterEmpTypeOptions(productKey) {
      const sel = document.getElementById('w-emptype');
      if (!sel) return;

      // Resolve the product the SAME way the rest of the wizard does (see
      // getActiveWizardSteps): _selectedLoanProduct is the authoritative source.
      // This guarantees the Employment Type options always match the wizard's
      // active product even when the caller passes an empty key (e.g. w-loantype
      // value not yet reflected, or an entry path that skipped applyProductToWizard).
      // Previously an empty key fell through to "show all", which is exactly why
      // Personal/Business loans were showing every option.
      productKey = productKey
        || (typeof _selectedLoanProduct !== 'undefined' && _selectedLoanProduct)
        || document.getElementById('w-loantype')?.value
        || window._wizardLoanProduct
        || 'personal_loan';

      const isPersonalLoan = productKey === 'personal_loan';
      const isBusinessLoan = productKey === 'business_loan';

      // Rebuild the options list from scratch so toggling products is idempotent
      const ALL_OPTIONS = [
        { value: '',             label: 'Select' },
        { value: 'SALARIED',    label: 'Salaried' },
        { value: 'SELFEMP',     label: 'Self Employed' },
        { value: 'PROFESSIONAL',label: 'Professional' },
      ];

      // Determine which values to hide for this product
      const hiddenValues = new Set(
        isPersonalLoan ? ['SELFEMP']   :   // Personal Loan: no Self Employed
        isBusinessLoan ? ['SALARIED']  :   // Business Loan: no Salaried
        []                                  // All other products: show all
      );

      const currentVal = sel.value;
      sel.innerHTML = '';

      ALL_OPTIONS.forEach(opt => {
        if (hiddenValues.has(opt.value)) return;  // skip hidden option
        const o = document.createElement('option');
        o.value = opt.value;
        o.textContent = opt.label;
        sel.appendChild(o);
      });

      // If the previously-selected value is now hidden, fall back to the
      // first valid non-empty option so the form is never in an invalid state
      const stillValid = [...sel.options].some(o => o.value === currentVal);
      if (!stillValid) {
        const fallback = [...sel.options].find(o => o.value !== '');
        sel.value = fallback ? fallback.value : '';
        // Re-trigger downstream visibility (field blocks, labels, etc.)
        if (typeof wOnEmpTypeChange === 'function') wOnEmpTypeChange();
      }
    }

    // Co-Applicant section (step 3) visibility + required-ness, driven by loan product.
    //   Home Loan / LAP     → shown, mandatory (Name, PAN, Aadhaar, Mobile)
    //   Business Loan       → shown, optional
    //   All other products  → hidden entirely (zero change to their existing flow)
    function wToggleCoApplicantSection(productKey) {
      const section = document.getElementById('wstep3-coapp-section');
      if (!section) return;
      const mandatoryFor = ['home_loan', 'loan_against_property'];
      const optionalFor  = ['business_loan'];
      const isMandatory = mandatoryFor.includes(productKey);
      const isOptional  = optionalFor.includes(productKey);
      const show = isMandatory || isOptional;
      section.style.display = show ? '' : 'none';
      if (!show) return;

      const badge = document.getElementById('wstep3-coapp-required-badge');
      const note  = document.getElementById('wstep3-coapp-note');
      if (badge) badge.textContent = isMandatory ? '*' : '(Optional)';
      if (note) {
        note.style.display = isMandatory ? '' : 'none';
      }
      ['name', 'pan', 'aadhar', 'mobile'].forEach(f => {
        const req = document.getElementById('wstep3-coapp-' + f + '-req');
        if (req) req.textContent = isMandatory ? '*' : '';
      });
    }

    function wOnEmpTypeChange() {
      const empType = (document.getElementById('w-emptype')?.value || '').toUpperCase();
      // Refresh workflow note for current product + new emp type
      const loanTypeSel = document.getElementById('w-loantype');
      if (loanTypeSel && loanTypeSel.value && typeof getWorkflow === 'function') {
        const wfN = getWorkflow(loanTypeSel.value, empType);
        const wfNEl = document.getElementById('wiz-workflow-note');
        if (wfNEl) {
          if (wfN.empNote) { wfNEl.textContent = '💡 ' + wfN.empNote; wfNEl.style.display = ''; }
          else { wfNEl.style.display = 'none'; }
        }
      }
      const isSalaried    = empType === 'SALARIED';
      const isSelf        = empType === 'SELFEMP';
      const isProfessional = empType === 'PROFESSIONAL';
      const isAny         = isSalaried || isSelf || isProfessional;

      const show = (id, vis) => { const el = document.getElementById(id); if (el) el.style.display = vis ? '' : 'none'; };

      // Show the correct section
      show('w-emp-salaried',  isSalaried);
      show('w-emp-selfprof',  isSelf || isProfessional);

      // Salary label
      const salLbl = document.getElementById('w-salary-label');
      if (salLbl) {
        salLbl.textContent = isSalaried
          ? 'Net Monthly Salary (₹) *'
          : isProfessional
            ? 'Net Monthly Income (₹) *'
            : 'Gross Monthly Income (₹) *';
      }
      // Designation label
      const desigLbl = document.getElementById('w-desig-label');
      if (desigLbl) {
        desigLbl.textContent = (isProfessional ? 'Profession / Specialisation' : 'Designation') + ' *';
      }

      // Business name label
      const bizNameLbl = document.getElementById('w-biz-name-label');
      if (bizNameLbl) {
        bizNameLbl.textContent = isProfessional ? 'Practice / Clinic / Firm Name' : 'Business / Firm Name';
      }

      // Professional body — only for Professional
      show('w-prof-body-wrap', isProfessional);

      // Business type — not relevant for Professional
      show('w-biz-type-wrap', isSelf);

      // If no type selected, hide both blocks
      if (!isAny) {
        show('w-emp-salaried', false);
        show('w-emp-selfprof', false);
      }
    }






