    // ── Validate official email in wizard before proceeding from Step 5 ──
    // Official Email ID is ALWAYS mandatory.
    function wValidateOfficeEmail() {
      const inp  = document.getElementById('w-empcode');
      const hint = document.getElementById('w-officeemail-hint');
      if (!inp) return true;
      // Salaried-only field (inside w-emp-salaried) — skip validation entirely
      // when hidden, e.g. for Professional/Self-Employed employment types.
      if (inp.closest('.form-group')?.offsetParent === null) return true;
      const val = inp.value.trim();
      if (!val) {
        if (hint) { hint.style.display = ''; hint.textContent = '⚠️ Official Email ID is required'; }
        inp.style.borderColor = 'var(--danger)';
        inp.focus();
        return false;
      }
      if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(val)) {
        if (hint) { hint.style.display = ''; hint.textContent = '⚠️ Enter a valid email address'; }
        inp.style.borderColor = 'var(--danger)';
        inp.focus();
        return false;
      }
      if (hint) hint.style.display = 'none';
      inp.style.borderColor = '';
      return true;
    }

