    function addCustomDoc(input) {
      if (!input.files[0]) return;
      const file = input.files[0];
      const wrap = document.getElementById('doc-upload-list');
      if (!wrap) return;
      const uid = 'docitem-custom-' + Math.random().toString(36).slice(2, 8);

      // Custom palette (falls back gracefully if palette not loaded)
      const pal = (window._DOC_CAT_PALETTE && _DOC_CAT_PALETTE.custom) || { bg:'#fef2e8', bd:'#fdba74', accent:'#c2410c', accent2:'#ea580c', light:'#fff7ed' };

      // Find or create a "Custom Documents" group section
      let customGroup = document.querySelector('[data-doc-group="custom"]');
      if (!customGroup) {
        customGroup = document.createElement('div');
        customGroup.setAttribute('data-doc-group', 'custom');
        customGroup.style.cssText = `margin-bottom:16px;padding:14px 14px 10px;background:${pal.light};border-radius:16px;border:1px solid ${pal.bd};position:relative;overflow:hidden`;
        customGroup.innerHTML = `<div style="position:absolute;left:0;top:0;bottom:0;width:3px;background:linear-gradient(180deg,${pal.accent},${pal.accent2})"></div>
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding:0 4px 8px;border-bottom:1px solid ${pal.bd}">
            <div style="width:28px;height:28px;border-radius:8px;background:${pal.bg};display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:14px;border:1px solid ${pal.bd}">📎</div>
            <div style="flex:1;min-width:0">
              <div style="font-size:11.5px;font-weight:800;color:${pal.accent};text-transform:uppercase;letter-spacing:.8px;line-height:1.2">Custom Documents</div>
              <div style="font-size:10px;color:${pal.accent2};margin-top:1px;font-weight:500;opacity:.85">Additional documents uploaded by user</div>
            </div>
            <span id="custom-doc-count" style="font-size:10px;color:#fff;background:linear-gradient(135deg,${pal.accent},${pal.accent2});padding:3px 10px;border-radius:20px;font-weight:700;letter-spacing:.4px;box-shadow:0 2px 6px ${pal.accent2}30;flex-shrink:0">0 DOCS</span>
          </div>`;
        const empty = document.getElementById('doc-empty-search');
        if (empty) wrap.insertBefore(customGroup, empty); else wrap.appendChild(customGroup);
      }

      const div = document.createElement('div');
      div.className = 'doc-item';
      div.id = uid;
      div.style.cssText = `display:flex;align-items:center;gap:13px;padding:13px 15px;border-radius:12px;border:1.5px dashed ${pal.bd};background:#fff;margin-bottom:8px;transition:all .2s`;
      div.innerHTML = `<div style="width:42px;height:42px;border-radius:11px;background:linear-gradient(135deg,${pal.accent},${pal.accent2});display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:19px;color:#fff;box-shadow:0 3px 8px ${pal.accent2}30">📎</div>
        <div class="doc-info" style="flex:1;min-width:0">
          <div class="doc-name" style="font-size:13.5px;font-weight:700;color:var(--text);line-height:1.35">${file.name}</div>
          <div class="doc-type" style="font-size:10.5px;color:var(--text3);margin-top:3px;font-weight:500;display:flex;align-items:center;gap:5px">
            <span style="color:${pal.accent};font-size:9px">●</span>
            <span>Custom document · ${(file.size/1024).toFixed(0)} KB</span>
          </div>
        </div>
        <span id="doc-status-${uid}" style="font-size:9.5px;font-weight:800;padding:4px 10px;border-radius:20px;background:${pal.bg};color:${pal.accent};border:1px solid ${pal.bd};flex-shrink:0;letter-spacing:.6px">UPLOADING</span>
        <label class="btn btn-ghost btn-sm" style="cursor:pointer;flex-shrink:0;font-size:11.5px;border-color:${pal.bd};color:${pal.accent};background:${pal.light};font-weight:600">↻ Replace<input type="file" style="display:none" onchange="markDocUploaded(this,'${file.name.replace(/'/g,"\\'")}');_docUpdateProgress()"></label>`;
      customGroup.appendChild(div);

      // Update count badge
      const countEl = document.getElementById('custom-doc-count');
      if (countEl) { const n = customGroup.querySelectorAll('.doc-item').length; countEl.textContent = n + ' DOC' + (n === 1 ? '' : 'S'); }

      // Check if password-protected PDF, then commit
      const fakeItem = div;
      fakeItem.id = uid;
      const isPdfCustom = file.type === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
      if (isPdfCustom && typeof pdfjsLib !== 'undefined' && typeof _docPasswordPrompt !== 'undefined') {
        file.arrayBuffer().then(function(buf) {
          const bytes = new Uint8Array(buf);
          pdfjsLib.getDocument({ data: bytes }).promise
            .then(function() { _docMarkUploaded_commit(fakeItem, file, file.name); })
            .catch(function(err) {
              if (err.name === 'PasswordException' || String(err.message).toLowerCase().includes('password')) {
                _docPasswordPrompt(file, file.name,
                  function(pw) { _docMarkUploaded_commit(fakeItem, file, file.name, pw); },
                  function()   { _docMarkUploaded_commit(fakeItem, file, file.name); }
                );
              } else {
                _docMarkUploaded_commit(fakeItem, file, file.name);
              }
            });
        }).catch(function() { _docMarkUploaded_commit(fakeItem, file, file.name); });
      } else {
        _docMarkUploaded_commit(fakeItem, file, file.name);
      }
    }
    // ── Binary-field attachment store (mirrors ir.attachment) ──
    // _BFP_STORE persists across openDetail calls intentionally (task attachments live here).
    // Only reset wizard doc keys when the wizard is freshly started.
    if (!window._BFP_STORE) window._BFP_STORE = {};
    // Clear only wizard-specific keys from previous sessions (not task attachments)
    Object.keys(window._BFP_STORE).forEach(function(k) {
      if (k.startsWith('docitem-wiz-') || k.startsWith('docitem-custom-')) delete window._BFP_STORE[k];
    }); // selective wizard reset — key: doc-item id → {name, mimetype, url (object URL)}

    function markDocUploaded(input, name) {
      if (!input.files || !input.files.length) return;
      // ── Bank statement: always route through Perfios v9 popup ──
      if (/bank statement|banking/i.test(name)) {
        const item = input.closest ? input.closest('.doc-item') : null;
        if (typeof pfv9Open === 'function') pfv9Open(item ? item.id : '', name);
        return;
      }
      const item = input.closest('.doc-item');
      if (!item) return;
      if (!item.id) item.id = 'docitem-' + Math.random().toString(36).slice(2, 8);

      // Process each selected file
      const files = Array.from(input.files);
      // Reset the store ONCE up-front so every file (sync or async PDF) just appends.
      // This avoids a race where an async PDF at idx 0 commits last and wipes
      // files that already committed — the cause of "only one file attached".
      if (!item.id) item.id = 'docitem-' + Math.random().toString(36).slice(2, 8);
      window._BFP_STORE[item.id] = {
        name: files[0] ? files[0].name : name,
        mimetype: files[0] ? (files[0].type || 'application/octet-stream') : '',
        url: '', isImage: false, isPdf: false, pdfPassword: null, files: []
      };
      function processFile(file, idx) {
        const isPdf = file.type === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
        if (isPdf && typeof pdfjsLib !== 'undefined') {
          file.arrayBuffer().then(function(buf) {
            const bytes = new Uint8Array(buf);
            pdfjsLib.getDocument({ data: bytes }).promise.then(function() {
              _docMarkUploaded_commit(item, file, name, null, idx, files.length);
            }).catch(function(err) {
              if (err.name === 'PasswordException' || String(err.message).toLowerCase().includes('password')) {
                _docShowPasswordPrompt(item, file, name, bytes);
              } else {
                _docMarkUploaded_commit(item, file, name, null, idx, files.length);
              }
            });
          }).catch(function() {
            _docMarkUploaded_commit(item, file, name, null, idx, files.length);
          });
        } else {
          _docMarkUploaded_commit(item, file, name, null, idx, files.length);
        }
      }
      files.forEach(function(f, i) { processFile(f, i); });
    }

    // ── Show inline password prompt on a doc-item ──
    function _docShowPasswordPrompt(item, file, name, pdfBytes) {
      // Mark item as "pending password" visually
      item.style.borderColor  = '#f59e0b';
      item.style.borderStyle  = 'solid';
      item.style.background   = 'linear-gradient(135deg,#fffbeb,#fef3c7)';
      item.style.boxShadow    = '0 3px 10px rgba(245,158,11,.14)';
      const typeEl = item.querySelector('.doc-type');
      if (typeEl) typeEl.innerHTML = `<span style="color:#b45309;font-size:9px">●</span> <span style="color:#b45309;font-weight:600">🔒 Password-protected PDF — ${file.name}</span>`;
      const statusEl = item.querySelector('[id^="doc-status-"]');
      if (statusEl) {
        statusEl.textContent = '🔒 LOCKED';
        statusEl.style.cssText = 'font-size:9.5px;font-weight:800;padding:4px 10px;border-radius:20px;background:#fef3c7;color:#b45309;border:1px solid #fcd34d;flex-shrink:0;letter-spacing:.6px';
      }

      // Remove any existing password row to avoid duplicates on re-upload
      const existing = item.querySelector('.doc-pw-row');
      if (existing) existing.remove();

      // Build the password row — sits below the main row inside the doc-item flex layout
      const pwRow = document.createElement('div');
      pwRow.className = 'doc-pw-row show';
      const pwId  = 'docpw-' + item.id;
      const stsId = 'docpws-' + item.id;
      pwRow.innerHTML = `
        <label for="${pwId}">🔒 PDF Password:</label>
        <input type="password" id="${pwId}" placeholder="Enter document password…"
               onkeydown="if(event.key==='Enter'){event.preventDefault();_docUnlockPdf('${item.id}');}"/>
        <button class="doc-pw-btn" onclick="_docUnlockPdf('${item.id}')">Unlock</button>
        <span class="doc-pw-status" id="${stsId}"></span>`;

      // Store file bytes on the item element for retrieval by _docUnlockPdf
      item._pendingPdfBytes = pdfBytes;
      item._pendingPdfFile  = file;
      item._pendingDocName  = name;

      // Make item a flex-column so the password row sits below the main content
      item.style.flexWrap = 'wrap';
      item.appendChild(pwRow);

      // Auto-focus after paint
      setTimeout(function() {
        const inp = document.getElementById(pwId);
        if (inp) inp.focus();
      }, 80);
    }

    // ── Unlock a password-protected doc-item PDF ──
    window._docUnlockPdf = function(itemId) {
      const item  = document.getElementById(itemId);
      if (!item) return;
      const bytes = item._pendingPdfBytes;
      const file  = item._pendingPdfFile;
      const name  = item._pendingDocName;
      if (!bytes || !file) return;

      const pwInput = document.getElementById('docpw-' + itemId);
      const stsEl   = document.getElementById('docpws-' + itemId);
      const pw = pwInput ? pwInput.value : '';

      if (stsEl) { stsEl.textContent = '⏳ Unlocking…'; stsEl.style.color = 'var(--text3)'; }

      // Pass a .slice() copy — pdf.js detaches the ArrayBuffer, so we preserve
      // item._pendingPdfBytes intact for retry attempts with a different password.
      pdfjsLib.getDocument({ data: bytes.slice(), password: pw }).promise.then(function() {
        // ── Correct password — commit upload, store password alongside file ──
        const pwRow = item.querySelector('.doc-pw-row');
        if (pwRow) pwRow.remove();

        // Persist the password so downstream processes can re-open the file
        if (!item.id) item.id = itemId;
        if (!window._BFP_STORE) window._BFP_STORE = {};
        // _docMarkUploaded_commit will store file; add password entry separately
        _docMarkUploaded_commit(item, file, name, pw);

        // Clean up temporary state
        delete item._pendingPdfBytes;
        delete item._pendingPdfFile;
        delete item._pendingDocName;

        // Flash the item green to confirm success
        setTimeout(function() {
          item.style.transition  = 'border-color .2s, box-shadow .2s, background .2s';
          item.style.borderColor = '#10b981';
          item.style.boxShadow   = '0 0 0 3px rgba(16,185,129,.18)';
          setTimeout(function() {
            item.style.borderColor = '';
            item.style.boxShadow   = '';
          }, 1600);
        }, 100);

      }).catch(function(err) {
        // ── Wrong password ──
        if (stsEl) { stsEl.textContent = '❌ Wrong password'; stsEl.style.color = '#ef4444'; }
        if (pwInput) {
          pwInput.style.borderColor = '#ef4444';
          pwInput.select();
          setTimeout(function() { pwInput.style.borderColor = ''; }, 1400);
        }
      });
    };

    // ── Core upload commit (called after password check passes or for non-protected files) ──
    function _docMarkUploaded_commit(item, file, name, pdfPassword, fileIdx, totalFiles) {
      const mimetype = file.type || 'application/octet-stream';
      const isImage  = mimetype.startsWith('image/');
      const isPdf    = mimetype === 'application/pdf' || file.name.toLowerCase().endsWith('.pdf');
      const objUrl   = URL.createObjectURL(file);

      if (!item.id) item.id = 'docitem-' + Math.random().toString(36).slice(2, 8);

      // Append to files array in store (store is initialised once up-front in
      // markDocUploaded, so every file — sync or async — simply appends here).
      var store = window._BFP_STORE[item.id];
      if (!store) {  // safety: re-uploads / password path may call directly
        store = { name: file.name, mimetype, url: objUrl, isImage, isPdf, pdfPassword: pdfPassword || null, files: [] };
        window._BFP_STORE[item.id] = store;
      }
      // Keep top-level metadata pointing at the first attached file
      if (!store.files.length) { store.name = file.name; store.mimetype = mimetype; store.url = objUrl; store.isImage = isImage; store.isPdf = isPdf; store.pdfPassword = pdfPassword || null; }
      store.files.push({ name: file.name, mimetype, url: objUrl, isImage, isPdf, pdfPassword: pdfPassword || null });

      // ── Update UI — green success styling ──
      item.style.borderColor  = '#10b981';
      item.style.borderStyle  = 'solid';
      item.style.borderWidth  = '1.5px';
      item.style.background   = 'linear-gradient(135deg,#f0faf3,#ecfdf5)';
      item.style.boxShadow    = '0 3px 10px rgba(16,185,129,.12)';
      item.style.flexWrap     = 'wrap';

      var fileCount = store.files.length;
      const typeEl = item.querySelector('.doc-type');
      if (typeEl) {
        if (fileCount === 1) {
          typeEl.innerHTML = '<span style="color:var(--success);font-size:9px">●</span> <span style="color:var(--success);font-weight:600">📎 ' + file.name + (pdfPassword ? ' · 🔓 Password saved' : '') + '</span>';
        } else {
          typeEl.innerHTML = '<span style="color:var(--success);font-size:9px">●</span> <span style="color:var(--success);font-weight:600">📎 ' + fileCount + ' files attached</span>';
        }
      }
      const statusEl = item.querySelector('[id^="doc-status-"]');
      if (statusEl) {
        statusEl.textContent = '✓ UPLOADED' + (fileCount > 1 ? ' (' + fileCount + ')' : '');
        statusEl.style.cssText = 'font-size:9.5px;font-weight:800;padding:4px 10px;border-radius:20px;background:linear-gradient(135deg,#059669,#10b981);color:#fff;border:1px solid #10b981;flex-shrink:0;letter-spacing:.6px;box-shadow:0 2px 6px rgba(16,185,129,.28)';
      }

      // Build file list chips below the doc-item main row
      var chipWrap = item.querySelector('.doc-multi-files');
      if (!chipWrap) {
        chipWrap = document.createElement('div');
        chipWrap.className = 'doc-multi-files';
        chipWrap.style.cssText = 'display:flex;flex-wrap:wrap;gap:4px;padding:6px 0 0;margin-top:6px;border-top:1px dashed rgba(16,185,129,.3);flex-basis:100%;width:100%';
        item.appendChild(chipWrap);
      }
      // Rebuild the chip list from the store every time (order-independent).
      chipWrap.innerHTML = '';
      store.files.forEach(function(f) {
        var chip = document.createElement('span');
        chip.style.cssText = 'font-size:10px;padding:3px 8px;border-radius:12px;background:rgba(16,185,129,.1);color:var(--success);font-weight:600;display:inline-flex;align-items:center;gap:3px;max-width:200px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap';
        chip.textContent = '📄 ' + f.name;
        chip.title = f.name;
        chipWrap.appendChild(chip);
      });
      if (fileCount <= 1) chipWrap.style.display = 'none';
      else chipWrap.style.display = 'flex';

      // Show View & Delete buttons
      const viewBtn = item.querySelector('.doc-view-btn');
      const delBtn  = item.querySelector('.doc-del-btn');
      if (viewBtn) viewBtn.style.display = '';
      if (delBtn)  delBtn.style.display  = '';

      // Eye preview button
      let eyeBtn = item.querySelector('.preview-btn-eye');
      if (!eyeBtn) {
        const uploadLabel = item.querySelector('label.btn');
        if (uploadLabel) {
          eyeBtn = document.createElement('button');
          eyeBtn.className = 'preview-btn-eye';
          eyeBtn.title = 'Preview attachment';
          eyeBtn.innerHTML = '👁';
          eyeBtn.addEventListener('click', function(e) {
            e.preventDefault();
            openPreviewModal(item.id);
          });
          item.insertBefore(eyeBtn, uploadLabel);
        }
      }

      // Capture dataUrl via FileReader
      const _fr = new FileReader();
      _fr.onload = function(ev) {
        if (window._BFP_STORE[item.id]) {
          window._BFP_STORE[item.id].dataUrl = ev.target.result;
          var fi = store.files.length - 1;
          if (store.files[fi]) store.files[fi].dataUrl = ev.target.result;
        }
      };
      _fr.readAsDataURL(file);

      showToast(name + ' — ' + file.name + ' uploaded ✓' + (pdfPassword ? ' (password saved)' : '') + (fileCount > 1 ? ' (' + fileCount + ' total)' : ''), 'success');
      if (typeof _docUpdateProgress === 'function') _docUpdateProgress();

      // Show password-stored badge on the item if a password was provided
      if (pdfPassword) _docShowPasswordBadge(item, file.name);
    }

    // ── Append a small "🔐 Password saved" badge to a doc-item ──
    function _docShowPasswordBadge(item, fileName) {
      if (!item) return;
      // Avoid duplicates
      if (item.querySelector('.doc-pw-badge')) return;
      const badge = document.createElement('span');
      badge.className   = 'doc-pw-badge';
      badge.title       = 'Password stored securely for: ' + fileName;
      badge.textContent = '🔐 Password saved';
      // Insert after the status pill if present, otherwise append
      const statusEl = item.querySelector('[id^="doc-status-"]');
      if (statusEl) statusEl.insertAdjacentElement('afterend', badge);
      else item.appendChild(badge);
    }

    // ═══════════════════════════════════════════════════════════════
    //  ENHANCED DOCUMENT CHECKLIST — Step 8 of wizard
    //  Features: progress bar, search, category grouping, per-doc icons,
    //  drag-and-drop, optional tagging, live upload counters
    // ═══════════════════════════════════════════════════════════════

    // Infer icon + category from a document label
    function _docInferMeta(label) {
      const l = label.toLowerCase();
      // Relocated to "Other Documents" per requirement — this exact label only.
      // All other Form 16 / ITR document variants elsewhere in the app are
      // unaffected and continue to categorize under "Income & Employment" below.
      if (label === 'Latest Form 16 / ITR (Last 2 years)')
        return { icon: '📄', category: 'Other Documents', catKey: 'other' };
      // Optional / miscellaneous docs — grouped as "Other Docs"
      if (/\(optional\)/i.test(label))
        return { icon: '📎', category: 'Other Docs', catKey: 'other_misc' };
      // KYC / Identity
      if (/pan card|aadhaar|aadhar|passport|voter|driving licence|driving license|photograph|photo/i.test(l))
        return { icon: '🪪', category: 'KYC & Identity', catKey: 'kyc' };
      // Income / Employment
      if (/salary slip|form 16|employee id|appointment letter|employment proof|itr|p&l|profit.*loss|balance sheet|computation|business vintage proof/i.test(l))
        return { icon: '💼', category: 'Income & Employment', catKey: 'income' };
      // Bank statements
      if (/bank statement|banking/i.test(l))
        return { icon: '🏦', category: 'Banking', catKey: 'bank' };
      // Business / GST
      if (/gst|udyam|business registration|moa|aoa|partnership deed|stock.*statement|book debt|trade licence/i.test(l))
        return { icon: '🏢', category: 'Business Documents', catKey: 'business' };
      // Professional
      if (/professional|registration certificate|practice|chamber|clinic|firm|bar council|icai|mci/i.test(l))
        return { icon: '🎓', category: 'Professional Credentials', catKey: 'professional' };
      // Property
      if (/property|title deed|sale agreement|allotment|registry|building plan|encumbrance|property tax|ec|khata|chain of title|builder|noc.*society/i.test(l))
        return { icon: '🏠', category: 'Property Documents', catKey: 'property' };
      // Vehicle
      if (/rc book|vehicle|form 29|form 30|vehicle.*valuation|inspection report|insurance copy|dealer|quotation|pro-forma invoice|driving licence/i.test(l))
        return { icon: '🚗', category: 'Vehicle Documents', catKey: 'vehicle' };
      // Education
      if (/admission|offer letter|fee structure|academic marksheet|entrance exam|scorecard|course/i.test(l))
        return { icon: '🎓', category: 'Education Documents', catKey: 'education' };
      // Insurance / Medical
      if (/medical report|health|policy copy|ncb|nominee|discharge summary|medical record/i.test(l))
        return { icon: '🏥', category: 'Medical & Insurance', catKey: 'medical' };
      // Card
      if (/credit card|card statement|card copy/i.test(l))
        return { icon: '💳', category: 'Credit Card Documents', catKey: 'card' };
      return { icon: '📄', category: 'Other Documents', catKey: 'other' };
    }

    // Calculate uploaded count from _BFP_STORE
    function _docCountUploaded() {
      const ids = Object.keys(window._BFP_STORE || {});
      return ids.filter(id => id.startsWith('docitem-wiz-') || id.startsWith('docitem-custom-') || id.startsWith('docitem-pse-slip-') || id.startsWith('docitem-wiz-bank-')).length;
    }

    // Update progress bar header — called after any upload/delete
    window._docUpdateProgress = function() {
      const bar = document.getElementById('doc-progress-bar');
      const txt = document.getElementById('doc-progress-text');
      const cnt = document.getElementById('doc-progress-count');
      if (!bar) return;
      const total = parseInt(bar.dataset.total) || 0;
      const done = _docCountUploaded();
      const pct = total ? Math.min(100, Math.round(done / total * 100)) : 0;
      bar.style.width = pct + '%';
      if (txt) txt.textContent = pct + '% complete';
      if (cnt) cnt.textContent = done + ' of ' + total;
      // Update empty-state message
      const empty = document.getElementById('doc-empty-search');
      if (empty) empty.style.display = 'none';
    };

    // Live search filter
    window._docSearch = function(q) {
      const query = (q || '').toLowerCase().trim();
      const groups = document.querySelectorAll('[data-doc-group]');
      let anyMatch = false;
      groups.forEach(g => {
        const items = g.querySelectorAll('.doc-item');
        let groupHasMatch = false;
        items.forEach(item => {
          const name = (item.querySelector('.doc-name')?.textContent || '').toLowerCase();
          const match = !query || name.includes(query);
          item.style.display = match ? '' : 'none';
          if (match) { groupHasMatch = true; anyMatch = true; }
        });
        g.style.display = groupHasMatch ? '' : 'none';
      });
      const empty = document.getElementById('doc-empty-search');
      if (empty) empty.style.display = anyMatch ? 'none' : '';
    };

    // Drag-and-drop handlers for a doc item
    window._docDragOver = function(e) {
      e.preventDefault();
      const item = e.currentTarget;
      item.style.borderColor = '#2c6fff';
      item.style.borderStyle = 'solid';
      item.style.background = 'linear-gradient(135deg,#eef4ff,#f5f8ff)';
      item.style.boxShadow = '0 6px 16px rgba(44,111,255,.25)';
      item.style.transform = 'translateX(5px) scale(1.01)';
    };
    window._docDragLeave = function(e) {
      const item = e.currentTarget;
      if (window._BFP_STORE[item.id]) {
        // Already uploaded — restore green
        item.style.borderColor = '#10b981';
        item.style.borderStyle = 'solid';
        item.style.background = 'linear-gradient(135deg,#f0faf3,#ecfdf5)';
        item.style.boxShadow = '0 3px 10px rgba(16,185,129,.12)';
      } else {
        // Restore pending state (category palette is applied on CSS-side via style attr)
        item.style.borderColor = '';
        item.style.borderStyle = '';
        item.style.background = '#fff';
        item.style.boxShadow = '';
      }
      item.style.transform = '';
    };
    window._docDrop = function(e, docName) {
      e.preventDefault();
      const item = e.currentTarget;
      const file = e.dataTransfer?.files?.[0];
      if (!file) return;
      // ── Bank statement: redirect drop → Perfios v9 popup ──
      if (/bank statement|banking/i.test(docName)) {
        if (typeof pfv9Open === 'function') pfv9Open(item.id, docName);
        return;
      }
      const fakeInput = { files: [file], closest: () => item };
      markDocUploaded(fakeInput, docName);
      _docUpdateProgress();
    };

    // Per-category visual palette (background, border, icon-gradient, accent colour)
    const _DOC_CAT_PALETTE = {
      kyc:          { bg:'#eef3ff', bd:'#c8d8f8', accent:'#1a4fa3', accent2:'#2c6fff', light:'#f5f8ff', icon:'🪪' },
      income:       { bg:'#fef6ec', bd:'#f5d8a8', accent:'#b45309', accent2:'#f59e0b', light:'#fffaf0', icon:'💼' },
      bank:         { bg:'#ecf7f0', bd:'#b8e8c8', accent:'#1a7340', accent2:'#10b981', light:'#f3fbf6', icon:'🏦' },
      business:     { bg:'#ede9fe', bd:'#c4b5fd', accent:'#5b21b6', accent2:'#8b5cf6', light:'#f5f3ff', icon:'🏢' },
      professional: { bg:'#fce7f3', bd:'#f9a8d4', accent:'#9d174d', accent2:'#db2777', light:'#fdf2f8', icon:'🎓' },
      property:     { bg:'#e0f2fe', bd:'#7dd3fc', accent:'#075985', accent2:'#0284c7', light:'#f0f9ff', icon:'🏠' },
      vehicle:      { bg:'#fee2e2', bd:'#fca5a5', accent:'#991b1b', accent2:'#dc2626', light:'#fef2f2', icon:'🚗' },
      education:    { bg:'#e0e7ff', bd:'#a5b4fc', accent:'#3730a3', accent2:'#6366f1', light:'#eef2ff', icon:'🎓' },
      medical:      { bg:'#ecfdf5', bd:'#6ee7b7', accent:'#065f46', accent2:'#059669', light:'#f0fdf4', icon:'🏥' },
      card:         { bg:'#fdf2f8', bd:'#f0abfc', accent:'#86198f', accent2:'#c026d3', light:'#fdf4ff', icon:'💳' },
      other:        { bg:'#f1f5f9', bd:'#cbd5e1', accent:'#475569', accent2:'#64748b', light:'#f8fafc', icon:'📄' },
      other_misc:   { bg:'#f5f5f5', bd:'#d1d5db', accent:'#6b7280', accent2:'#9ca3af', light:'#fafafa', icon:'📎' },
      custom:       { bg:'#fef2e8', bd:'#fdba74', accent:'#c2410c', accent2:'#ea580c', light:'#fff7ed', icon:'📎' },
    };

    function renderEnhancedDocChecklist() {
      const lt      = document.getElementById('w-loantype')?.value || 'personal_loan';
      const empType = document.getElementById('w-emptype')?.value  || 'SALARIED';
      const docs    = getWizardDocs(lt, empType);
      const wrap    = document.getElementById('doc-upload-list');
      if (!wrap) return;

      const loanLabel = (typeof loanTypeLabel === 'function' ? loanTypeLabel(lt) : lt.replace(/_/g,' '));
      const empLabel  = { SALARIED: 'Salaried', SELFEMP: 'Self-Employed', PROFESSIONAL: 'Professional' }[empType] || empType;

      // ── Filter out KYC docs already uploaded in Step 2 ──
      const kycPanUploaded    = typeof KYC !== 'undefined' && KYC.pan    && !!KYC.pan.dataUrl;
      const kycAadharUploaded = typeof KYC !== 'undefined' && KYC.aadhar && !!KYC.aadhar.dataUrl;
      const filteredDocs = docs.filter(d => {
        const dl = d.toLowerCase();
        if (kycPanUploaded    && dl.includes('pan card')) return false;
        if (kycAadharUploaded && dl.includes('aadhaar'))  return false;
        return true;
      });

      // ── Group docs by category ──
      const grouped = {};
      filteredDocs.forEach((d, i) => {
        const meta = _docInferMeta(d);
        if (!grouped[meta.catKey]) grouped[meta.catKey] = { label: meta.category, items: [] };
        grouped[meta.catKey].items.push({ name: d, index: i, icon: meta.icon });
      });

      const catOrder = ['income','bank','kyc','business','professional','property','vehicle','education','medical','card','other','other_misc'];
      const orderedGroups = catOrder.filter(k => grouped[k]).concat(Object.keys(grouped).filter(k => !catOrder.includes(k)));

      // ── Helper to escape quotes for inline handlers ──
      const esc = s => String(s).replace(/'/g, "\\'").replace(/"/g, '&quot;');

      // ══ Hero header (blue card removed) ══
      const total = filteredDocs.length;
      const headerHtml = `
        <span id="doc-progress-count" style="display:none">0 of ${total}</span>
        <span id="doc-progress-text" style="display:none">0%</span>
        <div id="doc-progress-bar" data-total="${total}" style="display:none"></div>
        <div style="margin-bottom:16px;position:relative">
          <span style="position:absolute;left:13px;top:50%;transform:translateY(-50%);font-size:14px;color:var(--text3);pointer-events:none">🔍</span>
          <input type="text" placeholder="Search documents…" oninput="_docSearch(this.value)"
            style="width:100%;padding:10px 16px 10px 40px;border:1.5px solid var(--border2);border-radius:var(--r-sm);font-size:13px;background:var(--surface2);color:var(--text);font-family:var(--font-body);outline:none;transition:border-color .18s,box-shadow .18s"
            onfocus="this.style.borderColor='var(--accent)';this.style.boxShadow='0 0 0 3px var(--accent-glow)'"
            onblur="this.style.borderColor='var(--border2)';this.style.boxShadow=''">
        </div>`;

      // ══ KYC section (auto-verified) ══
      let kycHtml = '';
      if (typeof KYC !== 'undefined') {
        const kycItems = [];
        if (KYC.pan && KYC.pan.dataUrl) kycItems.push({ label: 'PAN Card', file: KYC.pan });
        if (KYC.aadhar && KYC.aadhar.dataUrl) kycItems.push({ label: 'Aadhaar Front', file: KYC.aadhar });
        if (KYC.aadharBack && KYC.aadharBack.dataUrl) kycItems.push({ label: 'Aadhaar Back', file: KYC.aadharBack });
        if (kycItems.length > 0) {
          kycHtml = `<div style="display:none;margin-bottom:20px;padding:14px;background:linear-gradient(135deg,#f0faf3,#ecfaff);border-radius:16px;border:1.5px solid #b8e8c8;box-shadow:0 2px 8px rgba(26,115,64,.06)">
            <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px;padding:0 4px">
              <div style="width:32px;height:32px;border-radius:9px;background:linear-gradient(135deg,#059669,#10b981);display:flex;align-items:center;justify-content:center;box-shadow:0 3px 8px rgba(16,185,129,.28)">
                <span style="font-size:15px">🔏</span>
              </div>
              <div style="flex:1">
                <div style="font-family:var(--font-head);font-size:13.5px;font-weight:800;color:#065f46">Auto-verified from KYC Step</div>
                <div style="font-size:10.5px;color:#4a9a6a;margin-top:1px">Documents pre-uploaded and identity verified</div>
              </div>
              <span style="font-size:10px;background:#059669;color:#fff;padding:4px 11px;border-radius:20px;font-weight:700;letter-spacing:.4px;box-shadow:0 2px 6px rgba(16,185,129,.32)">${kycItems.length} VERIFIED</span>
            </div>` +
            kycItems.map(({ label, file }) => {
              const previewHtml = file.isPdf
                ? `<div style="width:48px;height:48px;border-radius:11px;background:linear-gradient(135deg,#059669,#10b981);display:flex;align-items:center;justify-content:center;font-size:22px;color:#fff;flex-shrink:0;box-shadow:0 3px 8px rgba(16,185,129,.28)">📄</div>`
                : `<img src="${file.dataUrl}" style="width:48px;height:48px;object-fit:cover;border-radius:11px;flex-shrink:0;border:2px solid #fff;box-shadow:0 2px 8px rgba(0,0,0,.12)" alt="${label}">`;
              const fname = file.file ? file.file.name : label;
              return `<div style="display:flex;align-items:center;gap:14px;padding:12px 14px;border-radius:12px;background:#fff;margin-bottom:6px;border:1px solid rgba(16,185,129,.18);transition:all .18s" onmouseenter="this.style.transform='translateX(3px)';this.style.boxShadow='0 3px 10px rgba(16,185,129,.14)'" onmouseleave="this.style.transform='';this.style.boxShadow=''">
                ${previewHtml}
                <div style="flex:1;min-width:0">
                  <div style="font-size:13px;font-weight:700;color:var(--text);line-height:1.3">${label}</div>
                  <div style="font-size:11px;color:#4a9a6a;margin-top:3px;font-weight:500;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">📎 ${fname}</div>
                </div>
                <span style="display:inline-flex;align-items:center;gap:4px;font-size:10px;color:#fff;background:linear-gradient(135deg,#059669,#10b981);padding:4px 11px;border-radius:20px;flex-shrink:0;font-weight:700;letter-spacing:.4px;box-shadow:0 2px 6px rgba(16,185,129,.28)"><span>✓</span> VERIFIED</span>
                <button class="btn btn-ghost btn-sm" onclick="kycWizPreview(this)" data-url="${file.dataUrl}" data-label="${label}" data-type="${file.isPdf ? 'pdf' : 'image'}" style="flex-shrink:0;border-color:#b8e8c8;color:#065f46;font-size:13px;padding:6px 10px">👁</button>
              </div>`;
            }).join('') +
          `</div>`;
        }
      }

      // ══ Grouped doc lists ══
      const groupsHtml = orderedGroups.map(catKey => {
        const g = grouped[catKey];
        const pal = _DOC_CAT_PALETTE[catKey] || _DOC_CAT_PALETTE.other;
        const isOptionalGroup = catKey === 'other_misc';
        const itemsHtml = g.items.map(({ name, index, icon }) => {
          const displayName = name.replace(/\s*\(Optional\)\s*$/i, '');
          // Mandatory income/banking docs before Loan Analytics get a visible * mark
          const isMandatoryDocMark = _WIZ_MANDATORY_DOC_NAMES.includes(displayName);
          const itemId = `docitem-wiz-${index}`;
          return `<div class="doc-item" id="${itemId}"
              style="display:flex;align-items:center;gap:13px;padding:13px 15px;border-radius:12px;border:1.5px dashed ${pal.bd};background:#fff;margin-bottom:8px;transition:all .2s;cursor:default;position:relative"
              ondragover="_docDragOver(event)" ondragleave="_docDragLeave(event)" ondrop="_docDrop(event,'${esc(name)}')"
              onmouseenter="if(!window._BFP_STORE['${itemId}']){this.style.borderColor='${pal.accent2}';this.style.boxShadow='0 3px 12px ${pal.accent2}22';this.style.transform='translateX(3px)'}"
              onmouseleave="if(!window._BFP_STORE['${itemId}']){this.style.borderColor='${pal.bd}';this.style.boxShadow='';this.style.transform=''}">
            <div style="width:42px;height:42px;border-radius:11px;background:linear-gradient(135deg,${pal.accent},${pal.accent2});display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:19px;color:#fff;box-shadow:0 3px 8px ${pal.accent2}30">${icon}</div>
            <div class="doc-info" style="flex:1;min-width:0">
              <div class="doc-name" style="font-size:13.5px;font-weight:700;color:var(--text);line-height:1.35">${displayName}${isMandatoryDocMark ? ' <span class="req" style="color:#e24b4a">*</span>' : ''}</div>
              <div class="doc-type" style="font-size:10.5px;color:var(--text3);margin-top:3px;font-weight:500;display:flex;align-items:center;gap:5px">
                <span style="color:${pal.accent};font-size:9px">●</span>
                <span>Drag &amp; drop here or click Upload</span>
              </div>
            </div>
            <span id="doc-status-${index}" style="font-size:9.5px;font-weight:800;padding:4px 10px;border-radius:20px;background:#f1f5f9;color:#64748b;border:1px solid #cbd5e1;flex-shrink:0;letter-spacing:.6px">PENDING</span>
            ${displayName === 'Last 3 Month Salary Slips'
              ? `<button class="btn btn-ghost btn-sm" style="cursor:pointer;flex-shrink:0;font-size:11.5px;border-color:${pal.bd};color:${pal.accent};background:${pal.light};font-weight:600;border:1.5px solid"
                  onmouseenter="this.style.background='${pal.bg}';this.style.borderColor='${pal.accent2}'"
                  onmouseleave="this.style.background='${pal.light}';this.style.borderColor='${pal.bd}'"
                  onclick="openPerfiosExtractionModal('${itemId}')">
                  ⚡ Upload Document
                </button>`
              : /bank statement|banking/i.test(name)
              ? `<button class="btn btn-ghost btn-sm" style="cursor:pointer;flex-shrink:0;font-size:11.5px;border-color:${pal.bd};color:${pal.accent};background:${pal.light};font-weight:600;border:1.5px solid"
                  onmouseenter="this.style.background='${pal.bg}';this.style.borderColor='${pal.accent2}'"
                  onmouseleave="this.style.background='${pal.light}';this.style.borderColor='${pal.bd}'"
                  onclick="pfv9Open('${itemId}','${esc(name)}')">
                  🏦 Upload Statement
                </button>`
              : `<label class="btn btn-ghost btn-sm" style="cursor:pointer;flex-shrink:0;font-size:11.5px;border-color:${pal.bd};color:${pal.accent};background:${pal.light};font-weight:600"
                  onmouseenter="this.style.background='${pal.bg}';this.style.borderColor='${pal.accent2}'"
                  onmouseleave="this.style.background='${pal.light}';this.style.borderColor='${pal.bd}'">
                  📤 Upload<input type="file" multiple style="display:none" onchange="markDocUploaded(this,'${esc(name)}');_docUpdateProgress()">
                </label>`}
          </div>`;
        }).join('');

        // ── Category section card ──
        return `<div data-doc-group="${catKey}" style="margin-bottom:16px;padding:14px 14px 10px;background:${pal.light};border-radius:16px;border:1px solid ${pal.bd};position:relative;overflow:hidden">
          <!-- Left accent bar -->
          <div style="position:absolute;left:0;top:0;bottom:0;width:3px;background:linear-gradient(180deg,${pal.accent},${pal.accent2})"></div>

          <!-- Category header -->
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px;padding:0 4px 8px;border-bottom:1px solid ${pal.bd}">
            <div style="width:28px;height:28px;border-radius:8px;background:${pal.bg};display:flex;align-items:center;justify-content:center;flex-shrink:0;font-size:14px;border:1px solid ${pal.bd}">${pal.icon || '📁'}</div>
            <div style="flex:1;min-width:0">
              <div style="font-size:11.5px;font-weight:800;color:${pal.accent};text-transform:uppercase;letter-spacing:.8px;line-height:1.2">${g.label}</div>
              <div style="font-size:10px;color:${pal.accent2};margin-top:1px;font-weight:500;opacity:.85">${isOptionalGroup ? 'Optional — upload if available' : g.items.length + ' ' + (g.items.length === 1 ? 'document required' : 'documents required')}</div>
            </div>
            <span style="font-size:10px;color:#fff;background:linear-gradient(135deg,${pal.accent},${pal.accent2});padding:3px 10px;border-radius:20px;font-weight:700;letter-spacing:.4px;box-shadow:0 2px 6px ${pal.accent2}30;flex-shrink:0">${isOptionalGroup ? 'OPTIONAL' : g.items.length + ' DOC' + (g.items.length === 1 ? '' : 'S')}</span>
          </div>

          ${itemsHtml}
        </div>`;
      }).join('');

      // ══ Empty search state ══
      const emptyHtml = `<div id="doc-empty-search" style="display:none;padding:40px 20px;text-align:center;background:linear-gradient(135deg,#f1f5f9,#f8fafc);border-radius:16px;border:1.5px dashed #cbd5e1">
        <div style="font-size:36px;margin-bottom:10px;opacity:.5">🔍</div>
        <div style="font-size:13.5px;color:var(--text2);font-weight:600">No documents match your search</div>
        <div style="font-size:11.5px;color:var(--text3);margin-top:4px">Try a different keyword or clear the search</div>
      </div>`;

      wrap.innerHTML = headerHtml + kycHtml + groupsHtml + emptyHtml;
      _docUpdateProgress();
    }

    function docViewFile(itemId) {
      openPreviewModal(itemId);
    }

    function docDeleteFile(itemId) {
      const item = document.getElementById(itemId);
      if (!item) return;
      if (!confirm('Remove this uploaded file?')) return;
      delete window._BFP_STORE[itemId];
      if (typeof _docUpdateProgress === 'function') _docUpdateProgress();
      // Reset UI to pending state
      item.style.borderColor = '';
      item.style.borderStyle = '';
      item.style.borderWidth = '';
      item.style.background = '#fff';
      item.style.boxShadow = '';
      const typeEl = item.querySelector('.doc-type');
      if (typeEl) { typeEl.innerHTML = `<span style="color:var(--text3);font-size:9px">●</span> <span>Drag &amp; drop here or click Upload</span>`; typeEl.style.color = ''; }
      const statusEl = item.querySelector('[id^="doc-status-"]');
      if (statusEl) {
        statusEl.textContent = 'PENDING';
        statusEl.style.color = '#64748b';
        statusEl.style.background = '#f1f5f9';
        statusEl.style.borderColor = '#cbd5e1';
        statusEl.style.boxShadow = '';
      }
      const viewBtn = item.querySelector('.doc-view-btn');
      const delBtn  = item.querySelector('.doc-del-btn');
      if (viewBtn) viewBtn.style.display = 'none';
      if (delBtn)  delBtn.style.display  = 'none';
      const eyeBtn = item.querySelector('.preview-btn-eye');
      if (eyeBtn) eyeBtn.remove();
      showToast('File removed', 'info');
    }

    function deleteTaskAttachment(appId, idx) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app || !app._taskAttachments) return;
      if (!confirm('Remove this task attachment?')) return;
      const att = app._taskAttachments[idx];
      if (att) delete window._BFP_STORE[att.storeKey];
      app._taskAttachments.splice(idx, 1);
      // Re-render docs tab
      openDetail(appId);
      showToast('Attachment removed', 'info');
    }

    // ── Delete a wizard-uploaded document (Documents tab, "Uploaded During
    //    Application" section). Partner and DSA users never see this button
    //    (enforced both by not rendering it and by re-checking the role here,
    //    since onclick handlers can in principle be invoked directly).
    function deleteWizDoc(appId, idx) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app || !app.uploadedDocs || !app.uploadedDocs[idx]) return;
      if (typeof guardFinalLock === 'function' && !guardFinalLock(app, 'Document delete')) return;
      if (currentUser && (currentUser.role === 'partner' || currentUser.role === 'dsa')) {
        showToast('You do not have permission to delete this document', 'error');
        return;
      }
      if (!confirm('Remove this document?')) return;
      const doc = app.uploadedDocs[idx];
      if (doc.storeKey) delete window._BFP_STORE[doc.storeKey];
      // If this was the Perfios-verified bank statement, also clear the transient
      // "Bank Statement — via Perfios" card and its injected DOM section — it's a
      // separate, session-only preview of the same document (see perfios-renderer.js),
      // and left uncleared it would silently reappear next time the Documents tab
      // is switched to, even though the real record was just deleted.
      if (doc.perfiosVerified) {
        window._perfiosBankDoc = null;
        const perfiosHdr = document.getElementById('perfios-bank-doc-section-hdr');
        if (perfiosHdr) perfiosHdr.remove();
        const perfiosEntry = document.getElementById('perfios-bank-doc-entry');
        if (perfiosEntry) perfiosEntry.remove();
      }
      app.uploadedDocs.splice(idx, 1);
      if (typeof persistSave === 'function') persistSave();
      openDetail(appId);
      showToast('Document removed', 'info');
    }
    window.deleteWizDoc = deleteWizDoc;

    // ── Open attachment preview modal ──
    // Mirrors ps_binary_field_attachment_preview.BinaryFieldPreview → openPreview()
    function openPreviewModal(itemId) {
      const att = window._BFP_STORE && window._BFP_STORE[itemId];
      if (!att) { showToast('Document preview not available', 'warn'); return; }

      const overlay = document.getElementById('preview-modal-overlay');
      const titleEl = document.getElementById('preview-modal-title');
      const metaEl  = document.getElementById('preview-modal-meta');
      const iconEl  = document.getElementById('preview-modal-icon');
      const bodyEl  = document.getElementById('preview-modal-body');

      titleEl.textContent = att.name;
      metaEl.textContent  = att.mimetype;

      // Prefer dataUrl (survives navigation) over url (blob URL — expires on navigation).
      // For PDFs: browsers block <iframe src="data:..."> so we create a fresh blob URL
      // from the dataUrl at preview time — this is always valid within the current session.
      // For images: dataUrl works directly as <img src>.
      const dataUrl = att.dataUrl || '';
      let   blobUrl = att.url    || '';            // may be stale after navigation
      // Defense-in-depth: a raw data: URI must never be used as an iframe
      // src (the browser blocks it) — only real blob:/http(s) URLs belong here.
      if (blobUrl.startsWith('data:')) blobUrl = '';

      function _getFreshSrc(isPdf) {
        if (dataUrl) {
          if (isPdf) {
            // Convert base64 dataUrl → fresh Blob URL for iframe
            try {
              const b64   = dataUrl.split(',')[1];
              const bytes = atob(b64);
              const ab    = new ArrayBuffer(bytes.length);
              const ia    = new Uint8Array(ab);
              for (let i = 0; i < bytes.length; i++) ia[i] = bytes.charCodeAt(i);
              return URL.createObjectURL(new Blob([ab], { type: 'application/pdf' }));
            } catch(_) { /* fall through to blobUrl */ }
          } else {
            return dataUrl;   // images: dataUrl works directly
          }
        }
        return blobUrl;       // last resort — original blob URL (valid in current session)
      }

      if (att.isImage) {
        iconEl.textContent = '🖼';
        const src = _getFreshSrc(false);
        bodyEl.innerHTML = `<img class="preview-img" src="${src}" alt="${att.name}">`;
      } else if (att.isPdf) {
        iconEl.textContent = '📑';
        const pdfPw = att.pdfPassword || null;

        if (pdfPw && typeof pdfjsLib !== 'undefined') {
          // ── Password-protected PDF: render with pdf.js so the stored password is used ──
          // Build a canvas-based inline viewer in bodyEl. We use one canvas per page.
          bodyEl.innerHTML = `<div id="pse-preview-pdf-wrap" style="overflow-y:auto;max-height:72vh;background:#525659;padding:12px;border-radius:8px;display:flex;flex-direction:column;align-items:center;gap:10px">
            <div style="color:#fff;font-size:13px;padding:14px;text-align:center;opacity:.7">🔓 Rendering password-protected PDF…</div>
          </div>`;
          overlay.classList.add('open');

          (async function() {
            try {
              // Reconstruct bytes from dataUrl or fetch from blobUrl
              let pdfBytes;
              if (dataUrl) {
                const b64   = dataUrl.split(',')[1];
                const bin   = atob(b64);
                pdfBytes    = new Uint8Array(bin.length);
                for (let bi = 0; bi < bin.length; bi++) pdfBytes[bi] = bin.charCodeAt(bi);
              } else if (blobUrl) {
                const resp  = await fetch(blobUrl);
                pdfBytes    = new Uint8Array(await resp.arrayBuffer());
              }

              if (!pdfBytes) {
                document.getElementById('pse-preview-pdf-wrap').innerHTML =
                  `<div style="color:#fff;font-size:13px;padding:24px;text-align:center">
                    ⚠ PDF data unavailable — please re-upload the document.<br>
                    ${blobUrl ? `<a href="${blobUrl}" download="${att.name}" class="btn btn-primary btn-sm" style="margin-top:12px;text-decoration:none;display:inline-block">⬇ Download PDF</a>` : ''}
                  </div>`;
                return;
              }

              const pdfDoc = await pdfjsLib.getDocument({ data: pdfBytes, password: pdfPw }).promise;
              const wrap   = document.getElementById('pse-preview-pdf-wrap');
              if (!wrap) return;  // modal was closed before render finished
              wrap.innerHTML = '';  // clear loading message

              for (let pn = 1; pn <= pdfDoc.numPages; pn++) {
                const page     = await pdfDoc.getPage(pn);
                const viewport = page.getViewport({ scale: 1.4 });
                const canvas   = document.createElement('canvas');
                canvas.width   = viewport.width;
                canvas.height  = viewport.height;
                canvas.style.cssText = 'max-width:100%;border-radius:4px;box-shadow:0 2px 12px rgba(0,0,0,.4)';
                wrap.appendChild(canvas);
                await page.render({ canvasContext: canvas.getContext('2d'), viewport }).promise;
              }

              // Add download button below rendered pages
              if (blobUrl || dataUrl) {
                const dlBtn = document.createElement('a');
                dlBtn.href     = blobUrl || dataUrl;
                dlBtn.download = att.name;
                dlBtn.className = 'btn btn-primary btn-sm';
                dlBtn.style.cssText = 'margin-top:6px;text-decoration:none;color:#fff';
                dlBtn.textContent = '⬇ Download PDF';
                wrap.appendChild(dlBtn);
              }
            } catch(e) {
              const wrap = document.getElementById('pse-preview-pdf-wrap');
              if (wrap) wrap.innerHTML =
                `<div style="color:#fca5a5;font-size:13px;padding:24px;text-align:center">
                  ❌ Could not render PDF — ${e.message || 'unknown error'}<br>
                  ${blobUrl ? `<a href="${blobUrl}" download="${att.name}" class="btn btn-primary btn-sm" style="margin-top:12px;text-decoration:none;display:inline-block">⬇ Download PDF</a>` : ''}
                </div>`;
            }
          })();
          return;   // overlay already opened above — skip the normal .classList.add('open') at end
        }

        // ── Standard (non-password) PDF: plain iframe ──
        const src = _getFreshSrc(true);
        if (src) {
          bodyEl.innerHTML = `<iframe class="preview-pdf-frame" src="${src}"></iframe>`;
        } else {
          // No URL available at all — offer download only
          bodyEl.innerHTML = `<div class="preview-no-preview">
            <div class="pnp-icon">📄</div>
            <div class="pnp-msg"><strong>${att.name}</strong></div>
            <div style="font-size:12px;color:var(--text3);margin-bottom:16px">PDF preview unavailable — file may have been moved or session expired.</div>
            ${blobUrl ? `<a href="${blobUrl}" download="${att.name}" class="btn btn-primary btn-sm" style="text-decoration:none">⬇ Download PDF</a>` : ''}
          </div>`;
        }
      } else {
        iconEl.textContent = '📄';
        const src = blobUrl || dataUrl;
        bodyEl.innerHTML = `<div class="preview-no-preview">
          <div class="pnp-icon">📁</div>
          <div class="pnp-msg"><strong>${att.name}</strong></div>
          <div style="font-size:12px;color:var(--text3);margin-bottom:16px">${att.mimetype}</div>
          ${src ? `<a href="${src}" download="${att.name}" class="btn btn-primary btn-sm" style="text-decoration:none">⬇ Download File</a>` : ''}
        </div>`;
      }

      overlay.classList.add('open');
    }

    function closePreviewModal(event) {
      if (event && event.target !== document.getElementById('preview-modal-overlay')) return;
      document.getElementById('preview-modal-overlay').classList.remove('open');
    }

    function kycWizPreview(btn) {
      var dataUrl = btn.getAttribute('data-url');
      var label   = btn.getAttribute('data-label') || 'Document';
      var type    = btn.getAttribute('data-type');
      if (!dataUrl) return;
      var overlay = document.getElementById('preview-modal-overlay');
      var titleEl = document.getElementById('preview-modal-title');
      var metaEl  = document.getElementById('preview-modal-meta');
      var iconEl  = document.getElementById('preview-modal-icon');
      var bodyEl  = document.getElementById('preview-modal-body');
      titleEl.textContent = label;
      metaEl.textContent  = 'KYC · Identity';
      if (type === 'pdf') {
        iconEl.textContent = '📑';
        try {
          var byteStr = atob(dataUrl.split(',')[1]);
          var ab = new ArrayBuffer(byteStr.length);
          var ia = new Uint8Array(ab);
          for (var i = 0; i < byteStr.length; i++) ia[i] = byteStr.charCodeAt(i);
          var blob = new Blob([ab], { type: 'application/pdf' });
          var blobUrl = URL.createObjectURL(blob);
          bodyEl.innerHTML = '<iframe class="preview-pdf-frame" src="' + blobUrl + '"></iframe>';
        } catch(e) {
          bodyEl.innerHTML = '<div style="text-align:center;padding:32px">📄<br><a href="' + dataUrl + '" download="' + label + '" class="btn btn-primary btn-sm" style="margin-top:12px">⬇ Download PDF</a></div>';
        }
      } else {
        iconEl.textContent = '🖼';
        bodyEl.innerHTML = '<img class="preview-img" src="' + dataUrl + '" alt="' + label + '">';
      }
      overlay.classList.add('open');
    }

    // ═══════════════════════════════════════════════════════
    //  ACTIVITY + NOTIFICATION FORWARD DECLARATIONS
    //  Full implementations defined later; these stubs make
    //  changeStatus safe to call before the definitions load.
    // ═══════════════════════════════════════════════════════
    function pushActivity(dot, text, appId) {
      if (typeof ACTIVITY_LOG !== 'undefined') {
        // Auto-extract appId from text if not provided (looks for EFIN\d+ pattern)
        const extractedId = appId || (text.match(/EFIN\d+/) || [])[0] || null;
        ACTIVITY_LOG.unshift({ dot, text, time: new Date().toISOString(), appId: extractedId });
        if (ACTIVITY_LOG.length > 30) ACTIVITY_LOG.pop();
        if (typeof renderActivity === 'function') renderActivity();
      }
    }
    function pushNotif(icon, text) {
      if (typeof NOTIF_STORE !== 'undefined') {
        if (typeof notifNextId === 'undefined') window.notifNextId = 100;
        NOTIF_STORE.unshift({ id: notifNextId++, icon, text, time: new Date().toISOString(), read: false });
        if (typeof updateNotifBadge === 'function') updateNotifBadge();
      }
    }

    // ═══════════════════════════════════════════════════════
    //  STATUS CHANGE
    // ═══════════════════════════════════════════════════════
    function changeStatus(id, newStatus, triggerEl) {
      const app = APPLICATIONS.find(a => a.id === id); if (!app) return;
      const rd = ROLES[currentUser.role];
      if (!rd.canChangeStatus) { showToast('You do not have permission to change status', 'error'); return; }
      // Final-stage lock: once the app is Disbursed/Rejected/Cancelled/Hold, only
      // admin can change its status any further (existing role checks above still apply as-is).
      if (typeof guardFinalLock === 'function' && !guardFinalLock(app, 'Status change')) return;
      const old = app.status; app.status = newStatus;
      // Record exact ISO timestamp of status change for hour-level TAT calculation
      app.statusChangedAt = new Date().toISOString();
      const dept = rd.dept;

      // Auto-tracking entries on status change
      if (newStatus === 'login' && old !== 'login') addTrackingEntry(app, 'EFIN-Assign Lender', dept, 'DONE', ' ');
      if (newStatus === 'underwriting') {
        // Only add the 'Move' entry if doUnderwriting hasn't already posted it
        const alreadyPosted = app.tracking && app.tracking.some(t => t.name === 'EFIN-Underwriting' && t.comment === 'Move');
        if (!alreadyPosted) addTrackingEntry(app, 'EFIN-Underwriting', dept, 'Move', ' ');
        addTrackingEntry(app, 'EFIN-Verification', 'System Comments', 'Application under review', ' ');
        addTrackingEntry(app, 'EFIN-PD Call', 'System Comments', 'Our credit team will contact you shortly.', ' ');
      }
      if (newStatus === 'disbursed') {
        const loanNo = 'E-LAN' + Math.floor(100000 + Math.random() * 900000);
        app.disbursement_date = new Date().toLocaleDateString('en-IN');
        addTrackingEntry(app, 'EFIN-Disbursed', dept, ' ', 'Loan amt and tenor update');
        addTrackingEntry(app, 'EFIN-Disbursed', dept, ' ', loanNo);
        addTrackingEntry(app, 'EFIN-Disbursed', 'System Comments', 'OK to Process', ' ');
        addTrackingEntry(app, 'EFIN-Disbursed', 'System Comments', 'Disbursement Done', ' ');
        addTrackingEntry(app, 'EFIN-Disbursed', 'System Comments', 'Work Flow Completed', ' ');
        bumpStat('st-disbursed', getPartnerScopedApps().filter(a => a.status === 'disbursed').length);
        // ── Auto-create payout claim for all relevant users ──
        autoCreatePayoutClaim(app);
      }
      if (newStatus === 'rejected') {
        bumpStat('st-rejected', getPartnerScopedApps().filter(a => a.status === 'rejected').length);
      }

      renderTable();
      flashTableRow(id);
      // Keep dashboard live
      updateDashboardStats();
      // ── Email notification on key status changes ──
      (function() {
        var emailTriggerMap = {
          'approved':   'approved',
          'disbursed':  'disbursed',
          'rejected':   'rejected',
          'sanctioned': 'sanctioned',
          'hold':       'hold',
        };
        if (emailTriggerMap[newStatus] && typeof window.lewSendLenderEmail === 'function') {
          try {
            window.lewSendLenderEmail(app, emailTriggerMap[newStatus], {
              isManual: false, triggeredBy: currentUser ? currentUser.name : 'System'
            });
          } catch(e) {}
        }
      })();
      renderPipeline();
      renderActivity();

      // ── Per-status celebration logic ──
      if (newStatus === 'disbursed') {
        // Money particles from button if available
        if (triggerEl) {
          const rect = triggerEl.getBoundingClientRect();
          spawnMoneyParticles(rect.left + rect.width / 2, rect.top + rect.height / 2);
          spawnDisburseRing(triggerEl);
        }
        setTimeout(() => {
          showCelebration({
            icon: '💰',
            title: 'Loan Disbursed! 🎉',
            amount: '₹' + Number(app.amount).toLocaleString('en-IN'),
            amountColor: '#1a7340',
            appId: id,
            sub: app.name + '\'s ' + loanTypeLabel(app.loanType) + ' has been successfully disbursed. The funds are on their way!',
            btnText: 'View Application →',
            btnColor: '#1a7340',
            btnShadow: 'rgba(26,115,64,.45)',
            confetti: true,
            confettiCount: 180,
          });
          document.getElementById('celebration-btn').onclick = () => {
            closeCelebration();
            openDetail(id);
          };
        }, 350);

      } else if (newStatus === 'approved') {
        setTimeout(() => {
          showCelebration({
            icon: '✅',
            title: 'Application Approved!',
            amount: '₹' + Number(app.amount).toLocaleString('en-IN'),
            amountColor: 'var(--accent)',
            appId: id,
            sub: app.name + '\'s application has been approved. Proceed to disbursement when ready.',
            btnText: 'Continue to Disbursement →',
            btnColor: 'var(--accent)',
            btnShadow: 'rgba(26,79,163,.4)',
            confetti: true,
            confettiCount: 90,
          });
          document.getElementById('celebration-btn').onclick = () => {
            closeCelebration();
            openDetail(id);
          };
        }, 250);

      } else if (newStatus === 'login') {
        showToast(id + ' lender assigned — stage advanced automatically 🏦', 'info');
        pushActivity('var(--accent)', `<strong>${id}</strong> advanced to Assign Lender (auto-mode)`);
        pushNotif('🏦', `${id} — ${app.name} moved to Assign Lender`);
        // Highlight nav item briefly
        const loginNav = [...document.querySelectorAll('.nav-item')].find(el => el.textContent.includes('Applications'));
        if (loginNav) { loginNav.classList.add('nav-ping'); setTimeout(() => loginNav.classList.remove('nav-ping'), 600); }

      } else if (newStatus === 'underwriting') {
        showToast(id + ' → Underwriting. Verification triggered. 🔍', 'info');
        pushActivity('var(--accent)', `<strong>${id}</strong> moved to Underwriting`);

      } else if (newStatus === 'rejected') {
        // Shake effect on the detail card if visible
        const detailTitle = document.getElementById('detail-title');
        if (detailTitle) {
          const card = detailTitle.closest('.page');
          if (card) { card.classList.add('rejected-shake'); setTimeout(() => card.classList.remove('rejected-shake'), 600); }
        }
        showToast(id + ' has been rejected', 'error');
        pushActivity('var(--danger)', `<strong>${id}</strong> — <strong>${app.name}</strong> rejected`);
        pushNotif('🚫', `${id} — ${app.name} has been rejected`);

      } else {
        showToast(id + ' → ' + (STATUSES[newStatus] || newStatus), 'success');
        pushActivity('var(--accent)', `<strong>${id}</strong> → ${STATUSES[newStatus] || newStatus}`);
      }

      // Disbursal and approval activity hooks (run regardless of animation branch)
      if (newStatus === 'disbursed') {
        pushActivity('var(--accent2)', `<strong>${id}</strong> — ₹${Number(app.amount).toLocaleString('en-IN')} <strong>DISBURSED</strong> to ${app.name}`);
        pushNotif('💰', `${id} — ₹${Number(app.amount).toLocaleString('en-IN')} disbursed to ${app.name}`);
      }
      if (newStatus === 'approved') {
        pushActivity('var(--success)', `<strong>${id}</strong> — ${app.name} <strong>APPROVED</strong>`);
        pushNotif('✅', `${id} — ${app.name} approved for ₹${Number(app.amount).toLocaleString('en-IN')}`);
      }

      // ── Change 3: Auto WhatsApp + Email notification to partner & salesperson ──
      setTimeout(() => sendStageNotifications(app, newStatus), 600);

      // ── Change 2: Approval/Disbursement popup for partner home screen ──
      if ((newStatus === 'approved' || newStatus === 'disbursed') && currentUser.role === 'partner') {
        setTimeout(() => showApprovalDisbursementPopup(app, newStatus), 800);
      }
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
    }

    function holdApp(id) {
      const reason = prompt('Enter hold reason:');
      if (reason) { changeStatus(id, 'hold'); showToast('Application placed on hold', 'warn'); }
    }
    function rejectApp(id) {
      if (confirm('Reject this application? It can be re-opened within 45 days of the original creation date.')) {
        const app = APPLICATIONS.find(a => a.id === id);
        if (app) {
          app.preRejectedStatus = app.status; // snapshot stage for re-open restoration
          app.rejectedAt = new Date().toISOString();
        }
        changeStatus(id, 'rejected');
      }
    }

    function reopenApp(id) {
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app) return;

      // Final-stage lock: only admin may re-open a rejected application
      if (typeof guardFinalLock === 'function' && !guardFinalLock(app, 'Re-open')) return;

      // Blocked for partner and dsa_user regardless of other permissions
      if (['partner','dsa_user'].includes(currentUser.role)) {
        showToast('You do not have permission to re-open applications', 'error'); return;
      }

      // Enforce 45-day window from creation date
      const createdAt = app.login_date_time
        ? new Date(app.login_date_time)
        : new Date((app.date || '').replace(/(\d{2}) (\w+) (\d{4})/, '$2 $1 $3'));
      const daysElapsed = (Date.now() - createdAt.getTime()) / (1000 * 60 * 60 * 24);
      if (daysElapsed > 45) {
        showToast('Re-open window has expired (45 days from creation date)', 'error'); return;
      }

      const restoreStatus = app.preRejectedStatus || 'login';
      const restoreLabel  = STATUSES[restoreStatus] || restoreStatus;

      // ── Guard: prevent duplicate overlays ──
      const existingOverlay = document.getElementById('reopen-overlay');
      if (existingOverlay) existingOverlay.remove();

      // ── Styled Re-open modal with remarks input ──
      const overlay = document.createElement('div');
      overlay.id = 'reopen-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(8,18,52,.65);backdrop-filter:blur(10px);display:flex;align-items:center;justify-content:center;padding:16px';
      overlay.innerHTML = `
        <div style="background:var(--surface);border:1.5px solid var(--border);border-radius:22px;padding:36px;max-width:480px;width:100%;box-shadow:0 40px 100px rgba(12,23,61,.3);max-height:90vh;overflow-y:auto">
          <div style="font-size:38px;text-align:center;margin-bottom:14px">🔄</div>
          <div style="font-family:var(--font-head);font-size:18px;font-weight:800;margin-bottom:6px;text-align:center">Re-open Application?</div>
          <div style="font-size:12.5px;color:var(--text2);text-align:center;margin-bottom:4px"><strong>${app.name}</strong> · ${id}</div>
          <div style="font-size:12px;color:var(--text3);text-align:center;margin-bottom:20px">
            Will resume processing from: <span style="font-weight:700;color:var(--accent)">${restoreLabel}</span>
          </div>
          <div style="margin-bottom:16px">
            <label style="font-size:12px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;display:block;margin-bottom:6px">Remarks <span style="color:var(--danger)">*</span></label>
            <textarea class="ro-remarks" rows="3" placeholder="Enter reason for re-opening this application…"
              style="width:100%;padding:10px 12px;font-size:13px;font-family:var(--font-body);background:var(--surface2);border:1.5px solid var(--border2);border-radius:10px;color:var(--text);resize:vertical;outline:none;box-sizing:border-box"></textarea>
            <div class="ro-err" style="font-size:11.5px;color:var(--danger);margin-top:4px;display:none">Please enter a remark before re-opening.</div>
          </div>
          <div style="margin-bottom:20px">
            <label style="font-size:12px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;display:block;margin-bottom:6px">Attach Documents <span style="font-size:10px;font-weight:400;text-transform:none;color:var(--text3)">(optional — multiple files)</span></label>
            <label class="ro-file-label" style="display:flex;align-items:center;gap:8px;padding:10px 14px;background:var(--surface2);border:1.5px dashed var(--border2);border-radius:10px;cursor:pointer;font-size:12.5px;color:var(--text3);transition:border-color .15s" onmouseover="this.style.borderColor='var(--accent)'" onmouseout="this.style.borderColor='var(--border2)'">
              <span style="font-size:18px">📎</span>
              <span class="ro-file-hint">Click to select files, or drag &amp; drop</span>
              <input type="file" class="ro-file-input" multiple accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.txt" style="display:none">
            </label>
            <div class="ro-file-list" style="margin-top:8px;display:flex;flex-wrap:wrap;gap:6px"></div>
          </div>
          <div style="display:flex;gap:10px;justify-content:center">
            <button class="ro-cancel" style="padding:10px 24px;border-radius:10px;border:1.5px solid var(--border2);background:transparent;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:600;color:var(--text2)">Cancel</button>
            <button class="ro-confirm" disabled style="padding:10px 24px;border-radius:10px;border:none;background:linear-gradient(135deg,#7c3aed,#4f46e5);color:#fff;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:700;box-shadow:0 4px 16px rgba(124,58,237,.35);opacity:.6;transition:opacity .15s"
              onmouseenter="if(!this.disabled)this.style.opacity='.85'" onmouseleave="if(!this.disabled)this.style.opacity='1'">
              🔄 Confirm Re-open
            </button>
          </div>
        </div>`;
      document.body.appendChild(overlay);

      // ── All queries scoped to overlay — no global getElementById ──
      const confirmBtn  = overlay.querySelector('.ro-confirm');
      const cancelBtn   = overlay.querySelector('.ro-cancel');
      const textarea    = overlay.querySelector('.ro-remarks');
      const errMsg      = overlay.querySelector('.ro-err');
      const fileInput   = overlay.querySelector('.ro-file-input');
      const fileList    = overlay.querySelector('.ro-file-list');
      const fileHint    = overlay.querySelector('.ro-file-hint');

      // Attached files store: [{name, dataUrl, mediaType}]
      let attachedFiles = [];

      function renderFileChips() {
        fileList.innerHTML = attachedFiles.map((f, i) =>
          '<span style="display:inline-flex;align-items:center;gap:5px;background:var(--accent-subtle);border:1px solid var(--accent-glow);border-radius:20px;padding:3px 10px;font-size:11.5px;color:var(--accent);font-weight:600;">' +
            '<span style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + f.name + '</span>' +
            '<span onclick="this.parentElement._removeIdx(' + i + ')" style="cursor:pointer;font-size:13px;color:var(--text3);margin-left:2px">&times;</span>' +
          '</span>'
        ).join('');
        // Attach remove handler to each chip
        fileList.querySelectorAll('span[style]').forEach((chip, i) => {
          chip._removeIdx = function(idx) {
            attachedFiles.splice(idx, 1);
            renderFileChips();
          };
        });
        fileHint.textContent = attachedFiles.length
          ? attachedFiles.length + ' file' + (attachedFiles.length > 1 ? 's' : '') + ' selected — click to add more'
          : 'Click to select files, or drag & drop';
      }

      function readFiles(files) {
        Array.from(files).forEach(file => {
          const reader = new FileReader();
          reader.onload = e => {
            attachedFiles.push({ name: file.name, dataUrl: e.target.result, mediaType: file.type });
            renderFileChips();
          };
          reader.readAsDataURL(file);
        });
      }

      fileInput.addEventListener('change', () => { readFiles(fileInput.files); fileInput.value = ''; });

      // Drag-and-drop on the label
      const fileLabel = overlay.querySelector('.ro-file-label');
      fileLabel.addEventListener('dragover', e => { e.preventDefault(); fileLabel.style.borderColor = 'var(--accent)'; });
      fileLabel.addEventListener('dragleave', () => { fileLabel.style.borderColor = 'var(--border2)'; });
      fileLabel.addEventListener('drop', e => { e.preventDefault(); fileLabel.style.borderColor = 'var(--border2)'; readFiles(e.dataTransfer.files); });

      textarea.focus();

      textarea.addEventListener('input', () => {
        const hasText = !!textarea.value.trim();
        confirmBtn.disabled = !hasText;
        confirmBtn.style.opacity = hasText ? '1' : '.6';
      });

      cancelBtn.onclick = () => overlay.remove();
      overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });

      confirmBtn.onclick = () => {
        const remark = textarea.value.trim();
        if (!remark) { errMsg.style.display = 'block'; textarea.focus(); return; }

        // Close modal first — unconditionally
        overlay.remove();

        try {
          const rd         = ROLES[currentUser.role];
          const dept       = rd ? (rd.dept || 'System') : 'System';
          const now        = new Date();
          const ts         = now.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
                           + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
          const reopenedBy = currentUser.name || currentUser.id || currentUser.role;

          // ── Apply state ──
          app.status     = restoreStatus;
          app.reopenedAt = now.toISOString();
          app.reopenedBy = reopenedBy;

          // ── Tracking entry ──
          app.tracking = app.tracking || [];
          const rejDate = app.rejectedAt
            ? new Date(app.rejectedAt).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
            : '\u2014';
          app.tracking.push({
            id: app.tracking.length + 1,
            name: 'EFIN-Re-opened',
            current_stage: dept,
            current_user: reopenedBy,
            status: 'Re-opened',
            comment: remark,
            sub_note: 'Resumed from: ' + restoreLabel + ' \xB7 Rejected on: ' + rejDate +
              (attachedFiles.length ? ' \xB7 ' + attachedFiles.length + ' doc(s) attached' : ''),
            date: ts,
            attachments: attachedFiles.length ? attachedFiles.slice() : undefined
          });

          // ── Re-render ──
          openDetail(id);
          renderTable();
          flashTableRow(id);
          updateDashboardStats();
          renderPipeline();
          renderActivity();
          if (typeof persistSave === 'function') persistSave();

          showToast(id + ' re-opened \u2014 resumed at ' + restoreLabel + (attachedFiles.length ? ' \xB7 ' + attachedFiles.length + ' doc(s) saved' : '') + ' \u2713', 'success');
        } catch (err) {
          console.error('reopenApp error:', err);
          showToast('Re-open failed: ' + (err.message || err), 'error');
        }
      };
    }
    window.reopenApp = reopenApp;

    // ── Un-hold application — restores to the exact pre-hold stage ──
    function unholdApp(id) {
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app) return;
      if (app.status !== 'hold') { showToast('Application is not currently on hold', 'warn'); return; }

      // Final-stage lock: only admin may un-hold
      if (typeof guardFinalLock === 'function' && !guardFinalLock(app, 'Un-hold')) return;

      // Blocked for partner and dsa_user
      if (['partner','dsa_user'].includes(currentUser.role)) {
        showToast('You do not have permission to un-hold applications', 'error'); return;
      }

      const restoreStatus = app.preHoldStatus || 'wip';
      const restoreLabel  = STATUSES[restoreStatus] || restoreStatus;
      const heldSince     = app.hold_start_time
        ? new Date(app.hold_start_time).toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
        : '—';

      // Guard: prevent duplicate overlays
      const existingOverlay = document.getElementById('unhold-overlay');
      if (existingOverlay) existingOverlay.remove();

      const overlay = document.createElement('div');
      overlay.id = 'unhold-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(8,18,52,.65);backdrop-filter:blur(10px);display:flex;align-items:center;justify-content:center;padding:16px';
      overlay.innerHTML =
        '<div style="background:var(--surface);border:1.5px solid var(--border);border-radius:22px;padding:36px;max-width:480px;width:100%;box-shadow:0 40px 100px rgba(12,23,61,.3);max-height:90vh;overflow-y:auto">' +
          '<div style="font-size:38px;text-align:center;margin-bottom:14px">\u25B6\uFE0F</div>' +
          '<div style="font-family:var(--font-head);font-size:18px;font-weight:800;margin-bottom:6px;text-align:center">Un-hold Application?</div>' +
          '<div style="font-size:12.5px;color:var(--text2);text-align:center;margin-bottom:4px"><strong>' + app.name + '</strong> \xB7 ' + id + '</div>' +
          '<div style="font-size:12px;color:var(--text3);text-align:center;margin-bottom:4px">On hold since: <strong>' + heldSince + '</strong></div>' +
          '<div style="font-size:12px;color:var(--text3);text-align:center;margin-bottom:20px">Will resume processing from: <span style="font-weight:700;color:var(--accent)">' + restoreLabel + '</span></div>' +
          '<div style="margin-bottom:16px">' +
            '<label style="font-size:12px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;display:block;margin-bottom:6px">Remarks <span style="color:var(--danger)">*</span></label>' +
            '<textarea class="uh-remarks" rows="3" placeholder="Enter reason for removing hold\u2026" style="width:100%;padding:10px 12px;font-size:13px;font-family:var(--font-body);background:var(--surface2);border:1.5px solid var(--border2);border-radius:10px;color:var(--text);resize:vertical;outline:none;box-sizing:border-box"></textarea>' +
            '<div class="uh-err" style="font-size:11.5px;color:var(--danger);margin-top:4px;display:none">Please enter a remark before un-holding.</div>' +
          '</div>' +
          '<div style="margin-bottom:20px">' +
            '<label style="font-size:12px;font-weight:700;color:var(--text2);text-transform:uppercase;letter-spacing:.6px;display:block;margin-bottom:6px">Attach Documents <span style="font-size:10px;font-weight:400;text-transform:none;color:var(--text3)">(optional \u2014 multiple files)</span></label>' +
            '<label class="uh-file-label" style="display:flex;align-items:center;gap:8px;padding:10px 14px;background:var(--surface2);border:1.5px dashed var(--border2);border-radius:10px;cursor:pointer;font-size:12.5px;color:var(--text3);transition:border-color .15s" onmouseover="this.style.borderColor=\'var(--accent)\'" onmouseout="this.style.borderColor=\'var(--border2)\'">' +
              '<span style="font-size:18px">\uD83D\uDCCE</span>' +
              '<span class="uh-file-hint">Click to select files, or drag &amp; drop</span>' +
              '<input type="file" class="uh-file-input" multiple accept="image/*,.pdf,.doc,.docx,.xls,.xlsx,.txt" style="display:none">' +
            '</label>' +
            '<div class="uh-file-list" style="margin-top:8px;display:flex;flex-wrap:wrap;gap:6px"></div>' +
          '</div>' +
          '<div style="display:flex;gap:10px;justify-content:center">' +
            '<button class="uh-cancel" style="padding:10px 24px;border-radius:10px;border:1.5px solid var(--border2);background:transparent;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:600;color:var(--text2)">Cancel</button>' +
            '<button class="uh-confirm" disabled style="padding:10px 24px;border-radius:10px;border:none;background:linear-gradient(135deg,#e67e00,#f59e0b);color:#fff;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:700;box-shadow:0 4px 16px rgba(230,126,0,.35);opacity:.6;transition:opacity .15s">' +
              '\u25B6 Confirm Un-hold' +
            '</button>' +
          '</div>' +
        '</div>';
      document.body.appendChild(overlay);

      const confirmBtn = overlay.querySelector('.uh-confirm');
      const cancelBtn  = overlay.querySelector('.uh-cancel');
      const textarea   = overlay.querySelector('.uh-remarks');
      const errMsg     = overlay.querySelector('.uh-err');
      const fileInput  = overlay.querySelector('.uh-file-input');
      const fileList   = overlay.querySelector('.uh-file-list');
      const fileHint   = overlay.querySelector('.uh-file-hint');
      const fileLabel  = overlay.querySelector('.uh-file-label');

      let attachedFiles = [];

      function renderFileChips() {
        fileList.innerHTML = attachedFiles.map((f, i) =>
          '<span style="display:inline-flex;align-items:center;gap:5px;background:var(--accent-subtle);border:1px solid var(--accent-glow);border-radius:20px;padding:3px 10px;font-size:11.5px;color:var(--accent);font-weight:600">' +
            '<span style="max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">' + f.name + '</span>' +
            '<span class="uh-rm" data-i="' + i + '" style="cursor:pointer;font-size:13px;color:var(--text3);margin-left:2px">&times;</span>' +
          '</span>'
        ).join('');
        fileList.querySelectorAll('.uh-rm').forEach(btn => {
          btn.onclick = function() { attachedFiles.splice(parseInt(this.dataset.i), 1); renderFileChips(); };
        });
        fileHint.textContent = attachedFiles.length
          ? attachedFiles.length + ' file' + (attachedFiles.length > 1 ? 's' : '') + ' selected \u2014 click to add more'
          : 'Click to select files, or drag & drop';
      }

      function readFiles(files) {
        Array.from(files).forEach(file => {
          const reader = new FileReader();
          reader.onload = e => {
            attachedFiles.push({ name: file.name, dataUrl: e.target.result, mediaType: file.type });
            renderFileChips();
          };
          reader.readAsDataURL(file);
        });
      }

      fileInput.addEventListener('change', () => { readFiles(fileInput.files); fileInput.value = ''; });
      fileLabel.addEventListener('dragover', e => { e.preventDefault(); fileLabel.style.borderColor = 'var(--accent)'; });
      fileLabel.addEventListener('dragleave', () => { fileLabel.style.borderColor = 'var(--border2)'; });
      fileLabel.addEventListener('drop', e => { e.preventDefault(); fileLabel.style.borderColor = 'var(--border2)'; readFiles(e.dataTransfer.files); });

      textarea.focus();

      textarea.addEventListener('input', () => {
        const hasText = !!textarea.value.trim();
        confirmBtn.disabled = !hasText;
        confirmBtn.style.opacity = hasText ? '1' : '.6';
      });

      cancelBtn.onclick = () => overlay.remove();
      overlay.addEventListener('click', e => { if (e.target === overlay) overlay.remove(); });

      confirmBtn.onclick = () => {
        const remark = textarea.value.trim();
        if (!remark) { errMsg.style.display = 'block'; textarea.focus(); return; }

        overlay.remove();

        try {
          const rd        = ROLES[currentUser.role];
          const dept      = rd ? (rd.dept || 'System') : 'System';
          const now       = new Date();
          const ts        = now.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
                          + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
          const unHeldBy  = currentUser.name || currentUser.id || currentUser.role;

          app.status          = restoreStatus;
          app.unHeldAt        = now.toISOString();
          app.unHeldBy        = unHeldBy;
          app.hold_start_time = null;

          // ── Save attached documents to Documents tab ──
          if (attachedFiles.length > 0) {
            app.uploadedDocs = app.uploadedDocs || [];
            const uploadedAt = now.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' })
              + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
            attachedFiles.forEach(function(f) {
              app.uploadedDocs.push({
                docName:    f.name,
                fileName:   f.name,
                dataUrl:    f.dataUrl,
                mediaType:  f.mediaType,
                isPdf:      f.mediaType === 'application/pdf',
                uploadedAt: uploadedAt,
                uploadedBy: unHeldBy,
                source:     'Un-hold',
                isPasswordProtected: false
              });
            });
          }

          app.tracking = app.tracking || [];
          app.tracking.push({
            id: app.tracking.length + 1,
            name: 'EFIN-Un-hold',
            current_stage: dept,
            current_user: unHeldBy,
            status: 'Un-hold',
            comment: remark,
            sub_note: 'Resumed from: ' + restoreLabel + ' \xB7 Held since: ' + heldSince +
              (attachedFiles.length ? ' \xB7 ' + attachedFiles.length + ' doc(s) attached' : ''),
            date: ts,
            attachments: attachedFiles.length ? attachedFiles.slice() : undefined
          });

          openDetail(id);
          renderTable();
          flashTableRow(id);
          updateDashboardStats();
          renderPipeline();
          renderActivity();
          if (typeof persistSave === 'function') persistSave();

          showToast(id + ' un-held \u2014 resumed at ' + restoreLabel + (attachedFiles.length ? ' \xB7 ' + attachedFiles.length + ' doc(s) saved' : '') + ' \u2713', 'success');
        } catch (err) {
          console.error('unholdApp error:', err);
          showToast('Un-hold failed: ' + (err.message || err), 'error');
        }
      };
    }
    window.unholdApp = unholdApp;

    // ── Delete application (Admin only) ──
    function deleteApplication(id, event) {
      if (event) event.stopPropagation();
      if (currentUser.role !== 'admin') {
        showToast('Only Admins can delete applications', 'error'); return;
      }
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app) return;

      // Use a styled confirm modal instead of browser confirm
      const overlay = document.createElement('div');
      overlay.style.cssText = 'position:fixed;inset:0;z-index:10000;background:rgba(8,18,52,.65);backdrop-filter:blur(10px);display:flex;align-items:center;justify-content:center';
      overlay.innerHTML = `
    <div style="background:var(--surface);border:1.5px solid var(--border);border-radius:22px;padding:36px;max-width:400px;width:90%;text-align:center;box-shadow:0 40px 100px rgba(12,23,61,.3)">
      <div style="font-size:48px;margin-bottom:16px">🗑️</div>
      <div style="font-family:var(--font-head);font-size:18px;font-weight:800;margin-bottom:8px;color:var(--danger)">Delete Application?</div>
      <div style="font-size:13px;color:var(--text2);margin-bottom:6px"><strong>${app.name}</strong></div>
      <div style="font-size:12px;color:var(--text3);margin-bottom:24px">${app.id} · ${loanTypeLabel(app.loanType)} · ₹${Number(app.amount).toLocaleString('en-IN')}</div>
      <div style="font-size:12.5px;color:var(--text3);background:rgba(192,57,43,.07);border:1px solid rgba(192,57,43,.18);border-radius:10px;padding:10px;margin-bottom:24px">⚠️ This action is permanent and cannot be undone.</div>
      <div style="display:flex;gap:10px;justify-content:center">
        <button id="del-cancel" style="padding:10px 22px;border-radius:10px;border:1.5px solid var(--border2);background:transparent;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:600;color:var(--text2)">Cancel</button>
        <button id="del-confirm" style="padding:10px 22px;border-radius:10px;border:none;background:var(--danger);color:#fff;cursor:pointer;font-family:var(--font-body);font-size:13px;font-weight:700;box-shadow:0 4px 16px rgba(192,57,43,.35)">Yes, Delete</button>
      </div>
    </div>`;
      document.body.appendChild(overlay);

      document.getElementById('del-cancel').onclick = () => overlay.remove();
      document.getElementById('del-confirm').onclick = () => {
        const idx = APPLICATIONS.findIndex(a => a.id === id);
        if (idx !== -1) {
          APPLICATIONS.splice(idx, 1);
          renderTable();
          updateDashboardStats();
          renderPipeline();
          renderActivity();
          if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
          showToast(`Application ${id} deleted`, 'warn');
          // If detail page was open, go back
          const detailPage = document.getElementById('page-app-detail');
          if (detailPage && detailPage.classList.contains('active')) {
            showPage('applications', null);
          }
        }
        overlay.remove();
      };
    }

    // ═══════════════════════════════════════════════════════
    //  EMI CALCULATOR v2 — Upgraded
    // ═══════════════════════════════════════════════════════
    let _calcType = 'reducing';   // 'reducing' | 'flat'
    let _amortView = 'monthly';   // 'monthly' | 'yearly'
    let _calcAmortData = [];      // full schedule array

    const fmtINR = v => '₹' + Math.round(v).toLocaleString('en-IN');

    // ── Mode switch ──
    function calcSwitchMode(mode, btn) {
      ['standard','compare','prepay','reverse'].forEach(m => {
        const el = document.getElementById('calc-mode-' + m);
        if (el) el.style.display = m === mode ? '' : 'none';
      });
      document.querySelectorAll('.calc-mode-tab').forEach(b => b.classList.remove('active'));
      if (btn) btn.classList.add('active');
    }

    // ── Loan type toggle ──
    function calcSetType(type, btn) {
      _calcType = type;
      document.getElementById('calc-type-reducing').classList.toggle('active', type === 'reducing');
      document.getElementById('calc-type-flat').classList.toggle('active', type === 'flat');
      calcEmi();
    }

    // ── Slider ↔ input sync ──
    function calcSyncInput(field) {
      if (field === 'amt') {
        const v = parseFloat(document.getElementById('calc-amt')?.value) || 0;
        const r = document.getElementById('calc-amt-range');
        if (r) r.value = Math.min(v, 10000000);
        document.getElementById('calc-amt-badge').textContent = v ? fmtINR(v) : '₹0';
      } else if (field === 'rate') {
        const v = parseFloat(document.getElementById('calc-rate')?.value) || 0;
        const r = document.getElementById('calc-rate-range');
        if (r) r.value = Math.min(v, 30);
        document.getElementById('calc-rate-badge').textContent = v ? v + '%' : '0%';
      }
    }
    function calcSyncRange(field) {
      if (field === 'amt') {
        const v = parseFloat(document.getElementById('calc-amt-range')?.value) || 0;
        const inp = document.getElementById('calc-amt');
        if (inp) inp.value = v;
        document.getElementById('calc-amt-badge').textContent = fmtINR(v);
      } else if (field === 'rate') {
        const v = parseFloat(document.getElementById('calc-rate-range')?.value) || 0;
        const inp = document.getElementById('calc-rate');
        if (inp) inp.value = v;
        document.getElementById('calc-rate-badge').textContent = v + '%';
      } else if (field === 'tenure') {
        const v = parseInt(document.getElementById('calc-tenure-range')?.value) || 0;
        const mth = document.getElementById('calc-tenure');
        const yrs = document.getElementById('calc-tenure-years');
        if (mth) mth.value = v;
        if (yrs) yrs.value = (v / 12).toFixed(v % 12 === 0 ? 0 : 1);
        document.getElementById('calc-tenure-badge').textContent = v + ' mo';
      }
    }

    // ── Tenure year/month sync ──
    function calcEmiSyncYears() {
      const yrs = parseFloat(document.getElementById('calc-tenure-years')?.value) || 0;
      const mth = Math.round(yrs * 12);
      const mEl = document.getElementById('calc-tenure');
      const rEl = document.getElementById('calc-tenure-range');
      if (mEl) mEl.value = mth;
      if (rEl) rEl.value = mth;
      document.getElementById('calc-tenure-badge').textContent = mth ? mth + ' mo' : '0 mo';
      calcEmi();
    }
    function calcEmiSyncMonths() {
      const mth = parseInt(document.getElementById('calc-tenure')?.value) || 0;
      const yEl = document.getElementById('calc-tenure-years');
      const rEl = document.getElementById('calc-tenure-range');
      if (yEl) yEl.value = (mth / 12).toFixed(mth % 12 === 0 ? 0 : 1);
      if (rEl) rEl.value = mth;
      document.getElementById('calc-tenure-badge').textContent = mth ? mth + ' mo' : '0 mo';
      calcEmi();
    }

    // ── Core EMI math ──
    function _emiReducing(P, annualRate, months) {
      const r = annualRate / 12 / 100;
      if (r === 0) return { emi: P / months, total: P, totalInt: 0 };
      const emi = P * r * Math.pow(1 + r, months) / (Math.pow(1 + r, months) - 1);
      const total = emi * months;
      return { emi, total, totalInt: total - P };
    }
    function _emiFlat(P, annualRate, months) {
      const totalInt = P * (annualRate / 100) * (months / 12);
      const total = P + totalInt;
      const emi = total / months;
      return { emi, total, totalInt };
    }
    function computeEmi(P, annualRate, months) {
      return _calcType === 'flat' ? _emiFlat(P, annualRate, months) : _emiReducing(P, annualRate, months);
    }

    // ── Build full amortisation schedule ──
    function buildAmortSchedule(P, annualRate, months) {
      const r = annualRate / 12 / 100;
      const { emi } = _emiReducing(P, annualRate, months);
      let balance = P, rows = [];
      for (let m = 1; m <= months; m++) {
        const intPart = balance * r;
        const prinPart = Math.min(emi - intPart, balance);
        balance = Math.max(balance - prinPart, 0);
        rows.push({ m, emi, prin: prinPart, int: intPart, balance });
      }
      return rows;
    }

    // ── Render amort table ──
    function calcAmortView(view, btn) {
      _amortView = view;
      document.getElementById('amort-btn-monthly').classList.toggle('active', view === 'monthly');
      document.getElementById('amort-btn-yearly').classList.toggle('active', view === 'yearly');
      renderAmortTable();
    }
    function renderAmortTable() {
      const tbody = document.getElementById('amort-body');
      if (!tbody || !_calcAmortData.length) return;
      let html = '';
      if (_amortView === 'monthly') {
        _calcAmortData.forEach(row => {
          const paid = ((_calcAmortData[0]?.balance + _calcAmortData[0]?.prin - row.balance) / (_calcAmortData[0]?.balance + _calcAmortData[0]?.prin) * 100) || 0;
          html += `<tr>
            <td>Month ${row.m}</td>
            <td>${fmtINR(row.emi)}</td>
            <td>${fmtINR(row.prin)}</td>
            <td>${fmtINR(row.int)}</td>
            <td>${fmtINR(row.balance)}</td>
            <td><div style="display:flex;align-items:center;gap:6px;justify-content:flex-end">
              <div style="width:40px;height:4px;background:var(--surface3);border-radius:99px;overflow:hidden">
                <div style="height:100%;width:${Math.min(100,paid)}%;background:var(--accent);border-radius:99px"></div>
              </div>
              <span style="font-size:11px">${paid.toFixed(0)}%</span>
            </div></td>
          </tr>`;
        });
      } else {
        // Yearly summary
        const years = {};
        _calcAmortData.forEach(r => {
          const yr = Math.ceil(r.m / 12);
          if (!years[yr]) years[yr] = { yr, totalEmi: 0, totalPrin: 0, totalInt: 0, balance: 0 };
          years[yr].totalEmi  += r.emi;
          years[yr].totalPrin += r.prin;
          years[yr].totalInt  += r.int;
          years[yr].balance    = r.balance;
        });
        Object.values(years).forEach(y => {
          html += `<tr class="year-row">
            <td>Year ${y.yr}</td>
            <td>${fmtINR(y.totalEmi)}</td>
            <td>${fmtINR(y.totalPrin)}</td>
            <td>${fmtINR(y.totalInt)}</td>
            <td>${fmtINR(y.balance)}</td>
            <td>—</td>
          </tr>`;
        });
      }
      tbody.innerHTML = html;
    }

    // ── Main calcEmi ──
    function calcEmi() {
      const P         = parseFloat(document.getElementById('calc-amt')?.value)         || 0;
      const annualRate= parseFloat(document.getElementById('calc-rate')?.value)        || 0;
      const months    = parseInt(document.getElementById('calc-tenure')?.value)        || 0;
      const salary    = parseFloat(document.getElementById('calc-salary')?.value)      || 0;
      const obligations = parseFloat(document.getElementById('calc-obligations-inp')?.value) || 0;

      // Update badges
      document.getElementById('calc-amt-badge').textContent  = P ? fmtINR(P) : '₹0';
      document.getElementById('calc-rate-badge').textContent = annualRate ? annualRate + '%' : '0%';
      document.getElementById('calc-tenure-badge').textContent = months ? months + ' mo' : '0 mo';
      if (salary) document.getElementById('calc-salary-badge').textContent = fmtINR(salary);
      if (obligations) document.getElementById('calc-oblig-badge').textContent = fmtINR(obligations);

      const wrap = document.getElementById('calc-result-card-wrap');
      const amortSec = document.getElementById('calc-amort-section');

      if (!(P > 0 && annualRate > 0 && months > 0)) {
        if (wrap) wrap.style.display = 'none';
        if (amortSec) amortSec.style.display = 'none';
        return;
      }

      if (wrap) wrap.style.display = '';
      if (amortSec) amortSec.style.display = '';

      const { emi, total, totalInt } = computeEmi(P, annualRate, months);
      const intPct   = Math.round(totalInt / total * 100);
      const prinPct  = 100 - intPct;
      const CIRC     = 2 * Math.PI * 38; // circumference for r=38

      // Hero EMI
      document.getElementById('calc-emi-val').textContent    = fmtINR(emi);
      document.getElementById('calc-principal').textContent  = fmtINR(P);
      document.getElementById('calc-interest').textContent   = fmtINR(totalInt);
      document.getElementById('calc-total').textContent      = fmtINR(total);
      document.getElementById('calc-type-note').textContent  = _calcType === 'flat' ? 'Flat rate method' : 'Reducing balance method';

      // Donut chart
      const intArc   = CIRC * intPct / 100;
      const prinArc  = CIRC * prinPct / 100;
      const intEl    = document.getElementById('calc-donut-interest');
      const prinEl   = document.getElementById('calc-donut-principal');
      if (intEl)  { intEl.setAttribute('stroke-dasharray',  `${intArc} ${CIRC - intArc}`);  intEl.setAttribute('stroke-dashoffset', '0'); }
      if (prinEl) { prinEl.setAttribute('stroke-dasharray', `${prinArc} ${CIRC - prinArc}`); prinEl.setAttribute('stroke-dashoffset', -intArc); }
      document.getElementById('calc-principal-pct').textContent = prinPct + '%';
      document.getElementById('calc-interest-pct').textContent  = intPct + '%';
      const costMultiplier = (total / P).toFixed(2);
      document.getElementById('calc-cost-note').textContent = `Cost of credit: ${costMultiplier}× principal`;

      // FOIR
      const foirSec = document.getElementById('calc-foir-section');
      if (salary > 0) {
        foirSec.style.display = '';
        const totalEmi = emi + obligations;
        const foirPct  = totalEmi / salary * 100;
        const fill     = document.getElementById('calc-foir-fill');
        const foirZone = foirPct <= 40 ? { lbl: 'Conservative — Healthy', col: 'var(--success)' }
                       : foirPct <= 50 ? { lbl: 'Standard — Acceptable',  col: 'var(--accent)'  }
                       : foirPct <= 65 ? { lbl: 'Moderate — Watch out',   col: 'var(--warn)'    }
                       :                 { lbl: 'High — Risk of rejection',col: 'var(--danger)' };
        document.getElementById('calc-foir-pct').textContent     = foirPct.toFixed(1) + '%' + (obligations ? ' (incl. other EMIs)' : '');
        fill.style.width      = Math.min(foirPct, 100) + '%';
        fill.style.background = foirZone.col;
        document.getElementById('calc-foir-verdict').innerHTML   = `<span style="color:${foirZone.col}">${foirZone.lbl}</span>`;
        const maxEmi = salary * 0.50 - obligations;
        document.getElementById('calc-max-eligible').textContent = maxEmi > 0
          ? `Max eligible EMI at 50% FOIR: ${fmtINR(Math.max(0, maxEmi))}`
          : 'Existing obligations exceed 50% FOIR limit';
      } else {
        foirSec.style.display = 'none';
      }

      // What-if rate table
      const baseRate = annualRate;
      const offsets  = [-2, -1, 0, 1, 2];
      const wBody    = document.getElementById('calc-whatif-body');
      if (wBody) {
        wBody.innerHTML = offsets.map(d => {
          const r = Math.max(0.1, baseRate + d);
          const { emi: e2, totalInt: ti2 } = _emiReducing(P, r, months);
          const isBase = d === 0;
          return `<tr ${isBase ? 'class="active-row"' : ''}>
            <td>${r.toFixed(1)}%${isBase ? ' ★' : ''}</td>
            <td style="text-align:right;font-family:var(--font-head)">${fmtINR(e2)}</td>
            <td style="text-align:right;font-family:var(--font-head)">${fmtINR(ti2)}</td>
          </tr>`;
        }).join('');
      }

      // Amortisation
      _calcAmortData = _calcType === 'flat'
        ? (() => {
            // flat: equal principal each month
            const monthlyPrin = P / months;
            return Array.from({length: months}, (_,i) => {
              const m = i + 1;
              const int = (P - monthlyPrin * i) * (annualRate / 100 / 12);
              const balance = P - monthlyPrin * m;
              return { m, emi: monthlyPrin + int, prin: monthlyPrin, int, balance: Math.max(balance, 0) };
            });
          })()
        : buildAmortSchedule(P, annualRate, months);

      renderAmortTable();
    }

    // ── Compare mode ──
    function calcCompare() {
      const readLoan = prefix => {
        const amt    = parseFloat(document.getElementById(prefix+'-amt')?.value)    || 0;
        const rate   = parseFloat(document.getElementById(prefix+'-rate')?.value)   || 0;
        const yrs    = parseFloat(document.getElementById(prefix+'-years')?.value)  || 0;
        const months = parseInt(document.getElementById(prefix+'-months')?.value)   || (yrs > 0 ? Math.round(yrs*12) : 0);
        return { amt, rate, months };
      };
      const A = readLoan('cmpA'), B = readLoan('cmpB');
      ['A','B'].forEach(ltr => {
        const l = ltr === 'A' ? A : B;
        const resEl = document.getElementById('cmp'+ltr+'-result');
        if (l.amt > 0 && l.rate > 0 && l.months > 0) {
          const { emi, total, totalInt } = _emiReducing(l.amt, l.rate, l.months);
          document.getElementById('cmp'+ltr+'-amt-badge').textContent  = fmtINR(l.amt);
          document.getElementById('cmp'+ltr+'-rate-badge').textContent = l.rate + '%';
          document.getElementById('cmp'+ltr+'-emi').textContent        = fmtINR(emi);
          document.getElementById('cmp'+ltr+'-interest').textContent   = fmtINR(totalInt);
          document.getElementById('cmp'+ltr+'-total').textContent      = fmtINR(total);
          resEl.style.display = '';
          l._emi = emi; l._totalInt = totalInt; l._total = total;
        } else {
          resEl.style.display = 'none';
        }
      });
      const diffEl = document.getElementById('cmp-diff');
      if (A._emi && B._emi) {
        diffEl.style.display = '';
        const winner  = A._emi <= B._emi ? 'A' : 'B';
        const diffEmi = Math.abs(A._emi - B._emi);
        const diffInt = Math.abs(A._totalInt - B._totalInt);
        document.getElementById('cmp-diff-body').innerHTML = `
          <div class="diff-row"><span class="diff-label">Lower Monthly EMI</span><span class="diff-val ${winner==='A'?'diff-better':'diff-worse'}">Loan ${winner} saves ${fmtINR(diffEmi)}/mo</span></div>
          <div class="diff-row"><span class="diff-label">Total Interest</span><span class="diff-val">A: ${fmtINR(A._totalInt)} &nbsp;|&nbsp; B: ${fmtINR(B._totalInt)}</span></div>
          <div class="diff-row"><span class="diff-label">Interest Saved</span><span class="diff-val diff-better">${fmtINR(diffInt)} (Loan ${A._totalInt <= B._totalInt ? 'A' : 'B'} is better)</span></div>
          <div class="diff-row"><span class="diff-label">Total Payable</span><span class="diff-val">A: ${fmtINR(A._total)} &nbsp;|&nbsp; B: ${fmtINR(B._total)}</span></div>`;
      } else {
        diffEl.style.display = 'none';
      }
    }

    // ── Prepayment mode ──
    function calcPrepay() {
      const P       = parseFloat(document.getElementById('pp-amt')?.value)    || 0;
      const rate    = parseFloat(document.getElementById('pp-rate')?.value)   || 0;
      const months  = parseInt(document.getElementById('pp-tenure')?.value)   || 0;
      const extra   = parseFloat(document.getElementById('pp-extra')?.value)  || 0;
      const startM  = parseInt(document.getElementById('pp-start')?.value)    || 1;

      document.getElementById('pp-amt-badge').textContent    = P ? fmtINR(P) : '₹0';
      document.getElementById('pp-rate-badge').textContent   = rate ? rate + '%' : '0%';
      document.getElementById('pp-tenure-badge').textContent = months ? months + ' mo' : '0 mo';
      document.getElementById('pp-extra-badge').textContent  = extra ? fmtINR(extra) : '₹0';
      document.getElementById('pp-start-badge').textContent  = startM ? 'Mo ' + startM : '—';

      const wrap = document.getElementById('pp-result-wrap');
      if (!(P > 0 && rate > 0 && months > 0)) { wrap.style.display = 'none'; return; }
      wrap.style.display = '';

      const { emi, totalInt: origTotalInt } = _emiReducing(P, rate, months);
      document.getElementById('pp-orig-emi').textContent      = fmtINR(emi);
      document.getElementById('pp-orig-interest').textContent = fmtINR(origTotalInt);

      // Simulate with prepayment
      const r = rate / 12 / 100;
      let balance = P, m = 0, totalIntNew = 0;
      while (balance > 0.5 && m < months * 3) {
        m++;
        const intPart  = balance * r;
        const payment  = emi + (m >= startM ? extra : 0);
        const prinPart = Math.min(payment - intPart, balance);
        totalIntNew   += intPart;
        balance        = Math.max(balance - prinPart, 0);
      }

      const saved = origTotalInt - totalIntNew;
      const moSaved = months - m;
      document.getElementById('pp-new-interest').textContent  = fmtINR(totalIntNew);
      document.getElementById('pp-interest-saved').textContent= fmtINR(Math.max(saved, 0));
      document.getElementById('pp-months-saved').textContent  = moSaved > 0 ? moSaved + ' mo' : '0';
      document.getElementById('pp-new-tenure').textContent    = m + ' mo';
    }

    // ═══════════════════════════════════════════════════════
    //  REVERSE EMI CALCULATOR — Loan Amount from EMI & Tenure
    // ═══════════════════════════════════════════════════════
    let _revCalcType = 'reducing'; // 'reducing' | 'flat'

    // ── Interest method toggle ──
    function revSetType(type, btn) {
      _revCalcType = type;
      document.getElementById('rev-type-reducing').classList.toggle('active', type === 'reducing');
      document.getElementById('rev-type-flat').classList.toggle('active', type === 'flat');
      calcReverse();
    }

    // ── Reverse math: P from EMI ──
    // Reducing balance: EMI = P * r * (1+r)^n / ((1+r)^n - 1)
    //   ⟹  P = EMI * ((1+r)^n - 1) / (r * (1+r)^n)
    // Flat rate: EMI = (P + P*R*n/12) / n  ⟹  P = EMI * n / (1 + R*n/12)
    function _reverseLoanReducing(emi, annualRate, months) {
      const r = annualRate / 12 / 100;
      if (r === 0) return { P: emi * months, totalInt: 0, total: emi * months };
      const factor = Math.pow(1 + r, months);
      const P = emi * (factor - 1) / (r * factor);
      const total = emi * months;
      return { P, total, totalInt: total - P };
    }
    function _reverseLoanFlat(emi, annualRate, months) {
      const R = annualRate / 100;
      const P = (emi * months) / (1 + R * months / 12);
      const total = emi * months;
      return { P, total, totalInt: total - P };
    }
    function computeReverseLoan(emi, annualRate, months) {
      return _revCalcType === 'flat'
        ? _reverseLoanFlat(emi, annualRate, months)
        : _reverseLoanReducing(emi, annualRate, months);
    }

    // ── Slider ↔ input sync ──
    function revSyncInput(field) {
      if (field === 'emi') {
        const v = parseFloat(document.getElementById('rev-emi')?.value) || 0;
        const r = document.getElementById('rev-emi-range');
        if (r) r.value = Math.min(v, 500000);
        document.getElementById('rev-emi-badge').textContent = v ? fmtINR(v) : '₹0';
      } else if (field === 'rate') {
        const v = parseFloat(document.getElementById('rev-rate')?.value) || 0;
        const r = document.getElementById('rev-rate-range');
        if (r) r.value = Math.min(v, 36);
        document.getElementById('rev-rate-badge').textContent = v ? v + '%' : '0%';
      }
    }
    function revSyncRange(field) {
      if (field === 'emi') {
        const v = parseFloat(document.getElementById('rev-emi-range')?.value) || 0;
        const inp = document.getElementById('rev-emi');
        if (inp) inp.value = v;
        document.getElementById('rev-emi-badge').textContent = fmtINR(v);
      } else if (field === 'rate') {
        const v = parseFloat(document.getElementById('rev-rate-range')?.value) || 0;
        const inp = document.getElementById('rev-rate');
        if (inp) inp.value = v;
        document.getElementById('rev-rate-badge').textContent = v + '%';
      } else if (field === 'tenure') {
        const v = parseInt(document.getElementById('rev-tenure-range')?.value) || 0;
        const mth = document.getElementById('rev-tenure');
        const yrs = document.getElementById('rev-tenure-years');
        if (mth) mth.value = v;
        if (yrs) yrs.value = (v / 12).toFixed(v % 12 === 0 ? 0 : 1);
        document.getElementById('rev-tenure-badge').textContent = v + ' mo';
      }
    }
    function revSyncYears() {
      const yrs = parseFloat(document.getElementById('rev-tenure-years')?.value) || 0;
      const mth = Math.round(yrs * 12);
      const mEl = document.getElementById('rev-tenure');
      const rEl = document.getElementById('rev-tenure-range');
      if (mEl) mEl.value = mth;
      if (rEl) rEl.value = mth;
      document.getElementById('rev-tenure-badge').textContent = mth ? mth + ' mo' : '0 mo';
      calcReverse();
    }
    function revSyncMonths() {
      const mth = parseInt(document.getElementById('rev-tenure')?.value) || 0;
      const yEl = document.getElementById('rev-tenure-years');
      const rEl = document.getElementById('rev-tenure-range');
      if (yEl) yEl.value = (mth / 12).toFixed(mth % 12 === 0 ? 0 : 1);
      if (rEl) rEl.value = mth;
      document.getElementById('rev-tenure-badge').textContent = mth ? mth + ' mo' : '0 mo';
      calcReverse();
    }

    // ── Main Reverse EMI calculator ──
    function calcReverse() {
      const emi     = parseFloat(document.getElementById('rev-emi')?.value)    || 0;
      const rate    = parseFloat(document.getElementById('rev-rate')?.value)   || 0;
      const months  = parseInt(document.getElementById('rev-tenure')?.value)   || 0;
      const salary  = parseFloat(document.getElementById('rev-salary')?.value) || 0;

      // Badge updates
      document.getElementById('rev-emi-badge').textContent    = emi    ? fmtINR(emi)  : '₹0';
      document.getElementById('rev-rate-badge').textContent   = rate   ? rate + '%'   : '0%';
      document.getElementById('rev-tenure-badge').textContent = months ? months + ' mo' : '0 mo';

      const wrap = document.getElementById('rev-result-wrap');
      if (!(emi > 0 && rate > 0 && months > 0)) {
        if (wrap) wrap.style.display = 'none';
        return;
      }
      if (wrap) wrap.style.display = '';

      const { P, total, totalInt } = computeReverseLoan(emi, rate, months);
      const CIRC    = 2 * Math.PI * 38;
      const intPct  = Math.round(totalInt / total * 100);
      const prinPct = 100 - intPct;

      // Hero result
      document.getElementById('rev-loan-val').textContent       = fmtINR(Math.round(P));
      document.getElementById('rev-total-interest').textContent = fmtINR(Math.round(totalInt));
      document.getElementById('rev-total-payable').textContent  = fmtINR(Math.round(total));
      document.getElementById('rev-cost-ratio').textContent     = (total / P).toFixed(2) + '×';
      document.getElementById('rev-type-note').textContent      = _revCalcType === 'flat'
        ? 'Flat rate method' : 'Reducing balance method';

      // Donut
      const intArc  = CIRC * intPct / 100;
      const prinArc = CIRC * prinPct / 100;
      const intEl   = document.getElementById('rev-donut-interest');
      const prinEl  = document.getElementById('rev-donut-principal');
      if (intEl)  { intEl.setAttribute('stroke-dasharray',  `${intArc} ${CIRC - intArc}`);  intEl.setAttribute('stroke-dashoffset', '0'); }
      if (prinEl) { prinEl.setAttribute('stroke-dasharray', `${prinArc} ${CIRC - prinArc}`); prinEl.setAttribute('stroke-dashoffset', -intArc); }
      document.getElementById('rev-principal-pct').textContent = prinPct + '%';
      document.getElementById('rev-interest-pct').textContent  = intPct + '%';

      // FOIR section
      const foirSec = document.getElementById('rev-foir-section');
      if (salary > 0) {
        foirSec.style.display = '';
        const foirPct = (emi / salary * 100);
        const fill    = document.getElementById('rev-foir-fill');
        const zone    = foirPct <= 40 ? { lbl: 'Conservative — Healthy',   col: 'var(--success)' }
                      : foirPct <= 50 ? { lbl: 'Standard — Acceptable',    col: 'var(--accent)'  }
                      : foirPct <= 65 ? { lbl: 'Moderate — Watch out',     col: 'var(--warn)'    }
                      :                 { lbl: 'High — Risk of rejection',  col: 'var(--danger)' };
        document.getElementById('rev-foir-pct').textContent = foirPct.toFixed(1) + '%';
        fill.style.width      = Math.min(foirPct, 100) + '%';
        fill.style.background = zone.col;
        document.getElementById('rev-foir-verdict').innerHTML = `<span style="color:${zone.col}">${zone.lbl}</span>`;
      } else {
        foirSec.style.display = 'none';
      }

      // Tenure sensitivity table — show loan amounts for ±2 tenure steps
      const tbody = document.getElementById('rev-tenure-body');
      if (tbody) {
        const steps = [-24, -12, 0, 12, 24, 36];
        tbody.innerHTML = steps.map(d => {
          const t = Math.max(6, months + d);
          const { P: lp, totalInt: li } = computeReverseLoan(emi, rate, t);
          const yr = (t / 12).toFixed(t % 12 === 0 ? 0 : 1);
          const isActive = d === 0;
          return `<tr${isActive ? ' class="active-row"' : ''}>
            <td>${t} mo (${yr} yr)</td>
            <td style="text-align:right">${fmtINR(Math.round(lp))}</td>
            <td style="text-align:right">${fmtINR(Math.round(li))}</td>
          </tr>`;
        }).join('');
      }
    }

    // ═══════════════════════════════════════════════════════
    //  DASHBOARD CHARTS
    // ═══════════════════════════════════════════════════════
    function renderPipeline() {
      // Count live from APPLICATIONS (exclude historical seed entries)
      const liveApps = APPLICATIONS.filter(a => !a.id.startsWith('H') && !a.is_draft);
      const stages = PIPELINE_STAGE_META.map(s => ({
        ...s,
        count: liveApps.filter(a => a.status === s.key).length
      })).filter(s => s.count > 0);
      if (!stages.length) {
        document.getElementById('pipeline').innerHTML = '<div style="text-align:center;padding:24px;color:var(--text3);font-size:13px">No active applications</div>';
        return;
      }
      const max = Math.max(...stages.map(s => s.count), 1);
      document.getElementById('pipeline').innerHTML = stages.map(s => `
    <div class="pipeline-stage" onclick="showPage('applications',null);filterByStatus('${s.key}',null)">
      <div class="stage-label">${s.label}</div>
      <div class="stage-bar-wrap"><div class="stage-bar" style="background:${s.color}22;border-left:3px solid ${s.color};color:${s.color};width:${Math.max(18, s.count / max * 100)}%">${s.count}</div></div>
      <div class="stage-count">${s.count}</div>
    </div>`).join('');
    }

    function renderChart() {
      // Build last-6-months application + disbursal counts from APPLICATIONS
      const now = new Date();
      const months = [];
      for (let i = 5; i >= 0; i--) {
        const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
        months.push({ label: d.toLocaleString('en-IN', { month: 'short' }), year: d.getFullYear(), month: d.getMonth() });
      }

      // Parse dates robustly (handles "15 Mar 2026", "2026-03-15", etc.)
      const _chartApps = getPartnerScopedApps();
      const vals = months.map(m =>
        _chartApps.filter(a => {
          const d = parseAppDate(a.date);
          return d && d.getMonth() === m.month && d.getFullYear() === m.year;
        }).length
      );
      const disb = months.map(m =>
        _chartApps.filter(a => {
          const d = parseAppDate(a.date);
          return a.status === 'disbursed' && d && d.getMonth() === m.month && d.getFullYear() === m.year;
        }).length
      );

      const finalVals = vals;
      const finalDisb = disb;

      const maxV = Math.max(...finalVals, 1);
      const currentMonthIdx = 5; // last entry is current month
      document.getElementById('chart-bars').innerHTML = months.map((m, i) => {
        const isCurrent = i === currentMonthIdx;
        const change = i > 0 ? finalVals[i] - finalVals[i - 1] : 0;
        const changeStr = i > 0 ? (change >= 0 ? `<span style="color:var(--danger);font-size:9px">▲${change}</span>` : `<span style="color:var(--danger);font-size:9px">▼${Math.abs(change)}</span>`) : '';
        return `
    <div class="chart-bar-col" style="${isCurrent ? 'opacity:1' : 'opacity:.85'}">
      <div style="font-size:9px;color:var(--text3);text-align:center;margin-bottom:4px;min-height:14px">${changeStr}</div>
      <div style="position:relative;width:100%;display:flex;align-items:flex-end;height:140px;gap:3px">
        <div class="chart-bar-inner" style="height:${Math.max(6, finalVals[i] / maxV * 130)}px;flex:1;${isCurrent ? 'background:rgba(26,79,163,.28);border-color:var(--accent)' : ''}" title="${finalVals[i]} applications in ${m.label}"></div>
        <div class="chart-bar-inner" style="height:${Math.max(finalDisb[i] ? 5 : 0, finalDisb[i] / maxV * 130)}px;flex:1;background:rgba(0,212,170,.25);border-color:#00d4aa;${isCurrent ? 'background:rgba(0,212,170,.4)' : ''}" title="${finalDisb[i]} disbursed in ${m.label}"></div>
      </div>
      <div class="chart-label" style="${isCurrent ? 'color:var(--accent);font-weight:700' : ''}">${m.label}</div>
    </div>`;
      }).join('');

      // Update chart title with current month
      const chartTitle = document.querySelector('.card-head .card-title');
      if (chartTitle && chartTitle.textContent.includes('Monthly')) {
        const fyLabel = document.querySelector('.card-head span[style*="font-size:12px"]');
        if (fyLabel) fyLabel.textContent = `FY ${now.getFullYear() - 1}–${String(now.getFullYear()).slice(-2)}`;
      }
    }

    function renderLoanTypeChart() {
      const _ltcApps = getPartnerScopedApps();
      const total = _ltcApps.length || 1;
      const typeMap = {};
      _ltcApps.forEach(a => { typeMap[a.loanType] = (typeMap[a.loanType] || 0) + 1; });
      const colors = {
        personal_loan: 'var(--accent)', business_loan: 'var(--accent2)', home_loan: '#a159ff',
        new_car_loan: 'var(--accent3)', used_car_loan: '#f59e0b', loan_against_property: '#0891b2',
        over_draft: '#10b981',
        education_loan: '#7c3aed',
        insurance: '#6b7280',
      };
      const sorted = Object.entries(typeMap).sort((a, b) => b[1] - a[1]).slice(0, 6);
      document.getElementById('loan-type-chart').innerHTML = sorted.map(([key, cnt]) => {
        const pct = Math.round(cnt / total * 100);
        const color = colors[key] || 'var(--text3)';
        return `<div style="margin-bottom:12px">
      <div style="display:flex;justify-content:space-between;margin-bottom:5px">
        <span style="font-size:12px;color:var(--text2)">${loanTypeLabel(key)}</span>
        <span style="font-size:12px;font-weight:700;color:var(--text)">${pct}%</span>
      </div>
      <div class="progress-wrap"><div class="progress-bar" style="width:${pct}%;background:${color}"></div></div>
    </div>`;
      }).join('') || '<div style="color:var(--text3);font-size:13px;text-align:center;padding:16px">No data</div>';
    }

    // ═══════════════════════════════════════════════════════
    //  TASKS PAGE
    // ═══════════════════════════════════════════════════════
    let _TASKS_LOCAL = [
    ];

    let _tasksFilter = 'all';

    function filterGlobalTasks(f, btn) {
      _tasksFilter = f;
      document.querySelectorAll('.tasks-filter-btn').forEach(b => b.classList.remove('active'));
      if (btn) btn.classList.add('active');
      renderGlobalTasks();
    }

    function renderGlobalTasks() {
      const body = document.getElementById('global-tasks-body');
      if (!body) return;
      const today = new Date().toISOString().slice(0, 10);
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const isAdmin = currentUser && currentUser.role === 'admin';

      let tasks = _TASKS_LOCAL.filter(t => {
        // Admins see all tasks; others only see tasks they created or are assigned to
        if (!isAdmin && t.createdBy !== uname && t.assignedTo !== uname) return false;
        if (_tasksFilter === 'pending')  return !t.done && t.due >= today;
        if (_tasksFilter === 'overdue')  return !t.done && t.due < today;
        if (_tasksFilter === 'done')     return t.done;
        return true;
      });

      // Sort: overdue first, then by due date, done last
      tasks.sort((a, b) => {
        if (a.done !== b.done) return a.done ? 1 : -1;
        return a.due < b.due ? -1 : 1;
      });

      if (!tasks.length) {
        body.innerHTML = `<div style="text-align:center;padding:48px 24px;color:var(--text3)">
          <div style="font-size:36px;margin-bottom:10px">✅</div>
          <div style="font-size:14px;font-weight:600">No tasks here</div>
        </div>`;
        return;
      }

      body.innerHTML = tasks.map(t => {
        const overdue = !t.done && t.due < today;
        const app = APPLICATIONS.find(a => a.id === t.appId);
        const dueFmt = t.due ? new Date(t.due + 'T00:00:00').toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' }) : '';
        return `
          <div class="task-card ${t.done ? 'done' : ''} ${overdue ? 'overdue' : ''}" id="tcard-${t.id}">
            <div class="task-check ${t.done ? 'checked' : ''}" onclick="toggleTask('${t.id}')"></div>
            <div style="flex:1;min-width:0">
              <div style="font-size:13.5px;font-weight:600;color:var(--text);margin-bottom:6px;${t.done ? 'text-decoration:line-through;color:var(--text3)' : ''}">${t.title}</div>
              <div style="display:flex;flex-wrap:wrap;align-items:center;gap:8px">
                <span class="task-priority ${t.priority}">${t.priority}</span>
                ${app ? `<span style="font-size:11px;color:var(--accent);background:var(--accent-subtle);padding:2px 8px;border-radius:6px;cursor:pointer;font-weight:600" onclick="openDetail('${t.appId}')">${t.appId} — ${app.name}</span>` : ''}
                <span style="font-size:11.5px;color:${overdue ? 'var(--accent2)' : 'var(--text3)'}">
                  ${overdue ? '⚠ Overdue · ' : '📅 '}${dueFmt}
                </span>
              </div>
            </div>
            <button onclick="deleteTask('${t.id}')" style="background:none;border:none;cursor:pointer;color:var(--text3);font-size:16px;padding:2px 4px;flex-shrink:0;line-height:1;border-radius:6px;transition:color .15s" title="Remove task" onmouseover="this.style.color='var(--danger)'" onmouseout="this.style.color='var(--text3)'">✕</button>
          </div>`;
      }).join('');

      updateTasksNavBadge();
    }

    function toggleTask(id) {
      const t = _TASKS_LOCAL.find(x => x.id === id);
      if (!t) return;
      if (!t.done) {
        // Marking as complete — show attachment modal
        showTaskClearModal(id);
      } else {
        t.done = false;
        renderGlobalTasks();
      }
    }

    // ── Task Clear Modal ──
    window._clearTaskPendingAttachments = [];

    function showTaskClearModal(taskId) {
      const t = _TASKS_LOCAL.find(x => x.id === taskId);
      if (!t) return;
      window._clearTaskPendingAttachments = [];
      // Remove existing modal if any
      const existing = document.getElementById('task-clear-modal-overlay');
      if (existing) existing.remove();

      const overlay = document.createElement('div');
      overlay.id = 'task-clear-modal-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,20,50,.45);backdrop-filter:blur(4px);z-index:9000;display:flex;align-items:center;justify-content:center;padding:20px;overflow-y:auto';
      overlay.innerHTML = `
        <div style="background:var(--surface);border-radius:20px;box-shadow:var(--shadow-lg);width:100%;max-width:500px;overflow:hidden;margin:auto">
          <div style="padding:20px 22px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:12px">
            <div style="width:36px;height:36px;border-radius:10px;background:rgba(26,115,64,.12);display:flex;align-items:center;justify-content:center;font-size:18px">✅</div>
            <div style="flex:1">
              <div style="font-family:var(--font-head);font-size:15px;font-weight:800">Complete Task</div>
              <div style="font-size:12px;color:var(--text3);margin-top:2px">Attach files and add a note before marking done</div>
            </div>
            <button onclick="document.getElementById('task-clear-modal-overlay').remove()" style="width:30px;height:30px;border-radius:8px;border:1px solid var(--border2);background:transparent;cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center">✕</button>
          </div>
          <div style="padding:18px 22px;display:flex;flex-direction:column;gap:14px">
            <div style="font-size:13px;font-weight:600;color:var(--text);padding:10px 14px;background:var(--surface2);border-radius:10px;border:1px solid var(--border)">${t.title}</div>
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Completion Note (optional)</label>
              <textarea id="task-clear-note" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none;resize:vertical;min-height:64px" placeholder="Add a note about this completion…"></textarea>
            </div>
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:8px">Attachments — Saved to Documents by Name</label>
              <div id="clear-task-attachments-list" style="display:flex;flex-direction:column;gap:8px;margin-bottom:8px"></div>
              <label id="clear-task-attach-zone" style="display:flex;align-items:center;gap:10px;padding:11px 14px;border:1.5px dashed var(--border2);border-radius:12px;cursor:pointer;background:var(--surface2);transition:all .18s" onmouseover="this.style.borderColor='var(--accent)';this.style.background='var(--accent-subtle)'" onmouseout="this.style.borderColor='var(--border2)';this.style.background='var(--surface2)'">
                <span style="font-size:20px">📎</span>
                <div>
                  <div style="font-size:12.5px;font-weight:600;color:var(--text)">Click to attach files</div>
                  <div style="font-size:11px;color:var(--text3)">PDF, image, or any document — rename before saving</div>
                </div>
                <input type="file" id="task-clear-file" style="display:none" multiple onchange="addClearTaskAttachment(this,'${taskId}')">
              </label>
            </div>
          </div>
          <div style="padding:14px 22px 18px;display:flex;gap:10px;justify-content:flex-end;border-top:1px solid var(--border)">
            <button class="btn btn-ghost" onclick="document.getElementById('task-clear-modal-overlay').remove()">Cancel</button>
            <button class="btn btn-primary" onclick="confirmTaskClear('${taskId}')" style="background:var(--success);box-shadow:0 2px 12px rgba(26,115,64,.22)">✓ Mark Complete</button>
          </div>
        </div>`;
      document.body.appendChild(overlay);
    }

    function addClearTaskAttachment(input) {
      if (!input.files || !input.files.length) return;
      Array.from(input.files).forEach(file => {
        const objUrl = URL.createObjectURL(file);
        const mimetype = file.type || 'application/octet-stream';
        const isImage = mimetype.startsWith('image/');
        const isPdf = mimetype === 'application/pdf';
        const uid = 'cta-' + Date.now() + '-' + Math.random().toString(36).slice(2, 6);
        window._clearTaskPendingAttachments.push({ uid, file, name: file.name, mimetype, isImage, isPdf, objUrl, docName: file.name });
        renderClearTaskAttachments();
      });
      input.value = '';
    }

    function renderClearTaskAttachments() {
      const list = document.getElementById('clear-task-attachments-list');
      if (!list) return;
      if (!window._clearTaskPendingAttachments.length) { list.innerHTML = ''; return; }
      list.innerHTML = window._clearTaskPendingAttachments.map((att, idx) => `
        <div style="display:flex;align-items:center;gap:10px;padding:9px 12px;background:rgba(26,115,64,.06);border:1px solid rgba(26,115,64,.18);border-radius:10px">
          <span style="font-size:18px;flex-shrink:0">${att.isImage ? '🖼' : att.isPdf ? '📄' : '📎'}</span>
          <div style="flex:1;min-width:0">
            <div style="font-size:12px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${att.file.name} <span style="font-weight:400;color:var(--text3)">(${(att.file.size/1024).toFixed(1)} KB)</span></div>
            <div style="display:flex;align-items:center;gap:6px;margin-top:4px">
              <span style="font-size:10px;color:var(--text3);white-space:nowrap">Save as:</span>
              <input type="text" value="${att.docName}" placeholder="Document name…"
                style="flex:1;font-size:11.5px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:3px 8px;font-family:var(--font-body);color:var(--text);outline:none"
                oninput="window._clearTaskPendingAttachments[${idx}].docName=this.value">
            </div>
          </div>
          <button onclick="removeClearTaskAttachment(${idx})" style="background:none;border:none;cursor:pointer;color:var(--text3);font-size:15px;padding:2px 4px;border-radius:6px;flex-shrink:0" onmouseover="this.style.color='var(--danger)'" onmouseout="this.style.color='var(--text3)'">✕</button>
        </div>`).join('');
    }

    function removeClearTaskAttachment(idx) {
      window._clearTaskPendingAttachments.splice(idx, 1);
      renderClearTaskAttachments();
    }

    // (previewTaskAttachment replaced by addClearTaskAttachment with multi-file + custom name support)

    function confirmTaskClear(taskId) {
      const t = _TASKS_LOCAL.find(x => x.id === taskId);
      if (!t) return;
      const note = (document.getElementById('task-clear-note')?.value || '').trim();

      // Process multiple pending attachments with custom names
      const attachments = window._clearTaskPendingAttachments || [];
      if (attachments.length) {
        if (!t.attachments) t.attachments = [];
        attachments.forEach(att => {
          const storeKey = 'task-attach-' + taskId + '-' + att.uid;
          window._BFP_STORE[storeKey] = { name: att.docName || att.file.name, mimetype: att.mimetype, url: att.objUrl, isImage: att.isImage, isPdf: att.isPdf };
          t.attachments.push({ storeKey, name: att.docName || att.file.name, mimetype: att.mimetype, isImage: att.isImage, isPdf: att.isPdf });
          if (t.appId) {
            const app = APPLICATIONS.find(a => a.id === t.appId);
            if (app) {
              if (!app._taskAttachments) app._taskAttachments = [];
              app._taskAttachments.push({ storeKey, name: att.docName || att.file.name, mimetype: att.mimetype, isImage: att.isImage, isPdf: att.isPdf, taskTitle: t.title, date: new Date().toLocaleDateString('en-IN') });
            }
          }
        });
        showToast(attachments.length + ' file(s) added to Documents ✓', 'success');
        window._clearTaskPendingAttachments = [];
      }

      if (note) t.completionNote = note;
      t.done = true;
      document.getElementById('task-clear-modal-overlay')?.remove();
      renderGlobalTasks();
      showToast('Task marked complete ✓', 'success');
    }

    function deleteTask(id) {
      const idx = _TASKS_LOCAL.findIndex(x => x.id === id);
      if (idx > -1) { _TASKS_LOCAL.splice(idx, 1); renderGlobalTasks(); }
    }

    function addGlobalTask() {
      if (currentUser && currentUser.role === 'partner') { showToast('Partners cannot create tasks', 'error'); return; }
      const existing = document.getElementById('add-task-modal-overlay');
      if (existing) existing.remove();

      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const today = new Date().toISOString().slice(0, 10);

      // Build app options for linking
      const appOptions = APPLICATIONS.map(a => `<option value="${a.id}">${a.id} — ${a.name}</option>`).join('');

      const overlay = document.createElement('div');
      overlay.id = 'add-task-modal-overlay';
      overlay.style.cssText = 'position:fixed;inset:0;background:rgba(10,20,50,.45);backdrop-filter:blur(4px);z-index:9000;display:flex;align-items:center;justify-content:center;padding:20px;overflow-y:auto';
      overlay.innerHTML = `
        <div style="background:var(--surface);border-radius:20px;box-shadow:var(--shadow-lg);width:100%;max-width:520px;overflow:hidden;margin:auto">
          <!-- Header -->
          <div style="padding:20px 22px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;gap:12px">
            <div style="width:36px;height:36px;border-radius:10px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:18px">＋</div>
            <div style="flex:1">
              <div style="font-family:var(--font-head);font-size:15px;font-weight:800">Add New Task</div>
              <div style="font-size:12px;color:var(--text3);margin-top:2px">Fill in details and optionally attach files</div>
            </div>
            <button onclick="document.getElementById('add-task-modal-overlay').remove()" style="width:30px;height:30px;border-radius:8px;border:1px solid var(--border2);background:transparent;cursor:pointer;font-size:15px;display:flex;align-items:center;justify-content:center">✕</button>
          </div>
          <!-- Body -->
          <div style="padding:18px 22px;display:flex;flex-direction:column;gap:14px">
            <!-- Title -->
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Task Title *</label>
              <input id="new-task-title" type="text" placeholder="Describe the task…" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none" oninput="this.style.borderColor=this.value.trim()?'var(--success)':'var(--border)'">
            </div>
            <!-- Due Date + Priority row -->
            <div style="display:flex;gap:12px;flex-wrap:wrap">
              <div style="flex:1;min-width:130px">
                <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Due Date</label>
                <input id="new-task-due" type="date" value="${today}" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:9px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none">
              </div>
              <div style="flex:1;min-width:130px">
                <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Priority</label>
                <select id="new-task-priority" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:9px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none">
                  <option value="low">Low</option>
                  <option value="medium" selected>Medium</option>
                  <option value="high">High</option>
                </select>
              </div>
            </div>
            <!-- Linked Application -->
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Link to Application (optional)</label>
              <select id="new-task-app" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:9px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none">
                <option value="">— No application —</option>
                ${appOptions}
              </select>
            </div>
            <!-- Assign To -->
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Assign To</label>
              <input id="new-task-assign" type="text" value="${uname}" placeholder="Assignee name" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none">
            </div>
            <!-- Attachments section -->
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:8px">Attachments (optional)</label>
              <div id="new-task-attachments-list" style="display:flex;flex-direction:column;gap:8px;margin-bottom:8px"></div>
              <label id="new-task-attach-zone" style="display:flex;align-items:center;gap:10px;padding:11px 14px;border:1.5px dashed var(--border2);border-radius:12px;cursor:pointer;background:var(--surface2);transition:all .18s" onmouseover="this.style.borderColor='var(--accent)';this.style.background='var(--accent-subtle)'" onmouseout="this.style.borderColor='var(--border2)';this.style.background='var(--surface2)'">
                <span style="font-size:20px">📎</span>
                <div>
                  <div style="font-size:12.5px;font-weight:600;color:var(--text)">Click to attach files</div>
                  <div style="font-size:11px;color:var(--text3)">PDF, image, or any document — added to linked application's Documents</div>
                </div>
                <input type="file" id="new-task-file-input" style="display:none" multiple onchange="addNewTaskAttachment(this)">
              </label>
            </div>
            <!-- Note -->
            <div>
              <label style="display:block;font-size:11px;text-transform:uppercase;letter-spacing:.8px;color:var(--text3);font-weight:600;margin-bottom:6px">Notes (optional)</label>
              <textarea id="new-task-note" rows="2" placeholder="Any additional notes…" style="width:100%;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:10px 14px;font-family:var(--font-body);font-size:13px;color:var(--text);outline:none;resize:vertical"></textarea>
            </div>
          </div>
          <!-- Footer -->
          <div style="padding:14px 22px 18px;display:flex;gap:10px;justify-content:flex-end;border-top:1px solid var(--border)">
            <button class="btn btn-ghost" onclick="document.getElementById('add-task-modal-overlay').remove()">Cancel</button>
            <button class="btn btn-primary" onclick="confirmAddTask()">＋ Add Task</button>
          </div>
        </div>`;
      document.body.appendChild(overlay);
      setTimeout(() => { const el = document.getElementById('new-task-title'); if (el) el.focus(); }, 100);
    }

    // Temp store for attachments being added in the new-task modal
    window._newTaskPendingAttachments = [];

    function addNewTaskAttachment(input) {
      if (!input.files || !input.files.length) return;
      Array.from(input.files).forEach(file => {
        const objUrl = URL.createObjectURL(file);
        const mimetype = file.type || 'application/octet-stream';
        const isImage = mimetype.startsWith('image/');
        const isPdf = mimetype === 'application/pdf';
        const uid = 'nta-' + Date.now() + '-' + Math.random().toString(36).slice(2, 6);
        window._newTaskPendingAttachments.push({ uid, file, name: file.name, mimetype, isImage, isPdf, objUrl, docName: file.name });
        renderNewTaskAttachments();
      });
      // Reset so same file can be re-picked
      input.value = '';
    }

    function renderNewTaskAttachments() {
      const list = document.getElementById('new-task-attachments-list');
      if (!list) return;
      if (!window._newTaskPendingAttachments.length) { list.innerHTML = ''; return; }
      list.innerHTML = window._newTaskPendingAttachments.map((att, idx) => `
        <div style="display:flex;align-items:center;gap:10px;padding:9px 12px;background:rgba(26,115,64,.06);border:1px solid rgba(26,115,64,.18);border-radius:10px">
          <span style="font-size:18px;flex-shrink:0">${att.isImage ? '🖼' : att.isPdf ? '📄' : '📎'}</span>
          <div style="flex:1;min-width:0">
            <div style="font-size:12px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${att.file.name} <span style="font-weight:400;color:var(--text3)">(${(att.file.size/1024).toFixed(1)} KB)</span></div>
            <div style="display:flex;align-items:center;gap:6px;margin-top:4px">
              <span style="font-size:10px;color:var(--text3);white-space:nowrap">Save to Documents as:</span>
              <input type="text" value="${att.docName}" placeholder="Document name…"
                style="flex:1;font-size:11.5px;background:var(--surface);border:1px solid var(--border);border-radius:6px;padding:3px 8px;font-family:var(--font-body);color:var(--text);outline:none"
                oninput="window._newTaskPendingAttachments[${idx}].docName=this.value">
            </div>
          </div>
          <button onclick="removeNewTaskAttachment(${idx})" style="background:none;border:none;cursor:pointer;color:var(--text3);font-size:15px;padding:2px 4px;border-radius:6px;flex-shrink:0" onmouseover="this.style.color='var(--danger)'" onmouseout="this.style.color='var(--text3)'">✕</button>
        </div>`).join('');
    }

    function removeNewTaskAttachment(idx) {
      window._newTaskPendingAttachments.splice(idx, 1);
      renderNewTaskAttachments();
    }

    function confirmAddTask() {
      const title = (document.getElementById('new-task-title')?.value || '').trim();
      if (!title) { showToast('Please enter a task title', 'error'); return; }
      const due = document.getElementById('new-task-due')?.value || new Date().toISOString().slice(0, 10);
      const priority = document.getElementById('new-task-priority')?.value || 'medium';
      const appId = document.getElementById('new-task-app')?.value || null;
      const assignTo = (document.getElementById('new-task-assign')?.value || '').trim();
      const note = (document.getElementById('new-task-note')?.value || '').trim();
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';

      const newTask = {
        id: 't' + Date.now(),
        title,
        appId: appId || null,
        priority,
        due,
        done: false,
        createdBy: uname,
        assignedTo: assignTo || uname,
        note: note || undefined
      };

      // Process pending attachments
      if (window._newTaskPendingAttachments && window._newTaskPendingAttachments.length) {
        newTask.attachments = [];
        window._newTaskPendingAttachments.forEach(att => {
          const storeKey = 'task-attach-' + newTask.id + '-' + att.uid;
          window._BFP_STORE[storeKey] = { name: att.docName || att.file.name, mimetype: att.mimetype, url: att.objUrl, isImage: att.isImage, isPdf: att.isPdf };
          newTask.attachments.push({ storeKey, name: att.docName || att.file.name, mimetype: att.mimetype, isImage: att.isImage, isPdf: att.isPdf });
          // Add to linked app documents if applicable
          if (appId) {
            const app = APPLICATIONS.find(a => a.id === appId);
            if (app) {
              if (!app._taskAttachments) app._taskAttachments = [];
              app._taskAttachments.push({ storeKey, name: att.docName || att.file.name, mimetype: att.mimetype, isImage: att.isImage, isPdf: att.isPdf, taskTitle: title, date: new Date().toLocaleDateString('en-IN') });
            }
          }
        });
        if (window._newTaskPendingAttachments.length > 0)
          showToast(window._newTaskPendingAttachments.length + ' file(s) attached and added to Documents ✓', 'success');
        window._newTaskPendingAttachments = [];
      }

      _TASKS_LOCAL.unshift(newTask);
      document.getElementById('add-task-modal-overlay')?.remove();
      renderGlobalTasks();
      showToast('Task added ✓', 'success');
    }

    function updateTasksNavBadge() {
      // Delegates to the up-to-date badge logic (reads window.TASK_STORE,
      // the same store the Tasks page itself renders from) — the count
      // computed here previously used a separate, stale _TASKS_LOCAL store
      // that could disagree with what the Tasks page actually shows.
      if (typeof _refreshTaskNavBadge === 'function') { _refreshTaskNavBadge(); return; }
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const isAdmin = currentUser && currentUser.role === 'admin';
      const pending = _TASKS_LOCAL.filter(t => {
        if (!t.done === false) return false;
        if (!t.done && (isAdmin || t.createdBy === uname || t.assignedTo === uname)) return true;
        return false;
      }).length;
      const badge = document.getElementById('tasks-nav-badge');
      if (badge) {
        badge.style.display = pending ? '' : 'none';
        badge.textContent = pending;
      }
    }

    // ── Tasks tabs ──
    let _currentTasksTab = 'mytasks';

    function switchTasksTab(tab, el) {
      _currentTasksTab = tab;
      ['mytasks','created','assigned'].forEach(t => {
        const panel = document.getElementById('tasks-panel-' + t);
        const tabEl = document.getElementById('ttab-' + t);
        if (panel) panel.style.display = t === tab ? '' : 'none';
        if (tabEl) tabEl.classList.toggle('active', t === tab);
      });
      if (tab === 'created')  renderAppTasks('created');
      if (tab === 'assigned') renderAppTasks('assigned');
      if (tab === 'mytasks')  renderGlobalTasks();
    }

    // Render Tasks page top-level (called when page opens)
    function renderTasksPage() {
      renderGlobalTasks();
      renderTasksSummaryBar();
      // Hide Add Task button for partners — they can resolve but not create
      const addTaskBtn = document.getElementById('add-task-btn');
      if (addTaskBtn) addTaskBtn.style.display = (currentUser && currentUser.role === 'partner') ? 'none' : '';
      // Update tab counts
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const created  = APPLICATIONS.filter(a => _appCreatedBy(a) === uname);
      const assigned = APPLICATIONS.filter(a => (a.sales || '') === uname);
      const cEl = document.getElementById('ttab-created-cnt');
      const aEl = document.getElementById('ttab-assigned-cnt');
      if (cEl) cEl.textContent = created.length  || '';
      if (aEl) aEl.textContent = assigned.length || '';
      // Reset to mytasks tab each time page opens
      switchTasksTab('mytasks', null);
    }

    function _appCreatedBy(app) {
      // The first tracking entry records who created/submitted the app
      if (app.tracking && app.tracking.length > 0) return app.tracking[0].current_user || '';
      return app.sales || '';
    }

    function renderTasksSummaryBar() {
      const bar = document.getElementById('tasks-summary-bar');
      if (!bar) return;
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const myTasksPending  = _TASKS_LOCAL.filter(t => !t.done && (t.assignedTo === uname || !t.assignedTo)).length;
      const myTasksOverdue  = _TASKS_LOCAL.filter(t => !t.done && (t.assignedTo === uname || !t.assignedTo) && t.due < new Date().toISOString().slice(0,10)).length;
      const createdCount    = APPLICATIONS.filter(a => _appCreatedBy(a) === uname).length;
      const assignedCount   = APPLICATIONS.filter(a => (a.sales || '') === uname).length;
      const pills = [
        { label: 'Pending Tasks',     value: myTasksPending,  color: 'var(--accent)',  bg: 'var(--accent-subtle)'  },
        { label: 'Overdue',           value: myTasksOverdue,  color: 'var(--danger)', bg: 'var(--accent2-subtle)' },
        { label: 'Apps I Created',    value: createdCount,    color: '#7c3aed',        bg: 'rgba(124,58,237,.08)'  },
        { label: 'Assigned to Me',    value: assignedCount,   color: 'var(--success)', bg: 'rgba(26,115,64,.08)'   },
      ];
      bar.innerHTML = pills.map(p => `
        <div style="display:flex;align-items:center;gap:10px;background:${p.bg};border-radius:12px;padding:10px 18px;min-width:130px">
          <div style="font-family:var(--font-head);font-size:22px;font-weight:900;color:${p.color}">${p.value}</div>
          <div style="font-size:11.5px;font-weight:600;color:${p.color};line-height:1.3">${p.label}</div>
        </div>`).join('');
    }

    // Application task card renderer (for Created / Assigned tabs)
    const STATUS_META = {
      wip:          { label: 'WIP',          color: 'var(--warn)',    bg: 'rgba(230,126,0,.1)'    },
      login:        { label: 'Assign Lender',  color: 'var(--accent)',  bg: 'var(--accent-subtle)'  },
      underwriting: { label: 'Underwriting',  color: '#7c3aed',        bg: 'rgba(124,58,237,.08)'  },
      offer:        { label: 'Offer',         color: '#0891b2',        bg: 'rgba(8,145,178,.08)'   },
      approved:     { label: 'Approved',      color: 'var(--success)', bg: 'rgba(26,115,64,.1)'    },
      disbursed:    { label: 'Disbursed',     color: 'var(--success)', bg: 'rgba(26,115,64,.12)'   },
      rejected:     { label: 'Rejected',      color: 'var(--danger)', bg: 'var(--accent2-subtle)' },
      hold:         { label: 'On Hold',       color: 'var(--text3)',   bg: 'var(--surface3)'       },
    };

    const LOAN_LABELS = {
      personal_loan:'Personal Loan', business_loan:'Business Loan', home_loan:'Home Loan',
      loan_against_property:'LAP', new_car_loan:'New Car Loan', used_car_loan:'Used Car Loan',
      over_draft:'OD / CC', education_loan:'Education Loan', insurance:'Insurance'
    };

    function renderAppTasks(type) {
      const uname = (currentUser && currentUser.name) ? currentUser.name : '';
      const bodyId = type === 'created' ? 'tasks-created-body' : 'tasks-assigned-body';
      const body = document.getElementById(bodyId);
      if (!body) return;

      const statusFilter = (document.getElementById(type + '-status-filter') || {}).value || '';
      const searchEl = document.getElementById(type === 'created' ? 'created-search' : 'assigned-search');
      const searchVal = (searchEl ? searchEl.value : '').toLowerCase();

      let apps = APPLICATIONS.filter(a => {
        if (type === 'created')  return _appCreatedBy(a) === uname;
        if (type === 'assigned') return (a.sales || '') === uname;
        return false;
      });

      if (statusFilter) apps = apps.filter(a => a.status === statusFilter);
      if (searchVal) apps = apps.filter(a =>
        (a.name || '').toLowerCase().includes(searchVal) ||
        (a.id   || '').toLowerCase().includes(searchVal)
      );

      // Update tab count badges
      const allForType = APPLICATIONS.filter(a => type === 'created' ? _appCreatedBy(a) === uname : (a.sales||'') === uname);
      const cntEl = document.getElementById('ttab-' + type + '-cnt');
      if (cntEl) cntEl.textContent = allForType.length || '';

      if (!apps.length) {
        body.innerHTML = `<div style="text-align:center;padding:48px 24px;color:var(--text3)">
          <div style="font-size:36px;margin-bottom:10px">${type === 'created' ? '📝' : '📌'}</div>
          <div style="font-size:14px;font-weight:600">No applications found</div>
          <div style="font-size:12.5px;margin-top:4px">${type === 'created' ? 'You have not created any applications yet.' : 'No applications are currently assigned to you.'}</div>
        </div>`;
        return;
      }

      body.innerHTML = apps.map(a => {
        const sm = STATUS_META[a.status] || { label: a.status, color: 'var(--text3)', bg: 'var(--surface3)' };
        const ll = LOAN_LABELS[a.loanType] || a.loanType || '—';
        const amtFmt = a.amount ? '₹' + Number(a.amount).toLocaleString('en-IN') : '—';
        const lastTrack = a.tracking && a.tracking.length ? a.tracking[a.tracking.length - 1] : null;
        const lastStep  = lastTrack ? lastTrack.name : '—';
        const lastDate  = lastTrack ? lastTrack.date : '';
        const linkedTasks = _TASKS_LOCAL.filter(t => t.appId === a.id && !t.done);
        const pendingTasksHtml = linkedTasks.length
          ? `<div style="margin-top:10px;display:flex;flex-wrap:wrap;gap:6px">${linkedTasks.map(t => `
              <span style="font-size:11px;background:${t.priority==='high'?'rgba(212,43,43,.09)':t.priority==='medium'?'rgba(230,126,0,.09)':'rgba(26,115,64,.08)'};color:${t.priority==='high'?'var(--accent2)':t.priority==='medium'?'var(--warn)':'var(--success)'};padding:3px 9px;border-radius:99px;font-weight:600;cursor:pointer" onclick="showPage('tasks-page',null);setTimeout(()=>{switchTasksTab('mytasks',null);},50)" title="${t.title}">
                ⚑ ${t.title.length > 38 ? t.title.slice(0,38) + '…' : t.title}
              </span>`).join('')}
            </div>` : '';

        return `
          <div style="background:var(--surface);border:1px solid var(--border);border-radius:14px;padding:16px 18px;cursor:pointer;transition:box-shadow .18s,border-color .18s"
               onmouseover="this.style.borderColor='var(--accent)';this.style.boxShadow='0 4px 20px rgba(26,79,163,.1)'"
               onmouseout="this.style.borderColor='var(--border)';this.style.boxShadow='none'"
               onclick="openDetail('${a.id}')">
            <div style="display:flex;align-items:flex-start;gap:12px;flex-wrap:wrap">
              <!-- Avatar + name -->
              <div style="width:40px;height:40px;border-radius:10px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-family:var(--font-head);font-weight:800;font-size:14px;color:var(--accent);flex-shrink:0">
                ${(a.fname || a.name || '?')[0].toUpperCase()}
              </div>
              <div style="flex:1;min-width:0">
                <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">
                  <span style="font-weight:700;font-size:14px;color:var(--text)">${a.name || '—'}</span>
                  <span style="font-size:11px;color:var(--text3);font-family:var(--font-head)">${a.id}</span>
                  <span style="font-size:11px;padding:2px 9px;border-radius:99px;font-weight:700;background:${sm.bg};color:${sm.color}">${sm.label}</span>
                </div>
                <div style="display:flex;flex-wrap:wrap;gap:12px;font-size:12px;color:var(--text2)">
                  <span>🏦 ${ll}</span>
                  <span>💰 ${amtFmt}</span>
                  <span>📅 ${a.date || '—'}</span>
                </div>
                ${pendingTasksHtml}
              </div>
              <!-- Last stage -->
              <div style="text-align:right;flex-shrink:0;min-width:120px">
                <div style="font-size:10px;color:var(--text3);text-transform:uppercase;letter-spacing:.8px;margin-bottom:3px">Last Stage</div>
                <div style="font-size:12px;font-weight:600;color:var(--text2);max-width:160px;text-align:right;white-space:nowrap;overflow:hidden;text-overflow:ellipsis" title="${lastStep}">${lastStep}</div>
                ${lastDate ? `<div style="font-size:10.5px;color:var(--text3);margin-top:2px">${lastDate}</div>` : ''}
                <div style="margin-top:6px">
                  <span style="font-size:11px;background:var(--accent-subtle);color:var(--accent);padding:2px 9px;border-radius:6px;font-weight:600">View →</span>
                </div>
              </div>
            </div>
          </div>`;
      }).join('');
    }

    function filterAppTasks(type, val) {
      const searchId = type === 'created' ? 'created-search' : 'assigned-search';
      const el = document.getElementById(searchId);
      if (el) el.value = val;
      renderAppTasks(type);
    }

    // ═══════════════════════════════════════════════════════
    //  REPORTS & ANALYTICS ENGINE
    // ═══════════════════════════════════════════════════════

    // Monthly targets store: { 'YYYY-MM': { disbAmt, loginCount, disbCount } }
    const RPT_TARGETS = {
      '2026-01': { disbAmt: 5000000, loginCount: 20, disbCount: 8 },
      '2026-02': { disbAmt: 6000000, loginCount: 22, disbCount: 9 },
      '2026-03': { disbAmt: 7000000, loginCount: 25, disbCount: 11 },
      '2026-04': { disbAmt: 7500000, loginCount: 28, disbCount: 12 },
    };
    window.RPT_TARGETS = RPT_TARGETS;

    let _rptScope = 'all'; // 'mine' | 'team' | 'all'
    let _rptStatusFilter = '';
    let _rptLbSortCol = 'disb';
    let _rptLbSortDir = 'desc'; // 'asc' | 'desc'
    let _rptUserFilter = '';   // specific user name filter
    let _rptTeamFilter = '';   // specific team filter
    let _rptActiveTimeMode = 'user'; // 'user' | 'group' — Active Time aggregation view

    // Extract numeric active-time hours for an application (reuses getActiveTimeDisplay logic).
    function _rptActiveHours(app) {
      if (!app) return 0;
      if (app.total_active_hours != null && !isNaN(app.total_active_hours)) return Math.max(0, Number(app.total_active_hours));
      // Fall back: parse the hours figure out of the display string ("1501.00 Hours (…)")
      try {
        var disp = (typeof getActiveTimeDisplay === 'function') ? getActiveTimeDisplay(app) : '';
        var m = String(disp).match(/([\d.]+)\s*Hours/i);
        return m ? Math.max(0, parseFloat(m[1])) : 0;
      } catch (_) { return 0; }
    }

    // Render Active Time aggregated by user or by group (team).
    function renderActiveTimeAgg() {
      var elT = document.getElementById('rpt-activetime-table');
      if (!elT) return;
      // Highlight the active tab
      var ub = document.getElementById('rpt-at-tab-user'), gb = document.getElementById('rpt-at-tab-group');
      if (ub) { ub.style.background = _rptActiveTimeMode==='user' ? 'var(--accent)' : ''; ub.style.color = _rptActiveTimeMode==='user' ? '#fff' : ''; }
      if (gb) { gb.style.background = _rptActiveTimeMode==='group' ? 'var(--accent)' : ''; gb.style.color = _rptActiveTimeMode==='group' ? '#fff' : ''; }

      var ALL = [].concat(
        (typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []),
        (typeof HISTORICAL_APPS !== 'undefined' ? HISTORICAL_APPS : [])
      );
      var apps = (typeof _rptGetFilteredApps === 'function') ? _rptGetFilteredApps(ALL) : ALL;

      var keyFn = _rptActiveTimeMode === 'group'
        ? function(a){ return a.salesTeam || a.team || '— Unassigned —'; }
        : function(a){ return a.sales || a.rm || '— Unassigned —'; };

      var agg = {};
      apps.forEach(function(a){
        var k = keyFn(a);
        if (!agg[k]) agg[k] = { name: k, count: 0, hours: 0, disb: 0 };
        agg[k].count++;
        agg[k].hours += _rptActiveHours(a);
        if (a.status === 'disbursed') agg[k].disb++;
      });
      var list = Object.values(agg).sort(function(x,y){ return y.hours - x.hours; });

      var fmtH = function(h){
        h = Math.max(0, Number(h)||0);
        if (h < 1) return Math.round(h*60) + ' min';
        var d = Math.floor(h/24), r = Math.round(h%24);
        return h.toFixed(2) + ' Hours' + (d>0 ? ' ('+d+'d '+r+'h)' : '');
      };
      if (!list.length) { elT.innerHTML = '<div style="text-align:center;padding:24px;color:var(--text3)">No active-time data for current scope</div>'; return; }
      var maxH = Math.max.apply(null, list.map(function(r){ return r.hours; }).concat([1]));
      var grandHours = list.reduce(function(s,r){ return s + r.hours; }, 0);
      var grandCount = list.reduce(function(s,r){ return s + r.count; }, 0);
      var grandDisb  = list.reduce(function(s,r){ return s + r.disb;  }, 0);
      var grandAvg   = grandCount ? grandHours / grandCount : 0;
      var label = _rptActiveTimeMode === 'group' ? 'Group / Team' : 'User';
      elT.innerHTML =
        '<table style="width:100%;font-size:12.5px;border-collapse:collapse">' +
          '<thead><tr style="border-bottom:1px solid var(--border)">' +
            '<th style="padding:6px 8px;text-align:left;color:var(--text3);font-weight:600">#</th>' +
            '<th style="padding:6px 8px;text-align:left;color:var(--text3);font-weight:600">'+label+'</th>' +
            '<th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">Apps</th>' +
            '<th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">Disbursed</th>' +
            '<th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">Avg Active Time</th>' +
            '<th style="padding:6px 8px;text-align:right;color:var(--text3);font-weight:600">Total Active Time</th>' +
          '</tr></thead><tbody>' +
          list.map(function(r,i){
            var avg = r.count ? r.hours / r.count : 0;
            return '<tr style="border-bottom:1px solid var(--border)">' +
              '<td style="padding:7px 8px;font-weight:700;color:'+(i===0?'#f59e0b':i===1?'#94a3b8':i===2?'#cd7c2f':'var(--text3)')+'">'+(i<3?['🥇','🥈','🥉'][i]:'#'+(i+1))+'</td>' +
              '<td style="padding:7px 8px;font-weight:600">'+r.name+'</td>' +
              '<td style="padding:7px 8px;text-align:center">'+r.count+'</td>' +
              '<td style="padding:7px 8px;text-align:center;color:var(--success);font-weight:700">'+r.disb+'</td>' +
              '<td style="padding:7px 8px;text-align:center;color:var(--accent)">'+fmtH(avg)+'</td>' +
              '<td style="padding:7px 8px;text-align:right">' +
                '<div style="font-weight:700;color:var(--accent);font-size:12.5px">'+fmtH(r.hours)+'</div>' +
                '<div style="background:var(--surface3);border-radius:99px;height:4px;margin-top:3px;overflow:hidden"><div style="height:100%;border-radius:99px;background:var(--accent-light);width:'+Math.round(r.hours/maxH*100)+'%"></div></div>' +
              '</td>' +
            '</tr>';
          }).join('') +
          '<tr style="border-top:2px solid var(--accent);background:var(--surface2)">' +
            '<td style="padding:9px 8px"></td>' +
            '<td style="padding:9px 8px;font-weight:800">TOTAL ('+list.length+' '+(_rptActiveTimeMode==='group'?'groups':'users')+')</td>' +
            '<td style="padding:9px 8px;text-align:center;font-weight:800">'+grandCount+'</td>' +
            '<td style="padding:9px 8px;text-align:center;font-weight:800;color:var(--success)">'+grandDisb+'</td>' +
            '<td style="padding:9px 8px;text-align:center;font-weight:800;color:var(--accent)">'+fmtH(grandAvg)+'</td>' +
            '<td style="padding:9px 8px;text-align:right;font-weight:800;color:var(--accent)">'+fmtH(grandHours)+'</td>' +
          '</tr>' +
          '</tbody></table>';
    }

    function _rptActiveTimeView(mode) {
      _rptActiveTimeMode = (mode === 'group') ? 'group' : 'user';
      renderActiveTimeAgg();
    }
    window._rptActiveTimeView = _rptActiveTimeView;
    window.renderActiveTimeAgg = renderActiveTimeAgg;

    function setRptScope(scope) {
      _rptScope = scope;
      // Reset user/team filters when scope changes
      _rptUserFilter = '';
      _rptTeamFilter = '';
      renderReports();
    }

    function setRptUserFilter(val) {
      _rptUserFilter = val;
      _rptTeamFilter = '';  // clear team filter
      // If a specific user selected, switch to 'all' scope so full data is visible
      if (val) _rptScope = 'all';
      renderReports();
    }

    function setRptTeamFilter(val) {
      _rptTeamFilter = val;
      _rptUserFilter = '';  // clear user filter
      // If a specific team selected, switch to 'all' scope
      if (val) _rptScope = 'all';
      renderReports();
    }

    function setRptStatusFilter(s) {
      _rptStatusFilter = s;
      document.querySelectorAll('.rpt-chip').forEach(c => {
        c.classList.toggle('rpt-chip-active', c.dataset.chip === s);
      });
      renderReports();
    }

    function rptMonthChanged() {
      // Clear custom date range when month filter is used
      const df = document.getElementById('rpt-date-from');
      const dt = document.getElementById('rpt-date-to');
      if (df) df.value = '';
      if (dt) dt.value = '';
      renderReports();
    }

    function clearRptDateRange() {
      const df = document.getElementById('rpt-date-from');
      const dt = document.getElementById('rpt-date-to');
      if (df) df.value = '';
      if (dt) dt.value = '';
      renderReports();
    }

    function toggleRptExportMenu(e) {
      e.stopPropagation();
      const m = document.getElementById('rpt-export-menu');
      if (!m) return;
      m.style.display = m.style.display === 'none' ? 'block' : 'none';
      const close = () => { m.style.display = 'none'; document.removeEventListener('click', close); };
      setTimeout(() => document.addEventListener('click', close), 10);
    }

    function rptLbSort(col) {
      if (_rptLbSortCol === col) {
        _rptLbSortDir = _rptLbSortDir === 'desc' ? 'asc' : 'desc';
      } else {
        _rptLbSortCol = col;
        _rptLbSortDir = col === 'name' ? 'asc' : 'desc';
      }
      // Update sort indicators
      ['name','total','disb','amt','conv','rej','tat'].forEach(c => {
        const s = document.getElementById('rpt-lbs-' + c);
        if (s) s.textContent = c === _rptLbSortCol ? (_rptLbSortDir === 'desc' ? '▼' : '▲') : '';
      });
      renderReports();
    }

    function toggleTargetEditor() {
      const body = document.getElementById('rpt-target-editor-body');
      const chev = document.getElementById('rpt-target-editor-chevron');
      if (!body) return;
      const open = body.style.display !== 'none';
      body.style.display = open ? 'none' : 'block';
      if (chev) chev.style.transform = open ? '' : 'rotate(180deg)';
      if (!open) renderTargetEditorRows();
    }

    function renderTargetEditorRows() {
      const cont = document.getElementById('rpt-target-editor-rows');
      if (!cont) return;
      cont.innerHTML = Object.entries(RPT_TARGETS).sort().map(([m, t]) => `
        <div style="display:grid;grid-template-columns:auto 1fr 1fr 1fr auto;gap:10px;align-items:center;margin-bottom:8px">
          <span style="font-size:13px;font-weight:700;min-width:80px">${monthLabel(m)}</span>
          <input type="number" value="${t.disbAmt}" onchange="updateTarget('${m}','disbAmt',this.value)"
            style="padding:6px 10px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface2);color:var(--text)">
          <input type="number" value="${t.loginCount}" onchange="updateTarget('${m}','loginCount',this.value)"
            style="padding:6px 10px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface2);color:var(--text)">
          <input type="number" value="${t.disbCount}" onchange="updateTarget('${m}','disbCount',this.value)"
            style="padding:6px 10px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface2);color:var(--text)">
          <button onclick="deleteTarget('${m}')" title="Remove" style="background:none;border:none;cursor:pointer;color:var(--danger);font-size:16px;padding:2px 6px">✕</button>
        </div>`).join('');
    }

    function updateTarget(month, field, val) {
      if (currentUser && currentUser.role !== 'admin') { showToast('Only Admin can edit report targets', 'error'); return; }
      if (!RPT_TARGETS[month]) RPT_TARGETS[month] = { disbAmt: 0, loginCount: 0, disbCount: 0 };
      RPT_TARGETS[month][field] = +val;
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
      renderReports();
    }

    function deleteTarget(month) {
      if (currentUser && currentUser.role !== 'admin') { showToast('Only Admin can edit report targets', 'error'); return; }
      if (!confirm('Remove target for ' + monthLabel(month) + '?')) return;
      delete RPT_TARGETS[month];
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
      renderTargetEditorRows();
      renderReports();
    }

    function addTargetEditorRow() {
      if (currentUser && currentUser.role !== 'admin') { showToast('Only Admin can edit report targets', 'error'); return; }
      const months = Object.keys(RPT_TARGETS).sort();
      const lastM = months[months.length - 1];
      let newM;
      if (lastM) {
        const [y, mo] = lastM.split('-').map(Number);
        const next = new Date(y, mo); // month is 0-indexed, so mo (1-12) -> next month
        newM = next.getFullYear() + '-' + String(next.getMonth() + 1).padStart(2, '0');
      } else {
        const n = new Date();
        newM = n.getFullYear() + '-' + String(n.getMonth() + 1).padStart(2, '0');
      }
      if (!RPT_TARGETS[newM]) {
        RPT_TARGETS[newM] = { disbAmt: 5000000, loginCount: 20, disbCount: 8 };
        if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
        renderTargetEditorRows();
      }
    }

    function exportReportCSV() {
      try {
        const ALL_APPS = [
          ...(typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []),
          ...(typeof HISTORICAL_APPS !== 'undefined' ? HISTORICAL_APPS : []),
        ];
        const apps = _rptGetFilteredApps(ALL_APPS);
        if (!apps.length) { showToast('No data to export for current filters', 'warn'); return; }
        const header = ['ID','Name','Loan Type','Amount','Bank','Status','Sales Person','Team','Date','City','State','CIBIL','Lead Source','Channel','Active Time (Hrs)'];
        const rows = apps.map(a => [
          a.id, a.name, loanTypeLabel(a.loanType), a.amount, a.bank || '—', a.status,
          a.sales || '—', a.salesTeam || a.team || '—', a.date || '—', a.city || '', a.state || '', a.cibil || '', a.leadsrc || '', a.channel || '',
          (typeof _rptActiveHours === 'function' ? _rptActiveHours(a).toFixed(2) : '')
        ]);
        const csv = '\uFEFF' + [header, ...rows].map(r => r.map(v => '"' + String(v || '').replace(/"/g, '""') + '"').join(',')).join('\n');
        const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', 'EFIN_Report_' + new Date().toISOString().slice(0,10) + '.csv');
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        setTimeout(() => URL.revokeObjectURL(url), 1000);
        showToast('✅ CSV exported — ' + apps.length + ' applications', 'success');
      } catch(e) {
        showToast('Export failed: ' + e.message, 'error');
      }
    }

    function exportReportExcel() {
      try {
        const ALL_APPS_EX = [
          ...(typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []),
          ...(typeof HISTORICAL_APPS !== 'undefined' ? HISTORICAL_APPS : []),
        ];
        const apps = _rptGetFilteredApps(ALL_APPS_EX);
        if (!apps.length) { showToast('No data to export for current filters', 'warn'); return; }
        const scopeLabel = _rptUserFilter ? 'User: ' + _rptUserFilter
          : _rptTeamFilter ? 'Team: ' + _rptTeamFilter
          : _rptScope === 'mine' ? 'My Data' : _rptScope === 'team' ? 'My Team' : 'All';

        const header = ['Application ID','Applicant Name','Loan Type','Amount (₹)','Bank/NBFC','Status','Sales Person','Team','Date','City','State','CIBIL Score','Lead Source','Channel','Active Time (Hrs)'];
        const rows = apps.map(a => [
          a.id, a.name, loanTypeLabel(a.loanType),
          Number(a.amount||0).toLocaleString('en-IN'),
          a.bank || '—', a.status, a.sales || '—', a.salesTeam || a.team || '—', a.date || '—',
          a.city || '—', a.state || '—', a.cibil || '—',
          a.leadsrc || '—', a.channel || '—',
          (typeof _rptActiveHours === 'function' ? _rptActiveHours(a).toFixed(2) : '')
        ]);

        const tableHtml = `<table>
          <thead>
            <tr style="background:#1a4fa3;color:#fff;font-weight:bold">
              ${header.map(h => `<th>${h}</th>`).join('')}
            </tr>
          </thead>
          <tbody>
            ${rows.map((r, i) => `<tr style="background:${i%2===0?'#f8faff':'#fff'}">
              ${r.map((v, ci) => `<td ${ci===3?'align="right"':''}>${v}</td>`).join('')}
            </tr>`).join('')}
          </tbody>
        </table>`;

        const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:x="urn:schemas-microsoft-com:office:excel" xmlns="http://www.w3.org/TR/REC-html40">
          <head><meta charset="UTF-8">
          <!--[if gte mso 9]><xml><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet>
          <x:Name>EFIN Report</x:Name>
          <x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions>
          </x:ExcelWorksheet></x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]-->
          <style>td,th{border:1px solid #c8d8f8;padding:6px 10px;font-size:12px;font-family:Arial}
          th{background:#1a4fa3;color:#fff;font-weight:bold}</style>
          </head><body>
          <h2 style="font-family:Arial;color:#1a4fa3">EFIN — Loan Application Report</h2>
          <p style="font-family:Arial;font-size:12px;color:#666">
            Scope: ${scopeLabel} &nbsp;|&nbsp; Generated: ${new Date().toLocaleString('en-IN')} &nbsp;|&nbsp; Total: ${apps.length} applications
          </p>
          ${tableHtml}
          </body></html>`;

        const blob = new Blob(['\uFEFF' + html], { type: 'application/vnd.ms-excel;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement('a');
        link.href = url;
        link.setAttribute('download', 'EFIN_Report_' + new Date().toISOString().slice(0,10) + '.xls');
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
        setTimeout(() => URL.revokeObjectURL(url), 1000);
        showToast('✅ Excel exported — ' + apps.length + ' applications', 'success');
      } catch(e) {
        showToast('Export failed: ' + e.message, 'error');
      }
    }

    function exportReportPDF() {
      try {
        const ALL_APPS_PDF = [
          ...(typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []),
          ...(typeof HISTORICAL_APPS !== 'undefined' ? HISTORICAL_APPS : []),
        ];
        const apps = _rptGetFilteredApps(ALL_APPS_PDF);
        if (!apps.length) { showToast('No data to export for current filters', 'warn'); return; }
        const scopeLabel = _rptUserFilter ? 'User: ' + _rptUserFilter
          : _rptTeamFilter ? 'Team: ' + _rptTeamFilter
          : _rptScope === 'mine' ? 'My Data' : _rptScope === 'team' ? 'My Team' : 'All';

        const header = ['ID','Applicant','Loan Type','Amount','Bank','Status','Sales','Team','Date','Active Time (Hrs)'];
        const rows = apps.map(a => [
          a.id, a.name, loanTypeLabel(a.loanType),
          '₹' + Number(a.amount||0).toLocaleString('en-IN'),
          a.bank || '—', a.status, a.sales || '—', a.salesTeam || a.team || '—', a.date || '—',
          (typeof _rptActiveHours === 'function' ? _rptActiveHours(a).toFixed(2) : '—')
        ]);

        const disbApps = apps.filter(a => a.status === 'disbursed');
        const totalDisb = disbApps.reduce((s,a)=>s+(+a.amount||0),0);
        const convRate = apps.length ? ((disbApps.length/apps.length)*100).toFixed(1) : '0.0';

        const statusColor = {
          disbursed:'#d1fae5;color:#065f46', approved:'#dbeafe;color:#1e40af',
          rejected:'#fee2e2;color:#b91c1c', hold:'#fef3c7;color:#92400e',
          underwriting:'#ede9fe;color:#5b21b6', wip:'#e0f2fe;color:#0369a1'
        };

        const html = `<!DOCTYPE html>
<html><head><meta charset="UTF-8">
<title>EFIN Report — ${new Date().toLocaleDateString('en-IN')}</title>
<style>
  body{font-family:Arial,sans-serif;margin:24px;color:#1a1a2e;font-size:12px}
  h1{color:#1a4fa3;font-size:20px;margin:0 0 4px}
  .meta{color:#6b7280;font-size:11px;margin-bottom:16px}
  .stats{display:flex;gap:14px;margin-bottom:20px;flex-wrap:wrap}
  .stat{background:#f0f5ff;border:1px solid #c8d8f8;border-radius:8px;padding:10px 16px;min-width:120px}
  .stat-label{font-size:10px;color:#6b7280;text-transform:uppercase;letter-spacing:.5px}
  .stat-val{font-size:16px;font-weight:bold;color:#1a4fa3}
  table{width:100%;border-collapse:collapse;font-size:11px}
  th{background:#1a4fa3;color:#fff;padding:7px 8px;text-align:left;white-space:nowrap}
  td{padding:6px 8px;border-bottom:1px solid #e5e7eb}
  tr:nth-child(even) td{background:#f8faff}
  .badge{padding:2px 8px;border-radius:10px;font-size:10px;font-weight:bold;background:#f3f4f6}
  .footer{margin-top:20px;font-size:10px;color:#9ca3af;border-top:1px solid #e5e7eb;padding-top:8px}
  @media print{body{margin:10px}@page{size:landscape;margin:10mm}}
</style>
</head><body>
<h1>📊 EFIN — Loan Application Report</h1>
<div class="meta">Scope: <strong>${scopeLabel}</strong> &nbsp;|&nbsp; Generated: ${new Date().toLocaleString('en-IN')} &nbsp;|&nbsp; Total: ${apps.length} applications</div>
<div class="stats">
  <div class="stat"><div class="stat-label">Total Apps</div><div class="stat-val">${apps.length}</div></div>
  <div class="stat"><div class="stat-label">Disbursed</div><div class="stat-val" style="color:var(--success)">${disbApps.length}</div></div>
  <div class="stat"><div class="stat-label">Total Disbursed</div><div class="stat-val">₹${Number(totalDisb).toLocaleString('en-IN')}</div></div>
  <div class="stat"><div class="stat-label">Conversion Rate</div><div class="stat-val">${convRate}%</div></div>
</div>
<table>
  <thead><tr>${header.map(h=>`<th>${h}</th>`).join('')}</tr></thead>
  <tbody>
    ${rows.map((r,i) => `<tr>
      ${r.map((v,ci) => {
        if (ci === 5) {
          const sc = statusColor[v] || '#f3f4f6;color:#374151';
          const [bg,col] = sc.split(';color:');
          return `<td><span class="badge" style="background:${bg};color:${col||'#374151'}">${v}</span></td>`;
        }
        return `<td${ci===3?' style="text-align:right"':''}>${v}</td>`;
      }).join('')}
    </tr>`).join('')}
  </tbody>
</table>
<div class="footer">EFIN Loan Management System — Confidential &nbsp;|&nbsp; ${new Date().toLocaleDateString('en-IN')}</div>
<script>window.onload=function(){window.print();}<\/script>
</body></html>`;

        // Open in new tab — user can print/save as PDF from there
        const blob = new Blob([html], { type: 'text/html;charset=utf-8' });
        const url = URL.createObjectURL(blob);
        const printWin = window.open(url, '_blank');
        if (!printWin) {
          // Popup blocked — fallback: download as HTML
          const link = document.createElement('a');
          link.href = url;
          link.setAttribute('download', 'EFIN_Report_' + new Date().toISOString().slice(0,10) + '.html');
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
          showToast('PDF preview blocked by browser. Downloaded as HTML — open and print (Ctrl+P) to save as PDF.', 'info');
        } else {
          showToast('✅ PDF preview opened — use Ctrl+P or browser Print to save as PDF', 'success');
        }
        setTimeout(() => URL.revokeObjectURL(url), 3000);
      } catch(e) {
        showToast('PDF export failed: ' + e.message, 'error');
      }
    }

    function exportReportPrint() {
      // Print only the reports page content, not the sidebar/topbar
      const reportPage = document.getElementById('page-reports');
      if (!reportPage) { window.print(); return; }
      const printContent = reportPage.innerHTML;
      const printWin = window.open('', '_blank', 'width=1100,height=800');
      if (!printWin) { showToast('Print window blocked by browser. Please allow popups for this site.', 'warn'); return; }
      printWin.document.write(`<!DOCTYPE html>
<html><head><meta charset="UTF-8">
<title>EFIN Reports — Print</title>
<style>
  body{font-family:Arial,sans-serif;margin:20px;color:#1a1a2e;font-size:12px;background:#fff}
  .card{background:#fff;border:1px solid #e5e7eb;border-radius:12px;padding:16px;margin-bottom:16px;break-inside:avoid}
  .stat-card,.kpi-card{break-inside:avoid}
  table{width:100%;border-collapse:collapse;font-size:11px}
  th{background:#1a4fa3;color:#fff;padding:7px 8px;text-align:left}
  td{padding:6px 8px;border-bottom:1px solid #e5e7eb}
  tr:nth-child(even) td{background:#f8faff}
  button,.btn,.rpt-chip,.topbar,select,.export-btn{display:none!important}
  h2,h3{color:#1a4fa3}
  @media print{body{margin:8px}@page{size:landscape;margin:10mm}}
</style>
</head><body>
<h2 style="margin:0 0 12px;color:#1a4fa3">📊 EFIN — Reports & Analytics</h2>
<p style="color:#6b7280;font-size:11px;margin-bottom:16px">Generated: ${new Date().toLocaleString('en-IN')}</p>
${printContent}
<script>window.onload=function(){window.print();window.onafterprint=function(){window.close();}}<\/script>
</body></html>`);
      printWin.document.close();
    }

    function _rptGetFilteredApps(ALL_APPS) {
      const uname = currentUser.name;
      const role  = currentUser.role;
      const isTL  = role === 'team_leader';
      const isAdmin = role === 'admin';
      let teamMembers = [];
      if (isTL || isAdmin) {
        const myTeam = twSalesTeams.find(t => t.leader === uname);
        teamMembers = myTeam ? [uname, ...myTeam.members] : [uname];
      }
      // For partner role: enforce scoped view regardless of _rptScope selection
      let apps = (role === 'partner') ? getPartnerScopedApps() : ALL_APPS;
      if (role !== 'partner') {
        if (_rptScope === 'mine') apps = apps.filter(a => a.sales === uname || (a.rm && a.rm.includes(uname)));
        else if (_rptScope === 'team' && teamMembers.length) apps = apps.filter(a => teamMembers.includes(a.sales));
        // Individual user filter (overrides scope)
        if (_rptUserFilter) apps = apps.filter(a => a.sales === _rptUserFilter || (a.rm && a.rm.includes(_rptUserFilter)));
        // Team filter (overrides scope)
        if (_rptTeamFilter) {
          const team = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : []).find(t => t.name === _rptTeamFilter);
          if (team) apps = apps.filter(a => [team.leader, ...(team.members||[])].includes(a.sales));
        }
      }

      // Status filter
      if (_rptStatusFilter) apps = apps.filter(a => a.status === _rptStatusFilter);

      // Month filter
      const monthSel = document.getElementById('rpt-month-filter');
      const curMonthVal = monthSel?.value || '';
      // Custom date range overrides month
      const dfEl = document.getElementById('rpt-date-from');
      const dtEl = document.getElementById('rpt-date-to');
      const dfVal = dfEl?.value; const dtVal = dtEl?.value;
      if (dfVal || dtVal) {
        apps = apps.filter(a => {
          const d = parseAppDate(a.date); if (!d) return false;
          if (dfVal && d < new Date(dfVal)) return false;
          if (dtVal && d > new Date(dtVal + 'T23:59:59')) return false;
          return true;
        });
      } else if (curMonthVal) {
        apps = apps.filter(a => {
          const d = parseAppDate(a.date); if (!d) return false;
          const m = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0');
          return m === curMonthVal;
        });
      }
      return apps;
    }

    function renderReports() {
      if (typeof window.renderReports === 'function' && window.renderReports !== renderReports) {
        return window.renderReports.apply(this, arguments);
      }
      const role  = currentUser.role;
      const uname = currentUser.name;
      const isAdmin = role === 'admin';
      const isTL    = role === 'team_leader';
      const isPartner = role === 'partner';

      // Partner: hide scope-switcher buttons (Mine/Team/All) — always see own scope only
      const scopeBtns = document.getElementById('rpt-scope-btns');
      if (scopeBtns) scopeBtns.style.display = isPartner ? 'none' : '';

      // Show target editor to admin
      const tec = document.getElementById('rpt-target-editor-card');
      if (tec) tec.style.display = isAdmin ? '' : 'none';

      // thisMonthKey needed by KPI rendering
      const nowD = new Date();
      const thisMonthKey = nowD.getFullYear() + '-' + String(nowD.getMonth()+1).padStart(2,'0');

      // ── Scope buttons visibility ──
      const btnMine = document.getElementById('rpt-btn-mine');
      const btnTeam = document.getElementById('rpt-btn-team');
      const btnAll  = document.getElementById('rpt-btn-all');
      if (btnMine) btnMine.style.display = '';
      if (btnTeam) btnTeam.style.display = (isTL || isAdmin) ? '' : 'none';
      if (btnAll)  btnAll.style.display  = isAdmin ? '' : 'none';

      // Dropdowns populated after ALL_APPS is defined (see below)

      // Highlight active scope button — dim all if user/team filter active
      [['mine','rpt-btn-mine'],['team','rpt-btn-team'],['all','rpt-btn-all']].forEach(([s, id]) => {
        const b = document.getElementById(id);
        if (!b) return;
        const isActive = _rptScope === s && !_rptUserFilter && !_rptTeamFilter;
        b.style.background = isActive ? 'var(--accent)' : '';
        b.style.color      = isActive ? '#fff' : '';
        b.style.border     = isActive ? 'none' : '';
      });

      // ── All apps pool (live + historical) ──
      const ALL_APPS = [
        ...(typeof APPLICATIONS !== 'undefined' ? APPLICATIONS : []),
        ...(typeof HISTORICAL_APPS !== 'undefined' ? HISTORICAL_APPS : []),
      ];

      // ── User filter dropdown — populated here so ALL_APPS is in scope ──
      const userFilterEl = document.getElementById('rpt-user-filter');
      if (userFilterEl) {
        if (isAdmin || isTL) {
          userFilterEl.style.display = '';
          // Build unique sorted list of all sales persons across all apps
          const allUsers = [...new Set(ALL_APPS.map(a => a.sales).filter(Boolean))].sort();
          userFilterEl.innerHTML = '<option value="">👤 All Users</option>' +
            allUsers.map(u => `<option value="${u}"${u === _rptUserFilter ? ' selected' : ''}>${u}</option>`).join('');
        } else {
          userFilterEl.style.display = 'none';
        }
      }

      // ── Team filter dropdown — populated here alongside user filter ──
      const teamFilterEl = document.getElementById('rpt-team-filter');
      if (teamFilterEl) {
        if (isAdmin) {
          teamFilterEl.style.display = '';
          const allTeams = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : []);
          if (allTeams.length > 0) {
            teamFilterEl.innerHTML = '<option value="">🏢 All Teams</option>' +
              allTeams.map(t => `<option value="${t.name}"${t.name === _rptTeamFilter ? ' selected' : ''}>${t.name}</option>`).join('');
          } else {
            // Fallback: build teams from salesTeam field on apps
            const teamNames = [...new Set(ALL_APPS.map(a => a.salesTeam).filter(Boolean))].sort();
            teamFilterEl.innerHTML = '<option value="">🏢 All Teams</option>' +
              teamNames.map(t => `<option value="${t}"${t === _rptTeamFilter ? ' selected' : ''}>${t}</option>`).join('');
          }
        } else {
          teamFilterEl.style.display = 'none';
        }
      }

      // ── Team members for TL scope ──
      let teamMembers = [];
      if (isTL || isAdmin) {
        const myTeam = twSalesTeams.find(t => t.leader === uname);
        teamMembers = myTeam ? [uname, ...myTeam.members] : [uname];
      }

      // ── Scope filter helper (used for per-scope sub-queries) ──
      function scopeFilter(apps) {
        let filtered = apps;
        if (_rptUserFilter) return filtered.filter(a => a.sales === _rptUserFilter || (a.rm && a.rm.includes(_rptUserFilter)));
        if (_rptTeamFilter) {
          const team = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : []).find(t => t.name === _rptTeamFilter);
          if (team) return filtered.filter(a => [team.leader, ...(team.members||[])].includes(a.sales));
        }
        if (_rptScope === 'mine') return filtered.filter(a => a.sales === uname || a.rm?.includes(uname));
        if (_rptScope === 'team' && teamMembers.length) return filtered.filter(a => teamMembers.includes(a.sales));
        return filtered;
      }

      // ── Month filter ──
      const monthSel = document.getElementById('rpt-month-filter');
      // Populate month options once
      const allMonths = [...new Set(ALL_APPS.map(a => {
        const d = parseAppDate(a.date);
        return d ? d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') : null;
      }).filter(Boolean))].sort().reverse();
      const curMonthVal = monthSel?.value || '';
      if (monthSel && monthSel.options.length <= 1) {
        monthSel.innerHTML = '<option value="">All Time</option>' +
          allMonths.map(m => `<option value="${m}">${monthLabel(m)}</option>`).join('');
      }

      // ── Full filtered apps (scope + status + date) ──
      const apps = _rptGetFilteredApps(ALL_APPS);

      // ── Scope label ──
      const dfEl = document.getElementById('rpt-date-from');
      const dtEl = document.getElementById('rpt-date-to');
      const dfVal = dfEl?.value; const dtVal = dtEl?.value;
      let filterSuffix = dfVal || dtVal
        ? ` · ${dfVal || '…'} → ${dtVal || '…'}`
        : curMonthVal ? ` · ${monthLabel(curMonthVal)}` : '';
      if (_rptStatusFilter) filterSuffix += ` · ${_rptStatusFilter}`;
      const scopeLabel = _rptUserFilter
        ? `👤 ${_rptUserFilter} — Individual data`
        : _rptTeamFilter
        ? `🏢 ${_rptTeamFilter} — Team data`
        : _rptScope === 'mine' ? `My data — ${uname}`
        : _rptScope === 'team' ? `Team data — ${teamMembers.join(', ')}`
        : 'All applications · Live data';
      const el = id => document.getElementById(id);
      if (el('rpt-scope-label')) el('rpt-scope-label').textContent = scopeLabel + filterSuffix;

      // ── Core KPIs ──
      const total     = apps.length;
      const disbursed = apps.filter(a => a.status === 'disbursed');
      const rejected  = apps.filter(a => a.status === 'rejected');
      // "Logged in" = any application that has moved past the WIP/draft stage — this mirrors
      // the same login/terminal lifecycle distinction already validated in the
      // Overview → Active Time calculation (getActiveTimeDisplay's terminalStatuses group,
      // which treats disbursed/hold/rejected/cancelled/ni as post-login states). The previous
      // explicit whitelist here missed 'hold' and 'rejected' apps, undercounting logins.
      const logins    = apps.filter(a => a.status !== 'wip');
      const active    = apps.filter(a => !['disbursed','rejected','cancelled','ni'].includes(a.status));

      const totalDisbAmt  = disbursed.reduce((s, a) => s + (a.amount || 0), 0);
      const allAmounts    = apps.map(a => a.amount || 0).filter(v => v > 0).sort((a,b) => a-b);
      const disbAmounts   = disbursed.map(a => a.amount || 0).filter(v => v > 0);
      const avgLoan       = allAmounts.length ? Math.round(allAmounts.reduce((s,v)=>s+v,0)/allAmounts.length) : 0;
      const disbAvgLoan   = disbAmounts.length ? Math.round(disbAmounts.reduce((s,v)=>s+v,0)/disbAmounts.length) : 0;
      const medianLoan    = allAmounts.length ? allAmounts[Math.floor(allAmounts.length/2)] : 0;
      const minLoan       = allAmounts.length ? allAmounts[0] : 0;
      const maxLoan       = allAmounts.length ? allAmounts[allAmounts.length-1] : 0;
      const convRate      = total ? (disbursed.length / total * 100).toFixed(1) : '0.0';
      const rejRate       = total ? (rejected.length  / total * 100).toFixed(1) : '0.0';
      const ldrRatio      = logins.length ? (disbursed.length / logins.length * 100).toFixed(1) : '—';
      const approvedPending = apps.filter(a => ['approved','acceptance','approved_deviation'].includes(a.status));

      const fmtAmt = v => v >= 1e7 ? '₹'+(v/1e7).toFixed(2)+'Cr' : v >= 1e5 ? '₹'+(v/1e5).toFixed(1)+'L' : '₹'+v.toLocaleString('en-IN');

      // MoM comparison (prev month same scope)
      const prevMonthKey = (() => { const d = new Date(nowD.getFullYear(), nowD.getMonth()-1, 1); return d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0'); })();
      const prevApps = scopeFilter(ALL_APPS).filter(a => {
        const d = parseAppDate(a.date); if (!d) return false;
        return (d.getFullYear()+'-'+String(d.getMonth()+1).padStart(2,'0')) === prevMonthKey;
      });
      const prevDisbAmt = prevApps.filter(a => a.status==='disbursed').reduce((s,a)=>s+(a.amount||0), 0);
      const prevRejCnt  = prevApps.filter(a => a.status==='rejected').length;
      const prevTotal   = prevApps.length;
      const momDisbPct  = prevDisbAmt > 0 ? ((totalDisbAmt - prevDisbAmt) / prevDisbAmt * 100).toFixed(1) : null;
      const momRejRate  = prevTotal > 0 ? ((+rejRate) - (prevRejCnt/prevTotal*100)).toFixed(1) : null;

      // ── Render KPI card 1: Total Disbursed ──
      const tgtDisbAmt = (RPT_TARGETS[thisMonthKey] || {}).disbAmt || 5000000;
      const disbPct = Math.min(100, Math.round(totalDisbAmt / tgtDisbAmt * 100));
      if (el('rpt-disbursed-amt')) el('rpt-disbursed-amt').textContent = fmtAmt(totalDisbAmt);
      if (el('rpt-disb-progress')) el('rpt-disb-progress').style.width = disbPct + '%';
      if (el('rpt-disbursed-change')) el('rpt-disbursed-change').innerHTML =
        `↑ ${disbursed.length} disbursed of ${total} applications`;
      if (el('rpt-disb-mom')) {
        if (momDisbPct !== null) {
          const up = +momDisbPct >= 0;
          const momColor = up ? 'var(--success)' : 'var(--accent2)';
          el('rpt-disb-mom').innerHTML = `<span style="color:${momColor};font-weight:700">${up?'↑':'↓'} ${Math.abs(momDisbPct)}% vs prev month</span>`;
        } else { el('rpt-disb-mom').textContent = disbPct + '% of monthly target'; }
      }

      // ── Render KPI card 2: Avg Loan Size ──
      if (el('rpt-avg-loan'))      el('rpt-avg-loan').textContent = fmtAmt(avgLoan);
      if (el('rpt-median-loan'))   el('rpt-median-loan').textContent = fmtAmt(medianLoan);
      if (el('rpt-disb-avg-loan')) el('rpt-disb-avg-loan').textContent = disbAmounts.length ? fmtAmt(disbAvgLoan) : '—';
      if (el('rpt-loan-range'))    el('rpt-loan-range').textContent = allAmounts.length
        ? `Range: ${fmtAmt(minLoan)} – ${fmtAmt(maxLoan)}`
        : 'No amount data';

      // ── Render KPI card 3: Conversion Rate ──
      if (el('rpt-conversion')) el('rpt-conversion').textContent = convRate + '%';
      const convNum = +convRate;
      const convColor = convNum >= 50 ? 'var(--success)' : convNum >= 25 ? 'var(--warn)' : 'var(--accent2)';
      const convLabel = convNum >= 50 ? '🟢 Healthy' : convNum >= 25 ? '🟡 Average' : '🔴 Low';
      if (el('rpt-conversion')) el('rpt-conversion').style.color = convColor;
      if (el('rpt-conv-badge')) { el('rpt-conv-badge').textContent = convLabel; el('rpt-conv-badge').style.color = convColor; el('rpt-conv-badge').style.background = convNum>=50?'rgba(26,115,64,.1)':convNum>=25?'rgba(230,126,0,.1)':'rgba(212,43,43,.1)'; }
      if (total > 0) {
        const dFlex = Math.round(disbursed.length/total*100);
        const aFlex = Math.round(active.length/total*100);
        const rFlex = Math.round(rejected.length/total*100);
        if (el('rpt-conv-disb'))  { el('rpt-conv-disb').style.flex = dFlex; el('rpt-conv-disb').style.borderRadius = '3px 0 0 3px'; }
        if (el('rpt-conv-active')){ el('rpt-conv-active').style.flex = aFlex; }
        if (el('rpt-conv-rej'))   { el('rpt-conv-rej').style.flex = rFlex; el('rpt-conv-rej').style.borderRadius = '0 3px 3px 0'; }
        if (el('rpt-conv-rest'))  el('rpt-conv-rest').style.flex = Math.max(0, 100-dFlex-aFlex-rFlex);
      }
      if (el('rpt-conv-detail')) el('rpt-conv-detail').innerHTML =
        `<span style="color:var(--success)">●</span> ${disbursed.length} Disb &nbsp;<span style="color:#f59e0b">●</span> ${active.length} Active &nbsp;<span style="color:var(--danger)">●</span> ${rejected.length} Rej`;

      // ── Render KPI card 4: Rejection Rate ──
      if (el('rpt-rejection')) el('rpt-rejection').textContent = rejRate + '%';
      const rejNum = +rejRate;
      const rejColor = rejNum <= 10 ? 'var(--success)' : rejNum <= 25 ? 'var(--warn)' : 'var(--accent2)';
      const rejLabel = rejNum <= 10 ? '🟢 Low' : rejNum <= 25 ? '🟡 Medium' : '🔴 High';
      if (el('rpt-rejection')) el('rpt-rejection').style.color = rejColor;
      if (el('rpt-rej-badge')) { el('rpt-rej-badge').textContent = rejLabel; el('rpt-rej-badge').style.color = rejColor; el('rpt-rej-badge').style.background = rejNum<=10?'rgba(26,115,64,.1)':rejNum<=25?'rgba(230,126,0,.1)':'rgba(212,43,43,.1)'; }
      if (el('rpt-rej-bar')) el('rpt-rej-bar').style.width = Math.min(100,rejNum) + '%';
      if (el('rpt-rejection-change')) el('rpt-rejection-change').textContent = `${rejected.length} rejected of ${total}`;
      if (el('rpt-rej-mom')) {
        if (momRejRate !== null) {
          const better = +momRejRate < 0;
          el('rpt-rej-mom').innerHTML = `<span style="color:${better?'var(--success)':'var(--accent2)'};font-weight:700">${better?'↓':'↑'} ${Math.abs(momRejRate)}pp vs prev month</span>`;
        } else { el('rpt-rej-mom').textContent = 'No prior month data'; }
      }

      // ── TAT: Login → Disbursed (hours) ──
      // Reuses the validated Active Time calculation (_rptActiveHours → getActiveTimeDisplay /
      // total_active_hours, same source already powering Overview → Active Time and the
      // Active Time aggregation table below) instead of the old 'EFIN-Login' tracking lookup,
      // which never matched because no 'EFIN-Login' tracking entry is ever created — that made
      // this metric permanently blank regardless of real data.
      const tatValues = disbursed.map(a => _rptActiveHours(a)).filter(v => v > 0);
      const avgTAT = tatValues.length ? (tatValues.reduce((s,v)=>s+v,0)/tatValues.length) : null;
      const minTAT = tatValues.length ? Math.min(...tatValues) : null;
      const maxTAT = tatValues.length ? Math.max(...tatValues) : null;
      // Thresholds: ≤168h (7d)=fast, ≤336h (14d)=avg, >336h=slow
      const tatColor = avgTAT === null ? 'var(--text3)' : avgTAT <= 168 ? 'var(--success)' : avgTAT <= 336 ? 'var(--warn)' : 'var(--accent2)';
      const tatBadge = avgTAT === null ? '—' : avgTAT <= 168 ? '🟢 Fast' : avgTAT <= 336 ? '🟡 Avg' : '🔴 Slow';
      if (el('rpt-tat'))      { el('rpt-tat').textContent = avgTAT !== null ? fmtHours(avgTAT) : '—'; el('rpt-tat').style.color = tatColor; }
      if (el('rpt-tat-badge')){ el('rpt-tat-badge').textContent = tatBadge; el('rpt-tat-badge').style.color = tatColor; el('rpt-tat-badge').style.background = avgTAT!==null&&avgTAT<=168?'rgba(26,115,64,.1)':avgTAT!==null&&avgTAT<=336?'rgba(230,126,0,.1)':'rgba(212,43,43,.1)'; }
      if (el('rpt-tat-min'))  el('rpt-tat-min').textContent = minTAT !== null ? fmtHours(minTAT) : '—';
      if (el('rpt-tat-max'))  el('rpt-tat-max').textContent = maxTAT !== null ? fmtHours(maxTAT) : '—';
      if (el('rpt-tat-cnt'))  el('rpt-tat-cnt').textContent = tatValues.length;
      if (el('rpt-tat-sub'))  el('rpt-tat-sub').textContent = tatValues.length
        ? `Based on ${tatValues.length} completed case${tatValues.length>1?'s':''}`
        : 'No completed cases with tracking';

      // ── Login-to-DDR Ratio ──
      if (el('rpt-ldr')) el('rpt-ldr').textContent = ldrRatio !== '—' ? ldrRatio + '%' : '—';
      if (el('rpt-ldr-sub')) el('rpt-ldr-sub').textContent = `${disbursed.length} disbursed / ${logins.length} logins`;
      const ldrNum = ldrRatio !== '—' ? +ldrRatio : null;
      const ldrColor = ldrNum === null ? '#6366f1' : ldrNum >= 40 ? 'var(--success)' : ldrNum >= 20 ? 'var(--warn)' : 'var(--accent2)';
      const ldrLabel = ldrNum === null ? '—' : ldrNum >= 40 ? '🟢 Good' : ldrNum >= 20 ? '🟡 Fair' : '🔴 Low';
      if (el('rpt-ldr')) el('rpt-ldr').style.color = ldrColor;
      if (el('rpt-ldr-health')) { el('rpt-ldr-health').textContent = ldrLabel; el('rpt-ldr-health').style.color = ldrColor; }
      if (el('rpt-ldr-bar')) el('rpt-ldr-bar').style.width = ldrNum !== null ? Math.min(100, ldrNum * 2) + '%' : '0%'; // scale: 50% ratio = full bar
      if (el('rpt-ldr-bar')) el('rpt-ldr-bar').style.background = ldrColor;
      if (el('rpt-ldr-bench')) el('rpt-ldr-bench').innerHTML =
        `Benchmark: 40%+ &nbsp;·&nbsp; Approved pending: <strong>${approvedPending.length}</strong>`;

      // ── PD → Underwriting stage time ──
      const pdUwValues = apps.map(a => {
        const pdEntry  = (a.tracking || []).find(t => t.name === 'EFIN- PersonalDetails' || t.name === 'EFIN-Workflow Start');
        const uwEntry  = (a.tracking || []).find(t => t.name === 'EFIN-Underwriting');
        if (!pdEntry || !uwEntry) return null;
        const d1 = parseTrackDate(pdEntry.date), d2 = parseTrackDate(uwEntry.date);
        if (!d1 || !d2) return null;
        return Math.max(0, (d2 - d1) / 86400000);
      }).filter(v => v !== null);
      const avgPdUwH = pdUwValues.length ? Math.round(pdUwValues.reduce((s,v)=>s+v,0)/pdUwValues.length * 24) : null;
      const avgPdUw = avgPdUwH !== null ? fmtHours(avgPdUwH) : null;
      if (el('rpt-pd-uw')) el('rpt-pd-uw').textContent = avgPdUw !== null ? avgPdUw : '—';

      // Multi-stage TAT rows
      const STAGE_PAIRS = [
        { label: 'PD → UW',        t1: ['EFIN-Workflow Start','EFIN- PersonalDetails'], t2: ['EFIN-Underwriting'] },
        { label: 'UW → Approved',  t1: ['EFIN-Underwriting'], t2: ['EFIN-Approved'] },
        { label: 'Approved → Disb',t1: ['EFIN-Approved'], t2: ['EFIN-Disbursed'] },
      ];
      const stageColors = ['#f59e0b','#6366f1','#22c55e'];
      const stageRows = STAGE_PAIRS.map((pair, i) => {
        const vals = apps.map(a => {
          const t1e = (a.tracking||[]).find(t => pair.t1.includes(t.name));
          const t2e = (a.tracking||[]).find(t => pair.t2.includes(t.name));
          if (!t1e || !t2e) return null;
          const d1 = parseTrackDate(t1e.date), d2 = parseTrackDate(t2e.date);
          return d1 && d2 ? Math.max(0, (d2-d1)/3600000) : null; // hours
        }).filter(v => v !== null);
        const avgH = vals.length ? Math.round(vals.reduce((s,v)=>s+v,0)/vals.length) : null;
        return { label: pair.label, avg: avgH, display: avgH !== null ? fmtHours(avgH) : null, color: stageColors[i] };
      });
      const maxStageAvg = Math.max(...stageRows.map(r => r.avg ? +r.avg : 0), 1);
      if (el('rpt-stage-tat-rows')) el('rpt-stage-tat-rows').innerHTML = stageRows.map(r => `
        <div style="display:flex;align-items:center;gap:6px;margin-bottom:5px">
          <span style="font-size:10px;color:var(--text3);font-weight:600;min-width:80px">${r.label}</span>
          <div style="flex:1;background:var(--surface3);border-radius:99px;height:5px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:${r.color};width:${r.avg?Math.max(6,Math.round(+r.avg/maxStageAvg*100)):0}%;transition:width .6s"></div>
          </div>
          <span style="font-size:10.5px;font-weight:800;color:${r.color};min-width:40px;text-align:right">${r.display !== null ? r.display : '—'}</span>
        </div>`).join('');
      if (el('rpt-pduw-sub')) el('rpt-pduw-sub').textContent = `Avg across ${apps.filter(a=>a.tracking&&a.tracking.length>1).length} tracked cases`;

      // ── Active Pipeline ──
      if (el('rpt-pipeline-cnt')) el('rpt-pipeline-cnt').textContent = active.length;
      const pipelineVal = active.reduce((s,a)=>s+(a.amount||0),0);
      if (el('rpt-pipeline-val')) el('rpt-pipeline-val').textContent = fmtAmt(pipelineVal);
      const PIPE_STAGES = [
        { key:'wip',          label:'Personal Details', color:'#94a3b8' },
        { key:'login',        label:'Login',            color:'#6366f1' },
        { key:'underwriting', label:'Underwriting',     color:'#3b82f6' },
        { key:'offer',        label:'Offer',            color:'#0891b2' },
        { key:'approved',     label:'Approved',         color:'#22c55e' },
        { key:'hold',         label:'Hold',             color:'#f59e0b' },
      ];
      const pipeStaged = PIPE_STAGES.map(s => ({ ...s, cnt: active.filter(a=>a.status===s.key).length })).filter(s=>s.cnt>0);
      if (el('rpt-pipeline-stages')) el('rpt-pipeline-stages').innerHTML = pipeStaged.map(s => `
        <div style="display:flex;align-items:center;justify-content:space-between;font-size:10.5px">
          <span style="color:${s.color};font-weight:600;display:flex;align-items:center;gap:4px"><span style="width:7px;height:7px;border-radius:50%;background:${s.color};display:inline-block"></span>${s.label}</span>
          <span style="font-weight:800;color:${s.color}">${s.cnt}</span>
        </div>`).join('') || '<span style="font-size:11px;color:var(--text3)">No active apps</span>';
      if (el('rpt-pipeline-sub')) el('rpt-pipeline-sub').textContent = `${active.length} in-progress · ${fmtAmt(pipelineVal)} at stake`;
      // Oldest active app age
      const oldestApp = active.map(a => ({ a, d: parseAppDate(a.date) })).filter(x=>x.d).sort((x,y)=>x.d-y.d)[0];
      if (el('rpt-pipeline-oldest')) {
        if (oldestApp) {
          const ageDays = Math.round((Date.now() - oldestApp.d) / 86400000);
          el('rpt-pipeline-oldest').innerHTML = `Oldest: <strong>${oldestApp.a.name}</strong> — ${ageDays}d`;
        } else { el('rpt-pipeline-oldest').textContent = ''; }
      }

      // ── Monthly Targets & Achievements ──
      const now      = nowD; // reuse nowD declared earlier
      // thisMonthKey already declared above
      const target   = RPT_TARGETS[thisMonthKey] || { disbAmt: 5000000, loginCount: 20, disbCount: 8 };

      const thisMonthApps = scopeFilter(ALL_APPS).filter(a => {
        const d = parseAppDate(a.date); if (!d) return false;
        return d.getFullYear() === now.getFullYear() && d.getMonth() === now.getMonth();
      });
      const achDisbAmt   = thisMonthApps.filter(a=>a.status==='disbursed').reduce((s,a)=>s+(a.amount||0),0);
      const achLoginCnt  = thisMonthApps.filter(a=>logins.map(x=>x.id).includes(a.id) || ['login','underwriting','offer','approved','disbursed'].includes(a.status)).length;
      const achDisbCnt   = thisMonthApps.filter(a=>a.status==='disbursed').length;

      if (el('rpt-target-period')) el('rpt-target-period').textContent = monthLabel(thisMonthKey);

      if (el('rpt-target-cards')) el('rpt-target-cards').innerHTML = [
        { label:'Disbursed Amount', ach: achDisbAmt,  tgt: target.disbAmt,   fmt: fmtAmt },
        { label:'Login Count',      ach: achLoginCnt,  tgt: target.loginCount, fmt: v=>v },
        { label:'Disbursed Count',  ach: achDisbCnt,   tgt: target.disbCount,  fmt: v=>v },
      ].map(({ label, ach, tgt, fmt }) => {
        const pct = tgt > 0 ? Math.min(100, Math.round(ach / tgt * 100)) : 0;
        const color = pct >= 100 ? 'var(--success)' : pct >= 70 ? 'var(--warn)' : 'var(--accent2)';
        return `<div style="background:var(--surface2);border:1px solid var(--border);border-radius:12px;padding:14px">
          <div style="font-size:11px;font-weight:700;color:var(--text3);margin-bottom:8px;text-transform:uppercase;letter-spacing:.5px">${label}</div>
          <div style="display:flex;justify-content:space-between;align-items:baseline;margin-bottom:8px">
            <span style="font-family:var(--font-head);font-size:18px;font-weight:800;color:${color}">${fmt(ach)}</span>
            <span style="font-size:11px;color:var(--text3)">/ ${fmt(tgt)}</span>
          </div>
          <div style="background:var(--surface3);border-radius:99px;height:8px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:${color};width:${pct}%;transition:width .6s"></div>
          </div>
          <div style="font-size:11px;color:${color};font-weight:700;margin-top:5px">${pct}% achieved</div>
        </div>`;
      }).join('');

      // ── Month-over-month chart ──
      const last6 = allMonths.slice(0, 6).reverse();
      const monthlyData = last6.map(m => {
        const mApps = scopeFilter(ALL_APPS).filter(a => {
          const d = parseAppDate(a.date); if (!d) return false;
          return (d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0')) === m;
        });
        return {
          m,
          disb:   mApps.filter(a=>a.status==='disbursed').length,
          total:  mApps.length,
          amt:    mApps.filter(a=>a.status==='disbursed').reduce((s,a)=>s+(a.amount||0),0),
        };
      });
      const maxDisb = Math.max(...monthlyData.map(d=>d.disb), 1);
      const maxTotal = Math.max(...monthlyData.map(d=>d.total), 1);

      if (el('rpt-monthly-chart')) {
        el('rpt-monthly-chart').innerHTML = monthlyData.map(d => {
          const hDisb  = Math.max(8, Math.round(d.disb  / maxTotal * 92));
          const hTotal = Math.max(8, Math.round(d.total / maxTotal * 92));
          return `<div style="flex:1;display:flex;flex-direction:column;align-items:center;gap:3px;position:relative" title="${monthLabel(d.m)}: ${d.total} apps, ${d.disb} disbursed (${fmtAmt(d.amt)})">
            <div style="width:100%;display:flex;align-items:flex-end;gap:2px;height:92px">
              <div style="flex:1;background:rgba(26,79,163,.15);border-radius:4px 4px 0 0;height:${hTotal}px;position:relative">
                <div style="position:absolute;bottom:0;left:0;right:0;background:var(--accent);border-radius:4px 4px 0 0;height:${hDisb}px"></div>
              </div>
            </div>
            <div style="font-size:10px;font-weight:700;color:var(--accent)">${d.disb}</div>
          </div>`;
        }).join('');
        if (el('rpt-monthly-labels')) el('rpt-monthly-labels').innerHTML = monthlyData.map(d =>
          `<div style="flex:1;text-align:center;font-size:9.5px;color:var(--text3)">${monthLabel(d.m).slice(0,3)}</div>`
        ).join('');
      }

      // ── TAT detail table by month ──
      const tatByMonth = last6.map(m => {
        const mApps = scopeFilter(ALL_APPS).filter(a => {
          const d = parseAppDate(a.date); if (!d) return false;
          return (d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0')) === m && a.status === 'disbursed';
        });
        const tats = mApps.map(a => {
          const t1 = (a.tracking||[]).find(t=>t.name==='EFIN-Login');
          const t2 = (a.tracking||[]).find(t=>t.name==='EFIN-Disbursed');
          if (!t1||!t2) return null;
          const d1=parseTrackDate(t1.date), d2=parseTrackDate(t2.date);
          return d1&&d2 ? Math.max(0,(d2-d1)/3600000) : null; // hours
        }).filter(v=>v!==null);
        const pdUws = mApps.map(a => {
          const t1 = (a.tracking||[]).find(t=>t.name==='EFIN-Workflow Start'||t.name==='EFIN- PersonalDetails');
          const t2 = (a.tracking||[]).find(t=>t.name==='EFIN-Underwriting');
          if (!t1||!t2) return null;
          const d1=parseTrackDate(t1.date), d2=parseTrackDate(t2.date);
          return d1&&d2 ? Math.max(0,(d2-d1)/3600000) : null; // hours
        }).filter(v=>v!==null);
        return {
          m,
          cnt:   mApps.length,
          tat:   tats.length   ? fmtHours(Math.round(tats.reduce((s,v)=>s+v,0)/tats.length))   : '—',
          pduw:  pdUws.length  ? fmtHours(Math.round(pdUws.reduce((s,v)=>s+v,0)/pdUws.length)) : '—',
        };
      });

      if (el('rpt-tat-table')) el('rpt-tat-table').innerHTML = `
        <table style="width:100%;font-size:12.5px;border-collapse:collapse">
          <thead>
            <tr style="border-bottom:1px solid var(--border)">
              <th style="padding:6px 8px;text-align:left;color:var(--text3);font-weight:600">Month</th>
              <th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">Disbursed</th>
              <th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">Login→Disb</th>
              <th style="padding:6px 8px;text-align:center;color:var(--text3);font-weight:600">PD→UW</th>
            </tr>
          </thead>
          <tbody>
            ${tatByMonth.map((r,i) => `<tr style="border-bottom:1px solid var(--border);${i%2===0?'background:rgba(26,79,163,.02)':''}">
              <td style="padding:7px 8px;font-weight:600">${monthLabel(r.m)}</td>
              <td style="padding:7px 8px;text-align:center;color:var(--success);font-weight:700">${r.cnt}</td>
              <td style="padding:7px 8px;text-align:center;color:${r.tat==='—'?'var(--text3)':'var(--accent)'};font-weight:${r.tat==='—'?'400':'700'}">${r.tat}</td>
              <td style="padding:7px 8px;text-align:center;color:${r.pduw==='—'?'var(--text3)':'var(--warn)'};font-weight:${r.pduw==='—'?'400':'700'}">${r.pduw}</td>
            </tr>`).join('')}
          </tbody>
        </table>`;

      // ── Pipeline funnel ──
      const FUNNEL_STAGES = [
        { key: 'wip',          label: 'Personal Details' },
        { key: 'login',        label: 'Assign Lender' },
        { key: 'underwriting', label: 'Underwriting' },
        { key: 'offer',        label: 'Offer' },
        { key: 'approved',     label: 'Approved' },
        { key: 'disbursed',    label: 'Disbursed' },
      ];
      const funnelColors = ['#6366f1','#3b82f6','#0891b2','#0d9488','#16a34a','#22c55e','#15803d'];
      const funnelCounts = FUNNEL_STAGES.map(s => ({
        ...s,
        cnt: scopeFilter(ALL_APPS).filter(a => a.status === s.key).length,
      }));
      const maxFunnel = Math.max(...funnelCounts.map(f=>f.cnt), 1);
      if (el('rpt-funnel')) el('rpt-funnel').innerHTML = funnelCounts.map((f, i) => `
        <div style="margin-bottom:10px">
          <div style="display:flex;justify-content:space-between;margin-bottom:4px;font-size:12px">
            <span style="color:var(--text2);font-weight:600">${f.label}</span>
            <span style="font-weight:700;color:${funnelColors[i]}">${f.cnt}</span>
          </div>
          <div style="background:var(--surface3);border-radius:99px;height:10px;overflow:hidden">
            <div style="height:100%;border-radius:99px;width:${Math.max(4,Math.round(f.cnt/maxFunnel*100))}%;background:${funnelColors[i]};transition:width .6s"></div>
          </div>
        </div>`).join('');

      // ── Loan types breakdown ──
      const typeMap = {}, bankMap = {}, bankAmt = {};
      apps.forEach(a => {
        typeMap[a.loanType] = (typeMap[a.loanType] || 0) + 1;
        if (a.status === 'disbursed') {
          bankMap[a.bank] = (bankMap[a.bank] || 0) + 1;
          bankAmt[a.bank] = (bankAmt[a.bank] || 0) + (a.amount || 0);
        }
      });
      const typesSorted = Object.entries(typeMap).sort((a,b)=>b[1]-a[1]).slice(0,6);
      if (el('report-loan-types')) el('report-loan-types').innerHTML = typesSorted.map(([key,cnt]) => {
        const amt = apps.filter(a=>a.loanType===key&&a.status==='disbursed').reduce((s,a)=>s+(a.amount||0),0);
        return `<div style="display:flex;align-items:center;gap:12px;margin-bottom:14px">
          <div style="flex:1;font-size:13px;color:var(--text2)">${loanTypeLabel(key)}</div>
          <div style="font-size:13px;font-weight:700;color:var(--text);min-width:70px;text-align:right">${amt ? fmtAmt(amt) : '—'}</div>
          <div style="font-size:12px;color:var(--text3);min-width:30px;text-align:right">${cnt}</div>
        </div>`;
      }).join('') || '<div style="color:var(--text3);font-size:13px;padding:12px">No data</div>';

      const banksSorted = Object.entries(bankMap).sort((a,b)=>b[1]-a[1]).slice(0,5);
      const maxBankAmt  = Math.max(...Object.values(bankAmt), 1);
      if (el('report-banks')) el('report-banks').innerHTML = banksSorted.map(([bank]) => {
        const amt = bankAmt[bank] || 0;
        const pct = Math.round(amt / maxBankAmt * 100);
        return `<div style="margin-bottom:14px">
          <div style="display:flex;justify-content:space-between;margin-bottom:5px">
            <span style="font-size:12px;color:var(--text2)">${bank}</span>
            <span style="font-size:12px;font-weight:700;color:var(--text)">${fmtAmt(amt)}</span>
          </div>
          <div class="progress-wrap"><div class="progress-bar" style="width:${pct}%"></div></div>
        </div>`;
      }).join('') || '<div style="color:var(--text3);font-size:13px;padding:12px">No disbursals</div>';

      // ── Leaderboard: per user or per team ──
      const lbTitle = el('rpt-leaderboard-title');
      if (lbTitle) lbTitle.textContent = _rptScope === 'team' ? '👥 Team Member Performance' : '👤 User Performance';

      const salesPeople = [...new Set(scopeFilter(ALL_APPS).map(a => a.sales).filter(Boolean))];
      let lbData = salesPeople.map(sp => {
        const spApps  = scopeFilter(ALL_APPS).filter(a => a.sales === sp);
        const spDisb  = spApps.filter(a => a.status === 'disbursed');
        const spRej   = spApps.filter(a => a.status === 'rejected');
        const spAmt   = spDisb.reduce((s,a)=>s+(a.amount||0),0);
        const spConv  = spApps.length ? (spDisb.length/spApps.length*100).toFixed(1) : '0';
        const spRejR  = spApps.length ? (spRej.length/spApps.length*100).toFixed(1)  : '0';
        const spTats  = spDisb.map(a => {
          const t1=(a.tracking||[]).find(t=>t.name==='EFIN-Login');
          const t2=(a.tracking||[]).find(t=>t.name==='EFIN-Disbursed');
          if(!t1||!t2) return null;
          const d1=parseTrackDate(t1.date),d2=parseTrackDate(t2.date);
          return d1&&d2?Math.max(0,(d2-d1)/86400000):null;
        }).filter(v=>v!==null);
        const spTatNum = spTats.length ? Math.round(spTats.reduce((s,v)=>s+v,0)/spTats.length * 24) : null;
        const spTat = spTatNum !== null ? fmtHours(spTatNum) : '—';

        // Mini trend: last 3 months disbursals
        const now3 = new Date();
        const trend = [2,1,0].map(mOff => {
          const ref = new Date(now3.getFullYear(), now3.getMonth() - mOff, 1);
          const mKey = ref.getFullYear() + '-' + String(ref.getMonth()+1).padStart(2,'0');
          return spApps.filter(a => {
            const d = parseAppDate(a.date); if (!d) return false;
            const ak = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0');
            return ak === mKey && a.status === 'disbursed';
          }).length;
        });

        return { name:sp, total:spApps.length, disb:spDisb.length, amt:spAmt, conv:spConv, rej:spRejR, tat:spTat, tatNum:spTatNum, trend };
      });

      // Sort leaderboard
      lbData.sort((a, b) => {
        let av = a[_rptLbSortCol], bv = b[_rptLbSortCol];
        if (_rptLbSortCol === 'name') { av = av || ''; bv = bv || ''; }
        else { av = parseFloat(av) || 0; bv = parseFloat(bv) || 0; }
        return _rptLbSortDir === 'desc' ? (bv > av ? 1 : -1) : (av > bv ? 1 : -1);
      });

      const maxAmt = Math.max(...lbData.map(r => r.amt), 1);

      const lbBody = el('rpt-leaderboard-body');
      if (lbBody) lbBody.innerHTML = lbData.length ? lbData.map((r,i) => {
        const trendSvg = (() => {
          const vals = r.trend;
          const mx = Math.max(...vals, 1);
          const pts = vals.map((v, j) => `${j * 22},${20 - Math.round(v/mx*18)}`).join(' ');
          const col = vals[2] >= vals[1] ? '#22c55e' : '#ef4444';
          return `<svg width="48" height="22" viewBox="0 0 46 22" style="overflow:visible">
            <polyline points="${pts}" fill="none" stroke="${col}" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
            ${vals.map((v,j) => `<circle cx="${j*22}" cy="${20-Math.round(v/mx*18)}" r="2.5" fill="${col}"/>`).join('')}
          </svg>`;
        })();
        return `<tr>
          <td style="font-weight:700;color:${i===0?'#f59e0b':i===1?'#94a3b8':i===2?'#cd7c2f':'var(--text3)'}">
            ${i===0?'🥇':i===1?'🥈':i===2?'🥉':'#'+(i+1)}
          </td>
          <td style="font-weight:600">${r.name}</td>
          <td style="text-align:center">${r.total}</td>
          <td style="text-align:center;font-weight:700;color:var(--success)">${r.disb}</td>
          <td style="text-align:right">
            <div style="font-weight:700;color:var(--accent);font-size:12.5px">${fmtAmt(r.amt)}</div>
            <div style="background:var(--surface3);border-radius:99px;height:4px;margin-top:3px;overflow:hidden">
              <div style="height:100%;border-radius:99px;background:var(--accent-light);width:${Math.round(r.amt/maxAmt*100)}%"></div>
            </div>
          </td>
          <td style="text-align:center"><span style="color:${+r.conv>=50?'var(--success)':+r.conv>=25?'var(--warn)':'var(--danger)'};font-weight:700">${r.conv}%</span></td>
          <td style="text-align:center"><span style="color:${+r.rej>=30?'var(--danger)':+r.rej>=15?'var(--warn)':'var(--text3)'};font-weight:600">${r.rej}%</span></td>
          <td style="text-align:center;color:var(--accent)">${r.tat}</td>
          <td style="text-align:center">${trendSvg}</td>
        </tr>`;
      }).join('') : '<tr><td colspan="9" style="text-align:center;padding:24px;color:var(--text3)">No data for current scope</td></tr>';

      // ── Lead source breakdown ──
      const leadSrcMap = {};
      apps.forEach(a => { if (a.leadsrc) leadSrcMap[a.leadsrc] = (leadSrcMap[a.leadsrc] || 0) + 1; });
      const leadSorted = Object.entries(leadSrcMap).sort((a,b)=>b[1]-a[1]);
      const maxLead = Math.max(...Object.values(leadSrcMap), 1);
      const leadLabels = { google_ads:'Google Ads', facebook:'Facebook', whatsapp:'WhatsApp', instagram:'Instagram', reference:'Reference', direct:'Direct' };
      const leadColors = ['#6366f1','#3b82f6','#22c55e','#f59e0b','#ef4444','#8b5cf6','#14b8a6'];
      if (el('rpt-lead-source')) el('rpt-lead-source').innerHTML = leadSorted.length ? leadSorted.map(([src, cnt], i) => `
        <div style="margin-bottom:12px">
          <div style="display:flex;justify-content:space-between;margin-bottom:4px">
            <span style="font-size:12px;color:var(--text2);font-weight:600">${leadLabels[src] || src}</span>
            <span style="font-size:12px;font-weight:700;color:${leadColors[i%leadColors.length]}">${cnt} <span style="color:var(--text3);font-weight:400">(${Math.round(cnt/apps.length*100)}%)</span></span>
          </div>
          <div style="background:var(--surface3);border-radius:99px;height:8px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:${leadColors[i%leadColors.length]};width:${Math.round(cnt/maxLead*100)}%;transition:width .5s"></div>
          </div>
        </div>`).join('') : '<div style="color:var(--text3);font-size:13px;padding:8px">No data</div>';

      // ── CIBIL score distribution ──
      const cibilBuckets = [
        { label: '< 600', min: 0,   max: 599,  color: '#ef4444' },
        { label: '600–649', min: 600, max: 649, color: '#f97316' },
        { label: '650–699', min: 650, max: 699, color: '#f59e0b' },
        { label: '700–749', min: 700, max: 749, color: '#84cc16' },
        { label: '750–799', min: 750, max: 799, color: '#22c55e' },
        { label: '800+',  min: 800, max: 999,   color: '#16a34a' },
      ];
      const cibilApps = apps.filter(a => a.cibil);
      const maxCibil = Math.max(...cibilBuckets.map(b => cibilApps.filter(a => a.cibil >= b.min && a.cibil <= b.max).length), 1);
      if (el('rpt-cibil-dist')) el('rpt-cibil-dist').innerHTML = cibilApps.length ? cibilBuckets.map(b => {
        const cnt = cibilApps.filter(a => a.cibil >= b.min && a.cibil <= b.max).length;
        return `<div style="display:flex;align-items:center;gap:10px;margin-bottom:9px">
          <span style="font-size:11.5px;color:var(--text2);font-weight:600;min-width:64px">${b.label}</span>
          <div style="flex:1;background:var(--surface3);border-radius:99px;height:9px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:${b.color};width:${Math.round(cnt/maxCibil*100)}%;transition:width .5s"></div>
          </div>
          <span style="font-size:12px;font-weight:700;color:${b.color};min-width:24px;text-align:right">${cnt}</span>
        </div>`;
      }).join('') : '<div style="color:var(--text3);font-size:13px;padding:8px">No CIBIL data</div>';

      // ── Top cities ──
      const cityMap = {};
      apps.forEach(a => { if (a.city) cityMap[a.city] = (cityMap[a.city] || 0) + 1; });
      const citiesSorted = Object.entries(cityMap).sort((a,b)=>b[1]-a[1]).slice(0, 8);
      const maxCity = Math.max(...citiesSorted.map(([,c])=>c), 1);
      if (el('rpt-top-cities')) el('rpt-top-cities').innerHTML = citiesSorted.length ? citiesSorted.map(([city, cnt], i) => `
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:9px">
          <span style="font-size:11px;font-weight:800;color:var(--text3);min-width:16px;text-align:center">${i+1}</span>
          <span style="font-size:12.5px;color:var(--text2);font-weight:600;flex:1">${city}</span>
          <div style="width:60px;background:var(--surface3);border-radius:99px;height:7px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:var(--accent);opacity:${0.4 + 0.6*(cnt/maxCity)};width:${Math.round(cnt/maxCity*100)}%;transition:width .5s"></div>
          </div>
          <span style="font-size:12px;font-weight:700;color:var(--accent);min-width:20px;text-align:right">${cnt}</span>
        </div>`).join('') : '<div style="color:var(--text3);font-size:13px;padding:8px">No city data</div>';

      // ── Employment type breakdown ──
      const empMap = {};
      apps.forEach(a => { if (a.empType) empMap[a.empType] = (empMap[a.empType] || 0) + 1; });
      const empLabels = { SALARIED:'Salaried', SELFEMP:'Self-Employed', BUSINESS:'Business', PROFESSIONAL:'Professional' };
      const empColors = ['#3b82f6','#f59e0b','#22c55e','#8b5cf6','#ef4444'];
      const empSorted = Object.entries(empMap).sort((a,b)=>b[1]-a[1]);
      const totalEmp = empSorted.reduce((s,[,c])=>s+c, 0);
      if (el('rpt-emp-type')) el('rpt-emp-type').innerHTML = empSorted.length ? `
        <div style="display:flex;gap:6px;flex-wrap:wrap;margin-bottom:14px">
          ${empSorted.map(([k,cnt],i) => `<div style="display:flex;align-items:center;gap:5px">
            <div style="width:10px;height:10px;border-radius:50%;background:${empColors[i%empColors.length]}"></div>
            <span style="font-size:11px;color:var(--text2)">${empLabels[k]||k} <strong>(${cnt})</strong></span>
          </div>`).join('')}
        </div>
        ${empSorted.map(([k,cnt],i) => {
          const pct = totalEmp ? Math.round(cnt/totalEmp*100) : 0;
          return `<div style="margin-bottom:10px">
            <div style="display:flex;justify-content:space-between;margin-bottom:4px;font-size:12px">
              <span style="color:var(--text2);font-weight:600">${empLabels[k]||k}</span>
              <span style="font-weight:700;color:${empColors[i%empColors.length]}">${pct}%</span>
            </div>
            <div style="background:var(--surface3);border-radius:99px;height:9px;overflow:hidden">
              <div style="height:100%;border-radius:99px;width:${pct}%;background:${empColors[i%empColors.length]};transition:width .5s"></div>
            </div>
          </div>`;
        }).join('')}` : '<div style="color:var(--text3);font-size:13px;padding:8px">No data</div>';

      // ── Loan amount buckets ──
      const amtBuckets = [
        { label: 'Under ₹2L',  min: 0,      max: 199999  },
        { label: '₹2L – ₹5L',  min: 200000, max: 499999  },
        { label: '₹5L – ₹10L', min: 500000, max: 999999  },
        { label: '₹10L – ₹25L',min: 1000000,max: 2499999 },
        { label: '₹25L – ₹50L',min: 2500000,max: 4999999 },
        { label: '₹50L+',      min: 5000000,max: Infinity },
      ];
      const amtColors2 = ['#6366f1','#3b82f6','#0891b2','#16a34a','#f59e0b','#ef4444'];
      const amtCounts = amtBuckets.map(b => ({ ...b, cnt: apps.filter(a => (a.amount||0) >= b.min && (a.amount||0) <= b.max).length }));
      const maxAmtB = Math.max(...amtCounts.map(b=>b.cnt), 1);
      if (el('rpt-amt-buckets')) el('rpt-amt-buckets').innerHTML = amtCounts.map((b,i) => `
        <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
          <span style="font-size:11.5px;color:var(--text2);font-weight:600;min-width:100px">${b.label}</span>
          <div style="flex:1;background:var(--surface3);border-radius:99px;height:9px;overflow:hidden">
            <div style="height:100%;border-radius:99px;background:${amtColors2[i]};width:${b.cnt ? Math.max(6,Math.round(b.cnt/maxAmtB*100)) : 0}%;transition:width .5s"></div>
          </div>
          <span style="font-size:12px;font-weight:700;color:${amtColors2[i]};min-width:24px;text-align:right">${b.cnt}</span>
        </div>`).join('');

      // ── Active Time aggregation by user / group ──
      try { renderActiveTimeAgg(); } catch(_) {}
    }

    // ── Date helpers ──
    function parseAppDate(str) {
      if (!str) return null;
      // Formats: '15 Mar 2026', '2026-03-15'
      const m1 = str.match(/(\d{1,2})\s+(\w+)\s+(\d{4})/);
      if (m1) {
        const MONTHS = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
        return new Date(+m1[3], MONTHS[m1[2]] ?? 0, +m1[1]);
      }
      const m2 = str.match(/(\d{4})-(\d{2})-(\d{2})/);
      if (m2) return new Date(+m2[1], +m2[2]-1, +m2[3]);
      return null;
    }

    function parseTrackDate(str) {
      if (!str) return null;
      // Format: '15 Mar 2026 09:00'
      const m = str.match(/(\d{1,2})\s+(\w+)\s+(\d{4})(?:\s+(\d{2}):(\d{2}))?/);
      if (!m) return null;
      const MONTHS = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
      return new Date(+m[3], MONTHS[m[2]]??0, +m[1], +(m[4]||0), +(m[5]||0));
    }

    function monthLabel(key) {
      if (!key) return '';
      const [y,mo] = key.split('-');
      const names = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
      return (names[parseInt(mo)-1] || mo) + ' ' + y;
    }

