    var ACTIVITY_LOG = [
    ];

    function renderActivity() {
      const el = document.getElementById('recent-activity-list');
      if (!el) return;
      const timeAgo = iso => {
        const diff = (Date.now() - new Date(iso)) / 1000;
        if (diff < 60) return 'Just now';
        if (diff < 3600) return Math.floor(diff / 60) + ' min ago';
        if (diff < 86400) return Math.floor(diff / 3600) + ' hr ago';
        return Math.floor(diff / 86400) + ' day' + (Math.floor(diff / 86400) > 1 ? 's' : '') + ' ago';
      };
      el.innerHTML = ACTIVITY_LOG.slice(0, 7).map(e => {
        const hasApp = e.appId && typeof openDetail === 'function';
        return `
    <div class="activity-item${hasApp ? ' activity-item-link' : ''}"${hasApp ? ` onclick="_activityOpenApp('${e.appId}')" style="cursor:pointer"` : ''}>
      <div class="act-dot" style="background:${e.dot}"></div>
      <div class="act-content">
        <div class="act-text">${e.text}</div>
        <div class="act-time">${timeAgo(e.time)}${hasApp ? `<span style="margin-left:6px;font-size:10px;color:var(--accent);font-weight:600;opacity:.7">→ Open</span>` : ''}</div>
      </div>
    </div>`;
      }).join('');
    }

