    // ═══════════════════════════════════════════════════════════════════════
    //  EXPERT EXPORT — role/user-based access control
    //  Admin always allowed; additional roles/individual users can be granted
    //  from Settings → Roles & Permissions. The backend (ExpertExportController)
    //  is the real authorization gate — this is only UI convenience so the
    //  button isn't shown to users who would just get a 403 anyway.
    // ═══════════════════════════════════════════════════════════════════════
    let _expertExportAllowed = null;
    let _expertExportCheckedAt = 0;

    function _expertExportAuthHeader() {
      var tok = null;
      try { tok = localStorage.getItem('loanms_token'); } catch(e) {}
      return tok ? { 'Authorization': 'Bearer ' + tok } : {};
    }

    async function expertExportCheckAccess() {
      // Cache for 30s so this cheap call doesn't re-fire on every dashboard re-render
      if (_expertExportAllowed !== null && (Date.now() - _expertExportCheckedAt) < 30000) {
        _expertExportApplyVisibility(_expertExportAllowed);
        return _expertExportAllowed;
      }
      try {
        const res = await fetch('/api/expertexport/access', { headers: _expertExportAuthHeader() });
        if (!res.ok) { _expertExportAllowed = false; }
        else { const data = await res.json(); _expertExportAllowed = !!data.allowed; }
      } catch(e) { _expertExportAllowed = false; }
      _expertExportCheckedAt = Date.now();
      _expertExportApplyVisibility(_expertExportAllowed);
      return _expertExportAllowed;
    }

    function _expertExportApplyVisibility(allowed) {
      const btn = document.getElementById('expert-export-btn');
      if (btn) btn.style.display = allowed ? 'inline-flex' : 'none';
    }

    async function expertExportRun() {
      const btn = document.getElementById('expert-export-btn');
      const orig = btn ? btn.innerHTML : '';
      if (btn) { btn.disabled = true; btn.innerHTML = '<span>⏳</span> Exporting…'; }
      try {
        const res = await fetch('/api/expertexport/data', { headers: _expertExportAuthHeader() });
        if (res.status === 403) {
          showToast('You do not have permission for Expert Export', 'error');
          _expertExportAllowed = false;
          _expertExportApplyVisibility(false);
          return;
        }
        if (!res.ok) { showToast('Expert Export failed', 'error'); return; }
        const blob = await res.blob();
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'expert-export-' + new Date().toISOString().slice(0,10) + '.csv';
        document.body.appendChild(a); a.click(); document.body.removeChild(a);
        URL.revokeObjectURL(url);
        showToast('✓ Expert Export downloaded', 'success');
      } catch(e) {
        showToast('Expert Export failed: ' + (e.message || e), 'error');
      } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = orig; }
      }
    }
    window.expertExportRun = expertExportRun;
    window.expertExportCheckAccess = expertExportCheckAccess;
    window.expertExportInvalidateCache = function() { _expertExportAllowed = null; _expertExportCheckedAt = 0; };

    function updateDashboardStats() {
      // Expert Export button visibility — re-checked (cheaply, cached) on every
      // dashboard render; the real gate is always the backend, this only decides
      // whether to show the button.
      if (typeof expertExportCheckAccess === 'function') expertExportCheckAccess();
      const live   = APPLICATIONS.filter(a => !a.id.startsWith('H') && !a.is_draft);
      // Role-scoped: each user sees only their accessible apps in counts
      const scoped = (typeof _applyRoleFilter === 'function') ? _applyRoleFilter(live) : live;
      const total     = scoped.length;
      const disbursed = scoped.filter(a => a.status === 'disbursed').length;
      const inProcess = scoped.filter(a => ['login','underwriting','offer'].includes(a.status)).length;
      const rejected  = scoped.filter(a => a.status === 'rejected').length;
      const newCases  = scoped.filter(a => a.status === 'wip').length;
      const approved  = scoped.filter(a => a.status === 'approved').length;
      const hold      = scoped.filter(a => a.status === 'hold').length;
      const appCount  = document.getElementById('app-count');
      const set = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
      set('st-total',    total);
      set('st-disbursed',disbursed);
      set('st-process',  inProcess);
      set('st-rejected', rejected);
      set('st-new',      newCases);
      set('st-approved', approved);
      set('st-hold',     hold);
      if (appCount) appCount.textContent = total;
      // Real, computed sub-metrics (replaces hardcoded fake percentages).
      const pct = (n) => total ? Math.round((n / total) * 100) : 0;
      const setHTML = (id, html) => { const e = document.getElementById(id); if (e) e.innerHTML = html; };
      setHTML('st-total-sub',     `<span style="color:var(--text3)">${approved + disbursed} closed · ${inProcess + newCases} active</span>`);
      setHTML('st-disbursed-sub', `<span class="up">${pct(disbursed)}%</span>&nbsp;conversion rate`);
      setHTML('st-process-sub',   `<span style="color:var(--warn)">●</span>&nbsp;${inProcess} need attention`);
      setHTML('st-rejected-sub',  `<span style="color:var(--text3)">${pct(rejected)}% of total</span>`);
    }

    // Update greeting based on time of day
    function updateGreeting() {
      const h = new Date().getHours();
      const period = h < 12 ? 'Morning' : h < 17 ? 'Afternoon' : 'Evening';
      const name = (currentUser && currentUser.name) ? currentUser.name.split(' ')[0] : 'Admin';
      const el = document.getElementById('dash-greeting');
      if (el) el.textContent = `Good ${period}, ${name} 👋`;
    }

