    function laConfirmAddBank(ov) {
      const name = document.getElementById("ab-name")?.value.trim();
      if (!name) { showToast("Bank name is required", "error"); return; }
      const empTypes = [];
      if (document.getElementById("ab-emp-sal")?.checked) empTypes.push("SALARIED");
      if (document.getElementById("ab-emp-sep")?.checked) empTypes.push("SELFEMP");
      if (document.getElementById("ab-emp-senp")?.checked) empTypes.push("SENP");
      const cibil = parseInt(document.getElementById("ab-cibil")?.value) || 700;
      const maxLoan = parseInt(document.getElementById("ab-maxloan")?.value) || 5000000;
      LA_DB.banks.push({
        id: LA_DB.nextId.bank++, name,
        isIncred: document.getElementById("ab-incred")?.checked||false,
        isElite: document.getElementById("ab-elite")?.checked||false,
        lines: [],
        serviceablePins: [],
        rules: { minCibil: cibil, acceptNTC: false, maxLoanAmt: maxLoan, minTenure: 12, maxTenure: 60, foirLimit: 50, pfRequired: false, minAge: 21, maxAge: 60, minExpMonths: 6, empTypes: empTypes.length ? empTypes : ["SALARIED"], compTypes: ["plcc","plc","llp","govt","psu"], acceptedCategories: [] }
      });
      ov.remove(); laRenderBanks(); showToast(name + " added ✓ — click ✏ Edit to configure eligibility filters", "success");
    }

    function laDeleteBank(id) {
      const bank = LA_DB.banks.find(b => b.id === id); if (!bank) return;
      if (!confirm(`Delete "${bank.name}" and its ${bank.lines.length} line(s)?`)) return;
      LA_DB.banks = LA_DB.banks.filter(b => b.id !== id);
      LA_DB.wizardSelectedBanks = LA_DB.wizardSelectedBanks.filter(bid => bid !== id);
      laRenderBanks(); laLoadEligibility(); showToast("Bank deleted", "info");
    }

    function laOpenBankDetail(id) {
      const b = LA_DB.banks.find(x => x.id === id); if (!b) return;
      LA_DB.currentBankId = id;
      const det = document.getElementById("la-bank-detail"); if (!det) return;
      det.style.display = "block";
      document.getElementById("la-detail-bname").textContent = b.name;
      document.getElementById("la-detail-name-input").value = b.name;
      document.getElementById("la-detail-incred").checked = b.isIncred;
      document.getElementById("la-detail-elite").checked = b.isElite;
      // Update avatar
      const av = document.getElementById("la-detail-avatar");
      if (av) { av.textContent = b.name[0]; av.style.background = b.isIncred ? 'rgba(245,158,11,.15)' : 'rgba(77,124,255,.12)'; av.style.color = b.isIncred ? '#f59e0b' : 'var(--accent)'; }
      // Mode badge
      const mb = document.getElementById("la-detail-mode-badge");
      if (mb) mb.innerHTML = b.lines.length > 0
        ? `<span style="font-size:10.5px;padding:2px 8px;border-radius:99px;background:rgba(26,115,64,.1);color:var(--success);font-weight:700">🏢 Path A — Company List (${b.lines.length} lines)</span>`
        : `<span style="font-size:10.5px;padding:2px 8px;border-radius:99px;background:rgba(3,105,161,.1);color:#0369a1;font-weight:700">🔓 Path B — Open List</span>`;
      // Activate the Companies tab by default
      const firstTab = document.querySelector('.la-dtab');
      laDetailTab('companies', firstTab);
      laRenderLines(b);
      det.scrollIntoView({ behavior: "smooth", block: "nearest" });
    }

    let _laLineSortField = null, _laLineSortDir = "asc";

    function laLineSort(field) {
      if (_laLineSortField === field) _laLineSortDir = _laLineSortDir === "asc" ? "desc" : "asc";
      else { _laLineSortField = field; _laLineSortDir = "asc"; }
      ["company","category","salary"].forEach(f => { const el = document.getElementById("la-lsort-" + f); if (el) el.textContent = f === field ? (_laLineSortDir === "asc" ? " ↑" : " ↓") : ""; });
      laRenderLines();
    }

    function laFilterLines() { laRenderLines(); }

    function laRenderLines(bank) {
      if (!bank) bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId);
      const tbody = document.getElementById("la-lines-body"); if (!tbody || !bank) return;
      const countEl = document.getElementById("la-lines-count");
      if (countEl) countEl.textContent = "(" + bank.lines.length + " line" + (bank.lines.length!==1?"s":"") + ")";
      const lineKeys = bank.lines.map(l => l.companyId + "-" + l.categoryId);
      const dupes = lineKeys.filter((k, i) => lineKeys.indexOf(k) !== i);
      const dupeWarn = document.getElementById("la-lines-dupe-warn");
      if (dupeWarn) dupeWarn.style.display = dupes.length ? "" : "none";
      const searchRaw = (document.getElementById("la-lines-search")?.value || "").toLowerCase();
      let lines = [...bank.lines];
      if (searchRaw) lines = lines.filter(l => {
        const comp = LA_DB.companies.find(c => c.id === l.companyId);
        const cat  = LA_DB.categories.find(c => c.id === l.categoryId);
        return (comp?.name||"").toLowerCase().includes(searchRaw) || (cat?.name||"").toLowerCase().includes(searchRaw) || (l.pinCode||"").includes(searchRaw);
      });
      if (_laLineSortField) lines.sort((a, b) => {
        let va, vb;
        if (_laLineSortField === "company") { va = LA_DB.companies.find(c => c.id === a.companyId)?.name||""; vb = LA_DB.companies.find(c => c.id === b.companyId)?.name||""; }
        else if (_laLineSortField === "category") { va = LA_DB.categories.find(c => c.id === a.categoryId)?.name||""; vb = LA_DB.categories.find(c => c.id === b.categoryId)?.name||""; }
        else { va = LA_DB.categories.find(c => c.id === a.categoryId)?.salary||0; vb = LA_DB.categories.find(c => c.id === b.categoryId)?.salary||0; }
        return _laLineSortDir === "asc" ? (va < vb ? -1 : va > vb ? 1 : 0) : (va > vb ? -1 : va < vb ? 1 : 0);
      });
      const CT_LABEL = { plcc:'Pvt Ltd', plc:'Public Ltd', llp:'LLP', govt:'Government', psu:'PSU', proprietorship:'Proprietorship', partnership:'Partnership', other:'Other' };
      if (!lines.length) { tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;color:var(--text3);padding:20px">${searchRaw ? "No lines match" : "No company lines yet — this bank is on Path B (Open List)"}</td></tr>`; return; }
      tbody.innerHTML = lines.map(l => {
        const comp = LA_DB.companies.find(c => c.id === l.companyId);
        const cat  = LA_DB.categories.find(c => c.id === l.categoryId);
        const isDupe = dupes.includes(l.companyId + "-" + l.categoryId);
        const compType = comp ? (CT_LABEL[comp.compType] || comp.compType || '—') : '—';
        return `<tr style="${isDupe ? "background:rgba(212,43,43,.04)" : ""}">
          <td><span style="font-weight:600">${comp ? comp.name : "<span style='color:var(--danger)'>Unknown</span>"}</span>${isDupe ? " <span style='font-size:10px;color:var(--danger)'>⚠ dup</span>" : ""}</td>
          <td><span style="font-size:10.5px;background:rgba(10,88,154,.07);color:var(--accent2-dark)||var(--text2);padding:2px 8px;border-radius:7px;font-weight:500">${compType}</span></td>
          <td>${cat ? `<span class="badge badge-wip" style="font-size:10px">${cat.name}</span>` : "—"}</td>
          <td style="font-family:monospace;font-size:12px">${l.pinCode||"—"}</td>
          <td style="color:var(--danger);font-family:monospace;font-size:12px;font-weight:600">${cat ? "₹"+cat.salary.toLocaleString("en-IN") : "—"}</td>
          <td>${l.pf ? "<span class='badge badge-approved' style='font-size:10px'>✓ PF</span>" : "<span style='color:var(--text3);font-size:11px'>—</span>"}</td>
          <td><button class="btn btn-danger btn-sm" onclick="laDeleteLine(${l.id})" style="font-size:11px">✕</button></td>
        </tr>`;
      }).join("");
    }

    function laAddCompanyLine() {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId); if (!bank) return;
      const co = LA_DB.companies.map(c => `<option value="${c.id}">${c.name}</option>`).join("");
      const ca = LA_DB.categories.map(c => `<option value="${c.id}">${c.name} (₹${c.salary.toLocaleString("en-IN")})</option>`).join("");
      const tbody = document.getElementById("la-lines-body"); if (!tbody) return;
      document.getElementById("la-new-line-row")?.remove();
      const row = document.createElement("tr"); row.id = "la-new-line-row";
      row.innerHTML = `<td><select id="la-nl-comp" onchange="laUpdateNewLineCompType()" style="background:var(--surface2);border:1px solid var(--border);color:var(--text);padding:5px 8px;border-radius:6px;font-size:12px;width:100%"><option value="">Select…</option>${co}</select></td><td id="la-nl-comptype" style="font-size:10.5px;color:var(--text3)">—</td><td><select id="la-nl-cat" style="background:var(--surface2);border:1px solid var(--border);color:var(--text);padding:5px 8px;border-radius:6px;font-size:12px;width:100%"><option value="">Select…</option>${ca}</select></td><td><input id="la-nl-pin" type="text" placeholder="400001" maxlength="6" style="background:var(--surface2);border:1px solid var(--border);color:var(--text);padding:5px 8px;border-radius:6px;font-family:monospace;font-size:12px;width:80px"></td><td style="color:var(--text3);font-size:12px">Auto</td><td><label style="display:flex;align-items:center;gap:5px;font-size:12px;cursor:pointer"><input type="checkbox" id="la-nl-pf" style="width:auto"> PF</label></td><td style="display:flex;gap:4px"><button class="btn btn-success btn-sm" onclick="laSaveNewLine()" style="font-size:11px">Save</button><button class="btn btn-ghost btn-sm" onclick="document.getElementById('la-new-line-row').remove()" style="font-size:11px">✕</button></td>`;
      tbody.prepend(row);
    }

    function laAddMultipleLines() {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId); if (!bank) return;
      const ov = document.createElement("div");
      ov.style.cssText = "position:fixed;inset:0;background:rgba(12,23,51,.45);backdrop-filter:blur(4px);z-index:700;display:flex;align-items:center;justify-content:center";
      ov.innerHTML = `<div style="background:var(--surface);border-radius:16px;width:min(560px,96vw);max-height:80vh;overflow-y:auto;box-shadow:var(--shadow-lg);padding:24px"><div style="font-family:var(--font-head);font-size:15px;font-weight:800;margin-bottom:4px">＋ Add Multiple Lines — ${bank.name}</div><div style="font-size:12px;color:var(--text3);margin-bottom:16px">Add up to 10 lines at once</div><div id="ml-rows" style="display:flex;flex-direction:column;gap:8px;margin-bottom:14px"></div><button class="btn btn-ghost btn-sm" onclick="laAddMultiRow()" style="margin-bottom:16px">＋ Add Row</button><div style="display:flex;gap:10px"><button class="btn btn-primary" onclick="laSaveMultipleLines(this.closest('[style*=fixed]'))" style="flex:1">✓ Save All</button><button class="btn btn-ghost" onclick="this.closest('[style*=fixed]').remove()">Cancel</button></div></div>`;
      document.body.appendChild(ov);
      for (let i = 0; i < 3; i++) laAddMultiRow();
    }

    function laAddMultiRow() {
      const co = LA_DB.companies.map(c => `<option value="${c.id}">${c.name}</option>`).join("");
      const ca = LA_DB.categories.map(c => `<option value="${c.id}">${c.name}</option>`).join("");
      const cont = document.getElementById("ml-rows"); if (!cont) return;
      const row = document.createElement("div");
      row.style.cssText = "display:grid;grid-template-columns:2fr 1.5fr 80px 50px 20px;gap:6px;align-items:center";
      row.innerHTML = `<select class="ml-comp" style="padding:7px 8px;border:1px solid var(--border2);border-radius:7px;font-size:12px;background:var(--surface);color:var(--text)"><option value="">Company…</option>${co}</select><select class="ml-cat" style="padding:7px 8px;border:1px solid var(--border2);border-radius:7px;font-size:12px;background:var(--surface);color:var(--text)"><option value="">Category…</option>${ca}</select><input class="ml-pin" type="text" placeholder="PIN" maxlength="6" style="padding:7px 8px;border:1px solid var(--border2);border-radius:7px;font-size:12px;font-family:monospace;background:var(--surface);color:var(--text)"><label style="display:flex;align-items:center;gap:4px;font-size:12px;cursor:pointer"><input type="checkbox" class="ml-pf" style="width:auto"> PF</label><button onclick="this.parentElement.remove()" style="background:none;border:none;cursor:pointer;font-size:16px;color:var(--text3)">✕</button>`;
      cont.appendChild(row);
    }

    function laSaveMultipleLines(ov) {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId); if (!bank) return;
      let added = 0;
      document.querySelectorAll("#ml-rows > div").forEach(row => {
        const compId = parseInt(row.querySelector(".ml-comp")?.value);
        const catId  = parseInt(row.querySelector(".ml-cat")?.value);
        const pin    = row.querySelector(".ml-pin")?.value.trim()||"";
        const pf     = row.querySelector(".ml-pf")?.checked||false;
        if (compId && catId) { bank.lines.push({ id: LA_DB.nextId.line++, companyId: compId, categoryId: catId, pinCode: pin, pf }); added++; }
      });
      ov.remove(); laRenderLines(bank); laRenderBanks();
      showToast(added + " line" + (added!==1?"s":"") + " added ✓", "success");
    }

    function laUpdateNewLineCompType() {
      const sel = document.getElementById('la-nl-comp');
      const ct = document.getElementById('la-nl-comptype');
      if (!sel || !ct) return;
      const comp = LA_DB.companies.find(c => c.id === parseInt(sel.value));
      const CT_LABEL = { plcc:'Pvt Ltd', plc:'Public Ltd', llp:'LLP', govt:'Government', psu:'PSU', proprietorship:'Proprietorship', partnership:'Partnership', other:'Other' };
      ct.innerHTML = comp ? `<span style="font-size:10.5px;background:rgba(26,79,163,.07);color:var(--text2);padding:2px 7px;border-radius:6px">${CT_LABEL[comp.compType]||comp.compType||'—'}</span>` : '—';
    }

    function laSaveNewLine() {
      const compId = parseInt(document.getElementById("la-nl-comp")?.value);
      const catId  = parseInt(document.getElementById("la-nl-cat")?.value);
      if (!compId || !catId) { showToast("Company and Category are required", "error"); return; }
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId);
      bank.lines.push({ id: LA_DB.nextId.line++, companyId: compId, categoryId: catId, pinCode: document.getElementById("la-nl-pin")?.value.trim()||"", pf: document.getElementById("la-nl-pf")?.checked||false });
      document.getElementById("la-new-line-row")?.remove();
      laRenderLines(bank); laRenderBanks(); showToast("Line added ✓", "success");
    }

    function laDeleteLine(lineId) {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId);
      bank.lines = bank.lines.filter(l => l.id !== lineId);
      laRenderLines(bank); laRenderBanks(); showToast("Line removed", "info");
    }

    function laDeleteAllLines() {
      if (!confirm("Delete ALL lines for this bank?")) return;
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId);
      bank.lines = []; laRenderLines(bank); laRenderBanks(); showToast("All lines deleted", "info");
    }

    function laSaveBankDetails() {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId); if (!bank) return;
      const name = document.getElementById("la-detail-name-input")?.value.trim();
      if (name) bank.name = name;
      bank.isIncred = document.getElementById("la-detail-incred")?.checked||false;
      bank.isElite  = document.getElementById("la-detail-elite")?.checked||false;
      document.getElementById("la-detail-bname").textContent = bank.name;
      laRenderBanks(); showToast("Bank saved ✓", "success");
    }

    function laExportBanks() {
      const rows = [["Bank","InCred","Mudrahub","Lines","Max Loan","Min CIBIL","FOIR%"]];
      LA_DB.banks.forEach(b => { const r=b.rules||{}; rows.push([b.name,b.isIncred?"Yes":"No",b.isElite?"Yes":"No",b.lines.length,r.maxLoanAmt||"",r.minCibil||"",r.foirLimit||""]); });
      _laCsvDownload(rows, "analytic_banks.csv"); showToast("Banks exported ✓", "success");
    }

    function laExportBankLines() {
      const bank = LA_DB.banks.find(x => x.id === LA_DB.currentBankId); if (!bank) return;
      const rows = [["Category","Company","PIN Code","Min Salary","PF"]];
      bank.lines.forEach(l => { const comp=LA_DB.companies.find(c=>c.id===l.companyId); const cat=LA_DB.categories.find(c=>c.id===l.categoryId); rows.push([cat?.name||"",comp?.name||"",l.pinCode||"",cat?.salary||"",l.pf?"True":"False"]); });
      _laCsvDownload(rows, bank.name.replace(/\s+/g,"_")+"_lines.csv"); showToast("Lines exported ✓", "success");
    }

    // ════════════════════════════════════════════════════════
    //  COMPANIES — enhanced
    // ════════════════════════════════════════════════════════

    let _laCompSortField = "name", _laCompSortDir = "asc";

    function laCompSort(field) {
      if (_laCompSortField === field) _laCompSortDir = _laCompSortDir === "asc" ? "desc" : "asc";
      else { _laCompSortField = field; _laCompSortDir = "asc"; }
      ["name","compType","lines"].forEach(f => { const el = document.getElementById("la-csort-"+f); if (el) el.textContent = f===field?(_laCompSortDir==="asc"?" ↑":" ↓"):""; });
      laRenderCompanies();
    }

    function laRenderCompanies() {
      const tbody = document.getElementById("la-companies-body"); if (!tbody) return;
      const search = (document.getElementById("la-comp-search")?.value||"").toLowerCase();
      const lineCounts = {};
      LA_DB.banks.forEach(b => b.lines.forEach(l => { lineCounts[l.companyId] = (lineCounts[l.companyId]||0)+1; }));
      let companies = LA_DB.companies.map(c => ({...c, lineCount: lineCounts[c.id]||0}));
      if (search) companies = companies.filter(c => c.name.toLowerCase().includes(search) || (c.compType||"").toLowerCase().includes(search));
      companies.sort((a,b) => {
        let va = _laCompSortField==="lines" ? a.lineCount : (a[_laCompSortField]||"");
        let vb = _laCompSortField==="lines" ? b.lineCount : (b[_laCompSortField]||"");
        if (typeof va==="string") { va=va.toLowerCase(); vb=vb.toLowerCase(); }
        return _laCompSortDir==="asc" ? (va<vb?-1:va>vb?1:0) : (va>vb?-1:va<vb?1:0);
      });
      const ctOpts = Object.entries(LC_COMP_TYPES).map(([k,v])=>`<option value="${k}">${v}</option>`).join("");
      tbody.innerHTML = companies.map(c => {
        const empTags = (c.empTypes||[]).map(e=>`<span style="font-size:10px;padding:1px 6px;border-radius:4px;background:var(--surface2);color:var(--text3)">${e}</span>`).join("");
        return `<tr><td><input value="${c.name}" onblur="laUpdateCompany(${c.id},'name',this.value)" style="background:transparent;border:none;border-bottom:1px solid transparent;color:var(--text);font-family:inherit;font-size:13px;outline:none;width:100%;min-width:140px" onfocus="this.style.borderBottomColor='var(--accent)'"></td><td><select onchange="laUpdateCompany(${c.id},'compType',this.value)" style="background:transparent;border:none;border-bottom:1px solid transparent;color:var(--text2);font-size:12px;outline:none;cursor:pointer" onfocus="this.style.borderBottomColor='var(--accent)'"><option value="">—</option>${ctOpts.replace(`value="${c.compType||""}"`,`value="${c.compType||""}" selected`)}</select></td><td style="font-weight:600;color:var(--accent)">${c.lineCount}</td><td><div style="display:flex;gap:4px;flex-wrap:wrap">${empTags||"<span style=\"color:var(--text3);font-size:11px\">—</span>"}</div></td><td><button class="btn btn-danger btn-sm" onclick="laDeleteCompany(${c.id})" style="font-size:11px">✕</button></td></tr>`;
      }).join("") || `<tr><td colspan="5" style="text-align:center;padding:32px;color:var(--text3)">No companies</td></tr>`;
      const statsEl = document.getElementById("la-comp-stats");
      if (statsEl) statsEl.textContent = `${LA_DB.companies.length} companies · ${Object.values(lineCounts).reduce((s,v)=>s+v,0)} total lines`;
    }

    function laOpenAddCompanyModal() {
      const ctOpts = Object.entries(LC_COMP_TYPES).map(([k,v])=>`<option value="${k}">${v}</option>`).join("");
      const etChecks = LC_EMP_TYPES.map(e=>`<label style="display:flex;align-items:center;gap:7px;cursor:pointer;font-size:13px"><input type="checkbox" id="ac-et-${e.key}" style="width:14px;height:14px;accent-color:var(--accent)"> ${e.label}</label>`).join("");
      const ov = document.createElement("div");
      ov.style.cssText = "position:fixed;inset:0;background:rgba(12,23,51,.45);backdrop-filter:blur(4px);z-index:700;display:flex;align-items:center;justify-content:center";
      ov.innerHTML = `<div style="background:var(--surface);border-radius:16px;width:min(420px,92vw);box-shadow:var(--shadow-lg);padding:24px"><div style="font-family:var(--font-head);font-size:15px;font-weight:800;margin-bottom:18px">＋ Add Company</div><div class="form-group" style="margin-bottom:12px"><label>Company Name *</label><input type="text" id="ac-name" style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none"></div><div class="form-group" style="margin-bottom:14px"><label>Company Type</label><select id="ac-type" style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text)"><option value="">—</option>${ctOpts}</select></div><div style="font-size:12px;font-weight:600;color:var(--text3);text-transform:uppercase;letter-spacing:.7px;margin-bottom:8px">Employment Types</div><div style="display:flex;flex-direction:column;gap:6px;margin-bottom:20px">${etChecks}</div><div style="display:flex;gap:10px"><button class="btn btn-primary" style="flex:1" onclick="laConfirmAddCompany(this.closest('[style*=fixed]'))">Add</button><button class="btn btn-ghost" onclick="this.closest('[style*=fixed]').remove()">Cancel</button></div></div>`;
      document.body.appendChild(ov);
      setTimeout(() => ov.querySelector("#ac-name")?.focus(), 50);
    }

    function laConfirmAddCompany(ov) {
      const name = document.getElementById("ac-name")?.value.trim();
      if (!name) { showToast("Company name is required", "error"); return; }
      const empTypes = LC_EMP_TYPES.map(e=>e.key).filter(k=>document.getElementById("ac-et-"+k)?.checked);
      LA_DB.companies.push({ id: LA_DB.nextId.company++, name, compType: document.getElementById("ac-type")?.value||"", empTypes });
      ov.remove(); laRenderCompanies(); laPopulateCompanySelect(); laPopulateWizardCompanySelect();
      showToast(name + " added ✓", "success");
    }

    function laUpdateCompany(id, field, val) {
      const c = LA_DB.companies.find(x => x.id === id); if (!c) return;
      c[field] = val?.trim ? val.trim() : val;
      if (field === "name") { laPopulateCompanySelect(); laPopulateWizardCompanySelect(); }
      showToast("Saved ✓", "success");
    }

    function laDeleteCompany(id) {
      const c = LA_DB.companies.find(x => x.id === id); if (!c) return;
      const lc = LA_DB.banks.reduce((s,b)=>s+b.lines.filter(l=>l.companyId===id).length,0);
      if (!confirm(`Delete "${c.name}"?${lc>0?"\nOrphans "+lc+" line(s).":""}`)) return;
      LA_DB.companies = LA_DB.companies.filter(x => x.id !== id);
      laRenderCompanies(); laPopulateCompanySelect(); laPopulateWizardCompanySelect();
      showToast("Company removed", "info");
    }

    function laDeleteAllCompanies() {
      if (!confirm("Delete ALL " + LA_DB.companies.length + " companies?")) return;
      LA_DB.companies = [];
      laRenderCompanies(); laPopulateCompanySelect(); laPopulateWizardCompanySelect();
      showToast("All companies deleted", "info");
    }

    function laImportCompaniesCSV() {
      const ov = document.createElement("div");
      ov.style.cssText = "position:fixed;inset:0;background:rgba(12,23,51,.45);backdrop-filter:blur(4px);z-index:700;display:flex;align-items:center;justify-content:center";
      ov.innerHTML = `<div style="background:var(--surface);border-radius:16px;width:min(480px,96vw);box-shadow:var(--shadow-lg);padding:24px"><div style="font-family:var(--font-head);font-size:15px;font-weight:800;margin-bottom:8px">↑ Bulk Import Companies</div><div style="font-size:12px;color:var(--text3);margin-bottom:14px">Paste company names — one per line or comma-separated</div><textarea id="bulk-comp-input" rows="8" placeholder="Infosys Limited&#10;Wipro Technologies&#10;HDFC Ltd&#10;TCS, Accenture, IBM India" style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface2);color:var(--text);resize:vertical;outline:none;box-sizing:border-box;margin-bottom:14px"></textarea><div style="display:flex;gap:10px"><button class="btn btn-primary" style="flex:1" onclick="laConfirmBulkCompanies(this.closest('[style*=fixed]'))">Import</button><button class="btn btn-ghost" onclick="this.closest('[style*=fixed]').remove()">Cancel</button></div></div>`;
      document.body.appendChild(ov);
    }

    function laConfirmBulkCompanies(ov) {
      const names = (document.getElementById("bulk-comp-input")?.value||"").split(/[\n,]+/).map(n=>n.trim()).filter(n=>n.length>0);
      if (!names.length) { showToast("No names found", "error"); return; }
      let added = 0;
      names.forEach(name => { if (!LA_DB.companies.find(c=>c.name.toLowerCase()===name.toLowerCase())) { LA_DB.companies.push({ id:LA_DB.nextId.company++, name, compType:"", empTypes:["SALARIED"] }); added++; } });
      ov.remove(); laRenderCompanies(); laPopulateCompanySelect(); laPopulateWizardCompanySelect();
      showToast(added + " added (" + (names.length-added) + " duplicates skipped) ✓", "success");
    }

    function laExportCompanies() {
      const lc = {}; LA_DB.banks.forEach(b=>b.lines.forEach(l=>{lc[l.companyId]=(lc[l.companyId]||0)+1;}));
      const rows = [["Company","Type","Emp Types","Lines"]];
      LA_DB.companies.forEach(c=>rows.push([c.name,LC_COMP_TYPES[c.compType]||"",(c.empTypes||[]).join(";"),lc[c.id]||0]));
      _laCsvDownload(rows, "companies.csv"); showToast("Exported ✓", "success");
    }

    // ════════════════════════════════════════════════════════
    //  CATEGORIES — enhanced
    // ════════════════════════════════════════════════════════

    let _laCatSortField = "salary", _laCatSortDir = "asc";
    const LA_CAT_TIERS = [
      { label:"Platinum", color:"#7c3aed", bg:"rgba(139,92,246,.12)", min:40000 },
      { label:"Gold",     color:"#d97706", bg:"rgba(245,158,11,.12)", min:25000 },
      { label:"Silver",   color:"#64748b", bg:"rgba(100,116,139,.12)", min:15000 },
      { label:"Bronze",   color:"#92400e", bg:"rgba(180,83,9,.12)",    min:0     },
    ];
    function laCatTier(s) { return LA_CAT_TIERS.find(t=>s>=t.min)||LA_CAT_TIERS[LA_CAT_TIERS.length-1]; }

    // ── Populate the bank filter dropdown in the Categories panel ──
    function laPopulateCatBankFilter() {
      const sel = document.getElementById('la-cat-bank-filter'); if (!sel) return;
      const current = sel.value;
      sel.innerHTML = `<option value="">All Banks</option>
        <option value="__global__">Global (no specific bank)</option>` +
        LA_DB.banks.map(b => `<option value="${b.id}" ${current==b.id?'selected':''}>${b.name}</option>`).join('');
      if (current) sel.value = current;
    }

    function laCatSort(field) {
      if (_laCatSortField===field) _laCatSortDir=_laCatSortDir==="asc"?"desc":"asc";
      else { _laCatSortField=field; _laCatSortDir="asc"; }
      ["name","bank","salary","lines"].forEach(f=>{const el=document.getElementById("la-kssort-"+f);if(el)el.textContent=f===field?(_laCatSortDir==="asc"?" ↑":" ↓"):"";});
      laRenderCategories();
    }

    function laRenderCategories() {
      laPopulateCatBankFilter();
      const tbody = document.getElementById("la-categories-body"); if (!tbody) return;
      const bankFilterVal = document.getElementById('la-cat-bank-filter')?.value || '';

      // line count per category
      const lc = {}; LA_DB.banks.forEach(b=>b.lines.forEach(l=>{lc[l.categoryId]=(lc[l.categoryId]||0)+1;}));

      let cats = LA_DB.categories.map(c => {
        const bank = c.bankId ? LA_DB.banks.find(b => b.id === c.bankId) : null;
        return { ...c, lineCount: lc[c.id]||0, bankName: bank?.name || '' };
      });

      // Apply bank filter
      if (bankFilterVal === '__global__') {
        cats = cats.filter(c => !c.bankId);
      } else if (bankFilterVal) {
        cats = cats.filter(c => c.bankId === parseInt(bankFilterVal));
      }

      // Update label
      const lbl = document.getElementById('la-cat-filter-label');
      if (lbl) lbl.textContent = cats.length + ' categor' + (cats.length===1?'y':'ies') + ' shown';

      cats.sort((a,b)=>{
        let va, vb;
        if (_laCatSortField==="lines")     { va=a.lineCount; vb=b.lineCount; }
        else if (_laCatSortField==="bank") { va=a.bankName.toLowerCase(); vb=b.bankName.toLowerCase(); }
        else { va=a[_laCatSortField]||""; vb=b[_laCatSortField]||""; if(typeof va==="string"){va=va.toLowerCase();vb=vb.toLowerCase();} }
        return _laCatSortDir==="asc"?(va<vb?-1:va>vb?1:0):(va>vb?-1:va<vb?1:0);
      });

      // Bank dropdown options for inline editing
      const bankOptsGlobal = `<option value="">Global (all banks)</option>` +
        LA_DB.banks.map(b=>`<option value="${b.id}">${b.name}</option>`).join('');

      tbody.innerHTML = cats.map(c => {
        const tier = laCatTier(c.salary);
        const bankOpts = `<option value="" ${!c.bankId?'selected':''}>Global</option>` +
          LA_DB.banks.map(b=>`<option value="${b.id}" ${c.bankId===b.id?'selected':''}>${b.name}</option>`).join('');
        const bankBadge = c.bankId
          ? `<span style="font-size:10.5px;padding:2px 9px;border-radius:99px;background:rgba(26,79,163,.1);color:var(--accent);font-weight:600">${c.bankName}</span>`
          : `<span style="font-size:10.5px;padding:2px 9px;border-radius:99px;background:var(--surface2);color:var(--text3);font-weight:500">Global</span>`;
        return `<tr>
          <td>
            <input value="${c.name}" onblur="laUpdateCategory(${c.id},'name',this.value)"
              style="background:transparent;border:none;border-bottom:1px solid transparent;color:var(--text);font-family:inherit;font-size:13px;outline:none;width:100%;min-width:80px"
              onfocus="this.style.borderBottomColor='var(--accent)'" onblur="this.style.borderBottomColor='transparent';laUpdateCategory(${c.id},'name',this.value)">
          </td>
          <td>
            <div style="display:flex;align-items:center;gap:6px">
              <select onchange="laUpdateCategoryBank(${c.id},this.value)"
                style="padding:4px 8px;border:1.5px solid var(--border2);border-radius:7px;font-size:12px;background:var(--surface2);color:var(--text);cursor:pointer;outline:none;max-width:140px">
                ${bankOpts}
              </select>
              ${c.bankId ? `<button onclick="lcTab('banks-cfg');laOpenBankDetail(${c.bankId});setTimeout(()=>laDetailTab('categories',document.querySelector('.la-dtab:nth-child(4)')),400)"
                title="Open this bank's detail panel → Salary Categories"
                style="background:rgba(26,79,163,.08);border:1px solid rgba(26,79,163,.2);border-radius:6px;cursor:pointer;font-size:10.5px;color:var(--accent);padding:3px 7px;white-space:nowrap;font-weight:600">↗ Bank</button>` : ''}
            </div>
          </td>
          <td>
            <input type="number" value="${c.salary}" onblur="laUpdateCategory(${c.id},'salary',parseFloat(this.value)||0)"
              style="background:transparent;border:none;border-bottom:1px solid transparent;color:var(--danger);font-family:monospace;font-size:13px;font-weight:600;outline:none;width:110px"
              onfocus="this.style.borderBottomColor='var(--accent)'" onblur="this.style.borderBottomColor='transparent';laUpdateCategory(${c.id},'salary',parseFloat(this.value)||0)">
          </td>
          <td><span style="font-size:11px;padding:3px 10px;border-radius:99px;background:${tier.bg};color:${tier.color};font-weight:700">${tier.label}</span></td>
          <td style="font-weight:600;color:var(--accent)">${c.lineCount}</td>
          <td>
            <input value="${c.notes||""}" placeholder="Optional note…" onblur="laUpdateCategory(${c.id},'notes',this.value)"
              style="background:transparent;border:none;border-bottom:1px solid transparent;color:var(--text3);font-size:12px;outline:none;width:100%;min-width:80px"
              onfocus="this.style.borderBottomColor='var(--accent)'" onblur="this.style.borderBottomColor='transparent';laUpdateCategory(${c.id},'notes',this.value)">
          </td>
          <td><button class="btn btn-danger btn-sm" onclick="laDeleteCategory(${c.id})" style="font-size:11px">✕</button></td>
        </tr>`;
      }).join("")||`<tr><td colspan="7" style="text-align:center;padding:32px;color:var(--text3)">No categories${bankFilterVal?' for this bank':''} — click <strong>＋ Add Category</strong></td></tr>`;
    }

    function laUpdateCategoryBank(catId, bankIdVal) {
      const c = LA_DB.categories.find(x=>x.id===catId); if (!c) return;
      c.bankId = bankIdVal ? parseInt(bankIdVal) : null;
      const bank = bankIdVal ? LA_DB.banks.find(b=>b.id===parseInt(bankIdVal)) : null;
      showToast(`${c.name} → ${bank ? bank.name : 'Global'} ✓`, 'success');
    }

    function laOpenAddCategoryModal() {
      const bankOpts = `<option value="">Global (applies to all banks)</option>` +
        LA_DB.banks.map(b=>`<option value="${b.id}">${b.name}</option>`).join('');
      // Pre-select the bank filter if one is active
      const filterBankId = document.getElementById('la-cat-bank-filter')?.value || '';
      const ov = document.createElement("div");
      ov.style.cssText = "position:fixed;inset:0;background:rgba(12,23,51,.45);backdrop-filter:blur(4px);z-index:700;display:flex;align-items:center;justify-content:center";
      ov.innerHTML = `
        <div style="background:var(--surface);border-radius:16px;width:min(420px,94vw);box-shadow:var(--shadow-lg);padding:24px">
          <div style="font-family:var(--font-head);font-size:15px;font-weight:800;margin-bottom:4px">＋ Add Salary Category</div>
          <div style="font-size:12px;color:var(--text3);margin-bottom:18px">Categories set the minimum salary threshold and fee tier per bank</div>

          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Category Name *</label>
            <input type="text" id="acat-name" placeholder="e.g. Diamond, Platinum, Gold…"
              style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
          </div>

          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">
              Bank <span style="font-weight:400;color:var(--text3)">(leave blank for all banks)</span>
            </label>
            <select id="acat-bank"
              style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;cursor:pointer">
              ${bankOpts}
            </select>
          </div>

          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Minimum Salary (₹) *</label>
            <input type="number" id="acat-salary" placeholder="e.g. 50000"
              style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;font-family:monospace;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
          </div>

          <div class="form-group" style="margin-bottom:20px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Notes <span style="font-weight:400;color:var(--text3)">(optional)</span></label>
            <input type="text" id="acat-notes" placeholder="e.g. processing fee 1.5%, GST 18%…"
              style="width:100%;padding:10px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
          </div>

          <div id="acat-preview" style="display:none;font-size:12px;padding:8px 12px;background:var(--surface2);border-radius:8px;margin-bottom:16px;color:var(--text3)"></div>

          <div style="display:flex;gap:10px">
            <button class="btn btn-primary" style="flex:1" onclick="laConfirmAddCategory(this.closest('[style*=fixed]'))">Add Category</button>
            <button class="btn btn-ghost" onclick="this.closest('[style*=fixed]').remove()">Cancel</button>
          </div>
        </div>`;
      document.body.appendChild(ov);

      // Pre-select bank if filter is active
      if (filterBankId && filterBankId !== '__global__') {
        const sel = ov.querySelector('#acat-bank');
        if (sel) sel.value = filterBankId;
      }

      // Live preview
      const updatePreview = () => {
        const name   = ov.querySelector('#acat-name')?.value.trim();
        const salary = parseFloat(ov.querySelector('#acat-salary')?.value)||0;
        const bankId = parseInt(ov.querySelector('#acat-bank')?.value)||null;
        const bank   = bankId ? LA_DB.banks.find(b=>b.id===bankId) : null;
        const prev   = ov.querySelector('#acat-preview');
        if (name && salary) {
          const tier = laCatTier(salary);
          prev.style.display = '';
          prev.innerHTML = `<span style="font-size:11.5px;font-weight:600;color:var(--text2)">Preview: </span>
            <span style="font-size:11px;padding:2px 9px;border-radius:99px;background:${tier.bg};color:${tier.color};font-weight:700">${tier.label}</span>
            &nbsp;<strong>${name}</strong> · ₹${salary.toLocaleString('en-IN')} min salary
            ${bank ? `· <span style="color:var(--accent)">${bank.name}</span>` : `· <span style="color:var(--text3)">All banks</span>`}`;
        } else { prev.style.display = 'none'; }
      };
      ov.querySelector('#acat-name').addEventListener('input', updatePreview);
      ov.querySelector('#acat-salary').addEventListener('input', updatePreview);
      ov.querySelector('#acat-bank').addEventListener('change', updatePreview);
      setTimeout(() => ov.querySelector("#acat-name")?.focus(), 50);
    }

    function laConfirmAddCategory(ov) {
      const name   = document.getElementById("acat-name")?.value.trim();
      const salary = parseFloat(document.getElementById("acat-salary")?.value)||0;
      const notes  = document.getElementById("acat-notes")?.value.trim()||"";
      const bankId = parseInt(document.getElementById("acat-bank")?.value)||null;
      if (!name)   { showToast("Category name required", "error"); return; }
      if (!salary) { showToast("Minimum salary required", "error"); return; }
      LA_DB.categories.push({ id:LA_DB.nextId.category++, name, salary, notes, bankId });
      ov.remove();
      laRenderCategories();
      const bank = bankId ? LA_DB.banks.find(b=>b.id===bankId) : null;
      showToast(`${name} added${bank?' for '+bank.name:' (global)'} ✓`, "success");
    }

    function laUpdateCategory(id, field, val) {
      const c = LA_DB.categories.find(x=>x.id===id); if (!c) return;
      c[field] = field==="salary" ? (parseFloat(val)||0) : val;
      if (field === 'salary') laRenderCategories(); // re-render tier badge
      showToast("Saved ✓", "success");
    }

    function laDeleteCategory(id) {
      const c = LA_DB.categories.find(x=>x.id===id); if (!c) return;
      const lc = LA_DB.banks.reduce((s,b)=>s+b.lines.filter(l=>l.categoryId===id).length,0);
      if (!confirm(`Delete "${c.name}"?${lc>0?"\nThis will orphan "+lc+" line(s).":""}`)) return;
      LA_DB.categories = LA_DB.categories.filter(x=>x.id!==id);
      laRenderCategories(); showToast("Category removed", "info");
    }

    function laExportCategories() {
      const lc = {}; LA_DB.banks.forEach(b=>b.lines.forEach(l=>{lc[l.categoryId]=(lc[l.categoryId]||0)+1;}));
      const rows = [["Category","Bank","Min Salary","Tier","Lines Used","Notes"]];
      LA_DB.categories.forEach(c=>{
        const bank = c.bankId ? LA_DB.banks.find(b=>b.id===c.bankId) : null;
        rows.push([c.name, bank?.name||'Global', c.salary, laCatTier(c.salary).label, lc[c.id]||0, c.notes||""]);
      });
      _laCsvDownload(rows, "categories.csv"); showToast("Exported ✓", "success");
    }

    // ════════════════════════════════════════════════════════
    //  IMPORT LINES — enhanced
    // ════════════════════════════════════════════════════════

    let _laImportRows = [];

    function laPopulateImportBanks() {
      ["la-import-bank","la-export-bank"].forEach(id => {
        const sel = document.getElementById(id); if (!sel) return;
        const cur = sel.value;
        sel.innerHTML = (id==="la-export-bank"?"<option value=''>— All Banks —</option>":"<option value=''>— Select Bank —</option>") +
          LA_DB.banks.map(b=>`<option value="${b.id}" ${b.id==cur?"selected":""}>${b.name}</option>`).join("");
      });
    }

    function laHandleFileSelect(e) {
      const f = e.target.files[0];
      if (f) { LA_DB.importFile=f; const el=document.getElementById("la-file-chosen"); if(el)el.textContent="📄 "+f.name; }
      _laImportRows=[]; const pv=document.getElementById("la-import-preview"); if(pv)pv.style.display="none";
    }

    function laHandleDrop(e) {
      e.preventDefault(); e.currentTarget.style.borderColor=""; e.currentTarget.style.background="var(--surface2)";
      const f=e.dataTransfer.files[0];
      if(f){LA_DB.importFile=f;const el=document.getElementById("la-file-chosen");if(el)el.textContent="📄 "+f.name;}
      _laImportRows=[]; const pv=document.getElementById("la-import-preview");if(pv)pv.style.display="none";
    }

    function laPreviewImport() {
      const bankId=parseInt(document.getElementById("la-import-bank")?.value);
      if(!bankId){showToast("Select a bank first","error");return;}
      if(!LA_DB.importFile){showToast("Upload a file first","error");return;}
      const createMissing=document.getElementById("la-import-create-missing")?.checked;
      const updateExisting=document.getElementById("la-import-update")?.checked;
      const bank=LA_DB.banks.find(b=>b.id===bankId);
      const sampleRows=[
        {cat:"Gold",comp:"ABC Corporation",pin:"400001",pf:true},
        {cat:"Silver",comp:"XYZ Limited",pin:"400002",pf:false},
        {cat:"Platinum",comp:"LMN Industries",pin:"400003",pf:true},
        {cat:"Gold",comp:"New Company Ltd",pin:"400004",pf:false},
        {cat:"Diamond",comp:"ABC Corporation",pin:"400001",pf:true},
      ];
      _laImportRows=sampleRows.map(r=>{
        const catR=LA_DB.categories.find(c=>c.name.toLowerCase()===r.cat.toLowerCase());
        const compR=LA_DB.companies.find(c=>c.name.toLowerCase()===r.comp.toLowerCase());
        let status="ok";
        if(!catR&&!createMissing) status="missing_cat";
        else if(!compR&&!createMissing) status="missing_comp";
        else if(bank&&catR&&compR&&bank.lines.find(l=>l.companyId===compR.id&&l.categoryId===catR.id)) status=updateExisting?"update":"skip";
        else if(!catR||!compR) status="will_create";
        return {...r,catR,compR,status};
      });
      const badge=s=>({ok:'<span style="color:var(--success);font-weight:700;font-size:10.5px">✓ New</span>',update:'<span style="color:var(--accent);font-weight:700;font-size:10.5px">↻ Update</span>',skip:'<span style="color:var(--text3);font-size:10.5px">⊘ Skip</span>',missing_cat:'<span style="color:var(--danger);font-weight:700;font-size:10.5px">✕ Unknown Cat</span>',missing_comp:'<span style="color:var(--danger);font-weight:700;font-size:10.5px">✕ Unknown Comp</span>',will_create:'<span style="color:var(--warn);font-weight:700;font-size:10.5px">＋ Will Create</span>'})[s]||s;
      const tbody=document.getElementById("la-preview-tbody"); if(!tbody)return;
      tbody.innerHTML=_laImportRows.map((r,i)=>`<tr><td style="color:var(--text3)">${i+1}</td><td>${r.cat}</td><td>${r.comp}</td><td style="font-family:monospace">${r.pin||"—"}</td><td>${r.pf?"Yes":"No"}</td><td>${badge(r.status)}</td></tr>`).join("");
      const cnt=document.getElementById("la-preview-count"); if(cnt)cnt.textContent="("+_laImportRows.length+" rows)";
      const pv=document.getElementById("la-import-preview"); if(pv)pv.style.display="";
    }

    function laFinishImport(bankId,resDiv,progDiv) {
      const bank=LA_DB.banks.find(b=>b.id===bankId);
      const updateExisting=document.getElementById("la-import-update")?.checked||false;
      const createMissing=document.getElementById("la-import-create-missing")?.checked||false;
      let created=0,updated=0,skipped=0,errors=0;
      const rows=_laImportRows.length?_laImportRows:[
        {cat:"Gold",comp:"ABC Corporation",pin:"400001",pf:true,status:"ok"},
        {cat:"Silver",comp:"XYZ Limited",pin:"400002",pf:false,status:"ok"},
      ];
      for(const r of rows){
        if(r.status==="missing_cat"||r.status==="missing_comp"){errors++;continue;}
        let catR=LA_DB.categories.find(c=>c.name.toLowerCase()===r.cat.toLowerCase());
        let compR=LA_DB.companies.find(c=>c.name.toLowerCase()===r.comp.toLowerCase());
        if(!catR&&createMissing){catR={id:LA_DB.nextId.category++,name:r.cat,salary:20000};LA_DB.categories.push(catR);}
        if(!compR&&createMissing){compR={id:LA_DB.nextId.company++,name:r.comp,compType:"",empTypes:["SALARIED"]};LA_DB.companies.push(compR);}
        if(!catR||!compR){errors++;continue;}
        const exists=bank.lines.find(l=>l.companyId===compR.id&&l.categoryId===catR.id);
        if(exists){if(updateExisting){exists.pinCode=r.pin;exists.pf=!!r.pf;updated++;}else skipped++;}
        else{bank.lines.push({id:LA_DB.nextId.line++,companyId:compR.id,categoryId:catR.id,pinCode:r.pin||"",pf:!!r.pf});created++;}
      }
      if(progDiv)progDiv.style.display="none";
      const histEl=document.getElementById("la-import-history");
      const ts=new Date().toLocaleString("en-IN",{day:"2-digit",month:"short",hour:"2-digit",minute:"2-digit"});
      if(histEl){
        const entry=document.createElement("div");
        entry.style.cssText="padding:6px 0;border-bottom:1px solid var(--border);font-size:12px";
        entry.innerHTML=`<span style="color:var(--text2);font-weight:600">${bank.name}</span> <span style="color:var(--text3);margin-left:6px">${ts}</span><br><span style="color:var(--success)">+${created}</span> · <span style="color:var(--accent)">↻${updated}</span> · <span style="color:var(--text3)">⊘${skipped}</span>${errors?` · <span style="color:var(--danger)">✕${errors}</span>`:""}`;
        if(histEl.textContent==="No imports yet.")histEl.innerHTML="";
        histEl.insertBefore(entry,histEl.firstChild);
      }
      if(resDiv){resDiv.style.display="block";resDiv.innerHTML=`<div style="padding:12px 16px;border-radius:8px;font-size:13px;background:rgba(26,115,64,.06);border:1px solid rgba(26,115,64,.2);color:var(--success)"><strong>✓ ${bank.name}</strong><br>+${created} created · ↻${updated} updated · ⊘${skipped} skipped${errors?" · ✕"+errors+" errors":""}</div>`;}
      laRenderBanks(); laPopulateCompanySelect(); laPopulateWizardCompanySelect();
      showToast("Import complete ✓","success");
    }

    function laExportLines() {
      const bankId=document.getElementById("la-export-bank")?.value;
      const banks=bankId?LA_DB.banks.filter(b=>b.id==bankId):LA_DB.banks;
      const rows=[["Bank","Category","Company","PIN Code","Min Salary","PF"]];
      banks.forEach(b=>b.lines.forEach(l=>{const comp=LA_DB.companies.find(c=>c.id===l.companyId);const cat=LA_DB.categories.find(c=>c.id===l.categoryId);rows.push([b.name,cat?.name||"",comp?.name||"",l.pinCode||"",cat?.salary||"",l.pf?"True":"False"]);}));
      _laCsvDownload(rows,"company_lines_export.csv");showToast("Exported "+(rows.length-1)+" lines ✓","success");
    }

    function laDownloadTemplate() {
      _laCsvDownload([["Category","Company","PIN Code","PF"],["Gold","ABC Corporation","400001","True"],["Silver","XYZ Limited","400002","False"],["Platinum","LMN Industries","400003","Yes"]],"Company_Lines_Import_Template.csv");
      showToast("Template downloaded","info");
    }

    function _laCsvDownload(rows, filename) {
      const csv=rows.map(r=>r.map(x=>'"'+String(x??'').replace(/"/g,'""')+'"').join(",")).join("\n");
      const a=document.createElement("a");a.href=URL.createObjectURL(new Blob([csv],{type:"text/csv"}));a.download=filename;a.click();
    }

    // ── END LOAN ANALYTIC SYSTEM ──


    // ══════════════════════════════════════════════════════════
    //  ANALYTIC COMPANY DROPDOWN + CUSTOM COMPANY TOGGLE
    //  mirrors new_loan.py Application.company_name_id + is_custom_company_name
    // ══════════════════════════════════════════════════════════
    function laPopulateWizardCompanySelect() {
      // Refresh WSDD items from latest LA_DB companies
      if (typeof wsddSetItems === 'function') {
        wsddSetItems('wsdd-company-name', _buildCompanyItems());
      }
      // Re-apply previously selected value if any
      const hidVal = document.getElementById('w-company-name-id')?.value;
      if (hidVal && typeof wsddSetValue === 'function') {
        wsddSetValue('wsdd-company-name', hidVal);
      }
    }

    function toggleCustomCompany() {
      const isCustom = document.getElementById('w-is-custom-company')?.checked;
      const wsddWrap = document.getElementById('wsdd-company-name');
      const txtInput = document.getElementById('w-compname');
      if (wsddWrap) wsddWrap.style.display = isCustom ? 'none'  : '';
      if (txtInput) txtInput.style.display  = isCustom ? 'block' : 'none';
      // Clear the WSDD selection when switching to manual
      if (isCustom && typeof wsddClear === 'function') wsddClear('wsdd-company-name');
      laAutoDetectFromWizard();
    }

    // Auto-detect company + salary → trigger eligibility check and update InCred flag
    // mirrors loan_application_inherit.py action_create_eligiblity + new_loan.py _compute_bank
    function laAutoDetectFromWizard() {
      const isCustom    = document.getElementById('w-is-custom-company')?.checked || false;
      const companyId   = isCustom ? 0 : (parseInt(document.getElementById('w-company-name-id')?.value) || 0);
      const salaryEl    = document.getElementById('la-elig-salary');
      const salaryWizEl = document.getElementById('w-salary');
      const wizSalary   = parseFloat(salaryWizEl?.value) || 0;

      // Mirror salary into the Eligibility tab
      if (salaryEl && wizSalary) salaryEl.value = wizSalary;

      // Mirror salary + name into the CAM tab
      const camSalEl = document.getElementById('cam-salary');
      if (camSalEl && wizSalary) camSalEl.value = wizSalary;
      const fname = document.getElementById('w-fname')?.value || '';
      const lname = document.getElementById('w-lname')?.value || '';
      const camNameEl = document.getElementById('cam-name');
      if (camNameEl && (fname || lname)) camNameEl.value = [fname, lname].filter(Boolean).join(' ').toUpperCase();

      // Mirror company into the Eligibility tab
      const eligCompEl = document.getElementById('la-elig-company');
      if (eligCompEl && companyId) eligCompEl.value = companyId;

      // Compute is_incred_bank: any selected bank with isIncred=true
      const selectedBanks = (LA_DB.wizardSelectedBanks || []).map(id => LA_DB.banks.find(b => b.id === id)).filter(Boolean);
      const hasIncred = selectedBanks.some(b => b.isIncred);
      const rmEmailGroup = null; // w-rm-email-group removed
      if (rmEmailGroup) rmEmailGroup.style.display = hasIncred ? '' : 'none';

      // Reload eligibility — always, so empty state shows if data is missing
      laLoadEligibility();
    }

    // Called when a bank card is toggled — recheck InCred flag
    const _origToggleCard = laToggleCard;
    laToggleCard = function(bankId, loanType) {
      _origToggleCard(bankId, loanType);
      laAutoDetectFromWizard();
    };

    // ══════════════════════════════════════════════════════════
    //  BANK ELIGIBILITY SECTION ON APP DETAIL
    //  mirrors loan_app_inherit_view.xml custom_collapsible_section_1
    // ══════════════════════════════════════════════════════════
    let _bankEligOpen = true;

    function toggleBankEligSection() {
      _bankEligOpen = !_bankEligOpen;
      const content = document.getElementById('bank-elig-section-content');
      const icon    = document.getElementById('bank-elig-toggle-icon');
      if (content) content.style.display = _bankEligOpen ? '' : 'none';
      if (icon)    icon.textContent = _bankEligOpen ? '▾' : '▸';
    }

    function renderDetailBankEligibility(app) {
      const section  = document.getElementById('detail-bank-eligibility-section');
      const container= document.getElementById('detail-last-eligible-banks');
      const btn      = document.getElementById('detail-check-elig-btn');
      if (!section) return;

      // Hide entirely for partner role; show for all others
      if (currentUser.role === 'partner') {
        section.style.display = 'none';
        return;
      }
      section.style.display = '';

      // Disable Check Eligibility button for roles that can't create eligibility
      const rd = ROLES[currentUser.role];
      if (btn) btn.style.display = (rd.canCreateApp || currentUser.role === 'admin') ? '' : 'none';

      if (!container) return;
      const banks = app.lastEligibleBanks || [];
      if (!banks.length) {
        container.innerHTML = '<div style="color:var(--text3);font-size:13px;padding:8px 0">No banks selected yet. Click "Check Eligibility" to run the wizard.</div>';
        return;
      }

      // Show bank chips — mirrors last.eligible showing bank logos/names
      container.innerHTML = banks.map(b => `
        <div style="display:flex;align-items:center;gap:8px;background:${b.isIncred?'rgba(245,158,11,.1)':'rgba(26,79,163,.08)'};border:1.5px solid ${b.isIncred?'rgba(245,158,11,.3)':'rgba(26,79,163,.2)'};border-radius:10px;padding:10px 14px;min-width:110px">
          <div style="width:36px;height:36px;border-radius:8px;background:${b.isIncred?'rgba(245,158,11,.2)':'rgba(26,79,163,.15)'};display:flex;align-items:center;justify-content:center;font-weight:800;font-size:14px;color:${b.isIncred?'#f59e0b':'var(--accent)'}">
            ${(b.bankName||'B')[0]}
          </div>
          <div>
            <div style="font-size:12.5px;font-weight:700;color:var(--text)">${b.bankName}</div>
            ${b.isIncred?'<div style="font-size:10px;color:#f59e0b;font-weight:600">InCred</div>':''}
            ${b.isElite?'<div style="font-size:10px;color:var(--danger);font-weight:600">Mudrahub</div>':''}
          </div>
        </div>`).join('');
    }

    // ══════════════════════════════════════════════════════════
    //  ELIGIBILITY WIZARD (modal)
    //  mirrors eligible_wizard.py + loan_application_inherit.py action_create_eligiblity
    //  max 2 banks, save to app.lastEligibleBanks
    // ══════════════════════════════════════════════════════════
    let _ewSelectedBanks = [];   // { bankId, bankName, isIncred, isElite, minSalary, pinCode }

    function openDetailEligibilityWizard() {
      if (!currentDetail) return;
      const app = currentDetail;

      // Pre-populate company dropdown — include ALL companies + app's own company name if not in list
      const compSel = document.getElementById('ew-company');
      if (compSel) {
        // Try to match app.compName against LA_DB.companies
        let matchedId = app.companyNameId || null;
        if (!matchedId && app.compName) {
          const found = LA_DB.companies.find(c => c.name.toLowerCase() === (app.compName||'').toLowerCase());
          if (found) matchedId = found.id;
        }
        compSel.innerHTML = '<option value="">— Select company —</option>' +
          LA_DB.companies.map(c => `<option value="${c.id}" ${c.id===matchedId?'selected':''}>${c.name}</option>`).join('');
      }

      // Pre-populate salary
      const salEl = document.getElementById('ew-salary');
      if (salEl) salEl.value = app.salary || '';

      // Restore previously selected banks
      _ewSelectedBanks = (app.lastEligibleBanks || []).map(b => ({...b}));

      // ── Applicant snapshot bar ──
      const bar = document.getElementById('ew-applicant-bar');
      if (bar) {
        const pill = (icon, label, val, color) =>
          `<div style="display:flex;align-items:center;gap:6px;background:var(--surface2);border:1px solid var(--border);border-radius:8px;padding:6px 11px">
            <span style="font-size:14px">${icon}</span>
            <div>
              <div style="font-size:9.5px;color:var(--text3);font-weight:600;text-transform:uppercase;letter-spacing:.4px">${label}</div>
              <div style="font-size:12.5px;font-weight:700;color:${color||'var(--text)'}">${val}</div>
            </div>
          </div>`;
        const cibilColor = app.cibil >= 750 ? '#15803d' : app.cibil >= 700 ? '#b45309' : '#dc2626';
        bar.style.display = 'flex';
        bar.innerHTML =
          pill('👤', 'Applicant', app.name || '—', 'var(--accent)') +
          pill('🏢', 'Company', app.compName || '—') +
          pill('💰', 'Salary', app.salary ? '₹'+Number(app.salary).toLocaleString('en-IN')+'/mo' : '—') +
          pill('📊', 'CIBIL Score', app.cibil || '—', cibilColor) +
          pill('🏦', 'Loan Type', (app.loanType||'').replace(/_/g,' ').replace(/\b\w/g,l=>l.toUpperCase()) || '—') +
          (app.amount ? pill('💵', 'Loan Amt', '₹'+Number(app.amount).toLocaleString('en-IN')) : '');
      }

      const overlay = document.getElementById('elig-wizard-overlay');
      if (overlay) overlay.style.display = 'flex';

      ewLoadBanks();
    }

    function closeEligWizard() {
      const overlay = document.getElementById('elig-wizard-overlay');
      if (overlay) overlay.style.display = 'none';
    }

    function ewLoadBanks() {
      const companyId = parseInt(document.getElementById('ew-company')?.value) || 0;
      const salary    = parseFloat(document.getElementById('ew-salary')?.value)  || 0;
      const alertDiv  = document.getElementById('ew-alert');
      const result    = document.getElementById('ew-banks-result');
      const empty     = document.getElementById('ew-empty');
      const subEl     = document.getElementById('ew-banks-sub');
      const cibilNote = document.getElementById('ew-cibil-note');

      // Salary is the only hard prerequisite. Company is an optional, per-bank
      // filter (see business rule) — evaluated inside the loop below, not here.
      if (!salary) {
        if (alertDiv) { alertDiv.style.display='block'; alertDiv.textContent='ℹ️  Please enter the net monthly salary to check eligible banks.'; }
        if (result)   result.style.display='none';
        if (empty)    empty.style.display='none';
        ewUpdateSummary();
        return;
      }
      if (alertDiv) alertDiv.style.display='none';

      const app       = currentDetail || {};
      const appCibil  = app.cibil || 0;
      const appAge    = app.dob ? Math.floor((Date.now() - new Date(app.dob)) / 31557600000) : 0;
      const appEmp    = app.empType || '';
      const appExp    = app.workExpMonths || 0;
      // PIN: use office address pin if available, else residential zip
      const officePin = app.officeAddrPin || '';

      const eligible  = [];
      const ineligible = [];

      for (const bank of LA_DB.banks) {
        // ── Bank-level rules check (if rules exist) ──
        const rules = bank.rules || {};
        const failReasons = [];
        if (rules.minCibil  && appCibil  && appCibil  < rules.minCibil)  failReasons.push(`CIBIL ${appCibil} < ${rules.minCibil} required`);
        if (rules.minAge    && appAge    && appAge    < rules.minAge)    failReasons.push(`Age ${appAge} < ${rules.minAge} min`);
        if (rules.maxAge    && appAge    && appAge    > rules.maxAge)    failReasons.push(`Age ${appAge} > ${rules.maxAge} max`);
        if (rules.empTypes  && appEmp    && !rules.empTypes.includes(appEmp)) failReasons.push(`${appEmp} not accepted`);
        if (rules.minExpMonths && appExp && appExp < rules.minExpMonths)  failReasons.push(`Exp ${appExp}mo < ${rules.minExpMonths}mo`);

        // ── Line-level check: company + salary category ──
        // PATH A — bank HAS a configured company list: applicant's company must
        //   match one of the configured lines (business rule 2).
        // PATH B — bank has NO company list at all: company is not evaluated;
        //   eligibility is decided purely on salary/category + the bank-level
        //   rules already checked above (business rule 3). Previously this case
        //   fell through with an empty `bank.lines` loop and was silently
        //   dropped from BOTH the eligible and ineligible lists — a bank with no
        //   company configured could never appear here no matter how well the
        //   applicant matched every other condition.
        const bankHasCompanyList = bank.lines && bank.lines.length > 0;
        let bestLine = null;

        if (bankHasCompanyList) {
          for (const line of bank.lines) {
            if (line.companyId !== companyId) continue;
            const cat = LA_DB.categories.find(c => c.id === line.categoryId);
            if (!cat || cat.salary > salary) continue;
            // PIN: only filter if BOTH app and line have a pin AND they don't match
            if (line.pinCode && officePin && line.pinCode !== officePin) continue;
            bestLine = { line, cat };
            break;
          }
          if (!bestLine) {
            const hasCompany = companyId && bank.lines.some(l => l.companyId === companyId);
            if (hasCompany) ineligible.push({ bank, reason: 'Salary below minimum for this company' });
            else ineligible.push({ bank, reason: companyId ? 'Company not in this bank\u2019s approved list' : 'This lender requires an approved company' });
            continue;
          }
        } else {
          // PATH B — no company configured for this bank: match on the best
          // global salary category only, and bank-level serviceable PINs
          // (mirrors the Step 9 wizard's Path B).
          let bestCat = null;
          for (const cat of LA_DB.categories) {
            if (cat.salary <= salary && (!bestCat || cat.salary > bestCat.salary)) bestCat = cat;
          }
          if (!bestCat) { ineligible.push({ bank, reason: `Salary below all category thresholds` }); continue; }
          const bankPins = bank.serviceablePins;
          if (bankPins && bankPins.length > 0 && officePin && !bankPins.includes(officePin)) {
            ineligible.push({ bank, reason: `PIN ${officePin} not serviceable` });
            continue;
          }
          bestLine = { line: null, cat: bestCat };
        }

        if (failReasons.length) {
          ineligible.push({ bank, reason: failReasons.join(' · ') });
          continue;
        }

        if (!eligible.find(e => e.bankId === bank.id)) {
          eligible.push({
            bankId: bank.id, bankName: bank.name,
            isIncred: bank.isIncred, isElite: bank.isElite,
            minSalary: bestLine.cat.salary, categoryName: bestLine.cat.name,
            pinCode: bestLine.line ? bestLine.line.pinCode : '', pf: bestLine.line ? bestLine.line.pf : false,
            rules: bank.rules || {},
          });
        }
      }

      // ── CIBIL hint ──
      if (cibilNote) {
        if (appCibil) {
          const cColor = appCibil >= 750 ? '#15803d' : appCibil >= 700 ? '#b45309' : '#dc2626';
          cibilNote.innerHTML = `<span style="color:${cColor};font-weight:700">CIBIL ${appCibil}</span> · ${appCibil>=750?'Excellent — all banks eligible':appCibil>=700?'Good — most banks eligible':'Low — limited options'}`;
        } else {
          cibilNote.textContent = '';
        }
      }

      if (!eligible.length) {
        if (result) result.style.display='none';
        if (empty)  {
          empty.style.display='block';
          const reasonEl = document.getElementById('ew-empty-reason');
          if (reasonEl) {
            if (ineligible.length) {
              reasonEl.innerHTML = `<strong>${ineligible.length} bank(s)</strong> found but not eligible:<br>` +
                ineligible.slice(0,3).map(x => `<span style="color:var(--danger)">✗</span> ${x.bank.name}: ${x.reason}`).join('<br>');
            } else {
              reasonEl.textContent = 'No eligible banks found for these details. Try a different company/salary or update Lender Config.';
            }
          }
        }
        ewUpdateSummary();
        return;
      }

      if (empty)  empty.style.display='none';
      if (result) result.style.display='block';
      if (subEl)  subEl.textContent = `${eligible.length} eligible bank${eligible.length>1?'s':''} found — select up to 2`;

      document.getElementById('ew-bank-cards').innerHTML = eligible.map(e => {
        const isSel      = _ewSelectedBanks.some(b => b.bankId === e.bankId);
        const maxLoan    = e.rules.maxLoanAmt ? '₹'+Number(e.rules.maxLoanAmt).toLocaleString('en-IN') : null;
        const foirPct    = e.rules.foirLimit ? e.rules.foirLimit+'% FOIR' : null;
        const minCibil   = e.rules.minCibil  ? 'CIBIL '+e.rules.minCibil : null;
        const tenureInfo = (e.rules.minTenure && e.rules.maxTenure) ? `${e.rules.minTenure}–${e.rules.maxTenure} mo` : null;
        const tagColor   = e.isIncred ? '#f59e0b' : e.isElite ? 'var(--accent2)' : 'var(--accent)';
        const tagBg      = e.isIncred ? 'rgba(245,158,11,.12)' : e.isElite ? 'rgba(212,43,43,.08)' : 'rgba(26,79,163,.08)';
        const tag        = e.isIncred ? 'InCred' : e.isElite ? 'Mudrahub' : '';

        return `<div id="ewcard-${e.bankId}" onclick="ewToggleCard(${e.bankId},${JSON.stringify(e).replace(/"/g,'&quot;')})"
          style="background:${isSel?'rgba(26,79,163,.07)':'var(--surface2)'};border:2px solid ${isSel?'var(--accent)':'var(--border2)'};border-radius:14px;padding:16px 14px;cursor:pointer;transition:all .18s;position:relative">

          <!-- Bank avatar + name -->
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
            <div style="width:44px;height:44px;border-radius:12px;background:${e.isIncred?'rgba(245,158,11,.15)':'rgba(26,79,163,.1)'};display:flex;align-items:center;justify-content:center;font-weight:800;font-size:1.1rem;color:${tagColor};flex-shrink:0">
              ${e.bankName[0]}
            </div>
            <div style="flex:1;min-width:0">
              <div style="font-size:13px;font-weight:800;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${e.bankName}</div>
              ${tag ? `<span style="font-size:9.5px;font-weight:700;background:${tagBg};color:${tagColor};padding:2px 7px;border-radius:20px">${tag}</span>` : ''}
            </div>
          </div>

          <!-- Key metrics -->
          <div style="display:flex;flex-direction:column;gap:5px;margin-bottom:12px">
            <div style="display:flex;justify-content:space-between;font-size:11px">
              <span style="color:var(--text3)">Category</span>
              <span style="font-weight:600;color:var(--text)">${e.categoryName}</span>
            </div>
            <div style="display:flex;justify-content:space-between;font-size:11px">
              <span style="color:var(--text3)">Min Salary</span>
              <span style="font-weight:600;color:#15803d">₹${e.minSalary.toLocaleString('en-IN')}/mo</span>
            </div>
            ${maxLoan ? `<div style="display:flex;justify-content:space-between;font-size:11px"><span style="color:var(--text3)">Max Loan</span><span style="font-weight:600;color:var(--accent)">${maxLoan}</span></div>` : ''}
            ${tenureInfo ? `<div style="display:flex;justify-content:space-between;font-size:11px"><span style="color:var(--text3)">Tenure</span><span style="font-weight:600;color:var(--text)">${tenureInfo}</span></div>` : ''}
            ${minCibil ? `<div style="display:flex;justify-content:space-between;font-size:11px"><span style="color:var(--text3)">Min CIBIL</span><span style="font-weight:600;color:${appCibil&&appCibil>=e.rules.minCibil?'#15803d':'var(--text)'}">${e.rules.minCibil}</span></div>` : ''}
            ${foirPct ? `<div style="display:flex;justify-content:space-between;font-size:11px"><span style="color:var(--text3)">FOIR Limit</span><span style="font-weight:600;color:var(--text)">${foirPct}</span></div>` : ''}
          </div>

          <!-- PF badge -->
          ${e.pf ? `<div style="font-size:9.5px;background:rgba(26,79,163,.08);color:var(--accent);padding:2px 8px;border-radius:20px;display:inline-block;margin-bottom:10px;font-weight:600">✓ PF Required</div>` : ''}

          <!-- Select indicator -->
          <div style="display:flex;align-items:center;justify-content:center;gap:6px;padding:7px;border-radius:8px;background:${isSel?'var(--accent)':'transparent'};border:1.5px solid ${isSel?'var(--accent)':'var(--border2)'};transition:all .18s">
            <div id="ewcheck-${e.bankId}" style="font-size:12px;font-weight:700;color:${isSel?'#fff':'var(--text3)'}">${isSel?'✓ Selected':'+ Select'}</div>
          </div>
        </div>`;
      }).join('');

      ewUpdateSummary();
    }

    function ewToggleCard(bankId, bankData) {
      const already = _ewSelectedBanks.findIndex(b => b.bankId === bankId);
      const card    = document.getElementById('ewcard-' + bankId);
      const check   = document.getElementById('ewcheck-' + bankId);

      if (already >= 0) {
        _ewSelectedBanks.splice(already, 1);
        if (card)  { card.style.borderColor='var(--border2)'; card.style.background='var(--surface2)'; }
        if (check) { check.textContent='+ Select'; check.style.color='var(--text3)'; check.parentElement.style.background='transparent'; check.parentElement.style.borderColor='var(--border2)'; }
      } else {
        if (_ewSelectedBanks.length >= 2) {
          showToast('Maximum 2 banks allowed — deselect one first', 'error');
          return;
        }
        _ewSelectedBanks.push(bankData);
        if (card)  { card.style.borderColor='var(--accent)'; card.style.background='rgba(26,79,163,.07)'; }
        if (check) { check.textContent='✓ Selected'; check.style.color='#fff'; check.parentElement.style.background='var(--accent)'; check.parentElement.style.borderColor='var(--accent)'; }
      }
      ewUpdateSummary();
    }

    function ewUpdateSummary() {
      const sumDiv  = document.getElementById('ew-selected-summary');
      const sumList = document.getElementById('ew-selected-list');
      const sub     = document.getElementById('ew-subtitle');
      if (!sumDiv || !sumList) return;
      if (sub) {
        sub.textContent = `${_ewSelectedBanks.length}/2 selected`;
        sub.style.color = _ewSelectedBanks.length === 2 ? '#15803d' : _ewSelectedBanks.length === 1 ? '#b45309' : 'var(--text3)';
      }
      if (!_ewSelectedBanks.length) { sumDiv.style.display='none'; return; }
      sumDiv.style.display='block';
      sumList.innerHTML = _ewSelectedBanks.map(b =>
        `<div style="display:inline-flex;align-items:center;gap:8px;background:rgba(26,79,163,.09);border:1px solid rgba(26,79,163,.2);padding:6px 12px;border-radius:10px">
          <span style="font-size:13px">🏦</span>
          <span style="font-size:13px;font-weight:700;color:var(--accent)">${b.bankName}</span>
          ${b.isIncred?'<span style="font-size:10px;color:#f59e0b;font-weight:600">InCred</span>':''}
          ${b.isElite?'<span style="font-size:10px;color:var(--danger);font-weight:600">Mudrahub</span>':''}
          <span onclick="ewToggleCard(${b.bankId},{})" style="cursor:pointer;color:var(--danger);font-size:14px;line-height:1;margin-left:2px" title="Remove">✕</span>
        </div>`
      ).join('');
    }

    function ewSave() {
      // mirrors eligible_wizard.py action_save
      if (!_ewSelectedBanks.length) {
        showToast('Please select at least one bank', 'error');
        return;
      }
      if (!currentDetail) { closeEligWizard(); return; }

      // Save to app's lastEligibleBanks (mirrors last.eligible model)
      currentDetail.lastEligibleBanks = _ewSelectedBanks.map(b => ({
        bankId: b.bankId, bankName: b.bankName,
        isIncred: b.isIncred, isElite: b.isElite,
      }));

      // Update anaBank — use first InCred bank, or first bank
      const incredBank = _ewSelectedBanks.find(b => b.isIncred);
      currentDetail.anaBank = (incredBank || _ewSelectedBanks[0])?.bankName || '';
      currentDetail.isIncredBank = !!incredBank;

      // Log to tracking
      const bankNames = _ewSelectedBanks.map(b => b.bankName).join(', ');
      const now = new Date();
      currentDetail.tracking = currentDetail.tracking || [];
      currentDetail.tracking.push({
        id: currentDetail.tracking.length + 1,
        name: 'EFIN- Eligible Lnders Selected',
        current_stage: 'PAR_DEP',
        current_user: currentUser.name,
        status: 'COMPLETE',
        comment: 'Banks selected: ' + bankNames,
        sub_note: ' ',
        date: now.toLocaleDateString('en-IN', {day:'2-digit',month:'short',year:'numeric'}) + ' ' + now.toLocaleTimeString('en-IN',{hour:'2-digit',minute:'2-digit'}),
      });

      closeEligWizard();
      renderDetailBankEligibility(currentDetail);
      // Also refresh the Reports > Bank Eligibility tab if it's visible
      if (typeof window._renderReportsBankEligibility === 'function') {
        window._renderReportsBankEligibility(currentDetail);
      }
      showToast('✓ Banks saved: ' + bankNames, 'success');
    }

    // ══════════════════════════════════════════════════════════
    //  ENHANCED IMPORT WIZARD
    //  mirrors analytic_bank_import_wizard.py _import_company_lines
    //  Row-by-row validation: category must exist, company must exist
    //  update_existing flag: skip vs overwrite duplicates
    // ══════════════════════════════════════════════════════════
    function laRunImport() {
      const bankId = parseInt(document.getElementById('la-import-bank')?.value);
      const resDiv = document.getElementById('la-import-result');
      if (!bankId) { showToast('Please select a bank', 'error'); return; }
      if (!LA_DB.importFile) { showToast('Please upload an Excel file', 'error'); return; }
      const ext = LA_DB.importFile.name.split('.').pop().toLowerCase();
      if (!['xls', 'xlsx'].includes(ext)) { showToast('Only .xls and .xlsx files are supported', 'error'); return; }

      const updateExisting = document.getElementById('la-import-update')?.checked || false;
      const bank = LA_DB.banks.find(b => b.id === bankId);
      if (!bank) return;

      // Read CSV/text from the file (browser can't parse xlsx natively; parse CSV-like format)
      const reader = new FileReader();
      reader.onload = function(e) {
        const text = e.target.result;
        const rows = text.split('\n').map(r => r.split(',').map(c => c.trim().replace(/^"|"$/g,'')));
        if (rows.length < 2) { showToast('File is empty or has no data rows', 'error'); return; }

        let created=0, updated=0, skipped=0;
        const errors=[];

        // Skip header row (row index 0) — mirrors _import_company_lines sheet_data[1:]
        for (let i=1; i<rows.length; i++) {
          const row = rows[i];
          if (!row || row.every(c=>!c)) continue; // skip empty rows

          const rowNum = i + 1; // user-friendly row number
          const categoryName  = row[0] || '';
          const companyName   = row[1] || '';
          const pinCode       = row[2] || '';
          const pfRaw         = row[3] || '';

          // Validate category exists — mirrors "Category not found" error
          const cat = LA_DB.categories.find(c => c.name.toLowerCase() === categoryName.toLowerCase());
          if (!cat) {
            errors.push(`Row ${rowNum}: Category '${categoryName}' not found. Please create it first.`);
            continue;
          }

          // Validate company exists — mirrors "Company not found" error
          const company = LA_DB.companies.find(c => c.name.toLowerCase() === companyName.toLowerCase());
          if (!company) {
            errors.push(`Row ${rowNum}: Company '${companyName}' not found. Please create it first.`);
            continue;
          }

          // Parse PF boolean — mirrors _parse_boolean
          const pf = ['true','yes','1','y','x'].includes(pfRaw.toLowerCase());

          // Check duplicate: same bank + category + company — mirrors domain search
          const existingIdx = bank.lines.findIndex(l => l.categoryId===cat.id && l.companyId===company.id);

          if (existingIdx >= 0) {
            if (updateExisting) {
              // Update existing line
              bank.lines[existingIdx].pinCode = pinCode;
              bank.lines[existingIdx].pf = pf;
              updated++;
            } else {
              skipped++; // mirrors "skipped existing lines"
            }
          } else {
            bank.lines.push({ id: LA_DB.nextId.line++, companyId: company.id, categoryId: cat.id, pinCode, pf });
            created++;
          }
        }

        // Show result — mirrors _show_result_message
        if (resDiv) {
          const hasErrors = errors.length > 0;
          const errHtml = hasErrors
            ? `<div style="margin-top:10px;padding:10px 14px;background:rgba(212,43,43,.06);border-radius:8px;font-size:12px;color:var(--danger)">
                <strong>❌ ${errors.length} error(s):</strong><br>
                ${errors.slice(0,10).map(e=>`<div style="margin-top:4px">• ${e}</div>`).join('')}
                ${errors.length>10?`<div style="margin-top:4px;color:var(--text3)">... and ${errors.length-10} more</div>`:''}
              </div>` : '';
          resDiv.style.display = 'block';
          resDiv.innerHTML = `
            <div style="padding:12px 16px;border-radius:var(--r-sm);font-size:13px;background:${hasErrors?'rgba(230,126,0,.06)':'rgba(26,115,64,.06)'};border:1px solid ${hasErrors?'rgba(230,126,0,.2)':'rgba(26,115,64,.2)'};color:${hasErrors?'var(--warn)':'var(--success)'}">
              <strong>Import completed — ${bank.name}</strong><br>
              ✓ Created: <strong>${created}</strong> &nbsp;|&nbsp; ✓ Updated: <strong>${updated}</strong> &nbsp;|&nbsp; ⊘ Skipped: <strong>${skipped}</strong>
              ${skipped?'<br><small style="color:var(--text3)">Enable "Update Existing Lines" to overwrite duplicates.</small>':''}
            </div>${errHtml}`;
        }
        laRenderBanks();
        if (created+updated > 0) showToast(`Import done — ${created} created, ${updated} updated`, 'success');
        else showToast('Import complete. ' + (skipped?`${skipped} skipped.`:'') + (errors.length?` ${errors.length} errors.`:''), errors.length?'error':'info');
      };
      reader.readAsText(LA_DB.importFile);
    }


