    // ── Role-based visibility filter (used by renderTable and filterTable) ──
    // UPDATED: All status (ASSIGNED/IN_PROGRESS/COMPLETED/REJECTED) visible to login_team,
    //          operation_manager (Leader) and admin — no status-based hiding.
    function _applyRoleFilter(apps) {
      if (!window.currentUser) return apps;
      var role  = currentUser.role;
      var uname = currentUser.name;
      var email = (currentUser.email || '').toLowerCase();

      // ── ADMIN (location_head alias): ALL statuses, filtered by assigned locations ──
      if (role === 'admin') {
        // Admin sees all applications in their assigned locations — ALL statuses visible
        var adminRec = (typeof twUsers !== 'undefined' ? twUsers : [])
          .find(function(u) {
            return u.name === uname || u.email.toLowerCase() === email;
          });
        var adminLocs = adminRec ? (adminRec.locs || []) : [];
        // If admin has no location restriction (super-admin), return everything
        if (!adminLocs.length) return apps;
        return apps.filter(function(a) {
          // Show if app has a matching location, or app has no location set yet
          return !a.location || adminLocs.includes(a.location);
        });
      }

      // ── LOCATION HEAD: ALL statuses, filtered by assigned locations ──
      if (role === 'location_head') {
        var lhRec = (typeof twUsers !== 'undefined' ? twUsers : [])
          .find(function(u) {
            return u.name === uname || u.email.toLowerCase() === email;
          });
        var lhLocs = lhRec ? (lhRec.locs || []) : [];
        if (lhLocs.length > 0) {
          return apps.filter(function(a) { return !a.location || lhLocs.includes(a.location); });
        }
        return apps;
      }

      // ── PARTNER: own apps only (existing scoped filter) ──
      if (role === 'partner') {
        return getPartnerScopedApps();
      }

      // ── SALES EXECUTIVE: own assigned apps + unassigned apps in their location ──
      if (role === 'sales_executive') {
        var myApps = apps.filter(function(a) { return (a.sales || '') === uname; });
        var seRec  = (typeof twUsers !== 'undefined' ? twUsers : [])
          .find(function(u) { return u.name === uname || (u.email||'').toLowerCase() === email; });
        var seLocs = seRec ? (seRec.locs || []) : [];
        if (seLocs.length > 0) {
          var locUnassigned = apps.filter(function(a) {
            return seLocs.includes(a.location) && !a.sales;
          });
          var merged = myApps.concat(locUnassigned);
          return merged.filter(function(v, i, arr) { return arr.findIndex(function(x){ return x.id===v.id; })===i; });
        }
        return myApps;
      }

      // ── TEAM LEADER (sales team leader): team members' apps — all statuses ──
      if (role === 'team_leader') {
        var myTeams = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : [])
          .filter(function(t) { return t.leader === uname || (t.members || []).includes(uname); });
        var teamMembers = myTeams.reduce(function(acc, t) {
          return acc.concat([t.leader], t.members || []);
        }, [uname]);
        var uniqueMembers = teamMembers.filter(function(v, i, a) { return v && a.indexOf(v) === i; });
        return apps.filter(function(a) { return uniqueMembers.includes(a.sales); });
      }

      // ── MANAGER: same scope as team_leader — all statuses ──
      if (role === 'manager') {
        var mgrTeams = (typeof twSalesTeams !== 'undefined' ? twSalesTeams : [])
          .filter(function(t) { return t.leader === uname || (t.members || []).includes(uname); });
        var mgrMembers = mgrTeams.reduce(function(acc, t) {
          return acc.concat([t.leader], t.members || []);
        }, [uname]);
        var uniqueMgr = mgrMembers.filter(function(v, i, a) { return v && a.indexOf(v) === i; });
        return apps.filter(function(a) { return uniqueMgr.includes(a.sales); });
      }

      // ── LOGIN USER (login_team): ALL statuses, only own assigned apps ──
      // Shows ASSIGNED + IN_PROGRESS + COMPLETED + REJECTED — no status filter here
      if (role === 'login_team') {
        return apps.filter(function(a) { return (a.loginUser || '') === uname; });
      }

      // ── OPERATION LEADER (operation_manager): ALL statuses ──
      // Visibility criteria: app.location ∈ leader's team locations
      //                   AND app.loginUser ∈ team members (or loginUser unset — newly created)
      //                   AND loanType matches team.loanTypes restriction (if any)
      // This covers the full lifecycle: ASSIGNED → IN_PROGRESS → COMPLETED → REJECTED
      if (role === 'operation_manager') {
        var leaderOpTeams = (typeof twLoginTeams !== 'undefined' ? twLoginTeams : [])
          .filter(function(t) {
            return t.leader === uname || (t.members || []).includes(uname);
          });

        if (!leaderOpTeams.length) return [];

        // Collect all loginUser members across all op teams this leader manages
        var opMemberSet = {};
        leaderOpTeams.forEach(function(t) {
          if (t.leader) opMemberSet[t.leader] = true;
          (t.members || []).forEach(function(m) { if (m) opMemberSet[m] = true; });
        });

        // Location set for this leader's teams
        var leaderLocSet = {};
        leaderOpTeams.forEach(function(t) { if (t.location) leaderLocSet[t.location] = true; });

        return apps.filter(function(a) {
          // Location must match one of the leader's team locations
          var locMatch = !a.location || leaderLocSet[a.location];
          if (!locMatch) return false;

          // loginUser must be a member of one of this leader's teams
          // (if loginUser is not yet set, include the app — it may be unassigned)
          var loginMatch = !a.loginUser || opMemberSet[a.loginUser];
          if (!loginMatch) return false;

          // Product (loanType) filter: check if ANY of the leader's teams restricts by loanType
          // An app passes if at least one matching team either has no loanType restriction
          // or explicitly includes the app's loanType
          var productMatch = leaderOpTeams.some(function(t) {
            var locOk = !t.location || t.location === a.location;
            if (!locOk) return false;
            if (!Array.isArray(t.loanTypes) || !t.loanTypes.length) return true; // no restriction
            return t.loanTypes.includes(a.loanType || '');
          });
          return productMatch;
        });
      }

      // ── ACCOUNTS, PRODUCT TEAM, DSA USER: full read-only access ──
      if (role === 'accounts' || role === 'product_team' || role === 'dsa_user') return apps;

      // Default safe fallback
      return apps;
    }
