    // ── Standalone bank-body renderer (called by openDetail AND edit/save/cancel) ──
    function renderBankBody(app) {
      if (!app) return;
      const rd = ROLES[currentUser.role];

      // Ensure bankLines array exists
      if (!app.bankLines) {
        app.bankLines = [{
          id: 1,
          bankName: app.bank || '',
          tempAppNo: app._tempAppNo || ('APP-' + Math.random().toString(36).slice(2, 8).toUpperCase()),
          applicationNumber: '',
          approvedLoan: 0,
          remarks: 'IN PROCESS'
        }];
      }

      const canEditRole = !!(rd && (rd.canChangeStatus || currentUser.role === 'admin' || currentUser.role === 'login_team'));
      const canEdit     = canEditRole && !!window._bankEditMode;

      // ── Toolbar visibility (always applied — independent of tbody) ──
      const toolbar   = document.getElementById('bank-edit-toolbar');
      const btnEdit   = document.getElementById('bank-btn-edit');
      const btnSave   = document.getElementById('bank-btn-save');
      const btnCancel = document.getElementById('bank-btn-cancel');
      const dot       = document.getElementById('bank-edit-status-dot');
      const lbl       = document.getElementById('bank-edit-status-label');

      if (toolbar)   toolbar.style.display   = canEditRole ? 'flex'        : 'none';
      if (btnEdit)   btnEdit.style.display   = canEdit     ? 'none'        : 'inline-flex';
      if (btnSave)   btnSave.style.display   = canEdit     ? 'inline-flex' : 'none';
      if (btnCancel) btnCancel.style.display = canEdit     ? 'inline-flex' : 'none';
      if (dot) dot.style.background          = canEdit     ? '#f59e0b'     : 'var(--text3)';
      if (lbl) lbl.textContent               = canEdit     ? 'Edit mode — changes not yet saved' : 'View mode';

      // ── Table rows ──
      const tbody = document.getElementById('detail-banks-body');
      if (!tbody) return;

      tbody.innerHTML = app.bankLines.map((line, idx) => `
        <tr style="border-bottom:1px solid var(--border)">
          <td style="padding:10px 12px">
            ${canEdit
              ? `<select onchange="updateBankLine('${app.id}',${idx},'bankName',this.value)"
                  style="width:100%;background:var(--surface2);border:1px solid var(--border2);border-radius:8px;padding:7px 10px;font-size:12.5px;color:var(--text);font-family:var(--font-body);outline:none;cursor:pointer">
                  <option value="">— Select Bank —</option>
                  ${BANKS_STORE.map(b => `<option value="${b.name}"${line.bankName===b.name?' selected':''}>${b.name}</option>`).join('')}
                </select>`
              : `<strong style="font-size:13px">${line.bankName || '—'}</strong>`}
          </td>
          <td style="padding:10px 12px;font-family:monospace;font-size:12.5px;color:var(--accent);font-weight:600;letter-spacing:.3px">
            ${line.tempAppNo || '—'}
          </td>
          <td style="padding:10px 12px${currentUser.role==='partner'?';display:none':''}">
            ${canEdit
              ? `<input value="${line.applicationNumber||''}" placeholder="Enter application no."
                  onblur="updateBankLine('${app.id}',${idx},'applicationNumber',this.value)"
                  style="width:100%;background:var(--surface2);border:1px solid var(--border2);border-radius:8px;padding:7px 10px;font-size:12.5px;color:var(--text);font-family:var(--font-body);outline:none"/>`
              : `<span style="font-size:12.5px">${line.applicationNumber || '—'}</span>`}
          </td>
          <td style="padding:10px 12px">
            ${canEdit
              ? `<input type="number" value="${line.approvedLoan||0}" placeholder="0" min="0"
                  onblur="updateBankLine('${app.id}',${idx},'approvedLoan',parseFloat(this.value)||0)"
                  style="width:100%;background:var(--surface2);border:1px solid var(--border2);border-radius:8px;padding:7px 10px;font-size:12.5px;color:var(--text);font-family:var(--font-body);outline:none;text-align:right"/>`
              : `<span style="font-size:12.5px">${line.approvedLoan ? '₹'+Number(line.approvedLoan).toLocaleString('en-IN') : '0'}</span>`}
          </td>
          <td style="padding:10px 12px">
            ${canEdit
              ? `<select onchange="updateBankLine('${app.id}',${idx},'remarks',this.value)"
                  style="width:100%;background:var(--surface2);border:1px solid var(--border2);border-radius:8px;padding:7px 10px;font-size:12.5px;color:var(--text);font-family:var(--font-body);outline:none;cursor:pointer">
                  <option value="">— Select Status —</option>
                  <option value="IN PROCESS"${line.remarks==='IN PROCESS'?' selected':''}>In Process</option>
                  <option value="Draft"${line.remarks==='Draft'?' selected':''}>Draft</option>
                  <option value="Personal Details"${line.remarks==='Personal Details'?' selected':''}>Personal Details</option>
                  <option value="Recommendation"${line.remarks==='Recommendation'?' selected':''}>Recommendation</option>
                  <option value="Module"${line.remarks==='Module'?' selected':''}>Module</option>
                  <option value="Income Verified"${line.remarks==='Income Verified'?' selected':''}>Income Verified</option>
                  <option value="Assign Lender"${line.remarks==='Assign Lender'?' selected':''}>Assign Lender</option>
                  <option value="Underwriting"${line.remarks==='Underwriting'?' selected':''}>Underwriting</option>
                  <option value="Offer"${line.remarks==='Offer'?' selected':''}>Offer</option>
                  <option value="Approved"${line.remarks==='Approved'?' selected':''}>Approved</option>
                  <option value="Deviation"${line.remarks==='Deviation'?' selected':''}>Deviation</option>
                  <option value="Approved Deviation"${line.remarks==='Approved Deviation'?' selected':''}>Approved Deviation</option>
                  <option value="Acceptance"${line.remarks==='Acceptance'?' selected':''}>Acceptance</option>
                  <option value="Disbursed"${line.remarks==='Disbursed'?' selected':''}>Disbursed</option>
                  <option value="Hold"${line.remarks==='Hold'?' selected':''}>Hold</option>
                  <option value="Rejected"${line.remarks==='Rejected'?' selected':''}>Rejected</option>
                  <option value="NI"${line.remarks==='NI'?' selected':''}>NI</option>
                  <option value="Cancelled"${line.remarks==='Cancelled'?' selected':''}>Cancelled</option>
                </select>`
              : `<span style="font-size:12.5px;color:var(--text2)">${line.remarks || '—'}</span>`}
          </td>
          <td style="padding:10px 8px;text-align:center">
            ${canEdit && app.bankLines.length > 1
              ? `<button onclick="removeBankLine('${app.id}',${idx})"
                  style="background:rgba(212,43,43,.08);border:1px solid rgba(212,43,43,.2);border-radius:7px;color:var(--danger);font-size:13px;width:28px;height:28px;cursor:pointer;display:flex;align-items:center;justify-content:center"
                  title="Remove row">✕</button>`
              : ''}
          </td>
        </tr>`).join('');

      if (canEdit) {
        const addRow = document.createElement('tr');
        addRow.innerHTML = `<td colspan="6" style="padding:10px 12px;border-top:1px dashed var(--border2)">
          <button onclick="addBankLine('${app.id}')"
            style="display:inline-flex;align-items:center;gap:6px;background:rgba(26,79,163,.06);border:1.5px dashed rgba(26,79,163,.3);border-radius:8px;padding:7px 16px;font-size:13px;font-weight:600;color:var(--accent);cursor:pointer;transition:all .18s"
            onmouseover="this.style.background='rgba(26,79,163,.12)'" onmouseout="this.style.background='rgba(26,79,163,.06)'">
            ＋ Add Bank Line
          </button>
        </td>`;
        tbody.appendChild(addRow);
      }
    }
    window.renderBankBody = renderBankBody;

    // ── Bank Details Edit / Save / Cancel ──────────────────────────────────
    window._bankEditMode     = false;
    window._bankEditSnapshot = null;

    function bankDetailsSetEditMode(on) {
      const app = currentDetail || window.currentDetail;
      if (!app) return;
      const rd = ROLES[currentUser.role];
      const canEditRole = !!(rd && (rd.canChangeStatus || currentUser.role === 'admin' || currentUser.role === 'login_team'));
      if (on && !canEditRole) { showToast('You do not have permission to edit Bank Details', 'warn'); return; }

      if (on) {
        window._bankEditSnapshot = JSON.parse(JSON.stringify(app.bankLines || []));
        window._bankEditMode = true;
      } else {
        // Cancel — restore snapshot
        if (window._bankEditSnapshot) {
          app.bankLines = JSON.parse(JSON.stringify(window._bankEditSnapshot));
          window._bankEditSnapshot = null;
        }
        window._bankEditMode = false;
      }

      renderBankBody(app);
    }
    window.bankDetailsSetEditMode = bankDetailsSetEditMode;

    function bankDetailsSave() {
      const app = currentDetail || window.currentDetail;
      if (!app) return;
      window._bankEditSnapshot = null;
      window._bankEditMode = false;
      if (typeof persistSave === 'function') persistSave();
      if (typeof showToast === 'function') showToast('Bank Details saved ✓', 'success');
      renderBankBody(app);
    }
