    // ── incredSetRM: mirrors incred.rm.email Many2one on loan.application ──
    window.incredSetRM = function(appId, rmId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;

      // Use window.RM_EMAILS (stores.js — localStorage-backed, includes user-added RMs)
      const _rmList = (window.RM_EMAILS && window.RM_EMAILS.length)
        ? window.RM_EMAILS
        : (typeof RM_EMAILS !== 'undefined' ? RM_EMAILS : []);

      const rm = _rmList.find(r => String(r.id) === String(rmId));

      // Save to app object
      app.rm_email_id = rmId ? parseInt(rmId) : null;
      if (rm) {
        app.rm = rm.name + ' (' + (rm.location || '') + ')';
        app.rm_email_address = rm.email;
        showToast('✅ RM assigned: ' + rm.name, 'success');
      } else {
        app.rm = '';
        app.rm_email_address = '';
        showToast('⚠ RM not found in list', 'warn');
      }
      if (typeof persistSave === 'function') persistSave();

      // Debounce _refreshIncredTab to prevent multiple rapid re-renders
      clearTimeout(window._rmRefreshTimer);
      window._rmRefreshTimer = setTimeout(function() {
        if (typeof window._refreshIncredTab === 'function') {
          window._refreshIncredTab(appId);
        }
      }, 80);
    };
