    // ═══════════════════════════════════════════════════════
    //  BRANDING PANEL — Admin Settings → Logo & Branding
    // ═══════════════════════════════════════════════════════

    function brandingInitPanel() {
      // Sync current icon logo state
      const iconImg = document.getElementById('logo-img');
      const iconPrev = document.getElementById('branding-icon-preview-img');
      const iconPlaceholder = document.getElementById('branding-icon-preview-placeholder');
      const iconRemoveBtn = document.getElementById('branding-icon-remove-btn');
      if (iconImg && iconImg.src && iconImg.style.display !== 'none') {
        iconPrev.src = iconImg.src; iconPrev.style.display = 'block';
        if (iconPlaceholder) iconPlaceholder.style.display = 'none';
        if (iconRemoveBtn) iconRemoveBtn.style.display = '';
      } else {
        iconPrev.style.display = 'none';
        if (iconPlaceholder) iconPlaceholder.style.display = '';
        if (iconRemoveBtn) iconRemoveBtn.style.display = 'none';
      }

      // Sync current banner logo state
      const bannerImg = document.getElementById('logo-banner-img');
      const bannerPrev = document.getElementById('branding-banner-preview-img');
      const bannerPlaceholder = document.getElementById('branding-banner-preview-placeholder');
      const bannerRemoveBtn = document.getElementById('branding-banner-remove-btn');
      if (bannerImg && bannerImg.src && bannerImg.style.display !== 'none') {
        bannerPrev.src = bannerImg.src; bannerPrev.style.display = 'block';
        if (bannerPlaceholder) bannerPlaceholder.style.display = 'none';
        if (bannerRemoveBtn) bannerRemoveBtn.style.display = '';
      } else {
        bannerPrev.style.display = 'none';
        if (bannerPlaceholder) bannerPlaceholder.style.display = '';
        if (bannerRemoveBtn) bannerRemoveBtn.style.display = 'none';
      }

      // Sync size sliders from localStorage
      try {
        const iconSize = parseInt(localStorage.getItem('efin_logo_icon_size') || '44');
        const bannerSize = parseInt(localStorage.getItem('efin_logo_banner_size') || '44');
        const iconSlider = document.getElementById('branding-icon-size-slider');
        const bannerSlider = document.getElementById('branding-banner-size-slider');
        if (iconSlider) { iconSlider.value = iconSize; brandingUpdateIconSize(iconSize, false); }
        if (bannerSlider) { bannerSlider.value = bannerSize; brandingUpdateBannerSize(bannerSize, false); }
      } catch(e) {}

      // Sync brand text
      try {
        const savedName = localStorage.getItem('efin_brand_name');
        const savedSub  = localStorage.getItem('efin_brand_sub');
        if (savedName) document.getElementById('branding-text-name').value = savedName;
        if (savedSub)  document.getElementById('branding-text-sub').value  = savedSub;
        brandingUpdateText();
      } catch(e) {}

      // Sync sign-in page logo state
      try {
        const signinPrev = document.getElementById('branding-signin-preview-img');
        const signinPlaceholder = document.getElementById('branding-signin-preview-placeholder');
        const signinRemoveBtn = document.getElementById('branding-signin-remove-btn');
        const savedSignin = localStorage.getItem('efin_signin_logo');
        const loginImg = document.getElementById('login-logo-img');
        const currentSrc = savedSignin || (loginImg && loginImg.style.display !== 'none' ? loginImg.src : '');
        if (currentSrc && signinPrev) {
          signinPrev.src = currentSrc; signinPrev.style.display = 'block';
          if (signinPlaceholder) signinPlaceholder.style.display = 'none';
          if (signinRemoveBtn) signinRemoveBtn.style.display = '';
        } else {
          if (signinPrev) signinPrev.style.display = 'none';
          if (signinPlaceholder) signinPlaceholder.style.display = '';
          if (signinRemoveBtn) signinRemoveBtn.style.display = 'none';
        }
      } catch(e) {}
    }

    function brandingHandleDrop(event, type) {
      event.preventDefault();
      const file = event.dataTransfer.files[0];
      if (!file || !file.type.startsWith('image/')) return;
      if (type === 'icon') brandingApplyIcon(file);
      else if (type === 'banner') brandingApplyBanner(file);
      else if (type === 'signin') brandingApplySignin(file);
    }

    function brandingApplyIcon(file) {
      if (!file) return;
      const reader = new FileReader();
      reader.onload = function(e) {
        const dataUrl = e.target.result;
        applyLogoToSidebar(dataUrl);
        applyLogoToLogin(dataUrl);
        try { localStorage.setItem('efin_logo', dataUrl); } catch(err) {}
        // Update panel preview
        const prev = document.getElementById('branding-icon-preview-img');
        const placeholder = document.getElementById('branding-icon-preview-placeholder');
        const removeBtn = document.getElementById('branding-icon-remove-btn');
        if (prev) { prev.src = dataUrl; prev.style.display = 'block'; }
        if (placeholder) placeholder.style.display = 'none';
        if (removeBtn) removeBtn.style.display = '';
        document.getElementById('branding-icon-filename').textContent = '✓ ' + file.name;
        showToast('Icon logo updated successfully', 'success');
      };
      reader.readAsDataURL(file);
    }

    function brandingApplyBanner(file) {
      if (!file) return;
      const reader = new FileReader();
      reader.onload = function(e) {
        const dataUrl = e.target.result;
        applyBannerLogoToSidebar(dataUrl);
        try { localStorage.setItem('efin_banner_logo', dataUrl); } catch(err) {}
        // Update panel preview
        const prev = document.getElementById('branding-banner-preview-img');
        const placeholder = document.getElementById('branding-banner-preview-placeholder');
        const removeBtn = document.getElementById('branding-banner-remove-btn');
        if (prev) { prev.src = dataUrl; prev.style.display = 'block'; }
        if (placeholder) placeholder.style.display = 'none';
        if (removeBtn) removeBtn.style.display = '';
        document.getElementById('branding-banner-filename').textContent = '✓ ' + file.name;
        showToast('Banner logo updated successfully', 'success');
      };
      reader.readAsDataURL(file);
    }

    function brandingApplySignin(file) {
      if (!file) return;
      const reader = new FileReader();
      reader.onload = function(e) {
        const dataUrl = e.target.result;
        // Apply to actual login page logo
        applyLogoToLogin(dataUrl);
        try { localStorage.setItem('efin_signin_logo', dataUrl); } catch(err) {}
        // Save to server so logo persists across all browsers/sessions
        fetch('/api/settings/signin-logo', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + localStorage.getItem('efin_auth_token') || sessionStorage.getItem('efin_auth_token') || '' },
          body: JSON.stringify({ logo: dataUrl })
        }).catch(function(){});
        // Update panel preview
        const prev = document.getElementById('branding-signin-preview-img');
        const placeholder = document.getElementById('branding-signin-preview-placeholder');
        const removeBtn = document.getElementById('branding-signin-remove-btn');
        if (prev) { prev.src = dataUrl; prev.style.display = 'block'; }
        if (placeholder) placeholder.style.display = 'none';
        if (removeBtn) removeBtn.style.display = '';
        document.getElementById('branding-signin-filename').textContent = '✓ ' + file.name;
        showToast('Sign-in logo updated successfully', 'success');
      };
      reader.readAsDataURL(file);
    }

    function brandingRemoveSignin() {
      if (!confirm('Remove the sign-in page logo? The default will be restored.')) return;
      const loginImg = document.getElementById('login-logo-img');
      if (loginImg) { loginImg.src = ''; loginImg.style.display = 'none'; }
      const loginLetter = document.getElementById('login-logo-letter');
      if (loginLetter) loginLetter.style.display = '';
      // Panel
      const prev = document.getElementById('branding-signin-preview-img');
      const placeholder = document.getElementById('branding-signin-preview-placeholder');
      const removeBtn = document.getElementById('branding-signin-remove-btn');
      if (prev) { prev.src = ''; prev.style.display = 'none'; }
      if (placeholder) placeholder.style.display = '';
      if (removeBtn) removeBtn.style.display = 'none';
      document.getElementById('branding-signin-filename').textContent = '';
      try { localStorage.removeItem('efin_signin_logo'); } catch(e) {}
      // Clear from server too
      fetch('/api/settings/signin-logo', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': 'Bearer ' + (_lsGet('efin_auth_token') || sessionStorage.getItem('efin_auth_token') || '') },
        body: JSON.stringify({ logo: '' })
      }).catch(function(){});
      showToast('Sign-in logo removed', 'success');
    }

    function brandingRemoveIcon() {
      if (!confirm('Remove the icon logo? The default icon will be restored.')) return;
      // Sidebar
      const img = document.getElementById('logo-img');
      if (img) { img.src = ''; img.style.display = 'none'; }
      const defIcon = document.getElementById('sidebar-default-icon');
      if (defIcon) defIcon.style.display = '';
      const box = document.getElementById('logo-icon-box');
      if (box) box.classList.remove('has-image');
      // Login page
      const loginImg = document.getElementById('login-logo-img');
      if (loginImg) { loginImg.src = ''; loginImg.style.display = 'none'; }
      const loginLetter = document.getElementById('login-logo-letter');
      if (loginLetter) loginLetter.style.display = '';
      // Panel
      const prev = document.getElementById('branding-icon-preview-img');
      const placeholder = document.getElementById('branding-icon-preview-placeholder');
      const removeBtn = document.getElementById('branding-icon-remove-btn');
      if (prev) { prev.src = ''; prev.style.display = 'none'; }
      if (placeholder) placeholder.style.display = '';
      if (removeBtn) removeBtn.style.display = 'none';
      document.getElementById('branding-icon-filename').textContent = '';
      try { localStorage.removeItem('efin_logo'); } catch(e) {}
      showToast('Icon logo removed', 'success');
    }

    function brandingRemoveBanner() {
      if (!confirm('Remove the banner logo? The brand text fallback will be shown.')) return;
      const img = document.getElementById('logo-banner-img');
      if (img) { img.src = ''; img.style.display = 'none'; }
      const def = document.getElementById('logo-banner-default');
      if (def) def.style.display = '';
      const box = document.getElementById('logo-banner-box');
      if (box) box.classList.remove('has-image');
      // Panel
      const prev = document.getElementById('branding-banner-preview-img');
      const placeholder = document.getElementById('branding-banner-preview-placeholder');
      const removeBtn = document.getElementById('branding-banner-remove-btn');
      if (prev) { prev.src = ''; prev.style.display = 'none'; }
      if (placeholder) placeholder.style.display = '';
      if (removeBtn) removeBtn.style.display = 'none';
      document.getElementById('branding-banner-filename').textContent = '';
      try { localStorage.removeItem('efin_banner_logo'); } catch(e) {}
      showToast('Banner logo removed', 'success');
    }

    function brandingUpdateIconSize(val, save) {
      const size = parseInt(val);
      // Update sidebar icon box
      const iconBox = document.getElementById('logo-icon-box');
      if (iconBox) { iconBox.style.width = size + 'px'; iconBox.style.height = size + 'px'; }
      // Update preview box in panel
      const prevBox = document.getElementById('branding-icon-preview-box');
      if (prevBox) { prevBox.style.width = size + 'px'; prevBox.style.height = size + 'px'; }
      // Update label
      const label = document.getElementById('branding-icon-size-label');
      if (label) label.textContent = size + ' px';
      if (save !== false) {
        try { localStorage.setItem('efin_logo_icon_size', size); } catch(e) {}
      }
    }

    function brandingUpdateBannerSize(val, save) {
      const size = parseInt(val);
      // Update sidebar banner box height
      const bannerBox = document.getElementById('logo-banner-box');
      if (bannerBox) bannerBox.style.height = size + 'px';
      // Update the dual-logo-zone height to fit the banner + padding
      const zone = document.querySelector('.dual-logo-zone');
      if (zone) zone.style.height = (size + 24) + 'px';
      // Update preview in settings panel
      const prevBox = document.getElementById('branding-banner-preview-box');
      if (prevBox) prevBox.style.height = size + 'px';
      const label = document.getElementById('branding-banner-size-label');
      if (label) label.textContent = size + ' px';
      if (save !== false) {
        try { localStorage.setItem('efin_logo_banner_size', size); } catch(e) {}
      }
    }

    function brandingUpdateText() {
      const name = document.getElementById('branding-text-name').value || 'Mudrahub';
      const sub  = document.getElementById('branding-text-sub').value  || 'LET\'S MAKE IT HAPPEN';
      // Live preview in panel
      const pName = document.getElementById('branding-text-preview-name');
      const pSub  = document.getElementById('branding-text-preview-sub');
      if (pName) pName.textContent = name;
      if (pSub)  pSub.textContent  = sub;
      // Sidebar text
      const sName = document.getElementById('sidebar-logo-text');
      const sSub  = document.getElementById('sidebar-logo-sub');
      if (sName) sName.textContent = name;
      if (sSub)  sSub.textContent  = sub;
      try {
        localStorage.setItem('efin_brand_name', name);
        localStorage.setItem('efin_brand_sub', sub);
      } catch(e) {}
    }

    function brandingResetAll() {
      if (!confirm('Reset ALL branding? Both logos and brand text will be cleared and restored to defaults.')) return;
      brandingRemoveIconSilent();
      brandingRemoveBannerSilent();
      brandingRemoveSigninSilent();
      // Reset text
      document.getElementById('branding-text-name').value = 'Mudrahub';
      document.getElementById('branding-text-sub').value  = "LET'S MAKE IT HAPPEN";
      brandingUpdateText();
      // Reset sizes
      document.getElementById('branding-icon-size-slider').value = 44;
      document.getElementById('branding-banner-size-slider').value = 44;
      brandingUpdateIconSize(44);
      brandingUpdateBannerSize(44);
      try { localStorage.removeItem('efin_brand_name'); localStorage.removeItem('efin_brand_sub'); } catch(e) {}
      showToast('All branding reset to defaults', 'success');
    }

