    // ════════════════════════════════════════════════════════════════════════
    //  BUSINESS LOAN ELIGIBILITY CONFIG MODULE
    //  All functions scoped to business_loan — data stored on bank.blRules
    //  Structure per bank:
    //    bank.blRules = {
    //      pins:        [],          // 6-digit PIN codes
    //      empTypes:    ['SELFEMP','SENP'],
    //      compTypes:   ['plcc','plc','llp','proprietorship','partnership'],
    //      homeTypes:   ['OWNED_SELF_SPOUSE','OWNED_BY_PARENTS','RENTED_SELF_WITH_FAMILY'],
    //      minCibil:    650,
    //      acceptNTC:   false,
    //      maxLoanAmt:  5000000,
    //      minTenure:   12,
    //      maxTenure:   60,
    //      foirLimit:   55,
    //      minAge:      25,
    //      maxAge:      65,
    //      minVintage:  24,          // months business must be active
    //      minTurnover: 200000,      // monthly turnover
    //      minAcctVintage: 12,       // banking account vintage months
    //      minAvgBalance:  50000,
    //      minCreditScore: 650,
    //      bankStmtMonths: 12,
    //      bounceTolerance: 2,
    //    }
    //    bank.blCategories = [{ id, name, bankId, minTurnover, color, notes }]
    // ════════════════════════════════════════════════════════════════════════

    // Ensure blRules exists on every bank
    // ════════════════════════════════════════════════════════════════════════
    //  PER-PRODUCT ELIGIBILITY CONFIG — storage helpers
    //  Data structure (fully isolated per product key):
    //    bank.productRules[productKey]          → eligibility rules object
    //    LA_DB.productCategories[productKey]    → array of categories
    //    LA_DB.nextId.prCat[productKey]         → category ID counter
    // ════════════════════════════════════════════════════════════════════════

    // Default rules template — cloned for each product, never shared
    function _prDefaultRules() {
      return {
        pins: [], empTypes: ['SALARIED', 'SELFEMP', 'SENP'],
        compTypes: ['plcc', 'plc', 'llp', 'govt', 'psu', 'proprietorship', 'partnership', 'other'],
        homeTypes: ['OWNED_SELF_SPOUSE', 'OWNED_BY_PARENTS', 'RENTED_SELF_WITH_FAMILY', 'PAYING_GUEST_PL', 'COMPANY_PROVIDED', 'OTHER'],
        minCibil: 700, acceptNTC: false,
        maxLoanAmt: 5000000, minTenure: 12, maxTenure: 60, foirLimit: 50,
        minAge: 21, maxAge: 65, minVintage: 0, minTurnover: 0,
        minAcctVintage: 6, minAvgBalance: 10000, minCreditScore: 700,
        bankStmtMonths: 6, bounceTolerance: 3,
      };
    }

    // Get (or initialise) rules for a specific bank + product combination
    function _prEnsureRules(bank, productKey) {
      if (!bank.productRules) bank.productRules = {};
      if (!bank.productRules[productKey]) {
        // Migrate legacy blRules data for business_loan on first access
        if (productKey === 'business_loan' && bank.blRules) {
          bank.productRules[productKey] = Object.assign({}, bank.blRules);
        } else {
          bank.productRules[productKey] = _prDefaultRules();
        }
      }
      return bank.productRules[productKey];
    }

    // Keep _blEnsureRules as a backward-compat alias (business_loan)
    function _blEnsureRules(bank) { return _prEnsureRules(bank, 'business_loan'); }

    // Ensure per-product categories storage
    function _prEnsureCategories(productKey) {
      if (!LA_DB.productCategories) LA_DB.productCategories = {};
      if (!LA_DB.productCategories[productKey]) {
        // Migrate legacy blCategories for business_loan
        if (productKey === 'business_loan' && LA_DB.blCategories && LA_DB.blCategories.length) {
          LA_DB.productCategories[productKey] = LA_DB.blCategories.map(c => Object.assign({}, c));
        } else {
          LA_DB.productCategories[productKey] = [];
        }
      }
      if (!LA_DB.nextId.prCat) LA_DB.nextId.prCat = {};
      if (!LA_DB.nextId.prCat[productKey]) LA_DB.nextId.prCat[productKey] = 1;
      return LA_DB.productCategories[productKey];
    }

    // ── Tab switcher — shared across all 8 multi-config products ─────────
    function lcBlTab(panel, el) {
      document.querySelectorAll('#lc-bl-tabs .tab').forEach(t => t.classList.remove('active'));
      ['bl-pins-cfg','bl-emptype-cfg','bl-cibil-cfg','bl-hometype-cfg',
       'bl-bankrules-cfg','bl-categories-cfg','bl-creditscore-cfg'].forEach(id => {
        const p = document.getElementById('lc-panel-' + id);
        if (p) p.style.display = 'none';
      });
      if (el) el.classList.add('active');
      const target = document.getElementById('lc-panel-' + panel);
      if (target) target.style.display = 'block';
      const renders = {
        'bl-pins-cfg':       lcBlRenderPins,
        'bl-emptype-cfg':    lcBlRenderEmpTypes,
        'bl-cibil-cfg':      lcBlRenderCibil,
        'bl-hometype-cfg':   lcBlRenderHomeTypes,
        'bl-bankrules-cfg':  lcBlRenderBankRules,
        'bl-categories-cfg': lcBlRenderCategories,
        'bl-creditscore-cfg':lcBlRenderCreditScores,
      };
      if (renders[panel]) renders[panel]();
    }

    // ── Get banks assigned to the currently-active product ───────────────
    function _prBanks(productKey) {
      const pk = productKey || _lcActiveProduct || 'business_loan';
      const assigned = LA_DB.productBanks && LA_DB.productBanks[pk];
      if (!assigned) return LA_DB.banks;
      return LA_DB.banks.filter(b => assigned.has(b.id));
    }

    // Backward-compat alias
    function _blBanks() { return _prBanks('business_loan'); }

    // ──────────────────────────────────────────────────────────────────────
    //  1. SERVICEABLE PIN CODES
    // ──────────────────────────────────────────────────────────────────────
    function lcBlRenderPins() {
      const pk   = _lcActiveProduct || 'business_loan';
      const grid = document.getElementById('lc-bl-pins-grid'); if (!grid) return;
      const search = (document.getElementById('lc-bl-pins-search')?.value || '').toLowerCase();
      const filter = document.getElementById('lc-bl-pins-filter')?.value || '';
      let banks = _prBanks(pk);
      if (search)              banks = banks.filter(b => b.name.toLowerCase().includes(search));
      if (filter === 'has_pins')  banks = banks.filter(b => (_prEnsureRules(b,pk).pins||[]).length > 0);
      if (filter === 'no_pins')   banks = banks.filter(b => !(_prEnsureRules(b,pk).pins||[]).length);

      if (!banks.length) {
        grid.innerHTML = `<div style="color:var(--text3);font-size:13px;text-align:center;padding:32px;grid-column:1/-1">
          ${_prBanks(pk).length ? 'No banks match the current filter.' : 'No banks assigned to this product yet — add banks in the Assigned Banks section above.'}
        </div>`;
        return;
      }
      grid.innerHTML = banks.map(b => {
        const rules    = _prEnsureRules(b,pk);
        const pins     = rules.pins || [];
        const pinCount = pins.length;
        const statusColor = pinCount ? 'var(--success)' : 'var(--text3)';
        const statusLabel = pinCount ? `${pinCount} PIN${pinCount !== 1 ? 's' : ''}` : 'All locations';
        return `
        <div style="background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:16px 18px">
          <div style="display:flex;align-items:center;gap:10px;margin-bottom:12px">
            <div style="width:32px;height:32px;border-radius:8px;background:rgba(77,124,255,.12);display:flex;align-items:center;justify-content:center;font-weight:700;font-size:13px;color:var(--accent);flex-shrink:0">${b.name[0]}</div>
            <div style="flex:1;min-width:0">
              <div style="font-weight:700;font-size:13px;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${b.name}</div>
              <div style="font-size:10.5px;color:${statusColor};font-weight:600;margin-top:1px">${statusLabel}</div>
            </div>
            <button onclick="lcBlClearPins(${b.id})" title="Clear all PINs"
              style="padding:4px 8px;border:1px solid var(--border2);border-radius:6px;background:var(--surface2);font-size:11px;color:var(--danger);cursor:pointer"
              onmouseover="this.style.background='var(--accent2)';this.style.color='#fff'" onmouseout="this.style.background='var(--surface2)';this.style.color='var(--danger)'">✕</button>
          </div>
          <textarea id="blpins-${b.id}" rows="3"
            placeholder="Enter 6-digit PINs separated by commas or new lines&#10;e.g. 400001, 400002&#10;Leave empty = serves all locations"
            style="width:100%;padding:8px 10px;border:1px solid var(--border2);border-radius:8px;font-size:12px;font-family:monospace;resize:vertical;background:var(--surface2);color:var(--text);outline:none;box-sizing:border-box"
            oninput="lcBlValidatePinsTA(${b.id})"
          >${pins.join(', ')}</textarea>
          <div id="blpins-fb-${b.id}" style="font-size:11px;color:var(--text3);margin-top:4px;min-height:16px"></div>
          <div style="display:flex;align-items:center;justify-content:space-between;margin-top:8px">
            <span id="blpins-ct-${b.id}" style="font-size:11px;color:var(--text3)">${pinCount ? pinCount + ' PIN' + (pinCount!==1?'s':'') + ' saved' : 'No restriction'}</span>
            <button class="btn btn-ghost btn-sm" onclick="lcBlSavePins(${b.id})" style="font-size:11px">✓ Save</button>
          </div>
        </div>`;
      }).join('');
    }

    function lcBlValidatePinsTA(bankId) {
      const raw    = document.getElementById('blpins-' + bankId)?.value || '';
      const tokens = raw.split(/[\s,;\n]+/).map(p => p.trim()).filter(p => p.length > 0);
      const valid  = tokens.filter(p => /^\d{6}$/.test(p));
      const bad    = tokens.filter(p => p.length > 0 && !/^\d{6}$/.test(p));
      const fb = document.getElementById('blpins-fb-' + bankId);
      const ct = document.getElementById('blpins-ct-' + bankId);
      if (!fb) return;
      if (!tokens.length) { fb.textContent = ''; if (ct) ct.textContent = 'No restriction (serves all)'; return; }
      const parts = [];
      if (valid.length) parts.push(`<span style="color:var(--success)">${valid.length} valid</span>`);
      if (bad.length)   parts.push(`<span style="color:var(--danger)">${bad.length} invalid</span>`);
      fb.innerHTML = parts.join(' · ');
      if (ct) ct.textContent = valid.length + ' PIN' + (valid.length!==1?'s':'') + ' ready to save';
    }

    function lcBlSavePins(bankId) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const raw  = document.getElementById('blpins-' + bankId)?.value || '';
      const pins = [...new Set(raw.split(/[\s,;\n]+/).map(p => p.trim()).filter(p => /^\d{6}$/.test(p)))];
      _prEnsureRules(bank,pk).pins = pins;
      lcBlRenderPins();
      const prod = LC_PRODUCTS.find(p => p.key === pk);
      showToast(`${bank.name}: ${pins.length} PIN${pins.length!==1?'s':''} saved for ${prod?prod.name:pk} ✓`, 'success');
    }

    function lcBlClearPins(bankId) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const ta = document.getElementById('blpins-' + bankId);
      if (ta) ta.value = '';
      _prEnsureRules(bank,pk).pins = [];
      lcBlRenderPins();
      showToast(`${bank.name} — PINs cleared for this product`, 'info');
    }

    function lcBlSaveAllPins() {
      const pk = _lcActiveProduct || 'business_loan';
      let total = 0;
      _prBanks(pk).forEach(b => {
        const ta = document.getElementById('blpins-' + b.id);
        if (!ta) return;
        const pins = [...new Set(ta.value.split(/[\s,;\n]+/).map(p => p.trim()).filter(p => /^\d{6}$/.test(p)))];
        _prEnsureRules(b,pk).pins = pins;
        total += pins.length;
      });
      lcBlRenderPins();
      showToast(`All banks saved — ${total} total PIN${total!==1?'s':''} ✓`, 'success');
    }

    function lcBlPinsExportAll() {
      const pk = _lcActiveProduct || 'business_loan';
      const prod = LC_PRODUCTS.find(p => p.key === pk);
      const rows = [['Bank', 'PIN Code']];
      _prBanks(pk).forEach(b => (_prEnsureRules(b,pk).pins || []).forEach(p => rows.push([b.name, p])));
      if (rows.length === 1) { showToast('No PINs to export for this product', 'info'); return; }
      _laCsvDownload(rows, (pk) + '_pins.csv');
      showToast(`Exported ${rows.length - 1} PIN entries ✓`, 'success');
    }

    // ──────────────────────────────────────────────────────────────────────
    //  2. EMPLOYMENT TYPES
    // ──────────────────────────────────────────────────────────────────────
    function lcBlRenderEmpTypes() {
      const pk    = _lcActiveProduct || 'business_loan';
      const tbody = document.getElementById('lc-bl-emptype-tbody'); if (!tbody) return;
      const banks = _prBanks(pk);
      if (!banks.length) { tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;color:var(--text3);padding:24px">No banks assigned to this product yet.</td></tr>`; return; }
      const EMP_TYPES = [
        { id: 'SALARIED', label: 'Salaried' },
        { id: 'SELFEMP',  label: 'SEP' },
        { id: 'SENP',     label: 'SENP' },
      ];
      const COMP_TYPES = ['plcc','plc','llp','govt','psu','proprietorship','partnership','other'];
      tbody.innerHTML = banks.map(b => {
        const r = _prEnsureRules(b,pk);
        const empChecks = EMP_TYPES.map(et =>
          `<td style="text-align:center">
            <input type="checkbox" ${(r.empTypes||[]).includes(et.id)?'checked':''}
              onchange="lcBlToggleEmpType(${b.id},'${et.id}',this.checked)"
              style="width:16px;height:16px;cursor:pointer;accent-color:var(--accent)">
          </td>`).join('');
        const ctPills = COMP_TYPES.map(ct =>
          `<label style="display:inline-flex;align-items:center;gap:4px;padding:3px 8px;border:1px solid var(--border2);border-radius:6px;cursor:pointer;font-size:11px;margin:2px;background:${(r.compTypes||[]).includes(ct)?'rgba(26,79,163,.1)':'var(--surface2)'};color:${(r.compTypes||[]).includes(ct)?'var(--accent)':'var(--text3)'}">
            <input type="checkbox" ${(r.compTypes||[]).includes(ct)?'checked':''} value="${ct}"
              onchange="lcBlToggleCompType(${b.id},'${ct}',this.checked)"
              style="width:auto;cursor:pointer;accent-color:var(--accent)"> ${ct}
          </label>`).join('');
        return `<tr>
          <td style="font-weight:600;white-space:nowrap">${b.name}</td>
          ${empChecks}
          <td style="max-width:240px"><div style="display:flex;flex-wrap:wrap;gap:2px">${ctPills}</div></td>
          <td><button class="btn btn-ghost btn-sm" onclick="lcBlSaveEmpTypeRow(${b.id})" style="font-size:11px">✓ Save</button></td>
        </tr>`;
      }).join('');
    }

    function lcBlToggleEmpType(bankId, empType, checked) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const r = _prEnsureRules(bank,pk);
      if (!r.empTypes) r.empTypes = [];
      if (checked) { if (!r.empTypes.includes(empType)) r.empTypes.push(empType); }
      else { r.empTypes = r.empTypes.filter(e => e !== empType); }
    }

    function lcBlToggleCompType(bankId, compType, checked) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const r = _prEnsureRules(bank,pk);
      if (!r.compTypes) r.compTypes = [];
      if (checked) { if (!r.compTypes.includes(compType)) r.compTypes.push(compType); }
      else { r.compTypes = r.compTypes.filter(c => c !== compType); }
    }

    function lcBlSaveEmpTypeRow(bankId) {
      showToast('Employment type settings saved ✓', 'success');
      lcBlRenderEmpTypes();
    }

    // ──────────────────────────────────────────────────────────────────────
    //  3. CIBIL RULES
    // ──────────────────────────────────────────────────────────────────────
    function lcBlRenderCibil() {
      const pk    = _lcActiveProduct || 'business_loan';
      const tbody = document.getElementById('lc-bl-cibil-tbody'); if (!tbody) return;
      const banks = _prBanks(pk);
      if (!banks.length) { tbody.innerHTML = `<tr><td colspan="5" style="text-align:center;color:var(--text3);padding:24px">No banks assigned to this product yet.</td></tr>`; return; }
      tbody.innerHTML = banks.map(b => {
        const r = _prEnsureRules(b,pk);
        const score = r.minCibil || 650;
        const color = score >= 720 ? 'var(--success)' : score >= 680 ? 'var(--warn)' : 'var(--accent2)';
        const band  = score >= 750 ? 'Prime only' : score >= 700 ? 'Near-prime & above' : score >= 650 ? 'Sub-prime & above' : 'All (incl. high-risk)';
        return `<tr>
          <td style="font-weight:600">${b.name}</td>
          <td>
            <input type="number" value="${score}" min="300" max="900"
              style="width:80px;padding:5px 8px;border:1px solid var(--border2);border-radius:6px;font-size:13px;font-family:monospace;font-weight:700;background:var(--surface);color:${color}"
              oninput="this.style.color=+this.value>=720?'var(--success)':+this.value>=680?'var(--warn)':'var(--accent2)'"
              onblur="lcBlSaveRule(${b.id},'minCibil',+this.value)">
          </td>
          <td style="text-align:center">
            <label style="display:flex;align-items:center;gap:6px;cursor:pointer;font-size:13px;justify-content:center">
              <input type="checkbox" ${r.acceptNTC?'checked':''} onchange="lcBlSaveRule(${b.id},'acceptNTC',this.checked)" style="width:16px;height:16px;cursor:pointer;accent-color:var(--accent)"> Accept
            </label>
          </td>
          <td style="font-size:12px;color:var(--text3)">${band}</td>
          <td><button class="btn btn-ghost btn-sm" onclick="lcBlSaveRule(${b.id},'_cibil_row',null)" style="font-size:11px" onclick="showToast('Saved ✓','success')">✓ Save</button></td>
        </tr>`;
      }).join('');
    }

    // ──────────────────────────────────────────────────────────────────────
    //  4. HOME TYPE
    // ──────────────────────────────────────────────────────────────────────
    const BL_HOME_TYPES = [
      { id: 'OWNED_SELF_SPOUSE',        col: 'Owned (Self/Spouse)' },
      { id: 'OWNED_BY_PARENTS',         col: 'Owned by Parents' },
      { id: 'RENTED_SELF_WITH_FAMILY',  col: 'Rented' },
      { id: 'PAYING_GUEST_PL',          col: 'Paying Guest' },
      { id: 'COMPANY_PROVIDED',         col: 'Company Provided' },
      { id: 'OTHER',                    col: 'Other' },
    ];

    function lcBlRenderHomeTypes() {
      const pk    = _lcActiveProduct || 'business_loan';
      const tbody = document.getElementById('lc-bl-hometype-tbody'); if (!tbody) return;
      const banks = _prBanks(pk);
      if (!banks.length) { tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--text3);padding:24px">No banks assigned to this product yet.</td></tr>`; return; }
      tbody.innerHTML = banks.map(b => {
        const r = _prEnsureRules(b,pk);
        const ht = r.homeTypes || BL_HOME_TYPES.map(x => x.id); // default: all accepted
        const cols = BL_HOME_TYPES.map(ht_def =>
          `<td style="text-align:center">
            <input type="checkbox" data-ht="${ht_def.id}" ${ht.includes(ht_def.id)?'checked':''}
              onchange="lcBlToggleHomeType(${b.id},'${ht_def.id}',this.checked)"
              style="width:16px;height:16px;cursor:pointer;accent-color:var(--accent)">
          </td>`).join('');
        return `<tr>
          <td style="font-weight:600;white-space:nowrap">${b.name}</td>
          ${cols}
          <td><button class="btn btn-ghost btn-sm" onclick="lcBlSaveHomeTypeRow(${b.id})" style="font-size:11px">✓ Save</button></td>
        </tr>`;
      }).join('');
    }

    function lcBlToggleHomeType(bankId, htId, checked) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const r = _prEnsureRules(bank,pk);
      if (!r.homeTypes) r.homeTypes = BL_HOME_TYPES.map(x => x.id);
      if (checked) { if (!r.homeTypes.includes(htId)) r.homeTypes.push(htId); }
      else { r.homeTypes = r.homeTypes.filter(h => h !== htId); }
    }

    function lcBlSaveHomeTypeRow(bankId) { showToast('Home type settings saved ✓', 'success'); }

    function lcBlSaveAllHomeTypes() {
      showToast('All home type settings saved ✓', 'success');
      if (typeof persistSave === 'function') persistSave();
    }

    // ──────────────────────────────────────────────────────────────────────
    //  5. BANK RULES
    // ──────────────────────────────────────────────────────────────────────
    function lcBlRenderBankRules() {
      const pk    = _lcActiveProduct || 'business_loan';
      const tbody = document.getElementById('lc-bl-bankrules-tbody'); if (!tbody) return;
      const banks = _prBanks(pk);
      if (!banks.length) { tbody.innerHTML = `<tr><td colspan="8" style="text-align:center;color:var(--text3);padding:24px">No banks assigned to this product yet.</td></tr>`; return; }
      tbody.innerHTML = banks.map(b => {
        const r = _prEnsureRules(b,pk);
        return `<tr>
          <td style="font-weight:600;white-space:nowrap">${b.name}</td>
          <td><input type="number" value="${r.maxLoanAmt||5000000}" onblur="lcBlSaveRule(${b.id},'maxLoanAmt',+this.value)"
            style="width:100px;padding:5px 8px;border:1px solid var(--border2);border-radius:6px;font-size:12px;font-family:monospace;background:var(--surface);color:var(--text)"></td>
          <td style="white-space:nowrap">
            <input type="number" value="${r.minTenure||12}" onblur="lcBlSaveRule(${b.id},'minTenure',+this.value)"
              style="width:50px;padding:5px 6px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)">
            <span style="color:var(--text3);margin:0 4px">–</span>
            <input type="number" value="${r.maxTenure||60}" onblur="lcBlSaveRule(${b.id},'maxTenure',+this.value)"
              style="width:50px;padding:5px 6px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)">
          </td>
          <td><input type="number" value="${r.foirLimit||55}" onblur="lcBlSaveRule(${b.id},'foirLimit',+this.value)" min="0" max="100"
            style="width:55px;padding:5px 8px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)"> %</td>
          <td style="white-space:nowrap">
            <input type="number" value="${r.minAge||25}" onblur="lcBlSaveRule(${b.id},'minAge',+this.value)"
              style="width:46px;padding:5px 6px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)">
            <span style="color:var(--text3);margin:0 4px">–</span>
            <input type="number" value="${r.maxAge||65}" onblur="lcBlSaveRule(${b.id},'maxAge',+this.value)"
              style="width:46px;padding:5px 6px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)">
          </td>
          <td><input type="number" value="${r.minVintage||24}" onblur="lcBlSaveRule(${b.id},'minVintage',+this.value)"
            style="width:65px;padding:5px 8px;border:1px solid var(--border2);border-radius:6px;font-size:12px;background:var(--surface);color:var(--text)"></td>
          <td><input type="number" value="${r.minTurnover||200000}" onblur="lcBlSaveRule(${b.id},'minTurnover',+this.value)"
            style="width:100px;padding:5px 8px;border:1px solid var(--border2);border-radius:6px;font-size:12px;font-family:monospace;background:var(--surface);color:var(--text)"></td>
          <td><button class="btn btn-ghost btn-sm" onclick="lcBlSaveRuleRow(${b.id})" style="font-size:11px">✓ Save</button></td>
        </tr>`;
      }).join('');
    }

    function lcBlSaveRule(bankId, field, value) {
      const pk   = _lcActiveProduct || 'business_loan';
      const bank = LA_DB.banks.find(b => b.id === bankId); if (!bank) return;
      const r = _prEnsureRules(bank,pk);
      if (field === '_cibil_row') { showToast('CIBIL rules saved ✓', 'success'); if (typeof persistSave==='function') persistSave(); return; }
      if (field === 'acceptNTC') r[field] = !!value;
      else r[field] = Number(value);
    }

    function lcBlSaveRuleRow(bankId) { showToast('Bank rules saved ✓', 'success'); if (typeof persistSave==='function') persistSave(); }

    // ──────────────────────────────────────────────────────────────────────
    //  6. CATEGORIES
    // ──────────────────────────────────────────────────────────────────────
    // Ensure global BL categories array
    if (!LA_DB.blCategories) LA_DB.blCategories = [];
    if (!LA_DB.nextId.blCat) LA_DB.nextId.blCat = 1;

    function lcBlRenderCategories() {
      const pk    = _lcActiveProduct || 'business_loan';
      const tbody = document.getElementById('lc-bl-categories-tbody'); if (!tbody) return;
      const bankFilter = document.getElementById('lc-bl-cat-bank-filter')?.value || '';
      const allCats = _prEnsureCategories(pk);

      // Populate bank filter dropdown (always refresh for current product)
      const bfSel = document.getElementById('lc-bl-cat-bank-filter');
      if (bfSel) {
        // Only rebuild if not already populated for this product
        const currentBanks = _prBanks(pk);
        if (bfSel.options.length <= 1 || bfSel.dataset.forProduct !== pk) {
          bfSel.innerHTML = '<option value="">All Banks</option>';
          currentBanks.forEach(b => {
            const opt = document.createElement('option');
            opt.value = b.id; opt.textContent = b.name;
            bfSel.appendChild(opt);
          });
          bfSel.dataset.forProduct = pk;
        }
      }

      let cats = allCats;
      if (bankFilter) cats = cats.filter(c => String(c.bankId) === String(bankFilter));

      if (!cats.length) {
        tbody.innerHTML = `<tr><td colspan="6" style="text-align:center;color:var(--text3);padding:24px">${allCats.length ? 'No categories for the selected bank.' : 'No categories yet — click ＋ Add Category to create one.'}</td></tr>`;
        return;
      }
      tbody.innerHTML = cats.map(c => {
        const bank = LA_DB.banks.find(b => b.id === c.bankId);
        const TIER_COLORS = { gold:'#d97706', silver:'#6b7280', platinum:'#7c3aed', standard:'var(--accent)', premium:'var(--success)' };
        const tierColor = TIER_COLORS[c.color] || 'var(--text3)';
        return `<tr>
          <td><strong style="color:${tierColor}">${c.name}</strong></td>
          <td style="font-size:12px;color:var(--text2)">${bank ? bank.name : '—'}</td>
          <td style="font-family:monospace">₹${(c.minTurnover||0).toLocaleString('en-IN')}</td>
          <td><span style="font-size:11px;padding:2px 10px;border-radius:20px;background:${tierColor}20;color:${tierColor};font-weight:700">${c.color||'standard'}</span></td>
          <td style="font-size:12px;color:var(--text3);max-width:180px;overflow:hidden;text-overflow:ellipsis">${c.notes||'—'}</td>
          <td>
            <button class="btn btn-ghost btn-sm" onclick="lcBlEditCategory(${c.id})" style="font-size:11px">✏</button>
            <button class="btn btn-ghost btn-sm" onclick="lcBlDeleteCategory(${c.id})" style="font-size:11px;color:var(--danger)">🗑</button>
          </td>
        </tr>`;
      }).join('');
    }

    function lcBlOpenAddCategoryModal(editId) {
      const pk      = _lcActiveProduct || 'business_loan';
      const allCats = _prEnsureCategories(pk);
      const editing = editId ? allCats.find(c => c.id === editId) : null;
      const prod    = LC_PRODUCTS.find(p => p.key === pk);
      const bankOptions = `<option value="">— Select Bank —</option>` + _prBanks(pk).map(b => `<option value="${b.id}" ${editing && editing.bankId===b.id?'selected':''}>${b.name}</option>`).join('');
      const ov = document.createElement('div');
      ov.style.cssText = 'position:fixed;inset:0;background:rgba(12,23,51,.45);backdrop-filter:blur(4px);z-index:800;display:flex;align-items:center;justify-content:center';
      ov.innerHTML = `
        <div style="background:var(--surface);border-radius:16px;width:min(420px,94vw);box-shadow:var(--shadow-lg);padding:24px">
          <div style="font-family:var(--font-head);font-size:15px;font-weight:800;margin-bottom:18px">${editing?'✏ Edit':'＋ Add'} ${prod?prod.name:pk} Category</div>
          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Category Name *</label>
            <input type="text" id="blcat-name" value="${editing?editing.name:''}" placeholder="e.g. Premium · Gold · Standard"
              style="width:100%;padding:9px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
          </div>
          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Bank *</label>
            <select id="blcat-bank" style="width:100%;padding:9px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;cursor:pointer">${bankOptions}</select>
          </div>
          <div class="form-group" style="margin-bottom:12px">
            <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Min Monthly Turnover (₹) *</label>
            <input type="number" id="blcat-turnover" value="${editing?editing.minTurnover:''}" placeholder="e.g. 200000"
              style="width:100%;padding:9px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;font-family:monospace;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
            <div class="form-group" style="margin:0">
              <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Color Tier</label>
              <select id="blcat-color" style="width:100%;padding:9px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none">
                <option value="standard" ${!editing||editing.color==='standard'?'selected':''}>Standard</option>
                <option value="silver"   ${editing&&editing.color==='silver'?'selected':''}>Silver</option>
                <option value="gold"     ${editing&&editing.color==='gold'?'selected':''}>Gold</option>
                <option value="platinum" ${editing&&editing.color==='platinum'?'selected':''}>Platinum</option>
                <option value="premium"  ${editing&&editing.color==='premium'?'selected':''}>Premium</option>
              </select>
            </div>
            <div class="form-group" style="margin:0">
              <label style="font-size:12px;font-weight:600;display:block;margin-bottom:5px">Notes</label>
              <input type="text" id="blcat-notes" value="${editing?editing.notes||'':''}" placeholder="Optional note"
                style="width:100%;padding:9px 12px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none;box-sizing:border-box">
            </div>
          </div>
          <div style="display:flex;gap:10px">
            <button class="btn btn-primary" style="flex:1" onclick="lcBlConfirmSaveCategory(${editId||'null'},this.closest('[style*=fixed]'))">✓ ${editing?'Update':'Add'} Category</button>
            <button class="btn btn-ghost" onclick="this.closest('[style*=fixed]').remove()">Cancel</button>
          </div>
        </div>`;
      document.body.appendChild(ov);
      setTimeout(() => ov.querySelector('#blcat-name')?.focus(), 50);
    }

    function lcBlEditCategory(id) { lcBlOpenAddCategoryModal(id); }

    function lcBlConfirmSaveCategory(editId, ov) {
      const name     = document.getElementById('blcat-name')?.value.trim();
      const bankId   = parseInt(document.getElementById('blcat-bank')?.value);
      const turnover = parseInt(document.getElementById('blcat-turnover')?.value) || 0;
      const color    = document.getElementById('blcat-color')?.value || 'standard';
      const notes    = document.getElementById('blcat-notes')?.value.trim() || '';
      if (!name)   { showToast('Category name is required', 'error'); return; }
      if (!bankId) { showToast('Please select a bank', 'error'); return; }
      const pk2     = _lcActiveProduct || 'business_loan';
      const allCats2 = _prEnsureCategories(pk2);
      if (editId) {
        const cat = allCats2.find(c => c.id === editId);
        if (cat) Object.assign(cat, { name, bankId, minTurnover: turnover, color, notes });
      } else {
        allCats2.push({ id: LA_DB.nextId.prCat[pk2]++, name, bankId, minTurnover: turnover, color, notes });
      }
      ov.remove();
      lcBlRenderCategories();
      if (typeof persistSave === 'function') persistSave();
      showToast(`Category "${name}" ${editId?'updated':'added'} ✓`, 'success');
    }

    function lcBlDeleteCategory(id) {
      const pk3 = _lcActiveProduct || 'business_loan';
      const cats = _prEnsureCategories(pk3);
      LA_DB.productCategories[pk3] = cats.filter(c => c.id !== id);
      lcBlRenderCategories();
      if (typeof persistSave === 'function') persistSave();
      showToast('Category deleted', 'info');
    }

