    document.addEventListener('DOMContentLoaded', function () {
      // Restore uploaded logos from previous session
      try {
        const savedLogo = localStorage.getItem('efin_logo');
        if (savedLogo) { applyLogoToSidebar(savedLogo); }
        // Restore sign-in page logo — fetch from server first (persists across sessions),
        // fall back to localStorage cache if server unavailable
        (async function() {
          try {
            const r = await fetch('/api/settings/signin-logo');
            if (r.ok) {
              const d = await r.json();
              const serverLogo = d && d.logo;
              if (serverLogo) {
                applyLogoToLogin(serverLogo);
                try { localStorage.setItem('efin_signin_logo', serverLogo); } catch(e) {}
              } else {
                // No server logo — use localStorage cache if available
                const cached = localStorage.getItem('efin_signin_logo');
                if (cached) applyLogoToLogin(cached);
              }
            } else {
              const cached = localStorage.getItem('efin_signin_logo');
              if (cached) applyLogoToLogin(cached);
            }
          } catch(e) {
            const cached = localStorage.getItem('efin_signin_logo');
            if (cached) applyLogoToLogin(cached);
          }
        })();
        // If no signin logo saved, efin-logo.png is already set as src in HTML
        const savedBanner = localStorage.getItem('efin_banner_logo');
        if (savedBanner) applyBannerLogoToSidebar(savedBanner);
        // Restore sizes
        const iconSize = localStorage.getItem('efin_logo_icon_size');
        if (iconSize) brandingUpdateIconSize(parseInt(iconSize), false);
        const bannerSize = localStorage.getItem('efin_logo_banner_size');
        if (bannerSize) brandingUpdateBannerSize(parseInt(bannerSize), false);
        // Restore brand text
        const savedName = localStorage.getItem('efin_brand_name');
        const savedSub  = localStorage.getItem('efin_brand_sub');
        const sName = document.getElementById('sidebar-logo-text');
        const sSub  = document.getElementById('sidebar-logo-sub');
        if (savedName && sName) sName.textContent = savedName;
        if (savedSub  && sSub)  sSub.textContent  = savedSub;
      } catch(err) {}

      // Start clock
      updateClock();
      setInterval(updateClock, 30000);

      // Render dashboard charts
      renderPipeline();
      renderChart();
      renderLoanTypeChart();
      updateDashboardStats();
      updateGreeting();
      renderActivity();

      // Render applications table
      renderTable();

      // Render banks table
      renderBanksTable();

      // Render InCred page
      renderIncredPage();

      // Init notification badge
      updateNotifBadge();

      // Render access rights (pre-load)
      renderAccessRights();

      // Apply session for default user shown on login screen
      applySession();

      // Init payout claims with sample cross-partner data for Accounts view
      initSamplePayoutData();

      // Populate analytic company dropdown in wizard
      laPopulateWizardCompanySelect();

      // Populate wizard step 1 location + sales person dropdowns
      initWizardStep1Dropdowns();

      // Init loan management features
      initLoanFeatures();
    });
  

    // ══════════════════════════════════════════════════
    //  IN-MEMORY STORES  (mirrors model records)
    // ══════════════════════════════════════════════════

    // task.assign store
    window.TASK_STORE = window.TASK_STORE || [];
    var TASK_STORE = window.TASK_STORE;
    var taskNextId = 1;

    // incred.rm.email store
    var RM_EMAILS = [
    ];
    var rmNextId = 4;
    window.RM_EMAILS = RM_EMAILS; // expose for _refreshIncredTab in app-core.js
;

    // running_loan_bank_line (obligations) per application
    var OBLIGATIONS = {};   // { appId: [ {id, loan_type, sanction_amt, financer_name, loan_emi, amount_out, loan_closure_date, select_bt} ] }
    let oblNextId = 1;

    // ══════════════════════════════════════════════════
    //  INIT
    // ══════════════════════════════════════════════════
    function initLoanFeatures() {
      // Patch openDetail to also render new tabs (guard prevents double-wrap)
      if (!window.openDetail || !window.openDetail._loanFeaturePatched) {
        var _origOpenDetail = window.openDetail;
        window.openDetail = function (id) {
          if (_origOpenDetail) _origOpenDetail(id);
          renderObligationsTab(id);
          renderTasksTab(id);
          renderFoirPanel(id);
        };
        window.openDetail._loanFeaturePatched = true;
      }

      // Patch holdApp to use modal instead of prompt
      window.holdApp = function (id) {
        const app = APPLICATIONS.find(a => a.id === id);
        if (!app) return;
        document.getElementById('hold-app-id').value = id;
        document.getElementById('hold-reason-input').value = app.hold_reason || '';
        openModal('modal-hold-reason');
      };

      // Patch rejectApp to use rejection modal
      window.rejectApp = function (id) {
        document.getElementById('reject-app-id').value = id;
        document.getElementById('reject-reason-select').value = '';
        var lbl = document.getElementById('reject-dd-label');
        if (lbl) { lbl.textContent = '— Select Reason —'; lbl.style.color = 'var(--text3)'; }
        var list = document.getElementById('reject-dd-list');
        if (list) list.style.display = 'none';
        openModal('modal-reject-reason');
      };

      // Patch showPage to register extra page titles
      var _origSP = window.showPage;
      window.showPage = function (name, navEl) {
        _origSP(name, navEl);
        const titles = {
          'rm-emails': 'InCred RM Emails',
        };
        if (titles[name]) document.getElementById('page-title').textContent = titles[name];
      };

      // Update wizard validation to add PAN 45-day check + auto-uppercase
      var _origValidateStep = window.validateStep;
      window.validateStep = function (step) {
        if (step === 1) {
          const pan = (document.getElementById('w-pan')?.value || '').toUpperCase();
          if (pan) {
            // Auto-uppercase PAN
            if (document.getElementById('w-pan')) document.getElementById('w-pan').value = pan;
            // 45-day duplicate check
            const cutoff = new Date(); cutoff.setDate(cutoff.getDate() - 45);
            const dup = APPLICATIONS.find(a => a.pan && a.pan.toUpperCase() === pan && !a.is_draft &&
              new Date(a.login_date || a.date) >= cutoff);
            if (dup) {
              const daysAgo = Math.floor((new Date() - new Date(dup.login_date || dup.date)) / (1000 * 60 * 60 * 24));
              showToast(`PAN ${pan} has an application from ${daysAgo} days ago (${dup.id}). Must wait 45 days.`, 'error');
              return false;
            }
          }
        }
        // Name fields preserve exact casing as extracted by KYC (no forced uppercase)
        return _origValidateStep ? _origValidateStep(step) : true;
      };

      // Populate RM select in wizard
      populateRmSelect();

      // Render RM email page if it exists
      if (document.getElementById('page-rm-emails')) renderRmEmails();
    }

    // ══════════════════════════════════════════════════
    //  HOLD REASON MODAL  (mirrors action_hold in loan_application.py)
    // ══════════════════════════════════════════════════
    function confirmHold() {
      const id = document.getElementById('hold-app-id').value;
      const reason = document.getElementById('hold-reason-input').value.trim();
      if (!reason) { showToast('Please enter a hold reason before submitting', 'error'); return; }
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app) return;
      // Snapshot the exact current stage so un-hold can resume from here
      app.preHoldStatus = app.status;
      app.hold_reason = reason;
      app.hold_start_time = new Date().toISOString();
      changeStatus(id, 'hold');
      addTrackingEntry(app, 'EFIN-Hold Reason', 'Hold', 'On Hold by ' + currentUser.name, reason);
      closeModal('modal-hold-reason');
      showToast('Application placed on hold', 'warn');
      if (currentDetail && currentDetail.id === id) openDetail(id);
    }

    // ══════════════════════════════════════════════════
    //  REJECT REASON MODAL  (mirrors action_rejected)
    // ══════════════════════════════════════════════════
    function confirmReject() {
      const id = document.getElementById('reject-app-id').value;
      const reason = document.getElementById('reject-reason-select').value;
      const app = APPLICATIONS.find(a => a.id === id);
      if (!reason) { showToast('Please select a rejection reason', 'error'); return; }
      if (!app) return;
      // Check pending tasks (mirrors action_rejected validation)
      const pending = (TASK_STORE.filter(t => t.appId === id && t.status !== 'done') || []);
      if (pending.length) { showToast(`Complete ${pending.length} pending task(s) before rejecting`, 'error'); return; }
      app.rejection_reason = reason;
      app.login_end_date_time = new Date().toISOString();
      // Snapshot the exact current stage so re-open can resume from here
      app.preRejectedStatus = app.status;
      app.rejectedAt = new Date().toISOString();
      changeStatus(id, 'rejected');
      closeModal('modal-reject-reason');
      if (currentDetail && currentDetail.id === id) openDetail(id);
    }

    // ══════════════════════════════════════════════════
    //  DISBURSE ACTION  (mirrors action_disburse in loan_application.py)
    // ══════════════════════════════════════════════════
    function disburseApp(id, triggerEl) {
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app) return;
      // Check pending tasks
      const pending = TASK_STORE.filter(t => t.appId === id && t.status !== 'done');
      if (pending.length) {
        showToast(`${pending.length} pending task(s) must be completed before disbursement`, 'error');
        return;
      }
      app.disbursement_date = new Date().toLocaleDateString('en-IN');
      app.login_end_date_time = new Date().toISOString();
      changeStatus(id, 'disbursed', triggerEl);
      if (currentDetail && currentDetail.id === id) openDetail(id);
    }

    // ══════════════════════════════════════════════════
    //  TASK ASSIGN  (mirrors task_assign.py)
    // ══════════════════════════════════════════════════
    var TASK_TYPES = {
      detail_ver: 'Details Verification',
      pd: 'Pending Documents',
      disbures: 'Disbursement',
      cad: 'Complete Application Data',
      eav: 'Error Application Verification',
      other: 'Other',
    };

    function renderTasksTab(appId) {
      const container = document.getElementById('tasks-tab-body');
      if (!container) return;
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      const tasks = TASK_STORE.filter(t => t.appId === appId);
      const pendingCount = tasks.filter(t => t.status !== 'done').length;
      const doneCount    = tasks.filter(t => t.status === 'done').length;
      const highCount    = tasks.filter(t => t.priority === 'high' && t.status !== 'done').length;

      const badge = document.getElementById('pending-task-badge');
      if (badge) { badge.textContent = pendingCount || ''; badge.style.display = pendingCount ? '' : 'none'; }

      const rd = ROLES[currentUser.role];
      const priColor = { high:'#dc2626', medium:'#b45309', low:'#15803d' };
      const priBg    = { high:'rgba(212,43,43,.09)', medium:'rgba(230,126,0,.09)', low:'rgba(26,115,64,.08)' };
      const priLabel = { high:'\ud83d\udd34 High', medium:'\ud83d\udfe1 Medium', low:'\ud83d\udfe2 Low' };
      const typeIcon = { detail_ver:'\ud83d\udd0d', pd:'\ud83d\udcc4', disbures:'\ud83d\udcb0', cad:'\ud83d\udcdd', eav:'\u26a0\ufe0f', other:'\ud83d\udccc' };
      const today = new Date(); today.setHours(0,0,0,0);

      const taskRows = tasks.map(t => {
        const isDone   = t.status === 'done';
        const pri      = t.priority || 'medium';
        const overdue  = !isDone && t.due_date && new Date(t.due_date) < today;
        const dueText  = t.due_date ? new Date(t.due_date).toLocaleDateString('en-IN', {day:'2-digit',month:'short',year:'numeric'}) : null;
        const canComplete = !isDone && (currentUser.name === t.user_name || rd.canChangeStatus);
        return `<div id="task-card-${t.id}" style="background:var(--surface);border:1.5px solid ${isDone?'rgba(26,115,64,.2)':overdue?'rgba(212,43,43,.3)':'#dde8fb'};border-radius:14px;padding:16px 20px;margin-bottom:12px;transition:box-shadow .2s;box-shadow:0 2px 8px rgba(26,79,163,.04)" onmouseenter="this.style.boxShadow='0 4px 20px rgba(26,79,163,.1)'" onmouseleave="this.style.boxShadow='0 2px 8px rgba(26,79,163,.04)'">
          <div style="display:flex;align-items:flex-start;gap:14px">
            <div style="width:44px;height:44px;border-radius:12px;background:${isDone?'rgba(26,115,64,.1)':priBg[pri]};display:flex;align-items:center;justify-content:center;font-size:20px;flex-shrink:0">${isDone ? '\u2705' : (typeIcon[t.assign_type]||'\ud83d\udccc')}</div>
            <div style="flex:1;min-width:0">
              <div style="display:flex;align-items:center;flex-wrap:wrap;gap:6px;margin-bottom:4px">
                <span style="font-size:14px;font-weight:800;color:var(--text)">${TASK_TYPES[t.assign_type]||t.assign_type}</span>
                ${t.name ? `<span style="font-size:11.5px;color:var(--text3)">· ${t.name}</span>` : ''}
              </div>
              <div style="display:flex;flex-wrap:wrap;gap:6px;margin-bottom:8px">
                <span style="font-size:10.5px;font-weight:700;background:${isDone?'rgba(26,115,64,.1)':'rgba(230,126,0,.1)'};color:${isDone?'#15803d':'#b45309'};padding:2px 9px;border-radius:99px;border:1px solid ${isDone?'rgba(26,115,64,.2)':'rgba(230,126,0,.2)'}">${isDone ? '\u2713 Done' : '\u23f3 Pending'}</span>
                ${!isDone ? `<span style="font-size:10.5px;font-weight:700;background:${priBg[pri]};color:${priColor[pri]};padding:2px 9px;border-radius:99px">${priLabel[pri]}</span>` : ''}
                ${overdue ? `<span style="font-size:10.5px;font-weight:700;background:rgba(212,43,43,.1);color:#dc2626;padding:2px 9px;border-radius:99px">\u26a0 Overdue</span>` : ''}
              </div>
              <div style="display:flex;flex-wrap:wrap;gap:12px;font-size:12px;color:var(--text3)">
                <span>\ud83d\udc64 <strong style="color:var(--text)">${t.user_name||'\u2014'}</strong></span>
                <span>By: ${t.assign_user||currentUser.name}</span>
                <span>\ud83d\udcc5 ${t.date_assigned||'\u2014'}</span>
                ${dueText ? `<span style="color:${overdue?'#dc2626':'var(--text3)'}">Due: <strong>${dueText}</strong></span>` : ''}
              </div>
              ${t.remarks ? `<div style="font-size:12px;color:var(--text2);margin-top:8px;padding:8px 12px;background:var(--surface2);border-radius:8px;border-left:3px solid var(--accent)">\ud83d\udcac ${t.remarks}</div>` : ''}
              ${isDone && t.completion_remark ? `<div style="font-size:12px;margin-top:8px;padding:8px 12px;background:rgba(26,115,64,.06);border-radius:8px;border-left:3px solid #15803d;color:#14532d">\u2705 <strong>Completed by ${t.completed_user||'\u2014'}</strong> on ${t.completion_date||'\u2014'}<br><span style="color:var(--text2)">${t.completion_remark}</span></div>` : ''}
            </div>
            ${canComplete ? `<div style="display:flex;flex-direction:column;gap:6px;flex-shrink:0">
              <button class="btn btn-success btn-sm" onclick="openTaskCompleteModal(${t.id})" style="white-space:nowrap">\u2713 Mark Done</button>
              <button class="btn btn-ghost btn-sm" onclick="openTaskTransferModal(${t.id})" style="white-space:nowrap">\ud83d\udd04 Transfer</button>
            </div>` : ''}
          </div>
        </div>`;
      }).join('');

      container.innerHTML =
        `<div style="display:flex;align-items:center;gap:10px;margin-bottom:18px;background:linear-gradient(135deg,#eef4ff,#e8f0fe);border:1.5px solid #c8d8f8;border-radius:14px;padding:14px 18px;flex-wrap:wrap">
          <span style="font-size:20px">\ud83d\udccb</span>
          <div style="font-family:var(--font-head);font-size:16px;font-weight:800;color:var(--text)">Task Assignments</div>
          <span style="font-size:11px;font-weight:700;background:rgba(230,126,0,.12);color:#b45309;padding:3px 12px;border-radius:99px;border:1px solid rgba(230,126,0,.25)">${pendingCount} Pending</span>
          <span style="font-size:11px;font-weight:700;background:rgba(26,115,64,.1);color:#15803d;padding:3px 12px;border-radius:99px;border:1px solid rgba(26,115,64,.2)">${doneCount} Done</span>
          ${highCount ? `<span style="font-size:11px;font-weight:700;background:rgba(212,43,43,.09);color:#dc2626;padding:3px 12px;border-radius:99px;border:1px solid rgba(212,43,43,.2)">\ud83d\udd34 ${highCount} High Priority</span>` : ''}
          ${rd.canChangeStatus ? `<button class="btn btn-primary btn-sm" style="margin-left:auto" onclick="openTaskModal('${appId}')">\uff0b Assign Task</button>` : ''}
        </div>
        ${tasks.length === 0 ? `<div style="text-align:center;padding:56px 24px;background:var(--surface2);border-radius:16px;border:1.5px dashed #c8d8f8"><div style="font-size:44px;margin-bottom:12px">\ud83d\udccb</div><div style="font-family:var(--font-head);font-size:16px;font-weight:700;margin-bottom:6px;color:var(--text)">No Tasks Yet</div><div style="font-size:13px;color:var(--text3);margin-bottom:20px">Assign the first task to get started</div>${rd.canChangeStatus ? `<button class="btn btn-primary btn-sm" onclick="openTaskModal('${appId}')">\uff0b Assign First Task</button>` : ''}</div>` : ''}
        ${taskRows}`;
    }

    function setTaskPriority(p) {
      document.getElementById('task-assign-priority').value = p;
      const styles = {
        low:    { border:'#86efac', bg:'rgba(26,115,64,.12)',  color:'#15803d', label:'🟢 Low'    },
        medium: { border:'#f59e0b', bg:'rgba(245,158,11,.15)', color:'#b45309', label:'🟡 Medium' },
        high:   { border:'#f87171', bg:'rgba(212,43,43,.12)',  color:'#dc2626', label:'🔴 High'   },
      };
      ['low','medium','high'].forEach(k => {
        const el = document.getElementById('task-pri-' + k);
        if (!el) return;
        const s = styles[k];
        if (k === p) {
          el.style.borderColor = s.border; el.style.background = s.bg;
          el.style.color = s.color; el.style.fontWeight = '800';
          el.style.boxShadow = '0 2px 8px ' + s.bg;
        } else {
          el.style.borderColor = 'var(--border2)'; el.style.background = 'var(--surface2)';
          el.style.color = 'var(--text3)'; el.style.fontWeight = '600';
          el.style.boxShadow = 'none';
        }
      });
    }

    function onTaskTypeChange() {
      const type = document.getElementById('task-assign-type')?.value;
      const warn = document.getElementById('task-pd-warning');
      if (warn) warn.style.display = (type === 'pd') ? 'block' : 'none';
    }

    // ── Transfer an existing task to another user (Assigned To only; Assigned By is never changed) ──
    function openTaskTransferModal(taskId) {
      const t = (window.TASK_STORE || []).find(x => x.id === taskId);
      if (!t) return;
      // Same permission rule as the Mark Done button: only the current assignee (or the same admin-equivalent) may transfer.
      const rd = ROLES[currentUser.role];
      if (!(currentUser.name === t.user_name || rd.canChangeStatus)) { showToast('Only the current assignee can transfer this task', 'error'); return; }

      const allNames = new Set();
      (typeof USER_ACCOUNTS !== 'undefined' ? USER_ACCOUNTS : []).forEach(u => allNames.add(u.name));
      (typeof twUsers !== 'undefined' ? twUsers : []).forEach(u => allNames.add(u.name));
      allNames.delete(t.user_name);
      const items = [...allNames].sort().map(n => ({ value: n, label: n }));
      if (!items.length) { showToast('No other users available to transfer to', 'warn'); return; }

      const html = `
        <div class="modal-overlay" id="modal-task-transfer" style="display:flex" onclick="if(event.target===this)this.remove()">
          <div class="modal" style="max-width:420px">
            <div class="modal-header"><h3>\ud83d\udd04 Transfer Task</h3><button class="modal-close" onclick="document.getElementById('modal-task-transfer').remove()">&times;</button></div>
            <div class="modal-body">
              <div class="form-group"><label>Transfer to</label>
                <input type="hidden" id="task-transfer-user-hidden">
                <div class="wsdd-wrap" id="wsdd-task-transfer-user"></div>
              </div>
            </div>
            <div class="modal-footer">
              <button class="btn btn-ghost btn-sm" onclick="document.getElementById('modal-task-transfer').remove()">Cancel</button>
              <button class="btn btn-primary btn-sm" onclick="confirmTaskTransfer(${taskId})">Transfer</button>
            </div>
          </div>
        </div>`;
      document.body.insertAdjacentHTML('beforeend', html);
      if (typeof wsddCreate === 'function') {
        wsddCreate('wsdd-task-transfer-user', {
          placeholder: '— Select User —',
          searchPlaceholder: 'Search user…',
          hiddenId: 'task-transfer-user-hidden',
          allowEmpty: true,
          emptyLabel: '— Select User —',
          items,
        });
      }
    }

    function confirmTaskTransfer(taskId) {
      const t = (window.TASK_STORE || []).find(x => x.id === taskId);
      const newUser = document.getElementById('task-transfer-user-hidden')?.value;
      if (!t || !newUser) { showToast('Please select a user', 'error'); return; }
      const rd = ROLES[currentUser.role];
      if (!(currentUser.name === t.user_name || rd.canChangeStatus)) { showToast('Only the current assignee can transfer this task', 'error'); return; }
      // Only "Assigned To" changes — assign_user (Assigned By) is untouched.
      t.user_name = newUser;
      if (typeof persistSave === 'function') persistSave();
      const modal = document.getElementById('modal-task-transfer'); if (modal) modal.remove();
      if (typeof window.renderTasksPage === 'function') window.renderTasksPage();
      showToast('Task transferred to ' + newUser, 'success');
    }

    function openTaskModal(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      document.getElementById('task-app-id').value = appId;
      document.getElementById('task-assign-type').value = '';
      document.getElementById('task-assign-name').value = '';
      document.getElementById('task-assign-remarks').value = '';
      document.getElementById('task-assign-priority').value = 'medium';
      const dueEl = document.getElementById('task-assign-due');
      if (dueEl) {
        // Default due date: tomorrow
        const tmr = new Date(); tmr.setDate(tmr.getDate() + 1);
        dueEl.value = tmr.toISOString().split('T')[0];
      }
      const pdWarn = document.getElementById('task-pd-warning');
      if (pdWarn) pdWarn.style.display = 'none';

      // App label in header
      const lbl = document.getElementById('task-modal-app-label');
      if (lbl && app) lbl.textContent = app.id + ' · ' + app.name;

      // Set default priority to medium
      setTaskPriority('medium');

      // Populate users
      const userSelect = document.getElementById('task-assign-user');
      userSelect.innerHTML = '<option value="">— Select User —</option>';
      const allNames = new Set();
      (typeof USER_ACCOUNTS !== 'undefined' ? USER_ACCOUNTS : []).forEach(u => allNames.add(u.name));
      (typeof twUsers !== 'undefined' ? twUsers : []).forEach(u => allNames.add(u.name));
      [...allNames].sort().forEach(name => {
        const opt = document.createElement('option');
        opt.value = name;
        const acct = (typeof USER_ACCOUNTS !== 'undefined' ? USER_ACCOUNTS : []).find(u => u.name === name);
        const twU  = (typeof twUsers !== 'undefined' ? twUsers : []).find(u => u.name === name);
        const roleLabel = acct ? (ROLES[acct.role]?.label || acct.role) : (twU ? twU.role : '');
        opt.textContent = name + (roleLabel ? ' — ' + roleLabel : '');
        userSelect.appendChild(opt);
      });
      userSelect.value = '';
      openModal('modal-task-assign');
    }

    function saveTask() {
      const appId      = document.getElementById('task-app-id').value;
      const assign_type= document.getElementById('task-assign-type').value;
      const name       = document.getElementById('task-assign-name').value.trim();
      const user_name  = document.getElementById('task-assign-user').value.trim();
      const remarks    = document.getElementById('task-assign-remarks').value.trim();
      const priority   = document.getElementById('task-assign-priority')?.value || 'medium';
      const due_date   = document.getElementById('task-assign-due')?.value || '';

      if (!assign_type) { showToast('Please select a Task Type', 'error'); return; }
      if (!user_name)   { showToast('Please select a user to assign the task to', 'error'); return; }

      const now = new Date();
      const task = {
        id: taskNextId++,
        appId,
        assign_type,
        name,
        user_name,
        remarks,
        priority,
        due_date,
        assign_user: currentUser.name,
        date_assigned: now.toLocaleDateString('en-IN') + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' }),
        status: 'open',
        completed_user: null,
        completion_date: null,
        completion_remark: null,
      };
      TASK_STORE.push(task);
      closeModal('modal-task-assign');

      const app = APPLICATIONS.find(a => a.id === appId);
      if (app) {
        addTrackingEntry(app, 'Task — ' + (TASK_TYPES[assign_type] || assign_type), ROLES[currentUser.role]?.dept || 'Admin',
          'Task Assigned',
          remarks || 'No remarks');
      }

      const priorityLabel = { low: '🟢 Low', medium: '🟡 Medium', high: '🔴 High' }[priority] || priority;
      showToast(`📋 Task assigned to ${user_name} · ${priorityLabel} priority`, 'success');

      renderTasksTab(appId);
      renderTrackingSection(app || currentDetail);
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
    }

    function openTaskCompleteModal(taskId) {
      const task = TASK_STORE.find(t => t.id === taskId);
      document.getElementById('task-complete-id').value = taskId;
      document.getElementById('task-completion-remark').value = '';

      // Show task summary in modal
      const meta  = document.getElementById('task-complete-meta');
      const sumEl = document.getElementById('task-complete-summary');
      if (task) {
        if (meta) meta.textContent = TASK_TYPES[task.assign_type] || task.assign_type;
        if (sumEl) {
          const priColor = { high:'#dc2626', medium:'#b45309', low:'#15803d' }[task.priority||'medium'];
          const priLabel = { high:'🔴 High', medium:'🟡 Medium', low:'🟢 Low' }[task.priority||'medium'];
          sumEl.innerHTML =
            `<div style="display:flex;flex-wrap:wrap;gap:10px;font-size:12.5px">
              <div><span style="color:var(--text3)">Type: </span><strong>${TASK_TYPES[task.assign_type]||task.assign_type}</strong></div>
              <div><span style="color:var(--text3)">Assigned by: </span><strong>${task.assign_user||'—'}</strong></div>
              <div><span style="color:var(--text3)">On: </span><strong>${task.date_assigned||'—'}</strong></div>
              ${task.due_date?`<div><span style="color:var(--text3)">Due: </span><strong>${task.due_date}</strong></div>`:''}
              <div><span style="color:var(--text3)">Priority: </span><strong style="color:${priColor}">${priLabel}</strong></div>
            </div>
            ${task.remarks?`<div style="margin-top:8px;padding:8px 10px;background:var(--surface);border-radius:6px;font-size:12px;color:var(--text2);border:1px solid var(--border)">💬 ${task.remarks}</div>`:''}`;
        }
      }
      openModal('modal-task-complete');
    }

    function completeTask() {
      const taskId = parseInt(document.getElementById('task-complete-id').value);
      const remark = document.getElementById('task-completion-remark').value.trim();
      if (!remark) { showToast('Completion remark is required (task_assign.py validation)', 'error'); return; }
      const task = TASK_STORE.find(t => t.id === taskId);
      if (!task) return;

      // PD type requires documents check (mirrors action_status_done validation)
      // (skipped in UI as file upload not tracked per task here — shown as warning only)
      if (task.assign_type === 'pd') {
        showToast('Note: Ensure required documents are attached before completing a PD task', 'warn');
      }

      task.status = 'done';
      task.completed_user = currentUser.name;
      task.completion_date = new Date().toLocaleDateString('en-IN');
      task.completion_remark = remark;
      closeModal('modal-task-complete');

      // Create tracking entry for completion (mirrors write→_action_create_tracking)
      const app = APPLICATIONS.find(a => a.id === task.appId);
      if (app) {
        addTrackingEntry(app, 'Task Clear', 'CPA Check', 'Completed', remark);
      }
      showToast('Task marked as done', 'success');
      renderTasksTab(task.appId);
      if (app) renderTrackingSection(app);
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
    }

    // ══════════════════════════════════════════════════
    //  RUNNING LOAN OBLIGATIONS  (mirrors running_loan_bank_line.py)
    //  + FOIR eligibility computation  (loan_application.py)
    // ══════════════════════════════════════════════════
    var OBL_LOAN_TYPES = {
      personal_loan: 'Personal Loan', business_loan: 'Business Loan', home_loan: 'Home Loan',
      loan_against_property: 'LAP', new_car_loan: 'New Car Loan', used_car_loan: 'Used Car Loan',
      credit_card_loan: 'Credit Card', over_draft: 'OD/CC',
      education_loan: 'Education', tw_loan: 'Two-Wheeler', educational_loans: 'App Loan',
      gold_loan: 'Gold Loan', consumer_loans: 'Consumer Loans', other: 'Other',
    };

    function renderObligationsTab(appId) {
      const container = document.getElementById('obligations-tab-body');
      if (!container) return;
      if (!OBLIGATIONS[appId]) OBLIGATIONS[appId] = [];
      const obls = OBLIGATIONS[appId];
      const rd = ROLES[currentUser.role];
      const canEdit = rd.canEditObligations;

      const totalEMI = obls.reduce((s, o) => s + (o.loan_emi || 0), 0);
      const totalOuts = obls.reduce((s, o) => s + (o.amount_out || 0), 0);
      const totalSanc = obls.reduce((s, o) => s + (o.sanction_amt || 0), 0);

      container.innerHTML = `
    <!-- Header bar -->
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;background:linear-gradient(135deg,#fff8ee,#fff3e0);border:1.5px solid #fcd8a0;border-radius:14px;padding:14px 20px;flex-wrap:wrap">
      <span style="font-size:22px">💳</span>
      <div>
        <div style="font-family:var(--font-head);font-size:16px;font-weight:800;color:var(--text)">Running Loan Obligations</div>
        <div style="font-size:11px;color:var(--text3);margin-top:1px">${obls.length} loan(s) · Total EMI ₹${totalEMI.toLocaleString('en-IN')} · Outstanding ₹${totalOuts.toLocaleString('en-IN')}</div>
      </div>
      ${canEdit ? `<button class="btn btn-primary btn-sm" style="margin-left:auto" onclick="openOblModal('${appId}')">＋ Add Obligation</button>` : `<span style="margin-left:auto;font-size:11px;color:var(--text3);background:rgba(138,150,180,.12);padding:4px 10px;border-radius:8px">👁 View Only</span>`}
    </div>

    ${obls.length === 0 ? `
    <div style="text-align:center;padding:50px;color:var(--text3);background:#fffaf5;border-radius:14px;border:1.5px dashed #fcd8a0">
      <div style="font-size:40px;margin-bottom:12px">💳</div>
      <div style="font-family:var(--font-head);font-size:15px;font-weight:700;margin-bottom:6px;color:var(--text2)">No Obligations Added</div>
      <div style="font-size:13px">${canEdit ? 'Click "+ Add Obligation" to add running loans' : 'No running loan obligations recorded'}</div>
    </div>` : `

    <!-- Obligations table -->
    <div class="table-wrap" style="border-radius:14px;overflow:hidden;border:1.5px solid #dde8fb;margin-bottom:4px">
      <table>
        <thead>
          <tr>
            <th style="width:130px">Loan Type</th>
            <th>Financer</th>
            <th style="text-align:right">Sanction Amt</th>
            <th style="text-align:right">EMI/mo</th>
            <th style="text-align:right">Outstanding</th>
            <th>Closure</th>
            <th>Loan A/c</th>
            <th style="text-align:center">BT</th>
            ${canEdit ? '<th style="width:80px;text-align:center">Actions</th>' : ''}
          </tr>
        </thead>
        <tbody>
          ${obls.map(o => `
          <tr id="obl-row-${o.id}">
            <td>
              ${canEdit ? `
              <select onchange="oblField('${appId}',${o.id},'loan_type',this.value)"
                style="width:100%;padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:11.5px;background:var(--surface2);color:var(--text)">
                ${Object.entries(OBL_LOAN_TYPES).map(([k, v]) => `<option value="${k}" ${o.loan_type === k ? 'selected' : ''}>${v}</option>`).join('')}
              </select>` : `<span style="font-size:12.5px">${OBL_LOAN_TYPES[o.loan_type] || o.loan_type}</span>`}
            </td>
            <td>
              ${canEdit ? `<input type="text" value="${o.financer_name || ''}" onchange="oblField('${appId}',${o.id},'financer_name',this.value)"
                style="width:100%;padding:4px 8px;border:1px solid var(--border);border-radius:6px;font-size:12px;background:var(--surface2);color:var(--text)" placeholder="Bank / NBFC">` : `<span>${o.financer_name || '—'}</span>`}
            </td>
            <td style="text-align:right">
              ${canEdit ? `<input type="number" value="${o.sanction_amt || ''}" onchange="oblField('${appId}',${o.id},'sanction_amt',+this.value)"
                style="width:100%;padding:4px 8px;border:1px solid var(--border);border-radius:6px;font-size:12px;text-align:right;background:var(--surface2);color:var(--text)" placeholder="0">` : `₹${Number(o.sanction_amt || 0).toLocaleString('en-IN')}`}
            </td>
            <td style="text-align:right">
              ${canEdit ? `<input type="number" value="${o.loan_emi || ''}" onchange="oblField('${appId}',${o.id},'loan_emi',+this.value)"
                style="width:100%;padding:4px 8px;border:1px solid var(--border);border-radius:6px;font-size:12px;text-align:right;background:var(--surface2);color:${o.loan_emi ? 'var(--warn)' : 'var(--text)'};font-weight:${o.loan_emi ? '700' : '400'}" placeholder="0">` : `<strong style="color:${o.loan_emi ? 'var(--warn)' : 'var(--text3)'}">₹${Number(o.loan_emi || 0).toLocaleString('en-IN')}</strong>`}
            </td>
            <td style="text-align:right">
              ${canEdit ? `<input type="number" value="${o.amount_out || ''}" onchange="oblField('${appId}',${o.id},'amount_out',+this.value)"
                style="width:100%;padding:4px 8px;border:1px solid var(--border);border-radius:6px;font-size:12px;text-align:right;background:var(--surface2);color:var(--text)" placeholder="0">` : `₹${Number(o.amount_out || 0).toLocaleString('en-IN')}`}
            </td>
            <td>
              ${canEdit ? `<input type="date" value="${o.loan_closure_date || ''}" onchange="oblField('${appId}',${o.id},'loan_closure_date',this.value)"
                style="width:100%;padding:4px 6px;border:1px solid var(--border);border-radius:6px;font-size:11.5px;background:var(--surface2);color:var(--text)">` : `<span style="font-size:12px">${o.loan_closure_date || '—'}</span>`}
            </td>
            <td>
              ${canEdit ? `<input type="text" value="${o.loan_acc_no || ''}" onchange="oblField('${appId}',${o.id},'loan_acc_no',this.value)"
                style="width:100%;padding:4px 8px;border:1px solid var(--border);border-radius:6px;font-size:11px;font-family:monospace;background:var(--surface2);color:var(--text)" placeholder="A/c no.">` : `<span style="font-family:monospace;font-size:11px">${o.loan_acc_no || '—'}</span>`}
            </td>
            <td style="text-align:center">
              <label style="display:inline-flex;align-items:center;gap:5px;cursor:${canEdit ? 'pointer' : 'default'};font-size:12px;font-weight:600;color:${o.select_bt ? 'var(--accent)' : 'var(--text3)'}">
                <input type="checkbox" ${o.select_bt ? 'checked' : ''} ${canEdit ? `onchange="toggleBT('${appId}',${o.id},this.checked)"` : 'disabled'}
                  style="width:auto;accent-color:var(--accent)">
                <span style="font-size:10px;text-transform:uppercase;letter-spacing:.5px">${o.select_bt ? 'BT' : '—'}</span>
              </label>
            </td>
            ${canEdit ? `
            <td style="text-align:center">
              <button class="btn btn-danger btn-sm" onclick="deleteObligation('${appId}',${o.id})" title="Delete obligation" style="padding:4px 10px">✕</button>
            </td>` : ''}
          </tr>`).join('')}
        </tbody>
        <!-- Totals footer -->
        <tfoot>
          <tr style="background:rgba(26,79,163,.04);font-weight:700">
            <td colspan="2" style="font-size:12px;color:var(--text2)">Totals (${obls.length} loan${obls.length !== 1 ? 's' : ''})</td>
            <td style="text-align:right;font-size:12px;color:var(--text)">₹${totalSanc.toLocaleString('en-IN')}</td>
            <td style="text-align:right;font-size:12.5px;color:var(--warn)">₹${totalEMI.toLocaleString('en-IN')}</td>
            <td style="text-align:right;font-size:12px;color:var(--text)">₹${totalOuts.toLocaleString('en-IN')}</td>
            <td colspan="${canEdit ? 4 : 3}"></td>
          </tr>
        </tfoot>
      </table>
    </div>
    ${!canEdit ? `<div style="font-size:11.5px;color:var(--text3);padding:6px 2px;display:flex;align-items:center;gap:6px">🔒 <span>Obligation editing is restricted for Partner and Sales Executive roles.</span></div>` : ''}`}
  `;

      // Render FOIR panel (always, above obligations)
      renderFoirPanel(appId);
    }

    // ── Inline field update for obligations ──
    function oblField(appId, oblId, field, value) {
      const obl = (OBLIGATIONS[appId] || []).find(o => o.id === oblId);
      if (!obl) return;
      obl[field] = value;
      // Re-render FOIR panel live on EMI/BT change
      if (['loan_emi', 'select_bt', 'amount_out'].includes(field)) {
        renderFoirPanel(appId);
        // Update totals row without full re-render
        const container = document.getElementById('obligations-tab-body');
        if (container) {
          const obls = OBLIGATIONS[appId] || [];
          const totalEMI = obls.reduce((s, o) => s + (o.loan_emi || 0), 0);
          const totalOuts = obls.reduce((s, o) => s + (o.amount_out || 0), 0);
          const totalSanc = obls.reduce((s, o) => s + (o.sanction_amt || 0), 0);
          const tfoot = container.querySelector('tfoot tr');
          if (tfoot) {
            const cells = tfoot.querySelectorAll('td');
            if (cells[0]) cells[0].textContent = `Totals (${obls.length} loan${obls.length !== 1 ? 's' : ''})`;
            if (cells[1]) cells[1].textContent = `₹${totalSanc.toLocaleString('en-IN')}`;
            if (cells[2]) { cells[2].textContent = `₹${totalEMI.toLocaleString('en-IN')}`; cells[2].style.color = 'var(--warn)'; }
            if (cells[3]) cells[3].textContent = `₹${totalOuts.toLocaleString('en-IN')}`;
          }
        }
      }
    }

    // ── FOIR state per app (in-memory cache; persisted to app.foirState via _persistFoirState) ──
    var FOIR_STATE = {}; // { appId: { foir, coAppSalary } }

    function getFoirState(appId) {
      if (!FOIR_STATE[appId]) {
        // Seed from the persisted value on the app object if one exists, so a
        // user's FOIR%/co-applicant salary selection survives a page reload
        // instead of always resetting to the default 50%/₹0.
        const app = (typeof APPLICATIONS !== 'undefined') ? APPLICATIONS.find(a => a.id === appId) : null;
        const saved = app && app.foirState;
        FOIR_STATE[appId] = saved
          ? { foir: saved.foir || 50, coAppSalary: saved.coAppSalary || 0 }
          : { foir: 50, coAppSalary: 0 };
      }
      // Enforce 40–80 range
      FOIR_STATE[appId].foir = Math.min(80, Math.max(40, FOIR_STATE[appId].foir));
      return FOIR_STATE[appId];
    }

    // Persist the current FOIR selection onto the app object (same object
    // already saved by persistSave() elsewhere) — reuses existing persistence,
    // no new storage mechanism.
    function _persistFoirState(appId) {
      const app = (typeof APPLICATIONS !== 'undefined') ? APPLICATIONS.find(a => a.id === appId) : null;
      if (!app) return;
      const st = FOIR_STATE[appId];
      if (!st) return;
      app.foirState = { foir: st.foir, coAppSalary: st.coAppSalary };
      if (typeof persistSave === 'function') persistSave();
    }

    function renderFoirPanel(appId) {
      const container = document.getElementById('foir-panel');
      if (!container) return;
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      const obls = OBLIGATIONS[appId] || [];
      const st = getFoirState(appId);

      // ── Income inputs ──
      const grossSalary   = app.salary || 0;
      const empType       = (app.empType || '').toUpperCase();
      const isSalaried    = empType === 'SALARIED';
      const isSelfEmp     = empType === 'SELFEMP' || empType === 'SELF_EMPLOYED';
      const loanType      = app.loanType || 'personal_loan';
      const cibil         = app.cibil   || 700;
      const coAppSalary   = st.coAppSalary || 0;

      // ── Net take-home for self-employed ──
      // Prefer verified ABB (Average Bank Balance) from a Perfios-verified bank
      // statement upload when available — reuses the existing uploadedDocs +
      // Perfios data already captured elsewhere (no new data source created).
      // Falls back to the existing 70%-of-gross estimate otherwise, so this
      // is purely additive: nothing changes for applications without a
      // Perfios-verified statement on file.
      const verifiedBankDoc = isSelfEmp && Array.isArray(app.uploadedDocs)
        ? app.uploadedDocs.find(d => d.perfiosVerified && d.perfiosData && d.perfiosData.abb > 0)
        : null;
      const primaryNetSalary = isSelfEmp
        ? (verifiedBankDoc ? Math.round(verifiedBankDoc.perfiosData.abb) : Math.round(grossSalary * 0.70))
        : grossSalary;
      const netIncomeSource = isSelfEmp
        ? (verifiedBankDoc ? 'verified' : 'estimated')
        : 'salaried';
      const combinedSalary = primaryNetSalary + coAppSalary;

      // ══════════════════════════════════════════════
      // ROI: CIBIL + loan-type matrix (industry-realistic)
      // ══════════════════════════════════════════════
      var ROI_MATRIX = {
        personal_loan:          { base: 14.0, cibilAdj: [{ min:750, r:11.5 },{ min:720, r:12.5 },{ min:700, r:13.5 },{ min:675, r:15.5 },{ min:650, r:18.0 },{ min:0, r:21.0 }] },
        business_loan:          { base: 15.0, cibilAdj: [{ min:750, r:12.5 },{ min:720, r:14.0 },{ min:700, r:15.5 },{ min:675, r:17.5 },{ min:650, r:20.0 },{ min:0, r:24.0 }] },
        home_loan:              { base:  9.0, cibilAdj: [{ min:800, r: 8.4 },{ min:750, r: 8.75},{ min:720, r: 9.25},{ min:700, r: 9.75},{ min:675, r:10.5 },{ min:0, r:11.5 }] },
        loan_against_property:  { base: 11.0, cibilAdj: [{ min:750, r: 9.5 },{ min:720, r:10.5 },{ min:700, r:11.5 },{ min:675, r:13.0 },{ min:0, r:15.0 }] },
        new_car_loan:           { base:  9.0, cibilAdj: [{ min:750, r: 7.5 },{ min:720, r: 8.25},{ min:700, r: 9.0 },{ min:675, r:10.0 },{ min:0, r:12.0 }] },
        used_car_loan:          { base: 13.0, cibilAdj: [{ min:750, r:11.0 },{ min:720, r:12.0 },{ min:700, r:13.0 },{ min:675, r:15.0 },{ min:0, r:18.0 }] },
        education_loan:         { base:  9.5, cibilAdj: [{ min:750, r: 8.0 },{ min:720, r: 9.0 },{ min:700, r: 9.5 },{ min:0, r:11.0 }] },
        over_draft:             { base: 14.0, cibilAdj: [{ min:750, r:12.0 },{ min:720, r:13.5 },{ min:700, r:14.5 },{ min:0, r:17.0 }] },
        gold_loan:              { base:  9.5, cibilAdj: [{ min:0, r: 9.5 }] },
        tw_loan:                { base: 16.0, cibilAdj: [{ min:750, r:13.0 },{ min:720, r:14.5 },{ min:700, r:16.0 },{ min:0, r:19.0 }] },
      };
      function getSuggestedROI(lt, cib) {
        const m = ROI_MATRIX[lt] || ROI_MATRIX['personal_loan'];
        const entry = m.cibilAdj.find(e => cib >= e.min);
        return entry ? entry.r : m.base;
      }
      const suggestedROI = getSuggestedROI(loanType, cibil);
      // Use app's stored rate if set and reasonable, else suggested
      const rate = (app.loanRate && app.loanRate >= 6 && app.loanRate <= 36) ? app.loanRate : suggestedROI;

      // ══════════════════════════════════════════════
      // FOIR suggestion — range clamped to 40–80%
      // Based on: loan type + emp type + income tier + CIBIL
      // ══════════════════════════════════════════════
      function getSuggestedFOIR(lt, empT, income, cib) {
        // Base by loan type
        let base = lt === 'home_loan' ? 60
                 : lt === 'loan_against_property' ? 60
                 : lt === 'business_loan' ? 55
                 : lt === 'new_car_loan' || lt === 'used_car_loan' ? 55
                 : 50; // personal / others
        // Income uplift
        if (income >= 200000) base = Math.min(base + 15, 75);
        else if (income >= 100000) base = Math.min(base + 10, 70);
        else if (income >= 75000)  base = Math.min(base + 5, 65);
        else if (income < 25000)   base = Math.max(base - 5, 40);
        // CIBIL adjustment
        if (cib >= 800)      base = Math.min(base + 5, 75);
        else if (cib >= 750) base = Math.min(base + 2, 72);
        else if (cib < 650)  base = Math.max(base - 8, 40);
        else if (cib < 675)  base = Math.max(base - 4, 42);
        // Self-employed: slightly lower cap (more income uncertainty)
        if (empT === 'SELFEMP' || empT === 'SELF_EMPLOYED') base = Math.max(base - 3, 40);
        // Clamp to 40–80
        return Math.min(80, Math.max(40, Math.round(base)));
      }
      const suggestedFoir = getSuggestedFOIR(loanType, empType, combinedSalary, cibil);

      // ── Cross-check against the assigned lender's FOIR limit (read-only) ──
      // Reuses the same BANKS_STORE lookup already used elsewhere (e.g. the
      // lender-email-workflow RM lookup) — no new data source, no change to
      // lender-matching logic itself, purely an informational comparison.
      const assignedBank = (window.BANKS_STORE || []).find(b => b.name === app.bank || b.name === (app.lenderName || ''));
      const assignedBankFoirLimit = assignedBank && assignedBank.rules && assignedBank.rules.foirLimit;
      const foirExceedsLenderLimit = !!(assignedBankFoirLimit && suggestedFoir > assignedBankFoirLimit);

      // User-selected FOIR — clamp to 40–80
      const rawFoir = st.foir;
      const foir = Math.min(80, Math.max(40, rawFoir || suggestedFoir));
      if (st.foir !== foir) st.foir = foir; // auto-correct if out of range

      const tenureMonths = parseInt(app.tenure || 36);

      // ── Going EMI: non-BT obligations ──
      const going_emi   = obls.filter(o => !o.select_bt).reduce((s, o) => s + (o.loan_emi || 0), 0);
      const bt_emi      = obls.filter(o =>  o.select_bt).reduce((s, o) => s + (o.loan_emi || 0), 0);
      const any_bt      = obls.some(o => o.select_bt);

      // ── Eligible EMI & availability ──
      const eligible_emi     = combinedSalary * foir / 100;
      const net_eligible_emi = Math.max(0, eligible_emi - going_emi);

      // ── Actual FOIR % (going EMI as % of net salary — key metric) ──
      const actualFoirPct    = combinedSalary > 0 ? (going_emi / combinedSalary) * 100 : 0;
      const newLoanEMI       = calcLoanEMI(net_eligible_emi, rate, tenureMonths); // proposed EMI
      const totalFoirAfter   = combinedSalary > 0 ? ((going_emi + newLoanEMI) / combinedSalary) * 100 : 0;

      // ── Utilisation of FOIR cap ──
      const utilisationPct   = eligible_emi > 0 ? Math.min(100, Math.round((going_emi / eligible_emi) * 100)) : 0;
      const utilColor = utilisationPct >= 90 ? 'var(--danger)' : utilisationPct >= 70 ? 'var(--warn)' : 'var(--success)';
      const utilLabel = utilisationPct >= 90 ? '🔴 Over-leveraged' : utilisationPct >= 70 ? '🟡 Moderate' : utilisationPct >= 40 ? '🟢 Healthy' : '🔵 Low';

      // ── Loan eligibility (PV formula) ──
      function calcLoan(emi, annualRate, months) {
        const r = annualRate / 12 / 100;
        if (!emi || !months) return 0;
        return r > 0 ? Math.round(emi * (1 - Math.pow(1 + r, -months)) / r) : emi * months;
      }
      function calcLoanEMI(loanAmt, annualRate, months) {
        const r = annualRate / 12 / 100;
        if (!loanAmt || !months) return 0;
        return r > 0 ? loanAmt * r * Math.pow(1 + r, months) / (Math.pow(1 + r, months) - 1) : loanAmt / months;
      }

      const eligible_loan  = calcLoan(net_eligible_emi, rate, tenureMonths);
      const max_possible   = calcLoan(eligible_emi,     rate, tenureMonths);
      const bt_benefit     = calcLoan(bt_emi,           rate, tenureMonths);
      const loanDiff       = eligible_loan - (app.amount || 0);

      // ── CIBIL-based multiplier (cross-check) ──
      const salaryMultiplier = loanType === 'home_loan' ? (cibil >= 750 ? 72 : 60)
        : loanType === 'business_loan' ? (cibil >= 750 ? 48 : 36)
        : (cibil >= 750 ? 30 : cibil >= 700 ? 24 : 18);
      const loan_by_mult = Math.round(primaryNetSalary * (isSalaried ? 1 : 0.75) * salaryMultiplier / 12);

      // ── Final eligible (conservative: min of FOIR method and multiplier) ──
      const conservative_eligible = Math.min(eligible_loan, loan_by_mult);

      // ── Outstanding summary ──
      const outstanding_non_bt = obls.filter(o => !o.select_bt).reduce((s, o) => s + (o.amount_out || 0), 0);
      const outstanding_bt     = obls.filter(o =>  o.select_bt).reduce((s, o) => s + (o.amount_out || 0), 0);

      // ── FOIR zone colour (40–80 range) ──
      const foirZoneColor = foir >= 70 ? 'var(--danger)' : foir >= 60 ? 'var(--warn)' : foir >= 50 ? 'var(--accent)' : 'var(--success)';
      const foirZoneLabel = foir >= 70 ? 'Aggressive' : foir >= 60 ? 'Moderate-High' : foir >= 50 ? 'Standard' : 'Conservative';

      // ── ROI risk label ──
      const roiRisk = rate >= 18 ? '🔴 High Risk' : rate >= 13 ? '🟡 Moderate' : '🟢 Prime';

      // ── DSCR (for business loans) ──
      const dscr = going_emi > 0 ? (combinedSalary / going_emi).toFixed(2) : '—';
      const dscrOk = going_emi > 0 ? combinedSalary / going_emi >= 1.5 : true;

      container.innerHTML = `
  <div style="background:linear-gradient(135deg,rgba(26,79,163,.04),rgba(212,43,43,.03));border:1.5px solid rgba(26,79,163,.15);border-radius:18px;padding:22px 24px;margin-top:18px">

    <!-- Header -->
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:18px;flex-wrap:wrap">
      <div>
        <div style="font-family:var(--font-head);font-size:15px;font-weight:800;color:var(--text)">📊 FOIR Eligibility Engine</div>
        <div style="font-size:11px;color:var(--text3);margin-top:2px">${isSelfEmp ? (netIncomeSource === 'verified' ? 'Self-Employed · Net income from verified bank statement' : 'Self-Employed · Net income est. 70% of gross') : 'Salaried'} · CIBIL ${cibil} · ${loanType.replace(/_/g,' ')}</div>
      </div>
      <div style="margin-left:auto;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
        <!-- ROI pill -->
        <div style="background:var(--surface);border:1px solid var(--border2);border-radius:10px;padding:6px 12px;font-size:12px;display:flex;flex-direction:column;align-items:center;min-width:80px">
          <span style="font-size:9px;color:var(--text3);font-weight:700;letter-spacing:.8px;text-transform:uppercase">ROI</span>
          <span style="font-family:var(--font-head);font-size:17px;font-weight:800;color:var(--accent)">${rate}%</span>
          <span style="font-size:9px;color:var(--text3)">${roiRisk}</span>
        </div>
        <!-- Suggested FOIR -->
        <div style="font-size:11.5px;color:var(--text3);background:rgba(26,79,163,.08);padding:5px 11px;border-radius:8px;line-height:1.5">
          Suggested: <strong style="color:var(--accent)">${suggestedFoir}%</strong><br>
          <span style="font-size:10px">₹${(combinedSalary/1000).toFixed(0)}K · CIBIL ${cibil}</span>
        </div>
        ${foirExceedsLenderLimit ? `<div style="font-size:10.5px;color:var(--danger);background:rgba(192,57,43,.08);padding:5px 11px;border-radius:8px;line-height:1.4;max-width:170px">⚠ Suggested ${suggestedFoir}% exceeds ${assignedBank.name}'s ${assignedBankFoirLimit}% limit</div>` : ''}
      </div>
    </div>

    <!-- FOIR slider (40–80) -->
    <div style="background:var(--surface);border:1px solid var(--border);border-radius:14px;padding:14px 18px;margin-bottom:16px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:10px;flex-wrap:wrap;gap:8px">
        <div style="display:flex;align-items:center;gap:10px">
          <span style="font-size:12px;font-weight:700;color:var(--text2)">FOIR</span>
          <span style="font-family:var(--font-head);font-size:22px;font-weight:800;color:${foirZoneColor}">${foir}%</span>
          <span style="font-size:10px;padding:2px 8px;border-radius:99px;background:${foir >= 70 ? 'rgba(192,57,43,.1)' : foir >= 60 ? 'rgba(230,126,0,.1)' : foir >= 50 ? 'rgba(26,79,163,.1)' : 'rgba(26,115,64,.1)'};color:${foirZoneColor};font-weight:700">${foirZoneLabel}</span>
        </div>
        <div style="display:flex;gap:6px;align-items:center;flex-wrap:wrap">
          ${[40, 50, 55, 60, 65, 70, 75, 80].map(f => `<button onclick="setFoir('${appId}',${f})" style="padding:3px 8px;border-radius:6px;border:1.5px solid ${foir===f ? foirZoneColor : 'var(--border2)'};cursor:pointer;font-size:11px;font-weight:700;transition:all .15s;background:${foir===f ? foirZoneColor : 'var(--surface2)'};color:${foir===f ? '#fff' : 'var(--text3)'}">${f}%</button>`).join('')}
        </div>
      </div>
      <!-- Slider -->
      <input type="range" min="40" max="80" step="1" value="${foir}"
        oninput="setFoir('${appId}',+this.value)"
        style="width:100%;accent-color:${foirZoneColor};height:6px;cursor:pointer">
      <div style="display:flex;justify-content:space-between;margin-top:4px;font-size:10px;color:var(--text3)">
        <span>40% Conservative</span>
        <span>60% Standard</span>
        <span>80% Max</span>
      </div>
    </div>

    <!-- EMI utilisation bar -->
    <div style="margin-bottom:18px">
      <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;flex-wrap:wrap;gap:4px">
        <span style="font-size:12px;color:var(--text2);font-weight:600">Current EMI Load (Actual FOIR)</span>
        <span style="font-size:12px;font-weight:700;color:${utilColor}">${utilLabel} · ${utilisationPct}% of cap used · Actual ${actualFoirPct.toFixed(1)}% of income</span>
      </div>
      <div style="background:var(--surface3);border-radius:99px;height:12px;overflow:hidden;position:relative">
        <div style="height:100%;border-radius:99px;width:${utilisationPct}%;background:${utilColor};transition:width .5s;position:relative">
          ${utilisationPct > 10 ? `<div style="position:absolute;right:4px;top:50%;transform:translateY(-50%);font-size:8px;color:#fff;font-weight:700">${utilisationPct}%</div>` : ''}
        </div>
      </div>
      <div style="display:flex;justify-content:space-between;margin-top:4px;font-size:10.5px;color:var(--text3)">
        <span>Going EMI ₹${Math.round(going_emi).toLocaleString('en-IN')}</span>
        <span>FOIR Cap ₹${Math.round(eligible_emi).toLocaleString('en-IN')} (${foir}% of ₹${Number(combinedSalary).toLocaleString('en-IN')})</span>
      </div>
      ${totalFoirAfter > 0 ? `
      <div style="margin-top:8px;display:flex;align-items:center;gap:8px;font-size:11px;color:var(--text3)">
        <span>After new loan:</span>
        <div style="flex:1;background:var(--surface3);border-radius:99px;height:6px;overflow:hidden">
          <div style="height:100%;border-radius:99px;width:${Math.min(100, totalFoirAfter / foir * 100).toFixed(1)}%;background:${totalFoirAfter > foir ? 'var(--danger)' : 'var(--accent)'}"></div>
        </div>
        <span style="font-weight:700;color:${totalFoirAfter > foir ? 'var(--danger)' : 'var(--accent)'}">FOIR → ${totalFoirAfter.toFixed(1)}%${totalFoirAfter > foir ? ' ⚠ Exceeds cap' : ' ✓'}</span>
      </div>` : ''}
    </div>

    <!-- 6 metric cards -->
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:14px">

      <!-- Net Income -->
      <div style="background:var(--surface);border:1.5px solid var(--border);border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--accent),transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">Net Income</div>
        <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:var(--text)">₹${Number(primaryNetSalary).toLocaleString('en-IN')}</div>
        ${isSelfEmp ? (netIncomeSource === 'verified'
          ? `<div style="font-size:10px;color:var(--success);margin-top:2px;font-weight:600">✓ Verified — Avg. Bank Balance</div>`
          : `<div style="font-size:10px;color:var(--text3);margin-top:2px">~70% of ₹${Number(grossSalary).toLocaleString('en-IN')} gross <span style="color:var(--warn)">(estimated)</span></div>`
        ) : ''}
        ${coAppSalary > 0 ? `<div style="font-size:11px;color:var(--danger);margin-top:3px;font-weight:600">+₹${Number(coAppSalary).toLocaleString('en-IN')} co-app</div>` : ''}
        <div style="font-size:10.5px;color:var(--text3);margin-top:3px">Combined ₹${Number(combinedSalary).toLocaleString('en-IN')}</div>
        <div style="margin-top:6px;padding:3px 8px;background:rgba(26,79,163,.08);border-radius:6px;font-size:10px;color:var(--accent);display:inline-block">${isSalaried ? '💼 Salaried' : '🏢 Self-Employed'}</div>
      </div>

      <!-- Eligible EMI -->
      <div style="background:var(--surface);border:1.5px solid rgba(26,79,163,.25);border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--accent),transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">Eligible EMI</div>
        <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:var(--accent)">₹${Math.round(eligible_emi).toLocaleString('en-IN')}</div>
        <div style="font-size:10.5px;color:var(--text3);margin-top:3px">₹${Number(combinedSalary).toLocaleString('en-IN')} × ${foir}%</div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px">Max EMI allowed · ROI ${rate}%</div>
        <div style="margin-top:6px;font-size:11px;color:var(--accent);font-weight:600">Net available: ₹${Math.round(net_eligible_emi).toLocaleString('en-IN')}</div>
      </div>

      <!-- ROI & CIBIL -->
      <div style="background:var(--surface);border:1.5px solid rgba(${cibil>=750?'26,115,64':cibil>=700?'230,126,0':'192,57,43'},.2);border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,${cibil>=750?'var(--success)':cibil>=700?'var(--warn)':'var(--danger)'},transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">ROI & CIBIL</div>
        <div style="display:flex;align-items:baseline;gap:8px">
          <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:var(--accent)">${rate}% p.a.</div>
          <div style="font-size:11px;color:${cibil>=750?'var(--success)':cibil>=700?'var(--warn)':'var(--danger)'};font-weight:700">CIBIL ${cibil}</div>
        </div>
        <div style="font-size:10px;color:var(--text3);margin-top:3px">${roiRisk} · ${loanType.replace(/_/g,' ')}</div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px">Suggested: ${suggestedROI}%${rate !== suggestedROI ? ` · Entered: ${rate}%` : ''}</div>
        <div style="margin-top:5px;font-size:10px;color:var(--text3)">Monthly rate: ${(rate/12).toFixed(3)}%</div>
      </div>

      <!-- Going EMI -->
      <div style="background:var(--surface);border:1.5px solid ${going_emi > 0 ? 'rgba(230,126,0,.3)' : 'var(--border)'};border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,${going_emi > 0 ? 'var(--warn)' : 'var(--border2)'},transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">Going EMI</div>
        <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:${going_emi > 0 ? 'var(--warn)' : 'var(--text3)'}">₹${Math.round(going_emi).toLocaleString('en-IN')}</div>
        ${bt_emi > 0 ? `<div style="font-size:10.5px;color:var(--danger);margin-top:2px;font-weight:600">+₹${Math.round(bt_emi).toLocaleString('en-IN')} BT (excluded)</div>` : ''}
        <div style="font-size:10.5px;color:var(--text3);margin-top:3px">Actual FOIR: <strong style="color:${actualFoirPct > foir ? 'var(--danger)' : 'var(--text)'}">${actualFoirPct.toFixed(1)}%</strong></div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px">${obls.filter(o=>!o.select_bt).length} active obligation(s)</div>
      </div>

      <!-- Available EMI -->
      <div style="background:${net_eligible_emi > 0 ? 'rgba(26,115,64,.06)' : 'rgba(192,57,43,.06)'};border:1.5px solid ${net_eligible_emi > 0 ? 'rgba(26,115,64,.25)' : 'rgba(192,57,43,.3)'};border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,${net_eligible_emi > 0 ? 'var(--success)' : 'var(--danger)'},transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">Available EMI</div>
        <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:${net_eligible_emi > 0 ? 'var(--success)' : 'var(--danger)'}">₹${Math.round(net_eligible_emi).toLocaleString('en-IN')}</div>
        <div style="font-size:10.5px;color:var(--text3);margin-top:3px">FOIR Cap − Going EMI</div>
        <div style="display:inline-block;margin-top:5px;padding:2px 8px;border-radius:99px;font-size:9.5px;font-weight:700;background:${net_eligible_emi > 0 ? 'rgba(26,115,64,.12)' : 'rgba(192,57,43,.12)'};color:${net_eligible_emi > 0 ? 'var(--success)' : 'var(--danger)'}">
          ${net_eligible_emi > 0 ? '✓ Surplus' : '✗ Deficit'}
        </div>
      </div>

      <!-- Eligible Loan -->
      <div style="background:rgba(212,43,43,.05);border:1.5px solid rgba(212,43,43,.25);border-radius:14px;padding:14px;position:relative;overflow:hidden">
        <div style="position:absolute;top:0;left:0;right:0;height:3px;background:linear-gradient(90deg,var(--accent2),transparent)"></div>
        <div style="font-size:9.5px;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:5px;font-weight:700">Eligible Loan</div>
        <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:var(--danger)">₹${Number(eligible_loan).toLocaleString('en-IN')}</div>
        <div style="font-size:10.5px;color:var(--text3);margin-top:3px">@ ${rate}% · ${tenureMonths}m · EMI ₹${Math.round(newLoanEMI).toLocaleString('en-IN')}/mo</div>
        <div style="font-size:10px;color:var(--text3);margin-top:2px">Conservative: ₹${Number(conservative_eligible).toLocaleString('en-IN')}</div>
      </div>

    </div>

    <!-- Detail breakdown (3 columns) -->
    <div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-bottom:14px">

      <!-- Loan vs Request -->
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:14px">
        <div style="font-size:11px;font-weight:700;color:var(--text2);margin-bottom:10px">📋 Loan vs Request</div>
        <div style="display:flex;flex-direction:column;gap:7px;font-size:12px">
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Requested</span>
            <span style="font-weight:600">₹${Number(app.amount || 0).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">FOIR-eligible</span>
            <span style="font-weight:700;color:${eligible_loan >= (app.amount||0) ? 'var(--success)' : 'var(--danger)'}">₹${Number(eligible_loan).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Conservative</span>
            <span style="font-weight:600;color:var(--accent)">₹${Number(conservative_eligible).toLocaleString('en-IN')}</span>
          </div>
          <div style="height:1px;background:var(--border)"></div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">${loanDiff >= 0 ? 'Headroom' : 'Shortfall'}</span>
            <span style="font-weight:700;color:${loanDiff >= 0 ? 'var(--success)' : 'var(--danger)'}">
              ${loanDiff >= 0 ? '↑' : '↓'} ₹${Math.abs(loanDiff).toLocaleString('en-IN')}
            </span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Max (no obls)</span>
            <span style="font-weight:600;color:var(--text)">₹${Number(max_possible).toLocaleString('en-IN')}</span>
          </div>
        </div>
      </div>

      <!-- EMI breakdown -->
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:14px">
        <div style="font-size:11px;font-weight:700;color:var(--text2);margin-bottom:10px">💳 EMI Breakdown</div>
        <div style="display:flex;flex-direction:column;gap:7px;font-size:12px">
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">FOIR Cap (${foir}%)</span>
            <span style="font-weight:600;color:var(--accent)">₹${Math.round(eligible_emi).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Going EMI</span>
            <span style="font-weight:600;color:${going_emi > 0 ? 'var(--warn)' : 'var(--text3)'}">₹${Math.round(going_emi).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Available EMI</span>
            <span style="font-weight:700;color:${net_eligible_emi > 0 ? 'var(--success)' : 'var(--danger)'}">₹${Math.round(net_eligible_emi).toLocaleString('en-IN')}</span>
          </div>
          <div style="height:1px;background:var(--border)"></div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Proposed EMI</span>
            <span style="font-weight:700;color:var(--accent)">₹${Math.round(newLoanEMI).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Total EMI after</span>
            <span style="font-weight:700;color:${(going_emi + newLoanEMI) > eligible_emi ? 'var(--danger)' : 'var(--success)'}">₹${Math.round(going_emi + newLoanEMI).toLocaleString('en-IN')}</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">CIBIL multiplier</span>
            <span style="font-weight:600;color:var(--text)">₹${Number(loan_by_mult).toLocaleString('en-IN')}</span>
          </div>
        </div>
      </div>

      <!-- Co-applicant + DSCR -->
      <div style="background:var(--surface);border:1px solid var(--border);border-radius:12px;padding:14px">
        <div style="font-size:11px;font-weight:700;color:var(--text2);margin-bottom:8px">👥 Co-App & Risk Metrics</div>
        <div style="font-size:11px;color:var(--text3);margin-bottom:8px">Co-applicant salary boosts eligibility</div>
        <div style="display:flex;gap:6px;align-items:center;margin-bottom:10px">
          <input type="number" id="coapp-salary-${appId}" value="${coAppSalary || ''}" placeholder="₹ Co-app monthly"
            style="flex:1;padding:7px 10px;border:1px solid var(--border);border-radius:8px;font-size:12px;outline:none;color:var(--text);background:var(--surface)"
            oninput="updateCoAppSalaryDebounced('${appId}',this.value)">
        </div>
        ${coAppSalary > 0 ? `
        <div style="padding:7px 10px;background:rgba(26,79,163,.07);border-radius:8px;font-size:11px;color:var(--accent);margin-bottom:8px">
          Combined: ₹${Number(combinedSalary).toLocaleString('en-IN')}<br>
          Extra eligible: ₹${calcLoan(coAppSalary * foir / 100, rate, tenureMonths).toLocaleString('en-IN')}
        </div>` : ''}
        <div style="height:1px;background:var(--border);margin-bottom:8px"></div>
        <div style="font-size:11px;display:flex;flex-direction:column;gap:5px">
          ${loanType === 'business_loan' || isSelfEmp ? `
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">DSCR</span>
            <span style="font-weight:700;color:${dscrOk ? 'var(--success)' : 'var(--danger)'}">${dscr} ${going_emi>0 ? (dscrOk?'✓':'⚠ <1.5')  : ''}</span>
          </div>` : ''}
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Actual FOIR%</span>
            <span style="font-weight:700;color:${actualFoirPct > 80 ? 'var(--danger)' : actualFoirPct > 60 ? 'var(--warn)' : 'var(--success)'}">${actualFoirPct.toFixed(1)}%</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Post-loan FOIR</span>
            <span style="font-weight:700;color:${totalFoirAfter > 80 ? 'var(--danger)' : totalFoirAfter > 60 ? 'var(--warn)' : 'var(--success)'}">${totalFoirAfter.toFixed(1)}%</span>
          </div>
          <div style="display:flex;justify-content:space-between">
            <span style="color:var(--text3)">Salary mult.</span>
            <span style="font-weight:600;color:var(--text)">${salaryMultiplier}× · ₹${Number(loan_by_mult).toLocaleString('en-IN')}</span>
          </div>
        </div>
      </div>
    </div>

    <!-- BT benefit banner -->
    ${any_bt ? `
    <div style="padding:11px 16px;background:rgba(26,79,163,.07);border:1px solid rgba(26,79,163,.2);border-radius:10px;font-size:12.5px;color:var(--accent);display:flex;align-items:center;gap:10px;margin-bottom:10px">
      <span style="font-size:18px">🔄</span>
      <span><strong>Balance Transfer:</strong> ₹${Math.round(bt_emi).toLocaleString('en-IN')}/mo excluded → boosts eligible loan by ₹${Number(bt_benefit).toLocaleString('en-IN')}</span>
    </div>` : ''}

    <!-- Outstanding warning -->
    ${outstanding_non_bt > 0 ? `
    <div style="padding:10px 14px;background:rgba(255,179,71,.08);border:1px solid rgba(255,179,71,.25);border-radius:8px;font-size:12px;color:var(--warn);display:flex;gap:8px;align-items:center">
      <span>⚠</span>
      <span>Non-BT outstanding: <strong>₹${Number(outstanding_non_bt).toLocaleString('en-IN')}</strong>${outstanding_bt > 0 ? ' · BT outstanding: ₹' + Number(outstanding_bt).toLocaleString('en-IN') : ''}</span>
    </div>` : ''}

  </div>`;
    }

    function setFoir(appId, val) {
      getFoirState(appId).foir = Math.min(80, Math.max(40, Number(val)));
      _persistFoirState(appId);
      renderFoirPanel(appId);
    }

    function updateCoAppSalary(appId, val) {
      getFoirState(appId).coAppSalary = parseInt(val) || 0;
      _persistFoirState(appId);
      renderFoirPanel(appId);
    }

    // Debounced version -- preserves input focus while user is typing
    var _coAppDebTimer = null;
    function updateCoAppSalaryDebounced(appId, val) {
      // Store the value immediately so it isn't lost
      getFoirState(appId).coAppSalary = parseInt(val) || 0;
      _persistFoirState(appId);
      // Debounce the full panel re-render by 600ms
      clearTimeout(_coAppDebTimer);
      _coAppDebTimer = setTimeout(function() {
        // Capture cursor position & value before re-render
        const inp = document.getElementById('coapp-salary-' + appId);
        const savedVal = inp ? inp.value : val;
        renderFoirPanel(appId);
        // Restore focus & value after re-render
        const newInp = document.getElementById('coapp-salary-' + appId);
        if (newInp) {
          newInp.value = savedVal;
          newInp.focus();
          // Place cursor at end
          const len = newInp.value.length;
          newInp.setSelectionRange(len, len);
        }
      }, 600);
    }

    function openOblModal(appId) {
      document.getElementById('obl-app-id').value = appId;
      ['obl-loan-type', 'obl-financer', 'obl-sanction', 'obl-emi', 'obl-outstanding', 'obl-closure', 'obl-accno'].forEach(id => {
        const el = document.getElementById(id); if (el) el.value = '';
      });
      document.getElementById('obl-select-bt').checked = false;
      openModal('modal-obligation');
    }

    function saveObligation() {
      const appId = document.getElementById('obl-app-id').value;
      const loan_type = document.getElementById('obl-loan-type').value;
      if (!loan_type) { showToast('Select loan type', 'error'); return; }
      if (!OBLIGATIONS[appId]) OBLIGATIONS[appId] = [];
      OBLIGATIONS[appId].push({
        id: oblNextId++,
        loan_type,
        financer_name: document.getElementById('obl-financer').value.trim(),
        sanction_amt: parseInt(document.getElementById('obl-sanction').value) || 0,
        loan_emi: parseInt(document.getElementById('obl-emi').value) || 0,
        amount_out: parseInt(document.getElementById('obl-outstanding').value) || 0,
        loan_closure_date: document.getElementById('obl-closure').value || '',
        loan_acc_no: document.getElementById('obl-accno').value.trim(),
        select_bt: document.getElementById('obl-select-bt').checked,
      });
      closeModal('modal-obligation');
      showToast('Obligation added', 'success');
      renderObligationsTab(appId);
    }

    function toggleBT(appId, oblId, val) {
      const obl = (OBLIGATIONS[appId] || []).find(o => o.id === oblId);
      if (!obl) return;
      obl.select_bt = val;
      // Update BT label color in the row
      const row = document.getElementById('obl-row-' + oblId);
      if (row) {
        const lbl = row.querySelector('td:nth-last-child(' + (ROLES[currentUser.role].canEditObligations ? '2' : '1') + ') label');
        if (lbl) { lbl.style.color = val ? 'var(--accent)' : 'var(--text3)'; lbl.querySelector('span').textContent = val ? 'BT' : '—'; }
      }
      renderFoirPanel(appId);
    }

    function deleteObligation(appId, oblId) {
      if (!OBLIGATIONS[appId]) return;
      OBLIGATIONS[appId] = OBLIGATIONS[appId].filter(o => o.id !== oblId);
      renderObligationsTab(appId);
    }

