    function populateRmSelect() {
      const sel = document.getElementById('w-rm');
      if (!sel) return;
      sel.innerHTML = '<option value="">Select RM</option>' +
        RM_EMAILS.map(rm => `<option value="${rm.id}">${rm.name} (${rm.location})</option>`).join('');
    }

    function renderRmEmails() {
      const container = document.getElementById('rm-emails-list');
      if (!container) return;
      document.getElementById('rm-count').textContent = RM_EMAILS.length;
      container.innerHTML = RM_EMAILS.map(rm => `
    <tr>
      <td><strong>${rm.name}</strong></td>
      <td>${rm.location || '—'}</td>
      <td><a href="mailto:${rm.email}" style="color:var(--accent)">${rm.email}</a></td>
      <td>${rm.contact_no || '—'}</td>
      <td style="display:flex;gap:6px">
        <button class="btn btn-ghost btn-sm" onclick="editRm(${rm.id})">Edit</button>
        <button class="btn btn-danger btn-sm" onclick="deleteRm(${rm.id})">✕</button>
      </td>
    </tr>`).join('');
    }

    function openRmModal(id) {
      const rm = id ? RM_EMAILS.find(r => r.id === id) : null;
      document.getElementById('rm-modal-id').value = id || '';
      document.getElementById('rm-modal-name').value = rm ? rm.name : '';
      document.getElementById('rm-modal-location').value = rm ? (rm.location || '') : '';
      document.getElementById('rm-modal-email').value = rm ? rm.email : '';
      document.getElementById('rm-modal-contact').value = rm ? (rm.contact_no || '') : '';
      openModal('modal-rm-email');
    }
    function editRm(id) { openRmModal(id); }

    function saveRm() {
      const id = document.getElementById('rm-modal-id').value;
      const name = document.getElementById('rm-modal-name').value.trim();
      const email = document.getElementById('rm-modal-email').value.trim();
      if (!name || !email) { showToast('Name and Email are required', 'error'); return; }
      const data = {
        name, email,
        location: document.getElementById('rm-modal-location').value.trim(),
        contact_no: document.getElementById('rm-modal-contact').value.trim(),
      };
      if (id) {
        const rm = RM_EMAILS.find(r => r.id === parseInt(id));
        if (rm) Object.assign(rm, data);
        showToast('RM updated', 'success');
      } else {
        RM_EMAILS.push({ id: rmNextId++, ...data });
        showToast('RM added', 'success');
      }
      closeModal('modal-rm-email');
      renderRmEmails();
      populateRmSelect();
    }

    function deleteRm(id) {
      if (!confirm('Delete this RM record?')) return;
      const idx = RM_EMAILS.findIndex(r => r.id === id);
      if (idx >= 0) RM_EMAILS.splice(idx, 1);
      renderRmEmails();
      populateRmSelect();
      showToast('RM deleted', 'info');
    }

    // ══════════════════════════════════════════════════
    //  DRAFT RESUME  (mirrors action_resume_draft / _determine_resume_step)
    // ══════════════════════════════════════════════════
    function resumeDraftApp(id) {
      const app = APPLICATIONS.find(a => a.id === id);
      if (!app || !app.is_draft) { showToast('Application is not a draft', 'error'); return; }
      // Determine resume step
      let step = 1;
      if (app.mobile && app.pan) step = 2;
      if (step >= 2 && app.name) step = 3;
      if (step >= 3 && app.city) step = 4;
      if (step >= 4 && app.salary) step = 5;
      if (step >= 5 && app.amount) step = 6;

      // Pre-fill wizard fields
      if (document.getElementById('w-mobile'))   document.getElementById('w-mobile').value   = app.mobile   || '';
      if (document.getElementById('w-pan'))      document.getElementById('w-pan').value      = (app.pan || '').toUpperCase();
      if (document.getElementById('w-fname'))    document.getElementById('w-fname').value    = app.fname    || (app.name || '').split(' ')[0] || '';
      if (document.getElementById('w-mname'))    document.getElementById('w-mname').value    = app.mname    || '';
      if (document.getElementById('w-lname'))    document.getElementById('w-lname').value    = app.lname    || (app.name || '').split(' ').slice(1).join(' ') || '';
      if (document.getElementById('w-dob'))      document.getElementById('w-dob').value      = app.dob      || '';
      if (document.getElementById('w-gender'))   document.getElementById('w-gender').value   = app.gender   || '';
      if (document.getElementById('w-aadhar'))   document.getElementById('w-aadhar').value   = app.aadhar   || '';
      if (document.getElementById('w-email'))    document.getElementById('w-email').value    = app.email    || '';
      if (document.getElementById('w-phone'))    document.getElementById('w-phone').value    = app.altPhone || '';
      if (document.getElementById('w-mname2'))   document.getElementById('w-mname2').value   = app.mname2   || '';
      if (document.getElementById('w-father'))   document.getElementById('w-father').value   = app.father   || '';
      if (document.getElementById('w-salary'))   document.getElementById('w-salary').value   = app.salary   || '';
      if (document.getElementById('w-loantype')) document.getElementById('w-loantype').value = app.loanType || 'personal_loan';
      if (document.getElementById('w-loanamt'))  document.getElementById('w-loanamt').value  = app.amount   || '';

      currentStep = step;
      showPage('new-application', document.getElementById('nav-new-app'));
      renderWizard();
      showToast(`Resuming draft ${id} from Step ${step}`, 'info');
    }

    // ══════════════════════════════════════════════════
    //  ACTIVE TIME TRACKING  (mirrors _compute_active_time in loan_application.py)
    // ══════════════════════════════════════════════════
    function getActiveTimeDisplay(app) {
      if (typeof window.getActiveTimeDisplay === 'function' && window.getActiveTimeDisplay !== getActiveTimeDisplay) {
        return window.getActiveTimeDisplay(app);
      }
      if (!app) return 'N/A';

      const terminalStatuses = ['disbursed', 'ni', 'cancelled', 'rejected', 'hold'];
      const fmt = function(totalHours) {
        const h = Math.max(0, Number(totalHours) || 0);
        const hoursStr = h.toFixed(2) + ' Hours';
        if (h < 1) { return `${hoursStr} (${Math.round(h*60)} min)`; }
        const days = Math.floor(h / 24), rem = Math.round(h % 24);
        return days > 0 ? `${hoursStr} (${days}d ${rem}h)` : hoursStr;
      };
      if (terminalStatuses.includes(app.status)) {
        return app.total_active_hours != null ? fmt(app.total_active_hours) : 'N/A';
      }

      const startStr = app.login_date_time || app.createdAt || app.date;
      if (!startStr) return 'N/A';
      let start;
      try {
        start = new Date(startStr);
        if (isNaN(start.getTime())) {
          const m = String(startStr).match(/(\d{1,2})\s+(\w+)\s+(\d{4})/);
          if (m) {
            const months = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
            start = new Date(parseInt(m[3]), months[m[2]] ?? 0, parseInt(m[1]));
          }
        }
      } catch(e) { return 'N/A'; }
      if (!start || isNaN(start.getTime())) return 'N/A';
      const diffHours = (Date.now() - start.getTime()) / 3600000;
      return fmt(diffHours + (Number(app.total_active_hours) || 0));
    }

    // Inject FOIR + tasks + obligations tabs into the app-detail page
