    var _mlActiveKey = null;

    // Populate a given select from MASTER_LISTS
    function mlPopulateSelect(listKey, selectId, keepValue) {
      const sel = document.getElementById(selectId); if (!sel) return;
      const list = MASTER_LISTS[listKey]; if (!list) return;
      const cur = keepValue || sel.value;
      sel.innerHTML = '<option value="">Select</option>' +
        list.items.map(i => `<option value="${i.value}" ${i.value===cur?'selected':''}>${i.label}</option>`).join('');
    }

    // Populate ALL wizard selects from their master lists
    function mlPopulateWizardSelects() {
      mlPopulateSelect('home_type',    'w-hometype');
      mlPopulateSelect('home_type',    'w-phometype');
      mlPopulateSelect('designation',  'w-desig');
      mlPopulateSelect('company_type', 'w-comptype');
      // Location and Sales Person have their own dynamic population via wPopulateLocations/wLocationChange
      // but we seed MASTER_LISTS.location into twLocations for consistency
      mlSyncLocationsToTw();
    }

    // Keep MASTER_LISTS.location in sync with twLocations
    function mlSyncLocationsToTw() {
      const mlLocs = MASTER_LISTS.location.items.map(i => i.value);
      // Add any MASTER_LISTS items not yet in twLocations
      mlLocs.forEach(name => {
        if (!twLocations.find(l => l.name === name)) {
          twLocations.push({ id: Date.now() + Math.random(), name });
        }
      });
      if (typeof wPopulateLocations === 'function') wPopulateLocations();
    }

    // ── LIST MANAGER UI ──────────────────────────────────────

    function mlRenderTabs() {
      const tabsEl = document.getElementById('ml-list-tabs'); if (!tabsEl) return;
      tabsEl.innerHTML = Object.entries(MASTER_LISTS).map(([key, list]) => `
        <button onclick="mlSelectList('${key}')"
          id="ml-tab-${key}"
          style="display:flex;align-items:center;gap:6px;padding:7px 14px;border:1.5px solid ${_mlActiveKey===key?'var(--accent)':'var(--border)'};border-radius:20px;background:${_mlActiveKey===key?'rgba(26,79,163,.08)':'var(--surface)'};color:${_mlActiveKey===key?'var(--accent)':'var(--text2)'};font-size:13px;font-weight:${_mlActiveKey===key?'700':'400'};cursor:pointer;transition:all .15s">
          <span>${list.icon}</span>
          <span>${list.label}</span>
          <span style="background:${_mlActiveKey===key?'var(--accent)':'var(--surface3)'};color:${_mlActiveKey===key?'#fff':'var(--text3)'};font-size:10px;font-weight:700;padding:1px 7px;border-radius:20px">${list.items.length}</span>
        </button>`).join('');

      // If a list is already active, render it
      if (_mlActiveKey) mlRenderItems(_mlActiveKey);
    }

    function mlSelectList(key) {
      _mlActiveKey = key;
      mlRenderTabs();

      const list = MASTER_LISTS[key];
      const title = document.getElementById('ml-editor-title');
      const desc  = document.getElementById('ml-editor-desc');
      const input = document.getElementById('ml-new-item-input');
      if (title) title.textContent = list.icon + '  ' + list.label;
      if (desc)  desc.textContent  = list.desc;
      if (input) { input.placeholder = `New ${list.label} option…`; input.value = ''; }

      mlRenderItems(key);
    }

    function mlRenderItems(key) {
      const grid = document.getElementById('ml-items-grid'); if (!grid) return;
      const list = MASTER_LISTS[key];
      if (!list || !list.items.length) {
        grid.innerHTML = `<div style="color:var(--text3);font-size:13px;grid-column:1/-1;text-align:center;padding:20px">No items yet. Add the first one above.</div>`;
        return;
      }

      // Check which values are in use by existing applications
      const inUse = new Set(APPLICATIONS.map(a => {
        if (key === 'location')     return a.location;
        if (key === 'sales_person') return a.sales;
        if (key === 'home_type')    return a.homeType;
        if (key === 'designation')  return a.desig;
        if (key === 'company_type') return a.compType;
        return null;
      }).filter(Boolean));

      grid.innerHTML = list.items.map((item, idx) => {
        const used = inUse.has(item.value);
        return `
          <div style="display:flex;align-items:center;gap:8px;background:var(--surface);border:1.5px solid var(--border);border-radius:10px;padding:10px 12px;transition:border-color .15s"
            onmouseover="this.style.borderColor='var(--border2)'" onmouseout="this.style.borderColor='var(--border)'">
            <span style="font-size:16px">${list.icon}</span>
            <div style="flex:1;min-width:0">
              <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${item.label}">${item.label}</div>
              <div style="font-size:10.5px;color:var(--text3);font-family:monospace;margin-top:1px">${item.value}</div>
            </div>
            ${used
              ? `<span style="font-size:10px;color:var(--success);background:rgba(26,115,64,.1);padding:2px 7px;border-radius:20px;flex-shrink:0" title="In use by existing applications">In use</span>`
              : `<button onclick="mlDeleteItem('${key}',${idx})" title="Delete"
                  style="background:none;border:none;cursor:pointer;color:var(--text3);font-size:16px;padding:2px 4px;border-radius:4px;flex-shrink:0"
                  onmouseover="this.style.color='var(--danger)'" onmouseout="this.style.color='var(--text3)'">✕</button>`
            }
          </div>`;
      }).join('');
    }

    function mlAddItem() {
      if (!_mlActiveKey) { showToast('Select a list first', 'warn'); return; }
      const input = document.getElementById('ml-new-item-input');
      const rawLabel = input?.value.trim();
      if (!rawLabel) { showToast('Enter an item label', 'error'); return; }

      const list = MASTER_LISTS[_mlActiveKey];
      // Generate value: lowercase, underscores for spaces
      const value = rawLabel.toLowerCase().replace(/\s+/g, '_').replace(/[^a-z0-9_]/g, '');

      // Prevent duplicates
      if (list.items.find(i => i.label.toLowerCase() === rawLabel.toLowerCase())) {
        showToast(`"${rawLabel}" already exists in ${list.label}`, 'warn'); return;
      }

      list.items.push({ value, label: rawLabel });
      if (input) input.value = '';

      // Sync to twLocations if this is the location list
      if (_mlActiveKey === 'location') {
        if (!twLocations.find(l => l.name === rawLabel)) {
          twLocations.push({ id: Date.now(), name: rawLabel });
          if (typeof wPopulateLocations === 'function') wPopulateLocations();
        }
      }

      // Repopulate the wizard select
      mlPopulateSelect(_mlActiveKey, list.wizardId);

      mlRenderTabs();
      showToast(`"${rawLabel}" added to ${list.label}`, 'success');
    }

    function mlDeleteItem(key, idx) {
      const list = MASTER_LISTS[key]; if (!list) return;
      const item = list.items[idx]; if (!item) return;

      // Check if in use
      const inUse = APPLICATIONS.some(a => {
        if (key === 'location')     return a.location  === item.value;
        if (key === 'sales_person') return a.sales     === item.value;
        if (key === 'home_type')    return a.homeType  === item.value;
        if (key === 'designation')  return a.desig     === item.value;
        if (key === 'company_type') return a.compType  === item.value;
        return false;
      });
      if (inUse) { showToast(`Cannot delete "${item.label}" — it is used by existing applications`, 'error'); return; }

      if (!confirm(`Delete "${item.label}" from ${list.label}?`)) return;

      list.items.splice(idx, 1);

      // Also remove from twLocations if location list
      if (key === 'location') {
        twLocations = twLocations.filter(l => l.name !== item.value);
        if (typeof wPopulateLocations === 'function') wPopulateLocations();
      }

      // Repopulate the wizard select
      mlPopulateSelect(key, list.wizardId);

      mlRenderTabs();
      showToast(`"${item.label}" removed`, 'info');
    }

    // Call on DOMContentLoaded to seed all wizard dropdowns
    document.addEventListener('DOMContentLoaded', function() {
      mlPopulateWizardSelects();
    });


    // ── Expose functions to window for onclick handlers ──
    window.mlPopulateSelect = mlPopulateSelect;
    window.mlPopulateWizardSelects = mlPopulateWizardSelects;
    window.mlSyncLocationsToTw = mlSyncLocationsToTw;
    window.mlRenderTabs = mlRenderTabs;

    // ══════════════════════════════════════════════════════════════
    //  INCOME CHECK COMMENT TEMPLATES — Admin/Product Team Manager
    // ══════════════════════════════════════════════════════════════

    function ictRender() {
      const listEl = document.getElementById('ict-list');
      if (!listEl) return;
      const q = (document.getElementById('ict-search')?.value || '').toLowerCase().trim();
      const templates = window.IC_COMMENT_TEMPLATES || [];
      const filtered = templates.map((t, i) => ({ t, i })).filter(({ t }) => !q || t.toLowerCase().includes(q));
      if (!filtered.length) {
        listEl.innerHTML = `<div style="grid-column:1/-1;text-align:center;color:var(--text3);font-size:13px;padding:20px">No templates match your search.</div>`;
        return;
      }
      listEl.innerHTML = filtered.map(({ t, i }) => `
        <div style="display:flex;align-items:center;gap:10px;background:var(--surface2);border:1px solid var(--border);border-radius:10px;padding:9px 12px;transition:box-shadow .15s"
          onmouseenter="this.style.boxShadow='var(--shadow)'" onmouseleave="this.style.boxShadow=''">
          <span style="font-size:10px;font-weight:800;color:var(--accent);min-width:22px;font-family:var(--font-head)">${i + 1}.</span>
          <span id="ict-label-${i}" style="flex:1;font-size:13px;color:var(--text)">${t}</span>
          <input type="text" id="ict-edit-${i}" value="${t.replace(/"/g,'&quot;')}"
            style="display:none;flex:1;padding:5px 9px;border:1.5px solid var(--accent);border-radius:7px;font-size:13px;background:var(--surface);color:var(--text);outline:none"
            onkeydown="if(event.key==='Enter') ictSaveEdit(${i}); if(event.key==='Escape') ictCancelEdit(${i})">
          <button onclick="ictStartEdit(${i})" title="Edit"
            style="background:rgba(26,79,163,.07);border:none;border-radius:7px;padding:5px 9px;cursor:pointer;color:var(--accent);font-size:13px" id="ict-edit-btn-${i}">✏️</button>
          <button onclick="ictSaveEdit(${i})" title="Save" id="ict-save-btn-${i}"
            style="display:none;background:rgba(26,115,64,.1);border:none;border-radius:7px;padding:5px 9px;cursor:pointer;color:var(--success);font-size:13px">✅</button>
          <button onclick="ictDelete(${i})" title="Delete"
            style="background:rgba(212,43,43,.07);border:none;border-radius:7px;padding:5px 9px;cursor:pointer;color:var(--danger);font-size:13px">🗑️</button>
        </div>`).join('');
    }

    function ictStartEdit(i) {
      const lbl = document.getElementById(`ict-label-${i}`);
      const inp = document.getElementById(`ict-edit-${i}`);
      const editBtn = document.getElementById(`ict-edit-btn-${i}`);
      const saveBtn = document.getElementById(`ict-save-btn-${i}`);
      if (lbl) lbl.style.display = 'none';
      if (inp) { inp.style.display = ''; inp.focus(); inp.select(); }
      if (editBtn) editBtn.style.display = 'none';
      if (saveBtn) saveBtn.style.display = '';
    }

    function ictCancelEdit(i) {
      ictRender(); // re-render resets everything
    }

    function ictSaveEdit(i) {
      const inp = document.getElementById(`ict-edit-${i}`);
      const val = (inp?.value || '').trim();
      if (!val) { showToast('Comment cannot be empty', 'warn'); return; }
      window.IC_COMMENT_TEMPLATES[i] = val;
      showToast('Template updated ✓', 'success');
      ictRender();
    }

    function ictAddTemplate() {
      const inp = document.getElementById('ict-new-input');
      const val = (inp?.value || '').trim();
      if (!val) { showToast('Please type a comment template first', 'warn'); inp?.focus(); return; }
      if (window.IC_COMMENT_TEMPLATES.includes(val)) { showToast('This template already exists', 'warn'); return; }
      window.IC_COMMENT_TEMPLATES.push(val);
      if (inp) inp.value = '';
      ictRender();
      showToast('Template added ✓', 'success');
    }

    function ictDelete(i) {
      const t = window.IC_COMMENT_TEMPLATES[i];
      if (!t) return;
      if (!confirm(`Delete this template?\n\n"${t}"`)) return;
      window.IC_COMMENT_TEMPLATES.splice(i, 1);
      ictRender();
      showToast('Template deleted', 'info');
    }

    window.ictRender = ictRender;
    window.ictAddTemplate = ictAddTemplate;
    window.ictSaveEdit = ictSaveEdit;
    window.ictCancelEdit = ictCancelEdit;
    window.ictStartEdit = ictStartEdit;
    window.ictDelete = ictDelete;
    window.mlSelectList = mlSelectList;
    window.mlRenderItems = mlRenderItems;
    window.mlAddItem = mlAddItem;
    window.mlDeleteItem = mlDeleteItem;

  

