    window.profileSwitchTab = profileSwitchTab;
    window.profileOpenEdit = profileOpenEdit;
    window.profileSaveEdit = profileSaveEdit;
    window.profileUploadAvatar = profileUploadAvatar;
    window.toggleProfileDropdown = toggleProfileDropdown;
    window.toggleTopbarProfileDropdown = toggleTopbarProfileDropdown;
    window.doLogout = doLogout;

    // ── KYC Proxy / API Key Settings UI (injected into Settings page) ──
    async function _renderKycProxySettingsCard() {
      var container = document.getElementById('stg-kyc-proxy-container');
      if (!container) return;

      var savedKey = '';
      try { savedKey = localStorage.getItem('efin_gemini_key') || ''; } catch(_) {}
      // Also check embedded default key
      var embeddedKey = '';
      var keyActive = !!savedKey;
      var displayKey = savedKey || embeddedKey;
      var isUsingEmbedded = !savedKey && !!embeddedKey;

      container.innerHTML =
        '<div class="stg-section-label" style="margin-top:0">KYC Vision — Document Auto-Fill</div>' +
        '<div style="font-size:12px;color:var(--text3);margin-bottom:14px;line-height:1.7">' +
          'PAN &amp; Aadhaar details are extracted automatically using <strong>Google Gemini Vision</strong>. ' +
          'An API key is required — paste yours below (stored only in this browser). ' +
          'Get a free key at <a href="https://aistudio.google.com/apikey" target="_blank" rel="noopener" style="color:var(--accent);font-weight:600">aistudio.google.com/apikey</a>.' +
        '</div>' +
        '<div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;margin-bottom:10px">' +
          '<input id="stg-gemini-key" type="password" placeholder="Paste Gemini API key (AIza… or AQ.…)" value="' + savedKey.replace(/"/g,'&quot;') + '" ' +
            'style="flex:1;min-width:240px;padding:10px 14px;border:1.5px solid var(--border2);border-radius:8px;font-size:13px;background:var(--surface);color:var(--text);outline:none">' +
          '<button onclick="_kycSaveGeminiKey()" style="padding:10px 18px;background:var(--accent);color:#fff;border:none;border-radius:8px;font-size:13px;font-weight:700;cursor:pointer">💾 Save Key</button>' +
          (keyActive ? '<button onclick="_kycClearGeminiKey()" style="padding:10px 14px;background:var(--surface2);color:var(--text2);border:1px solid var(--border2);border-radius:8px;font-size:13px;font-weight:600;cursor:pointer">Remove</button>' : '') +
        '</div>' +
        (keyActive
          ? '<div style="font-size:12px;color:#15803d;font-weight:600;background:rgba(26,115,64,.08);padding:8px 12px;border-radius:8px;border:1px solid rgba(26,115,64,.2)">✅ Custom Gemini key active — auto-fill enabled.</div>'
          : isUsingEmbedded
            ? '<div style="font-size:12px;color:#15803d;font-weight:600;background:rgba(26,115,64,.08);padding:8px 12px;border-radius:8px;border:1px solid rgba(26,115,64,.2)">✅ Default Gemini key active — PAN &amp; Aadhaar auto-fill is working. Paste your own key above to override.</div>'
            : '<div style="font-size:12px;color:#b45309;font-weight:600;background:rgba(245,158,11,.08);padding:8px 12px;border-radius:8px;border:1px solid rgba(245,158,11,.2)">⚠ No key set — paste your Gemini key above to enable auto-fill.</div>');
    }
    window._renderKycProxySettingsCard = _renderKycProxySettingsCard;

    // Save / clear the browser-side Gemini key used for KYC auto-fill.
    window._kycSaveGeminiKey = function() {
      var el = document.getElementById('stg-gemini-key');
      var k = (el && el.value || '').trim();
      if (!k) { showToast('Please paste a Gemini API key first', 'warn'); return; }
      try { localStorage.setItem('efin_gemini_key', k); } catch(_) {}
      showToast('Gemini key saved — PAN/Aadhaar auto-fill is now active', 'success');
      _renderKycProxySettingsCard();
    };
    window._kycClearGeminiKey = function() {
      try { localStorage.removeItem('efin_gemini_key'); } catch(_) {}
      showToast('Gemini key removed', 'info');
      _renderKycProxySettingsCard();
    };

  

    // ═══════════════════════════════════════════════════════
    //  HELPDESK TICKETS SYSTEM
    // ═══════════════════════════════════════════════════════

    // Shared store — seeded from twTickets, extended with full fields
    const TK_STORE = [
    ];
    var tkNextId = 4;
    var tkActiveFilter = 'all';
    window.TK_STORE = TK_STORE;

    var TK_PRIORITY_BADGE = {
      low: 'badge-hold',
      medium: 'badge-wip',
      high: 'badge-rejected',
      critical: 'badge-underwriting',
    };
    var TK_STATUS_BADGE = {
      open: 'badge-login',
      in_progress: 'badge-underwriting',
      resolved: 'badge-approved',
      closed: 'badge-hold',
    };
    var TK_STATUS_LABEL = { open: 'Open', in_progress: 'In Progress', resolved: 'Resolved', closed: 'Closed' };
    var TK_PRIORITY_LABEL = { low: 'Low', medium: 'Medium', high: 'High', critical: 'Critical' };

    function tkRenderTable(filter) {
      tkActiveFilter = filter || tkActiveFilter;
      const body = document.getElementById('tickets-table-body');
      if (!body) return;
      const rows = tkActiveFilter === 'all'
        ? TK_STORE
        : TK_STORE.filter(t => t.status === tkActiveFilter);

      if (!rows.length) {
        body.innerHTML = '<tr><td colspan="8" style="text-align:center;color:var(--text3);padding:40px">No tickets found</td></tr>';
        return;
      }
      body.innerHTML = rows.map(t => `
    <tr>
      <td><span class="app-id">#${t.id}</span></td>
      <td><strong>${t.subject}</strong>${t.desc ? `<div style="font-size:11px;color:var(--text3);margin-top:2px;max-width:260px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${t.desc}</div>` : ''}</td>
      <td>${t.loan ? `<span class="app-id" style="cursor:pointer;color:var(--accent)" onclick="openDetail('${t.loan}')">${t.loan}</span>` : '—'}</td>
      <td>${t.customer || '—'}</td>
      <td><span class="badge ${TK_PRIORITY_BADGE[t.priority] || 'badge-hold'}">${TK_PRIORITY_LABEL[t.priority] || t.priority}</span></td>
      <td><span class="badge ${TK_STATUS_BADGE[t.status] || 'badge-hold'}">${TK_STATUS_LABEL[t.status] || t.status}</span></td>
      <td style="font-size:12px;color:var(--text3)">${t.date}</td>
      <td onclick="event.stopPropagation()">
        <div style="display:flex;gap:6px">
          ${t.status !== 'resolved' && t.status !== 'closed'
          ? `<button class="btn btn-success btn-sm" onclick="tkResolve('${t.id}')">✓ Resolve</button>`
          : `<button class="btn btn-ghost btn-sm" onclick="tkReopen('${t.id}')">↩ Reopen</button>`}
          <button class="btn btn-danger btn-sm" onclick="tkClose('${t.id}')">✕</button>
        </div>
      </td>
    </tr>`).join('');
    }

    function tkFilter(status, el) {
      tkActiveFilter = status;
      document.querySelectorAll('#page-tickets .filter-chip').forEach(c => c.classList.remove('active'));
      if (el) el.classList.add('active');
      tkRenderTable(status);
    }

    function tkPopulateLoanSelect() {
      const sel = document.getElementById('tk-loan');
      if (!sel) return;
      sel.innerHTML = '<option value="">— None —</option>' +
        APPLICATIONS.map(a => `<option value="${a.id}">${a.id} — ${a.name}</option>`).join('');

      // Dynamically populate assigned-to from USER_ACCOUNTS + twUsers (deduplicated by name)
      const assignSel = document.getElementById('tk-assigned');
      if (assignSel) {
        const names = new Set();
        (typeof USER_ACCOUNTS !== 'undefined' ? USER_ACCOUNTS : []).forEach(u => names.add(u.name));
        (typeof twUsers !== 'undefined' ? twUsers : []).forEach(u => names.add(u.name));
        const currentVal = assignSel.value;
        assignSel.innerHTML = '<option value="">— Unassigned —</option>' +
          [...names].sort().map(n => `<option value="${n}"${n === currentVal ? ' selected' : ''}>${n}</option>`).join('');
      }
    }

    function tkSaveTicket() {
      const subject = document.getElementById('tk-subject')?.value.trim();
      const loan = document.getElementById('tk-loan')?.value;
      const priority = document.getElementById('tk-priority')?.value || 'medium';
      const team = document.getElementById('tk-team')?.value || 'General Support';
      const assigned = document.getElementById('tk-assigned')?.value || '';
      const desc = document.getElementById('tk-desc')?.value.trim();

      if (!subject) { showToast('Subject is required', 'error'); return; }

      // Derive customer name from linked application
      const linkedApp = APPLICATIONS.find(a => a.id === loan);
      const customer = linkedApp ? linkedApp.name : (currentUser.name || '');

      const now = new Date();
      const dateStr = now.toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });

      // Derive next id from existing store so it never collides after reload
      const _maxNum = TK_STORE.reduce(function(m,t){ var n=parseInt(String(t.id).replace(/\D/g,''),10); return isNaN(n)?m:Math.max(m,n); }, 0);
      if (tkNextId <= _maxNum) tkNextId = _maxNum + 1;
      const ticket = {
        id: 'TKT-' + String(tkNextId++).padStart(3, '0'),
        subject, loan, customer, priority, team, assigned,
        status: 'open',
        date: dateStr,
        desc,
      };

      TK_STORE.unshift(ticket);

      // Keep twTickets in sync for the Team Overview dashboard
      twTickets.unshift({ id: ticket.id, loan, team, customer, assigned, status: 'open', date: now.toISOString().slice(0, 10) });
      twUpdateCounts();
      twRenderDash();

      closeModal('modal-new-ticket');

      // Reset form
      ['tk-subject', 'tk-desc'].forEach(id => { const el = document.getElementById(id); if (el) el.value = ''; });
      ['tk-priority', 'tk-team', 'tk-assigned'].forEach(id => { const el = document.getElementById(id); if (el) el.selectedIndex = 0; });
      document.getElementById('tk-loan').value = '';

      tkRenderTable(tkActiveFilter);
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
      showToast(`Ticket #${ticket.id} created`, 'success');
    }

    function tkResolve(id) {
      const t = TK_STORE.find(x => x.id === id);
      if (!t) return;
      t.status = 'resolved';
      // Sync twTickets
      const tw = twTickets.find(x => x.id === id);
      if (tw) tw.status = 'resolved';
      twUpdateCounts();
      tkRenderTable(tkActiveFilter);
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
      showToast(`Ticket #${id} resolved`, 'success');
    }

    function tkReopen(id) {
      const t = TK_STORE.find(x => x.id === id);
      if (!t) return;
      t.status = 'open';
      const tw = twTickets.find(x => x.id === id);
      if (tw) tw.status = 'open';
      twUpdateCounts();
      tkRenderTable(tkActiveFilter);
      if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
      showToast(`Ticket #${id} reopened`, 'info');
    }

    function tkClose(id) {
      const idx = TK_STORE.findIndex(x => x.id === id);
      if (idx < 0) return;
      if (!confirm(`Close ticket #${id}? This cannot be undone.`)) return;
      TK_STORE.splice(idx, 1);
      const twIdx = twTickets.findIndex(x => x.id === id);
      if (twIdx >= 0) twTickets.splice(twIdx, 1);
      twUpdateCounts();
      tkRenderTable(tkActiveFilter);
      showToast(`Ticket #${id} closed`, 'info');
      if (typeof persistSave === 'function') persistSave();
    }

    // Repopulate loan select when modal opens
    document.addEventListener('DOMContentLoaded', function () {
      const overlay = document.getElementById('modal-new-ticket');
      if (overlay) {
        overlay.addEventListener('click', function (e) {
          if (e.target === overlay) return; // handled by openModal close
        });
      }
      // Hook modal open to refresh loan select
      const origOpenModal = window.openModal;
      window.openModal = function (id) {
        origOpenModal(id);
        if (id === 'modal-new-ticket') tkPopulateLoanSelect();
      };
    });
  

    // ═══════════════════════════════════════════════════════════════
    //  EDIT APPLICATION DETAIL LOGIC
    //  Permitted: login_team · team_leader (Ops Manager) · admin (Location Head)
    //  Editable tabs: Overview · Personal · Address · Employment · References
    //  Blocked stages: rejected · hold · disbursed
    // ═══════════════════════════════════════════════════════════════

    // EAV-allowed sections for Sales Executive with EAV task
    var EAV_ALLOWED_SECTIONS = ['overview', 'personal', 'address', 'employment', 'references'];

    function switchEditTab(name, el) {
      document.querySelectorAll('.edit-tab-panel').forEach(p => p.classList.remove('active'));
      document.querySelectorAll('#edit-detail-tabs .tab').forEach(t => t.classList.remove('active'));
      const panel = document.getElementById('edit-tab-' + name);
      if (panel) panel.classList.add('active');
      if (el) el.classList.add('active');
    }

    function openEditDetailModal(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;

      const role = currentUser.role;

      // ── Guard: enforce edit permission rule ──
      // Permitted: login_team, team_leader (Operations Manager), admin (Location Head)
      // Blocked stages: rejected, hold, disbursed
      if (!canEditAppDetail(app)) {
        if (!['login_team', 'team_leader', 'admin'].includes(role)) {
          showToast('Your role does not have permission to edit application details.', 'error');
        } else {
          showToast(`Editing is not available when the application is ${STATUSES[app.status] || app.status}.`, 'error');
        }
        return;
      }

      // ── Set modal title and role badge ──
      document.getElementById('edit-detail-app-id').value = appId;
      document.getElementById('modal-edit-detail-title').textContent = '✏️ Edit — ' + appId;
      const badge = document.getElementById('modal-edit-detail-badge');
      badge.textContent = '📝 Changes will be logged to tracking';
      badge.style.cssText = 'background:rgba(212,43,43,.08);color:var(--danger);font-size:11px;padding:3px 10px;border-radius:20px;font-weight:700;margin-left:8px';

      // ── All 5 tabs available ──
      document.querySelectorAll('#edit-detail-tabs .tab').forEach(tab => {
        tab.style.display = '';
      });

      // ── Rebuild dynamic selects (home_type, designation, company_type) FIRST,
      //    using the app's current value as keepValue so the correct option is
      //    pre-selected in the rebuilt <select> HTML ──
      mlPopulateSelect('home_type',    'ed-hometype',  app.homeType  || '');
      mlPopulateSelect('home_type',    'ed-phometype', app.pHomeType || '');
      mlPopulateSelect('designation',  'ed-desig',     app.desig     || '');
      mlPopulateSelect('company_type', 'ed-comptype',  app.compType  || '');

      // ── Pre-fill ALL fields with the app's current saved values ──
      // Overview
      document.getElementById('ed-amount').value   = (app.amount   != null) ? app.amount   : '';
      document.getElementById('ed-bank').value     = app.bank      || '';
      document.getElementById('ed-cibil').value    = (app.cibil    != null) ? app.cibil    : '';
      document.getElementById('ed-loanrate').value = (app.loanRate != null) ? app.loanRate : '';
      document.getElementById('ed-tenure').value   = app.tenure    || '';
      document.getElementById('ed-sales').value    = app.sales     || '';
      document.getElementById('ed-purpose').value  = app.purpose   || '';
      document.getElementById('ed-leadsrc').value  = app.leadsrc   || '';
      document.getElementById('ed-channel').value  = app.channel   || '';

      // Personal Details
      document.getElementById('ed-fname').value   = app.fname   || '';
      document.getElementById('ed-mname').value   = app.mname   || '';
      document.getElementById('ed-lname').value   = app.lname   || '';
      document.getElementById('ed-dob').value     = app.dob     || '';
      document.getElementById('ed-gender').value  = app.gender  || '';
      document.getElementById('ed-pan').value     = app.pan     || '';
      document.getElementById('ed-aadhar').value  = app.aadhar  || '';
      document.getElementById('ed-mobile').value  = app.mobile  || '';
      document.getElementById('ed-altphone').value = app.altPhone || '';
      document.getElementById('ed-email').value   = app.email   || '';
      document.getElementById('ed-mname2').value  = app.mname2  || '';
      document.getElementById('ed-father').value  = app.father  || '';

      // Address — Current
      document.getElementById('ed-street1').value  = app.street1  || '';
      document.getElementById('ed-street2').value  = app.street2  || '';
      document.getElementById('ed-city').value     = app.city     || '';
      document.getElementById('ed-zip').value      = app.zip      || '';
      document.getElementById('ed-state').value    = app.state    || '';
      // ed-hometype was already rebuilt by mlPopulateSelect above with the correct option pre-selected;
      // force-set the .value again to guarantee the browser reflects it
      document.getElementById('ed-hometype').value = app.homeType || '';

      // Address — Permanent
      document.getElementById('ed-pstreet1').value  = app.pStreet1 || '';
      document.getElementById('ed-pstreet2').value  = app.pStreet2 || '';
      document.getElementById('ed-pcity').value     = app.pCity    || '';
      document.getElementById('ed-pzip').value      = app.pZip     || '';
      document.getElementById('ed-pstate').value    = app.pState   || '';
      // ed-phometype — same force-set pattern
      document.getElementById('ed-phometype').value = app.pHomeType || '';

      // "Same as current" checkbox
      const sameChk = document.getElementById('ed-same-addr');
      if (sameChk) sameChk.checked = (
        app.pStreet1 === app.street1 &&
        app.pCity    === app.city    &&
        app.pZip     === app.zip     &&
        app.pHomeType === app.homeType
      );

      // Employment
      document.getElementById('ed-emptype').value       = app.empType    || '';
      document.getElementById('ed-salary').value        = (app.salary != null) ? app.salary : '';
      document.getElementById('ed-compname').value      = app.compName   || '';
      // ed-desig was rebuilt by mlPopulateSelect; force-set again for safety
      document.getElementById('ed-desig').value         = app.desig      || '';
      // ed-comptype same
      document.getElementById('ed-comptype').value      = app.compType   || '';
      document.getElementById('ed-empcode').value       = app.officeEmail || app.empCode || '';
      document.getElementById('ed-officeaddr-l1').value = app.officeAddrL1 || (app.officeAddr ? app.officeAddr.split(', ')[0] : '');
      document.getElementById('ed-officeaddr-l2').value = app.officeAddrL2 || (app.officeAddr ? app.officeAddr.split(', ').slice(1,-1).join(', ') : '');
      document.getElementById('ed-officeaddr-pin').value = app.officeAddrPin || (app.officeAddr ? app.officeAddr.split(', ').pop() : '');

      // References
      document.getElementById('ed-r1name').value  = app.r1name  || '';
      document.getElementById('ed-r1no').value    = app.r1no    || '';
      document.getElementById('ed-r1rel').value   = app.r1rel   || '';
      document.getElementById('ed-r1addr1').value = app.r1addr1 || '';
      document.getElementById('ed-r1addr2').value = app.r1addr2 || '';
      document.getElementById('ed-r1city').value  = app.r1city  || '';
      document.getElementById('ed-r1pin').value   = app.r1pin   || '';
      document.getElementById('ed-r2name').value  = app.r2name  || '';
      document.getElementById('ed-r2no').value    = app.r2no    || '';
      document.getElementById('ed-r2rel').value   = app.r2rel   || '';
      document.getElementById('ed-r2addr1').value = app.r2addr1 || '';
      document.getElementById('ed-r2addr2').value = app.r2addr2 || '';
      document.getElementById('ed-r2city').value  = app.r2city  || '';
      document.getElementById('ed-r2pin').value   = app.r2pin   || '';

      // Reset to Overview tab, then open
      switchEditTab('overview', document.querySelector('#edit-detail-tabs .tab'));
      openModal('modal-edit-detail');
    }

    function saveEditDetail() {
      const appId = document.getElementById('edit-detail-app-id').value;
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;

      const role = currentUser.role;

      // ── Re-check permission before saving (safety guard) ──
      if (!canEditAppDetail(app)) {
        showToast('Edit access has been revoked for this application stage.', 'error');
        closeModal('modal-edit-detail');
        return;
      }

      // ── Validate official email if mandatory checkbox is ticked ──
      if (!edValidateOfficeEmail()) {
        // Switch to Employment tab so user sees the error
        switchEditTab('employment', document.querySelector('#edit-detail-tabs .tab:nth-child(4)'));
        return;
      }

      // ── Snapshot BEFORE applying changes (for tracking diff) ──
      const before = {
        amount: app.amount, bank: app.bank, cibil: app.cibil, loanRate: app.loanRate,
        tenure: app.tenure, sales: app.sales, purpose: app.purpose, leadsrc: app.leadsrc,
        channel: app.channel,
        fname: app.fname, mname: app.mname, lname: app.lname, dob: app.dob,
        gender: app.gender, pan: app.pan, aadhar: app.aadhar, mobile: app.mobile,
        altPhone: app.altPhone, email: app.email, mname2: app.mname2, father: app.father,
        street1: app.street1, street2: app.street2, city: app.city, zip: app.zip,
        state: app.state, homeType: app.homeType,
        pStreet1: app.pStreet1, pStreet2: app.pStreet2, pCity: app.pCity, pZip: app.pZip, pState: app.pState, pHomeType: app.pHomeType,
        empType: app.empType, salary: app.salary, compName: app.compName, desig: app.desig,
        compType: app.compType, empCode: app.officeEmail || app.empCode,
        officeAddrL1: app.officeAddrL1 || '', officeAddrL2: app.officeAddrL2 || '', officeAddrPin: app.officeAddrPin || '',
        r1name: app.r1name, r1no: app.r1no, r1rel: app.r1rel,
        r2name: app.r2name, r2no: app.r2no, r2rel: app.r2rel,
      };

      // ── Apply all edited values — write every field back unconditionally
      //    so that untouched fields are preserved exactly as pre-filled ──

      // Overview
      const amtVal = parseFloat(document.getElementById('ed-amount').value);
      app.amount   = !isNaN(amtVal) && amtVal > 0 ? amtVal : app.amount;
      app.bank     = document.getElementById('ed-bank').value.trim()     || app.bank;
      const cibilVal = parseInt(document.getElementById('ed-cibil').value);
      app.cibil    = !isNaN(cibilVal) ? cibilVal : app.cibil;
      const rateVal = parseFloat(document.getElementById('ed-loanrate').value);
      app.loanRate  = !isNaN(rateVal) ? rateVal : app.loanRate;
      app.tenure   = document.getElementById('ed-tenure').value   || app.tenure;
      app.sales    = document.getElementById('ed-sales').value.trim()    || app.sales;
      app.purpose  = document.getElementById('ed-purpose').value  || app.purpose;
      app.leadsrc  = document.getElementById('ed-leadsrc').value  || app.leadsrc;
      app.channel  = document.getElementById('ed-channel').value  || app.channel;

      // Personal Details — always write back exactly what is in each field
      const fnNew = document.getElementById('ed-fname').value.trim().toUpperCase();
      const mnNew = document.getElementById('ed-mname').value.trim().toUpperCase();
      const lnNew = document.getElementById('ed-lname').value.trim().toUpperCase();
      if (fnNew) app.fname = fnNew;
      if (mnNew !== undefined) app.mname = mnNew;
      if (lnNew) app.lname = lnNew;
      if (fnNew || lnNew) app.name = [app.fname, app.mname, app.lname].filter(Boolean).join(' ');
      app.dob     = document.getElementById('ed-dob').value     || app.dob;
      app.gender  = document.getElementById('ed-gender').value  || app.gender;
      const panVal = document.getElementById('ed-pan').value.trim().toUpperCase();
      if (panVal) app.pan = panVal;
      const aadharVal = document.getElementById('ed-aadhar').value.trim();
      if (aadharVal) app.aadhar = aadharVal;
      const mobileVal = document.getElementById('ed-mobile').value.trim();
      if (mobileVal) app.mobile = mobileVal;
      app.altPhone = document.getElementById('ed-altphone').value.trim();
      const emailVal = document.getElementById('ed-email').value.trim();
      if (emailVal) app.email = emailVal;
      app.mname2   = document.getElementById('ed-mname2').value.trim() || app.mname2;
      app.father   = document.getElementById('ed-father').value.trim() || app.father;

      // Address — write back every field exactly as in the form
      app.street1  = document.getElementById('ed-street1').value.trim()  || app.street1;
      app.street2  = document.getElementById('ed-street2').value.trim();
      app.city     = document.getElementById('ed-city').value.trim()     || app.city;
      app.zip      = document.getElementById('ed-zip').value.trim()      || app.zip;
      app.state    = document.getElementById('ed-state').value           || app.state;
      app.homeType = document.getElementById('ed-hometype').value        || app.homeType;
      app.pStreet1 = document.getElementById('ed-pstreet1').value.trim();
      app.pStreet2 = document.getElementById('ed-pstreet2').value.trim();
      app.pCity    = document.getElementById('ed-pcity').value.trim();
      app.pZip     = document.getElementById('ed-pzip').value.trim();
      app.pState   = document.getElementById('ed-pstate').value;
      const pHtVal = document.getElementById('ed-phometype').value;
      if (pHtVal !== undefined) app.pHomeType = pHtVal;

      // Employment — write back every field
      app.empType      = document.getElementById('ed-emptype').value     || app.empType;
      const salVal = parseFloat(document.getElementById('ed-salary').value);
      if (!isNaN(salVal) && salVal > 0) app.salary = salVal;
      app.compName     = document.getElementById('ed-compname').value.trim() || app.compName;
      app.desig        = document.getElementById('ed-desig').value        || app.desig;
      app.compType     = document.getElementById('ed-comptype').value     || app.compType;
      app.officeEmail  = document.getElementById('ed-empcode').value.trim();
      app.officeAddrL1  = document.getElementById('ed-officeaddr-l1').value.trim();
      app.officeAddrL2  = document.getElementById('ed-officeaddr-l2').value.trim();
      app.officeAddrPin = document.getElementById('ed-officeaddr-pin').value.trim();
      app.officeAddr = [app.officeAddrL1, app.officeAddrL2, app.officeAddrPin].filter(Boolean).join(', ');

      // References — write back every field
      app.r1name  = document.getElementById('ed-r1name').value.trim();
      app.r1no    = document.getElementById('ed-r1no').value.trim();
      app.r1rel   = document.getElementById('ed-r1rel').value;
      app.r1addr1 = document.getElementById('ed-r1addr1').value.trim();
      app.r1addr2 = document.getElementById('ed-r1addr2').value.trim();
      app.r1city  = document.getElementById('ed-r1city').value.trim();
      app.r1pin   = document.getElementById('ed-r1pin').value.trim();
      app.r2name  = document.getElementById('ed-r2name').value.trim();
      app.r2no    = document.getElementById('ed-r2no').value.trim();
      app.r2rel   = document.getElementById('ed-r2rel').value;
      app.r2addr1 = document.getElementById('ed-r2addr1').value.trim();
      app.r2addr2 = document.getElementById('ed-r2addr2').value.trim();
      app.r2city  = document.getElementById('ed-r2city').value.trim();
      app.r2pin   = document.getElementById('ed-r2pin').value.trim();

      // ══════════════════════════════════════════════════════
      //  REQ 1: Admin — save silently, NO tracking entry
      // ══════════════════════════════════════════════════════
      if (isAdminUser()) {
        closeModal('modal-edit-detail');
        openDetail(appId);
        renderTable();
        showToast('Details updated by Admin (not logged to tracking) ✓', 'success');
        return;
      }

      // ══════════════════════════════════════════════════════
      //  REQ 2 & 3: Non-admin — diff changes and log to tracking
      // ══════════════════════════════════════════════════════
      const FIELD_LABELS = {
        amount: 'Loan Amount', bank: 'Bank/NBFC', cibil: 'CIBIL Score', loanRate: 'Loan Rate (%)',
        tenure: 'Tenure (months)', sales: 'Sales Person', purpose: 'Purpose', leadsrc: 'Lead Source',
        channel: 'Channel',
        fname: 'First Name', mname: 'Middle Name', lname: 'Last Name', dob: 'Date of Birth',
        gender: 'Gender', pan: 'PAN', aadhar: 'Aadhar', mobile: 'Mobile',
        altPhone: 'Alternate Phone', email: 'Email', mname2: "Mother's Name", father: "Father's Name",
        street1: 'House / Flat No.', street2: 'Street & Locality', city: 'City', zip: 'PIN Code',
        state: 'State', homeType: 'Home Type',
        pStreet1: 'Perm. House / Flat No.', pStreet2: 'Perm. Street & Locality', pCity: 'Perm. City',
        pZip: 'Perm. PIN', pState: 'Perm. State', pHomeType: 'Perm. Home Type',
        empType: 'Employment Type', salary: 'Net Salary', compName: 'Company Name',
        desig: 'Designation', compType: 'Company Type', empCode: 'Official Email ID',
        officeAddrL1: 'Office Address Line 1', officeAddrL2: 'Office Address Line 2', officeAddrPin: 'Office PIN Code',
        r1name: 'Ref 1 — Name', r1no: 'Ref 1 — Mobile', r1rel: 'Ref 1 — Relationship',
        r2name: 'Ref 2 — Name', r2no: 'Ref 2 — Mobile', r2rel: 'Ref 2 — Relationship',
      };

      const changes = [];
      for (const key of Object.keys(before)) {
        const oldVal = String(before[key] === null || before[key] === undefined ? '' : before[key]).trim();
        const newVal = String(app[key] === null || app[key] === undefined ? '' : app[key]).trim();
        if (oldVal !== newVal) {
          changes.push((FIELD_LABELS[key] || key) + ': "' + oldVal + '" → "' + newVal + '"');
        }
      }

      if (changes.length === 0) {
        showToast('No changes detected.', 'info');
        closeModal('modal-edit-detail');
        return;
      }

      // ── Log changes to tracking ──
      const dept = ROLES[role]?.dept || 'System';
      addTrackingEntry(
        app,
        'EFIN-Detail Edit',
        dept,
        changes.length + ' field(s) modified by ' + currentUser.name,
        changes.join('\n')
      );

      closeModal('modal-edit-detail');
      openDetail(appId);
      renderTable();
      showToast('Details updated and changes logged to tracking ✓', 'success');
    }

    // ── Expose functions to window for onclick handlers ──
    window.switchEditTab = switchEditTab;
    window.openEditDetailModal = openEditDetailModal;
    window.saveEditDetail = saveEditDetail;

  

    // ─────────────────────────────────────────────────────────────
    //  SIDEBAR SECTION TOGGLE (collapsible groups)
    // ─────────────────────────────────────────────────────────────
    function toggleNavSection(headerEl) {
      const section = headerEl.closest('.nav-section');
      if (section) section.classList.toggle('collapsed');
    }

    // Auto-expand section when its child nav-item is activated
    (function patchShowPageForSections() {
      function doSectionPatch() {
        var _origSP = window.showPage;
        if (!_origSP) { setTimeout(doSectionPatch, 200); return; }
        if (window._sectionPatchApplied) return; // prevent double-wrap
        window._sectionPatchApplied = true;
        window.showPage = function(name, navEl) {
          try { _origSP.apply(this, arguments); } catch(e) { console.warn('[showPage chain] sectionPatch:', e); }
          // After showPage runs, expand the section of whichever nav-item is now active
          const activeItem = document.querySelector('.nav-item.active');
          if (activeItem) {
            const section = activeItem.closest('.nav-section');
            if (section) section.classList.remove('collapsed');
          }
        };
      }
      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', doSectionPatch);
      } else {
        setTimeout(doSectionPatch, 300);
      }
    })();

