    // ─────────────────────────────────────────────────────────────────
    //  Helper — resolve workflow for a given app
    //  Returns merged config: _default overridden by empType-specific keys
    // ─────────────────────────────────────────────────────────────────
    function getWorkflow(loanType, empType) {
      const byLoan = LOAN_EMP_WORKFLOW[loanType] || LOAN_EMP_WORKFLOW['personal_loan'];
      const empKey = (['SALARIED','SELFEMP','PROFESSIONAL'].includes((empType||'').toUpperCase()))
        ? empType.toUpperCase() : 'SALARIED';
      const base    = { ...(byLoan._default || {}) };
      const specific = byLoan[empKey] || {};
      return { ...base, ...specific };
    }

    // ─────────────────────────────────────────────────────────────────
    //  Build header action buttons HTML from workflow config
    // ─────────────────────────────────────────────────────────────────
    function buildWorkflowActionButtons(app, rd) {
      // Underwriting, Approve with Details, and Disburse buttons have been moved
      // to the Timeline → Actions section (buildTimelineActionButtons).
      
      return '';
    }

    // ─────────────────────────────────────────────────────────────────
    //  Build Timeline Actions section buttons from workflow config
    // ─────────────────────────────────────────────────────────────────
    function buildTimelineActionButtons(app, rd, html_prefix) {
      const wf = getWorkflow(app.loanType, app.empType);
      const actions = wf.timelineActions || wf.headerActions || [];
      let html = '';
      actions.forEach(a => {
        if (a === 'fi_report') {
          // BUGFIX (FI Report button disappearing prematurely): the Approve
          // action has no FI-completion gate, so app.status can move past
          // 'underwriting'/'offer' into 'approved' (and, via Deviation, into
          // 'decision'/'approved_deviation') while the FI Report is still
          // incomplete or Negative/Pending. The button must stay visible on
          // all of these pre-Acceptance statuses until it is genuinely done —
          // it should never vanish just because the status moved on.
          if (['underwriting','offer','approved','decision','approved_deviation'].includes(app.status) && !['partner'].includes(currentUser.role)) {
            const fiPosted = app.final_report;
            const fiNegOrPend = fiPosted && ((app.fi_resi==='Negative'||app.fi_resi==='Pending')||(app.fi_office==='Negative'||app.fi_office==='Pending'));
            if (!fiPosted || fiNegOrPend)
              html += `<button class="btn btn-danger btn-sm" onclick="openTrackWizard('${app.id}','fi')">📋 EFIN FI Report</button>`;
          }
        }
        if (a === 'underwriting' && rd.canChangeStatus && app.status === 'login')
          html += `<button class="btn btn-primary btn-sm" onclick="doUnderwriting('${app.id}')">🔍 Underwriting</button>`;
        if (a === 'approve' && rd.canChangeStatus && app.status === 'underwriting')
          html += `<button class="btn btn-primary btn-sm" onclick="openLenderApprovalModal('${app.id}')">✅ Approve with Details</button>`;
        if (a === 'disburse' && rd.canDisburse && ['approved','approved_deviation','acceptance'].includes(app.status) && app.nach_done && app.customer_agreement_done)
          html += `<button class="btn btn-success btn-sm" onclick="openDisburseModal('${app.id}')">💰 Disburse</button>`;
        {
          const hasAppAccess = !(typeof efinIsAppLocked === 'function' && efinIsAppLocked(app));
          if (a === 'deviation' && hasAppAccess) {
            if (app.status === 'approved')
              html += `<button class="btn btn-danger btn-sm" onclick="openDeviationModal('${app.id}')">⚠️ Deviation</button>`;
            if (app.status === 'approved')
              html += `<button class="btn btn-warn btn-sm" onclick="openSkipDeviationModal('${app.id}')">⏭️ Skip Deviation</button>`;
          }
          if (a === 'deviation' && ['login_team','operation_manager','location_head','admin'].includes(currentUser.role)) {
            if (app.status === 'decision')
              html += `<button class="btn btn-success btn-sm" onclick="openApprovedDeviationModal('${app.id}')">✅ Approved Deviation</button>`;
          }
        }
        if (a === 'nach' && !['partner'].includes(currentUser.role)) {
          if (app.status === 'acceptance' && !app.nach_done)
            html += `<button class="btn btn-danger btn-sm" onclick="openTrackWizard('${app.id}','task','EFIN-Nach')">Nach</button>`;
        }
        // Insurance-specific policy actions
        if (a === 'approve_ins' && rd.canChangeStatus && app.status === 'login')
          html += `<button class="btn btn-primary btn-sm" onclick="doUnderwriting('${app.id}')">🔍 Verify Insurance</button>`;
        if (a === 'approve_ins' && rd.canChangeStatus && app.status === 'underwriting')
          html += `<button class="btn btn-primary btn-sm" onclick="openLenderApprovalModal('${app.id}')">✅ Approve Policy</button>`;
        if (a === 'disburse_ins' && rd.canDisburse && ['approved','approved_deviation','acceptance'].includes(app.status) && app.nach_done && app.customer_agreement_done)
          html += `<button class="btn btn-success btn-sm" onclick="openDisburseModal('${app.id}')">📋 Issue Policy</button>`;
      });
      return html;
    }

    // ─────────────────────────────────────────────────────────────────
    //  Underwriting prerequisites — Bank Details (Lender Details tab) must
    //  be completely filled, and Obligations/FOIR calculation must be done,
    //  before an application can be manually moved to Underwriting.
    // ─────────────────────────────────────────────────────────────────
    function _hasCompleteBankDetails(app) {
      const lines = app && app.bankLines;
      if (!Array.isArray(lines) || !lines.length) return false;
      return lines.some(function(l) {
        return !!(l.bankName && String(l.bankName).trim()) &&
               !!(l.applicationNumber && String(l.applicationNumber).trim()) &&
               (parseFloat(l.approvedLoan) > 0);
      });
    }

    function _hasObligationsCalculated(app) {
      return !!(app && app.foirState && app.foirState.foir);
    }

    // ─────────────────────────────────────────────────────────────────
    //  Underwriting action — sets status before re-render so button vanishes immediately
    // ─────────────────────────────────────────────────────────────────
    function doUnderwriting(appId) {
      const app = APPLICATIONS.find(a => a.id === appId);
      if (!app) return;
      // Mandatory prerequisites before moving to Underwriting.
      if (!_hasCompleteBankDetails(app)) {
        if (typeof showToast === 'function') showToast('Cannot move to Underwriting — complete Bank Details (Lender Details tab) first', 'error');
        return;
      }
      if (!_hasObligationsCalculated(app)) {
        if (typeof showToast === 'function') showToast('Cannot move to Underwriting — complete Obligations calculation first', 'error');
        return;
      }
      app.status = 'underwriting';  // set before re-render so button guard fails immediately
      // Immediately post tracking entry so timeline updates on click (no async delay)
      if (typeof addTrackingEntry === 'function') {
        const rd = ROLES[currentUser.role] || {};
        addTrackingEntry(app, 'EFIN-Underwriting', rd.dept || 'Admin', 'Move', ' ');
      }
      if (typeof refreshDetailTimeline === 'function') refreshDetailTimeline(appId);
      changeStatus(appId, 'underwriting');
    }
    window.doUnderwriting = doUnderwriting;

    // ─────────────────────────────────────────────────────────────────
    //  Show workflow note in detail header subtitle area
    // ─────────────────────────────────────────────────────────────────
    function renderWorkflowNote(app) {
      const wf = getWorkflow(app.loanType, app.empType);
      const noteEl = document.getElementById('detail-workflow-note');
      if (!noteEl) return;
      if (wf.empNote) {
        noteEl.textContent = '💡 ' + wf.empNote;
        noteEl.style.display = '';
      } else {
        noteEl.style.display = 'none';
      }
    }


