    function openCreateRoleModal(editKey) {
      if (currentUser.role !== 'admin' && currentUser.role !== 'product_team') {
        showToast('Only Admin or Product Team can manage roles', 'error'); return;
      }
      _crEditKey = editKey || null;
      const rd = editKey ? ROLES[editKey] : null;

      document.getElementById('create-role-modal-title').textContent = rd ? ('✏️ Edit Role — ' + rd.label) : '⚙️ Create New Role';
      document.getElementById('cr-label').value  = rd ? rd.label     : '';
      document.getElementById('cr-key').value    = rd ? rd.key       : '';
      document.getElementById('cr-dept').value   = rd ? (rd.dept||'') : '';
      document.getElementById('cr-icon').value   = rd ? (rd.icon||'') : '';

      // Build permission toggles grid
      const grid = document.getElementById('cr-perm-grid');
      if (grid) {
        grid.innerHTML = PERM_GROUPS_ALL.map(({ group, perms }) => `
          <div style="background:var(--surface2);border:1px solid var(--border);border-radius:12px;padding:14px;break-inside:avoid">
            <div style="font-size:10px;font-weight:800;text-transform:uppercase;letter-spacing:.8px;color:var(--accent);margin-bottom:10px">${group}</div>
            ${perms.map(([pKey, label]) => {
              const val = rd ? !!rd[pKey] : false;
              return `<label style="display:flex;align-items:center;gap:8px;cursor:pointer;padding:4px 0;border-bottom:1px solid var(--border)">
                <span id="cr-pt-${pKey}" data-perm="${pKey}"
                  onclick="crTogglePerm('${pKey}',this)"
                  style="display:inline-flex;width:32px;height:17px;border-radius:99px;background:${val?'var(--accent)':'var(--border2)'};cursor:pointer;transition:background .18s;position:relative;flex-shrink:0;align-items:center;padding:2px">
                  <span style="width:13px;height:13px;border-radius:50%;background:#fff;box-shadow:0 1px 3px rgba(0,0,0,.2);transition:transform .18s;transform:translateX(${val?'15px':'0'})"></span>
                </span>
                <span style="font-size:12px;color:${val?'var(--text)':'var(--text3)'}">${label}</span>
              </label>`;
            }).join('')}
          </div>`).join('');
      }

      openModal('modal-create-role');
    }

    function crTogglePerm(pKey, el) {
      const isOn = el.dataset.state === 'on';
      const nowOn = !isOn;
      el.dataset.state = nowOn ? 'on' : 'off';
      el.style.background = nowOn ? 'var(--accent)' : 'var(--border2)';
      el.querySelector('span').style.transform = nowOn ? 'translateX(15px)' : 'translateX(0)';
      const lbl = el.parentElement.querySelector('span:last-child');
      if (lbl) lbl.style.color = nowOn ? 'var(--text)' : 'var(--text3)';
    }

    function saveRoleConfig() {
      const label = document.getElementById('cr-label').value.trim();
      const key   = document.getElementById('cr-key').value.trim();
      const dept  = document.getElementById('cr-dept').value.trim();
      const icon  = document.getElementById('cr-icon').value.trim();

      if (!label) { showToast('Role display name is required', 'error'); return; }
      if (!key)   { showToast('System key is required', 'error'); return; }

      // Collect permission states from the toggle grid
      const perms = {};
      PERM_GROUPS_ALL.forEach(({ perms: ps }) => {
        ps.forEach(([pKey]) => {
          const el = document.getElementById('cr-pt-' + pKey);
          perms[pKey] = el ? el.dataset.state === 'on' : false;
        });
      });

      // Derive a camelCase role key from the system key for ROLES object
      const roleKey = key.replace('group_','').replace(/_([a-z])/g, (_,c) => c.toUpperCase()) || label.toLowerCase().replace(/\s+/g,'_');

      const target = _crEditKey || roleKey;

      // Build/update the role object
      const existing = ROLES[target] || {};
      ROLES[target] = Object.assign({}, existing, {
        label, key, dept, icon: icon || '🔑',
        color: existing.color || 'rgba(26,79,163,.1)',
        textColor: existing.textColor || 'var(--accent)',
        badgeClass: existing.badgeClass || 'role-badge-admin',
        desc: existing.desc || label + ' — custom role configured by administrator.',
        ...perms,
      });

      closeModal('modal-create-role');
      showToast(_crEditKey ? 'Role updated: ' + label : 'Role created: ' + label, 'success');
      pushActivity('var(--accent)', '<strong>' + (_crEditKey ? 'Updated' : 'Created') + ' role</strong>: ' + label + ' (' + key + ')');
      renderAccessRights(); // Re-render cards with new role
      _crEditKey = null;
    }

    function deleteRole(roleKey) {
      const rd = ROLES[roleKey];
      if (!rd) return;
      if (roleKey === 'admin') { showToast('Cannot delete Admin role', 'error'); return; }
      const usersWithRole = twUsers.filter(u => u.role === rd.label).length;
      const msg = usersWithRole
        ? 'Delete role "' + rd.label + '"? \n\n⚠️ ' + usersWithRole + ' user(s) are assigned this role. They will lose access until reassigned.\n\nThis cannot be undone.'
        : 'Delete role "' + rd.label + '"? This cannot be undone.';
      if (!confirm(msg)) return;
      delete ROLES[roleKey];
      showToast('Role deleted: ' + rd.label, 'info');
      pushActivity('var(--danger)', '<strong>Deleted role</strong>: ' + rd.label);
      renderAccessRights();
    }

