    function _postSubmitProductTasks() {
      const productKey = window._wizardLoanProduct || 'personal_loan';
      const cfg = LOAN_PRODUCT_CONFIG[productKey];
      if (!cfg || !cfg.defaultTasks || !cfg.defaultTasks.length) return;
      const newApp = window.APPLICATIONS && window.APPLICATIONS[0];
      if (!newApp) return;
      const now = new Date();
      const dateStr = now.toLocaleDateString('en-IN') + ' ' + now.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
      const sysUser = (window.currentUser && window.currentUser.name) || 'System';
      cfg.defaultTasks.forEach(function(t) {
        const task = {
          id: Date.now() + Math.random(),
          appId: newApp.id,
          assign_type: t.type,
          name: t.label,
          user_name: sysUser,
          remarks: t.note,
          assign_user: 'System (Auto)',
          date_assigned: dateStr,
          status: 'draft',
          completed_user: null, completion_date: null, completion_remark: null,
        };
        if (window.TASK_STORE) window.TASK_STORE.push(task);
      });
      if (typeof addTrackingEntry === 'function') {
        addTrackingEntry(newApp, 'EFIN-Tasks Auto-Generated', 'System',
          cfg.defaultTasks.length + ' task(s) created for ' + cfg.label,
          cfg.defaultTasks.map(t => '• ' + t.label).join('\n'));
      }
      const extraDocs = cfg.extraDocs || [];
      if (extraDocs.length && typeof addTrackingEntry === 'function') {
        addTrackingEntry(newApp, 'EFIN-Document Checklist', 'System',
          'Required docs for ' + cfg.label,
          extraDocs.map(d => '• ' + d).join('\n'));
      }
    }

