// ── Permission helper ──
// Roles: admin → full; team_leader/login_team/sales → create+edit+view; partner → view only
function dsaCanCreate()  { return ['admin','team_leader','login_team','sales_executive','product_team'].includes(currentUser?.role); }
function dsaCanEdit() {
  const role = currentUser?.role || window.currentUser?.role || '';
  if (!role) return true; // default allow if role not loaded yet
  return ['admin','team_leader','login_team','sales_executive','product_team'].includes(role);
}
function dsaAdminOnly()  { return currentUser?.role === 'admin' || currentUser?.role === 'product_team'; }

function dsaIsPartnerRole() { return currentUser?.role === 'partner'; }
    // ── Insurance Premium Summary Refresh ────────────────────
    // Reads wizard fields from step 5 (Proposer Details) and populates
    // the step 6 Premium Summary panel. Called on entry to step 6 and
    // by the Refresh button.
    function insRefreshPremiumSummary() {
      const insTypeMap = {
        life:'Term Life Insurance', health:'Health / Mediclaim',
        vehicle:'Vehicle Insurance', general:'General / Property Insurance', ulip:'ULIP / Investment-linked'
      };
      const insurerMap = {
        lic:'LIC of India', hdfc_life:'HDFC Life', icici_pru:'ICICI Prudential',
        sbi_life:'SBI Life', bajaj_allianz:'Bajaj Allianz', max_life:'Max Life',
        tata_aia:'Tata AIA', kotak_life:'Kotak Mahindra Life',
        new_india:'New India Assurance', united_india:'United India Insurance',
        star_health:'Star Health', niva_bupa:'Niva Bupa',
        care_health:'Care Health', other:'Other / Any Insurer'
      };
      const set = (id, val) => { const el = document.getElementById(id); if (el) el.textContent = val || '—'; };
      const insType    = document.getElementById('w-ins-type')?.value || '';
      const sumAssured = document.getElementById('w-sum-assured')?.value || '';
      const tenure     = document.getElementById('w-tenure')?.value || '';
      const policyTerm = document.getElementById('w-policy-term')?.value || '';
      const insurer    = document.getElementById('w-ins-insurer')?.value || '';
      const fname      = document.getElementById('w-fname')?.value || '';
      const lname      = document.getElementById('w-lname')?.value || '';
      const nomName    = document.getElementById('w-nominee-name')?.value || '';
      const nomRel     = document.getElementById('w-nominee-relation')?.value || '';
      set('ins-sum-type',     insTypeMap[insType] || insType || '—');
      set('ins-sum-assured',  sumAssured ? '₹' + Number(sumAssured).toLocaleString('en-IN') : '—');
      set('ins-sum-term',     policyTerm ? policyTerm + ' Years' : (tenure ? tenure + ' Months' : '—'));
      set('ins-sum-insurer',  insurerMap[insurer] || insurer || 'Not specified');
      set('ins-sum-proposer', [fname, lname].filter(Boolean).join(' ') || '—');
      set('ins-sum-nominee',  nomName ? nomName + (nomRel ? ' (' + nomRel + ')' : '') : '—');
      // Auto-set w-loanamt to sum assured if not yet set
      const laEl = document.getElementById('w-loanamt');
      if (laEl && sumAssured && !laEl.value) laEl.value = sumAssured;
    }
    window.insRefreshPremiumSummary = insRefreshPremiumSummary;

