    function wTogglePreexisting(sel) {
      const panel = document.getElementById('w-preexisting-details');
      if (panel) panel.style.display = sel.value === 'yes' ? '' : 'none';
    }
    window.wTogglePreexisting = wTogglePreexisting;


// ─────── DSA MANAGEMENT ───────
let _dsaEditId = null, _dsaFilterStatus = '';

function dsaStatsRefresh() {
  const all = window.twDSAList || [];
  const partners = window.twPartnerList || [];
  const set = (id,v) => { const e=document.getElementById(id); if(e) e.textContent=v; };
  set('dsa-stat-total',    all.length);
  set('dsa-stat-active',   all.filter(d=>d.status==='active').length);
  set('dsa-stat-inactive', all.filter(d=>d.status==='inactive').length);
  set('dsa-stat-mapped',   partners.filter(p=>p.mappedDsaId).length);
}

function dsaRender(q) {
  const tb = document.getElementById('dsa-table-body'); if(!tb) return;
  let data = window.twDSAList || [];
  if (q) { const lc=q.toLowerCase(); data=data.filter(d=>d.name.toLowerCase().includes(lc)||d.code.toLowerCase().includes(lc)||(d.mobile||'').includes(lc)); }
  if (_dsaFilterStatus) data=data.filter(d=>d.status===_dsaFilterStatus);
  const canEdit  = dsaCanEdit();
  if (!data.length) { tb.innerHTML='<tr><td colspan="8" style="text-align:center;padding:40px;color:var(--text3)">No DSAs found</td></tr>'; return; }
  tb.innerHTML = data.map(d => {
    const mappedPartners = (window.twPartnerList||[]).filter(p=>p.mappedDsaId===d.id);
    const mappedApps = (typeof APPLICATIONS!=='undefined'?APPLICATIONS:[]).filter(a=>a.dsaId===d.id||(a.channel==='dsa'&&(a.channelDSA===d.name||a.dsaId===d.id)));
    const partnerApps = (typeof APPLICATIONS!=='undefined'?APPLICATIONS:[]).filter(a=>{
      const mp = mappedPartners.find(p=>p.id===a.partnerId||p.name===a.channelPartner);
      return !!mp && a.channel!=='dsa';
    });
    const totalApps = mappedApps.length + partnerApps.length;
    return `<tr>
    <td><div style="display:flex;align-items:center;gap:10px">
      <div style="width:34px;height:34px;border-radius:8px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;color:var(--accent)">${d.name.charAt(0)}</div>
      <strong>${d.name}</strong></div></td>
    <td><code style="font-size:11.5px;background:var(--surface2);padding:2px 8px;border-radius:6px">${d.code||'—'}</code></td>
    <td>${d.mobile||'—'}</td>
    <td style="font-size:12.5px;color:var(--text2)">${d.email||'—'}</td>
    <td>
      <button onclick="dsaOpenMappingOverview('${d.id}')" style="display:inline-flex;align-items:center;gap:6px;background:${mappedPartners.length?'rgba(161,89,255,.1)':'var(--surface2)'};border:1px solid ${mappedPartners.length?'rgba(161,89,255,.3)':'var(--border)'};border-radius:8px;padding:4px 10px;font-size:12px;font-weight:700;color:${mappedPartners.length?'#a159ff':'var(--text3)'};cursor:pointer;transition:all .15s" onmouseover="this.style.background='rgba(161,89,255,.18)';this.style.borderColor='rgba(161,89,255,.5)'" onmouseout="this.style.background='${mappedPartners.length?'rgba(161,89,255,.1)':'var(--surface2)'}';this.style.borderColor='${mappedPartners.length?'rgba(161,89,255,.3)':'var(--border)'}'">
        🔗 ${mappedPartners.length} Partner${mappedPartners.length!==1?'s':''}
      </button>
    </td>
    <td>
      <button onclick="dsaViewApps('${d.id}')" style="display:inline-flex;align-items:center;gap:6px;background:${totalApps?'var(--accent-subtle)':'var(--surface2)'};border:1px solid ${totalApps?'rgba(26,79,163,.25)':'var(--border)'};border-radius:8px;padding:4px 10px;font-size:12px;font-weight:700;color:${totalApps?'var(--accent)':'var(--text3)'};cursor:pointer;transition:all .15s" onmouseover="this.style.background='var(--accent-subtle)';this.style.borderColor='var(--accent)'" onmouseout="this.style.background='${totalApps?'var(--accent-subtle)':'var(--surface2)'}';this.style.borderColor='${totalApps?'rgba(26,79,163,.25)':'var(--border)'}'">
        📋 ${totalApps} App${totalApps!==1?'s':''}
      </button>
    </td>
    <td><span class="badge ${d.status==='active'?'badge-approved':'badge-hold'}">${d.status==='active'?'Active':'Inactive'}</span></td>
    <td style="text-align:right">
      ${canEdit
        ? `<div style="display:flex;gap:6px;justify-content:flex-end">
            <button class="btn btn-ghost btn-sm" onclick="dsaOpenEdit('${d.id}')" title="Edit DSA">✎ Edit</button>
            <button class="btn btn-ghost btn-sm" onclick="dsaToggleStatus('${d.id}')" title="${d.status==='active'?'Deactivate':'Activate'}" style="color:${d.status==='active'?'var(--warn)':'var(--success)'}">
              ${d.status==='active'?'⏸ Deactivate':'▶ Activate'}
            </button>
           </div>`
        : '<span style="font-size:12px;color:var(--text3)">View only</span>'}
    </td>
  </tr>`;
  }).join('');
  dsaStatsRefresh();
}
function dsaFilterStatus(v) { _dsaFilterStatus=v; dsaRender(document.getElementById('dsa-search-input')?.value||''); }

function dsaToggleStatus(id) {
  if (typeof dsaCanEdit === 'function' && !dsaCanEdit()) { showToast('Permission denied: your role cannot change DSA status','error'); return; }
  const dsa = (window.twDSAList||[]).find(d=>d.id===id);
  if (!dsa) return;
  const newStatus = dsa.status === 'active' ? 'inactive' : 'active';
  dsa.status = newStatus;
  persistSave && persistSave();
  dsaRender(document.getElementById('dsa-search-input')?.value||'');
  showToast((newStatus==='active'?'✅ DSA activated':'⏸ DSA deactivated') + ' — ' + dsa.name, newStatus==='active'?'success':'warn');
}

// ── DSA Document Upload helper ──
var _dsaDocs = {};
function dsaDocUpload(docKey, side, input) {
  const file = input.files[0]; if (!file) return;
  const k = docKey + (side === 'back' ? '_back' : '');
  _dsaDocs[k] = file;
  const nameSpanId = side === 'back' ? `dsa-doc-${docKey}-back-name` : `dsa-doc-${docKey}-name`;
  const nameSpan = document.getElementById(nameSpanId);
  if (nameSpan) { nameSpan.textContent = file.name; nameSpan.style.color = 'var(--success)'; }
  // Update badge
  const badgeId = `dsa-doc-${docKey}-badge`;
  const badge = document.getElementById(badgeId);
  if (badge) {
    const frontKey = docKey, backKey = docKey + '_back';
    const needsBack = ['aadhar'].includes(docKey);
    const uploaded = _dsaDocs[frontKey] && (!needsBack || _dsaDocs[backKey]);
    badge.textContent = uploaded ? '✓ Uploaded' : 'Partial';
    badge.style.background = uploaded ? 'rgba(26,115,64,.12)' : 'rgba(230,126,0,.12)';
    badge.style.color = uploaded ? 'var(--success)' : 'var(--warn)';
  }
}

function dsaOpenAdd() {
  if (!dsaCanCreate()) { showToast('Permission denied: your role cannot add DSAs','error'); return; }
  _dsaEditId = null;
  document.getElementById('dsa-form-title').textContent='Add New DSA';
  document.getElementById('dsa-save-btn').textContent='Save DSA';
  ['dsa-f-name','dsa-f-code','dsa-f-mobile','dsa-f-email','dsa-f-pan',
   'dsa-f-office-addr','dsa-f-office-city','dsa-f-office-state','dsa-f-office-pin'].forEach(id=>{ const e=document.getElementById(id); if(e) e.value=''; });
  document.getElementById('dsa-f-status').value='active';
  const oat = document.getElementById('dsa-f-office-addr-type'); if(oat) oat.value='';
  // Reset doc badges & labels
  ['aadhar','pan','compan','breg','offaddr'].forEach(k=>{
    const b=document.getElementById(`dsa-doc-${k}-badge`);
    if(b){b.textContent='Pending';b.style.background='var(--surface3)';b.style.color='var(--text3)';}
    ['','-back'].forEach(sfx=>{
      const s=document.getElementById(`dsa-doc-${k}${sfx}-name`);
      if(s){s.textContent='Choose file…';s.style.color='var(--text3)';}
    });
    delete _dsaDocs[k]; delete _dsaDocs[k+'_back'];
  });
  document.getElementById('dsa-form-card').style.display='';
  document.getElementById('dsa-form-card').scrollIntoView({behavior:'smooth',block:'start'});
}
function dsaOpenEdit(id) {
  if (!dsaCanEdit()) { showToast('Permission denied','error'); return; }
  const d=(window.twDSAList||[]).find(x=>x.id===id); if(!d) return;
  _dsaEditId = id;
  document.getElementById('dsa-form-title').textContent='Edit DSA — '+d.name;
  document.getElementById('dsa-save-btn').textContent='Update DSA';
  document.getElementById('dsa-f-name').value=d.name||'';
  document.getElementById('dsa-f-code').value=d.code||'';
  document.getElementById('dsa-f-mobile').value=d.mobile||'';
  document.getElementById('dsa-f-email').value=d.email||'';
  document.getElementById('dsa-f-pan').value=d.pan||'';
  document.getElementById('dsa-f-status').value=d.status||'active';
  const oaEl=document.getElementById('dsa-f-office-addr'); if(oaEl) oaEl.value=d.officeAddr||'';
  const ocEl=document.getElementById('dsa-f-office-city'); if(ocEl) ocEl.value=d.officeCity||'';
  const osEl=document.getElementById('dsa-f-office-state'); if(osEl) osEl.value=d.officeState||'';
  const opEl=document.getElementById('dsa-f-office-pin'); if(opEl) opEl.value=d.officePin||'';
  const oatEl=document.getElementById('dsa-f-office-addr-type'); if(oatEl) oatEl.value=d.officeAddrType||'';
  document.getElementById('dsa-form-card').style.display='';
  document.getElementById('dsa-form-card').scrollIntoView({behavior:'smooth',block:'start'});
}
function dsaCloseForm() { document.getElementById('dsa-form-card').style.display='none'; _dsaEditId=null; }
function dsaSave() {
  const _ok = (typeof dsaCanCreate==='function'?dsaCanCreate():true) || (typeof dsaCanEdit==='function'?dsaCanEdit():true);
  if (!_ok) { showToast('Permission denied','error'); return; }
  const name   = document.getElementById('dsa-f-name').value.trim();
  const code   = document.getElementById('dsa-f-code').value.trim();
  const mobile = document.getElementById('dsa-f-mobile').value.trim();
  const email  = document.getElementById('dsa-f-email').value.trim();
  const pan    = document.getElementById('dsa-f-pan').value.trim().toUpperCase();
  const status = document.getElementById('dsa-f-status').value;
  const officeAddr     = (document.getElementById('dsa-f-office-addr')?.value||'').trim();
  const officeCity     = (document.getElementById('dsa-f-office-city')?.value||'').trim();
  const officeState    = (document.getElementById('dsa-f-office-state')?.value||'').trim();
  const officePin      = (document.getElementById('dsa-f-office-pin')?.value||'').trim();
  const officeAddrType = (document.getElementById('dsa-f-office-addr-type')?.value||'');
  const docs = { ..._dsaDocs };
  if (!name)   { showToast('DSA Name is required','error'); return; }
  if (!mobile||mobile.length!==10) { showToast('Valid 10-digit mobile required','error'); return; }
  if (_dsaEditId) {
    const d=(window.twDSAList||[]).find(x=>x.id===_dsaEditId);
    if(d){ d.name=name; d.code=code||(d.code); d.mobile=mobile; d.email=email; d.pan=pan; d.status=status;
      d.officeAddr=officeAddr; d.officeCity=officeCity; d.officeState=officeState; d.officePin=officePin; d.officeAddrType=officeAddrType; d.docs=Object.assign(d.docs||{},docs); }
    if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
    showToast('DSA updated successfully','success');
  } else {
    const newCode = code || 'DSA'+String(Date.now()).slice(-4);
    window.twDSAList.push({ id:'DSA'+Date.now(), name, code:newCode, mobile, email, pan, status, linkedPartners:[],
      officeAddr, officeCity, officeState, officePin, officeAddrType, docs });
    if (typeof persistSave === 'function') persistSave();
    showToast('DSA added successfully','success');
  }
  dsaCloseForm();
  dsaRender('');
  dsaStatsRefresh();
}

// ─────── PARTNER MANAGEMENT ───────
var _pmEditId = null, _pmFilterStatus = '';

function pmStatsRefresh() {
  const all = window.twPartnerList || [];
  const set = (id,v) => { const e=document.getElementById(id); if(e) e.textContent=v; };
  set('pm-stat-total',    all.length);
  set('pm-stat-active',   all.filter(p=>p.status==='active').length);
  set('pm-stat-inactive', all.filter(p=>p.status==='inactive').length);
}

// ── Populate the DSA dropdown in Partner form ──
function pmPopulateDsaDropdown(currentVal) {
  const sel = document.getElementById('pm-f-dsa-id'); if(!sel) return;
  sel.innerHTML = '<option value="">— No DSA Mapping —</option>' +
    (window.twDSAList||[]).filter(d=>d.status==='active').map(d => {
      const cnt = (window.twPartnerList||[]).filter(p=>p.mappedDsaId===d.id).length;
      return `<option value="${d.id}" ${d.id===currentVal?'selected':''}>${d.name} (${d.code}) · ${cnt} partner${cnt!==1?'s':''}</option>`;
    }).join('');
  // Trigger preview if a value is pre-selected
  if (currentVal) pmDsaMappingPreview(currentVal);
  else { const pv=document.getElementById('pm-dsa-preview'); if(pv) pv.style.display='none'; }
}

// ── Live DSA preview card in partner form ──
function pmDsaMappingPreview(dsaId) {
  const pv = document.getElementById('pm-dsa-preview'); if(!pv) return;
  if (!dsaId) { pv.style.display='none'; return; }
  const d = (window.twDSAList||[]).find(x=>x.id===dsaId);
  if (!d) { pv.style.display='none'; return; }
  // Count how many partners (excluding current edit) are already mapped to this DSA
  const mapped = (window.twPartnerList||[]).filter(p=>p.mappedDsaId===d.id && p.id!==_pmEditId);
  document.getElementById('pm-dsa-preview-avi').textContent  = d.name.charAt(0).toUpperCase();
  document.getElementById('pm-dsa-preview-name').textContent = d.name;
  document.getElementById('pm-dsa-preview-code').textContent = d.code + (d.mobile?' · '+d.mobile:'');
  document.getElementById('pm-dsa-preview-partners').textContent = mapped.length + ' partner'+(mapped.length!==1?'s':'')+' currently mapped';
  const statusEl = document.getElementById('pm-dsa-preview-status');
  statusEl.textContent = d.status==='active' ? 'Active' : 'Inactive';
  statusEl.style.cssText = `margin-left:auto;font-size:10px;padding:2px 8px;border-radius:20px;font-weight:700;flex-shrink:0;background:${d.status==='active'?'rgba(26,115,64,.12)':'rgba(138,150,180,.12)'};color:${d.status==='active'?'var(--success)':'var(--text3)'};`;
  pv.style.display = '';
}

function pmRender(q) {
  const tb = document.getElementById('pm-table-body'); if(!tb) return;
  let data = window.twPartnerList || [];
  if (q) { const lc=q.toLowerCase(); data=data.filter(p=>p.name.toLowerCase().includes(lc)||p.code.toLowerCase().includes(lc)||(p.mobile||'').includes(lc)); }
  if (_pmFilterStatus) data=data.filter(p=>p.status===_pmFilterStatus);
  const canEdit = dsaCanEdit();
  if (!data.length) { tb.innerHTML='<tr><td colspan="8" style="text-align:center;padding:40px;color:var(--text3)">No partners found</td></tr>'; return; }
  const typeColor={individual:'badge-approved',firm:'badge-login',agent:'badge-wip'};
  tb.innerHTML = data.map(p => {
    const mappedDsa = p.mappedDsaId ? (window.twDSAList||[]).find(d=>d.id===p.mappedDsaId) : null;
    const dsaCell = mappedDsa
      ? `<button onclick="dsaOpenMappingOverview('${mappedDsa.id}')" style="display:inline-flex;align-items:center;gap:6px;background:rgba(161,89,255,.1);border:1px solid rgba(161,89,255,.28);border-radius:8px;padding:4px 10px;font-size:12px;font-weight:700;color:#a159ff;cursor:pointer;transition:all .15s;max-width:160px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" onmouseover="this.style.background='rgba(161,89,255,.2)'" onmouseout="this.style.background='rgba(161,89,255,.1)'" title="View DSA mapping for ${mappedDsa.name}">🔗 ${mappedDsa.name}</button>`
      : `<span style="font-size:12px;color:var(--text3);font-style:italic">Unmapped</span>`;
    return `<tr>
    <td><div style="display:flex;align-items:center;gap:10px">
      <div style="width:34px;height:34px;border-radius:8px;background:rgba(161,89,255,.1);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:700;color:#a159ff">${p.name.charAt(0)}</div>
      <strong>${p.name}</strong></div></td>
    <td><code style="font-size:11.5px;background:var(--surface2);padding:2px 8px;border-radius:6px">${p.code||'—'}</code></td>
    <td>${p.mobile||'—'}</td>
    <td style="font-size:12.5px;color:var(--text2)">${p.email||'—'}</td>
    <td><span class="badge ${typeColor[p.type]||'badge-hold'}" style="font-size:10.5px;text-transform:capitalize">${p.type||'—'}</span></td>
    <td>${dsaCell}</td>
    <td><span class="badge ${p.status==='active'?'badge-approved':'badge-hold'}">${p.status==='active'?'Active':'Inactive'}</span></td>
    <td style="text-align:right">
      ${canEdit
        ? `<div style="display:flex;gap:6px;justify-content:flex-end">
            <button class="btn btn-ghost btn-sm" onclick="pmOpenEdit('${p.id}')" title="Edit Partner">✎ Edit</button>
            <button class="btn btn-ghost btn-sm" onclick="pmToggleStatus('${p.id}')" title="${p.status==='active'?'Deactivate':'Activate'}" style="color:${p.status==='active'?'var(--warn)':'var(--success)'}">
              ${p.status==='active'?'⏸ Deactivate':'▶ Activate'}
            </button>
           </div>`
        : '<span style="font-size:12px;color:var(--text3)">View only</span>'}
    </td>
  </tr>`;
  }).join('');
  pmStatsRefresh();
}

function pmFilterStatus(v) { _pmFilterStatus=v; pmRender(document.getElementById('pm-search-input')?.value||''); }

function pmToggleStatus(id) {
  if (typeof dsaCanEdit === 'function' && !dsaCanEdit()) { showToast('Permission denied: your role cannot change Partner status','error'); return; }
  const partner = (window.twPartnerList||[]).find(p=>p.id===id);
  if (!partner) return;
  const newStatus = partner.status === 'active' ? 'inactive' : 'active';
  partner.status = newStatus;
  persistSave && persistSave();
  pmRender(document.getElementById('pm-search-input')?.value||'');
  showToast((newStatus==='active'?'✅ Partner activated':'⏸ Partner deactivated') + ' — ' + partner.name, newStatus==='active'?'success':'warn');
}

function pmOpenAdd() {
  if (!dsaCanCreate()) { showToast('Permission denied: your role cannot add Partners','error'); return; }
  _pmEditId = null;
  document.getElementById('pm-form-title').textContent = 'Add New Partner';
  document.getElementById('pm-save-btn').textContent   = 'Save Partner';
  ['pm-f-name','pm-f-code','pm-f-mobile','pm-f-email'].forEach(id=>{ const e=document.getElementById(id); if(e) e.value=''; });
  document.getElementById('pm-f-type').value   = 'individual';
  document.getElementById('pm-f-status').value = 'active';
  pmPopulateDsaDropdown('');
  document.getElementById('pm-form-card').style.display = '';
  document.getElementById('pm-form-card').scrollIntoView({behavior:'smooth',block:'start'});
}

function pmOpenEdit(id) {
  if (!dsaCanEdit()) { showToast('Permission denied','error'); return; }
  const p = (window.twPartnerList||[]).find(x=>x.id===id); if(!p) return;
  _pmEditId = id;
  document.getElementById('pm-form-title').textContent = 'Edit Partner — '+p.name;
  document.getElementById('pm-save-btn').textContent   = 'Update Partner';
  document.getElementById('pm-f-name').value   = p.name   || '';
  document.getElementById('pm-f-code').value   = p.code   || '';
  document.getElementById('pm-f-mobile').value = p.mobile || '';
  document.getElementById('pm-f-email').value  = p.email  || '';
  document.getElementById('pm-f-type').value   = p.type   || 'individual';
  document.getElementById('pm-f-status').value = p.status || 'active';
  pmPopulateDsaDropdown(p.mappedDsaId || '');
  document.getElementById('pm-form-card').style.display = '';
  document.getElementById('pm-form-card').scrollIntoView({behavior:'smooth',block:'start'});
}

function pmCloseForm() {
  document.getElementById('pm-form-card').style.display = 'none';
  _pmEditId = null;
}

function pmSave() {
  const _ok = (typeof dsaCanCreate==='function'?dsaCanCreate():true) || (typeof dsaCanEdit==='function'?dsaCanEdit():true);
  if (!_ok) { showToast('Permission denied','error'); return; }
  const name       = document.getElementById('pm-f-name').value.trim();
  const code       = document.getElementById('pm-f-code').value.trim();
  const mobile     = document.getElementById('pm-f-mobile').value.trim();
  const email      = document.getElementById('pm-f-email').value.trim();
  const type       = document.getElementById('pm-f-type').value;
  const status     = document.getElementById('pm-f-status').value;
  const mappedDsaId = document.getElementById('pm-f-dsa-id')?.value || '';

  if (!name)                        { showToast('Partner Name is required','error'); return; }
  if (!mobile || mobile.length!==10){ showToast('Valid 10-digit mobile required','error'); return; }

  if (_pmEditId) {
    const p = (window.twPartnerList||[]).find(x=>x.id===_pmEditId);
    if (p) {
      const oldDsaId = p.mappedDsaId || '';
      p.name = name; p.code = code||(p.code); p.mobile = mobile;
      p.email = email; p.type = type; p.status = status;
      p.mappedDsaId = mappedDsaId;
      // Sync DSA linkedPartners arrays
      _pmSyncDsaLinks(p.id, oldDsaId, mappedDsaId);
    }
    if (typeof persistSave === 'function') { try { persistSave(); } catch(_) {} }
    showToast('Partner updated successfully','success');
  } else {
    const newCode = code || 'PAR'+String(Date.now()).slice(-4);
    const newId   = 'PAR'+Date.now();
    window.twPartnerList.push({ id:newId, name, code:newCode, mobile, email, type, status, mappedDsaId });
    _pmSyncDsaLinks(newId, '', mappedDsaId);
    if (typeof persistSave === 'function') persistSave();
    showToast('Partner added successfully','success');
  }
  pmCloseForm();
  pmRender('');
  pmStatsRefresh();
  dsaStatsRefresh();
  // Re-render DSA table to update partner count badges
  dsaRender('');
}

// ── Sync DSA linkedPartners when a partner's mapping changes ──
function _pmSyncDsaLinks(partnerId, oldDsaId, newDsaId) {
  // Remove from old DSA
  if (oldDsaId) {
    const oldDsa = (window.twDSAList||[]).find(d=>d.id===oldDsaId);
    if (oldDsa) {
      oldDsa.linkedPartners = (oldDsa.linkedPartners||[]).filter(x=>x!==partnerId);
    }
  }
  // Add to new DSA
  if (newDsaId) {
    const newDsa = (window.twDSAList||[]).find(d=>d.id===newDsaId);
    if (newDsa) {
      if (!newDsa.linkedPartners) newDsa.linkedPartners = [];
      if (!newDsa.linkedPartners.includes(partnerId)) newDsa.linkedPartners.push(partnerId);
    }
  }
}

// ════════════════════════════════════════════════════════
//  DSA MAPPING OVERVIEW MODAL
// ════════════════════════════════════════════════════════

var _dsaMappingFilterDsaId = '';

function dsaOpenMappingOverview(filterDsaId) {
  _dsaMappingFilterDsaId = filterDsaId || '';
  const overlay = document.getElementById('dsa-mapping-overlay');
  if (!overlay) return;
  overlay.style.display = 'flex';

  // Populate DSA filter dropdown
  const filterSel = document.getElementById('dsa-mapping-dsa-filter');
  if (filterSel) {
    filterSel.innerHTML = '<option value="">All DSAs</option>' +
      (window.twDSAList||[]).map(d=>`<option value="${d.id}" ${d.id===_dsaMappingFilterDsaId?'selected':''}>${d.name}</option>`).join('');
  }
  // Clear search
  const si = document.getElementById('dsa-mapping-search'); if(si) si.value='';
  renderDsaMappingOverview('');
}

function dsaCloseMappingOverview() {
  const overlay = document.getElementById('dsa-mapping-overlay');
  if (overlay) overlay.style.display = 'none';
}

function renderDsaMappingOverview(q) {
  const body = document.getElementById('dsa-mapping-body'); if(!body) return;
  const filterDsaId = document.getElementById('dsa-mapping-dsa-filter')?.value || '';
  const lc = (q||'').toLowerCase();

  const allDsas = (window.twDSAList||[]).filter(d=> !filterDsaId || d.id===filterDsaId);
  const allPartners = window.twPartnerList || [];

  if (!allDsas.length) {
    body.innerHTML = `<div style="text-align:center;padding:60px;color:var(--text3)"><div style="font-size:40px;margin-bottom:12px">🔗</div><div style="font-size:14px">No DSAs found</div></div>`;
    return;
  }

  let html = '';
  let anyVisible = false;

  allDsas.forEach(dsa => {
    // Partners mapped to this DSA
    let partners = allPartners.filter(p => p.mappedDsaId === dsa.id);
    // Apply search filter
    if (lc) {
      const dsaMatch = dsa.name.toLowerCase().includes(lc) || (dsa.code||'').toLowerCase().includes(lc);
      if (!dsaMatch) {
        partners = partners.filter(p =>
          p.name.toLowerCase().includes(lc) ||
          (p.code||'').toLowerCase().includes(lc) ||
          (p.mobile||'').includes(lc)
        );
        if (!partners.length) return; // skip this DSA entirely
      }
    }
    anyVisible = true;

    // Count apps for this DSA (direct DSA channel + partner-sourced)
    const apps = typeof APPLICATIONS!=='undefined' ? APPLICATIONS : [];
    const directApps  = apps.filter(a => a.channel==='dsa' && (a.dsaId===dsa.id || a.channelDSA===dsa.name));
    const partnerApps = apps.filter(a => {
      const mp = partners.find(p => p.id===a.partnerId || p.name===a.channelPartner);
      return !!mp && a.channel!=='dsa';
    });
    const totalApps = directApps.length + partnerApps.length;

    html += `
    <div style="background:var(--surface);border:1.5px solid var(--border);border-radius:16px;overflow:hidden;margin-bottom:18px;box-shadow:0 2px 12px rgba(26,79,163,.05)">
      <!-- DSA header -->
      <div style="display:flex;align-items:center;gap:14px;padding:16px 20px;background:linear-gradient(135deg,rgba(26,79,163,.05),rgba(26,79,163,.02));border-bottom:1px solid var(--border)">
        <div style="width:44px;height:44px;border-radius:12px;background:var(--accent-subtle);display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:var(--accent);flex-shrink:0">${dsa.name.charAt(0)}</div>
        <div style="flex:1;min-width:0">
          <div style="font-family:var(--font-head);font-size:15px;font-weight:800;color:var(--text)">${dsa.name}</div>
          <div style="display:flex;gap:12px;margin-top:3px;flex-wrap:wrap">
            <span style="font-size:11.5px;color:var(--text3)"><code style="background:var(--surface2);padding:1px 6px;border-radius:4px;font-size:11px">${dsa.code}</code></span>
            ${dsa.mobile?`<span style="font-size:11.5px;color:var(--text3)">📱 ${dsa.mobile}</span>`:''}
            ${dsa.email?`<span style="font-size:11.5px;color:var(--text3)">✉️ ${dsa.email}</span>`:''}
          </div>
        </div>
        <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap">
          <div style="text-align:center;background:rgba(161,89,255,.1);border:1px solid rgba(161,89,255,.2);border-radius:10px;padding:6px 14px">
            <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:#a159ff">${partners.length}</div>
            <div style="font-size:10px;color:var(--text3);font-weight:600;text-transform:uppercase;letter-spacing:.6px">Partner${partners.length!==1?'s':''}</div>
          </div>
          <div style="text-align:center;background:var(--accent-subtle);border:1px solid rgba(26,79,163,.2);border-radius:10px;padding:6px 14px;cursor:pointer" onclick="dsaViewApps('${dsa.id}')" title="View all applications for this DSA">
            <div style="font-family:var(--font-head);font-size:20px;font-weight:800;color:var(--accent)">${totalApps}</div>
            <div style="font-size:10px;color:var(--text3);font-weight:600;text-transform:uppercase;letter-spacing:.6px">App${totalApps!==1?'s':''}</div>
          </div>
          <span class="badge ${dsa.status==='active'?'badge-approved':'badge-hold'}" style="font-size:11px">${dsa.status==='active'?'Active':'Inactive'}</span>
        </div>
      </div>
      <!-- Partners list -->
      ${partners.length===0
        ? `<div style="padding:20px 22px;color:var(--text3);font-size:13px;font-style:italic">No partners mapped to this DSA yet. <button onclick="dsaCloseMappingOverview();showPage('partner-mgmt',null)" class="btn btn-ghost btn-sm" style="margin-left:8px">＋ Map a Partner</button></div>`
        : `<div style="padding:14px 20px">
            <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:1.2px;color:var(--text3);margin-bottom:10px">Mapped Partner IDs</div>
            <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(240px,1fr));gap:10px">
              ${partners.map(p => {
                const typeColor={individual:'#1a7340',firm:'var(--accent)',agent:'var(--warn)'};
                const pApps = apps.filter(a=>a.partnerId===p.id||a.channelPartner===p.name);
                return `<div style="display:flex;align-items:center;gap:10px;padding:10px 14px;background:var(--surface2);border:1px solid var(--border);border-radius:10px;transition:all .15s;cursor:pointer" onclick="dsaViewPartnerApps('${dsa.id}','${p.id}')" onmouseover="this.style.borderColor='rgba(161,89,255,.4)';this.style.background='rgba(161,89,255,.06)'" onmouseout="this.style.borderColor='var(--border)';this.style.background='var(--surface2)'">
                  <div style="width:32px;height:32px;border-radius:8px;background:rgba(161,89,255,.1);display:flex;align-items:center;justify-content:center;font-size:13px;font-weight:800;color:#a159ff;flex-shrink:0">${p.name.charAt(0)}</div>
                  <div style="flex:1;min-width:0">
                    <div style="font-size:13px;font-weight:600;color:var(--text);white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${p.name}</div>
                    <div style="display:flex;gap:8px;margin-top:2px;flex-wrap:wrap">
                      <code style="font-size:10px;background:var(--surface3);padding:1px 5px;border-radius:4px">${p.code}</code>
                      <span style="font-size:10.5px;color:${typeColor[p.type]||'var(--text3)'};font-weight:600;text-transform:capitalize">${p.type}</span>
                    </div>
                  </div>
                  <div style="text-align:center;flex-shrink:0">
                    <div style="font-size:14px;font-weight:800;color:var(--accent);font-family:var(--font-head)">${pApps.length}</div>
                    <div style="font-size:9.5px;color:var(--text3)">Apps</div>
                  </div>
                </div>`;
              }).join('')}
            </div>
          </div>`
      }
    </div>`;
  });

  if (!anyVisible) {
    body.innerHTML = `<div style="text-align:center;padding:60px;color:var(--text3)"><div style="font-size:40px;margin-bottom:12px">🔍</div><div style="font-size:14px">No results for "${q}"</div></div>`;
    return;
  }
  body.innerHTML = html;
}

// ════════════════════════════════════════════════════════
//  DSA APPLICATIONS DRILL-DOWN
// ════════════════════════════════════════════════════════

function dsaViewApps(dsaId, filterPartnerId) {
  const dsa = (window.twDSAList||[]).find(d=>d.id===dsaId);
  if (!dsa) return;

  const overlay = document.getElementById('dsa-apps-overlay');
  const titleEl  = document.getElementById('dsa-apps-title');
  const subEl    = document.getElementById('dsa-apps-subtitle');
  const bodyEl   = document.getElementById('dsa-apps-body');
  if (!overlay) return;

  const partners = (window.twPartnerList||[]).filter(p=>p.mappedDsaId===dsaId);
  const apps = typeof APPLICATIONS!=='undefined' ? APPLICATIONS : [];

  // Collect all apps: direct DSA channel + apps from mapped partners
  const directApps = apps.filter(a => a.channel==='dsa' && (a.dsaId===dsaId || a.channelDSA===dsa.name));
  const partnerAppsList = partners.flatMap(p => {
    if (filterPartnerId && p.id!==filterPartnerId) return [];
    return apps.filter(a => (a.partnerId===p.id || a.channelPartner===p.name) && a.channel!=='dsa')
      .map(a => ({...a, _fromPartner: p.name, _fromPartnerId: p.id}));
  });

  const allApps = [...directApps.map(a=>({...a,_fromPartner:'Direct DSA',_fromPartnerId:''})), ...partnerAppsList];

  titleEl.textContent  = filterPartnerId
    ? `Applications — ${partners.find(p=>p.id===filterPartnerId)?.name||'Partner'}`
    : `Applications — ${dsa.name}`;
  subEl.textContent    = filterPartnerId
    ? `Filtered to partner · ${allApps.length} application${allApps.length!==1?'s':''}`
    : `${dsa.name} (${dsa.code}) · ${allApps.length} total application${allApps.length!==1?'s':''}`;

  overlay.style.display = 'flex';

  if (!allApps.length) {
    bodyEl.innerHTML = `<div style="text-align:center;padding:60px;color:var(--text3)"><div style="font-size:40px;margin-bottom:12px">📋</div><div style="font-size:14px">No applications found for this DSA</div></div>`;
    return;
  }

  const statusColors = { wip:'#f59e0b',login:'var(--accent)',underwriting:'#6366f1',approved:'var(--success)',disbursed:'var(--info)',rejected:'var(--danger)',hold:'var(--warn)',offer:'#8b5cf6' };
  const STATUSES_LBL = { wip:'WIP',login:'Assign Lender',underwriting:'Underwriting',approved:'Approved',disbursed:'Disbursed',rejected:'Rejected',hold:'On Hold',offer:'Offer' };

  bodyEl.innerHTML = `
    <div style="padding:0 0 4px">
      <table style="width:100%;border-collapse:collapse">
        <thead>
          <tr style="background:var(--surface2);border-bottom:2px solid var(--border)">
            <th style="padding:12px 20px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">App ID</th>
            <th style="padding:12px 16px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Applicant</th>
            <th style="padding:12px 16px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Via</th>
            <th style="padding:12px 16px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Loan Type</th>
            <th style="padding:12px 16px;text-align:right;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Amount</th>
            <th style="padding:12px 16px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Status</th>
            <th style="padding:12px 16px;text-align:left;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px">Date</th>
            <th style="padding:12px 20px;text-align:right;font-size:10.5px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.8px"></th>
          </tr>
        </thead>
        <tbody>
          ${allApps.map(a => `
          <tr style="border-bottom:1px solid var(--border);transition:background .15s" onmouseover="this.style.background='var(--surface2)'" onmouseout="this.style.background=''">
            <td style="padding:12px 20px"><span style="font-family:monospace;font-size:12px;font-weight:700;color:var(--accent);background:var(--accent-subtle);padding:3px 8px;border-radius:6px">${a.id}</span></td>
            <td style="padding:12px 16px">
              <div style="font-size:13px;font-weight:600;color:var(--text)">${a.name||'—'}</div>
              <div style="font-size:11px;color:var(--text3);margin-top:1px">${a.mobile||''}</div>
            </td>
            <td style="padding:12px 16px">
              <span style="font-size:11.5px;padding:2px 8px;border-radius:6px;font-weight:600;background:${a._fromPartner==='Direct DSA'?'var(--accent-subtle)':'rgba(161,89,255,.1)'};color:${a._fromPartner==='Direct DSA'?'var(--accent)':'#a159ff'}">${a._fromPartner==='Direct DSA'?'Direct DSA':a._fromPartner}</span>
            </td>
            <td style="padding:12px 16px;font-size:12.5px;color:var(--text2)">${typeof loanTypeLabel==='function'?loanTypeLabel(a.loanType):(a.loanType||'—')}</td>
            <td style="padding:12px 16px;text-align:right;font-size:13px;font-weight:700;color:var(--text)">₹${Number(a.amount||0).toLocaleString('en-IN')}</td>
            <td style="padding:12px 16px"><span style="font-size:11px;padding:3px 9px;border-radius:20px;font-weight:700;background:${statusColors[a.status]||'#9ca3af'}22;color:${statusColors[a.status]||'#9ca3af'};border:1px solid ${statusColors[a.status]||'#9ca3af'}44">${STATUSES_LBL[a.status]||a.status||'—'}</span></td>
            <td style="padding:12px 16px;font-size:12px;color:var(--text3)">${a.date||'—'}</td>
            <td style="padding:12px 20px;text-align:right"><button class="btn btn-ghost btn-sm" onclick="dsaCloseAppsModal();openDetail('${a.id}')">Open →</button></td>
          </tr>`).join('')}
        </tbody>
      </table>
    </div>`;
}

function dsaViewPartnerApps(dsaId, partnerId) {
  dsaViewApps(dsaId, partnerId);
}

function dsaCloseAppsModal() {
  const overlay = document.getElementById('dsa-apps-overlay');
  if (overlay) overlay.style.display = 'none';
}

