function buildSanctionSummaryHTML(app) {
  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
  const emiDateLabel = d => d === '1' ? '1st' : d === '2' ? '2nd' : d === '3' ? '3rd' : (d + 'th');
  const lbl = (typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : app.loanType) || '—';
  const hasSanction = !!(app.sanctionLoanAmt || app.sanctionEMI || app.sanctionROI);
  return `
    <div style="display:flex;flex-direction:column;gap:0;width:100%">
      <div style="display:flex;flex-wrap:wrap;gap:10px 20px;padding-bottom:${hasSanction ? '10px' : '0'};border-bottom:${hasSanction ? '1px solid var(--border)' : 'none'};margin-bottom:${hasSanction ? '10px' : '0'}">
        <div class="esm-info-item"><div class="esm-info-label">Applicant</div><div class="esm-info-val">${app.name}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Loan Type</div><div class="esm-info-val">${lbl}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Bank</div><div class="esm-info-val">${app.bank || '—'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">CIBIL</div><div class="esm-info-val">${app.cibil || '—'}</div></div>
      </div>
      ${hasSanction ? `
      <div style="font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:var(--accent);margin-bottom:8px">✅ Approved Sanction Details</div>
      <div style="display:flex;flex-wrap:wrap;gap:10px 20px">
        <div class="esm-info-item"><div class="esm-info-label">Loan Amount</div><div class="esm-info-val" style="color:var(--accent)">${fmt(app.sanctionLoanAmt)}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Tenure</div><div class="esm-info-val">${app.sanctionTenureMo ? app.sanctionTenureMo + ' mo' : '—'}${app.sanctionTenureYr ? ' (' + app.sanctionTenureYr + ' yr)' : ''}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">ROI (Annual)</div><div class="esm-info-val">${app.sanctionROI ? app.sanctionROI + '%' : '—'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">EMI</div><div class="esm-info-val" style="color:var(--success)">${fmt(app.sanctionEMI)}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Processing Fee</div><div class="esm-info-val">${app.sanctionPFPct ? app.sanctionPFPct + '%' : '—'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Bundled Amt</div><div class="esm-info-val">${fmt(app.sanctionBundled)}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Insurance</div><div class="esm-info-val">${fmt(app.sanctionInsurance)}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">BT</div><div class="esm-info-val">${app.sanctionBT || 'NO'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">EMI Date</div><div class="esm-info-val">${app.sanctionEMIDate ? emiDateLabel(String(app.sanctionEMIDate)) + ' of month' : '—'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">GST</div><div class="esm-info-val">${app.sanctionGST ? app.sanctionGST + '%' : '18%'}</div></div>
        <div class="esm-info-item"><div class="esm-info-label">Stamp Duty</div><div class="esm-info-val" style="font-size:11.5px">${app.sanctionStamp || '—'}</div></div>
        ${app.sanctionFlatRate ? `<div class="esm-info-item"><div class="esm-info-label">Flat Rate</div><div class="esm-info-val">${app.sanctionFlatRate}%</div></div>` : ''}
      </div>` : '<div style="font-size:12px;color:var(--text3);font-style:italic">No sanction details recorded yet.</div>'}
    </div>`;
}

function openDeviationModal(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  document.getElementById('dev-app-id').value = appId;
  document.getElementById('dev-app-badge').textContent = appId;
  document.getElementById('dev-type').value = '';
  document.getElementById('dev-reason').value = '';
  document.getElementById('deviation-overlay').classList.add('open');
}

function closeDeviationModal() {
  document.getElementById('deviation-overlay').classList.remove('open');
}

function confirmDeviation() {
  const appId   = document.getElementById('dev-app-id').value;
  const app     = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const devType = document.getElementById('dev-type').value;
  const reason  = document.getElementById('dev-reason').value.trim();
  if (!devType) { showToast('Please select a Deviation Type', 'warn'); return; }
  if (!reason)  { showToast('Please enter the Deviation Reason', 'warn'); return; }
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';
  // Only Deviation Type and Reason posted — to Comment column
  const commentText = `Deviation Type: ${devType}\nDeviation Reason: ${reason}`;
  addTrackingEntry(app, 'EFIN-Deviation', dept, commentText, '');
  app.status = 'decision';
  closeDeviationModal();
  if (typeof refreshDetailTimeline === 'function') refreshDetailTimeline(appId);
  showToast('Deviation raised — status moved to Decision', 'warn');
}

