function appdevSyncTenure(changed) {
  const yr = document.getElementById('appdev-tenure-yr');
  const mo = document.getElementById('appdev-tenure-mo');
  if (!yr || !mo) return;
  if (changed === 'yr') {
    const v = parseFloat(yr.value);
    if (!isNaN(v) && v > 0) mo.value = Math.round(v * 12);
  } else {
    const v = parseFloat(mo.value);
    if (!isNaN(v) && v > 0) yr.value = +(v / 12).toFixed(2);
  }
  appdevAutoCalc();
}

function appdevAutoCalc() {
  const amt      = parseFloat(document.getElementById('appdev-loan-amt')?.value)  || 0;
  const months   = parseFloat(document.getElementById('appdev-tenure-mo')?.value) || 0;
  const roi      = parseFloat(document.getElementById('appdev-roi')?.value)        || 0;
  const pfPct    = parseFloat(document.getElementById('appdev-pf-pct')?.value)     || 0;
  const insurance= parseFloat(document.getElementById('appdev-insurance')?.value) || 0;
  const gstPct   = parseFloat(document.getElementById('appdev-gst')?.value)        || 18;
  const pf       = amt * pfPct / 100;
  const bundled  = Math.round(amt + pf * (1 + gstPct / 100) + insurance);
  let emi = 0;
  const base = bundled > 0 ? bundled : amt;
  if (base > 0 && months > 0) {
    const r = roi / 100 / 12;
    emi = r > 0 ? Math.round(base * r * Math.pow(1+r,months) / (Math.pow(1+r,months)-1)) : Math.round(base/months);
  }
  if (emi > 0)     document.getElementById('appdev-emi').value     = emi;
  if (bundled > 0) document.getElementById('appdev-bundled').value = bundled;
}

function openApprovedDeviationModal(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  document.getElementById('appdev-app-id').value = appId;
  document.getElementById('appdev-app-badge').textContent = appId;

  // Pre-fill sanction fields from app (so approver sees current values and can edit)
  document.getElementById('appdev-loan-amt').value   = app.sanctionLoanAmt   || app.amount || '';
  document.getElementById('appdev-tenure-yr').value  = app.sanctionTenureYr  || (app.tenure ? Math.round(parseInt(app.tenure)/12) : '') || '';
  document.getElementById('appdev-tenure-mo').value  = app.sanctionTenureMo  || app.tenure || '';
  document.getElementById('appdev-roi').value        = app.sanctionROI       || app.loanRate || '';
  document.getElementById('appdev-pf-pct').value     = app.sanctionPFPct     || '';
  document.getElementById('appdev-insurance').value  = app.sanctionInsurance || '';
  document.getElementById('appdev-emi').value        = app.sanctionEMI       || '';
  document.getElementById('appdev-emi-date').value   = app.sanctionEMIDate   || 3;
  document.getElementById('appdev-bundled').value    = app.sanctionBundled   || '';
  document.getElementById('appdev-gst').value        = app.sanctionGST       || 18;
  document.getElementById('appdev-bt').value         = app.sanctionBT        || 'NO';
  document.getElementById('appdev-flat-rate').value  = app.sanctionFlatRate  || '';
  document.getElementById('appdev-stamp').value      = app.sanctionStamp     || 'As per government applicable';

  // Show deviation context
  const ctx = document.getElementById('appdev-dev-context');
  if (ctx) {
    const devEntry = [...(app.tracking || [])].reverse().find(t => t.name === 'EFIN-Deviation');
    if (devEntry && devEntry.comment) {
      ctx.innerHTML = devEntry.comment.split('\n').map(line =>
        `<div style="color:var(--text2)">${line}</div>`
      ).join('') + `<div style="font-size:11px;color:var(--text3);margin-top:4px">Raised by: ${app.deviationRaisedBy || '—'} | Assigned approver: ${app.deviationApprover || '—'}</div>`;
    } else {
      ctx.innerHTML = `<div style="color:var(--text3);font-size:12px">No deviation record found — this may have been raised externally.</div>`;
    }
  }

  document.getElementById('approved-deviation-overlay').classList.add('open');
}

function closeApprovedDeviationModal() {
  document.getElementById('approved-deviation-overlay').classList.remove('open');
}

function confirmApprovedDeviation() {
  const appId = document.getElementById('appdev-app-id').value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  // Read (possibly edited) sanction fields and save to app
  const loanAmt   = parseFloat(document.getElementById('appdev-loan-amt').value)   || app.sanctionLoanAmt || 0;
  const tenureYr  = parseFloat(document.getElementById('appdev-tenure-yr').value)  || 0;
  const tenureMo  = parseFloat(document.getElementById('appdev-tenure-mo').value)  || 0;
  const roi       = parseFloat(document.getElementById('appdev-roi').value)         || 0;
  const pfPct     = parseFloat(document.getElementById('appdev-pf-pct').value)      || 0;
  const flatRate  = parseFloat(document.getElementById('appdev-flat-rate').value)   || 0;
  const gst       = parseFloat(document.getElementById('appdev-gst').value)         || 18;
  const stamp     = document.getElementById('appdev-stamp').value.trim()            || 'As per government applicable';
  const emi       = parseFloat(document.getElementById('appdev-emi').value)         || 0;
  const emiDate   = document.getElementById('appdev-emi-date').value;
  const insurance = parseFloat(document.getElementById('appdev-insurance').value)   || 0;
  const bundled   = parseFloat(document.getElementById('appdev-bundled').value)     || 0;
  const bt        = document.getElementById('appdev-bt').value;

  // Update sanction fields on app with approved (possibly revised) values
  app.sanctionLoanAmt   = loanAmt;
  app.sanctionTenureYr  = tenureYr;
  app.sanctionTenureMo  = tenureMo;
  app.sanctionROI       = roi;
  app.sanctionFlatRate  = flatRate;
  app.sanctionPFPct     = pfPct;
  app.sanctionGST       = gst;
  app.sanctionStamp     = stamp;
  app.sanctionEMI       = emi;
  app.sanctionEMIDate   = emiDate;
  app.sanctionInsurance = insurance;
  app.sanctionBundled   = bundled;
  app.sanctionBT        = bt;
  app.amount            = loanAmt;
  if (tenureMo) app.tenure   = String(tenureMo);
  if (roi)      app.loanRate = roi;

  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';

  // Sub Note: updated sanction details only
  const subNote = laBuildSubNote(app);

  const autoComment = `Deviation approved — proceeding to Sanction Stage`;
  addTrackingEntry(app, 'EFIN-Approved Deviation', dept, autoComment, subNote);
  if (app.tracking.length > 0) app.tracking[app.tracking.length - 1]._subNoteOnly = true;

  // Move to Approved Deviation (Sanction Stage)
  app.status = 'approved_deviation';
  closeApprovedDeviationModal();
  if (typeof renderTable === 'function') renderTable();
  if (typeof refreshDetailTimeline === 'function') refreshDetailTimeline(appId);
  showToast('Deviation approved — moved to Sanction Stage ✓', 'success');
}

