function disbUpdatePreview() {
  const amt    = parseFloat(document.getElementById('disb-amount').value) || 0;
  const date   = document.getElementById('disb-date').value;
  const mode   = document.getElementById('disb-mode').value;
  const loanNo = document.getElementById('disb-loan-no').value;
  const prev   = document.getElementById('disb-preview');
  if (amt > 0) {
    prev.style.display = 'flex';
    document.getElementById('disb-prev-amt').textContent  = '₹' + amt.toLocaleString('en-IN');
    document.getElementById('disb-prev-date').textContent = date || '—';
    document.getElementById('disb-prev-mode').textContent = mode || '—';
    document.getElementById('disb-prev-loanno').textContent = loanNo || '—';
  } else {
    prev.style.display = 'none';
  }
}

function openDisburseModal(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  // Guard: NACH and Customer Agreement must be finalised before disbursement
  if (!app.nach_done || !app.customer_agreement_done) {
    const missing = [];
    if (!app.nach_done) missing.push('NACH');
    if (!app.customer_agreement_done) missing.push('Customer Agreement');
    showToast(`Cannot disburse — ${missing.join(' and ')} not yet finalised`, 'error');
    return;
  }
  // Check pending tasks
  const pending = (typeof TASK_STORE !== 'undefined') ? TASK_STORE.filter(t => t.appId === appId && t.status !== 'done') : [];
  if (pending.length) {
    showToast(`${pending.length} pending task(s) must be completed before disbursement`, 'error');
    return;
  }
  document.getElementById('disb-app-id').value = appId;
  document.getElementById('disb-app-badge').textContent = appId;
  document.getElementById('disb-amount').value = app.sanctionBundled || app.sanctionLoanAmt || app.amount || '';
  document.getElementById('disb-date').value = new Date().toISOString().split('T')[0];
  document.getElementById('disb-loan-no').value = app.disburse_loan_no || '';
  document.getElementById('disb-mode').value = 'NEFT';
  // Pre-fill first EMI date: next month on the sanctionEMIDate day
  if (app.sanctionEMIDate) {
    const today = new Date();
    const emiDay = parseInt(app.sanctionEMIDate);
    const nextMonth = new Date(today.getFullYear(), today.getMonth() + 1, emiDay);
    document.getElementById('disb-first-emi').value = nextMonth.toISOString().split('T')[0];
  } else {
    document.getElementById('disb-first-emi').value = '';
  }
  document.getElementById('disb-by').value = currentUser.name || '';
  document.getElementById('disb-comment').value = '';
  document.getElementById('disb-preview').style.display = 'none';
  document.getElementById('disb-app-summary').innerHTML = buildSanctionSummaryHTML(app);
  disbUpdatePreview();
  document.getElementById('disburse-overlay').classList.add('open');
}

function closeDisburseModal() {
  document.getElementById('disburse-overlay').classList.remove('open');
}

function confirmDisburse() {
  const appId   = document.getElementById('disb-app-id').value;
  const app     = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const amount   = parseFloat(document.getElementById('disb-amount').value) || 0;
  const date     = document.getElementById('disb-date').value;
  const loanNo   = document.getElementById('disb-loan-no').value.trim();
  const mode     = document.getElementById('disb-mode').value;
  const firstEmi = document.getElementById('disb-first-emi').value;
  const disbBy   = document.getElementById('disb-by').value.trim();
  const comment  = document.getElementById('disb-comment').value.trim();
  if (!amount) { showToast('Please enter the Disbursement Amount', 'warn'); document.getElementById('disb-amount').focus(); return; }
  if (!date)   { showToast('Please select the Disbursement Date', 'warn'); return; }
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';
  const emiDateLabel = d => !d ? '' : (d==='1'?'1st':d==='2'?'2nd':d==='3'?'3rd':d+'th');
  const subNote = [
    `Disbursement Amount: ₹${amount.toLocaleString('en-IN')}`,
    `Date: ${date}`,
    `Mode: ${mode}`,
    loanNo   ? `Loan A/C: ${loanNo}`         : null,
    firstEmi ? `First EMI Date: ${firstEmi}` : null,
    disbBy   ? `Disbursed By: ${disbBy}`     : null,
    // ── Sanction details from Approve with Details ──
    app.sanctionLoanAmt   ? `Your Loan Amount: ₹${Number(app.sanctionLoanAmt).toLocaleString('en-IN')}` : null,
    app.sanctionTenureYr  ? `Tenure (Years): ${app.sanctionTenureYr}` : null,
    app.sanctionTenureMo  ? `Tenure (Months): ${app.sanctionTenureMo}` : null,
    app.sanctionEMI       ? `EMI (Calculated - Rounded): ₹${Number(app.sanctionEMI).toLocaleString('en-IN')}` : null,
    app.sanctionFlatRate  ? `Flat Reducing Rate: ${app.sanctionFlatRate}%` : null,
    app.sanctionPFPct     ? `Processing Fee: ${app.sanctionPFPct}%` : null,
    app.sanctionROI       ? `Rate of Interest (Annual): ${app.sanctionROI}%` : null,
    app.sanctionBundled   ? `Bundled Loan Amount: ₹${Number(app.sanctionBundled).toLocaleString('en-IN')}` : null,
    app.sanctionInsurance ? `Insurance: ₹${Number(app.sanctionInsurance).toLocaleString('en-IN')}` : null,
    app.sanctionBT        ? `BT (Balance Transfer): ${app.sanctionBT}` : null,
    app.sanctionEMIDate   ? `EMI Date (Every Month): ${emiDateLabel(String(app.sanctionEMIDate))} of every Month` : null,
    app.sanctionStamp     ? `Stamp Duty: ${app.sanctionStamp}` : null,
    app.sanctionGST       ? `GST Applicable: ${app.sanctionGST}%` : null,
  ].filter(Boolean).join(' | ');
  const autoComment = comment || 'Loan disbursed — funds transferred successfully';
  // Save disbursement info to app
  app.disbursement_date = date;
  app.login_end_date_time = new Date().toISOString();
  if (amount) app.amount = amount;
  if (loanNo) app.disburse_loan_no = loanNo;
  // Tracking entries (mirroring existing pattern)
  addTrackingEntry(app, 'EFIN-Disbursed', dept, autoComment, subNote);
  if (app.tracking.length > 0) app.tracking[app.tracking.length - 1]._subNoteOnly = true;
  addTrackingEntry(app, 'EFIN-Disbursed', 'System Comments', 'Disbursement Done', loanNo || ' ');
  addTrackingEntry(app, 'EFIN-Disbursed', 'System Comments', 'Work Flow Completed', ' ');
  closeDisburseModal();
  // Set status before re-render so button disappears immediately on submit
  app.status = 'disbursed';
  if (typeof refreshDetailTimeline === 'function') refreshDetailTimeline(appId);
  changeStatus(appId, 'disbursed');
}

(function(){
  const _orig = window.showPage;
  if (typeof _orig !== 'function') return;
  window.showPage = function(pageId, navEl) {
    _orig.apply(this, arguments);
    // Hide/show topbar New Application button and search on channel pages
    const mainTopbar = document.getElementById('main-topbar');
    const isChannelPage = pageId === 'dsa-mgmt' || pageId === 'partner-mgmt';
    if (mainTopbar) mainTopbar.style.display = isChannelPage ? 'none' : '';
    if (pageId === 'dsa-mgmt') {
      const btn = document.getElementById('dsa-add-btn');
      if (btn) btn.style.display = dsaCanCreate() ? '' : 'none';
      const si = document.getElementById('dsa-search-input'); if(si) si.value='';
      dsaRender('');
      dsaStatsRefresh();
    }
    if (pageId === 'partner-mgmt') {
      const btn = document.getElementById('pm-add-btn');
      if (btn) btn.style.display = dsaCanCreate() ? '' : 'none';
      const si = document.getElementById('pm-search-input'); if(si) si.value='';
      pmRender('');
      pmStatsRefresh();
    }
  };
})();

