// ── Paste toggle ──
function ecsTogglePaste() {
  const wrap  = document.getElementById('ecs-paste-wrap');
  const arrow = document.getElementById('ecs-paste-arrow');
  if (!wrap) return;
  const open = wrap.style.display !== 'none';
  wrap.style.display = open ? 'none' : 'block';
  if (arrow) arrow.textContent = open ? '▼ expand' : '▲ collapse';
}

// ── Parse pasted text into rows ──
function ecsParseAndFill() {
  const raw = (document.getElementById('ecs-paste-input')?.value || '').trim();
  if (!raw) return;
  const lines = raw.split('\n').map(l => l.trim()).filter(Boolean);
  const parsed = [];
  lines.forEach(line => {
    // Extract date (dd-mm-yyyy or dd/mm/yyyy) and amount (number with optional decimals)
    const dateRx = line.match(/(\d{1,2}[-\/]\d{1,2}[-\/]\d{2,4})/);
    const nums   = line.match(/[\d,]+\.?\d*/g) || [];
    const amounts = nums.map(n => parseFloat(n.replace(/,/g, ''))).filter(n => n > 0);
    // Pick the amount that is NOT part of the date
    const date    = dateRx ? dateRx[1].replace(/\//g, '-') : '';
    // Exclude date numbers from amounts
    const dateParts = date ? date.split('-').map(Number) : [];
    const amount = amounts.find(a => !dateParts.includes(a)) || amounts[0];
    if (amount) parsed.push({ date, amount });
  });
  if (!parsed.length) { showToast('Could not parse any entries — check format', 'warn'); return; }
  document.getElementById('ecs-entry-body').innerHTML = '';
  parsed.forEach(p => ecsAddRow(p.date, p.amount));
  while (document.getElementById('ecs-entry-body').rows.length < 3) ecsAddRow();
  // Collapse paste panel
  const wrap = document.getElementById('ecs-paste-wrap');
  const arrow = document.getElementById('ecs-paste-arrow');
  if (wrap) wrap.style.display = 'none';
  if (arrow) arrow.textContent = '▼ expand';
  showToast(`Parsed ${parsed.length} entr${parsed.length === 1 ? 'y' : 'ies'} ✓`, 'success');
}

// ── Add row ──
function ecsAddRow(date, amount) {
  const tbody = document.getElementById('ecs-entry-body');
  const tr    = document.createElement('tr');
  tr.innerHTML = `
    <td><input type="text" class="ecs-date" placeholder="DD-MM-YYYY" value="${date || ''}"></td>
    <td><input type="number" class="ecs-amt" placeholder="0.00" step="0.01" value="${amount !== undefined ? amount : ''}" oninput="ecsCalcStats()"></td>
    <td style="text-align:center"><button class="ecs-del-btn" onclick="this.closest('tr').remove();ecsCalcStats()" title="Remove">🗑</button></td>`;
  tbody.appendChild(tr);
  ecsCalcStats();
}

function ecsClearRows() {
  document.getElementById('ecs-entry-body').innerHTML = '';
  ecsAddRow(); ecsAddRow(); ecsAddRow();
}

// ── Calculate stats ──
function ecsCalcStats() {
  const amts = [...document.querySelectorAll('#ecs-entry-body .ecs-amt')]
    .map(el => parseFloat(el.value) || 0).filter(v => v > 0);
  const bar = document.getElementById('ecs-stats-bar');
  if (!amts.length) { if (bar) bar.style.display = 'none'; return; }
  const total = amts.reduce((s, v) => s + v, 0);
  const fmt   = v => '₹' + v.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  if (bar) {
    bar.style.display = 'flex';
    document.getElementById('ecs-count').textContent = amts.length;
    document.getElementById('ecs-total').textContent = fmt(total);
    document.getElementById('ecs-max').textContent   = fmt(Math.max(...amts));
    document.getElementById('ecs-min').textContent   = fmt(Math.min(...amts));
  }
}

function openEcsReturnModal(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  document.getElementById('ecs-app-id').value = appId;
  document.getElementById('ecs-app-badge').textContent = appId;
  document.getElementById('ecs-reason-code').value = '';
  document.getElementById('ecs-comment').value     = '';
  const pasteInput = document.getElementById('ecs-paste-input');
  if (pasteInput) pasteInput.value = '';
  const wrap = document.getElementById('ecs-paste-wrap');
  const arrow = document.getElementById('ecs-paste-arrow');
  if (wrap) wrap.style.display = 'none';
  if (arrow) arrow.textContent = '▼ expand';
  // Reset table — 3 blank rows
  document.getElementById('ecs-entry-body').innerHTML = '';
  ecsAddRow(); ecsAddRow(); ecsAddRow();
  document.getElementById('ecs-stats-bar').style.display = 'none';
  document.getElementById('ecs-overlay').classList.add('open');
}

function closeEcsReturnModal() {
  document.getElementById('ecs-overlay').classList.remove('open');
}

// ── ECS Task Clear: mark as complete when no ECS Found/entries detected ──
function ecsTaskClear() {
  const appId = document.getElementById('ecs-app-id').value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  // Check if any rows have entries — warn if entries exist (user may have meant to submit)
  const hasEntries = [...document.querySelectorAll('#ecs-entry-body .ecs-amt')]
    .some(el => parseFloat(el.value) > 0);

  if (hasEntries) {
    if (!confirm('You have ECS entries filled in. Are you sure you want to clear the task without submitting them?')) return;
  }

  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';

  addTrackingEntry(app, 'EFIN-Charge', dept,
    'No ECS Found',
    'Task marked as complete. No ECS return entries were recorded (no ECS Found found in bank statement).'
  );
  app.ecs_return = true;

  closeEcsReturnModal();
  setTimeout(() => {
    if (typeof renderTrackingSection === 'function') renderTrackingSection(app);
    if (typeof renderTable === 'function') renderTable();
    showToast('ECS Task marked as cleared — no font detected ✓', 'success');
  }, 100);
}

function confirmEcsReturn() {
  const appId = document.getElementById('ecs-app-id').value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  const comment    = document.getElementById('ecs-comment').value.trim();
  const reasonCode = document.getElementById('ecs-reason-code').value;
  if (!comment) { showToast('Please enter a remark', 'warn'); document.getElementById('ecs-comment').focus(); return; }

  const rows = [...document.querySelectorAll('#ecs-entry-body tr')].map(tr => ({
    date:   tr.querySelector('.ecs-date')?.value.trim() || '',
    amount: parseFloat(tr.querySelector('.ecs-amt')?.value) || 0,
  })).filter(r => r.amount > 0);

  if (!rows.length) { showToast('Please enter at least one return entry', 'warn'); return; }

  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';
  const fmt  = v => '₹' + v.toLocaleString('en-IN', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

  const entryLines = rows.map(r =>
    [r.date, fmt(r.amount)].filter(Boolean).join('    ')
  ).join('\n');

  const total = rows.reduce((s, r) => s + r.amount, 0);
  const hi    = Math.max(...rows.map(r => r.amount));
  const lo    = Math.min(...rows.map(r => r.amount));

  const fullComment = [
    'ECS Return Entries:',
    entryLines,
    '',
    `Total Entries: ${rows.length}`,
    `Total Amount: ${fmt(total)}`,
    `Highest: ${fmt(hi)}`,
    `Lowest: ${fmt(lo)}`,
    reasonCode ? `Reason: ${reasonCode}` : null,
    `Remark: ${comment}`,
  ].filter(v => v !== null).join('\n');

  addTrackingEntry(app, 'EFIN-Charge', dept, fullComment, '');
  app.ecs_return = true;

  closeEcsReturnModal();
  setTimeout(() => {
    renderTrackingSection(app);
        const _tEl = document.querySelector('#page-app-detail .tabs .tab[onclick*="tracking-tab"]');
        if (_tEl) switchTab('tracking-tab', _tEl);
    const firstRow = document.querySelector('#tracking-section .tracking-table tbody tr:first-child');
    if (firstRow) { firstRow.classList.add('row-new'); setTimeout(() => firstRow.classList.remove('row-new'), 600); }
    const _ttEl3 = document.querySelector('#page-app-detail .tabs .tab[onclick*="tracking-tab"]');
    if (_ttEl3) switchTab('tracking-tab', _ttEl3);
    showToast(`ECS Return recorded — ${rows.length} entries ✓`, 'success');
  }, 100);
}
