// ── Update email preview ──
function dcUpdatePreview() {
  const appId     = document.getElementById('dc-app-id')?.value;
  const app       = appId ? APPLICATIONS.find(a => a.id === appId) : null;
  const senderName  = document.getElementById('dc-sender-name')?.value  || 'Your Name';
  const senderDesig = document.getElementById('dc-sender-desig')?.value || 'Personal Loan | Business Loans';
  const senderMob   = document.getElementById('dc-sender-mobile')?.value || '';

  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '₹—';
  const loanAmt  = document.getElementById('dc-loan-amt')?.value   || '—';
  const tenureYr = document.getElementById('dc-tenure-yr')?.value  || '—';
  const tenureMo = document.getElementById('dc-tenure-mo')?.value  || '—';
  const emi      = document.getElementById('dc-emi')?.value        || '—';
  const flatRate = document.getElementById('dc-flat-rate')?.value  || '—';
  const pfPct    = document.getElementById('dc-pf-pct')?.value     || '—';
  const roi      = document.getElementById('dc-roi')?.value        || '—';
  const bundled  = document.getElementById('dc-bundled')?.value    || '—';
  const insurance= document.getElementById('dc-insurance')?.value  || '0';
  const bt       = document.getElementById('dc-bt')?.value         || 'NO';
  const emiDate  = document.getElementById('dc-emi-date')?.options[document.getElementById('dc-emi-date').selectedIndex]?.text || '—';
  const gst      = document.getElementById('dc-gst')?.value        || '18';
  const stamp    = document.getElementById('dc-stamp')?.value      || 'As per government applicable';
  const loanType = app ? (typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : 'Personal Loan') : 'Personal Loan';

  const rows = [
    ['Loan Amount',               loanAmt ? fmt(loanAmt) : '—'],
    ['Tenure (Years)',            tenureYr || '—'],
    ['Tenure (Months)',           tenureMo || '—'],
    ['EMI (Calculated, Rounded)', emi ? fmt(emi) : '—'],
    ['Flat Reducing Rate',        flatRate ? flatRate + '%' : '—'],
    ['Processing Fee',            pfPct ? pfPct + '%' : '—'],
    ['Rate of Interest (Annual)', roi ? roi + '%' : '—'],
    ['Bundled Loan Amount',       bundled ? fmt(bundled) : '—'],
    ['Insurance',                 insurance ? fmt(insurance) : '₹0'],
    ['Balance Transfer',          bt],
    ['EMI Date',                  emiDate && emiDate !== '—' ? emiDate + ' of every month' : '—'],
    ['Stamp Duty',                stamp],
    ['GST Applicable',            gst + '%'],
  ];

  const firstName = app && app.name ? app.name.split(' ')[0] : 'Customer';
  const appRef = app ? app.id : '—';
  const loanAmtDisplay = loanAmt && loanAmt !== '—' ? fmt(loanAmt) : '—';
  const emiDisplay     = emi && emi !== '—' ? fmt(emi) : '—';
  const tenureDisplay  = (tenureMo && tenureMo !== '—') ? `${tenureMo} months${tenureYr && tenureYr !== '—' ? ` (${tenureYr} yrs)` : ''}` : ((tenureYr && tenureYr !== '—') ? `${tenureYr} yrs` : '—');
  const emiDateText    = (emiDate && emiDate !== '—') ? `${emiDate} of every month` : '—';

  const cellPrev = (label, value) =>
    `<div style="font-size:12px;color:#1e3a5f;margin-bottom:6px;line-height:1.5"><span style="color:#5a7090">${label}:</span> <strong style="color:#0d2c54">${value}</strong></div>`;

  document.getElementById('dc-preview-text').innerHTML = `
<div style="background:#0a4d8c;margin:-18px -20px;padding:22px 12px;font-family:Arial,Helvetica,sans-serif">
  <div style="background:#ffffff;max-width:580px;margin:0 auto;border-radius:10px;overflow:hidden">
    <div style="padding:20px 24px 6px;color:#0d2c54;font-size:12.5px;line-height:1.55">
      <div style="font-weight:700;font-size:13.5px;margin-bottom:10px">Dear ${firstName},</div>
      <div style="margin-bottom:10px">We are pleased to inform you that your <strong>${loanType}</strong> application (Ref: <strong>${appRef}</strong>) has been <strong>approved</strong>. Your sanction details are set out below — please review them carefully before confirming.</div>
      <div style="margin-bottom:4px">To proceed, kindly reply to this email with either <strong>"Accepted"</strong> or <strong>"Declined"</strong> along with the application reference <strong>${appRef}</strong>.</div>
    </div>
    <div style="padding:14px 22px 4px;text-align:center">
      <div style="font-size:12.5px;font-weight:700;color:#ffffff;background:#0a4d8c;display:inline-block;padding:5px 18px;border-radius:4px;letter-spacing:.4px">Sanction Summary</div>
    </div>
    <div style="padding:10px 18px 4px">
      <table style="width:100%;border-collapse:separate;border-spacing:8px 0">
        <tr>
          <td width="50%" valign="top" style="background:#ffffff;border:1px solid #dbe7f2;border-radius:8px;overflow:hidden">
            <div style="background:#b3dcf5;padding:9px 12px;text-align:center;color:#0d2c54;font-weight:700;font-size:12.5px">Loan Sanction</div>
            <div style="padding:12px 14px">
              ${cellPrev('Loan Type', loanType)}
              ${cellPrev('Bundled Amount', bundled && bundled !== '—' ? fmt(bundled) : '—')}
              ${cellPrev('Insurance', insurance ? fmt(insurance) : '₹0')}
              <div style="margin-top:10px">
                <div style="font-size:11px;color:#5a7090;margin-bottom:3px">Sanctioned Loan Amount</div>
                <div style="font-size:18px;font-weight:800;color:#0a4d8c;border-bottom:2px solid #0a4d8c;display:inline-block;padding-bottom:2px">${loanAmtDisplay}</div>
              </div>
            </div>
          </td>
          <td width="50%" valign="top" style="background:#ffffff;border:1px solid #dbe7f2;border-radius:8px;overflow:hidden">
            <div style="background:#b3dcf5;padding:9px 12px;text-align:center;color:#0d2c54;font-weight:700;font-size:12.5px">Repayment Terms</div>
            <div style="padding:12px 14px">
              ${cellPrev('Tenure', tenureDisplay)}
              ${cellPrev('Rate of Interest', roi && roi !== '—' ? roi + '% p.a.' : '—')}
              ${cellPrev('Flat Reducing Rate', flatRate && flatRate !== '—' ? flatRate + '%' : '—')}
              <div style="margin-top:10px">
                <div style="font-size:11px;color:#5a7090;margin-bottom:3px">Monthly EMI</div>
                <div style="font-size:18px;font-weight:800;color:#0a4d8c;border-bottom:2px solid #0a4d8c;display:inline-block;padding-bottom:2px">${emiDisplay}</div>
              </div>
            </div>
          </td>
        </tr>
      </table>
    </div>
    <div style="padding:16px 22px 4px;text-align:center">
      <div style="font-size:12.5px;font-weight:700;color:#ffffff;background:#0a4d8c;display:inline-block;padding:5px 18px;border-radius:4px;letter-spacing:.4px">Charges &amp; Duties</div>
    </div>
    <div style="padding:10px 18px 10px">
      <div style="background:#ffffff;border:1px solid #dbe7f2;border-radius:8px;overflow:hidden">
        <div style="background:#b3dcf5;padding:9px 12px;text-align:center;color:#0d2c54;font-weight:700;font-size:12.5px">Additional Terms</div>
        <div style="padding:12px 16px">
          <table style="width:100%"><tr>
            <td valign="top" style="padding-right:12px;width:50%">
              ${cellPrev('Processing Fee', pfPct && pfPct !== '—' ? pfPct + '%' : '—')}
              ${cellPrev('GST Applicable', gst + '%')}
            </td>
            <td valign="top" style="padding-left:12px;border-left:1px dashed #dbe7f2;width:50%">
              ${cellPrev('Balance Transfer', bt || 'NO')}
              ${cellPrev('Stamp Duty', stamp)}
            </td>
          </tr></table>
        </div>
      </div>
    </div>
    <div style="padding:4px 22px 14px">
      <div style="background:#fff8e1;border-left:3px solid #f0a000;padding:10px 14px;border-radius:4px;color:#6b4e00;font-size:11.5px;line-height:1.5">
        <strong>Please note:</strong> Once the loan is disbursed, the terms above — including ROI, Processing Fee and Insurance Amount — <strong>cannot be modified</strong>.
      </div>
    </div>
    <div style="padding:4px 24px 20px;color:#0d2c54;font-size:12px;line-height:1.5">
      <div style="margin:6px 0 2px">Warm regards,</div>
      <div style="font-weight:700">${senderName}${senderDesig ? '<br><span style="font-weight:400;color:#5a7090">' + senderDesig + '</span>' : ''}${senderMob ? '<br><span style="font-weight:400;color:#5a7090">Mobile: ' + senderMob + '</span>' : ''}</div>
    </div>
  </div>
  <div style="text-align:center;color:#b8cde3;font-size:10.5px;margin-top:10px">Auto-generated confirmation · Ref: ${appRef}</div>
</div>`;
}

function openDealConfirmModal(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  document.getElementById('dc-app-id').value = appId;
  document.getElementById('dc-app-badge').textContent = appId;

  const sysCfg = sysmailGetConfig ? sysmailGetConfig() : {};
  document.getElementById('dc-to').value  = app.email || '';
  document.getElementById('dc-cc').value  = sysCfg.cc || '';
  document.getElementById('dc-sender-name').value   = sysCfg.name || currentUser.name || '';
  document.getElementById('dc-sender-desig').value  = sysCfg.signature ? sysCfg.signature.split('\n')[0] : '';
  document.getElementById('dc-sender-mobile').value = '';

  // Pre-fill sanction fields
  document.getElementById('dc-loan-amt').value  = app.sanctionLoanAmt   || app.amount || '';
  document.getElementById('dc-tenure-yr').value = app.sanctionTenureYr  || '';
  document.getElementById('dc-tenure-mo').value = app.sanctionTenureMo  || app.tenure || '';
  document.getElementById('dc-emi').value        = app.sanctionEMI       || '';
  document.getElementById('dc-flat-rate').value  = app.sanctionFlatRate  || '';
  document.getElementById('dc-pf-pct').value     = app.sanctionPFPct     || '';
  document.getElementById('dc-roi').value        = app.sanctionROI       || app.loanRate || '';
  document.getElementById('dc-bundled').value    = app.sanctionBundled   || '';
  document.getElementById('dc-insurance').value  = app.sanctionInsurance || '0';
  document.getElementById('dc-bt').value         = app.sanctionBT        || 'NO';
  document.getElementById('dc-gst').value        = app.sanctionGST       || '18';
  document.getElementById('dc-stamp').value      = app.sanctionStamp     || 'As per government applicable';
  // EMI date
  const emiDateEl = document.getElementById('dc-emi-date');
  if (emiDateEl && app.sanctionEMIDate) emiDateEl.value = String(app.sanctionEMIDate);

  // Show/hide accepted banner
  const accepted = app._dealConfirmSent && app.status === 'acceptance';
  document.getElementById('dc-accepted-wrap').style.display = accepted ? '' : 'none';
  const sw = document.getElementById('dc-sent-wrap'); if (sw) sw.style.display = 'none';

  dcUpdatePreview();
  document.getElementById('dc-overlay').classList.add('open');
}

function closeDealConfirmModal() {
  document.getElementById('dc-overlay').classList.remove('open');
}

// ── Open email client with pre-filled deal confirmation ──
// ── Build email content from modal fields ──
function dcBuildEmailContent(app) {
  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
  const loanType  = typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : 'Personal Loan';
  const loanAmt   = document.getElementById('dc-loan-amt')?.value   || '';
  const tenureYr  = document.getElementById('dc-tenure-yr')?.value  || '';
  const tenureMo  = document.getElementById('dc-tenure-mo')?.value  || '';
  const emi       = document.getElementById('dc-emi')?.value        || '';
  const flatRate  = document.getElementById('dc-flat-rate')?.value  || '';
  const pfPct     = document.getElementById('dc-pf-pct')?.value     || '';
  const roi       = document.getElementById('dc-roi')?.value        || '';
  const bundled   = document.getElementById('dc-bundled')?.value    || '';
  const insurance = document.getElementById('dc-insurance')?.value  || '0';
  const bt        = document.getElementById('dc-bt')?.value         || 'NO';
  const emiDate   = document.getElementById('dc-emi-date')?.options[document.getElementById('dc-emi-date').selectedIndex]?.text || '';
  const gst       = document.getElementById('dc-gst')?.value        || '18';
  const stamp     = document.getElementById('dc-stamp')?.value      || 'As per government applicable';
  const senderName  = document.getElementById('dc-sender-name')?.value.trim()  || currentUser.name;
  const senderDesig = document.getElementById('dc-sender-desig')?.value.trim() || '';
  const senderMob   = document.getElementById('dc-sender-mobile')?.value.trim() || '';

  const subject = `DEAL CONFIRMATION // ${app.id} ${app.name.toUpperCase()}`;

  // Shared row data — single source of truth for both plain-text and HTML renderings
  const rows = [
    ['Loan Amount',               loanAmt ? fmt(loanAmt) : '—'],
    ['Tenure (Years)',            tenureYr || '—'],
    ['Tenure (Months)',           tenureMo || '—'],
    ['EMI (Calculated, Rounded)', emi ? fmt(emi) : '—'],
    ['Flat Reducing Rate',        flatRate ? flatRate + '%' : '—'],
    ['Processing Fee',            pfPct ? pfPct + '%' : '—'],
    ['Rate of Interest (Annual)', roi ? roi + '%' : '—'],
    ['Bundled Loan Amount',       bundled ? fmt(bundled) : '—'],
    ['Insurance',                 insurance ? fmt(insurance) : '₹0'],
    ['Balance Transfer',          bt],
    ['EMI Date',                  emiDate ? emiDate + ' of every month' : '—'],
    ['Stamp Duty',                stamp],
    ['GST Applicable',            gst + '%'],
  ];

  // ── Plain-text version (this is what mailto: actually delivers to Outlook/Gmail)
  // Use a clean "Label : Value" format with leader-dot alignment — no box-drawing characters,
  // since those don't align reliably with proportional fonts in Outlook.
  const labelWidth = Math.max(...rows.map(([l]) => l.length));
  const padLabel = s => s + ' '.repeat(labelWidth - s.length);
  const detailLines = rows.map(([l, v]) => `  ${padLabel(l)}  :  ${v}`).join('\n');

  const bodyText =
`Dear Sir/Ma'am,

We are delighted to inform you that your ${loanType} application has been approved. Further processing of your loan would be subject to the terms and conditions mentioned in this email — please go through the details carefully.

To record your response, please reply to this email with either "Accepted" or "Declined" along with the application reference ${app.id}. Please note that once the loan is disbursed, conditions such as ROI, Processing Fee and Insurance Amount cannot be changed.

SANCTION DETAILS
----------------
${detailLines}

Thanks & regards,
${senderName}${senderDesig ? '\n' + senderDesig : ''}${senderMob ? '\nMobile: ' + senderMob : ''}`;

  // ── HTML version: styled layout inspired by reference image ──
  // Deep-navy outer frame → white centred container → two side-by-side cards
  // with light-blue header strips, bold navy body text, a highlighted key
  // value, and a muted footer note. Mirrors the "Option 1" composition.
  const firstName = app.name ? app.name.split(' ')[0] : 'Customer';
  const appRef    = app.id;
  const loanAmtDisplay = loanAmt ? fmt(loanAmt) : '—';
  const emiDisplay     = emi ? fmt(emi) : '—';
  const tenureDisplay  = tenureMo ? `${tenureMo} months${tenureYr ? ` (${tenureYr} yrs)` : ''}` : (tenureYr ? `${tenureYr} yrs` : '—');
  const emiDateText    = emiDate ? `${emiDate} of every month` : '—';

  // Cell helper — renders a "Label: Value" row inside a card body
  const cell = (label, value) =>
    `<div style="font-size:13px;color:#1e3a5f;margin-bottom:8px;line-height:1.5">
       <span style="color:#5a7090">${label}:</span>
       <strong style="color:#0d2c54">${value}</strong>
     </div>`;

  const bodyHtml = `
<div style="background:#0a4d8c;padding:32px 16px;font-family:Arial,Helvetica,sans-serif;color:#0d2c54">
  <table role="presentation" cellpadding="0" cellspacing="0" border="0" align="center" width="100%" style="max-width:660px;margin:0 auto;border-collapse:separate;border-spacing:0">

    <!-- Greeting -->
    <tr>
      <td style="background:#ffffff;padding:24px 28px 8px;border-radius:10px 10px 0 0;color:#0d2c54;font-size:14px;line-height:1.6">
        <p style="margin:0 0 12px;font-weight:700;font-size:15px">Dear ${firstName},</p>
        <p style="margin:0 0 12px">We are pleased to inform you that your <strong>${loanType}</strong> application (Ref: <strong>${appRef}</strong>) has been <strong>approved</strong>. Your sanction details are set out below — please review them carefully before confirming.</p>
        <p style="margin:0 0 4px">To proceed, kindly reply to this email with either <strong>"Accepted"</strong> or <strong>"Declined"</strong> along with the application reference <strong>${appRef}</strong>.</p>
      </td>
    </tr>

    <!-- Section label: Sanction Summary -->
    <tr>
      <td style="background:#ffffff;padding:18px 28px 6px;text-align:center">
        <div style="font-size:14px;font-weight:700;color:#ffffff;background:#0a4d8c;display:inline-block;padding:6px 22px;border-radius:4px;letter-spacing:.6px">Sanction Summary</div>
      </td>
    </tr>

    <!-- Two cards: Loan Sanction / Repayment Terms -->
    <tr>
      <td style="background:#ffffff;padding:14px 22px 4px">
        <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="border-collapse:separate;border-spacing:10px 0">
          <tr>
            <!-- Card 1: Loan Sanction -->
            <td width="50%" valign="top" style="background:#ffffff;border:1px solid #dbe7f2;border-radius:10px;overflow:hidden">
              <div style="background:#b3dcf5;padding:12px 16px;text-align:center;color:#0d2c54;font-weight:700;font-size:14px">Loan Sanction</div>
              <div style="padding:16px 18px">
                ${cell('Loan Type', loanType)}
                ${cell('Bundled Amount', bundled ? fmt(bundled) : '—')}
                ${cell('Insurance', insurance ? fmt(insurance) : '₹0')}
                <div style="margin-top:14px">
                  <div style="font-size:12px;color:#5a7090;margin-bottom:4px">Sanctioned Loan Amount</div>
                  <div style="font-size:22px;font-weight:800;color:#0a4d8c;border-bottom:2px solid #0a4d8c;display:inline-block;padding-bottom:2px">${loanAmtDisplay}</div>
                </div>
                <div style="margin-top:14px;padding-top:12px;border-top:1px dashed #dbe7f2;font-size:11.5px;color:#5a7090;line-height:1.5">
                  Bundled amount includes the loan principal together with insurance, if opted.
                </div>
              </div>
            </td>

            <!-- Card 2: Repayment Terms -->
            <td width="50%" valign="top" style="background:#ffffff;border:1px solid #dbe7f2;border-radius:10px;overflow:hidden">
              <div style="background:#b3dcf5;padding:12px 16px;text-align:center;color:#0d2c54;font-weight:700;font-size:14px">Repayment Terms</div>
              <div style="padding:16px 18px">
                ${cell('Tenure', tenureDisplay)}
                ${cell('Rate of Interest', roi ? roi + '% p.a.' : '—')}
                ${cell('Flat Reducing Rate', flatRate ? flatRate + '%' : '—')}
                <div style="margin-top:14px">
                  <div style="font-size:12px;color:#5a7090;margin-bottom:4px">Monthly EMI</div>
                  <div style="font-size:22px;font-weight:800;color:#0a4d8c;border-bottom:2px solid #0a4d8c;display:inline-block;padding-bottom:2px">${emiDisplay}</div>
                </div>
                <div style="margin-top:14px;padding-top:12px;border-top:1px dashed #dbe7f2;font-size:11.5px;color:#5a7090;line-height:1.5">
                  EMI will be debited on the <strong>${emiDateText}</strong>.
                </div>
              </div>
            </td>
          </tr>
        </table>
      </td>
    </tr>

    <!-- Section label: Charges & Duties -->
    <tr>
      <td style="background:#ffffff;padding:22px 28px 6px;text-align:center">
        <div style="font-size:14px;font-weight:700;color:#ffffff;background:#0a4d8c;display:inline-block;padding:6px 22px;border-radius:4px;letter-spacing:.6px">Charges &amp; Duties</div>
      </td>
    </tr>

    <!-- Single wide card: Charges -->
    <tr>
      <td style="background:#ffffff;padding:14px 22px 14px">
        <div style="background:#ffffff;border:1px solid #dbe7f2;border-radius:10px;overflow:hidden">
          <div style="background:#b3dcf5;padding:12px 16px;text-align:center;color:#0d2c54;font-weight:700;font-size:14px">Additional Terms</div>
          <div style="padding:16px 22px">
            <table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%">
              <tr>
                <td width="50%" valign="top" style="padding-right:14px">
                  ${cell('Processing Fee', pfPct ? pfPct + '%' : '—')}
                  ${cell('GST Applicable', gst + '%')}
                </td>
                <td width="50%" valign="top" style="padding-left:14px;border-left:1px dashed #dbe7f2">
                  ${cell('Balance Transfer', bt || 'NO')}
                  ${cell('Stamp Duty', stamp)}
                </td>
              </tr>
            </table>
          </div>
        </div>
      </td>
    </tr>

    <!-- Important note -->
    <tr>
      <td style="background:#ffffff;padding:8px 28px 18px">
        <div style="background:#fff8e1;border-left:3px solid #f0a000;padding:12px 16px;border-radius:4px;color:#6b4e00;font-size:12.5px;line-height:1.55">
          <strong>Please note:</strong> Once the loan is disbursed, the terms above — including ROI, Processing Fee and Insurance Amount — <strong>cannot be modified</strong>. Kindly review carefully before confirming.
        </div>
      </td>
    </tr>

    <!-- Signature -->
    <tr>
      <td style="background:#ffffff;padding:6px 28px 24px;color:#0d2c54;font-size:13.5px;line-height:1.55;border-radius:0 0 10px 10px">
        <p style="margin:10px 0 2px">Warm regards,</p>
        <p style="margin:0;font-weight:700">${senderName}${senderDesig ? '<br><span style="font-weight:400;color:#5a7090">' + senderDesig.replace(/\n/g, '<br>') + '</span>' : ''}${senderMob ? '<br><span style="font-weight:400;color:#5a7090">Mobile: ' + senderMob + '</span>' : ''}</p>
      </td>
    </tr>

    <!-- Footer strip -->
    <tr>
      <td style="padding:14px 4px 0;color:#b8cde3;font-size:11px;line-height:1.5;text-align:center">
        This is an auto-generated confirmation from EFIN. Ref: ${appRef}
      </td>
    </tr>
  </table>
</div>`;

  return { subject, bodyText, bodyHtml, senderName };
}

// ── Single button: Send via Gmail/Brevo + Mark as Accepted ──
async function dcSendAndConfirm() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  // ── Prevent duplicate timeline entries on repeat clicks / retries ──
  if (app._dealConfirmSent) { showToast('Deal confirmation already recorded for this application', 'info'); return; }

  const to  = document.getElementById('dc-to')?.value.trim();
  const cc  = document.getElementById('dc-cc')?.value.trim();
  if (!to) { showToast('Please enter the customer email address', 'warn'); document.getElementById('dc-to').focus(); return; }

  const btn  = document.getElementById('dc-btn-mailto');
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';
  const { subject, bodyText, bodyHtml } = dcBuildEmailContent(app);
  const cfg  = sysmailGetConfig ? sysmailGetConfig() : {};

  // ── Send via configured provider (Gmail or Brevo) ──
  if (cfg.fromEmail) {
    try {
      if (btn) { btn.disabled = true; btn.textContent = '⏳ Sending…'; }
      await sysmailSend({ to, toName: app.name, subject, html: bodyHtml, cc: cc || cfg.cc || '', replyTo: cfg.replyto || cfg.fromEmail });
      // ── Only create the timeline entry after the email has actually been sent successfully ──
      addTrackingEntry(app, 'EFIN-Deal Confirmation', dept,
        `Deal confirmation sent from ${cfg.fromEmail} to ${to}`,
        `Subject: ${subject}\nFrom: ${cfg.fromEmail}\nTo: ${to}${cc ? '\nCC: ' + cc : ''}\nProvider: ${cfg.provider || 'brevo'}`
      );
      app._dealConfirmSent = true;
      _dcFinaliseAcceptance(app, appId, dept);
      if (btn) { btn.disabled = false; btn.textContent = '📧 Send via Mail Client'; }
      showToast('Deal confirmation sent via ' + (cfg.provider === 'gmail' ? 'Gmail' : 'Brevo') + ' ✓', 'success');
      return;
    } catch(err) {
      // ── Email send failed: show the exact error and stop. Do NOT create a
      //    timeline entry and do NOT mark the task Complete. ──
      if (btn) { btn.disabled = false; btn.textContent = '📧 Send via Mail Client'; }
      const msg = err.message === 'NO_KEY'         ? 'Brevo API key not configured'  :
                  err.message === 'NO_FROM'        ? 'From address not configured'   :
                  err.message === 'NO_EJS_CONFIG'  ? 'Gmail/EmailJS not configured'  :
                  'Send failed: ' + err.message;
      showToast(msg, 'error');
      return;
    }
  }

  // ── Fallback: open mail client + mark accepted ──
  const mailtoStr = `mailto:${to}?${cc ? 'cc=' + encodeURIComponent(cc) + '&' : ''}subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(bodyText)}`;
  window.open(mailtoStr, '_blank');
  addTrackingEntry(app, 'EFIN-Deal Confirmation', dept,
    `Deal confirmation sent to ${to} via mail client`,
    `Subject: ${subject}\nTo: ${to}${cc ? '\nCC: ' + cc : ''}`
  );
  app._dealConfirmSent = true;
  _dcFinaliseAcceptance(app, appId, dept);
  showToast('Mail client opened — status moved to Acceptance ✓', 'success');
  if (btn) { btn.disabled = false; btn.textContent = '📧 Send via Mail Client'; }
}

// ── Shared finalise: post tracking + move to acceptance ──
function _dcFinaliseAcceptance(app, appId, dept) {
  const fiNegOrPend = app.final_report && ((app.fi_resi==='Negative'||app.fi_resi==='Pending')||(app.fi_office==='Negative'||app.fi_office==='Pending'));
  if (!app.final_report || fiNegOrPend) {
    if (typeof showToast === 'function') showToast('Cannot move to Acceptance — EFIN FI Report must be completed and Positive first', 'error');
    return;
  }
  addTrackingEntry(app, 'EFIN-Customer Confirmation', dept,
    'Deal confirmation sent — awaiting customer reply',
    'Status moved to Acceptance on deal confirmation send'
  );
  app.status = 'acceptance';
  document.getElementById('dc-accepted-wrap').style.display = '';
  closeDealConfirmModal();
  if (typeof renderTable === 'function') renderTable();
  if (typeof openDetail === 'function') setTimeout(() => openDetail(appId), 300);
}

// ── Open in mail client then show confirmation prompt ──
// IMPORTANT: this must stay synchronous (no top-level await before the anchor
// click). Browsers treat `window.open('mailto:')` as non-navigation and often
// block it, and any awaited Promise before navigation severs the user-gesture
// chain — so the default mail client silently fails to launch. The reliable
// pattern is: build the mailto, synthesise an <a> click, then kick off the
// clipboard copy afterwards (fire-and-forget).
function dcOpenMailtoAndPrompt() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const to = document.getElementById('dc-to')?.value.trim();
  const cc = document.getElementById('dc-cc')?.value.trim();
  if (!to) { showToast('Please enter the customer email address', 'warn'); return; }

  const btn = document.getElementById('dc-btn-mailto');
  const restoreBtn = () => { if (btn) { btn.disabled = false; btn.textContent = '📧 Send via Mail Client'; } };
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Opening…'; }

  const { bodyHtml, bodyText, subject } = dcBuildEmailContent(app);

  // Step 1 (synchronous, inside the user gesture): open the default mail client
  // via a real anchor click. mailto: URLs are handled by the OS/browser handler
  // and do not open a blank popup the way window.open('mailto:') can.
  const mailto = `mailto:${to}`
    + `?${cc ? 'cc=' + encodeURIComponent(cc) + '&' : ''}`
    + `subject=${encodeURIComponent(subject)}`
    + `&body=${encodeURIComponent(bodyText)}`;
  const a = document.createElement('a');
  a.href = mailto;
  a.rel  = 'noopener';
  // Do NOT set target="_blank" — mailto handlers are external to the browser,
  // and a blank target can leave an empty tab behind.
  document.body.appendChild(a);
  a.click();
  a.remove();

  // Step 2 (async, fire-and-forget): also copy the styled HTML to clipboard
  // so the agent can paste it into the mail draft that just opened. If copying
  // fails (Safari, insecure context, etc.) the plain-text body in the mailto
  // still gets the job done.
  let clipboardStatus = 'none';
  const copyPromise = (async () => {
    try {
      if (navigator.clipboard && window.ClipboardItem) {
        await navigator.clipboard.write([new ClipboardItem({
          'text/html':  new Blob([bodyHtml], { type: 'text/html' }),
          'text/plain': new Blob([bodyText], { type: 'text/plain' }),
        })]);
        clipboardStatus = 'html';
      } else if (navigator.clipboard) {
        await navigator.clipboard.writeText(bodyText);
        clipboardStatus = 'text';
      }
    } catch (err) {
      console.warn('Clipboard copy skipped:', err);
    }
  })();

  copyPromise.finally(() => {
    if (clipboardStatus === 'html') {
      showToast('Mail draft opened — the styled version is on your clipboard, press Ctrl+V to paste', 'success');
    } else if (clipboardStatus === 'text') {
      showToast('Mail draft opened — a plain-text copy is on your clipboard', 'info');
    } else {
      showToast('Mail draft opened in your default mail client', 'info');
    }
    restoreBtn();
  });

  // Step 3: reveal the Offer Accepted / Declined prompt
  const sentWrap = document.getElementById('dc-sent-wrap');
  if (sentWrap) {
    sentWrap.style.display = '';
    setTimeout(() => sentWrap.scrollIntoView({ behavior: 'smooth', block: 'nearest' }), 200);
  }
}

// ── Copy the formatted HTML email to clipboard ──
// Writes both text/html and text/plain so that pasting into Outlook / Gmail
// composer preserves the styled layout, while fallbacks still get the text.
async function dcCopyFormattedEmail() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const { bodyHtml, bodyText, subject } = dcBuildEmailContent(app);
  const btn = document.getElementById('dc-btn-copy-html');
  const restore = () => { if (btn) { btn.disabled = false; btn.textContent = '📋 Copy Formatted Email'; } };
  if (btn) { btn.disabled = true; btn.textContent = '⏳ Copying…'; }

  try {
    if (navigator.clipboard && window.ClipboardItem) {
      const item = new ClipboardItem({
        'text/html':  new Blob([bodyHtml], { type: 'text/html' }),
        'text/plain': new Blob([bodyText], { type: 'text/plain' }),
      });
      await navigator.clipboard.write([item]);
    } else if (navigator.clipboard) {
      // Safari / older browsers: fall back to plain text copy
      await navigator.clipboard.writeText(bodyText);
    } else {
      // Last-resort legacy path: create a contenteditable, select, execCommand
      const holder = document.createElement('div');
      holder.contentEditable = 'true';
      holder.style.cssText = 'position:fixed;left:-9999px;top:0';
      holder.innerHTML = bodyHtml;
      document.body.appendChild(holder);
      const range = document.createRange();
      range.selectNodeContents(holder);
      const sel = window.getSelection();
      sel.removeAllRanges(); sel.addRange(range);
      document.execCommand('copy');
      sel.removeAllRanges();
      document.body.removeChild(holder);
    }
    if (btn) btn.textContent = '✓ Copied — paste into Outlook';
    showToast('Formatted email copied. Paste it into your mail composer.', 'success');
    setTimeout(restore, 2200);
  } catch (err) {
    console.error('Copy failed:', err);
    showToast('Could not copy — your browser may block clipboard access', 'warn');
    restore();
  }
}

// ── Customer accepted the offer ──
function dcOfferAccepted() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  // ── Prevent duplicate timeline entries on repeat clicks / retries ──
  if (app._dealConfirmSent) { showToast('Deal confirmation already recorded for this application', 'info'); return; }

  const to   = document.getElementById('dc-to')?.value.trim()  || app.email || '';
  if (!to) { showToast('Please enter the customer email address', 'error'); return; }

  const cc   = document.getElementById('dc-cc')?.value.trim()  || '';
  const { subject } = dcBuildEmailContent(app);
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';

  // ── Only create the timeline entry after validation has passed ──
  addTrackingEntry(app, 'EFIN-Deal Confirmation', dept,
    `Deal confirmation email sent to ${to}`,
    `Subject: ${subject}\nTo: ${to}${cc ? '\nCC: ' + cc : ''}`
  );
  app._dealConfirmSent = true;
  _dcFinaliseAcceptance(app, appId, dept);
  showToast('Offer accepted — status moved to Acceptance ✓', 'success');
  dcShowAttachPanel(); // ← reveal attachment panel for deal confirmation docs
}

// ── Customer declined the offer ──
function dcOfferDeclined() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;

  // ── Prevent duplicate timeline entries on repeat clicks / retries ──
  if (app._dealConfirmSent) { showToast('Deal confirmation already recorded for this application', 'info'); return; }

  const to   = document.getElementById('dc-to')?.value.trim()  || app.email || '';
  if (!to) { showToast('Please enter the customer email address', 'error'); return; }

  const { subject } = dcBuildEmailContent(app);
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';

  // ── Only create the timeline entries after validation has passed ──
  addTrackingEntry(app, 'EFIN-Deal Confirmation', dept,
    `Deal confirmation email sent to ${to}`,
    `Subject: ${subject}\nTo: ${to}`
  );
  addTrackingEntry(app, 'EFIN-Customer Confirmation', dept,
    'Customer declined the offer — closing application',
    'Offer declined after deal confirmation'
  );

  app._dealConfirmSent = true;
  app.status = 'rejected';
  closeDealConfirmModal();
  if (typeof renderTable === 'function') renderTable();
  if (typeof openDetail === 'function') setTimeout(() => openDetail(appId), 300);
  showToast('Offer declined — application marked as Rejected', 'warn');
}

// ── Backward-compat alias for any older callers ──
function dcConfirmSent() { dcOfferAccepted(); }

// ── Deal Confirmation: attachment helpers (added v18) ──
// Pending attachments are stored here until "Save to Documents" is clicked
window._dcPendingAttachments = [];

function dcShowAttachPanel() {
  // Reveal the attach panel after offer is accepted
  const wrap = document.getElementById('dc-attach-wrap');
  if (wrap) { wrap.style.display = ''; wrap.scrollIntoView({ behavior: 'smooth', block: 'nearest' }); }
}

function dcHandleFileInput(input) {
  Array.from(input.files).forEach(dcAddAttachment);
  input.value = '';
}

function dcHandleDrop(e) {
  e.preventDefault();
  document.getElementById('dc-drop-area')?.classList.remove('drag-over');
  Array.from(e.dataTransfer.files).forEach(dcAddAttachment);
}

function dcAddAttachment(file) {
  if (!window._dcPendingAttachments) window._dcPendingAttachments = [];
  const uid    = Date.now() + '-' + Math.random().toString(36).slice(2, 7);
  const objUrl = URL.createObjectURL(file);
  const isImage = file.type.startsWith('image/');
  const isPdf   = file.type === 'application/pdf';
  window._dcPendingAttachments.push({ uid, file, displayName: file.name, objUrl, mimetype: file.type, isImage, isPdf });
  dcRenderAttachList();
}

function dcRenderAttachList() {
  const list = document.getElementById('dc-attach-list');
  if (!list) return;
  const items = window._dcPendingAttachments || [];
  list.innerHTML = items.map((att, idx) => {
    const icon = att.isImage ? '🖼️' : att.isPdf ? '📄' : '📎';
    const size = att.file.size > 1048576 ? (att.file.size / 1048576).toFixed(1) + ' MB' : Math.round(att.file.size / 1024) + ' KB';
    return `<div class="dc-attach-item">
      <span style="font-size:17px;flex-shrink:0">${icon}</span>
      <input class="dc-attach-rename" value="${att.displayName.replace(/"/g,'&quot;')}" oninput="window._dcPendingAttachments[${idx}].displayName=this.value" title="Rename file">
      <span class="dc-attach-size">${size}</span>
      <button class="dc-attach-del" onclick="dcRemoveAttachment(${idx})" title="Remove">✕</button>
    </div>`;
  }).join('');
}

function dcRemoveAttachment(idx) {
  if (!window._dcPendingAttachments) return;
  URL.revokeObjectURL(window._dcPendingAttachments[idx]?.objUrl);
  window._dcPendingAttachments.splice(idx, 1);
  dcRenderAttachList();
}

function dcSaveAttachments() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const pending = window._dcPendingAttachments || [];
  if (!pending.length) { showToast('No files to save — please attach at least one file', 'warn'); return; }
  if (!app._taskAttachments) app._taskAttachments = [];
  if (!window._BFP_STORE) window._BFP_STORE = {};
  pending.forEach(att => {
    const storeKey = 'dc-attach-' + appId + '-' + att.uid;
    window._BFP_STORE[storeKey] = { name: att.displayName || att.file.name, mimetype: att.mimetype, url: att.objUrl, isImage: att.isImage, isPdf: att.isPdf };
    app._taskAttachments.push({ storeKey, name: att.displayName || att.file.name, mimetype: att.mimetype, isImage: att.isImage, isPdf: att.isPdf, taskTitle: 'Deal Confirmation', date: new Date().toLocaleDateString('en-IN') });
  });
  // Mark any open "Deal Confirmation" task as complete
  if (typeof _TASKS_LOCAL2 !== 'undefined') {
    _TASKS_LOCAL2.forEach(t => {
      if (t.appId === appId && !t.done && /deal.confirm/i.test(t.title || '')) {
        t.done = true;
        t.completionNote = 'Documents attached via Deal Confirmation';
      }
    });
    if (typeof renderGlobalTasks === 'function') renderGlobalTasks();
  }
  window._dcPendingAttachments = [];
  dcRenderAttachList();
  showToast(pending.length + ' file(s) saved to Documents ✓', 'success');
  // Refresh docs tab if detail panel is open
  if (typeof openDetail === 'function') setTimeout(() => openDetail(appId), 300);
}

// Reset attach list whenever the modal is freshly opened
(function() {
  const _orig = openDealConfirmModal;
  openDealConfirmModal = function(appId) {
    window._dcPendingAttachments = [];
    const wrap = document.getElementById('dc-attach-wrap');
    if (wrap) wrap.style.display = 'none';
    dcRenderAttachList();
    _orig(appId);
  };
})();

// ── Open email client with pre-filled deal confirmation ──
function dcOpenMailto() {
  const appId = document.getElementById('dc-app-id')?.value;
  const app   = APPLICATIONS.find(a => a.id === appId);
  if (!app) return;
  const to = document.getElementById('dc-to')?.value.trim();
  const cc = document.getElementById('dc-cc')?.value.trim();
  if (!to) { showToast('Please enter the customer email address', 'warn'); return; }
  const { subject, bodyText } = dcBuildEmailContent(app);
  window.open(`mailto:${to}?${cc ? 'cc=' + encodeURIComponent(cc) + '&' : ''}subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(bodyText)}`, '_blank');
}
// ══════════════════════════════════════════════════════════════════════
//  SYSTEM EMAIL CONFIGURATION
//  Admin-configurable outgoing email identity for deal confirmations.
//  Inbox scan: paste reply → auto-detect app ID + acceptance keywords.
// ══════════════════════════════════════════════════════════════════════

// ══════════════════════════════════════════════════════════════════════
//  SYSTEM EMAIL — Gmail API via Google Identity Services (OAuth 2.0)
//  Sends deal confirmations FROM the configured Gmail address.
//  Polls that same inbox for customer replies and auto-attaches them.
// ══════════════════════════════════════════════════════════════════════

const SYSMAIL_KEY = 'efin_system_email_config_v2';

// ══════════════════════════════════════════════════════════════════
//  SYSTEM EMAIL ENGINE — Gmail SMTP (via EmailJS) + Brevo API
// ══════════════════════════════════════════════════════════════════


// ── Get config ──
function mailGetConfig() {
  try { return JSON.parse(localStorage.getItem(SYSMAIL_KEY) || '{}'); } catch(e) { return {}; }
}

// ══════════════════════════════════════════════════════════════════
//  CORE SEND FUNCTION — routes to Gmail (EmailJS) or Brevo
// ══════════════════════════════════════════════════════════════════
async function mailSend({ to, toName, subject, html, cc, replyTo }) {
  const cfg = mailGetConfig();
  if (!cfg.fromEmail) throw new Error('NO_FROM');

  if ((cfg.provider || 'brevo') === 'gmail') {
    return await _sendViaEmailJS({ to, toName, subject, html, cfg });
  } else {
    return await _sendViaBrevo({ to, toName, subject, html, cc, replyTo, cfg });
  }
}

// ── Brevo send ──
async function _sendViaBrevo({ to, toName, subject, html, cc, replyTo, cfg }) {
  if (!cfg.apiKey) throw new Error('NO_KEY');
  const body = {
    sender:      { name: cfg.name || 'EFIN', email: cfg.fromEmail },
    to:          [{ email: to, name: toName || to }],
    subject,
    htmlContent: html,
  };
  if (cc || cfg.cc)             body.cc      = [{ email: cc || cfg.cc }];
  if (replyTo || cfg.replyto)   body.replyTo = { email: replyTo || cfg.replyto };

  const res = await fetch('https://api.brevo.com/v3/smtp/email', {
    method: 'POST',
    headers: { 'api-key': cfg.apiKey, 'Content-Type': 'application/json', 'accept': 'application/json' },
    body: JSON.stringify(body),
  });
  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    throw new Error(err.message || 'Brevo HTTP ' + res.status);
  }
  return await res.json();
}

// ── Gmail via EmailJS ──
async function _sendViaEmailJS({ to, toName, subject, html, cfg }) {
  if (!cfg.ejsService || !cfg.ejsTemplate || !cfg.ejsPubKey) throw new Error('NO_EJS_CONFIG');

  // Load EmailJS SDK lazily
  if (typeof emailjs === 'undefined') {
    await new Promise((resolve, reject) => {
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/@emailjs/browser@4/dist/email.min.js';
      s.onload = resolve; s.onerror = () => reject(new Error('EmailJS SDK failed to load'));
      document.head.appendChild(s);
    });
  }
  emailjs.init(cfg.ejsPubKey);

  // Strip HTML tags for plain-text fallback
  const plainText = html.replace(/<[^>]+>/g, '').replace(/\n{3,}/g, '\n\n').trim();

  const templateParams = {
    to_email:    to,
    to_name:     toName || to,
    from_name:   cfg.name || 'EFIN',
    from_email:  cfg.fromEmail,
    subject:     subject,
    message:     plainText,
    message_html: html,
    reply_to:    cfg.replyto || cfg.fromEmail,
  };

  const result = await emailjs.send(cfg.ejsService, cfg.ejsTemplate, templateParams);
  if (result.status !== 200) throw new Error('EmailJS error: ' + result.text);
  return result;
}

// ══════════════════════════════════════════════════════════════════
//  INVITATION EMAIL — fires automatically on user creation
// ══════════════════════════════════════════════════════════════════
// SECURITY FIX: accept plainTextPwd as an explicit argument so we never read
// user._password (which is already masked to '***' by the time this fires).
async function mailSendInvitation(user, plainTextPwd) {
  const cfg = mailGetConfig();
  if (cfg.invEnabled === false) return; // disabled by admin
  if (!cfg.fromEmail) { showToast('Invitation email skipped — configure Settings → Mail & Email first', 'warn'); return; }

  // Use the explicitly passed plaintext password; fall back to a safe placeholder.
  // We intentionally do NOT read user._password here — it is already '***' in storage.
  const pwdDisplay = plainTextPwd || '(set by admin — please contact your admin for credentials)';

  const subject = (cfg.invSubject || "You've been invited to EFIN — Set your password");
  const bodyTemplate = cfg.invBody || `Hi {{name}},\n\nYour account has been created on the EFIN Loan Management System.\n\nLogin Email: {{email}}\nTemporary Password: {{password}}\nUser ID: {{uid}}\n\nPlease log in and change your password immediately.\n\n{{signature}}`;

  const body = bodyTemplate
    .replace(/{{name}}/g,      user.name     || '')
    .replace(/{{email}}/g,     user.email    || '')
    .replace(/{{password}}/g,  pwdDisplay)
    .replace(/{{uid}}/g,       user.uid      || '')
    .replace(/{{role}}/g,      user.role     || '')
    .replace(/{{signature}}/g, cfg.signature || '');

  // Convert plain text body to simple HTML
  const html = `
    <div style="font-family:Arial,sans-serif;max-width:520px;margin:0 auto;padding:28px 24px;background:#f4f7ff;border-radius:16px">
      <div style="background:#1a4fa3;border-radius:12px 12px 0 0;padding:20px 28px;text-align:center">
        <div style="font-size:26px;font-weight:900;color:#fff;letter-spacing:-1px">EFIN</div>
        <div style="font-size:12px;color:rgba(255,255,255,.7);letter-spacing:2px;text-transform:uppercase;margin-top:2px">Loan Management System</div>
      </div>
      <div style="background:#fff;border-radius:0 0 12px 12px;padding:28px 28px 24px;border:1px solid #dde3f0;border-top:none">
        <div style="font-size:20px;font-weight:800;color:#0c1733;margin-bottom:18px">🎉 Welcome to EFIN!</div>
        <pre style="white-space:pre-wrap;font-family:Arial,sans-serif;font-size:13.5px;color:#3a4d6e;line-height:1.75;margin:0">${body}</pre>
        <div style="margin-top:24px;padding:14px 18px;background:#f0f4ff;border-radius:10px;border-left:4px solid #1a4fa3">
          <div style="font-size:11.5px;color:#7a8aaa;font-weight:600;margin-bottom:4px">YOUR CREDENTIALS</div>
          <div style="font-size:13px;color:#0c1733"><strong>Email:</strong> ${user.email || ''}</div>
          <div style="font-size:13px;color:#0c1733"><strong>User ID:</strong> ${user.uid || ''}</div>
          <div style="font-size:13px;color:#0c1733"><strong>Role:</strong> ${user.role || ''}</div>
        </div>
        <div style="margin-top:20px;font-size:11px;color:#7a8aaa;text-align:center">This is an automated message from the EFIN system. Do not reply to this email.</div>
      </div>
    </div>`;

  try {
    await mailSend({ to: user.email, toName: user.name, subject, html });
    showToast('Invitation email sent to ' + user.email + ' ✓', 'success');
  } catch(err) {
    const msg = err.message === 'NO_FROM'       ? 'From address not configured in Settings → Mail & Email'  :
                err.message === 'NO_KEY'        ? 'Brevo API key not configured'                 :
                err.message === 'NO_EJS_CONFIG' ? 'EmailJS credentials not configured'           :
                err.message;
    showToast('Invitation email failed: ' + msg, 'warn');
    console.warn('[EFIN Invite Email]', err);
  }
}


// ── Back-compat aliases ──
// The email engine was renamed sysmail* → mail* when the System Email tab was
// removed from Profile. These thin aliases keep the ~15 automated-email call
// sites (status updates, deal confirmations, invitations, etc.) working and all
// route to the single Settings → Mail & Email configuration.
function sysmailGetConfig() { return mailGetConfig(); }
async function sysmailSend(opts) { return mailSend(opts); }
async function sysmailSendInvitation(user, pwd) { return mailSendInvitation(user, pwd); }
async function breveSend(opts) { return mailSend(opts); }

// ── Scan pasted reply ──
function sysmailScanReply() {
  const text    = (document.getElementById('stg-paste-reply')?.value || '').trim();
  const resultEl = document.getElementById('stg-scan-result');
  if (!text) { showToast('Please paste the customer reply first', 'warn'); return; }

  const idMatch    = text.match(/EFIN\d{7,12}/i);
  const detectedId = idMatch ? idMatch[0].toUpperCase() : null;
  const isAccepted = /i agree|ok to process|confirm|agreed|accept|proceed|go ahead/i.test(text.toLowerCase());

  if (!detectedId) {
    resultEl.style.display = '';
    resultEl.innerHTML = `<div style="padding:12px 16px;background:rgba(230,126,0,.08);border:1.5px solid rgba(230,126,0,.25);border-radius:10px;font-size:13px;color:var(--warn)">⚠️ Could not detect an EFIN Application ID — ensure the original subject line is included in the reply.</div>`;
    return;
  }
  const app = APPLICATIONS.find(a => a.id === detectedId);
  if (!app) {
    resultEl.style.display = '';
    resultEl.innerHTML = `<div style="padding:12px 16px;background:rgba(212,43,43,.06);border:1.5px solid rgba(212,43,43,.2);border-radius:10px;font-size:13px;color:var(--danger)">✗ Application <strong>${detectedId}</strong> not found in the system.</div>`;
    return;
  }
  const rd   = ROLES[currentUser.role] || {};
  const dept = rd.dept || 'Admin';
  addTrackingEntry(app, 'EFIN-Customer Reply', dept, text.slice(0, 120), 'Customer reply (manual paste):\n' + text);

  if (!isAccepted) {
    resultEl.style.display = '';
    resultEl.innerHTML = `<div style="padding:12px 16px;background:rgba(230,126,0,.08);border:1.5px solid rgba(230,126,0,.25);border-radius:10px;font-size:13px;color:var(--warn)">
      ⚠️ <strong>${detectedId}</strong> — reply attached but no clear acceptance keyword found.<br>
      <button class="btn btn-warn btn-sm" style="margin-top:8px" onclick="sysmailForceAccept('${detectedId}');sysmailRenderPending()">⚡ Mark Accepted Anyway</button>
    </div>`;
    return;
  }
  sysmailForceAccept(detectedId);
  resultEl.style.display = '';
  resultEl.innerHTML = `<div style="padding:12px 16px;background:rgba(26,115,64,.08);border:1.5px solid rgba(26,115,64,.25);border-radius:10px;font-size:13px;color:var(--success)">✅ <strong>${detectedId}</strong> — reply attached and status moved to <strong>Acceptance</strong>.</div>`;
  document.getElementById('stg-paste-reply').value = '';
  sysmailRenderPending();
}

function sysmailForceAccept(appId) {
  const app = APPLICATIONS.find(a => a.id === appId);
  if (!app || app.status === 'acceptance' || app.status === 'disbursed') return;
  const fiNegOrPend = app.final_report && ((app.fi_resi==='Negative'||app.fi_resi==='Pending')||(app.fi_office==='Negative'||app.fi_office==='Pending'));
  if (!app.final_report || fiNegOrPend) {
    if (typeof showToast === 'function') showToast('Cannot move to Acceptance — EFIN FI Report must be completed and Positive first', 'error');
    return;
  }
  const rd = ROLES[currentUser.role] || {};
  addTrackingEntry(app, 'EFIN-Customer Confirmation', rd.dept || 'Admin',
    'Customer confirmed — acceptance keyword detected',
    'Auto-updated by EFIN reply scanner'
  );
  app.status = 'acceptance';
  if (typeof renderTable === 'function') renderTable();
  showToast(appId + ' — Offer Accepted → Acceptance ✓', 'success');
}

function sysmailRenderPending() {
  const el   = document.getElementById('stg-pending-list');
  const ctEl = document.getElementById('stg-pending-count');
  if (!el) return;
  const pending = APPLICATIONS.filter(a => a._dealConfirmSent && a.status === 'approved_deviation');
  if (ctEl) ctEl.textContent = pending.length ? pending.length + ' pending' : '';
  if (!pending.length) {
    el.innerHTML = `<div style="padding:20px;text-align:center;color:var(--text3);font-size:13px">No applications awaiting confirmation.</div>`;
    return;
  }
  el.innerHTML = pending.map(a => `
    <div style="display:flex;align-items:center;gap:14px;padding:13px 16px;border:1.5px solid var(--border);border-radius:12px;margin-bottom:8px;background:var(--surface2)">
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:700;color:var(--text)">${a.id} — ${a.name}</div>
        <div style="font-size:11.5px;color:var(--text3);margin-top:2px">Awaiting reply · <strong>${a.email || 'No email'}</strong></div>
      </div>
      <button class="btn btn-success btn-sm" onclick="sysmailForceAccept('${a.id}');sysmailRenderPending()">✅ Accept</button>
      <button class="btn btn-ghost btn-sm" onclick="openDealConfirmModal('${a.id}')">📧 Resend</button>
    </div>`).join('');
}

// ══════════════════════════════════════════════════════
