// ── Filter state ──
var advFilter = {
  subDsa:'', teamLead:'', teamMember:'', location:'', channel:'',
  dateMode:'', dateFrom:'', dateTo:'',
  loanType:'', bank:'', status:'', purpose:'',
  amountMin:'', amountMax:'',
  empType:'', leadsrc:'', city:'', state:'', gender:'',
  cibilMin:'', cibilMax:'', salaryMin:'', salaryMax:'',
  dsaName:'', linkedPartner:'', companyName:''
};

// ── Saved filter presets (persisted in localStorage) ──
var _afPresets = [];
(function() {
  try { _afPresets = JSON.parse(localStorage.getItem('efin_filter_presets') || '[]'); } catch(e) {}
})();

function _afSavePresets() {
  try { localStorage.setItem('efin_filter_presets', JSON.stringify(_afPresets)); } catch(e) {}
}

function afSavePreset() {
  const hasAny = Object.values(advFilter).some(Boolean);
  if (!hasAny) { showToast('No active filters to save as preset', 'warn'); return; }
  const name = prompt('Preset name:');
  if (!name) return;
  _afPresets = _afPresets.filter(p => p.name !== name);
  _afPresets.push({ name, filters: Object.assign({}, advFilter) });
  _afSavePresets();
  _afRenderPresets();
  showToast('Preset "' + name + '" saved ✓', 'success');
}

function afLoadPreset(name) {
  const p = _afPresets.find(x => x.name === name);
  if (!p) return;
  advFilter = Object.assign({}, p.filters);
  _afRestoreToUI();
  _afUpdateLiveCount();
  showToast('Preset "' + name + '" loaded', 'info');
}

function afDeletePreset(name) {
  _afPresets = _afPresets.filter(p => p.name !== name);
  _afSavePresets();
  _afRenderPresets();
}

function _afRenderPresets() {
  const wrap = document.getElementById('af-preset-list');
  if (!wrap) return;
  if (!_afPresets.length) {
    wrap.innerHTML = '<span style="font-size:11.5px;color:var(--text3);font-style:italic">No saved presets yet</span>';
    return;
  }
  wrap.innerHTML = _afPresets.map(p =>
    '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--accent-subtle);border:1px solid rgba(26,79,163,.2);border-radius:20px;padding:3px 10px;font-size:11.5px;font-weight:600;color:var(--accent)">' +
    '<span onclick="afLoadPreset(\'' + p.name.replace(/'/g,"\\'") + '\')" style="cursor:pointer">' + p.name + '</span>' +
    '<span onclick="afDeletePreset(\'' + p.name.replace(/'/g,"\\'") + '\')" style="cursor:pointer;opacity:.5;margin-left:2px;font-size:10px" title="Delete preset">✕</span>' +
    '</span>'
  ).join('');
}

// ── Open filter modal ──
function openAdvFilter() {
  const liveApps = APPLICATIONS.filter(a => !a.id.startsWith('H') && !a.is_draft);

  // Sales people
  const salesPeople = [...new Set(liveApps.map(a => a.sales).filter(Boolean))].sort();
  const subDsaSel = document.getElementById('af-sub-dsa');
  if (subDsaSel) subDsaSel.innerHTML = '<option value="">All</option>' + salesPeople.map(s => '<option value="' + s + '"' + (advFilter.subDsa===s?' selected':'') + '>' + s + '</option>').join('');

  // Team leads
  const leads = USER_ACCOUNTS.filter(u => u.role === 'team_leader').map(u => u.name).sort();
  const tlSel = document.getElementById('af-team-lead');
  if (tlSel) tlSel.innerHTML = '<option value="">All</option>' + leads.map(l => '<option value="' + l + '"' + (advFilter.teamLead===l?' selected':'') + '>' + l + '</option>').join('');

  // Team members
  const members = USER_ACCOUNTS.filter(u => !['admin','partner'].includes(u.role)).map(u => u.name).sort();
  const tmSel = document.getElementById('af-team-member');
  if (tmSel) tmSel.innerHTML = '<option value="">All</option>' + members.map(m => '<option value="' + m + '"' + (advFilter.teamMember===m?' selected':'') + '>' + m + '</option>').join('');

  // Banks
  const banks = [...new Set(liveApps.map(a => a.bank).filter(Boolean))].sort();
  const bankSel = document.getElementById('af-bank');
  if (bankSel) bankSel.innerHTML = '<option value="">All Banks</option>' + banks.map(b => '<option value="' + b + '"' + (advFilter.bank===b?' selected':'') + '>' + b + '</option>').join('');

  // Locations
  const locations = [...new Set(liveApps.map(a => a.location).filter(Boolean))].sort();
  const locSel = document.getElementById('af-location');
  if (locSel) locSel.innerHTML = '<option value="">All Locations</option>' + locations.map(l => '<option value="' + l + '"' + (advFilter.location===l?' selected':'') + '>' + l + '</option>').join('');

  // Cities & States
  const cities = [...new Set(liveApps.map(a => a.city).filter(Boolean))].sort();
  const citySel = document.getElementById('af-city');
  if (citySel) citySel.innerHTML = '<option value="">All Cities</option>' + cities.map(c => '<option value="' + c + '"' + (advFilter.city===c?' selected':'') + '>' + c + '</option>').join('');

  const states = [...new Set(liveApps.map(a => a.state).filter(Boolean))].sort();
  const stateSel = document.getElementById('af-state');
  if (stateSel) stateSel.innerHTML = '<option value="">All States</option>' + states.map(s => '<option value="' + s + '"' + (advFilter.state===s?' selected':'') + '>' + s + '</option>').join('');

  // DSA Names (from apps that have channelDSA set, plus master DSA list)
  const dsaNames = [...new Set([
    ...liveApps.map(a => a.channelDSA).filter(Boolean),
    ...(window.twDSAList || []).filter(d => d.status === 'active').map(d => d.name)
  ])].sort();
  const dsaSel = document.getElementById('af-dsa-name');
  if (dsaSel) dsaSel.innerHTML = '<option value="">All DSAs</option>' + dsaNames.map(d => '<option value="' + d + '"' + (advFilter.dsaName===d?' selected':'') + '>' + d + '</option>').join('');

  // Linked Partners (from apps that have channelPartner, plus partner list)
  const partnerNames = [...new Set([
    ...liveApps.map(a => a.channelPartner).filter(Boolean),
    ...(window.twPartnerList || []).filter(p => p.status === 'active').map(p => p.name)
  ])].sort();
  const partnerSel = document.getElementById('af-linked-partner');
  if (partnerSel) partnerSel.innerHTML = '<option value="">All Partners</option>' + partnerNames.map(p => '<option value="' + p + '"' + (advFilter.linkedPartner===p?' selected':'') + '>' + p + '</option>').join('');

  // Company / Employer Names
  const companyNames = [...new Set(liveApps.map(a => a.compName).filter(Boolean))].sort();
  const companySel = document.getElementById('af-company-name');
  if (companySel) companySel.innerHTML = '<option value="">All Companies</option>' + companyNames.map(c => '<option value="' + c + '"' + (advFilter.companyName===c?' selected':'') + '>' + c + '</option>').join('');

  _afRestoreToUI();
  _afRenderPresets();
  _afUpdateLiveCount();
  openModal('modal-adv-filter');

  // Live count update on any field change
  document.querySelectorAll('#modal-adv-filter select, #modal-adv-filter input').forEach(function(el) {
    el.oninput = el.onchange = _afUpdateLiveCount;
  });
}

// Restore all field values from advFilter state to the UI
function _afRestoreToUI() {
  const fld = function(id, val) { const el = document.getElementById(id); if (el && val !== undefined) el.value = val; };
  fld('af-sub-dsa',    advFilter.subDsa);
  fld('af-team-lead',  advFilter.teamLead);
  fld('af-team-member',advFilter.teamMember);
  fld('af-location',   advFilter.location);
  fld('af-channel',    advFilter.channel);
  fld('af-loan-type',  advFilter.loanType);
  fld('af-bank',       advFilter.bank);
  fld('af-status',     advFilter.status);
  fld('af-purpose',    advFilter.purpose);
  fld('af-amount-min', advFilter.amountMin);
  fld('af-amount-max', advFilter.amountMax);
  fld('af-emp-type',   advFilter.empType);
  fld('af-leadsrc',    advFilter.leadsrc);
  fld('af-city',       advFilter.city);
  fld('af-state',      advFilter.state);
  fld('af-gender',     advFilter.gender);
  fld('af-cibil-min',  advFilter.cibilMin);
  fld('af-cibil-max',  advFilter.cibilMax);
  fld('af-salary-min', advFilter.salaryMin);
  fld('af-salary-max', advFilter.salaryMax);
  fld('af-dsa-name',      advFilter.dsaName);
  fld('af-linked-partner',advFilter.linkedPartner);
  fld('af-company-name',  advFilter.companyName);

  // Date chips
  document.querySelectorAll('.af-date-chip').forEach(function(c) {
    c.classList.toggle('active', c.dataset.mode === advFilter.dateMode);
  });
  const row = document.getElementById('af-custom-date-row');
  if (row) {
    row.style.display = advFilter.dateMode === 'custom' ? 'flex' : 'none';
    fld('af-date-from', advFilter.dateFrom);
    fld('af-date-to',   advFilter.dateTo);
  }
}

// Live result count as user changes filters
function _afUpdateLiveCount() {
  const tempFilter = _afReadFromUI();
  const liveApps = APPLICATIONS.filter(a => !a.id.startsWith('H') && !a.is_draft);
  const count = _applyAdvFilterToApps([...liveApps], tempFilter).length;
  const el = document.getElementById('af-result-count');
  if (el) el.textContent = count + (count === 1 ? ' result' : ' results');
}

// Read current UI values into a temporary filter object (without saving to advFilter)
function _afReadFromUI() {
  const g = function(id) { return (document.getElementById(id) || {}).value || ''; };
  const tmp = {
    subDsa:    g('af-sub-dsa'),
    teamLead:  g('af-team-lead'),
    teamMember:g('af-team-member'),
    location:  g('af-location'),
    channel:   g('af-channel'),
    loanType:  g('af-loan-type'),
    bank:      g('af-bank'),
    status:    g('af-status'),
    purpose:   g('af-purpose'),
    amountMin: g('af-amount-min'),
    amountMax: g('af-amount-max'),
    empType:   g('af-emp-type'),
    leadsrc:   g('af-leadsrc'),
    city:      g('af-city'),
    state:     g('af-state'),
    gender:    g('af-gender'),
    cibilMin:  g('af-cibil-min'),
    cibilMax:  g('af-cibil-max'),
    salaryMin: g('af-salary-min'),
    salaryMax: g('af-salary-max'),
    dateMode:  advFilter.dateMode,
    dateFrom:  advFilter.dateMode === 'custom' ? g('af-date-from') : '',
    dateTo:    advFilter.dateMode === 'custom' ? g('af-date-to')   : '',
    dsaName:      g('af-dsa-name'),
    linkedPartner:g('af-linked-partner'),
    companyName:  g('af-company-name'),
  };
  return tmp;
}

function setAdvDate(mode, el) {
  document.querySelectorAll('.af-date-chip').forEach(function(c) { c.classList.remove('active'); });
  el.classList.add('active');
  advFilter.dateMode = mode;
  const row = document.getElementById('af-custom-date-row');
  if (row) row.style.display = mode === 'custom' ? 'flex' : 'none';
  _afUpdateLiveCount();
}

// CIBIL band quick-select
function afSetCibilBand(btn) {
  document.querySelectorAll('.af-cibil-band').forEach(function(b) {
    b.style.fontWeight = b === btn ? '800' : '600';
    b.style.opacity    = b === btn ? '1'   : '0.7';
  });
  const minEl = document.getElementById('af-cibil-min');
  const maxEl = document.getElementById('af-cibil-max');
  if (minEl) minEl.value = btn.dataset.min;
  if (maxEl) maxEl.value = btn.dataset.max;
  _afUpdateLiveCount();
}

function applyAdvFilter() {
  advFilter = _afReadFromUI();

  // Update badge on filter button
  const activeCount = Object.values(advFilter).filter(Boolean).length;
  const badge = document.getElementById('adv-filter-badge');
  const btn   = document.getElementById('adv-filter-btn');
  if (badge) {
    badge.textContent = activeCount || '';
    badge.style.display = activeCount ? 'inline-block' : 'none';
    badge.style.background = 'var(--accent2)';
    badge.style.borderRadius = '20px';
    badge.style.padding = '1px 6px';
    badge.style.width = 'auto';
  }
  if (btn) activeCount ? btn.classList.add('has-filters') : btn.classList.remove('has-filters');

  // Update active chips in modal header
  _afUpdateActiveChips();

  if (typeof _appsCurrentPage !== 'undefined') _appsCurrentPage = 1;
  closeModal('modal-adv-filter');
  renderTableWithAdvFilter();
}

function _afUpdateActiveChips() {
  const summary = document.getElementById('af-active-summary');
  const chipsWrap = document.getElementById('af-active-chips');

  const FIELD_LABELS = {
    subDsa:'Sales', teamLead:'TL', teamMember:'Member',
    location:'Location', channel:'Channel', dateMode:'Date',
    dateFrom:'From', dateTo:'To',
    loanType:'Type', bank:'Bank', status:'Status', purpose:'Purpose',
    amountMin:'Min ₹', amountMax:'Max ₹',
    empType:'Emp.', leadsrc:'Lead Src', city:'City', state:'State', gender:'Gender',
    cibilMin:'CIBIL ≥', cibilMax:'CIBIL ≤', salaryMin:'Sal ≥', salaryMax:'Sal ≤',
    dsaName:'DSA', linkedPartner:'Partner', companyName:'Company'
  };

  const active = Object.entries(advFilter).filter(function([k,v]) { return !!v; });

  if (summary) {
    summary.textContent = active.length
      ? active.length + ' filter' + (active.length > 1 ? 's' : '') + ' active'
      : 'No filters applied';
  }

  if (chipsWrap) {
    chipsWrap.innerHTML = active.map(function([k, v]) {
      const label = FIELD_LABELS[k] || k;
      return '<span style="display:inline-flex;align-items:center;gap:4px;background:var(--accent-subtle);border:1px solid rgba(26,79,163,.18);border-radius:20px;padding:2px 8px;font-size:10.5px;font-weight:700;color:var(--accent);white-space:nowrap">'
        + label + ': ' + v
        + '<span onclick="clearSingleFilter(\'' + k + '\')" style="cursor:pointer;opacity:.55;font-size:9px;margin-left:1px" title="Remove">✕</span>'
        + '</span>';
    }).join('');
  }

  _afUpdateHeaderCount();
}

function clearSingleFilter(key) {
  if (advFilter.hasOwnProperty(key)) advFilter[key] = '';
  // also clear the corresponding DOM element
  var idMap = {
    subDsa:'af-sub-dsa', teamLead:'af-team-lead', teamMember:'af-team-member',
    location:'af-location', channel:'af-channel', loanType:'af-loan-type',
    bank:'af-bank', status:'af-status', purpose:'af-purpose',
    amountMin:'af-amount-min', amountMax:'af-amount-max',
    empType:'af-emp-type', leadsrc:'af-leadsrc', city:'af-city',
    state:'af-state', gender:'af-gender',
    cibilMin:'af-cibil-min', cibilMax:'af-cibil-max',
    salaryMin:'af-salary-min', salaryMax:'af-salary-max',
    dsaName:'af-dsa-name', linkedPartner:'af-linked-partner', companyName:'af-company-name',
    dateFrom:'af-date-from', dateTo:'af-date-to'
  };
  if (idMap[key]) { var el = document.getElementById(idMap[key]); if (el) el.value = ''; }
  if (key === 'dateMode') {
    advFilter.dateMode = ''; advFilter.dateFrom = ''; advFilter.dateTo = '';
    document.querySelectorAll('.af-date-chip').forEach(function(c) { c.classList.remove('active'); });
    var row = document.getElementById('af-custom-date-row'); if (row) row.style.display = 'none';
  }
  _afUpdateActiveChips();
  _afUpdateLiveCount();
  // Re-apply if filter panel is closed
  var modal = document.getElementById('modal-adv-filter');
  if (!modal || modal.style.display === 'none' || !modal.classList.contains('open')) {
    applyAdvFilter();
  }
}

function resetAdvFilter() {
  advFilter = {
    subDsa:'', teamLead:'', teamMember:'', location:'', channel:'',
    dateMode:'', dateFrom:'', dateTo:'',
    loanType:'', bank:'', status:'', purpose:'',
    amountMin:'', amountMax:'',
    empType:'', leadsrc:'', city:'', state:'', gender:'',
    cibilMin:'', cibilMax:'', salaryMin:'', salaryMax:'',
    dsaName:'', linkedPartner:'', companyName:''
  };
  document.querySelectorAll('.af-date-chip').forEach(function(c) { c.classList.remove('active'); });
  document.querySelectorAll('.af-cibil-band').forEach(function(b) { b.style.fontWeight='600'; b.style.opacity='0.7'; });
  ['af-sub-dsa','af-team-lead','af-team-member','af-location','af-channel',
   'af-loan-type','af-bank','af-status','af-purpose',
   'af-amount-min','af-amount-max',
   'af-emp-type','af-leadsrc','af-city','af-state','af-gender',
   'af-cibil-min','af-cibil-max','af-salary-min','af-salary-max',
   'af-dsa-name','af-linked-partner','af-company-name',
   'af-date-from','af-date-to'].forEach(function(id) {
    const el = document.getElementById(id); if (el) el.value = '';
  });
  const row = document.getElementById('af-custom-date-row');
  if (row) row.style.display = 'none';

  const badge = document.getElementById('adv-filter-badge');
  const filterBtn = document.getElementById('adv-filter-btn');
  if (badge) { badge.textContent = ''; badge.style.display = 'none'; }
  if (filterBtn) filterBtn.classList.remove('has-filters');

  _afUpdateHeaderCount();
  _afUpdateLiveCount();
  closeModal('modal-adv-filter');
  window.renderTable();
}

function _afUpdateHeaderCount() {
  const count = Object.values(advFilter).filter(Boolean).length;
  const el = document.getElementById('af-active-count');
  if (el) {
    el.textContent = count ? count + ' filter' + (count > 1 ? 's' : '') + ' active' : '';
    el.style.display = count ? 'inline-block' : 'none';
  }
}

function parseAppDateToMs(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr);
  if (!isNaN(d)) return d.getTime();
  const parts = dateStr.trim().split(' ');
  if (parts.length === 3) {
    const months = {Jan:0,Feb:1,Mar:2,Apr:3,May:4,Jun:5,Jul:6,Aug:7,Sep:8,Oct:9,Nov:10,Dec:11};
    return new Date(+parts[2], months[parts[1]] ?? 0, +parts[0]).getTime();
  }
  return null;
}

// Core filter engine — accepts optional filter override for live preview
function _applyAdvFilterToApps(apps, f) {
  f = f || advFilter;
  if (f.subDsa)      apps = apps.filter(function(a) { return (a.sales    || '') === f.subDsa; });
  if (f.teamMember)  apps = apps.filter(function(a) { return (a.sales    || '') === f.teamMember; });
  if (f.location)    apps = apps.filter(function(a) { return (a.location || '') === f.location; });
  if (f.channel)     apps = apps.filter(function(a) { return (a.channel  || '') === f.channel; });
  if (f.loanType)    apps = apps.filter(function(a) { return a.loanType  === f.loanType; });
  if (f.bank)        apps = apps.filter(function(a) { return (a.bank     || '') === f.bank; });
  if (f.status)      apps = apps.filter(function(a) { return a.status    === f.status; });
  if (f.purpose)     apps = apps.filter(function(a) { return (a.purpose  || '') === f.purpose; });
  if (f.empType)     apps = apps.filter(function(a) { return (a.empType  || '') === f.empType; });
  if (f.leadsrc)     apps = apps.filter(function(a) { return (a.leadsrc  || '') === f.leadsrc; });
  if (f.city)        apps = apps.filter(function(a) { return (a.city     || '') === f.city; });
  if (f.state)       apps = apps.filter(function(a) { return (a.state    || '') === f.state; });
  if (f.gender)      apps = apps.filter(function(a) { return (a.gender   || '') === f.gender; });
  if (f.amountMin)   apps = apps.filter(function(a) { return Number(a.amount) >= Number(f.amountMin); });
  if (f.amountMax)   apps = apps.filter(function(a) { return Number(a.amount) <= Number(f.amountMax); });
  if (f.cibilMin)    apps = apps.filter(function(a) { return Number(a.cibil)  >= Number(f.cibilMin); });
  if (f.cibilMax)    apps = apps.filter(function(a) { return Number(a.cibil)  <= Number(f.cibilMax); });
  if (f.salaryMin)   apps = apps.filter(function(a) { return Number(a.salary) >= Number(f.salaryMin); });
  if (f.salaryMax)   apps = apps.filter(function(a) { return Number(a.salary) <= Number(f.salaryMax); });
  // DSA Name — exact match OR partial match for robustness
  if (f.dsaName)      apps = apps.filter(function(a) { return (a.channelDSA || '').toLowerCase() === f.dsaName.toLowerCase() || (a.dsaId && (window.twDSAList||[]).some(function(d){ return d.id===a.dsaId && d.name===f.dsaName; })); });
  // Linked Partner — exact match (agents + DSA-linked partners)
  if (f.linkedPartner)apps = apps.filter(function(a) { return (a.channelPartner || '').toLowerCase() === f.linkedPartner.toLowerCase(); });
  // Company / Employer Name — case-insensitive exact match
  if (f.companyName)  apps = apps.filter(function(a) { return (a.compName || '').toLowerCase() === f.companyName.toLowerCase(); });

  if (f.dateMode && f.dateMode !== 'custom') {
    const today = new Date(); today.setHours(0,0,0,0);
    const todayMs = today.getTime();
    const monthStart = new Date(today.getFullYear(), today.getMonth(), 1).getTime();
    const quarterStart = new Date(today.getFullYear(), Math.floor(today.getMonth()/3)*3, 1).getTime();
    const yearStart = new Date(today.getFullYear(), 0, 1).getTime();
    apps = apps.filter(function(a) {
      const ms = parseAppDateToMs(a.date); if (ms === null) return true;
      if (f.dateMode === 'today')     return ms >= todayMs;
      if (f.dateMode === 'yesterday') return ms >= todayMs - 86400000 && ms < todayMs;
      if (f.dateMode === '7days')     return ms >= todayMs - 6*86400000;
      if (f.dateMode === '15days')    return ms >= todayMs - 14*86400000;
      if (f.dateMode === '30days')    return ms >= todayMs - 29*86400000;
      if (f.dateMode === '90days')    return ms >= todayMs - 89*86400000;
      if (f.dateMode === 'mtd')       return ms >= monthStart;
      if (f.dateMode === 'qtd')       return ms >= quarterStart;
      if (f.dateMode === 'ytd')       return ms >= yearStart;
      return true;
    });
  } else if (f.dateMode === 'custom') {
    if (f.dateFrom) {
      const from = new Date(f.dateFrom).getTime();
      apps = apps.filter(function(a) { const ms = parseAppDateToMs(a.date); return ms === null || ms >= from; });
    }
    if (f.dateTo) {
      const to = new Date(f.dateTo).getTime() + 86399999;
      apps = apps.filter(function(a) { const ms = parseAppDateToMs(a.date); return ms === null || ms <= to; });
    }
  }
  return apps;
}

function renderTableWithAdvFilter() {
  const _rawAppsAdv = APPLICATIONS.filter(function(a) { return !a.id.startsWith('H') && !a.is_draft; });
  // Fix 5: apply role-based filter
  const liveApps = (typeof window._applyRoleFilter === 'function') ? window._applyRoleFilter(_rawAppsAdv) : _rawAppsAdv;
  const isAdmin  = currentUser.role === 'admin';
  const _curFilter = window._activeFilterAdv || 'all';
  // Status filter from chips — skip if advFilter.status is set (modal overrides)
  let apps = _curFilter === 'all' ? liveApps : liveApps.filter(function(a) { return a.status === _curFilter; });
  // Override with modal status filter if set
  if (advFilter.status) apps = liveApps.filter(function(a) { return a.status === advFilter.status; });
  apps = _applyAdvFilterToApps(apps);

  const body = document.getElementById('app-table-body');
  if (!body) return;
  const pageApps = (typeof _appsPaginate === 'function') ? _appsPaginate(apps) : apps;
  body.innerHTML = pageApps.map(function(a) {
    return '<tr onclick="openDetail(\'' + a.id + '\')">' +
      '<td><span class="app-id">' + a.id + '</span></td>' +
      '<td><strong>' + a.name + '</strong></td>' +
      '<td>' + (typeof loanTypeLabel === 'function' ? loanTypeLabel(a.loanType) : a.loanType) + '</td>' +
      '<td>₹' + Number(a.amount).toLocaleString('en-IN') + '</td>' +
      '<td><span class="badge badge-' + a.status + '">' + (STATUSES[a.status] || a.status) + '</span></td>' +
      '<td>' + (a.sales || '—') + '</td>' +
      '<td>' + (a.date  || '—') + '</td>' +
      '<td onclick="event.stopPropagation()">' +
        (isAdmin ? '<button class="btn btn-sm" onclick="deleteApplication(\'' + a.id + '\',event)" style="background:rgba(192,57,43,.08);border:1px solid rgba(192,57,43,.25);color:var(--danger);border-radius:8px">🗑</button>' : '') +
      '</td>' +
    '</tr>';
  }).join('') || '<tr><td colspan="8" style="text-align:center;color:var(--text3);padding:40px">No applications match your filters</td></tr>';
}

// Override renderTable to respect adv filters
const _origRenderTable = window.renderTable;
window.renderTable = function renderTable(filter) {
  if (filter !== undefined) window._activeFilterAdv = filter;
  const hasAdv = Object.values(advFilter).some(function(v) { return v !== '' && v !== null && v !== undefined; });
  if (hasAdv) { renderTableWithAdvFilter(); return; }
  _origRenderTable(filter);
};
window.filterByStatus = function(status, el) {
  if (el) { document.querySelectorAll('#page-applications .filter-chip').forEach(function(c) { c.classList.remove('active'); }); el.classList.add('active'); }
  activeFilter = status;
  if (typeof _appsCurrentPage !== 'undefined') _appsCurrentPage = 1;
  window.renderTable(status);
};

