var _exportDragSrc = null;
var _exportScope   = 'filtered';
const EXPORT_PRESET_KEY = 'efin_export_presets_v2';

// ── Label helpers shared by export ──────────────────────────
const _EXP_LABELS = {
  loanType:  { personal_loan:'Personal Loan', business_loan:'Business Loan', home_loan:'Home Loan', new_car_loan:'New Car Loan', used_car_loan:'Used Car Loan', lap:'LAP', two_wheeler:'Two Wheeler Loan' },
  empType:   { SALARIED:'Salaried', SELFEMP:'Self Employed' },
  gender:    { M:'Male', F:'Female', O:'Other' },
  homeType:  { OWNED_SELF_SPOUSE:'Owned (Self/Spouse)', OWNED_BY_PARENTS:'Owned by Parents', RENTED_SELF_WITH_FAMILY:'Rented (With Family)', PAYING_GUEST_PL:'Paying Guest', COMPANY_ACCOMMODATION:'Company Accommodation' },
  leadsrc:   { facebook:'Facebook', whatsapp:'WhatsApp', instagram:'Instagram', google_ads:'Google Ads', reference:'Reference', walk_in:'Walk-In', cold_call:'Cold Call', partner:'Partner' },
  channel:   { direct:'Direct', agent:'Partner / Agent', online:'Online', dsa:'DSA' },
  compType:  { plcc:'Pvt Ltd / Ltd', plc:'Public Ltd', llp:'LLP / Partnership', govt:'Govt / PSU', other:'Other' },
  purpose:   { personal_use:'Personal Use', home_renovation:'Home Renovation', business_growth:'Business Growth', education:'Education', medical:'Medical', travel:'Travel', wedding:'Wedding' },
  incred_offer: { completed:'Approved', rejected:'Rejected', pending:'Pending', created:'Submitted', '':'Not Submitted' },
};
function _expLabel(key, val) {
  if (!val && val !== 0) return '';
  return (_EXP_LABELS[key] && _EXP_LABELS[key][val]) || String(val);
}

// ── Column presets ───────────────────────────────────────────
function exportQuickCols(preset) {
  const sets = {
    basic:     ['sequence','id','name','mobile','loanType','amount','bank','status','sales','location','date','city','state'],
    kyc:       ['sequence','id','name','mobile','email','pan','aadhar','dob','gender','father','homeType'],
    financial: ['sequence','id','name','loanType','amount','empType','compName','salary','obligations','_foir','_emi','cibil','loanRate','tenure','status','disbursement_date'],
    full:      null,
  };
  if (preset === 'full') {
    EXPORT_COLS.forEach(function(c) { c.checked = true; });
  } else {
    const active = new Set(sets[preset] || []);
    EXPORT_COLS.forEach(function(c) { c.checked = active.has(c.key); });
  }
  renderExportColList();
  _updateExportCounts();
  _renderExportPreview();
}

function exportSavePreset() {
  const name = prompt('Name this preset:', 'My Preset ' + (new Date().toLocaleDateString('en-IN')));
  if (!name || !name.trim()) return;
  const keys = EXPORT_COLS.filter(c => c.checked).map(c => c.key);
  let presets = _loadExportPresets();
  presets[name.trim()] = keys;
  try { localStorage.setItem(EXPORT_PRESET_KEY, JSON.stringify(presets)); } catch(e) {}
  _renderPresetSelect();
  showToast('Preset "' + name.trim() + '" saved ✓', 'success');
}

function exportLoadPreset(name) {
  if (!name) return;
  const presets = _loadExportPresets();
  if (!presets[name]) return;
  const active = new Set(presets[name]);
  EXPORT_COLS.forEach(function(c) { c.checked = active.has(c.key); });
  renderExportColList();
  _updateExportCounts();
  _renderExportPreview();
  // Reset select to blank after load
  const sel = document.getElementById('export-preset-select');
  if (sel) sel.value = '';
}

function _loadExportPresets() {
  try { return JSON.parse(localStorage.getItem(EXPORT_PRESET_KEY) || '{}'); } catch(e) { return {}; }
}

function _renderPresetSelect() {
  const sel = document.getElementById('export-preset-select');
  if (!sel) return;
  const presets = _loadExportPresets();
  const names = Object.keys(presets);
  sel.innerHTML = '<option value="">💾 Saved Presets…</option>' +
    names.map(function(n) { return '<option value="' + n.replace(/"/g,'&quot;') + '">' + n + '</option>'; }).join('');
}

// ── Scope helpers ────────────────────────────────────────────
function afSetExportScope(scope, btn) {
  _exportScope = scope;
  document.querySelectorAll('.af-date-chip[data-scope]').forEach(function(b) { b.classList.remove('active'); });
  if (btn) btn.classList.add('active');
  const cPanel = document.getElementById('export-custom-filters');
  if (cPanel) cPanel.style.display = scope === 'custom' ? '' : 'none';
  if (scope === 'custom') _populateCustomFilterDropdowns();
  _updateExportCounts();
  _renderExportPreview();
}

function _populateCustomFilterDropdowns() {
  const liveApps = APPLICATIONS.filter(function(a) { return !a.id.startsWith('H') && !a.is_draft; });
  // Banks
  const bankSel = document.getElementById('export-bank-filter');
  if (bankSel && bankSel.options.length <= 1) {
    const banks = [...new Set(liveApps.map(a => a.bank).filter(Boolean))].sort();
    banks.forEach(function(b) { const o = document.createElement('option'); o.value = b; o.textContent = b; bankSel.appendChild(o); });
  }
  // Sales
  const salesSel = document.getElementById('export-sales-filter');
  if (salesSel && salesSel.options.length <= 1) {
    const sales = [...new Set(liveApps.map(a => a.sales).filter(Boolean))].sort();
    sales.forEach(function(s) { const o = document.createElement('option'); o.value = s; o.textContent = s; salesSel.appendChild(o); });
  }
}

function _getExportApps() {
  const liveApps = APPLICATIONS.filter(function(a) { return !a.id.startsWith('H') && !a.is_draft; });
  if (_exportScope === 'all')       return liveApps;
  if (_exportScope === 'disbursed') return liveApps.filter(function(a) { return a.status === 'disbursed'; });
  if (_exportScope === 'pending')   return liveApps.filter(function(a) { return ['wip','login','underwriting','offer','approved'].includes(a.status); });
  if (_exportScope === 'rejected')  return liveApps.filter(function(a) { return a.status === 'rejected'; });
  if (_exportScope === 'custom') {
    let apps = liveApps;
    const dateFrom = document.getElementById('export-date-from')?.value;
    const dateTo   = document.getElementById('export-date-to')?.value;
    const loanType = document.getElementById('export-loantype-filter')?.value;
    const bank     = document.getElementById('export-bank-filter')?.value;
    const status   = document.getElementById('export-status-filter')?.value;
    const sales    = document.getElementById('export-sales-filter')?.value;
    const amtMin   = parseFloat(document.getElementById('export-amt-min')?.value) || 0;
    const amtMax   = parseFloat(document.getElementById('export-amt-max')?.value) || Infinity;
    const _parseDate = function(str) {
      // Handles "15 Mar 2026" and ISO formats
      if (!str) return null;
      const d = new Date(str);
      return isNaN(d) ? null : d;
    };
    if (dateFrom) {
      const from = new Date(dateFrom);
      apps = apps.filter(function(a) { const d = _parseDate(a.date); return d && d >= from; });
    }
    if (dateTo) {
      const to = new Date(dateTo); to.setHours(23,59,59);
      apps = apps.filter(function(a) { const d = _parseDate(a.date); return d && d <= to; });
    }
    if (loanType) apps = apps.filter(function(a) { return a.loanType === loanType; });
    if (bank)     apps = apps.filter(function(a) { return a.bank === bank; });
    if (status)   apps = apps.filter(function(a) { return a.status === status; });
    if (sales)    apps = apps.filter(function(a) { return a.sales === sales; });
    if (amtMin)   apps = apps.filter(function(a) { return (Number(a.amount) || 0) >= amtMin; });
    if (amtMax < Infinity) apps = apps.filter(function(a) { return (Number(a.amount) || 0) <= amtMax; });
    return apps;
  }
  // 'filtered': respect current active filter + adv filter
  const _curFilter = window._activeFilterAdv || 'all';
  let apps = _curFilter === 'all' ? liveApps : liveApps.filter(function(a) { return a.status === _curFilter; });
  const hasAdv = Object.values(advFilter || {}).some(Boolean);
  if (hasAdv) apps = _applyAdvFilterToApps(apps);
  return apps;
}

function _updateExportCounts() {
  const apps = _getExportApps();
  const cols = EXPORT_COLS.filter(function(c) { return c.checked; });
  const rowEl = document.getElementById('export-row-count');
  const colEl = document.getElementById('export-col-count');
  const lblEl = document.getElementById('export-scope-label');
  if (rowEl) rowEl.textContent = apps.length;
  if (colEl) colEl.textContent = cols.length;
  if (lblEl) {
    const scopeLabels = { filtered:'Current filtered view', all:'All applications', disbursed:'Disbursed only', pending:'Active pipeline', rejected:'Rejected only', custom:'Custom filter' };
    lblEl.textContent = (scopeLabels[_exportScope] || _exportScope) + ' — ' + apps.length + ' record' + (apps.length !== 1 ? 's' : '');
  }
}

// ── Cell resolver ────────────────────────────────────────────
function _resolveCell(a, col, idx) {
  switch (col.key) {
    case 'sequence':    return idx + 1;
    case 'loanType':    return (typeof loanTypeLabel === 'function' ? loanTypeLabel(a.loanType) : _expLabel('loanType', a.loanType)) || '';
    case 'status':      return (window.STATUSES && window.STATUSES[a.status]) || a.status || '';
    case 'empType':     return _expLabel('empType',  a.empType);
    case 'gender':      return _expLabel('gender',   a.gender);
    case 'homeType':    return _expLabel('homeType',  a.homeType);
    case 'leadsrc':     return _expLabel('leadsrc',   a.leadsrc);
    case 'channel':     return _expLabel('channel',   a.channel);
    case 'compType':    return _expLabel('compType',  a.compType);
    case 'purpose':     return _expLabel('purpose',   a.purpose);
    case 'incred_offer':return _expLabel('incred_offer', a.incred_offer);
    case 'amount':      return Number(a.amount)      || 0;
    case 'salary':      return Number(a.salary)      || 0;
    case 'obligations': return Number(a.obligations) || 0;
    case 'cibil':       return Number(a.cibil)       || '';
    case 'loanRate':    return Number(a.loanRate)     || '';
    case 'tenure':      return Number(a.tenure)       || '';
    case 'document_checked': return a.document_checked ? 'Yes' : 'No';
    case 'incom_check':      return a.incom_check      ? 'Yes' : 'No';
    case 'bank_check':       return a.bank_check       ? 'Yes' : 'No';
    case 'ecs_return':       return a.ecs_return        ? 'Yes' : 'No';
    case 'final_report':     return a.final_report      ? 'Yes' : 'No';
    case '_docs': {
      const checks = ['document_checked','incom_check','bank_check','ecs_return','final_report'];
      const done = checks.filter(function(k) { return !!a[k]; }).length;
      return done + '/' + checks.length;
    }
    case '_foir': {
      const sal = Number(a.salary) || 0;
      const obl = Number(a.obligations) || 0;
      if (!sal) return '';
      const rate = Number(a.loanRate) || 12;
      const months = Number(a.tenure) || 36;
      const r = rate / 12 / 100;
      const emi = sal > 0 && months > 0 ? Math.round(Number(a.amount) * r * Math.pow(1+r, months) / (Math.pow(1+r, months) - 1)) : 0;
      return Math.round(((emi + obl) / sal) * 100);
    }
    case '_emi': {
      const rate = Number(a.loanRate) || 12;
      const months = Number(a.tenure) || 36;
      const r = rate / 12 / 100;
      const amt = Number(a.amount) || 0;
      if (!amt || !months || !r) return '';
      return Math.round(amt * r * Math.pow(1+r, months) / (Math.pow(1+r, months) - 1));
    }
    default: return a[col.key] !== undefined ? (a[col.key] === null ? '' : a[col.key]) : '';
  }
}

function getExportData() {
  const apps = _getExportApps();
  const activeCols = EXPORT_COLS.filter(function(c) { return c.checked; });
  const headers = activeCols.map(function(c) { return c.label; });
  const rows = apps.map(function(a, idx) { return activeCols.map(function(c) { return _resolveCell(a, c, idx); }); });
  return { headers, rows };
}

// ── Live preview ─────────────────────────────────────────────
function _renderExportPreview() {
  const wrap = document.getElementById('export-preview-wrap');
  if (!wrap) return;
  const apps = _getExportApps().slice(0, 3);
  const activeCols = EXPORT_COLS.filter(function(c) { return c.checked; });
  if (!activeCols.length || !apps.length) {
    wrap.innerHTML = '<div style="padding:16px;text-align:center;color:var(--text3);font-size:12px">' + (!activeCols.length ? 'No columns selected' : 'No data matches current scope') + '</div>';
    return;
  }
  const th = activeCols.map(function(c) {
    return '<th style="padding:5px 10px;white-space:nowrap;background:var(--accent);color:#fff;font-size:10.5px;font-weight:700;text-align:left">' + c.label + '</th>';
  }).join('');
  const trs = apps.map(function(a, idx) {
    const cells = activeCols.map(function(c) {
      const v = _resolveCell(a, c, idx);
      return '<td style="padding:4px 10px;white-space:nowrap;font-size:11px;border-bottom:1px solid var(--border);max-width:140px;overflow:hidden;text-overflow:ellipsis">' + (v === '' || v === null || v === undefined ? '<span style="color:var(--text3)">—</span>' : v) + '</td>';
    }).join('');
    return '<tr>' + cells + '</tr>';
  }).join('');
  wrap.innerHTML = '<table style="border-collapse:collapse;width:100%"><thead><tr>' + th + '</tr></thead><tbody>' + trs + '</tbody></table>';
}

// ── Modal open ───────────────────────────────────────────────
function openExportModal() {
  renderExportColList();
  _exportScope = 'filtered';
  document.querySelectorAll('.af-date-chip[data-scope]').forEach(function(b) { b.classList.remove('active'); });
  const defBtn = document.getElementById('export-scope-filtered');
  if (defBtn) defBtn.classList.add('active');
  const cPanel = document.getElementById('export-custom-filters');
  if (cPanel) cPanel.style.display = 'none';

  document.querySelectorAll('.export-fmt-btn').forEach(function(btn) {
    const inp = btn.querySelector('input[type=radio]');
    btn.classList.toggle('selected', !!(inp && inp.checked));
    btn.onclick = function() {
      document.querySelectorAll('.export-fmt-btn').forEach(function(b) { b.classList.remove('selected'); });
      btn.classList.add('selected');
      const i = btn.querySelector('input[type=radio]'); if (i) i.checked = true;
    };
  });
  _renderPresetSelect();
  _updateExportCounts();
  _renderExportPreview();
  openModal('modal-export');
}

// ── Column list renderer ─────────────────────────────────────
function renderExportColList() {
  const list = document.getElementById('export-col-list');
  if (!list) return;
  const groups = { basic:'Core', kyc:'KYC & Identity', financial:'Financial & Employment', address:'Address', source:'Source & Tracking', docs:'Document Checks', refs:'References' };
  const grouped = {};
  EXPORT_COLS.forEach(function(col, i) {
    const g = col.group || 'basic';
    if (!grouped[g]) grouped[g] = [];
    grouped[g].push({ col, i });
  });
  let html = '';
  Object.keys(groups).forEach(function(gKey) {
    if (!grouped[gKey] || !grouped[gKey].length) return;
    const gChecked = grouped[gKey].every(function(item) { return item.col.checked; });
    html += '<div style="padding:5px 14px 5px 10px;font-size:9.5px;font-weight:800;text-transform:uppercase;letter-spacing:1.2px;color:var(--accent);background:var(--surface2);border-bottom:1px solid var(--border);display:flex;align-items:center;gap:8px">' +
      '<input type="checkbox" ' + (gChecked ? 'checked' : '') + ' title="Toggle group" style="accent-color:var(--accent);cursor:pointer" onchange="exportToggleGroup(\'' + gKey + '\',this.checked)">' +
      groups[gKey] + '</div>';
    grouped[gKey].forEach(function(item) {
      const col = item.col, i = item.i;
      html += '<div class="export-col-item" draggable="true" data-idx="' + i + '"' +
        ' ondragstart="exportDragStart(event,' + i + ')"' +
        ' ondragover="exportDragOver(event,' + i + ')"' +
        ' ondrop="exportDrop(event,' + i + ')"' +
        ' ondragend="exportDragEnd(event)">' +
        '<span class="export-col-drag" title="Drag to reorder" style="cursor:grab;color:var(--text3);font-size:13px;margin-right:2px">⠿</span>' +
        '<input class="export-col-cb" type="checkbox" id="excol-' + i + '" ' + (col.checked ? 'checked' : '') + ' onchange="EXPORT_COLS[' + i + '].checked=this.checked;_updateExportCounts();_renderExportPreview()">' +
        '<label class="export-col-label" for="excol-' + i + '" style="cursor:pointer;flex:1">' + col.label + '</label>' +
        '</div>';
    });
  });
  list.innerHTML = html;
}

function exportToggleGroup(gKey, state) {
  EXPORT_COLS.forEach(function(c) { if (c.group === gKey) c.checked = state; });
  renderExportColList();
  _updateExportCounts();
  _renderExportPreview();
}

function exportToggleAll(state) {
  EXPORT_COLS.forEach(function(c) { c.checked = state; });
  renderExportColList();
  _updateExportCounts();
  _renderExportPreview();
}

function exportDragStart(e, idx) { _exportDragSrc = idx; e.dataTransfer.effectAllowed = 'move'; e.currentTarget.classList.add('dragging'); }
function exportDragOver(e, idx) { e.preventDefault(); e.dataTransfer.dropEffect = 'move'; document.querySelectorAll('.export-col-item').forEach(function(el, i) { el.classList.toggle('drag-over', i === idx && idx !== _exportDragSrc); }); }
function exportDrop(e, idx) { e.preventDefault(); if (_exportDragSrc === null || _exportDragSrc === idx) return; const moved = EXPORT_COLS.splice(_exportDragSrc, 1)[0]; EXPORT_COLS.splice(idx, 0, moved); renderExportColList(); _updateExportCounts(); _renderExportPreview(); }
function exportDragEnd(e) { document.querySelectorAll('.export-col-item').forEach(function(el) { el.classList.remove('dragging','drag-over'); }); _exportDragSrc = null; }

// ── Main download dispatcher ─────────────────────────────────
function doExport() {
  const fmt = (document.querySelector('input[name="export-fmt"]:checked') || {}).value || 'xlsx';
  const { headers, rows } = getExportData();
  if (!rows.length) { showToast('No data to export with current scope/filters', 'warn'); return; }

  const btn = document.getElementById('export-download-btn');
  if (btn) { btn.disabled = true; btn.innerHTML = '⏳ Preparing…'; }
  const restore = function() {
    if (btn) { btn.disabled = false; btn.innerHTML = '<svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.2"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg> Download'; }
  };

  if (fmt === 'csv') {
    exportCSV(headers, rows);
    closeModal('modal-export');
    showToast('CSV downloaded (' + rows.length + ' rows) ✓', 'success');
    restore();
  } else if (fmt === 'pdf') {
    closeModal('modal-export');
    exportPDF(headers, rows);
    restore();
  } else {
    closeModal('modal-export');
    showToast('Preparing XLSX (' + rows.length + ' rows)…', 'info');
    exportXLSX(headers, rows, restore);
  }
}

// ── CSV export ───────────────────────────────────────────────
function exportCSV(headers, rows) {
  const BOM = '\uFEFF';
  const esc = function(v) { return '"' + String(v == null ? '' : v).replace(/"/g, '""') + '"'; };
  const csv = BOM + [headers.map(esc).join(','), ...rows.map(function(r) { return r.map(esc).join(','); })].join('\r\n');
  const now = new Date();
  const stamp = now.getFullYear() + ('0'+(now.getMonth()+1)).slice(-2) + ('0'+now.getDate()).slice(-2);
  downloadBlob(new Blob([csv], { type: 'text/csv;charset=utf-8;' }), 'efin_export_' + stamp + '.csv');
}

// ── PDF export (browser print) ───────────────────────────────
function exportPDF(headers, rows) {
  const now = new Date();
  const stamp = now.toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' });
  const brand = _lsGet('efin_brand_name') || 'EFIN';

  // Build compact table, max 12 cols wide
  const displayCols = headers.length > 12 ? headers.slice(0, 12) : headers;
  const displayRows = rows.map(function(r) { return r.slice(0, displayCols.length); });

  const thHtml = displayCols.map(function(h) { return '<th>' + h + '</th>'; }).join('');
  const trHtml = displayRows.map(function(r) {
    return '<tr>' + r.map(function(v) { return '<td>' + (v == null || v === '' ? '—' : v) + '</td>'; }).join('') + '</tr>';
  }).join('');

  const html = `<!DOCTYPE html><html><head><meta charset="UTF-8">
<title>${brand} — Application Export ${stamp}</title>
<style>
  @page { size: A4 landscape; margin: 12mm; }
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: Arial, Helvetica, sans-serif; font-size: 9pt; color: #111; }
  .hdr { display:flex; justify-content:space-between; align-items:flex-end; padding-bottom: 8px; border-bottom: 2px solid #1a4fa3; margin-bottom: 10px; }
  .hdr-title { font-size: 15pt; font-weight: 800; color: #1a4fa3; }
  .hdr-meta { font-size: 8pt; color: #555; text-align:right; line-height:1.5; }
  table { width: 100%; border-collapse: collapse; font-size: 8pt; }
  thead tr { background: #1a4fa3; color: #fff; }
  thead th { padding: 5px 6px; text-align: left; font-weight: 700; white-space: nowrap; }
  tbody tr:nth-child(even) { background: #f0f4ff; }
  tbody td { padding: 4px 6px; border-bottom: 1px solid #dde3f0; vertical-align: top; }
  .footer { margin-top: 10px; font-size: 7.5pt; color: #888; text-align: right; }
  ${headers.length > 12 ? '.truncate-note { color:#c0392b; font-size:8pt; margin-bottom:6px; }' : ''}
</style></head><body>
<div class="hdr">
  <div><div class="hdr-title">${brand} — Application Export</div>
    <div style="font-size:9pt;color:#444;margin-top:2px">${rows.length} record${rows.length !== 1 ? 's' : ''} · Generated ${stamp}</div>
  </div>
  <div class="hdr-meta">Exported by: ${(window.currentUser && window.currentUser.name) || '—'}<br>${new Date().toLocaleTimeString('en-IN')}</div>
</div>
${headers.length > 12 ? '<div class="truncate-note">⚠ PDF shows first 12 columns. Use XLSX or CSV for all ' + headers.length + ' columns.</div>' : ''}
<table><thead><tr>${thHtml}</tr></thead><tbody>${trHtml}</tbody></table>
<div class="footer">EFIN Loan Management System — Confidential</div>
</body></html>`;

  const win = window.open('', '_blank');
  if (!win) { showToast('Popup blocked — allow popups for PDF export', 'warn'); return; }
  win.document.write(html);
  win.document.close();
  win.focus();
  setTimeout(function() { win.print(); }, 500);
  showToast('PDF print dialog opened (' + rows.length + ' rows)', 'success');
}
function exportXLSX(headers, rows, onDone) {
  const doZip = function() {
    const xmlEsc = function(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); };

    // Shared string table
    let sharedStrings = [];
    const strIdx = function(s) {
      const str = String(s == null ? '' : s);
      let i = sharedStrings.indexOf(str);
      if (i === -1) { i = sharedStrings.length; sharedStrings.push(str); }
      return i;
    };

    // Column letter(s) from 0-based index: 0→A, 25→Z, 26→AA
    const col26 = function(n) {
      let s = ''; n = n + 1;
      while (n > 0) { n--; s = String.fromCharCode(65 + (n % 26)) + s; n = Math.floor(n / 26); }
      return s;
    };

    // Styles XML — correct namespace
    const STYLE_XML =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">' +
        '<fonts count="2">' +
          '<font><sz val="11"/><name val="Calibri"/></font>' +
          '<font><sz val="11"/><b/><color rgb="FFFFFFFF"/><name val="Calibri"/></font>' +
        '</fonts>' +
        '<fills count="3">' +
          '<fill><patternFill patternType="none"/></fill>' +
          '<fill><patternFill patternType="gray125"/></fill>' +
          '<fill><patternFill patternType="solid"><fgColor rgb="FF1A4FA3"/><bgColor indexed="64"/></patternFill></fill>' +
        '</fills>' +
        '<borders count="1"><border><left/><right/><top/><bottom/><diagonal/></border></borders>' +
        '<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>' +
        '<cellXfs count="3">' +
          '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0"/>' +
          '<xf numFmtId="0" fontId="1" fillId="2" borderId="0" xfId="0" applyFont="1" applyFill="1"/>' +
          '<xf numFmtId="0" fontId="0" fillId="0" borderId="0" xfId="0" applyNumberFormat="1"/>' +
        '</cellXfs>' +
        '<cellStyles count="1"><cellStyle name="Normal" xfId="0" builtinId="0"/></cellStyles>' +
      '</styleSheet>';

    const allRows = [headers, ...rows];
    const lastCol = col26(headers.length - 1);
    const lastRow = allRows.length;

    let sheetXml =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" ' +
               'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">' +
        '<sheetViews><sheetView workbookViewId="0"><selection activeCell="A2" sqref="A2"/></sheetView></sheetViews>' +
        '<sheetFormatPr defaultRowHeight="15" customHeight="1"/>' +
        '<sheetData>';

    allRows.forEach(function(row, ri) {
      const isHeader = ri === 0;
      sheetXml += '<row r="' + (ri + 1) + '"' + (isHeader ? ' ht="18" customHeight="1"' : '') + '>';
      row.forEach(function(cell, ci) {
        const addr = col26(ci) + (ri + 1);
        const sAttr = isHeader ? ' s="1"' : '';
        // Use numeric type for numbers, shared string for everything else
        const raw = cell == null ? '' : cell;
        if (!isHeader && typeof raw === 'number' && isFinite(raw)) {
          sheetXml += '<c r="' + addr + '"' + sAttr + '><v>' + raw + '</v></c>';
        } else {
          sheetXml += '<c r="' + addr + '" t="s"' + sAttr + '><v>' + strIdx(String(raw)) + '</v></c>';
        }
      });
      sheetXml += '</row>';
    });

    sheetXml +=
      '</sheetData>' +
      '<autoFilter ref="A1:' + lastCol + '1"/>' +
      '<pageMargins left="0.7" right="0.7" top="0.75" bottom="0.75" header="0.3" footer="0.3"/>' +
      '</worksheet>';

    // Shared strings XML — correct namespace
    const ssXml =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<sst xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" ' +
           'count="' + sharedStrings.length + '" uniqueCount="' + sharedStrings.length + '">' +
      sharedStrings.map(function(s) {
        return '<si><t xml:space="preserve">' + xmlEsc(s) + '</t></si>';
      }).join('') +
      '</sst>';

    // Workbook XML — correct namespace
    const wbXml =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" ' +
               'xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">' +
        '<fileVersion appName="xl" lastEdited="5" lowestEdited="5" rupBuild="9303"/>' +
        '<workbookPr defaultThemeVersion="124226"/>' +
        '<sheets><sheet name="Applications" sheetId="1" r:id="rId1"/></sheets>' +
        '<calcPr calcId="144525"/>' +
      '</workbook>';

    // Relationships — workbook.xml.rels
    const relsXml =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
        '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet1.xml"/>' +
        '<Relationship Id="rId2" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/sharedStrings" Target="sharedStrings.xml"/>' +
        '<Relationship Id="rId3" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>' +
      '</Relationships>';

    // Root _rels/.rels
    const appRels =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">' +
        '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>' +
      '</Relationships>';

    // Content types
    const contentTypes =
      '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>' +
      '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">' +
        '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>' +
        '<Default Extension="xml" ContentType="application/xml"/>' +
        '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>' +
        '<Override PartName="/xl/worksheets/sheet1.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>' +
        '<Override PartName="/xl/sharedStrings.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sharedStrings+xml"/>' +
        '<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>' +
      '</Types>';

    const zip = new JSZip();
    zip.file('[Content_Types].xml', contentTypes);
    zip.folder('_rels').file('.rels', appRels);
    const xl = zip.folder('xl');
    xl.file('workbook.xml', wbXml);
    xl.file('sharedStrings.xml', ssXml);
    xl.file('styles.xml', STYLE_XML);
    xl.folder('_rels').file('workbook.xml.rels', relsXml);
    xl.folder('worksheets').file('sheet1.xml', sheetXml);

    const now = new Date();
    const stamp = now.getFullYear() + ('0'+(now.getMonth()+1)).slice(-2) + ('0'+now.getDate()).slice(-2);
    zip.generateAsync({
      type: 'blob',
      mimeType: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      compression: 'DEFLATE',
      compressionOptions: { level: 6 }
    })
    .then(function(blob) {
      downloadBlob(blob, 'efin_export_' + stamp + '.xlsx');
      showToast('XLSX downloaded (' + rows.length + ' rows) ✓', 'success');
      if (onDone) onDone();
    })
    .catch(function(e) {
      exportCSV(headers, rows);
      showToast('XLSX failed — downloaded as CSV instead', 'warn');
      if (onDone) onDone();
    });
  };

  if (typeof JSZip !== 'undefined') {
    doZip();
  } else {
    const s = document.createElement('script');
    s.src = 'https://cdnjs.cloudflare.com/ajax/libs/jszip/3.10.1/jszip.min.js';
    s.onload  = doZip;
    s.onerror = function() { exportCSV(headers, rows); showToast('XLSX unavailable — downloaded as CSV', 'warn'); if (onDone) onDone(); };
    document.head.appendChild(s);
  }
}

function downloadBlob(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url; a.download = filename; a.style.display = 'none';
  document.body.appendChild(a); a.click();
  setTimeout(() => { document.body.removeChild(a); URL.revokeObjectURL(url); }, 1500);
}

// ══════════════════════════════════════════════════════════════════
//  EFIN COMPREHENSIVE EMAIL ENGINE
//  All email types centralised here. Every function uses sysmailSend
//  so it automatically routes via Gmail (EmailJS) or Brevo based on
//  whatever the admin has configured in Settings → Mail Configuration.
// ══════════════════════════════════════════════════════════════════

// ── Shared HTML email wrapper ──
function _emailWrap(accentColor, headerTitle, headerSub, bodyHtml, footerRef) {
  return `
<div style="font-family:Arial,Helvetica,sans-serif;background:#f0f4ff;padding:28px 12px;margin:0">
<table role="presentation" cellpadding="0" cellspacing="0" border="0" align="center" width="100%" style="max-width:580px;margin:0 auto;border-collapse:collapse">
  <!-- Header -->
  <tr><td style="background:${accentColor};padding:20px 28px 18px;border-radius:14px 14px 0 0;text-align:center">
    <div style="color:#fff;font-size:24px;font-weight:900;letter-spacing:-1px;font-family:Arial,sans-serif">EFIN</div>
    <div style="color:rgba(255,255,255,.75);font-size:10.5px;letter-spacing:2.5px;text-transform:uppercase;margin-top:2px">Loan Management System</div>
    ${headerTitle ? `<div style="color:#fff;font-size:15px;font-weight:700;margin-top:12px;padding-top:12px;border-top:1px solid rgba(255,255,255,.2)">${headerTitle}</div>` : ''}
    ${headerSub   ? `<div style="color:rgba(255,255,255,.8);font-size:12px;margin-top:4px">${headerSub}</div>` : ''}
  </td></tr>
  <!-- Body -->
  <tr><td style="background:#ffffff;padding:28px;border:1px solid #dde3f0;border-top:none">
    ${bodyHtml}
  </td></tr>
  <!-- Footer -->
  <tr><td style="background:#f8faff;padding:14px 28px 18px;border:1px solid #dde3f0;border-top:none;border-radius:0 0 14px 14px;text-align:center">
    <div style="font-size:11px;color:#a0aec0;line-height:1.6">
      This is an automated message from the EFIN Loan Management System.<br>
      ${footerRef ? `Ref: <strong>${footerRef}</strong> · ` : ''}${new Date().toLocaleDateString('en-IN', { day:'2-digit', month:'short', year:'numeric' })}
    </div>
  </td></tr>
</table></div>`;
}

// ── Info box helper ──
function _infoBox(rows, accentColor) {
  return `<div style="background:#f0f4ff;border:1px solid #dde3f0;border-radius:10px;padding:16px 20px;margin:16px 0">
    ${rows.map(([l,v]) => `<div style="font-size:13px;color:#0c1733;margin-bottom:7px"><span style="color:#7a8aaa;min-width:160px;display:inline-block">${l}:</span> <strong>${v}</strong></div>`).join('')}
  </div>`;
}

// ─────────────────────────────────────────────────────────────────
//  1. USER INVITATION EMAIL
//     Sent automatically when admin creates a new user.
// ─────────────────────────────────────────────────────────────────
// SECURITY FIX: accept plainTextPwd explicitly so we never read the already-masked user._password.
async function sendInvitationEmail(user, plainTextPwd) {
  const cfg = sysmailGetConfig();
  if (cfg.invEnabled === false || !cfg.fromEmail) return;

  // user._password is '***' in storage by this point; use the explicitly passed value.
  const pwd = plainTextPwd || '(set by admin — please contact your admin for credentials)';
  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">👋 Welcome to EFIN!</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Hi <strong>${user.name}</strong>, your account has been created on the EFIN Loan Management System.
      Use the credentials below to log in for the first time.
    </div>
    ${_infoBox([['Login Email', user.email || '—'], ['Temporary Password', pwd], ['Your User ID', user.uid || '—'], ['Role', user.role || '—']], '#1a4fa3')}
    <div style="margin:18px 0;padding:12px 16px;background:#fff8e1;border-left:4px solid #f0a000;border-radius:4px;font-size:12.5px;color:#6b4e00">
      <strong>⚠️ Action required:</strong> Please log in and change your password immediately for security.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#1a4fa3', '🎉 You\'ve been invited', 'Your account is ready', body, user.uid);
  const subject = cfg.invSubject || `You've been invited to EFIN — ${user.name}`;

  try {
    await sysmailSend({ to: user.email, toName: user.name, subject, html });
    showToast('Invitation email sent to ' + user.email + ' ✓', 'success');
  } catch(e) {
    showToast('Invitation email failed: ' + e.message, 'warn');
    console.warn('[EFIN Email: Invitation]', e);
  }
}

// ─────────────────────────────────────────────────────────────────
//  2. PASSWORD RESET EMAIL
//     Sent when admin resets a user's password.
// ─────────────────────────────────────────────────────────────────
async function sendPasswordResetEmail(user, newPassword) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !user.email) return;

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">🔐 Your Password Has Been Reset</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Hi <strong>${user.name}</strong>, your EFIN account password has been reset by the administrator. Use the new credentials below to log in.
    </div>
    ${_infoBox([['Login Email', user.email], ['New Password', newPassword], ['User ID', user.uid || '—']], '#d42b2b')}
    <div style="margin:18px 0;padding:12px 16px;background:#fff8e1;border-left:4px solid #f0a000;border-radius:4px;font-size:12.5px;color:#6b4e00">
      <strong>⚠️ Security notice:</strong> Please log in immediately and change this password. Do not share it with anyone.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#d42b2b', '🔐 Password Reset', 'Action required', body, user.uid);
  try {
    await sysmailSend({ to: user.email, toName: user.name, subject: 'EFIN — Your Password Has Been Reset', html });
    showToast('Password reset email sent to ' + user.email + ' ✓', 'success');
  } catch(e) {
    showToast('Password reset email failed: ' + e.message, 'warn');
    console.warn('[EFIN Email: Password Reset]', e);
  }
}

// ─────────────────────────────────────────────────────────────────
//  3. LOAN APPROVAL EMAIL
//     Sent to applicant when status moves to 'approved'.
// ─────────────────────────────────────────────────────────────────
async function sendLoanApprovalEmail(app) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !app.email) return;
  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
  const loanType = typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : 'Loan';

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">🎉 Congratulations! Your Loan Has Been Approved</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Dear <strong>${app.name}</strong>, we are delighted to inform you that your ${loanType} application has been <strong style="color:#1a7340">approved</strong>.
    </div>
    ${_infoBox([
      ['Application ID',    app.id],
      ['Loan Type',         loanType],
      ['Sanctioned Amount', fmt(app.sanctionLoanAmt || app.amount)],
      ['Rate of Interest',  app.sanctionROI ? app.sanctionROI + '% p.a.' : (app.loanRate ? app.loanRate + '% p.a.' : '—')],
      ['Applicant',         app.name],
    ], '#1a7340')}
    <div style="margin:16px 0;padding:14px 18px;background:rgba(26,115,64,.06);border:1px solid rgba(26,115,64,.2);border-radius:10px;font-size:13px;color:#1a7340;font-weight:600">
      ✅ Your loan is approved. Our team will contact you shortly with disbursement details.
    </div>
    <div style="font-size:12.5px;color:#7a8aaa;line-height:1.6">
      Please keep your KYC documents handy. If you have any questions, please contact your assigned relationship manager.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#1a7340', '✅ Loan Approved', app.id, body, app.id);
  try {
    await sysmailSend({ to: app.email, toName: app.name, subject: `EFIN — Loan Approved · ${app.id} · ${app.name}`, html });
  } catch(e) { console.warn('[EFIN Email: Approval]', e); }
}

// ─────────────────────────────────────────────────────────────────
//  4. LOAN DISBURSEMENT EMAIL
//     Sent to applicant when status moves to 'disbursed'.
// ─────────────────────────────────────────────────────────────────
async function sendLoanDisbursementEmail(app) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !app.email) return;
  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
  const loanType = typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : 'Loan';

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">🏦 Your Loan Has Been Disbursed</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Dear <strong>${app.name}</strong>, your ${loanType} has been successfully <strong style="color:#1a4fa3">disbursed</strong> to your registered bank account.
    </div>
    ${_infoBox([
      ['Application ID',     app.id],
      ['Loan Type',          loanType],
      ['Disbursed Amount',   fmt(app.sanctionLoanAmt || app.amount)],
      ['EMI',                fmt(app.emi) || '—'],
      ['First EMI Date',     app.emiDate ? app.emiDate + ' of next month' : '—'],
    ], '#1a4fa3')}
    <div style="margin:16px 0;padding:14px 18px;background:rgba(26,79,163,.05);border:1px solid rgba(26,79,163,.15);border-radius:10px;font-size:13px;color:#1a4fa3;font-weight:600">
      💳 Please ensure sufficient balance in your account before each EMI date.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#1a4fa3', '🏦 Loan Disbursed', app.id, body, app.id);
  try {
    await sysmailSend({ to: app.email, toName: app.name, subject: `EFIN — Loan Disbursed · ${app.id} · ${app.name}`, html });
  } catch(e) { console.warn('[EFIN Email: Disbursement]', e); }
}

// ─────────────────────────────────────────────────────────────────
//  5. LOAN REJECTION EMAIL
//     Sent to applicant when status moves to 'rejected'.
// ─────────────────────────────────────────────────────────────────
async function sendLoanRejectionEmail(app, reason) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !app.email) return;
  const loanType = typeof loanTypeLabel === 'function' ? loanTypeLabel(app.loanType) : 'Loan';

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">📋 Update on Your Loan Application</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Dear <strong>${app.name}</strong>, after careful review, we regret to inform you that your ${loanType} application (Ref: <strong>${app.id}</strong>) could not be approved at this time.
    </div>
    ${_infoBox([
      ['Application ID', app.id],
      ['Loan Type',      loanType],
      ['Decision',       'Not Approved'],
      ...(reason ? [['Reason', reason]] : []),
    ], '#c0392b')}
    <div style="margin:16px 0;font-size:13px;color:#3a4d6e;line-height:1.7">
      This decision does not prevent you from reapplying in the future. You may reapply after addressing the factors mentioned above. If you have questions, please contact your relationship manager.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#c0392b', '📋 Application Update', app.id, body, app.id);
  try {
    await sysmailSend({ to: app.email, toName: app.name, subject: `EFIN — Application Update · ${app.id} · ${app.name}`, html });
  } catch(e) { console.warn('[EFIN Email: Rejection]', e); }
}

// ─────────────────────────────────────────────────────────────────
//  6. DOCUMENT REQUEST EMAIL
//     Sent when agent requests additional documents from applicant.
// ─────────────────────────────────────────────────────────────────
async function sendDocumentRequestEmail(app, docList, instructions) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !app.email) return;

  const docsHtml = Array.isArray(docList) && docList.length
    ? `<ul style="margin:10px 0 0;padding-left:20px">${docList.map(d => `<li style="font-size:13px;color:#0c1733;margin-bottom:5px">${d}</li>`).join('')}</ul>`
    : `<p style="font-size:13px;color:#3a4d6e">${instructions || 'Please contact your relationship manager for the full list.'}</p>`;

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">📎 Additional Documents Required</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Dear <strong>${app.name}</strong>, to continue processing your loan application (Ref: <strong>${app.id}</strong>), we need the following documents at your earliest convenience.
    </div>
    <div style="background:#f0f4ff;border:1px solid #dde3f0;border-radius:10px;padding:16px 20px;margin-bottom:16px">
      <div style="font-size:12px;font-weight:700;color:#1a4fa3;text-transform:uppercase;letter-spacing:.8px;margin-bottom:8px">Documents Required</div>
      ${docsHtml}
    </div>
    ${instructions ? `<div style="font-size:13px;color:#3a4d6e;line-height:1.7;margin-bottom:12px"><strong>Instructions:</strong> ${instructions}</div>` : ''}
    <div style="font-size:12.5px;color:#7a8aaa">Please submit all documents within <strong>3 working days</strong> to avoid delays in processing.</div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#e67e00', '📎 Documents Required', app.id, body, app.id);
  try {
    await sysmailSend({ to: app.email, toName: app.name, subject: `EFIN — Documents Required · ${app.id} · ${app.name}`, html });
    showToast('Document request email sent ✓', 'success');
  } catch(e) {
    showToast('Document request email failed: ' + e.message, 'warn');
    console.warn('[EFIN Email: Document Request]', e);
  }
}

// ─────────────────────────────────────────────────────────────────
//  7. EMI REMINDER EMAIL
//     Can be triggered manually by admin or on a schedule.
// ─────────────────────────────────────────────────────────────────
async function sendEmiReminderEmail(app, daysUntilDue) {
  const cfg = sysmailGetConfig();
  if (!cfg.fromEmail || !app.email) return;
  const fmt = v => v ? '₹' + Number(v).toLocaleString('en-IN') : '—';
  const daysText = daysUntilDue === 0 ? 'today' : daysUntilDue === 1 ? 'tomorrow' : `in ${daysUntilDue} days`;

  const body = `
    <div style="font-size:15px;font-weight:800;color:#0c1733;margin-bottom:8px">💳 EMI Payment Reminder</div>
    <div style="font-size:13.5px;color:#3a4d6e;line-height:1.7;margin-bottom:16px">
      Dear <strong>${app.name}</strong>, this is a friendly reminder that your EMI payment is due <strong>${daysText}</strong>.
    </div>
    ${_infoBox([
      ['Application ID',  app.id],
      ['EMI Amount',      fmt(app.emi)],
      ['Due Date',        app.nextEmiDate || app.emiDate ? (app.nextEmiDate || app.emiDate) + ' of this month' : '—'],
      ['Account',         app.bankName || '—'],
    ], '#e67e00')}
    <div style="margin:16px 0;padding:12px 16px;background:#fff8e1;border-left:4px solid #f0a000;border-radius:4px;font-size:12.5px;color:#6b4e00">
      <strong>Reminder:</strong> Please ensure sufficient balance in your linked account before the due date to avoid penalties.
    </div>
    ${cfg.signature ? `<div style="margin-top:20px;padding-top:16px;border-top:1px solid #dde3f0;font-size:12.5px;color:#5a7090;white-space:pre-line">${cfg.signature}</div>` : ''}`;

  const html = _emailWrap('#e67e00', '💳 EMI Reminder', daysUntilDue === 0 ? 'Due Today' : `Due ${daysText}`, body, app.id);
  try {
    await sysmailSend({ to: app.email, toName: app.name, subject: `EFIN — EMI Reminder · ${fmt(app.emi)} due ${daysText} · ${app.id}`, html });
    showToast('EMI reminder sent to ' + app.email + ' ✓', 'success');
  } catch(e) {
    showToast('EMI reminder failed: ' + e.message, 'warn');
    console.warn('[EFIN Email: EMI Reminder]', e);
  }
}

// ─────────────────────────────────────────────────────────────────
//  8. STAGE CHANGE EMAIL  (also defined inline above for the
//     real-time sendStageNotifications, duplicated here as a
//     standalone callable for manual triggers)
// ─────────────────────────────────────────────────────────────────
async function sendStageChangeEmail(app, newStatus) {
  const STATUSES_LOCAL = { wip:'WIP', login:'Assign Lender', underwriting:'Underwriting', approved:'Approved', disbursed:'Disbursed', rejected:'Rejected', hold:'On Hold', offer:'Offer',  acceptance:'Acceptance' };
  const stageName = STATUSES_LOCAL[newStatus] || newStatus;
  await _sendStageChangeEmail(app, newStatus, stageName);
  // Also trigger specific lifecycle emails
  if (newStatus === 'approved')  sendLoanApprovalEmail(app);
  if (newStatus === 'disbursed') sendLoanDisbursementEmail(app);
  if (newStatus === 'rejected')  sendLoanRejectionEmail(app);
}

// ─────────────────────────────────────────────────────────────────
//  WIRE INTO EXISTING HOOKS
//  Patch cpSavePassword to also send a password-reset email.
// ─────────────────────────────────────────────────────────────────
(function() {
  const _origCpSave = window.cpSavePassword;
  if (typeof _origCpSave !== 'function') return;
  window.cpSavePassword = function() {
    // SECURITY FIX: capture BOTH the target email AND the plaintext password BEFORE calling
    // the original function, which clears the input field and masks u._password to '***'.
    const targetEmail = window._cpTargetEmail;
    const newPwdCapture = document.getElementById('cp-new')?.value || '';
    _origCpSave.apply(this, arguments);
    // If admin reset someone else's password, send them a notification with the actual password
    if (targetEmail && newPwdCapture) {
      const tu = (typeof twUsers !== 'undefined' ? twUsers : []).find(u => u.email === targetEmail);
      if (tu) setTimeout(() => sendPasswordResetEmail(tu, newPwdCapture), 400);
    }
  };
})();

// Patch invSaveSetup to use the new sendInvitationEmail
(function() {
  const _origInvSave = window.invSaveSetup;
  if (typeof _origInvSave !== 'function') return;
  window.invSaveSetup = function() {
    _origInvSave.apply(this, arguments);
    // sendInvitationEmail is already called via sysmailSendInvitation inside invSaveSetup
    // This patch ensures the new consolidated function is also wired
  };
})();

// Wire stgSaveMailConfig to also sync back to sysmailSendInvitation
// (already done in stgSaveMailConfig via localStorage.setItem(SYSMAIL_KEY))


//  Admin-only. Accessible via sidebar nav → Settings
// ══════════════════════════════════════════════════════════════════

const STG_KEY     = 'efin_settings_v1';
const STG_TPL_KEY = 'efin_email_templates_v1';

// ── Provider card selection — toggles Gmail vs Brevo folders ──
function stgSelectProvider(provider) {
  const gmailRadio = document.getElementById('stg-provider-gmail');
  const brevoRadio = document.getElementById('stg-provider-brevo');
  if (gmailRadio) gmailRadio.checked = provider === 'gmail';
  if (brevoRadio) brevoRadio.checked = provider === 'brevo';

  // Highlight the selected card
  const gmailCard = document.getElementById('stg-provider-gmail-card');
  const brevoCard = document.getElementById('stg-provider-brevo-card');
  if (gmailCard) gmailCard.classList.toggle('selected', provider === 'gmail');
  if (brevoCard) brevoCard.classList.toggle('selected', provider === 'brevo');

  // Show/hide the relevant setup folder
  const gmailFolder = document.getElementById('folder-gmail');
  const brevoFolder = document.getElementById('folder-brevo');
  if (gmailFolder) {
    gmailFolder.style.display = provider === 'gmail' ? '' : 'none';
    if (provider === 'gmail' && !gmailFolder.classList.contains('open')) gmailFolder.classList.add('open');
  }
  if (brevoFolder) {
    brevoFolder.style.display = provider === 'brevo' ? '' : 'none';
    if (provider === 'brevo' && !brevoFolder.classList.contains('open')) brevoFolder.classList.add('open');
  }
}

// ══════════════════════════════════════════════════════════════════
//  SETTINGS PAGE v2 — Consolidated (Mail + Roles + System)
// ══════════════════════════════════════════════════════════════════

// ── Folder accordion toggle ──
function stgToggleFolder(id) {
  const folder = document.getElementById(id);
  if (!folder) return;
  folder.classList.toggle('open');
}

// ── Tab switching — now 3 tabs ──
function settingsSwitchTab(tab, el) {
  if (currentUser.role !== 'admin') { showToast('Settings are accessible to Admin only', 'error'); return; }
  document.querySelectorAll('#settings-tabs .tab').forEach(t => t.classList.remove('active'));
  if (el) el.classList.add('active');
  document.getElementById('settings-tab-mail').style.display      = tab === 'mail'     ? '' : 'none';
  document.getElementById('settings-tab-access').style.display    = tab === 'access'   ? '' : 'none';
  document.getElementById('settings-tab-system').style.display    = tab === 'system'   ? '' : 'none';
  document.getElementById('settings-tab-branding').style.display  = tab === 'branding' ? '' : 'none';

  if (tab === 'access') {
    if (typeof renderAccessRights === 'function') {
      try { renderAccessRights(); } catch(e) { console.warn('[settings access tab]', e); }
    }
    stgRenderAccessRights();
  }
  if (tab === 'system') {
    stgMirrorCam(); stgRenderWebhookLogs(); stgMirrorDropdowns();
    if (typeof renderAccessRights === 'function') { try { renderAccessRights(); } catch(e) { console.warn('[sys-tab]',e); } }
    if (typeof renderMasterToggleGrid === 'function') { try { renderMasterToggleGrid(); } catch(e) { console.warn('[sys-tab-mtg]',e); } }
  }
  if (tab === 'mail') { stgRenderAllTemplates(); if (typeof sysmailRenderPending === 'function') sysmailRenderPending(); }
  if (tab === 'branding') { brandingInitPanel(); }
}

