// ── Default template content (shown when no saved version exists) ──
const STG_TPL_DEFAULTS = {
  invitation: { subject:"You've been invited to EFIN — Set your password",          body:"Hi {{name}},\n\nYour account has been created on the EFIN Loan Management System.\n\nLogin Email: {{email}}\nTemporary Password: {{password}}\nUser ID: {{uid}}\nRole: {{role}}\n\nPlease log in and change your password immediately.\n\n{{signature}}" },
  pwreset:    { subject:'EFIN — Your Password Has Been Reset',                       body:"Hi {{name}},\n\nYour EFIN account password has been reset by the administrator.\n\nLogin Email: {{email}}\nNew Password: {{password}}\n\nPlease log in immediately and change this password.\n\n{{signature}}" },
  stage:      { subject:'EFIN Update: {{app_id}} {{name}} → {{stage}}',             body:"Dear {{name}},\n\nYour loan application (Ref: {{app_id}}) has moved to a new stage: {{stage}}.\n\nLoan Amount: {{amount}}\n\nPlease log in to EFIN for full details and next steps.\n\n{{signature}}" },
  approval:   { subject:'EFIN — Loan Approved · {{app_id}} · {{name}}',             body:"Dear {{name}},\n\nCongratulations! Your {{loan_type}} application (Ref: {{app_id}}) has been approved.\n\nSanctioned Amount: {{amount}}\nRate of Interest:  {{roi}}\n\nOur team will contact you shortly with disbursement details. Please keep your KYC documents ready.\n\n{{signature}}" },
  disburse:   { subject:'EFIN — Loan Disbursed · {{app_id}} · {{name}}',            body:"Dear {{name}},\n\nYour {{loan_type}} (Ref: {{app_id}}) has been successfully disbursed to your registered bank account.\n\nDisbursed Amount: {{amount}}\nMonthly EMI:      {{emi}}\nFirst EMI Date:   {{emi_date}}\n\nPlease ensure sufficient balance in your account before each EMI date.\n\n{{signature}}" },
  rejection:  { subject:'EFIN — Application Update · {{app_id}} · {{name}}',        body:"Dear {{name}},\n\nAfter careful review, we regret to inform you that your {{loan_type}} application (Ref: {{app_id}}) could not be approved at this time.\n\nReason: {{reason}}\n\nThis decision does not prevent you from reapplying in the future. Please contact your relationship manager if you have any questions.\n\n{{signature}}" },
  docs:       { subject:'EFIN — Documents Required · {{app_id}} · {{name}}',        body:"Dear {{name}},\n\nTo continue processing your loan application (Ref: {{app_id}}), we require the following documents:\n\n{{doc_list}}\n\nInstructions: {{instructions}}\n\nPlease submit all documents within 3 working days to avoid delays.\n\n{{signature}}" },
  emi:        { subject:'EFIN — EMI Reminder · {{emi_amount}} due {{due_date}}',     body:"Dear {{name}},\n\nThis is a friendly reminder that your EMI payment of {{emi_amount}} is due on {{due_date}}.\n\nApplication ID: {{app_id}}\nBank Account:   {{bank}}\n\nPlease ensure sufficient balance in your linked account before the due date to avoid penalties.\n\n{{signature}}" },
};

// ── Icon background per template key ──
function _tplIconBg(key) {
  return { invitation:'linear-gradient(135deg,#1a7340,#22c55e)', pwreset:'linear-gradient(135deg,#d42b2b,#e94040)', stage:'linear-gradient(135deg,#7c3aed,#a78bfa)', approval:'linear-gradient(135deg,#1a7340,#22c55e)', disburse:'linear-gradient(135deg,#1a4fa3,#2d68cc)', rejection:'linear-gradient(135deg,#c0392b,#e74c3c)', docs:'linear-gradient(135deg,#e67e00,#f59e0b)', emi:'linear-gradient(135deg,#e67e00,#ff6b35)', deal:'linear-gradient(135deg,#0a4d8c,#1a4fa3)' }[key] || 'var(--surface3)';
}

// ── Render all email template rows inside the Templates folder ──
function stgRenderAllTemplates() {
  const container = document.getElementById('stg-all-templates-body');
  if (!container) return;

  const defs = [
    { key:'invitation', icon:'🎉', title:'User Invitation',            sub:'Auto-sent when a new user is created · To: new user email',                       badge:'auto',   vars:'{{name}} {{email}} {{password}} {{uid}} {{role}} {{signature}}' },
    { key:'pwreset',    icon:'🔐', title:'Password Reset',             sub:'Sent when admin resets a user\'s password · To: affected user',                   badge:'admin',  vars:'{{name}} {{email}} {{password}} {{uid}} {{signature}}' },
    { key:'stage',      icon:'📋', title:'Stage Change Notification',  sub:'Sent on every status change · To: applicant + assigned user',                     badge:'auto',   vars:'{{name}} {{app_id}} {{stage}} {{amount}} {{signature}}' },
    { key:'approval',   icon:'✅', title:'Loan Approval',              sub:'Status moves to Approved · To: applicant',                                        badge:'auto',   vars:'{{name}} {{app_id}} {{loan_type}} {{amount}} {{roi}} {{signature}}' },
    { key:'disburse',   icon:'🏦', title:'Loan Disbursement',          sub:'Status moves to Disbursed · To: applicant',                                       badge:'auto',   vars:'{{name}} {{app_id}} {{loan_type}} {{amount}} {{emi}} {{emi_date}} {{signature}}' },
    { key:'rejection',  icon:'❌', title:'Loan Rejection',             sub:'Status moves to Rejected · To: applicant',                                        badge:'auto',   vars:'{{name}} {{app_id}} {{loan_type}} {{reason}} {{signature}}' },
    { key:'docs',       icon:'📎', title:'Document Request',           sub:'Manually triggered by your team · To: applicant',                                 badge:'manual', vars:'{{name}} {{app_id}} {{doc_list}} {{instructions}} {{signature}}' },
    { key:'emi',        icon:'💳', title:'EMI Payment Reminder',       sub:'Manual or scheduled trigger · To: applicant',                                     badge:'manual', vars:'{{name}} {{app_id}} {{emi_amount}} {{due_date}} {{bank}} {{signature}}' },
    { key:'deal',       icon:'📄', title:'Deal Confirmation',          sub:'Fully customisable inside the Deal Confirmation modal on each application',        badge:'modal',  vars:null },
  ];

  const badgeCss = {
    auto:   'stg-badge stg-badge-auto',
    admin:  'stg-badge stg-badge-admin',
    manual: 'stg-badge stg-badge-manual',
    modal:  'stg-badge',
  };
  const badgeTxt = { auto:'AUTO', admin:'ADMIN TRIGGER', manual:'MANUAL', modal:'IN MODAL' };
  const badgeInlineStyle = { modal:'background:var(--surface3);color:var(--text3);border:1px solid var(--border)' };

  let saved = {};
  try { saved = JSON.parse(localStorage.getItem(STG_TPL_KEY) || '{}'); } catch(e) {}

  container.innerHTML = defs.map(t => {
    const sv      = saved[t.key] || {};
    const dflt    = STG_TPL_DEFAULTS[t.key] || {};
    const subject = sv.subject || dflt.subject || '';
    const tBody   = sv.body    || dflt.body    || '';
    const isModal = t.key === 'deal';
    const bClass  = badgeCss[t.badge] || 'stg-badge';
    const bStyle  = badgeInlineStyle[t.badge] ? ` style="${badgeInlineStyle[t.badge]}"` : '';
    const bLabel  = badgeTxt[t.badge] || t.badge.toUpperCase();
    const esc     = s => s.replace(/&/g,'&amp;').replace(/"/g,'&quot;');
    const escHtml = s => s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');

    return `
    <div style="border:1.5px solid var(--border);border-radius:13px;overflow:hidden;margin-bottom:10px;transition:box-shadow .18s"
         onmouseenter="this.style.boxShadow='var(--shadow)'" onmouseleave="this.style.boxShadow='none'">

      <!-- Row header (click to expand) -->
      <div style="display:flex;align-items:center;gap:13px;padding:14px 18px;background:var(--surface2);cursor:${isModal?'default':'pointer'};user-select:none"
           ${isModal ? '' : `onclick="stgToggleTplRow('tpl-row-${t.key}','tpl-chev-${t.key}')"`}>
        <div style="width:36px;height:36px;border-radius:9px;background:${_tplIconBg(t.key)};display:flex;align-items:center;justify-content:center;font-size:17px;flex-shrink:0">${t.icon}</div>
        <div style="flex:1;min-width:0">
          <div style="font-weight:700;font-size:13.5px;color:var(--text)">${t.title}</div>
          <div style="font-size:11.5px;color:var(--text3);margin-top:2px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${t.sub}</div>
        </div>
        <span class="${bClass}"${bStyle}>${bLabel}</span>
        ${isModal ? '' : `<span id="tpl-chev-${t.key}" style="color:var(--text3);font-size:13px;margin-left:8px;flex-shrink:0">▾</span>`}
      </div>

      <!-- Row body (edit area) -->
      ${isModal
        ? `<div style="padding:13px 18px;font-size:12.5px;color:var(--text3);background:var(--surface);border-top:1px solid var(--border)">
             The Deal Confirmation email is fully customisable within the <strong style="color:var(--text2)">Deal Confirmation modal</strong> on each individual application. Open any application → click <strong style="color:var(--text2)">📄 Deal Confirmation</strong>.
           </div>`
        : `<div id="tpl-row-${t.key}" style="display:none;padding:20px;background:var(--surface);border-top:1px solid var(--border)">
             <div class="form-group">
               <label style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.7px;color:var(--text3)">Subject Line</label>
               <input type="text" id="stg-tpl-${t.key}-subject" class="form-control" value="${esc(subject)}">
             </div>
             <div class="form-group">
               <label style="font-size:11px;font-weight:800;text-transform:uppercase;letter-spacing:.7px;color:var(--text3)">Message Body</label>
               <textarea id="stg-tpl-${t.key}-body" class="form-control" rows="7" style="resize:vertical;font-size:12.5px;font-family:monospace;line-height:1.65">${escHtml(tBody)}</textarea>
               ${t.vars ? `<div style="font-size:11px;color:var(--text3);margin-top:5px;line-height:1.8">
                 <strong>Variables:</strong> ${t.vars.split(' ').map(v=>`<code style="background:var(--surface2);border:1px solid var(--border);padding:1px 5px;border-radius:4px;font-size:10.5px">${v}</code>`).join(' ')}
               </div>` : ''}
             </div>
             <div style="display:flex;gap:10px;align-items:center;padding-top:4px">
               <button class="btn btn-primary btn-sm" onclick="stgSaveTpl('${t.key}')">💾 Save Template</button>
               <button class="btn btn-ghost btn-sm"   onclick="stgResetTpl('${t.key}')">↺ Reset to Default</button>
               <span id="stg-tpl-${t.key}-saved" style="display:none;font-size:12px;color:var(--success);font-weight:600">✓ Template saved</span>
             </div>
           </div>`
      }
    </div>`;
  }).join('') + `<div style="margin-top:14px;padding:13px 18px;background:var(--surface2);border:1px solid var(--border);border-radius:12px;font-size:12px;color:var(--text3);line-height:1.7">
    💡 <strong>AUTO</strong> templates fire automatically on the matching event. <strong>MANUAL</strong> templates are triggered by your team. <strong>ADMIN TRIGGER</strong> templates fire when an Admin performs that action. All emails use the sender identity configured above.
  </div>`;
}

// ── Toggle a template row open/closed ──
function stgToggleTplRow(rowId, chevId) {
  const row  = document.getElementById(rowId);
  const chev = document.getElementById(chevId);
  if (!row) return;
  const open = row.style.display !== 'none';
  row.style.display = open ? 'none' : '';
  if (chev) chev.textContent = open ? '▾' : '▴';
}

// ── Save a template ──
function stgSaveTpl(key) {
  const subjectEl = document.getElementById('stg-tpl-' + key + '-subject');
  const bodyEl    = document.getElementById('stg-tpl-' + key + '-body');
  if (!subjectEl || !bodyEl) return;
  let templates = {};
  try { templates = JSON.parse(localStorage.getItem(STG_TPL_KEY) || '{}'); } catch(e) {}
  templates[key] = { subject: subjectEl.value, body: bodyEl.value };
  _lsSet(STG_TPL_KEY, JSON.stringify(templates));
  const saved = document.getElementById('stg-tpl-' + key + '-saved');
  if (saved) { saved.style.display = 'inline'; setTimeout(() => saved.style.display = 'none', 2500); }
  showToast('Template saved ✓', 'success');
  // Sync invitation template to mail config if needed
  if (key === 'invitation') {
    const cfg = sysmailGetConfig ? sysmailGetConfig() : {};
    cfg.invSubject = subjectEl.value;
    cfg.invBody    = bodyEl.value;
    try { localStorage.setItem(SYSMAIL_KEY, JSON.stringify(cfg)); localStorage.setItem(STG_KEY, JSON.stringify(cfg)); } catch(e) {}
  }
}

// ── Reset a template to its default ──
function stgResetTpl(key) {
  const dflt = STG_TPL_DEFAULTS[key];
  if (!dflt) return;
  const subjectEl = document.getElementById('stg-tpl-' + key + '-subject');
  const bodyEl    = document.getElementById('stg-tpl-' + key + '-body');
  if (subjectEl) subjectEl.value = dflt.subject || '';
  if (bodyEl)    bodyEl.value    = dflt.body    || '';
  showToast('Template reset to default', 'info');
}



