// ════════════════════════════════════════════════════════════════
// 1. CLAIM SUBMISSION SYSTEM (My Claims)
// ════════════════════════════════════════════════════════════════

function submitNewClaim() {
  const form = document.getElementById('new-claim-form');
  if (!form || !validateClaimForm()) {
    showToast('Please fill all required fields', 'error');
    return;
  }

  const newClaim = {
    id: generateClaimID(),
    partner: currentUser.name,
    partnerId: currentUser.id,
    status: 'submitted',
    submittedAt: new Date().toISOString(),
    submittedBy: currentUser.id,
    loanApac: document.getElementById('claim-loan-apac').value,
    loanRefId: document.getElementById('claim-loan-ref').value,
    customerName: document.getElementById('claim-customer').value,
    disbAmount: parseFloat(document.getElementById('claim-disb-amount').value || 0),
    claimAmount: parseFloat(document.getElementById('claim-amount').value || 0),
    bankDetails: {
      accountNumber: document.getElementById('claim-bank-acc').value,
      bankName: document.getElementById('claim-bank-name').value,
      accountHolder: document.getElementById('claim-acc-holder').value,
      ifscCode: document.getElementById('claim-ifsc').value
    },
    documents: [],
    verificationStatus: 'pending',
    managementNotes: '',
    assignedTo: null,
    daysInStatus: 0,
    createdAt: new Date().toISOString(),
    updatedAt: new Date().toISOString()
  };

  PAYOUT_CLAIMS.push(newClaim);

  addTrackingEntry(
    newClaim,
    'Claim Submitted',
    'User Action',
    `New claim submitted by ${currentUser.name} for ₹${newClaim.claimAmount.toLocaleString()}`,
    document.getElementById('claim-notes').value || ''
  );

  notifyManagement('new_claim_submitted', newClaim);
  showToast('Claim submitted successfully! Management will verify it shortly. ✓', 'success');
  resetClaimForm();
  renderMyPayoutClaims();
}

function generateClaimID() {
  const date = new Date();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const year = String(date.getFullYear()).slice(-2);
  const random = Math.random().toString(36).substr(2, 7).toUpperCase();
  return `CLAIM-${month}${year}-${random}`;
}

function validateClaimForm() {
  const required = [
    'claim-loan-apac',
    'claim-amount',
    'claim-bank-acc',
    'claim-bank-name',
    'claim-ifsc'
  ];
  return required.every(id => {
    const el = document.getElementById(id);
    return el && el.value && el.value.trim();
  });
}

function notifyManagement(type, claim) {
  const notification = {
    type: type,
    claimId: claim.id,
    partner: claim.partner,
    amount: claim.claimAmount,
    timestamp: new Date().toISOString(),
    read: false
  };
  
  // Store in localStorage for notifications
  const notifications = JSON.parse(localStorage.getItem('mgmt_notifications') || '[]');
  notifications.unshift(notification);
  localStorage.setItem('mgmt_notifications', JSON.stringify(notifications.slice(0, 50)));
  
  // Show toast if admin is viewing
  if (currentUser.role === 'admin' || currentUser.role === 'accounts') {
    console.log('🔔 New claim notification:', claim.id);
  }
}

