function approveClaim(claimId) {
  const claim = PAYOUT_CLAIMS.find(c => c.id === claimId);
  if (!claim) return;

  claim.status = 'approved';
  claim.verificationStatus = 'verified';
  claim.verifiedBy = currentUser.id;
  claim.verifiedAt = new Date().toISOString();
  claim.verificationNotes = document.getElementById('mgmt-verify-notes')?.value || '';
  claim.updatedAt = new Date().toISOString();

  addTrackingEntry(
    claim,
    'Claim Approved',
    'Management Action',
    `Claim approved by ${currentUser.name}. All verifications complete.`,
    claim.verificationNotes
  );

  notifyPartner(claimId, 'approved', `Your claim has been approved! Amount: ₹${claim.claimAmount.toLocaleString()}`);
  
  showToast('Claim approved successfully! ✓', 'success');
  document.getElementById('mgmt-verify-panel').style.display = 'none';
  renderPayoutMgmt();
}

function requestClaimInfo(claimId) {
  const claim = PAYOUT_CLAIMS.find(c => c.id === claimId);
  if (!claim) return;

  claim.status = 'awaiting_info';
  claim.infoRequestedAt = new Date().toISOString();
  claim.infoRequest = document.getElementById('mgmt-verify-notes')?.value || 'Please provide additional information.';
  claim.dueDate = new Date(Date.now() + 5 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);

  addTrackingEntry(
    claim,
    'Information Requested',
    'Management Action',
    `Management requested additional information`,
    claim.infoRequest
  );

  notifyPartner(claimId, 'info_requested', `We need more information. Due Date: ${claim.dueDate}`);
  
  showToast('Information request sent to partner! ✓', 'success');
  document.getElementById('mgmt-verify-panel').style.display = 'none';
  renderPayoutMgmt();
}

function rejectClaim(claimId) {
  const claim = PAYOUT_CLAIMS.find(c => c.id === claimId);
  if (!claim) return;

  claim.status = 'rejected';
  claim.rejectionReason = document.getElementById('mgmt-verify-notes')?.value || 'Claim rejected';
  claim.rejectedAt = new Date().toISOString();
  claim.rejectedBy = currentUser.id;

  addTrackingEntry(
    claim,
    'Claim Rejected',
    'Management Action',
    `Claim rejected`,
    claim.rejectionReason
  );

  notifyPartner(claimId, 'rejected', `Your claim has been rejected. Reason: ${claim.rejectionReason}`);
  
  showToast('Claim rejected! Partner has been notified.', 'info');
  document.getElementById('mgmt-verify-panel').style.display = 'none';
  renderPayoutMgmt();
}

function notifyPartner(claimId, action, message) {
  const claim = PAYOUT_CLAIMS.find(c => c.id === claimId);
  if (!claim) return;

  console.log(`📧 Notify Partner ${claim.partner}: ${message}`);
  // In production, send actual email via backend
}

