// ════════════════════════════════════════════════════════════════
// 1. ADVANCED KPI DASHBOARD WITH REAL-TIME METRICS
// ════════════════════════════════════════════════════════════════

function buildAdvancedKPIDashboard(claims) {
  const stats = {
    total: claims.length,
    submitted: claims.filter(c => c.status === 'submitted').length,
    pending: claims.filter(c => c.status === 'pending_verification').length,
    approved: claims.filter(c => c.status === 'approved').length,
    processing: claims.filter(c => c.status === 'processing').length,
    paid: claims.filter(c => c.status === 'paid').length,
    rejected: claims.filter(c => c.status === 'rejected').length,
    onHold: claims.filter(c => c.status === 'on_hold').length
  };

  const amounts = {
    submitted: claims.filter(c => c.status === 'submitted').reduce((s, c) => s + Number(c.payoutAmount || 0), 0),
    pending: claims.filter(c => c.status === 'pending_verification').reduce((s, c) => s + Number(c.payoutAmount || 0), 0),
    approved: claims.filter(c => c.status === 'approved').reduce((s, c) => s + Number(c.payoutAmount || 0), 0),
    paid: claims.filter(c => c.status === 'paid').reduce((s, c) => s + Number(c.payoutAmount || 0), 0)
  };

  const totalAmount = Object.values(amounts).reduce((a, b) => a + b, 0);
  const successRate = claims.length > 0 ? Math.round((stats.paid / claims.length) * 100) : 0;
  
  const oldPending = claims.filter(c => c.status === 'pending_verification' && (c.daysInStatus || 0) > 15).length;
  const avgDays = claims.length > 0 ? Math.round(claims.reduce((s, c) => s + (c.daysInStatus || 0), 0) / claims.length) : 0;
  
  const slaBreach = claims.filter(c => (c.daysInStatus || 0) > 10).length;
  const slaAtRisk = claims.filter(c => (c.daysInStatus || 0) > 8 && (c.daysInStatus || 0) <= 10).length;

  return `
    <div style="background:linear-gradient(135deg,#f0f4ff,#f8f9ff);border-radius:16px;padding:20px;margin-bottom:24px">
      <div style="font-size:12px;color:var(--text3);text-transform:uppercase;letter-spacing:1px;font-weight:800;margin-bottom:16px">📊 MANAGEMENT DASHBOARD</div>
      
      <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px">
        <!-- KPI 1: Total Claims -->
        <div style="background:white;border-radius:12px;padding:14px;border-left:4px solid var(--accent);box-shadow:0 2px 8px rgba(0,0,0,.05)">
          <div style="font-size:10px;color:var(--text3);font-weight:700;text-transform:uppercase;margin-bottom:6px">Total Claims</div>
          <div style="font-size:24px;font-weight:900;color:var(--text)">${stats.total}</div>
          <div style="font-size:11px;color:var(--text2);margin-top:4px">₹${(totalAmount/100000).toFixed(1)}L total</div>
        </div>
        
        <!-- KPI 2: Success Rate -->
        <div style="background:white;border-radius:12px;padding:14px;border-left:4px solid var(--success);box-shadow:0 2px 8px rgba(0,0,0,.05)">
          <div style="font-size:10px;color:var(--text3);font-weight:700;text-transform:uppercase;margin-bottom:6px">Success Rate</div>
          <div style="font-size:24px;font-weight:900;color:var(--success)">${successRate}%</div>
          <div style="font-size:11px;color:var(--text2);margin-top:4px">${stats.paid} claims paid</div>
        </div>
        
        <!-- KPI 3: Avg Processing Time -->
        <div style="background:white;border-radius:12px;padding:14px;border-left:4px solid var(--accent);box-shadow:0 2px 8px rgba(0,0,0,.05)">
          <div style="font-size:10px;color:var(--text3);font-weight:700;text-transform:uppercase;margin-bottom:6px">Avg Time</div>
          <div style="font-size:24px;font-weight:900;color:var(--text)">${avgDays} days</div>
          <div style="font-size:11px;color:var(--text2);margin-top:4px">Target: 10 days</div>
        </div>
        
        <!-- KPI 4: SLA Status -->
        <div style="background:white;border-radius:12px;padding:14px;border-left:4px solid ${slaBreach > 0 ? 'var(--danger)' : 'var(--success)'};box-shadow:0 2px 8px rgba(0,0,0,.05)">
          <div style="font-size:10px;color:var(--text3);font-weight:700;text-transform:uppercase;margin-bottom:6px">SLA Status</div>
          <div style="font-size:20px;font-weight:900;color:${slaBreach > 0 ? 'var(--danger)' : 'var(--success)'}">${slaBreach > 0 ? '⚠️ ' + slaBreach : '✅ 100%'}</div>
          <div style="font-size:11px;color:var(--text2);margin-top:4px">${slaAtRisk} at risk</div>
        </div>
      </div>

      <div style="display:grid;grid-template-columns:repeat(8,1fr);gap:8px">
        ${buildStatusCard('Submitted', stats.submitted, amounts.submitted, 'var(--accent3)')}
        ${buildStatusCard('Pending', stats.pending, amounts.pending, 'var(--warn)')}
        ${buildStatusCard('Approved', stats.approved, amounts.approved, 'var(--accent)')}
        ${buildStatusCard('Processing', stats.processing, 0, 'var(--accent2)')}
        ${buildStatusCard('Paid', stats.paid, amounts.paid, 'var(--success)')}
        ${buildStatusCard('Rejected', stats.rejected, 0, 'var(--danger)')}
        ${buildStatusCard('On Hold', stats.onHold, 0, 'var(--text3)')}
        ${buildStatusCard('Overdue', oldPending, 0, 'var(--danger)')}
      </div>
    </div>
  `;
}

function buildStatusCard(label, count, amount, color) {
  return `
    <div style="background:white;border-radius:10px;padding:10px;border:1px solid var(--border);text-align:center">
      <div style="font-size:10px;color:var(--text3);font-weight:700;margin-bottom:4px">${label}</div>
      <div style="font-size:18px;font-weight:900;color:${color}">${count}</div>
      ${amount > 0 ? `<div style="font-size:9px;color:var(--text2)">₹${(amount/100000).toFixed(1)}L</div>` : ''}
    </div>
  `;
}

