// ════════════════════════════════════════════════════════════════════════════
// 2. INTELLIGENT RISK ASSESSMENT & EARLY WARNING SYSTEM
// ════════════════════════════════════════════════════════════════════════════

function buildRiskAssessment(claims) {
  const risks = [];
  
  // Risk 1: High-value claims
  const highValue = claims.filter(c => Number(c.payoutAmount || 0) > 500000).length;
  if (highValue > 0) {
    risks.push({
      level: 'medium',
      title: `${highValue} High-Value Claims (>₹5L)`,
      description: 'Require extra verification',
      action: 'Review Priority',
      color: '#faad14'
    });
  }
  
  // Risk 2: Slow processing
  const slow = claims.filter(c => (c.daysInStatus || 0) > 15).length;
  if (slow > 0) {
    risks.push({
      level: 'high',
      title: `${slow} Claims Stuck (>15 days)`,
      description: 'SLA compliance at risk',
      action: 'Expedite Now',
      color: '#ff4d4f'
    });
  }
  
  // Risk 3: Partner reliability
  const partners = {};
  claims.forEach(c => {
    if (!partners[c.partner]) {
      partners[c.partner] = { total: 0, rejected: 0 };
    }
    partners[c.partner].total++;
    if (c.status === 'rejected') partners[c.partner].rejected++;
  });
  
  const lowPerformers = Object.entries(partners)
    .filter(([_, data]) => (data.rejected / data.total) > 0.15)
    .map(([name]) => name);
  
  if (lowPerformers.length > 0) {
    risks.push({
      level: 'medium',
      title: `${lowPerformers.length} Low-Performing Partners`,
      description: `Rejection rate > 15%: ${lowPerformers.join(', ')}`,
      action: 'Review Quality',
      color: '#faad14'
    });
  }
  
  let html = `
    <div style="background:linear-gradient(135deg,#fff1f0,#ffebe6);border-radius:16px;padding:20px;margin-bottom:24px;border:1px solid #ffb8a8">
      <div style="font-size:13px;color:#d4380d;text-transform:uppercase;letter-spacing:1.5px;font-weight:900;margin-bottom:16px">⚠️ RISK ASSESSMENT & ALERTS</div>
      
      <div style="display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:12px">
  `;
  
  risks.forEach(risk => {
    const levelEmoji = risk.level === 'high' ? '🔴' : '🟡';
    html += `
      <div style="background:white;border-radius:12px;padding:14px;border-left:4px solid ${risk.color};box-shadow:0 4px 12px rgba(0,0,0,.08)">
        <div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:8px">
          <div style="font-size:12px;font-weight:700;color:var(--text)">${levelEmoji} ${risk.title}</div>
          <button onclick="alert('${risk.action}')" style="background:${risk.color};color:white;border:none;padding:4px 10px;border-radius:4px;font-size:9px;font-weight:700;cursor:pointer">${risk.action}</button>
        </div>
        <div style="font-size:11px;color:#666">${risk.description}</div>
      </div>
    `;
  });
  
  html += `</div></div>`;
  return html;
}

// ════════════════════════════════════════════════════════════════════════════
// 3. ADVANCED PERFORMANCE BENCHMARKING
// ════════════════════════════════════════════════════════════════════════════

function buildPerformanceBenchmark(claims) {
  const partners = {};
  
  claims.forEach(c => {
    if (!partners[c.partner]) {
      partners[c.partner] = {
        total: 0, paid: 0, rejected: 0, pending: 0,
        amount: 0, avgDays: 0, quality: 100
      };
    }
    partners[c.partner].total++;
    partners[c.partner].amount += Number(c.payoutAmount || 0);
    partners[c.partner].avgDays += (c.daysInStatus || 0);
    if (c.status === 'paid') partners[c.partner].paid++;
    else if (c.status === 'rejected') partners[c.partner].rejected++;
    else partners[c.partner].pending++;
  });

  // Calculate metrics
  const sortedPartners = Object.entries(partners)
    .map(([name, data]) => ({
      name,
      successRate: Math.round((data.paid / data.total) * 100),
      volume: data.total,
      amount: data.amount,
      avgDays: Math.round(data.avgDays / data.total),
      quality: 100 - (data.rejected * 5)
    }))
    .sort((a, b) => b.successRate - a.successRate)
    .slice(0, 5);

  let html = `
    <div style="background:linear-gradient(135deg,#f0fff4,#f5ffef);border-radius:16px;padding:20px;margin-bottom:24px;border:1px solid #b7eb8f">
      <div style="font-size:13px;color:#22863a;text-transform:uppercase;letter-spacing:1.5px;font-weight:900;margin-bottom:16px">🏆 TOP PERFORMERS & BENCHMARKS</div>
      
      <div style="display:flex;flex-direction:column;gap:12px">
  `;
  
  sortedPartners.forEach((partner, idx) => {
    const medal = idx === 0 ? '🥇' : idx === 1 ? '🥈' : idx === 2 ? '🥉' : '⭐';
    const barWidth = (partner.successRate / 100) * 100;
    
    html += `
      <div style="background:white;border-radius:10px;padding:12px;border-left:3px solid #52c41a">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px">
          <div style="font-weight:700;color:var(--text)">${medal} ${partner.name}</div>
          <div style="font-size:12px;font-weight:700;color:#22863a">${partner.successRate}%</div>
        </div>
        <div style="background:#f0f0f0;height:6px;border-radius:3px;overflow:hidden">
          <div style="background:#52c41a;height:100%;width:${barWidth}%"></div>
        </div>
        <div style="display:flex;justify-content:space-between;font-size:10px;color:#666;margin-top:6px">
          <span>Volume: ${partner.volume} | Avg: ${partner.avgDays}d</span>
          <span>Quality: ${partner.quality}/100</span>
        </div>
      </div>
    `;
  });
  
  html += `</div></div>`;
  return html;
}

