// 4. INTELLIGENT RECOMMENDATIONS ENGINE
// ════════════════════════════════════════════════════════════════════════════

function buildSmartRecommendations(claims) {
  const recommendations = [];
  
  // Recommendation 1
  const oldPending = claims.filter(c => c.status === 'pending_verification' && (c.daysInStatus || 0) > 15);
  if (oldPending.length > 0) {
    recommendations.push({
      priority: 1,
      icon: '⚡',
      title: 'Expedite Stuck Claims',
      description: `${oldPending.length} claims stuck > 15 days. Approve or request more info immediately.`,
      action: 'View Claims',
      benefit: 'Recover 2-3 days of processing time'
    });
  }
  
  // Recommendation 2
  recommendations.push({
    priority: 2,
    icon: '📈',
    title: 'Scale High-Performers',
    description: 'Increase processing limits for partners with 100% success rate.',
    action: 'Review Partners',
    benefit: 'Increase throughput by 25%'
  });
  
  // Recommendation 3
  recommendations.push({
    priority: 3,
    icon: '🎓',
    title: 'Partner Training Program',
    description: 'Low-performers need quality training on documentation.',
    action: 'Create Program',
    benefit: 'Reduce rejections by 40%'
  });
  
  // Recommendation 4
  recommendations.push({
    priority: 4,
    icon: '⚙️',
    title: 'Automate Verification',
    description: 'Implement automated document verification for standard loans.',
    action: 'Setup Automation',
    benefit: 'Reduce processing time by 50%'
  });

  let html = `
    <div style="background:linear-gradient(135deg,#f5f5f5,#fafafa);border-radius:16px;padding:20px;margin-bottom:24px;border:1px solid #d9d9d9">
      <div style="font-size:13px;color:#262626;text-transform:uppercase;letter-spacing:1.5px;font-weight:900;margin-bottom:16px">💡 SMART RECOMMENDATIONS</div>
      
      <div style="display:flex;flex-direction:column;gap:12px">
  `;
  
  recommendations.forEach(rec => {
    html += `
      <div style="background:white;border-radius:10px;padding:14px;border-left:4px solid #1890ff;box-shadow:0 2px 8px rgba(0,0,0,.06)">
        <div style="display:flex;justify-content:space-between;align-items:start;margin-bottom:8px">
          <div>
            <div style="font-weight:700;color:var(--text);font-size:13px">${rec.icon} ${rec.title}</div>
            <div style="font-size:11px;color:#666;margin-top:4px">${rec.description}</div>
          </div>
          <button onclick="alert('${rec.action}')" style="background:#1890ff;color:white;border:none;padding:6px 12px;border-radius:4px;font-size:10px;font-weight:700;cursor:pointer;white-space:nowrap">${rec.action}</button>
        </div>
        <div style="font-size:10px;color:#1890ff;font-weight:600">💪 ${rec.benefit}</div>
      </div>
    `;
  });
  
  html += `</div></div>`;
  return html;
}

